#include <cuda_runtime.h>
#include <utility>
#include <cstddef>
#include <cstdint>

namespace {

// Tuned for modern datacenter GPUs (A100/H100):
// - 256 threads/CTA provides good memory throughput for the streaming pass over `data`.
// - Each thread examines 8 points per round; this keeps register pressure modest.
// - The shared candidate queue keeps K + 2 full rounds of candidates. That slack
//   materially reduces prune frequency while keeping the worst-case dynamic shared
//   memory exactly at 48 KiB when K == 1024.
constexpr int kBlockThreads     = 256;
constexpr int kLocalBuffer      = 8;
constexpr int kQueueSlackRounds = 2;
constexpr unsigned int kInfBits = 0x7f800000u;

template<int K, int BLOCK_THREADS, int LOCAL_BUFFER, int SLACK_ROUNDS>
struct KnnConfig {
    static_assert((K & (K - 1)) == 0 && K >= 32 && K <= 1024,
                  "K must be a power of two in [32, 1024].");
    static_assert(BLOCK_THREADS % 32 == 0,
                  "BLOCK_THREADS must be a multiple of warp size.");

    static constexpr int kRoundCandidates = BLOCK_THREADS * LOCAL_BUFFER;
    static constexpr int kCapacity        = K + SLACK_ROUNDS * kRoundCandidates;
    static constexpr int kPruneTrigger    = kCapacity - kRoundCandidates;

    // Dynamic shared memory layout:
    //   float cand_dist[kCapacity]
    //   int   cand_idx [kCapacity]
    //   float tmp_dist [K]
    //   int   tmp_idx  [K]
    static constexpr std::size_t kDynamicSharedBytes =
        sizeof(float) * static_cast<std::size_t>(kCapacity) +
        sizeof(int)   * static_cast<std::size_t>(kCapacity) +
        sizeof(float) * static_cast<std::size_t>(K) +
        sizeof(int)   * static_cast<std::size_t>(K);
};

static_assert(
    KnnConfig<1024, kBlockThreads, kLocalBuffer, kQueueSlackRounds>::kDynamicSharedBytes
        == 48u * 1024u,
    "The chosen tuning is intended to keep the worst-case dynamic shared memory at 48 KiB."
);

// Per-CTA static shared state. All sizable temporaries used for the candidate queue live
// in dynamic shared memory, so this structure is intentionally small.
template<int BLOCK_THREADS>
struct StaticShared {
    unsigned int hist[256];               // 8-bit radix histogram for exact shared-memory pruning.
    int warp_sums[BLOCK_THREADS / 32];    // Scratch for block-wide exclusive scans.
    int scan_total;                       // Block-wide scan aggregate.
    int queue_size;                       // Current number of elements in the candidate queue.
    unsigned int threshold_bits;          // Current K-th distance threshold (IEEE-754 ordered bits).
    int threshold_valid;                  // 0 before the first exact prune, then 1.
    int write_base;                       // Queue insertion base for the current round.

    // Scratch for radix selection.
    unsigned int prefix;
    unsigned int mask;
    int rank;
    int total_lt;
    int need_eq;
};

// For non-negative IEEE-754 floats, raw bit order matches numeric order. Squared Euclidean
// distances are non-negative, so we can select/sort by raw bits without extra transforms.
__device__ __forceinline__ unsigned int ordered_bits_nonnegative(float x) {
    return __float_as_uint(x);
}

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    const unsigned int ba = ordered_bits_nonnegative(da);
    const unsigned int bb = ordered_bits_nonnegative(db);
    return (ba < bb) || ((ba == bb) && (ia < ib));
}

// Lightweight CTA-wide exclusive sum for integer counts. This replaces a heavier generic
// block scan because this kernel only needs scans over small integers.
template<int BLOCK_THREADS>
__device__ __forceinline__ int block_exclusive_sum(
    int x,
    int* block_total,
    int* warp_sums)
{
    static_assert(BLOCK_THREADS % 32 == 0, "BLOCK_THREADS must be warp-aligned.");

    constexpr int kNumWarps = BLOCK_THREADS / 32;
    constexpr unsigned int kFullMask = 0xffffffffu;

    const int tid  = threadIdx.x;
    const int lane = tid & 31;
    const int warp = tid >> 5;

    int inclusive = x;
#pragma unroll
    for (int offset = 1; offset < 32; offset <<= 1) {
        const int y = __shfl_up_sync(kFullMask, inclusive, offset);
        if (lane >= offset) inclusive += y;
    }

    const int warp_exclusive = inclusive - x;
    if (lane == 31) {
        warp_sums[warp] = inclusive;
    }
    __syncthreads();

    if (warp == 0) {
        int warp_total = (lane < kNumWarps) ? warp_sums[lane] : 0;
        int warp_scan  = warp_total;
#pragma unroll
        for (int offset = 1; offset < 32; offset <<= 1) {
            const int y = __shfl_up_sync(kFullMask, warp_scan, offset);
            if (lane >= offset) warp_scan += y;
        }
        if (lane < kNumWarps) {
            warp_sums[lane] = warp_scan - warp_total;
        }
        if (lane == kNumWarps - 1) {
            *block_total = warp_scan;
        }
    }
    __syncthreads();

    return warp_sums[warp] + warp_exclusive;
}

// Exact prune of the shared candidate queue back down to K elements.
// The queue always contains:
//   - the exact top-K among all previously processed points, and
//   - additional candidates with distance < the last known K-th threshold.
// Therefore, selecting the K smallest values from the queue is sufficient to restore the
// exact invariant after each prune.
template<int K, int BLOCK_THREADS>
__device__ __forceinline__ void prune_queue(
    int q,
    float* cand_dist,
    int* cand_idx,
    float* tmp_dist,
    int* tmp_idx,
    StaticShared<BLOCK_THREADS>& ss)
{
    const int tid = threadIdx.x;

    // Exact K-th order statistic by 4-pass 8-bit radix selection over the queue.
    if (tid == 0) {
        ss.prefix = 0u;
        ss.mask   = 0u;
        ss.rank   = K; // 1-based rank of the K-th smallest value.
    }
    __syncthreads();

#pragma unroll
    for (int shift = 24; shift >= 0; shift -= 8) {
        for (int b = tid; b < 256; b += BLOCK_THREADS) {
            ss.hist[b] = 0u;
        }
        __syncthreads();

        const unsigned int prefix = ss.prefix;
        const unsigned int mask   = ss.mask;

        for (int i = tid; i < q; i += BLOCK_THREADS) {
            const unsigned int bits = ordered_bits_nonnegative(cand_dist[i]);
            if ((bits & mask) == prefix) {
                atomicAdd(&ss.hist[(bits >> shift) & 0xFFu], 1u);
            }
        }
        __syncthreads();

        if (tid == 0) {
            unsigned int accum  = 0u;
            unsigned int chosen = 0u;
            const unsigned int rank = static_cast<unsigned int>(ss.rank);

            while (chosen < 256u) {
                const unsigned int c = ss.hist[chosen];
                if (accum + c >= rank) break;
                accum += c;
                ++chosen;
            }

            ss.prefix = prefix | (chosen << shift);
            ss.mask   = mask   | (0xFFu << shift);
            ss.rank  -= static_cast<int>(accum);
        }
        __syncthreads();
    }

    const unsigned int thr_bits = ss.prefix;
    if (tid == 0) {
        ss.threshold_bits  = thr_bits;
        ss.threshold_valid = 1;
    }
    __syncthreads();

    // Count elements strictly smaller than the threshold and those exactly equal to it.
    int lt_i = 0;
    int eq_i = 0;
    for (int i = tid; i < q; i += BLOCK_THREADS) {
        const unsigned int bits = ordered_bits_nonnegative(cand_dist[i]);
        lt_i += static_cast<int>(bits <  thr_bits);
        eq_i += static_cast<int>(bits == thr_bits);
    }

    const int lt_base = block_exclusive_sum<BLOCK_THREADS>(lt_i, &ss.scan_total, ss.warp_sums);
    const int total_lt = ss.scan_total;
    const int eq_base = block_exclusive_sum<BLOCK_THREADS>(eq_i, &ss.scan_total, ss.warp_sums);

    if (tid == 0) {
        ss.total_lt = total_lt;
        ss.need_eq  = K - total_lt;
    }
    __syncthreads();

    // Compact the exact K smallest items into tmp_* (unsorted):
    //   all keys < threshold
    //   plus just enough keys == threshold to reach K
    int lt_out = lt_base;
    int eq_out = eq_base;
    for (int i = tid; i < q; i += BLOCK_THREADS) {
        const float d = cand_dist[i];
        const int idx = cand_idx[i];
        const unsigned int bits = ordered_bits_nonnegative(d);

        if (bits < thr_bits) {
            tmp_dist[lt_out] = d;
            tmp_idx[lt_out]  = idx;
            ++lt_out;
        } else if (bits == thr_bits) {
            if (eq_out < ss.need_eq) {
                const int pos = ss.total_lt + eq_out;
                tmp_dist[pos] = d;
                tmp_idx[pos]  = idx;
            }
            ++eq_out;
        }
    }
    __syncthreads();

    for (int i = tid; i < K; i += BLOCK_THREADS) {
        cand_dist[i] = tmp_dist[i];
        cand_idx[i]  = tmp_idx[i];
    }
    __syncthreads();
}

// Final in-CTA sort of the exact top-K before writing results. K is a power of two, so a
// standard bitonic network is simple and effective here. This is done only once per query.
template<int K, int BLOCK_THREADS>
__device__ __forceinline__ void sort_final_topk(float* dist, int* idx) {
    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = threadIdx.x; i < K; i += BLOCK_THREADS) {
                const int j = i ^ stride;
                if (j > i) {
                    const bool up = ((i & size) == 0);

                    const float di = dist[i];
                    const int   ii = idx[i];
                    const float dj = dist[j];
                    const int   ij = idx[j];

                    const bool do_swap = up ? pair_less(dj, ij, di, ii)
                                            : pair_less(di, ii, dj, ij);

                    if (do_swap) {
                        dist[i] = dj;
                        idx[i]  = ij;
                        dist[j] = di;
                        idx[j]  = ii;
                    }
                }
            }
            __syncthreads();
        }
    }
}

template<int K, int BLOCK_THREADS = kBlockThreads, int LOCAL_BUFFER = kLocalBuffer, int SLACK_ROUNDS = kQueueSlackRounds>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result)
{
    using Cfg = KnnConfig<K, BLOCK_THREADS, LOCAL_BUFFER, SLACK_ROUNDS>;

    const int qid = blockIdx.x;
    if (qid >= query_count) {
        return;
    }

    __shared__ StaticShared<BLOCK_THREADS> ss;

    // Dynamic shared-memory layout:
    //   [cand_dist | cand_idx | tmp_dist | tmp_idx]
    extern __shared__ unsigned char smem_raw[];
    unsigned char* ptr = smem_raw;

    float* cand_dist = reinterpret_cast<float*>(ptr);
    ptr += sizeof(float) * Cfg::kCapacity;

    int* cand_idx = reinterpret_cast<int*>(ptr);
    ptr += sizeof(int) * Cfg::kCapacity;

    float* tmp_dist = reinterpret_cast<float*>(ptr);
    ptr += sizeof(float) * K;

    int* tmp_idx = reinterpret_cast<int*>(ptr);

    const int tid = threadIdx.x;

    const float2 q = query[qid];
    const float qx = q.x;
    const float qy = q.y;

    if (tid == 0) {
        ss.queue_size      = 0;
        ss.threshold_bits  = kInfBits;
        ss.threshold_valid = 0;
    }
    __syncthreads();

    float local_dist[LOCAL_BUFFER];
    int   local_idx[LOCAL_BUFFER];

    // Main streaming pass over the database.
    // Exactness invariant:
    //   after each prune, cand_[0:K) contains the exact K best points seen so far.
    // Therefore, once a valid threshold exists, any future point with distance >= threshold
    // cannot be required (ties may be broken arbitrarily), so we safely ignore equality.
    for (int base = 0; base < data_count; base += Cfg::kRoundCandidates) {
        int local_count = 0;

        const bool have_threshold   = (ss.threshold_valid != 0);
        const unsigned int thr_bits = ss.threshold_bits;

#pragma unroll
        for (int j = 0; j < LOCAL_BUFFER; ++j) {
            const int did = base + j * BLOCK_THREADS + tid;
            if (did < data_count) {
                const float2 p = data[did];
                const float dx = qx - p.x;
                const float dy = qy - p.y;
                const float d  = fmaf(dx, dx, dy * dy); // squared L2 distance

                if (have_threshold) {
                    if (ordered_bits_nonnegative(d) < thr_bits) {
                        local_dist[local_count] = d;
                        local_idx [local_count] = did;
                        ++local_count;
                    }
                } else {
                    // Before the first exact prune, accept everything so that +inf distances
                    // are still handled correctly.
                    local_dist[local_count] = d;
                    local_idx [local_count] = did;
                    ++local_count;
                }
            }
        }

        const int local_offset =
            block_exclusive_sum<BLOCK_THREADS>(local_count, &ss.scan_total, ss.warp_sums);
        const int round_total = ss.scan_total;

        if (tid == 0) {
            ss.write_base = ss.queue_size;
            ss.queue_size += round_total;
        }
        __syncthreads();

        const int out = ss.write_base + local_offset;
#pragma unroll
        for (int j = 0; j < LOCAL_BUFFER; ++j) {
            if (j < local_count) {
                cand_dist[out + j] = local_dist[j];
                cand_idx [out + j] = local_idx [j];
            }
        }
        __syncthreads();

        // Prune eagerly the first time we have more than K candidates, then only when the
        // shared queue approaches capacity. This cuts prune frequency while keeping the
        // queue safely bounded without any global scratch space.
        if ((ss.queue_size > K) &&
            ((ss.threshold_valid == 0) || (ss.queue_size > Cfg::kPruneTrigger))) {
            const int qsize = ss.queue_size;
            prune_queue<K, BLOCK_THREADS>(qsize, cand_dist, cand_idx, tmp_dist, tmp_idx, ss);
            if (tid == 0) {
                ss.queue_size = K;
            }
        }
        __syncthreads();
    }

    // Final exact prune if slack remains in the queue.
    if (ss.queue_size > K) {
        const int qsize = ss.queue_size;
        prune_queue<K, BLOCK_THREADS>(qsize, cand_dist, cand_idx, tmp_dist, tmp_idx, ss);
        if (tid == 0) {
            ss.queue_size = K;
        }
    }
    __syncthreads();

    sort_final_topk<K, BLOCK_THREADS>(cand_dist, cand_idx);

    // Store sorted (index, squared-distance) pairs for this query.
    // Use member assignment instead of constructing std::pair on device.
    std::pair<int, float>* const out =
        result + static_cast<std::size_t>(qid) * static_cast<std::size_t>(K);

    for (int i = tid; i < K; i += BLOCK_THREADS) {
        out[i].first  = cand_idx[i];
        out[i].second = cand_dist[i];
    }
}

template<int K>
inline void launch_knn_impl(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    using Cfg = KnnConfig<K, kBlockThreads, kLocalBuffer, kQueueSlackRounds>;

    // These attribute calls are idempotent and keep the kernel in a high-shared-memory mode.
    // The wrapper intentionally remains asynchronous with respect to the host, matching
    // normal CUDA kernel launch semantics.
    static_cast<void>(cudaFuncSetAttribute(
        knn_kernel<K, kBlockThreads, kLocalBuffer, kQueueSlackRounds>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(Cfg::kDynamicSharedBytes)));

    static_cast<void>(cudaFuncSetAttribute(
        knn_kernel<K, kBlockThreads, kLocalBuffer, kQueueSlackRounds>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100));

    knn_kernel<K, kBlockThreads, kLocalBuffer, kQueueSlackRounds>
        <<<query_count, kBlockThreads, Cfg::kDynamicSharedBytes>>>(
            query, query_count, data, data_count, result);
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    // K is specialized at compile time so that:
    //   - the final sort network is fully specialized,
    //   - shared-memory sizes scale with K,
    //   - the compiler can optimize aggressively for the fixed top-K width.
    switch (k) {
        case 32:   launch_knn_impl<32>  (query, query_count, data, data_count, result); break;
        case 64:   launch_knn_impl<64>  (query, query_count, data, data_count, result); break;
        case 128:  launch_knn_impl<128> (query, query_count, data, data_count, result); break;
        case 256:  launch_knn_impl<256> (query, query_count, data, data_count, result); break;
        case 512:  launch_knn_impl<512> (query, query_count, data, data_count, result); break;
        case 1024: launch_knn_impl<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs are guaranteed valid by contract.
    }
}

#include <cuda_runtime.h>

#include <cstddef>
#include <utility>

namespace {

// Chosen for the prompt's stated regime (query_count in the low-thousands, data_count in
// the millions) and for modern data-center GPUs:
//
// * 256 threads/block  -> 8 warps/block, so 8 queries are processed together.
// * 512 data points/tile -> each thread loads exactly 2 float2 values into shared memory.
// * Worst-case shared memory:
//       8 warps * 1024 heap entries * (4B dist + 4B idx) = 64 KiB dynamic
//       512 x-coordinates + 512 y-coordinates            =  4 KiB static
//   Total ~= 68 KiB, which still allows multiple resident blocks on A100/H100 once the
//   kernel opts into the larger shared-memory carveout.
constexpr int kWarpSize          = 32;
constexpr int kBlockThreads      = 256;
constexpr int kQueriesPerBlock   = kBlockThreads / kWarpSize;   // 8 queries/block
constexpr int kTilePoints        = 512;                         // 2 loads/thread
constexpr int kRoundsPerTile     = kTilePoints / kWarpSize;     // 16 warp rounds/tile
constexpr int kTileLoadsPerThread= kTilePoints / kBlockThreads; // 2
constexpr int kMaxK              = 1024;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be warp-aligned.");
static_assert(kTilePoints % kWarpSize == 0, "Tile size must be warp-aligned.");
static_assert(kTilePoints % kBlockThreads == 0, "Tile size must be an integer number of per-thread loads.");

// Device-side POD mirror of std::pair<int,float>.
// The public interface is fixed to std::pair<int,float>, but device code only needs raw
// field stores. Using a POD mirror avoids depending on std::pair constructors/operators
// being device-callable, while preserving the same binary size/layout in practice.
struct PairIF {
    int   first;
    float second;
};

static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>),
              "Unexpected std::pair<int,float> layout.");

// Per-warp max-heap helpers. The heap stores the current exact k best candidates seen so
// far for one query. The root (index 0) is the current kth-smallest distance threshold.
__device__ __forceinline__ void heap_swap(float* dist, int* idx, int a, int b) {
    const float td = dist[a];
    dist[a] = dist[b];
    dist[b] = td;

    const int ti = idx[a];
    idx[a] = idx[b];
    idx[b] = ti;
}

__device__ __forceinline__ void sift_down_max_heap(float* dist, int* idx, int root, int count) {
    while (true) {
        int child = (root << 1) + 1;
        if (child >= count) break;

        int largest = child;
        const int right = child + 1;
        if (right < count && dist[right] > dist[child]) {
            largest = right;
        }

        if (dist[root] >= dist[largest]) break;

        heap_swap(dist, idx, root, largest);
        root = largest;
    }
}

__device__ __forceinline__ void build_max_heap(float* dist, int* idx, int count) {
    for (int i = (count >> 1) - 1; i >= 0; --i) {
        sift_down_max_heap(dist, idx, i, count);
    }
}

__device__ __forceinline__ void replace_heap_root(float* dist, int* idx, int count,
                                                  float new_dist, int new_idx) {
    dist[0] = new_dist;
    idx[0]  = new_idx;
    sift_down_max_heap(dist, idx, 0, count);
}

// Standard in-place heapsort on a max-heap. Result is ascending by distance, which is
// exactly the output order required by result[i * k + j] == j-th nearest neighbor.
__device__ __forceinline__ void heap_sort_ascending(float* dist, int* idx, int count) {
    for (int end = count - 1; end > 0; --end) {
        heap_swap(dist, idx, 0, end);
        sift_down_max_heap(dist, idx, 0, end);
    }
}

} // namespace

// Exact k-NN kernel for 2D points:
//
//   * One warp owns one query for the entire scan.
//   * A block therefore handles 8 queries at once.
//   * Data is streamed through a shared-memory tile so each global load is reused by
//     8 queries before eviction.
//   * Each warp maintains its own exact top-k max-heap in shared memory.
//   * After the first k points initialize the heap, later points only incur heap work
//     when their squared distance is below the current kth-best threshold.
//
// This is exact, needs no extra device allocations, and is tuned for large batched scans.
__global__ __launch_bounds__(256, 2)
void knn_kernel_2d_euclidean(const float2* __restrict__ query,
                             int query_count,
                             const float2* __restrict__ data,
                             int data_count,
                             PairIF* __restrict__ result,
                             int k) {
    constexpr unsigned kFullMask = 0xffffffffu;

    const int tid     = threadIdx.x;
    const int warp_id = tid >> 5;
    const int lane    = tid & 31;
    const int qid     = static_cast<int>(blockIdx.x) * kQueriesPerBlock + warp_id;
    const bool active = (qid < query_count);

    // Dynamic shared memory layout:
    //   [0, kQueriesPerBlock * k) floats : heap distances
    //   [same size] ints                 : heap indices
    extern __shared__ unsigned char smem[];
    float* const all_heap_dist = reinterpret_cast<float*>(smem);
    int*   const all_heap_idx  = reinterpret_cast<int*>(all_heap_dist + kQueriesPerBlock * k);

    float* const heap_dist = all_heap_dist + warp_id * k;
    int*   const heap_idx  = all_heap_idx  + warp_id * k;

    // Shared-memory tile in SoA form. This avoids the 2-way bank conflicts that a naive
    // float2 AoS tile would create for warp-wide shared-memory reads.
    __shared__ float tile_x[kTilePoints];
    __shared__ float tile_y[kTilePoints];

    // One query point per warp; lane 0 loads it and broadcasts to the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active) {
        float2 q = make_float2(0.0f, 0.0f);
        if (lane == 0) {
            q = query[qid];
        }
        qx = __shfl_sync(kFullMask, q.x, 0);
        qy = __shfl_sync(kFullMask, q.y, 0);
    }

    // k is guaranteed to be a multiple of 32, so the initial fill phase reaches exactly
    // k entries on a warp-round boundary.
    int   local_count = 0;
    float kth_dist    = CUDART_INF_F; // valid in lane 0 once the heap is built

    for (int base = 0; base < data_count; base += kTilePoints) {
        int tile_count = data_count - base;
        if (tile_count > kTilePoints) tile_count = kTilePoints;

        // Cooperative global->shared staging. Each thread loads exactly two float2 values
        // on full tiles, which maps well to the chosen 512-point tile size.
        #pragma unroll
        for (int load = 0; load < kTileLoadsPerThread; ++load) {
            const int t = tid + load * kBlockThreads;
            if (t < tile_count) {
                const float2 p = data[base + t];
                tile_x[t] = p.x;
                tile_y[t] = p.y;
            }
        }

        __syncthreads();

        if (active) {
            const unsigned lane_mask_lt = (1u << lane) - 1u;

            // Fixed 16 rounds per tile; the valid predicate handles the tail tile.
            #pragma unroll
            for (int round = 0; round < kRoundsPerTile; ++round) {
                const int t     = (round << 5) + lane;
                const bool valid = (t < tile_count);

                float dist = 0.0f;
                int   idx  = base + t;

                if (valid) {
                    // Squared L2 distance; no sqrt because ordering is unchanged.
                    const float dx = tile_x[t] - qx;
                    const float dy = tile_y[t] - qy;
                    dist = fmaf(dx, dx, dy * dy);
                }

                if (local_count < k) {
                    // Heap fill phase: append the next valid distances contiguously.
                    const unsigned valid_mask = __ballot_sync(kFullMask, valid);
                    const int prefix = __popc(valid_mask & lane_mask_lt);

                    if (valid) {
                        heap_dist[local_count + prefix] = dist;
                        heap_idx [local_count + prefix] = idx;
                    }

                    // Needed before lane 0 can build the heap from the just-written batch.
                    __syncwarp(kFullMask);

                    local_count += __popc(valid_mask);

                    if (local_count == k) {
                        if (lane == 0) {
                            build_max_heap(heap_dist, heap_idx, k);
                            kth_dist = heap_dist[0];
                        }
                        __syncwarp(kFullMask);
                    }
                } else {
                    // Steady state: only candidates below the current kth-best threshold
                    // can possibly enter the exact top-k.
                    const float threshold = __shfl_sync(kFullMask, kth_dist, 0);
                    const bool hit = valid && (dist < threshold);
                    unsigned hit_mask = __ballot_sync(kFullMask, hit);

                    // The loop count is warp-uniform because hit_mask is warp-uniform, so
                    // the shuffle calls are legal. Lane 0 performs the heap updates.
                    while (hit_mask) {
                        const int src = __ffs(hit_mask) - 1;
                        const float cand_dist = __shfl_sync(kFullMask, dist, src);
                        const int   cand_idx  = __shfl_sync(kFullMask, idx,  src);

                        if (lane == 0 && cand_dist < heap_dist[0]) {
                            replace_heap_root(heap_dist, heap_idx, k, cand_dist, cand_idx);
                        }

                        hit_mask &= hit_mask - 1;
                    }

                    if (lane == 0) {
                        kth_dist = heap_dist[0];
                    }
                    __syncwarp(kFullMask);
                }
            }
        }

        // Protect the tile before the next global->shared load overwrites it.
        __syncthreads();
    }

    if (active) {
        if (lane == 0) {
            heap_sort_ascending(heap_dist, heap_idx, k);
        }
        __syncwarp(kFullMask);

        PairIF* const out = result + static_cast<std::size_t>(qid) * static_cast<std::size_t>(k);
        for (int j = lane; j < k; j += kWarpSize) {
            out[j].first  = heap_idx[j];
            out[j].second = heap_dist[j];
        }
    }
}

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Request enough dynamic shared memory for the worst-case heap footprint and ask the
    // driver to maximize the shared-memory carveout. This matches the target hardware in
    // the prompt (A100/H100-class parts).
    const int max_dynamic_smem =
        kQueriesPerBlock * kMaxK * (static_cast<int>(sizeof(float)) + static_cast<int>(sizeof(int)));
    (void)cudaFuncSetAttribute(knn_kernel_2d_euclidean,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               max_dynamic_smem);
    (void)cudaFuncSetAttribute(knn_kernel_2d_euclidean,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const std::size_t dynamic_smem =
        static_cast<std::size_t>(kQueriesPerBlock) *
        static_cast<std::size_t>(k) *
        (sizeof(float) + sizeof(int));

    const int blocks = (query_count + kQueriesPerBlock - 1) / kQueriesPerBlock;

    // Intentionally asynchronous, matching normal CUDA kernel-launch semantics.
    knn_kernel_2d_euclidean<<<blocks, kBlockThreads, dynamic_smem>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<PairIF*>(result),
        k
    );
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// Output type alias to keep signatures readable.
using ResultPair = std::pair<int, float>;

// Compact POD used for the per-query top-K heap in shared memory.
// Distance is placed first because heap operations compare on distance every time.
struct alignas(8) Neighbor {
    float dist;
    int idx;
};

static_assert(sizeof(Neighbor) == 8, "Neighbor must remain a compact 8-byte POD.");
static_assert(alignof(Neighbor) == 8, "Neighbor must remain 8-byte aligned.");

// Kernel configuration.
// Design notes:
//
// 1) One warp owns one query and maintains an exact max-heap of its current K best neighbors.
// 2) A block handles multiple queries so that each data tile loaded from HBM is reused across
//    many queries before being discarded.
// 3) The data tile is stored in shared memory in structure-of-arrays form (x[] and y[])
//    rather than as float2[] to avoid 64-bit shared-memory access patterns that can introduce
//    avoidable bank conflicts.
// 4) Launch bounds are derived conservatively from A100 limits so the same binary also fits H100.
template<int K, int WARPS_PER_BLOCK>
struct KernelConfig {
    static constexpr int kWarpSize = 32;
    static constexpr int kThreads = WARPS_PER_BLOCK * kWarpSize;
    static constexpr int kTilePoints = 1024; // 8 KiB tile (x[] + y[]), a good balance of reuse and occupancy.

    static constexpr int kSharedBytes =
        WARPS_PER_BLOCK * K * static_cast<int>(sizeof(Neighbor)) +
        2 * kTilePoints * static_cast<int>(sizeof(float)); // x[] + y[]

    static constexpr int kA100ThreadsPerSM = 2048;
    static constexpr int kA100SharedPerSM = 163840; // opt-in per-SM shared budget on A100

    static constexpr int kResidentByThreads = kA100ThreadsPerSM / kThreads;
    static constexpr int kResidentByShared  = kA100SharedPerSM / kSharedBytes;
    static constexpr int kResidentBlocks =
        (kResidentByThreads < kResidentByShared) ? kResidentByThreads : kResidentByShared;

    // Cap the launch-bounds hint so we do not over-constrain register allocation on small-K cases.
    static constexpr int kLaunchBoundsMinBlocks =
        (kResidentBlocks > 4) ? 4 : kResidentBlocks;

    static_assert((K & (K - 1)) == 0 && K >= 32 && K <= 1024, "Unsupported K.");
    static_assert(kThreads <= 1024, "Block size exceeds the hardware limit.");
    static_assert(kSharedBytes <= kA100SharedPerSM, "Shared-memory footprint exceeds A100 limits.");
    static_assert(kResidentBlocks >= 1, "Kernel configuration does not fit on A100.");
    static_assert((kTilePoints % kWarpSize) == 0, "Tile size must be a whole number of warps.");
    static_assert((kSharedBytes % 256) == 0, "Shared-memory size should align with allocator granularity.");
};

__device__ __forceinline__ float sq_l2_2d(float qx, float qy, float px, float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

__device__ __forceinline__ void sift_down(Neighbor* heap, int root, int count) {
    Neighbor val = heap[root];

    while (true) {
        int child = (root << 1) + 1;
        if (child >= count) break;

        Neighbor child_val = heap[child];
        const int right = child + 1;
        if (right < count) {
            const Neighbor right_val = heap[right];
            if (right_val.dist > child_val.dist) {
                child = right;
                child_val = right_val;
            }
        }

        if (child_val.dist <= val.dist) break;

        heap[root] = child_val;
        root = child;
    }

    heap[root] = val;
}

template<int K>
__device__ __forceinline__ void build_max_heap(Neighbor* heap) {
    for (int i = (K >> 1); i > 0;) {
        --i;
        sift_down(heap, i, K);
    }
}

template<int K>
__device__ __forceinline__ void replace_root_if_better(Neighbor* heap, float cand_dist, int cand_idx) {
    if (cand_dist < heap[0].dist) {
        heap[0].dist = cand_dist;
        heap[0].idx  = cand_idx;
        sift_down(heap, 0, K);
    }
}

template<int K>
__device__ __forceinline__ void sort_heap_ascending(Neighbor* heap) {
    // Standard heapsort on the max-heap. After this, heap[0..K-1] is ascending by distance.
    for (int end = K - 1; end > 0; --end) {
        const Neighbor tmp = heap[0];
        heap[0] = heap[end];
        heap[end] = tmp;
        sift_down(heap, 0, end);
    }
}

template<int THREADS, int TILE_POINTS>
__device__ __forceinline__ void load_data_tile_soa(
    float* __restrict__ tile_x,
    float* __restrict__ tile_y,
    const float2* __restrict__ data,
    int base,
    int count) {
#pragma unroll
    for (int i = threadIdx.x; i < TILE_POINTS; i += THREADS) {
        if (i < count) {
            const float2 p = data[base + i];
            tile_x[i] = p.x;
            tile_y[i] = p.y;
        }
    }
}

template<int K, int WARPS_PER_BLOCK>
__global__ __launch_bounds__(KernelConfig<K, WARPS_PER_BLOCK>::kThreads,
                             KernelConfig<K, WARPS_PER_BLOCK>::kLaunchBoundsMinBlocks)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    ResultPair* __restrict__ result) {
    using Config = KernelConfig<K, WARPS_PER_BLOCK>;
    constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

    // Dynamic shared-memory layout:
    //   [ WARPS_PER_BLOCK * K Neighbor heap entries ][ tile_x[TilePoints] ][ tile_y[TilePoints] ]
    extern __shared__ unsigned char smem_raw[];
    Neighbor* const all_heaps = reinterpret_cast<Neighbor*>(smem_raw);
    float* const tile_x = reinterpret_cast<float*>(all_heaps + WARPS_PER_BLOCK * K);
    float* const tile_y = tile_x + Config::kTilePoints;

    const int tid  = threadIdx.x;
    const int warp = tid >> 5;
    const int lane = tid & 31;

    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active_query = (query_idx < query_count);

    Neighbor* const heap = all_heaps + warp * K;

    // Load one query point per warp and broadcast to the full warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Seed the exact streaming top-K structure with the first K database points.
    if (active_query) {
        for (int i = lane; i < K; i += 32) {
            const float2 p = data[i];
            heap[i].dist = sq_l2_2d(qx, qy, p.x, p.y);
            heap[i].idx  = i;
        }
    }
    __syncwarp(FULL_MASK);
    if (active_query && lane == 0) {
        build_max_heap<K>(heap);
    }
    __syncwarp(FULL_MASK);

    // Stream the remainder of the database.
    //
    // Exactness comes from the standard online top-K invariant:
    // if a candidate's distance is not better than the current kth-best distance,
    // it can be discarded permanently.
    for (int base = K; base < data_count; base += Config::kTilePoints) {
        const int remaining  = data_count - base;
        const int tile_count = (remaining < Config::kTilePoints) ? remaining : Config::kTilePoints;

        load_data_tile_soa<Config::kThreads, Config::kTilePoints>(tile_x, tile_y, data, base, tile_count);
        __syncthreads();

        if (active_query) {
            float threshold = (lane == 0) ? heap[0].dist : 0.0f;
            threshold = __shfl_sync(FULL_MASK, threshold, 0);

            for (int off = 0; off < tile_count; off += 32) {
                const int local_idx = off + lane;
                const bool valid = (local_idx < tile_count);

                float dist = 0.0f;
                int data_idx = base + local_idx;
                if (valid) {
                    dist = sq_l2_2d(qx, qy, tile_x[local_idx], tile_y[local_idx]);
                }

                // All lanes that beat the current threshold form a candidate mask.
                // Candidates are processed one by one inside the warp; no inter-warp locking
                // is needed because each warp owns a disjoint heap.
                unsigned mask = __ballot_sync(FULL_MASK, valid && (dist < threshold));
                while (mask) {
                    const int src_lane = __ffs(mask) - 1;
                    const float cand_dist = __shfl_sync(FULL_MASK, dist, src_lane);
                    const int cand_idx    = __shfl_sync(FULL_MASK, data_idx, src_lane);

                    if (lane == 0) {
                        // threshold is the current root distance. If earlier insertions in this same
                        // batch already shrank the threshold enough, many stale candidates are skipped
                        // here without touching the heap.
                        if (cand_dist < threshold) {
                            replace_root_if_better<K>(heap, cand_dist, cand_idx);
                            threshold = heap[0].dist;
                        }
                    }
                    threshold = __shfl_sync(FULL_MASK, threshold, 0);

                    mask &= (mask - 1);
                }
            }
        }

        __syncthreads();
    }

    // Convert the heap to ascending order so result[q * K + j] is the j-th nearest neighbor.
    // Direct member writes are used on std::pair to avoid relying on any host-only constructors
    // or assignment operators in device code.
    if (active_query) {
        if (lane == 0) {
            sort_heap_ascending<K>(heap);
        }
        __syncwarp(FULL_MASK);

        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
        for (int i = lane; i < K; i += 32) {
            result[out_base + static_cast<std::size_t>(i)].first  = heap[i].idx;
            result[out_base + static_cast<std::size_t>(i)].second = heap[i].dist;
        }
    }
}

inline int blocks_for_queries(int query_count, int warps_per_block) {
    return (query_count + warps_per_block - 1) / warps_per_block;
}

template<int K, int WARPS_PER_BLOCK>
inline void launch_knn_kernel(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result) {
    using Config = KernelConfig<K, WARPS_PER_BLOCK>;
    constexpr int threads = Config::kThreads;
    constexpr int shared_bytes = Config::kSharedBytes;

    // Opt in to the larger dynamic shared-memory budget and bias the unified L1/shared pool
    // toward shared memory, which is the dominant on-chip resource used by this kernel.
    cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        shared_bytes);
    cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int grid = blocks_for_queries(query_count, WARPS_PER_BLOCK);
    knn_kernel<K, WARPS_PER_BLOCK><<<grid, threads, shared_bytes>>>(
        query, query_count, data, data_count, result);
}

// Choose the largest legal queries-per-block value that still leaves at least roughly one block
// per SM. Larger blocks reuse each data tile across more queries and therefore reduce HBM traffic.
template<int K>
inline void launch_best_up_to_32(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result,
    int sm_count) {
    if (blocks_for_queries(query_count, 32) >= sm_count) {
        launch_knn_kernel<K, 32>(query, query_count, data, data_count, result);
    } else if (blocks_for_queries(query_count, 16) >= sm_count) {
        launch_knn_kernel<K, 16>(query, query_count, data, data_count, result);
    } else if (blocks_for_queries(query_count, 8) >= sm_count) {
        launch_knn_kernel<K, 8>(query, query_count, data, data_count, result);
    } else {
        launch_knn_kernel<K, 4>(query, query_count, data, data_count, result);
    }
}

// K = 1024 cannot use 32 warps/block on A100 because the per-block shared-memory footprint
// would exceed the opt-in limit, so 16 warps/block is the largest legal choice.
template<int K>
inline void launch_best_up_to_16(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result,
    int sm_count) {
    if (blocks_for_queries(query_count, 16) >= sm_count) {
        launch_knn_kernel<K, 16>(query, query_count, data, data_count, result);
    } else if (blocks_for_queries(query_count, 8) >= sm_count) {
        launch_knn_kernel<K, 8>(query, query_count, data, data_count, result);
    } else {
        launch_knn_kernel<K, 4>(query, query_count, data, data_count, result);
    }
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {
    if (query_count <= 0) return;

    int device = 0;
    int sm_count = 0;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);

    // Launch is intentionally asynchronous, matching normal CUDA kernel-launch semantics.
    switch (k) {
        case 32:
            launch_best_up_to_32<32>(query, query_count, data, data_count, result, sm_count);
            break;
        case 64:
            launch_best_up_to_32<64>(query, query_count, data, data_count, result, sm_count);
            break;
        case 128:
            launch_best_up_to_32<128>(query, query_count, data, data_count, result, sm_count);
            break;
        case 256:
            launch_best_up_to_32<256>(query, query_count, data, data_count, result, sm_count);
            break;
        case 512:
            launch_best_up_to_32<512>(query, query_count, data, data_count, result, sm_count);
            break;
        case 1024:
            launch_best_up_to_16<1024>(query, query_count, data, data_count, result, sm_count);
            break;
        default:
            // Per problem statement, k is always a supported power of two.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>
#include <cstdint>

namespace {

// Exact brute-force k-NN for 2D points, specialized for the problem regime:
// - k is one of {32, 64, 128, 256, 512, 1024}
// - query_count is typically O(10^3)
// - data_count is typically O(10^6)
//
// High-level mapping:
//   * one warp owns one query;
//   * one CTA owns 8 queries (8 warps / 256 threads);
//   * each CTA stages 1024 data points in shared memory, so every global load
//     of a data point is reused across 8 independent queries.
//
// Per-query selection strategy:
//   * keep the exact current top-k as a sorted shared-memory array of packed
//     (distance_bits, index) keys;
//   * because distances are non-negative IEEE-754 floats, unsigned bit order
//     matches numeric order, so the packed key is totally ordered;
//   * after every 32-point batch, the current worst key is exact, so any new
//     candidate with key >= worst_key can be discarded exactly (not
//     approximately);
//   * if only a few candidates beat the threshold, lane 0 inserts them directly
//     into the sorted array;
//   * otherwise, the warp sorts the 32 new keys with a register-resident
//     bitonic network and merges them with the current top-k using a merge-path
//     style partition.
//
// This design uses no extra device allocations; only registers and dynamic
// shared memory are used.

using Key = unsigned long long;

constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 8;
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE; // 256
constexpr int TILE_POINTS       = 1024;                        // 8 KiB tile of float2
constexpr int SMALL_INSERT      = 8;                           // hybrid update threshold
constexpr unsigned FULL_MASK    = 0xFFFFFFFFu;

// Sentinel key: +inf distance with the largest possible index.
// Real finite keys are always smaller; real +inf distances are also smaller
// because their lower 32-bit index is < 0xFFFFFFFF.
constexpr Key INF_KEY = (static_cast<Key>(0x7F800000u) << 32) | static_cast<Key>(0xFFFFFFFFu);

__device__ __forceinline__ Key pack_key(const float dist, const int idx) {
    return (static_cast<Key>(__float_as_uint(dist)) << 32) |
           static_cast<Key>(static_cast<unsigned>(idx));
}

__device__ __forceinline__ float unpack_dist(const Key key) {
    return __uint_as_float(static_cast<unsigned>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(const Key key) {
    return static_cast<int>(static_cast<unsigned>(key));
}

// 64-bit shuffles built from two 32-bit shuffles for portability.
__device__ __forceinline__ Key shfl_u64(const Key v, const int src_lane) {
    const unsigned lo = __shfl_sync(FULL_MASK, static_cast<unsigned>(v), src_lane);
    const unsigned hi = __shfl_sync(FULL_MASK, static_cast<unsigned>(v >> 32), src_lane);
    return (static_cast<Key>(hi) << 32) | static_cast<Key>(lo);
}

__device__ __forceinline__ Key shfl_xor_u64(const Key v, const int lane_mask) {
    const unsigned lo = __shfl_xor_sync(FULL_MASK, static_cast<unsigned>(v), lane_mask);
    const unsigned hi = __shfl_xor_sync(FULL_MASK, static_cast<unsigned>(v >> 32), lane_mask);
    return (static_cast<Key>(hi) << 32) | static_cast<Key>(lo);
}

// Sort 32 keys across one warp in ascending order.
// Each lane owns one key. Invalid entries should already be set to INF_KEY.
__device__ __forceinline__ Key warp_bitonic_sort32(Key key) {
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    #pragma unroll
    for (int k = 2; k <= WARP_SIZE; k <<= 1) {
        #pragma unroll
        for (int j = k >> 1; j > 0; j >>= 1) {
            const Key other = shfl_xor_u64(key, j);
            const bool up   = ((lane & k) == 0);
            const Key minv  = (key < other) ? key : other;
            const Key maxv  = (key < other) ? other : key;
            key = up ? minv : maxv;
        }
    }
    return key;
}

// Merge the current sorted top-k array A[K] with a sorted candidate array B[m],
// producing the smallest K keys into OUT[K]. A and OUT must not alias.
template <int K>
__device__ __forceinline__ void warp_merge_topk(const Key* __restrict__ a,
                                                const Key* __restrict__ b,
                                                const int m,
                                                Key* __restrict__ out) {
    static_assert(K >= WARP_SIZE && K <= 1024 && (K & (K - 1)) == 0, "Unsupported K");
    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    const int lane      = threadIdx.x & (WARP_SIZE - 1);
    const int out_begin = lane * ITEMS_PER_LANE;

    // Merge-path partition for this lane's contiguous output segment.
    int low  = (out_begin > K) ? (out_begin - K) : 0;
    int high = (out_begin < m) ? out_begin : m;

    while (low < high) {
        const int mid        = (low + high) >> 1;
        const int a_left_idx = out_begin - mid - 1;

        if (a_left_idx >= 0 && b[mid] < a[a_left_idx]) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    int b_idx = low;
    int a_idx = out_begin - b_idx;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const Key a_val = (a_idx < K) ? a[a_idx] : INF_KEY;
        const Key b_val = (b_idx < m) ? b[b_idx] : INF_KEY;
        const bool take_a = (a_val <= b_val);
        out[out_begin + t] = take_a ? a_val : b_val;
        a_idx += take_a ? 1 : 0;
        b_idx += take_a ? 0 : 1;
    }
}

template <int K>
__launch_bounds__(THREADS_PER_BLOCK, 1)
__global__ void knn_kernel(const float2* __restrict__ query,
                           const int query_count,
                           const float2* __restrict__ data,
                           const int data_count,
                           std::pair<int, float>* __restrict__ result) {
    static_assert(K >= WARP_SIZE && K <= 1024 && (K & (K - 1)) == 0, "Unsupported K");

    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    // Dynamic shared memory layout:
    //   topk_buf0[WARPS_PER_BLOCK][K]
    //   topk_buf1[WARPS_PER_BLOCK][K]
    //   batch    [WARPS_PER_BLOCK][32]
    //   data_tile[TILE_POINTS]
    extern __shared__ __align__(8) unsigned char shared_raw[];
    Key* shared_keys = reinterpret_cast<Key*>(shared_raw);

    Key* topk_buf0 = shared_keys;
    Key* topk_buf1 = topk_buf0 + static_cast<std::size_t>(WARPS_PER_BLOCK) * K;
    Key* batch_buf = topk_buf1 + static_cast<std::size_t>(WARPS_PER_BLOCK) * K;
    float2* data_tile = reinterpret_cast<float2*>(batch_buf + static_cast<std::size_t>(WARPS_PER_BLOCK) * WARP_SIZE);

    const int lane = threadIdx.x & (WARP_SIZE - 1);
    const int warp = threadIdx.x >> 5;

    const int qid = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active = (qid < query_count);

    // One query per warp; lane 0 loads and broadcasts.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active) {
        const float2 q = query[qid];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    Key* const buf0 = topk_buf0 + static_cast<std::size_t>(warp) * K;
    Key* const buf1 = topk_buf1 + static_cast<std::size_t>(warp) * K;
    Key* const warp_batch = batch_buf + static_cast<std::size_t>(warp) * WARP_SIZE;

    // Initialize the current top-k buffer to +inf.
    #pragma unroll
    for (int i = 0; i < ITEMS_PER_LANE; ++i) {
        buf0[lane + i * WARP_SIZE] = INF_KEY;
    }

    // Current buffer selector and exact current worst key for this warp/query.
    int cur_sel = 0;
    Key worst_key = INF_KEY;

    // Full-tile loop over the database.
    for (int tile_base = 0; tile_base < data_count; tile_base += TILE_POINTS) {
        // Stage one tile of data points into shared memory.
        #pragma unroll
        for (int i = threadIdx.x; i < TILE_POINTS; i += THREADS_PER_BLOCK) {
            const int data_idx = tile_base + i;
            if (data_idx < data_count) {
                data_tile[i] = data[data_idx];
            }
        }

        __syncthreads();

        if (active) {
            // Process the tile in 32-point warp batches.
            #pragma unroll 1
            for (int sub = 0; sub < TILE_POINTS; sub += WARP_SIZE) {
                const int data_idx = tile_base + sub + lane;

                Key key = INF_KEY;
                bool valid = false;

                if (data_idx < data_count) {
                    const float2 p = data_tile[sub + lane];

                    const float dx = p.x - qx;
                    const float dy = p.y - qy;

                    // Squared Euclidean distance.
                    const float dist = __fmaf_rn(dx, dx, dy * dy);

                    key = pack_key(dist, data_idx);
                    valid = (key < worst_key);
                }

                const unsigned valid_mask = __ballot_sync(FULL_MASK, valid);
                const int m = __popc(valid_mask);

                if (m == 0) {
                    continue;
                }

                Key* const cur = (cur_sel == 0) ? buf0 : buf1;

                if (m <= SMALL_INSERT) {
                    // Fast path: only a few records beat the current threshold.
                    // Compact them, sort them cheaply in lane 0, then insert them
                    // into the current sorted top-k buffer in place.
                    if (valid) {
                        const unsigned lower_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
                        const int write_pos = __popc(valid_mask & lower_mask);
                        warp_batch[write_pos] = key;
                    }

                    __syncwarp(FULL_MASK);

                    if (lane == 0) {
                        // Insertion sort the tiny compacted batch.
                        for (int i = 1; i < m; ++i) {
                            const Key v = warp_batch[i];
                            int j = i - 1;
                            while (j >= 0 && warp_batch[j] > v) {
                                warp_batch[j + 1] = warp_batch[j];
                                --j;
                            }
                            warp_batch[j + 1] = v;
                        }

                        // Insert sorted keys into the current top-k.
                        // Since the batch is sorted ascending, insertion positions
                        // are monotone non-decreasing; search_lo exploits that.
                        int search_lo = 0;

                        for (int i = 0; i < m; ++i) {
                            const Key v = warp_batch[i];

                            // Earlier insertions may already have tightened the
                            // threshold enough that the remaining keys are no
                            // longer competitive.
                            if (!(v < cur[K - 1])) {
                                break;
                            }

                            int lo = search_lo;
                            int hi = K;
                            while (lo < hi) {
                                const int mid = (lo + hi) >> 1;
                                if (cur[mid] < v) {
                                    lo = mid + 1;
                                } else {
                                    hi = mid;
                                }
                            }

                            const int pos = lo;

                            // Shift tail right by one and place the new key.
                            #pragma unroll 1
                            for (int j = K - 1; j > pos; --j) {
                                cur[j] = cur[j - 1];
                            }
                            cur[pos] = v;
                            search_lo = pos + 1;
                        }

                        worst_key = cur[K - 1];
                    }

                    // Ensure lane-0 writes to shared memory are visible to the warp.
                    __syncwarp(FULL_MASK);
                    worst_key = shfl_u64(worst_key, 0);
                } else {
                    // Heavy path: enough winning candidates that a full warp-level
                    // sort + merge is cheaper than serial in-place insertion.
                    if (!valid) {
                        key = INF_KEY;
                    }

                    key = warp_bitonic_sort32(key);
                    warp_batch[lane] = key;

                    __syncwarp(FULL_MASK);

                    Key* const out = (cur_sel == 0) ? buf1 : buf0;
                    warp_merge_topk<K>(cur, warp_batch, m, out);

                    __syncwarp(FULL_MASK);

                    if (lane == 0) {
                        worst_key = out[K - 1];
                    }

                    cur_sel ^= 1;
                    worst_key = shfl_u64(worst_key, 0);
                }
            }
        }

        // The tile buffer is shared across all warps in the CTA.
        __syncthreads();
    }

    // top-k is already sorted ascending, so the final writeout is straightforward.
    if (active) {
        const Key* const cur = (cur_sel == 0) ? buf0 : buf1;
        const std::size_t out_base = static_cast<std::size_t>(qid) * K;

        #pragma unroll
        for (int i = 0; i < ITEMS_PER_LANE; ++i) {
            const int j = lane + i * WARP_SIZE;
            const Key key = cur[j];
            result[out_base + j].first  = unpack_idx(key);
            result[out_base + j].second = unpack_dist(key);
        }
    }
}

template <int K>
struct SharedBytes {
    static constexpr std::size_t value =
        // two K-sized top-k buffers per warp + one 32-key batch buffer per warp
        (static_cast<std::size_t>(WARPS_PER_BLOCK) *
         (static_cast<std::size_t>(2) * K + WARP_SIZE)) * sizeof(Key) +
        // one float2 tile shared across the whole CTA
        static_cast<std::size_t>(TILE_POINTS) * sizeof(float2);
};

template <int K>
inline void launch_knn(const float2* query,
                       const int query_count,
                       const float2* data,
                       const int data_count,
                       std::pair<int, float>* result) {
    constexpr std::size_t shared_bytes = SharedBytes<K>::value;

    // The chosen parameters are constrained by the A100 opt-in shared-memory
    // limit (163,840 bytes). They also keep the grid large enough for the
    // stated "thousands of queries" regime on 100+ SM GPUs.
    static_assert(shared_bytes <= 163840, "Per-block shared memory exceeds A100 opt-in limit.");

    // Opt in to the required dynamic shared-memory size and bias the L1/shared
    // partition toward shared memory; this kernel is explicitly shared-memory
    // heavy and stages the database tile in shared memory by design.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(shared_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(THREADS_PER_BLOCK);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    // Launch is intentionally asynchronous with respect to the host.
    knn_kernel<K><<<grid, block, shared_bytes>>>(query, query_count, data, data_count, result);
}

} // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // K is runtime but comes from a tiny fixed set, so dispatching to
    // compile-time specializations gives the compiler full visibility into:
    //   * K/32 items per lane,
    //   * shared-memory footprint,
    //   * merge-loop trip counts.
    switch (k) {
        case 32:   launch_knn<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn<1024>(query, query_count, data, data_count, result); break;
        default:
            // Input contract says k is always valid, so this path should never run.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// 256 data points per tile = 2 KiB of staged data.
// This is large enough to amortize synchronization, yet small enough that
// stale-threshold false positives remain limited and shared-memory use stays low.
constexpr int TILE_POINTS = 256;
constexpr int TILE_ITERS  = TILE_POINTS / 32;
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

// Internal heap node. We keep the distance first because the max-heap compares
// only on distance; the index is carried alongside it.
struct alignas(8) Neighbor {
    float dist;
    int   idx;
};

// Device code avoids constructing std::pair directly because standard-library
// constructors/operators are not guaranteed to be __device__-callable.
// We therefore write through an ABI-compatible POD view. CUDA-supported host
// toolchains lay out pair<int,float> as two consecutive 32-bit fields.
struct ResultPair {
    int   first;
    float second;
};

static_assert(TILE_POINTS % 32 == 0, "Tile size must be a whole number of warps.");
static_assert(sizeof(Neighbor) == 8, "Unexpected Neighbor size.");
static_assert(sizeof(ResultPair) == sizeof(std::pair<int, float>),
              "Unexpected std::pair<int,float> size.");
static_assert(alignof(ResultPair) <= alignof(std::pair<int, float>),
              "Unexpected std::pair<int,float> alignment.");

constexpr std::size_t align_up(std::size_t x, std::size_t a) {
    return (x + a - 1) & ~(a - 1);
}

__device__ __forceinline__ float sq_l2(const float qx, const float qy, const float2 p) {
    const float dx = p.x - qx;
    const float dy = p.y - qy;
    return fmaf(dx, dx, dy * dy);
}

// Standard in-place sift-down for a max-heap stored in shared memory.
__device__ __forceinline__ void heap_sift_down(Neighbor* heap, int n, int root) {
    Neighbor v = heap[root];
    int child = (root << 1) + 1;

    while (child < n) {
        int max_child = child;
        const int right = child + 1;
        if (right < n && heap[right].dist > heap[child].dist) {
            max_child = right;
        }
        if (heap[max_child].dist <= v.dist) {
            break;
        }
        heap[root] = heap[max_child];
        root = max_child;
        child = (root << 1) + 1;
    }
    heap[root] = v;
}

__device__ __forceinline__ void heap_build_max(Neighbor* heap, int n) {
    for (int i = (n >> 1) - 1; i >= 0; --i) {
        heap_sift_down(heap, n, i);
    }
}

__device__ __forceinline__ void heap_replace_root(Neighbor* heap, int n, const Neighbor candidate) {
    heap[0] = candidate;
    heap_sift_down(heap, n, 0);
}

// Exact brute-force 2D k-NN.
//
// Mapping:
//   - one warp owns one query;
//   - a block batches WARPS_PER_BLOCK queries;
//   - the block stages TILE_POINTS data points into shared memory once;
//   - every query-warp reuses that tile.
//
// Exact top-k maintenance:
//   - lane 0 of each warp maintains an exact max-heap of size k in shared memory;
//   - the heap root is the current k-th best distance threshold;
//   - while scanning a tile, the warp only records ballot masks for points with
//     d < threshold_snapshot;
//   - lane 0 revisits only those marked points and inserts them exactly into the heap.
//
// This is exact because the threshold only ever decreases: a point with
// d >= threshold_snapshot cannot enter the final top-k later.
template<int WARPS_PER_BLOCK>
__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           ResultPair* __restrict__ result,
                           int k) {
    extern __shared__ unsigned char smem[];

    std::size_t off = 0;

    off = align_up(off, alignof(float2));
    float2* tile = reinterpret_cast<float2*>(smem + off);
    off += TILE_POINTS * sizeof(float2);

    off = align_up(off, alignof(Neighbor));
    Neighbor* heaps = reinterpret_cast<Neighbor*>(smem + off);
    off += static_cast<std::size_t>(WARPS_PER_BLOCK) *
           static_cast<std::size_t>(k) * sizeof(Neighbor);

    off = align_up(off, alignof(unsigned int));
    unsigned int* qual_masks = reinterpret_cast<unsigned int*>(smem + off);

    const int warp = threadIdx.x >> 5;
    const int lane = threadIdx.x & 31;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active = query_idx < query_count;

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    Neighbor* const my_heap = heaps + static_cast<std::size_t>(warp) * static_cast<std::size_t>(k);
    unsigned int* const my_masks = qual_masks + warp * TILE_ITERS;

    // Initialize the exact top-k state from the first k data points.
    if (active) {
        for (int i = lane; i < k; i += 32) {
            const float2 p = data[i];
            my_heap[i] = Neighbor{sq_l2(qx, qy, p), i};
        }
    }
    __syncwarp(FULL_MASK);

    float my_threshold = CUDART_INF_F;
    if (active && lane == 0) {
        heap_build_max(my_heap, k);
        my_threshold = my_heap[0].dist;
    }

    constexpr int THREADS = WARPS_PER_BLOCK * 32;

    for (int base = k; base < data_count; base += TILE_POINTS) {
        // Cooperative staging of one data tile.
        #pragma unroll
        for (int t = threadIdx.x; t < TILE_POINTS; t += THREADS) {
            const int data_idx = base + t;
            if (data_idx < data_count) {
                tile[t] = data[data_idx];
            }
        }
        __syncthreads();

        if (active) {
            // Only lane 0 owns the authoritative threshold register, so every
            // tile starts by broadcasting it to the full warp.
            const float thr = __shfl_sync(FULL_MASK, my_threshold, 0);

            // Squared distances are non-negative. Once the current k-th best is
            // exactly zero, no future point can improve the heap.
            if (thr > 0.0f) {
                int tile_count = data_count - base;
                if (tile_count > TILE_POINTS) {
                    tile_count = TILE_POINTS;
                }

                // One ballot mask per 32-point slice of the tile.
                #pragma unroll
                for (int iter = 0; iter < TILE_ITERS; ++iter) {
                    const int local = (iter << 5) + lane;
                    bool qualifies = false;

                    if (local < tile_count) {
                        const float2 p = tile[local];
                        qualifies = (sq_l2(qx, qy, p) < thr);
                    }

                    const unsigned int mask = __ballot_sync(FULL_MASK, qualifies);
                    if (lane == 0) {
                        my_masks[iter] = mask;
                    }
                }

                __syncwarp(FULL_MASK);

                if (lane == 0) {
                    float root = my_threshold;

                    // Revisit only candidates marked by the ballots. The root is
                    // refreshed after every successful insertion, so false
                    // positives caused by the stale tile-wide threshold are
                    // filtered here exactly.
                    #pragma unroll
                    for (int iter = 0; iter < TILE_ITERS; ++iter) {
                        unsigned int mask = my_masks[iter];
                        const int base_local = iter << 5;

                        while (mask) {
                            const int bit = __ffs(static_cast<int>(mask)) - 1;
                            const int local = base_local + bit;
                            const float2 p = tile[local];

                            const Neighbor cand{sq_l2(qx, qy, p), base + local};

                            if (cand.dist < root) {
                                heap_replace_root(my_heap, k, cand);
                                root = my_heap[0].dist;

                                // Early stop inside this tile when no point can
                                // possibly improve the heap anymore.
                                if (root == 0.0f) {
                                    break;
                                }
                            }

                            mask &= (mask - 1u);
                        }

                        if (root == 0.0f) {
                            break;
                        }
                    }

                    my_threshold = root;
                }
            }
        }

        // Ensure every warp has finished using the current tile before it is overwritten.
        __syncthreads();
    }

    // Final heap sort. Because this is a max-heap, repeatedly popping the root
    // and writing from the end yields ascending distance order in result[].
    if (active && lane == 0) {
        ResultPair* const out = result +
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(k);

        int heap_size = k;
        for (int pos = k - 1; pos >= 0; --pos) {
            const Neighbor top = my_heap[0];
            out[pos].first  = top.idx;
            out[pos].second = top.dist;

            --heap_size;
            if (heap_size > 0) {
                my_heap[0] = my_heap[heap_size];
                heap_sift_down(my_heap, heap_size, 0);
            }
        }
    }
}

template<int WARPS_PER_BLOCK>
std::size_t shared_bytes_for(int k) {
    std::size_t off = 0;

    off = align_up(off, alignof(float2));
    off += TILE_POINTS * sizeof(float2);

    off = align_up(off, alignof(Neighbor));
    off += static_cast<std::size_t>(WARPS_PER_BLOCK) *
           static_cast<std::size_t>(k) * sizeof(Neighbor);

    off = align_up(off, alignof(unsigned int));
    off += static_cast<std::size_t>(WARPS_PER_BLOCK) *
           static_cast<std::size_t>(TILE_ITERS) * sizeof(unsigned int);

    return off;
}

// Pick the largest query batch (one warp/query) that:
//   1) fits in per-block shared memory, and
//   2) still leaves at least one block per SM in the grid.
// Larger batches are preferable because each staged data tile is then reused by
// more queries, which is the dominant optimization for this bandwidth-heavy kernel.
int choose_warps_per_block(int query_count, int sm_count, std::size_t max_shared_per_block, int k) {
    if (((query_count + 31) / 32) >= sm_count && shared_bytes_for<32>(k) <= max_shared_per_block) return 32;
    if (((query_count + 15) / 16) >= sm_count && shared_bytes_for<16>(k) <= max_shared_per_block) return 16;
    if (((query_count +  7) /  8) >= sm_count && shared_bytes_for<8 >(k) <= max_shared_per_block) return 8;
    if (((query_count +  3) /  4) >= sm_count && shared_bytes_for<4 >(k) <= max_shared_per_block) return 4;
    if (((query_count +  1) /  2) >= sm_count && shared_bytes_for<2 >(k) <= max_shared_per_block) return 2;
    return 1;
}

template<int WARPS_PER_BLOCK>
void launch_knn_kernel(const float2* query,
                       int query_count,
                       const float2* data,
                       int data_count,
                       std::pair<int, float>* result,
                       int k) {
    const std::size_t shmem = shared_bytes_for<WARPS_PER_BLOCK>(k);

    // Opt in to larger dynamic shared-memory allocations when needed.
    if (shmem > (48u * 1024u)) {
        cudaFuncSetAttribute(knn_kernel<WARPS_PER_BLOCK>,
                             cudaFuncAttributeMaxDynamicSharedMemorySize,
                             static_cast<int>(shmem));
    }

    // This kernel is deliberately shared-memory heavy; prefer the shared carveout.
    cudaFuncSetAttribute(knn_kernel<WARPS_PER_BLOCK>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // See the ResultPair comment above for the ABI assumption behind this cast.
    ResultPair* const result_view = reinterpret_cast<ResultPair*>(result);

    knn_kernel<WARPS_PER_BLOCK><<<blocks, WARPS_PER_BLOCK * 32, shmem>>>(
        query, query_count, data, data_count, result_view, k);
}

} // anonymous namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    if (cudaGetDevice(&device) != cudaSuccess) {
        device = 0;
    }

    int sm_count = 1;
    if (cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device) != cudaSuccess || sm_count < 1) {
        sm_count = 1;
    }

    int max_shared_regular = 48 * 1024;
    cudaDeviceGetAttribute(&max_shared_regular, cudaDevAttrMaxSharedMemoryPerBlock, device);

    int max_shared_optin = max_shared_regular;
    const cudaError_t optin_status =
        cudaDeviceGetAttribute(&max_shared_optin, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);
    if (optin_status != cudaSuccess || max_shared_optin < max_shared_regular) {
        max_shared_optin = max_shared_regular;
    }

    const int warps_per_block =
        choose_warps_per_block(query_count,
                               sm_count,
                               static_cast<std::size_t>(max_shared_optin),
                               k);

    // The interface has no stream argument, so this intentionally uses CUDA's
    // normal asynchronous launch semantics on the current default stream.
    switch (warps_per_block) {
        case 32: launch_knn_kernel<32>(query, query_count, data, data_count, result, k); break;
        case 16: launch_knn_kernel<16>(query, query_count, data, data_count, result, k); break;
        case 8:  launch_knn_kernel<8 >(query, query_count, data, data_count, result, k); break;
        case 4:  launch_knn_kernel<4 >(query, query_count, data, data_count, result, k); break;
        case 2:  launch_knn_kernel<2 >(query, query_count, data, data_count, result, k); break;
        default: launch_knn_kernel<1 >(query, query_count, data, data_count, result, k); break;
    }
}

#include <cuda_runtime.h>
#include <cub/block/block_radix_sort.cuh>

#include <climits>
#include <cstddef>
#include <utility>

namespace {

// Targeted for modern data-center GPUs (A100/H100 class).
//
// Hyper-parameter choice:
// - One CTA owns one query. With the "no extra device memory" constraint, this is the
//   simplest exact strategy because the entire per-query top-k state stays on chip.
// - 256 threads/CTA is the sweet spot here:
//     * fully coalesced 256-point streaming tiles from the data set,
//     * good occupancy on A100/H100,
//     * and, because k <= 1024, the persistent top-k state is at most 4 pairs/thread.
//
// Core idea:
// - Maintain the current exact top-k in a *striped* register layout across the CTA:
//     thread t owns ranks t, t + 256, t + 512, ...
// - On an update, append one new candidate per thread and radix-sort the combined set
//   with CUB, again asking for striped output.
// - In striped output, the last "stripe" is exactly the largest 256 items, so discarding
//   it leaves the smallest k items already laid out correctly for the next iteration.
// - For k < 256, extra lanes are simply padded with +inf sentinels.
//
// To get a tighter initial kth-distance threshold, we bootstrap from as many points as the
// update machinery can absorb in one shot: (TOP_ITEMS + 1) * 256 points. This is exact,
// costs no extra global-memory traffic, and often removes an otherwise inevitable early update.

constexpr int kBlockThreads = 256;
using ResultPair = std::pair<int, float>;

template <int K>
struct KnnTraits {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0,
                  "k must be a power of two in [32, 1024].");

    static constexpr int TOP_ITEMS    = (K + kBlockThreads - 1) / kBlockThreads;  // 1, 2, or 4
    static constexpr int UPDATE_ITEMS = TOP_ITEMS + 1;                             // 2, 3, or 5
    static constexpr int INIT_CAPACITY = UPDATE_ITEMS * kBlockThreads;             // 512, 768, 1280
    static constexpr bool NEED_MASK   = (K < kBlockThreads);

    // In striped layout, rank r lives in:
    //   thread = r % 256
    //   item   = r / 256
    static constexpr int KTH_THREAD = (K - 1) % kBlockThreads;
    static constexpr int KTH_ITEM   = (K - 1) / kBlockThreads;

    static_assert(TOP_ITEMS >= 1 && TOP_ITEMS <= 4, "Unexpected TOP_ITEMS.");
    static_assert(UPDATE_ITEMS >= 2 && UPDATE_ITEMS <= 5, "Unexpected UPDATE_ITEMS.");
    static_assert(KTH_ITEM < TOP_ITEMS, "Invalid kth element location.");

    using UpdateSort = cub::BlockRadixSort<float, kBlockThreads, UPDATE_ITEMS, int>;
    using TempStorage = typename UpdateSort::TempStorage;
};

__device__ __forceinline__ float squared_l2(const float qx, const float qy, const float2 p) {
    // Squared Euclidean distance. No sqrt is taken because the interface asks for the
    // squared L2 norm directly.
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

template <int K>
static __global__ __launch_bounds__(256)
void knn_kernel(const float2* __restrict__ query,
                const float2* __restrict__ data,
                int data_count,
                ResultPair* __restrict__ result) {
    using Traits = KnnTraits<K>;
    using UpdateSort = typename Traits::UpdateSort;

    constexpr int TOP_ITEMS     = Traits::TOP_ITEMS;
    constexpr int UPDATE_ITEMS  = Traits::UPDATE_ITEMS;
    constexpr int INIT_CAPACITY = Traits::INIT_CAPACITY;
    constexpr bool NEED_MASK    = Traits::NEED_MASK;
    constexpr int KTH_THREAD    = Traits::KTH_THREAD;
    constexpr int KTH_ITEM      = Traits::KTH_ITEM;

    __shared__ typename Traits::TempStorage sort_storage;
    __shared__ float shared_tau;

    const int tid = static_cast<int>(threadIdx.x);
    const int qid = static_cast<int>(blockIdx.x);

    // The query is tiny and reused for the full scan; keeping it in registers is ideal.
    const float2 q = query[qid];
    const float qx = q.x;
    const float qy = q.y;

    const float inf = CUDART_INF_F;
    const int invalid_index = INT_MAX;

    // Persistent exact top-k state for this thread, stored in striped layout.
    float top_keys[TOP_ITEMS];
    int   top_vals[TOP_ITEMS];

    // -------------------------------------------------------------------------
    // Bootstrap:
    // Sort the largest batch that the regular update path can consume in one shot.
    // This gives a much tighter initial threshold than starting from only the first k
    // elements and uses the same per-thread state size as every later update.
    // -------------------------------------------------------------------------
    const int init_points = (data_count < INIT_CAPACITY) ? data_count : INIT_CAPACITY;

    {
        float init_keys[UPDATE_ITEMS];
        int   init_vals[UPDATE_ITEMS];

        #pragma unroll
        for (int i = 0; i < UPDATE_ITEMS; ++i) {
            const int data_idx = tid + i * kBlockThreads;
            if (data_idx < init_points) {
                const float2 p = data[data_idx];
                init_keys[i] = squared_l2(qx, qy, p);
                init_vals[i] = data_idx;
            } else {
                init_keys[i] = inf;
                init_vals[i] = invalid_index;
            }
        }

        // Global sort of the bootstrap batch, with striped output.
        UpdateSort(sort_storage).SortBlockedToStriped(init_keys, init_vals);

        // Keep only the smallest k entries; for k < 256, only the first k lanes of the
        // first stripe are valid and the rest are masked back to +inf.
        #pragma unroll
        for (int i = 0; i < TOP_ITEMS; ++i) {
            if constexpr (NEED_MASK) {
                const int striped_rank = tid + i * kBlockThreads;
                if (striped_rank < K) {
                    top_keys[i] = init_keys[i];
                    top_vals[i] = init_vals[i];
                } else {
                    top_keys[i] = inf;
                    top_vals[i] = invalid_index;
                }
            } else {
                top_keys[i] = init_keys[i];
                top_vals[i] = init_vals[i];
            }
        }

        if (tid == KTH_THREAD) {
            shared_tau = top_keys[KTH_ITEM];
        }

        // This barrier serves both purposes:
        // 1) makes shared_tau visible to the whole CTA;
        // 2) satisfies CUB's requirement before reusing TempStorage.
        __syncthreads();
    }

    float tau = shared_tau;

    // -------------------------------------------------------------------------
    // Stream the rest of the data in 256-point tiles.
    // We only invoke the expensive block-wide sort if at least one point in the tile
    // beats the current kth distance. Using strict '< tau' is intentional:
    // - ties may be resolved arbitrarily per the problem statement,
    // - and avoiding '<=' reduces needless update sorts on boundary ties.
    // -------------------------------------------------------------------------
    for (int base = init_points; base < data_count; base += kBlockThreads) {
        const int data_idx = base + tid;

        float cand_key = inf;
        int   cand_val = invalid_index;
        bool  candidate = false;

        if (data_idx < data_count) {
            const float2 p = data[data_idx];
            const float dist = squared_l2(qx, qy, p);
            candidate = (dist < tau);
            if (candidate) {
                cand_key = dist;
                cand_val = data_idx;
            }
        }

        // Block-uniform branch: every thread gets the same result.
        const int any_update = __syncthreads_or(candidate);

        if (any_update) {
            float work_keys[UPDATE_ITEMS];
            int   work_vals[UPDATE_ITEMS];

            // Existing top-k + this thread's new candidate.
            #pragma unroll
            for (int i = 0; i < TOP_ITEMS; ++i) {
                work_keys[i] = top_keys[i];
                work_vals[i] = top_vals[i];
            }
            work_keys[TOP_ITEMS] = cand_key;
            work_vals[TOP_ITEMS] = cand_val;

            // Sort K + 256 logical items (plus +inf padding when k < 256).
            // In striped output, dropping the last stripe is exactly equivalent to
            // removing the 256 largest elements.
            UpdateSort(sort_storage).SortBlockedToStriped(work_keys, work_vals);

            #pragma unroll
            for (int i = 0; i < TOP_ITEMS; ++i) {
                if constexpr (NEED_MASK) {
                    const int striped_rank = tid + i * kBlockThreads;
                    if (striped_rank < K) {
                        top_keys[i] = work_keys[i];
                        top_vals[i] = work_vals[i];
                    } else {
                        top_keys[i] = inf;
                        top_vals[i] = invalid_index;
                    }
                } else {
                    top_keys[i] = work_keys[i];
                    top_vals[i] = work_vals[i];
                }
            }

            if (tid == KTH_THREAD) {
                shared_tau = top_keys[KTH_ITEM];
            }

            // Visible tau update + legal CUB TempStorage reuse barrier.
            __syncthreads();
            tau = shared_tau;
        }
    }

    // -------------------------------------------------------------------------
    // Write back the final exact top-k for this query.
    // The internal representation is already globally sorted in striped order:
    //   rank = tid + item * 256
    // -------------------------------------------------------------------------
    ResultPair* const out =
        result + static_cast<size_t>(qid) * static_cast<size_t>(K);

    #pragma unroll
    for (int i = 0; i < TOP_ITEMS; ++i) {
        const int rank = tid + i * kBlockThreads;

        if constexpr (NEED_MASK) {
            if (rank < K) {
                out[rank].first  = top_vals[i];
                out[rank].second = top_keys[i];
            }
        } else {
            out[rank].first  = top_vals[i];
            out[rank].second = top_keys[i];
        }
    }
}

template <int K>
inline void launch_knn_specialized(const float2* query,
                                   int query_count,
                                   const float2* data,
                                   int data_count,
                                   ResultPair* result) {
    const dim3 grid(static_cast<unsigned int>(query_count));
    const dim3 block(kBlockThreads);

    // Intentionally asynchronous: enqueue on the current default stream.
    knn_kernel<K><<<grid, block>>>(query, data, data_count, result);
}

}  // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Runtime dispatch over the only legal k values. This keeps all of the important
    // quantities (state size, loop trip counts, radix-sort arity, kth register location)
    // compile-time constants in the actual kernel.
    switch (k) {
        case 32:   launch_knn_specialized<32>(query, query_count, data, data_count, result);   return;
        case 64:   launch_knn_specialized<64>(query, query_count, data, data_count, result);   return;
        case 128:  launch_knn_specialized<128>(query, query_count, data, data_count, result);  return;
        case 256:  launch_knn_specialized<256>(query, query_count, data, data_count, result);  return;
        case 512:  launch_knn_specialized<512>(query, query_count, data, data_count, result);  return;
        case 1024: launch_knn_specialized<1024>(query, query_count, data, data_count, result); return;
        default:
            // Input validity guarantees this path is unreachable.
            return;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// Exact brute-force k-NN specialized for:
//   * 2D float points
//   * squared Euclidean distance
//   * k in [32, 1024], power of two
//
// Main optimization strategy:
//
// 1) One warp handles one query.
//    This keeps the query point in registers and lets us use warp ballot/shuffle
//    to compact candidates without any atomics.
//
// 2) One block handles 8 queries (8 warps / 256 threads).
//    The block streams the data set in 256-point tiles and loads each tile from
//    global memory exactly once into shared memory, then reuses it across 8 queries.
//    This is the key bandwidth optimization for the "thousands of queries" regime.
//
// 3) Each warp maintains an exact max-heap of size k in shared memory.
//    The root holds the current worst accepted neighbor, i.e. the pruning threshold.
//
// 4) Exact tile-level pruning:
//    For a tile, every lane compares against a snapshot of the current threshold.
//    Any point with distance >= snapshot threshold can never enter the final top-k
//    because the threshold only decreases as more points are processed.
//    Therefore, only points below the snapshot threshold are compacted into a
//    per-warp candidate buffer, and lane 0 merges them into the heap exactly.
//
// 5) No additional device allocations.
//    All temporary state lives in dynamic shared memory.

constexpr int kWarpSize        = 32;
constexpr int kWarpsPerBlock   = 8;
constexpr int kBlockThreads    = kWarpSize * kWarpsPerBlock;  // 256 threads
constexpr int kDataTilePoints  = kBlockThreads;               // 256 points / tile
constexpr int kTileRounds      = kDataTilePoints / kWarpSize; // 8 rounds of 32 points
constexpr int kMaxK            = 1024;
constexpr unsigned kFullMask   = 0xffffffffu;

static_assert(kDataTilePoints % kWarpSize == 0, "Tile size must be a multiple of warp size.");

struct alignas(8) Neighbor {
    float dist;
    int   idx;
};
static_assert(sizeof(Neighbor) == 8, "Neighbor must remain compact (8 bytes).");

// The public API uses std::pair<int, float>. The caller also guarantees the buffer
// comes from cudaMalloc, i.e. raw device storage. To avoid depending on device-side
// std::pair support, the kernel writes through an ABI-compatible POD view.
struct result_pair_t {
    int   first;
    float second;
};
static_assert(sizeof(result_pair_t)  == sizeof(std::pair<int, float>), "std::pair<int,float> ABI mismatch.");
static_assert(alignof(result_pair_t) == alignof(std::pair<int, float>), "std::pair<int,float> ABI mismatch.");

// Worst-case dynamic shared memory needed at k=1024.
constexpr std::size_t kMaxDynamicSharedBytes =
    kDataTilePoints * sizeof(float2) +
    static_cast<std::size_t>(kWarpsPerBlock) *
        static_cast<std::size_t>(kMaxK + kDataTilePoints) * sizeof(Neighbor);

__device__ __forceinline__ float sq_l2(const float2 p, const float qx, const float qy) {
    const float dx = p.x - qx;
    const float dy = p.y - qy;
    return fmaf(dx, dx, dy * dy);
}

__device__ __forceinline__ void swap_neighbor(Neighbor* a, Neighbor* b) {
    const Neighbor tmp = *a;
    *a = *b;
    *b = tmp;
}

__device__ __forceinline__ void sift_down(Neighbor* heap, int root, const int n) {
    while (true) {
        int child = (root << 1) + 1;
        if (child >= n) break;

        int largest = child;
        const int right = child + 1;
        if (right < n && heap[right].dist > heap[child].dist) {
            largest = right;
        }

        if (heap[root].dist >= heap[largest].dist) {
            break;
        }

        swap_neighbor(heap + root, heap + largest);
        root = largest;
    }
}

__device__ __forceinline__ void build_max_heap(Neighbor* heap, const int n) {
    for (int i = (n >> 1) - 1; i >= 0; --i) {
        sift_down(heap, i, n);
    }
}

__device__ __forceinline__ void maybe_replace_root(Neighbor* heap, const int n, const Neighbor cand) {
    if (cand.dist < heap[0].dist) {
        heap[0] = cand;
        sift_down(heap, 0, n);
    }
}

// Standard heapsort on a max-heap leaves the array in ascending order.
__device__ __forceinline__ void sort_heap_ascending(Neighbor* heap, const int n) {
    for (int end = n - 1; end > 0; --end) {
        swap_neighbor(heap + 0, heap + end);
        sift_down(heap, 0, end);
    }
}

__global__ __launch_bounds__(kBlockThreads, 2)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                result_pair_t* __restrict__ result,
                int k) {
    const int warp_id = threadIdx.x >> 5;
    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int qid     = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active_query = (qid < query_count);

    // One query point per warp. Lane 0 loads, then broadcasts.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query && lane == 0) {
        const float2 q = query[qid];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Shared memory layout:
    //   [ data tile:          kDataTilePoints * float2 ]
    //   [ per-warp heaps:     kWarpsPerBlock * k * Neighbor ]
    //   [ per-warp cand bufs: kWarpsPerBlock * kDataTilePoints * Neighbor ]
    extern __shared__ __align__(8) unsigned char smem_raw[];
    float2*  s_data = reinterpret_cast<float2*>(smem_raw);
    Neighbor* s_heap = reinterpret_cast<Neighbor*>(s_data + kDataTilePoints);
    Neighbor* s_cand = s_heap + static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(k);

    Neighbor* warp_heap = s_heap + static_cast<std::size_t>(warp_id) * static_cast<std::size_t>(k);
    Neighbor* warp_cand = s_cand + static_cast<std::size_t>(warp_id) * static_cast<std::size_t>(kDataTilePoints);

    bool heap_ready = false;
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    for (int base = 0; base < data_count; base += kDataTilePoints) {
        // Load one 256-point tile once per block and reuse it across 8 queries.
        const int data_idx = base + threadIdx.x;
        if (data_idx < data_count) {
            s_data[threadIdx.x] = data[data_idx];
        }
        __syncthreads();

        const int remaining = data_count - base;
        const int valid = (remaining < kDataTilePoints) ? remaining : kDataTilePoints;

        if (active_query) {
            if (!heap_ready) {
                // Initialization:
                //   - the first k points go directly into the heap array
                //   - if k falls inside this tile (small k), the tile tail is also
                //     used as a warm-up sample and merged immediately
                #pragma unroll
                for (int round = 0; round < kTileRounds; ++round) {
                    const int local = round * kWarpSize + lane;
                    if (local < valid) {
                        const int idx = base + local;
                        Neighbor n;
                        n.dist = sq_l2(s_data[local], qx, qy);
                        n.idx  = idx;

                        if (idx < k) {
                            warp_heap[idx] = n;
                        } else if (base < k) {
                            // Only the tile that crosses the initialization boundary
                            // can contribute here. Storing at idx-k keeps the buffer
                            // dense from 0..extra_count-1.
                            warp_cand[idx - k] = n;
                        }
                    }
                }
                __syncwarp();

                if (base + valid >= k) {
                    if (lane == 0) {
                        build_max_heap(warp_heap, k);

                        // extra_count > 0 only when k lies inside this tile
                        // (i.e. k < 256 in the requested range).
                        const int extra_count = base + valid - k;
                        for (int i = 0; i < extra_count; ++i) {
                            maybe_replace_root(warp_heap, k, warp_cand[i]);
                        }
                    }
                    heap_ready = true;
                }
            } else {
                // Snapshot the current worst accepted distance. This threshold is exact
                // for all points processed so far. Filtering against it for the whole tile
                // is also exact because the threshold can only decrease after processing
                // more points.
                const float threshold =
                    __shfl_sync(kFullMask, (lane == 0) ? warp_heap[0].dist : 0.0f, 0);

                // Warp-private compaction into warp_cand[].
                // Only lane 0 tracks the running count; no atomics are needed because
                // the whole buffer is private to this warp.
                int warp_count = 0;

                #pragma unroll
                for (int round = 0; round < kTileRounds; ++round) {
                    const int local = round * kWarpSize + lane;

                    Neighbor n;
                    bool keep = false;
                    if (local < valid) {
                        const float d = sq_l2(s_data[local], qx, qy);
                        keep = (d < threshold);
                        n.dist = d;
                        n.idx  = base + local;
                    }

                    const unsigned mask = __ballot_sync(kFullMask, keep);
                    if (mask) {
                        const int count = __popc(mask);

                        int offset = 0;
                        if (lane == 0) {
                            offset = warp_count;
                            warp_count += count;
                        }
                        offset = __shfl_sync(kFullMask, offset, 0);

                        if (keep) {
                            const int rank = __popc(mask & lane_mask_lt);
                            warp_cand[offset + rank] = n;
                        }
                    }
                }
                __syncwarp();

                // Exact heap maintenance is serialized in lane 0. This is cheap in practice
                // because only a tiny fraction of distances survive the threshold test once
                // the heap has warmed up.
                if (lane == 0) {
                    for (int i = 0; i < warp_count; ++i) {
                        maybe_replace_root(warp_heap, k, warp_cand[i]);
                    }
                }
            }
        }

        // Ensure all warps are done with the current shared tile before overwriting it.
        __syncthreads();
    }

    if (active_query && lane == 0) {
        sort_heap_ascending(warp_heap, k);

        result_pair_t* out =
            result + static_cast<std::size_t>(qid) * static_cast<std::size_t>(k);

        for (int i = 0; i < k; ++i) {
            out[i].first  = warp_heap[i].idx;
            out[i].second = warp_heap[i].dist;
        }
    }
}

} // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Needed because the worst case (k=1024) uses ~84 KiB of dynamic shared memory,
    // which is above the legacy 48 KiB default. The target hardware in the prompt
    // supports this opt-in size.
    cudaFuncSetAttribute(
        knn_kernel,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kMaxDynamicSharedBytes));

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    const std::size_t shared_bytes =
        kDataTilePoints * sizeof(float2) +
        static_cast<std::size_t>(kWarpsPerBlock) *
            static_cast<std::size_t>(k + kDataTilePoints) * sizeof(Neighbor);

    knn_kernel<<<blocks, kBlockThreads, shared_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<result_pair_t*>(result),
        k);
}

#include <cuda_runtime.h>
#include <utility>
#include <cstdint>
#include <cstddef>

namespace {

// Exact k-NN for 2D points, optimized for the stated regime:
//
// - One warp owns one query.
// - One 256-thread CTA therefore processes 8 queries at once.
// - Data are streamed through a 1024-point shared-memory tile (8 KiB), so each
//   global data load is reused by 8 different queries inside the CTA.
// - Each warp keeps an exact top-K max-heap in shared memory.
// - K is specialized at compile time for all valid values {32,64,128,256,512,1024},
//   which removes runtime branches from the inner heap logic.
// - The tile size is chosen to be exactly the largest supported K. This lets us
//   initialize the heap from the first K points in O(K): lanes write the first K
//   packed keys directly, and lane 0 heapifies once.
// - Candidate filtering uses a snapshot of the current heap root. The root can
//   only decrease as the scan proceeds, so snapshot filtering may admit extra
//   candidates but cannot miss a true top-K element. Lane 0 rechecks against the
//   live heap root before replacing it, preserving exactness.
// - No additional device memory is allocated; only dynamic shared memory is used.
//
// Packed heap key:
//   high 32 bits: IEEE-754 bits of the non-negative squared distance
//   low  32 bits: point index (arbitrary tie-break, allowed by the problem)
//
// For non-negative floats, the bit pattern is monotone with the numeric value,
// so unsigned integer comparison gives the correct distance ordering.

using ResultPair = std::pair<int, float>;
using PackedKey  = unsigned long long;

constexpr int      WARP_SIZE         = 32;
constexpr int      BLOCK_THREADS     = 256;                // 8 warps / CTA
constexpr int      WARPS_PER_BLOCK   = BLOCK_THREADS / WARP_SIZE;
constexpr int      DATA_TILE_POINTS  = 1024;               // 8 KiB of float2
constexpr int      LOADS_PER_THREAD  = DATA_TILE_POINTS / BLOCK_THREADS; // 4
constexpr int      DATA_TILE_CHUNKS  = DATA_TILE_POINTS / WARP_SIZE;     // 32
constexpr unsigned FULL_MASK         = 0xFFFFFFFFu;
constexpr PackedKey PACKED_INF       = ~PackedKey{0};

static_assert(BLOCK_THREADS % WARP_SIZE == 0, "BLOCK_THREADS must be a multiple of warp size.");
static_assert(DATA_TILE_POINTS % BLOCK_THREADS == 0, "Tile size must divide evenly across the CTA.");
static_assert(DATA_TILE_POINTS % WARP_SIZE == 0, "Tile size must divide evenly across a warp.");
static_assert(sizeof(float2) == 8, "This kernel assumes float2 is 8 bytes.");

__device__ __forceinline__ PackedKey pack_key(const float dist, const int idx) {
    return (static_cast<PackedKey>(__float_as_uint(dist)) << 32) |
           static_cast<PackedKey>(static_cast<unsigned int>(idx));
}

__device__ __forceinline__ float unpack_dist(const PackedKey key) {
    return __uint_as_float(static_cast<unsigned int>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(const PackedKey key) {
    return static_cast<int>(static_cast<unsigned int>(key));
}

// Explicit 64-bit shuffle helper. Using two 32-bit shuffles is portable across
// CUDA toolchains and avoids relying on a 64-bit overload being present.
__device__ __forceinline__ PackedKey shfl_packed_key(const PackedKey value, const int src_lane) {
    const unsigned lo = __shfl_sync(FULL_MASK, static_cast<unsigned>(value),       src_lane);
    const unsigned hi = __shfl_sync(FULL_MASK, static_cast<unsigned>(value >> 32), src_lane);
    return (static_cast<PackedKey>(hi) << 32) | static_cast<PackedKey>(lo);
}

__device__ __forceinline__ float squared_l2(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

// Build a fixed-size max-heap in-place. Only lane 0 of a warp calls this, so a
// simple serial heapify is best.
template <int K>
__device__ __forceinline__ void build_max_heap(PackedKey* heap) {
    for (int parent = (K >> 1) - 1; parent >= 0; --parent) {
        const PackedKey v = heap[parent];
        int root = parent;

        while (true) {
            const int left = (root << 1) + 1;
            if (left >= K) break;

            const int right = left + 1;
            int max_child = left;
            if (right < K && heap[right] > heap[left]) {
                max_child = right;
            }

            if (heap[max_child] <= v) break;
            heap[root] = heap[max_child];
            root = max_child;
        }

        heap[root] = v;
    }
}

// Replace the root if the new key is smaller. Returns whether the heap changed.
// Again, only lane 0 calls this.
template <int K>
__device__ __forceinline__ bool replace_root_if_smaller(PackedKey* heap, const PackedKey key) {
    if (key >= heap[0]) {
        return false;
    }

    int root = 0;
    while (true) {
        const int left = (root << 1) + 1;
        if (left >= K) break;

        const int right = left + 1;
        int max_child = left;
        if (right < K && heap[right] > heap[left]) {
            max_child = right;
        }

        if (heap[max_child] <= key) break;
        heap[root] = heap[max_child];
        root = max_child;
    }

    heap[root] = key;
    return true;
}

// Heapsort turns the max-heap into ascending order, which matches the required
// "j-th nearest neighbor" result layout.
template <int K>
__device__ __forceinline__ void heap_sort_ascending(PackedKey* heap) {
    for (int end = K - 1; end > 0; --end) {
        const PackedKey max_value = heap[0];
        const PackedKey tail      = heap[end];

        int root = 0;
        while (true) {
            const int left = (root << 1) + 1;
            if (left >= end) break;

            const int right = left + 1;
            int max_child = left;
            if (right < end && heap[right] > heap[left]) {
                max_child = right;
            }

            if (heap[max_child] <= tail) break;
            heap[root] = heap[max_child];
            root = max_child;
        }

        heap[root] = tail;
        heap[end]  = max_value;
    }
}

// Coalesced CTA-wide load of one data tile into shared memory.
__device__ __forceinline__ void load_data_tile(
    const float2* __restrict__ data,
    const int tile_base,
    const int tile_count,
    float2* __restrict__ tile,
    const int tid)
{
#pragma unroll
    for (int i = 0; i < LOADS_PER_THREAD; ++i) {
        const int off = tid + i * BLOCK_THREADS;
        if (off < tile_count) {
            tile[off] = data[tile_base + off];
        }
    }
}

// Process a tile for one query-warp.
//
// root_key_lane0 is meaningful only on lane 0; other lanes carry a dummy copy.
// Every chunk uses a broadcast snapshot of the root to prefilter candidates.
// Lane 0 then rechecks each candidate against the live root before replacing.
template <int K>
__device__ __forceinline__ PackedKey process_tile_for_query(
    const float qx,
    const float qy,
    const float2* __restrict__ tile,
    const int tile_base,
    const int tile_count,
    const int start_chunk,
    PackedKey* __restrict__ heap,
    const int lane,
    PackedKey root_key_lane0)
{
    for (int c = start_chunk; c < DATA_TILE_CHUNKS; ++c) {
        const int chunk_base = c * WARP_SIZE;
        if (chunk_base >= tile_count) {
            break;
        }

        const PackedKey root_snapshot = shfl_packed_key(root_key_lane0, 0);
        const int off = chunk_base + lane;

        PackedKey key = PACKED_INF;
        if (off < tile_count) {
            const float2 p = tile[off];
            key = pack_key(squared_l2(qx, qy, p), tile_base + off);
        }

        unsigned candidate_mask = __ballot_sync(FULL_MASK, key < root_snapshot);
        while (candidate_mask) {
            const int src_lane = __ffs(candidate_mask) - 1;
            const PackedKey candidate_key = shfl_packed_key(key, src_lane);

            if (lane == 0) {
                if (replace_root_if_smaller<K>(heap, candidate_key)) {
                    root_key_lane0 = heap[0];
                }
            }

            candidate_mask &= candidate_mask - 1;
        }
    }

    return root_key_lane0;
}

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    ResultPair* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K % WARP_SIZE == 0, "K must be a multiple of warp size.");
    static_assert(K <= DATA_TILE_POINTS, "The fixed data tile must hold the initial K points.");

    // Shared layout:
    //   [ WARPS_PER_BLOCK * K packed heap entries ][ DATA_TILE_POINTS float2 tile ]
    extern __shared__ PackedKey shared_mem[];
    PackedKey* const heaps = shared_mem;
    float2* const tile = reinterpret_cast<float2*>(heaps + WARPS_PER_BLOCK * K);

    const int tid     = static_cast<int>(threadIdx.x);
    const int warp_id = tid >> 5;
    const int lane    = tid & (WARP_SIZE - 1);

    const int query_idx   = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active_query = (query_idx < query_count);

    PackedKey* const my_heap = heaps + warp_id * K;

    // Load the query point once per warp and broadcast to the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(FULL_MASK, qx, 0);
        qy = __shfl_sync(FULL_MASK, qy, 0);
    }

    // First tile: this always contains the first K points, because K <= 1024
    // and data_count >= K. We exploit that to initialize the heap in O(K).
    const int first_tile_count = (data_count < DATA_TILE_POINTS) ? data_count : DATA_TILE_POINTS;
    load_data_tile(data, 0, first_tile_count, tile, tid);
    __syncthreads();

    PackedKey root_key = PACKED_INF;

    if (active_query) {
        constexpr int INIT_CHUNKS = K / WARP_SIZE;

#pragma unroll
        for (int c = 0; c < INIT_CHUNKS; ++c) {
            const int off = c * WARP_SIZE + lane;
            const float2 p = tile[off];
            my_heap[off] = pack_key(squared_l2(qx, qy, p), off);
        }

        // Make the initial K keys visible to lane 0 before heapify.
        __syncwarp(FULL_MASK);

        if (lane == 0) {
            build_max_heap<K>(my_heap);
            root_key = my_heap[0];
        }

        // If K < 1024, the first tile still has trailing points that must be
        // scanned with the now-initialized heap.
        if (K < DATA_TILE_POINTS) {
            root_key = process_tile_for_query<K>(
                qx, qy, tile, 0, first_tile_count, INIT_CHUNKS, my_heap, lane, root_key);
        }
    }

    __syncthreads();

    // Remaining tiles.
    for (int tile_base = DATA_TILE_POINTS; tile_base < data_count; tile_base += DATA_TILE_POINTS) {
        int tile_count = data_count - tile_base;
        if (tile_count > DATA_TILE_POINTS) {
            tile_count = DATA_TILE_POINTS;
        }

        load_data_tile(data, tile_base, tile_count, tile, tid);
        __syncthreads();

        if (active_query) {
            root_key = process_tile_for_query<K>(
                qx, qy, tile, tile_base, tile_count, 0, my_heap, lane, root_key);
        }

        __syncthreads();
    }

    // Sort the final top-K set into ascending order and write out results.
    if (active_query) {
        if (lane == 0) {
            heap_sort_ascending<K>(my_heap);
        }

        // Shared-memory visibility for the warp before parallel stores.
        __syncwarp(FULL_MASK);

        const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
        for (int i = lane; i < K; i += WARP_SIZE) {
            const PackedKey key = my_heap[i];
            result[out_base + static_cast<std::size_t>(i)].first  = unpack_idx(key);
            result[out_base + static_cast<std::size_t>(i)].second = unpack_dist(key);
        }
    }
}

template <int K>
void launch_knn_kernel(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    ResultPair* result)
{
    // Dynamic shared memory:
    //   8 query-heaps * K packed keys + 1024-point data tile
    //
    // 256 threads / CTA is a good balance on A100/H100:
    // it gives 8-way data reuse per tile while still allowing 2 CTAs/SM on
    // A100 even for K=1024 (and 3 CTAs/SM on H100).
    constexpr std::size_t required_shared_bytes =
        static_cast<std::size_t>(WARPS_PER_BLOCK) * static_cast<std::size_t>(K) * sizeof(PackedKey) +
        static_cast<std::size_t>(DATA_TILE_POINTS) * sizeof(float2);

    if (required_shared_bytes > (48u * 1024u)) {
        // K=1024 needs opt-in shared memory on modern data-center GPUs.
        cudaFuncSetAttribute(
            knn_kernel<K>,
            cudaFuncAttributeMaxDynamicSharedMemorySize,
            static_cast<int>(required_shared_bytes));
        cudaFuncSetAttribute(
            knn_kernel<K>,
            cudaFuncAttributePreferredSharedMemoryCarveout,
            100);
    }

    const int grid_x = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // Standard CUDA semantics: the launch is asynchronous with respect to the host.
    knn_kernel<K><<<grid_x, BLOCK_THREADS, required_shared_bytes>>>(
        query, query_count, data, data_count, result);
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_kernel<32>(query, query_count, data, data_count, result);   return;
        case 64:   launch_knn_kernel<64>(query, query_count, data, data_count, result);   return;
        case 128:  launch_knn_kernel<128>(query, query_count, data, data_count, result);  return;
        case 256:  launch_knn_kernel<256>(query, query_count, data, data_count, result);  return;
        case 512:  launch_knn_kernel<512>(query, query_count, data, data_count, result);  return;
        case 1024: launch_knn_kernel<1024>(query, query_count, data, data_count, result); return;
        default:
            // Per the problem statement, k is always valid. Keep the default
            // branch empty so the interface remains total.
            return;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// Exact brute-force k-NN for 2D points.
//
// Main design choices:
//
// 1) One warp owns one query.
//    - 256 threads / CTA => 8 warps / CTA => 8 queries processed together.
//
// 2) The CTA streams the data set through shared memory.
//    - Each loaded data tile is reused by all 8 queries in the CTA.
//    - This is the dominant optimization because the kernel is bandwidth-bound.
//
// 3) Each query keeps an exact top-k as a max-heap in shared memory.
//    - Only lane 0 mutates the heap.
//    - All 32 lanes compute distances and forward only promising candidates
//      to lane 0 via ballot+shuffle.
//
// 4) Heap entries are stored as a single 64-bit key:
//        high 32 bits = float distance bit pattern
//        low  32 bits = integer data index
//    For non-negative floats, unsigned ordering of the high 32 bits matches
//    numeric ordering of the distance, so unsigned 64-bit ordering matches
//    lexicographic ordering by (distance, index).
//    This makes heap comparisons cheap and also lets the final write be a
//    single 64-bit store directly into the pair<int,float> output buffer on
//    the standard little-endian CUDA ABI.
//
// 5) Shared memory budget is fixed at 80 KiB / CTA.
//    - On A100, 2 CTAs/SM fit exactly (163,840 B / SM).
//    - H100 also handles this comfortably.
//    - Tile size is specialized by K so that heap bytes + tile bytes = 80 KiB.

using PackedKnnWord = unsigned long long;

constexpr int KNN_THREADS          = 256;
constexpr int KNN_WARPS_PER_BLOCK  = KNN_THREADS / 32;
constexpr int KNN_SHARED_BYTES     = 80 * 1024;
constexpr int KNN_BATCH_GROUPS     = 4;   // refresh cutoff every 128 points / warp

static_assert(sizeof(int) == 4, "This implementation assumes 32-bit int.");
static_assert(sizeof(float) == 4, "This implementation assumes IEEE-754 float.");
static_assert(sizeof(PackedKnnWord) == 8, "PackedKnnWord must be 64-bit.");
static_assert(sizeof(std::pair<int, float>) == sizeof(PackedKnnWord),
              "This implementation assumes std::pair<int,float> occupies 8 bytes.");

template <int K>
struct KnnConfig {
    static constexpr int HEAP_BYTES  = KNN_WARPS_PER_BLOCK * K * sizeof(PackedKnnWord);
    static constexpr int TILE_POINTS = (KNN_SHARED_BYTES - HEAP_BYTES) / (2 * sizeof(float));

    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "k must be a power of two in [32, 1024].");
    static_assert(TILE_POINTS >= K, "The first tile must be large enough to seed the heap.");
    static_assert((TILE_POINTS % 32) == 0, "Tile size must be warp-aligned.");
    static_assert(2 * TILE_POINTS * static_cast<int>(sizeof(float)) + HEAP_BYTES == KNN_SHARED_BYTES,
                  "Shared-memory layout must exactly match the 80 KiB budget.");
};

__device__ __forceinline__ float sq_l2(const float qx, const float qy,
                                       const float px, const float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

__device__ __forceinline__ PackedKnnWord pack_key(const float dist, const int idx) {
    return (static_cast<PackedKnnWord>(__float_as_uint(dist)) << 32) |
           static_cast<unsigned int>(idx);
}

__device__ __forceinline__ void sift_down_max(PackedKnnWord* heap, int root, const int count) {
    PackedKnnWord value = heap[root];

    for (int child = (root << 1) + 1; child < count; child = (root << 1) + 1) {
        int worst_child = child;
        const int right = child + 1;
        if (right < count && heap[right] > heap[child]) {
            worst_child = right;
        }
        if (heap[worst_child] <= value) {
            break;
        }
        heap[root] = heap[worst_child];
        root = worst_child;
    }

    heap[root] = value;
}

__device__ __forceinline__ void heapify_max(PackedKnnWord* heap, const int count) {
    for (int root = (count >> 1) - 1; root >= 0; --root) {
        sift_down_max(heap, root, count);
    }
}

__device__ __forceinline__ void replace_root_if_better(PackedKnnWord* heap,
                                                       const PackedKnnWord cand,
                                                       const int count) {
    if (cand < heap[0]) {
        heap[0] = cand;
        sift_down_max(heap, 0, count);
    }
}

__device__ __forceinline__ void heapsort_ascending(PackedKnnWord* heap, const int count) {
    for (int end = count - 1; end > 0; --end) {
        const PackedKnnWord tmp = heap[0];
        heap[0] = heap[end];
        heap[end] = tmp;
        sift_down_max(heap, 0, end);
    }
}

__device__ __forceinline__ void load_tile_soa(const float2* __restrict__ data,
                                              const int base,
                                              const int count,
                                              float* __restrict__ tile_x,
                                              float* __restrict__ tile_y) {
    // Shared-memory tile is stored as SoA instead of AoS to avoid 64-bit shared
    // memory bank conflicts when a warp reads consecutive points.
    for (int t = threadIdx.x; t < count; t += KNN_THREADS) {
        const float2 p = data[base + t];
        tile_x[t] = p.x;
        tile_y[t] = p.y;
    }
}

template <int K>
__device__ __forceinline__ void process_tile_for_query(
    const float qx, const float qy,
    const float* __restrict__ tile_x,
    const float* __restrict__ tile_y,
    const int tile_base,
    const int tile_count,
    const int local_start,
    PackedKnnWord* __restrict__ heap) {

    constexpr unsigned FULL_MASK = 0xffffffffu;
    constexpr int GROUP_POINTS = 32 * KNN_BATCH_GROUPS;

    const int lane = threadIdx.x & 31;
    const PackedKnnWord invalid_key = ~PackedKnnWord(0);

    PackedKnnWord cutoff_key =
        __shfl_sync(FULL_MASK, (lane == 0 ? heap[0] : PackedKnnWord(0)), 0);

    for (int group_base = local_start; group_base < tile_count; group_base += GROUP_POINTS) {
        bool heap_changed = false;

        #pragma unroll
        for (int sub = 0; sub < KNN_BATCH_GROUPS; ++sub) {
            const int loc = group_base + (sub << 5) + lane;

            PackedKnnWord cand = invalid_key;
            if (loc < tile_count) {
                const float d = sq_l2(qx, qy, tile_x[loc], tile_y[loc]);
                cand = pack_key(d, tile_base + loc);
            }

            // Using a slightly stale cutoff inside this short group is safe:
            // the heap root only ever decreases, so this can create extra
            // candidate traffic but cannot miss a true top-k element. Lane 0
            // always rechecks against the current heap root before insertion.
            unsigned mask = __ballot_sync(FULL_MASK, loc < tile_count && cand < cutoff_key);

            if (mask) {
                heap_changed = true;
                while (mask) {
                    const int src = __ffs(mask) - 1;
                    const PackedKnnWord candidate = __shfl_sync(FULL_MASK, cand, src);
                    if (lane == 0) {
                        replace_root_if_better(heap, candidate, K);
                    }
                    mask &= mask - 1;
                }
            }
        }

        if (heap_changed) {
            __syncwarp();
            cutoff_key = __shfl_sync(FULL_MASK,
                                     (lane == 0 ? heap[0] : PackedKnnWord(0)),
                                     0);
        }
    }
}

template <int K>
__global__ __launch_bounds__(256, 2)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                PackedKnnWord* __restrict__ result_words) {
    using C = KnnConfig<K>;
    constexpr unsigned FULL_MASK = 0xffffffffu;

    extern __shared__ __align__(8) unsigned char smem[];

    float* const tile_x = reinterpret_cast<float*>(smem);
    float* const tile_y = tile_x + C::TILE_POINTS;
    PackedKnnWord* const heaps = reinterpret_cast<PackedKnnWord*>(tile_y + C::TILE_POINTS);

    const int warp = threadIdx.x >> 5;
    const int lane = threadIdx.x & 31;

    const int query_id = static_cast<int>(blockIdx.x) * KNN_WARPS_PER_BLOCK + warp;
    const bool active = query_id < query_count;

    PackedKnnWord* const my_heap = heaps + warp * K;

    float qx_local = 0.0f;
    float qy_local = 0.0f;
    if (lane == 0 && active) {
        const float2 q = query[query_id];
        qx_local = q.x;
        qy_local = q.y;
    }

    const float qx = __shfl_sync(FULL_MASK, qx_local, 0);
    const float qy = __shfl_sync(FULL_MASK, qy_local, 0);

    // First tile: also seeds the heap. By construction TILE_POINTS >= K.
    int tile_count = (data_count < C::TILE_POINTS) ? data_count : C::TILE_POINTS;
    load_tile_soa(data, 0, tile_count, tile_x, tile_y);
    __syncthreads();

    if (active && lane == 0) {
        for (int i = 0; i < K; ++i) {
            my_heap[i] = pack_key(sq_l2(qx, qy, tile_x[i], tile_y[i]), i);
        }
        heapify_max(my_heap, K);
    }
    __syncwarp();

    if (active && tile_count > K) {
        process_tile_for_query<K>(qx, qy, tile_x, tile_y, 0, tile_count, K, my_heap);
    }
    __syncthreads();

    // Remaining tiles.
    for (int tile_base = C::TILE_POINTS; tile_base < data_count; tile_base += C::TILE_POINTS) {
        tile_count = data_count - tile_base;
        if (tile_count > C::TILE_POINTS) {
            tile_count = C::TILE_POINTS;
        }

        load_tile_soa(data, tile_base, tile_count, tile_x, tile_y);
        __syncthreads();

        if (active) {
            process_tile_for_query<K>(qx, qy, tile_x, tile_y, tile_base, tile_count, 0, my_heap);
        }

        __syncthreads();
    }

    // Convert the max-heap into ascending nearest-neighbor order.
    if (active && lane == 0) {
        heapsort_ascending(my_heap, K);
    }
    __syncwarp();

    if (active) {
        const std::size_t out_base = static_cast<std::size_t>(query_id) * K;
        for (int j = lane; j < K; j += 32) {
            // The packed key stores:
            //   low  32 bits = index
            //   high 32 bits = float distance bits
            // This matches the in-memory layout of pair<int,float> on the
            // little-endian CUDA ABI, so a single 64-bit store writes the
            // required {index, distance} pair.
            result_words[out_base + j] = my_heap[j];
        }
    }
}

template <int K>
inline void launch_knn_impl(const float2* query,
                            const int query_count,
                            const float2* data,
                            const int data_count,
                            PackedKnnWord* result_words) {
    using C = KnnConfig<K>;

    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               KNN_SHARED_BYTES);
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(KNN_THREADS);
    const dim3 grid((query_count + KNN_WARPS_PER_BLOCK - 1) / KNN_WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, KNN_SHARED_BYTES>>>(
        query, query_count, data, data_count, result_words);
}

} // anonymous namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    PackedKnnWord* const result_words = reinterpret_cast<PackedKnnWord*>(result);

    switch (k) {
        case 32:   launch_knn_impl<32>(query, query_count, data, data_count, result_words); break;
        case 64:   launch_knn_impl<64>(query, query_count, data, data_count, result_words); break;
        case 128:  launch_knn_impl<128>(query, query_count, data, data_count, result_words); break;
        case 256:  launch_knn_impl<256>(query, query_count, data, data_count, result_words); break;
        case 512:  launch_knn_impl<512>(query, query_count, data, data_count, result_words); break;
        case 1024: launch_knn_impl<1024>(query, query_count, data, data_count, result_words); break;
        default:   break; // k is guaranteed valid by the caller contract.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

// Exact batched 2D k-NN specialized for very large `data_count` and
// K in {32, 64, 128, 256, 512, 1024}.
//
// Design choices tuned for A100/H100-class GPUs:
// - 256 threads/CTA = 8 warps/CTA, and each warp owns one query.
// - The CTA streams `data` through a 1024-point shared-memory tile reused by all 8 warps,
//   cutting global traffic by 8x relative to one-query-per-block streaming.
// - Each warp keeps its current top-K in a shared-memory max-heap. The heap root is the
//   current worst retained neighbor, so most points are rejected by a single comparison.
// - The first 1024-point tile also seeds the heap for every supported K, so no extra device
//   memory is needed beyond per-CTA shared memory.
//
// The implementation returns squared L2 distances exactly as requested; no square root is taken.

namespace {

constexpr int kWarpSize          = 32;
constexpr int kBlockThreads      = 256;   // 8 warps = 8 queries/CTA.
constexpr int kQueriesPerBlock   = kBlockThreads / kWarpSize;
constexpr int kTilePoints        = 1024;  // 8 KB tile (x,y), chosen to preserve occupancy at K=1024.
constexpr int kTileLoadsPerThread = kTilePoints / kBlockThreads;
constexpr unsigned kFullMask     = 0xFFFFFFFFu;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a whole number of warps.");
static_assert(kTilePoints % kWarpSize == 0, "Tile size must be warp-aligned.");
static_assert(kTileLoadsPerThread * kBlockThreads == kTilePoints, "Tile load shape must be exact.");
static_assert(kTilePoints >= 1024, "The first tile must cover the largest supported K.");

struct alignas(8) Candidate {
    int   index;
    float dist;
};

static_assert(sizeof(Candidate) == 8, "Candidate must remain compact.");

// Squared Euclidean distance in 2D; matches the problem statement exactly.
__device__ __forceinline__ float squared_l2(const float qx, const float qy,
                                            const float px, const float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return __fmaf_rn(dx, dx, dy * dy);
}

// Cooperative global->shared load for one tile.
// Shared storage is SoA (x[], y[]) so warps later issue simple 32-bit shared loads.
__device__ __forceinline__ void load_data_tile(const float2* __restrict__ data,
                                               const int base,
                                               const int data_count,
                                               float* __restrict__ tile_x,
                                               float* __restrict__ tile_y) {
#pragma unroll
    for (int it = 0; it < kTileLoadsPerThread; ++it) {
        const int local = threadIdx.x + it * kBlockThreads;
        const int idx   = base + local;
        if (idx < data_count) {
            const float2 p = data[idx];
            tile_x[local] = p.x;
            tile_y[local] = p.y;
        }
    }
}

// Standard max-heap sift-down on distance only.
// Ties are intentionally left unresolved because the problem statement imposes no tie policy.
__device__ __forceinline__ void heap_sift_down(Candidate* heap, const int size, const int root) {
    Candidate value = heap[root];
    int idx = root;

    while (true) {
        const int left = (idx << 1) + 1;
        if (left >= size) break;

        int child = left;
        const int right = left + 1;
        if (right < size && heap[right].dist > heap[left].dist) {
            child = right;
        }

        if (!(heap[child].dist > value.dist)) break;

        heap[idx] = heap[child];
        idx = child;
    }

    heap[idx] = value;
}

template <int K>
__device__ __forceinline__ void build_max_heap(Candidate* heap) {
#pragma unroll 1
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        heap_sift_down(heap, K, i);
    }
}

template <int K>
__device__ __forceinline__ void heap_sort_ascending(Candidate* heap) {
#pragma unroll 1
    for (int end = K - 1; end > 0; --end) {
        const Candidate tmp = heap[0];
        heap[0] = heap[end];
        heap[end] = tmp;
        heap_sift_down(heap, end, 0);
    }
}

// Process one shared-memory tile against one query/warp.
//
// START_OFFSET is compile-time because the first tile starts at K (the first K points already
// seeded the heap), while all later tiles start at 0.
// PARTIAL is compile-time so the hot full-tile path has no bounds checks; only the final tile
// (or the small-data case) pays for range guarding.
//
// All lanes participate in the ballot/shuffle collectives. Only lane 0 mutates the shared heap.
template <int K, int START_OFFSET, bool PARTIAL>
__device__ __forceinline__ void process_tile_candidates(Candidate* __restrict__ heap,
                                                        const float qx,
                                                        const float qy,
                                                        const float* __restrict__ tile_x,
                                                        const float* __restrict__ tile_y,
                                                        const int base,
                                                        const int valid,
                                                        const int lane) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a supported power of two.");
    static_assert(K % kWarpSize == 0, "K must be warp-aligned.");
    static_assert(START_OFFSET % kWarpSize == 0, "Tile start must be warp-aligned.");
    static_assert(START_OFFSET <= kTilePoints, "Tile start must lie inside the tile.");

    float threshold = (lane == 0) ? heap[0].dist : 0.0f;
    threshold = __shfl_sync(kFullMask, threshold, 0);

#pragma unroll
    for (int off = START_OFFSET; off < kTilePoints; off += kWarpSize) {
        const int local = off + lane;
        const bool in_range = PARTIAL ? (local < valid) : true;

        float dist = 0.0f;
        const int point_index = base + local;

        if (in_range) {
            dist = squared_l2(qx, qy, tile_x[local], tile_y[local]);
        }

        unsigned mask = __ballot_sync(kFullMask, in_range && (dist < threshold));

        while (mask) {
            const int src_lane = __ffs(mask) - 1;
            const float cand_dist = __shfl_sync(kFullMask, dist, src_lane);
            const int cand_index  = __shfl_sync(kFullMask, point_index, src_lane);

            if (lane == 0 && cand_dist < heap[0].dist) {
                heap[0].index = cand_index;
                heap[0].dist  = cand_dist;
                heap_sift_down(heap, K, 0);
            }

            mask &= (mask - 1);
        }

        if (lane == 0) {
            threshold = heap[0].dist;
        }
        threshold = __shfl_sync(kFullMask, threshold, 0);
    }
}

template <int K>
__global__ __launch_bounds__(kBlockThreads, 2)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                std::pair<int, float>* __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a supported power of two.");
    static_assert(K <= kTilePoints, "The seed tile must contain the entire initial top-K set.");

    // Shared layout:
    //   [ per-warp heaps ][ tile_x[1024] ][ tile_y[1024] ]
    extern __shared__ __align__(16) unsigned char smem_raw[];
    Candidate* const heaps = reinterpret_cast<Candidate*>(smem_raw);
    float* const tile_x = reinterpret_cast<float*>(heaps + kQueriesPerBlock * K);
    float* const tile_y = tile_x + kTilePoints;

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp = threadIdx.x >> 5;

    const int query_index = blockIdx.x * kQueriesPerBlock + warp;
    const bool active = query_index < query_count;

    Candidate* const heap = heaps + warp * K;

    // One query per warp; lane 0 loads and broadcasts to the rest of the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_index];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Largest multiple of the tile size not exceeding data_count.
    // All tiles before this boundary are full and use the bounds-check-free hot path.
    const int full_limit = (data_count / kTilePoints) * kTilePoints;

    // Load the first tile. Since kTilePoints == 1024 and K <= 1024, the entire initial seed set
    // lives inside this tile for every supported K.
    load_data_tile(data, 0, data_count, tile_x, tile_y);
    __syncthreads();

    // Seed each warp-local heap with the first K points from the first tile.
    if (active) {
#pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            heap[i].index = i;
            heap[i].dist  = squared_l2(qx, qy, tile_x[i], tile_y[i]);
        }
    }
    __syncwarp(kFullMask);

    if (active && lane == 0) {
        build_max_heap<K>(heap);
    }
    __syncwarp(kFullMask);

    // Process the remainder of the first tile. If data_count < 1024, this is the only tile.
    if (active) {
        if (full_limit > 0) {
            process_tile_candidates<K, K, false>(heap, qx, qy, tile_x, tile_y, 0, 0, lane);
        } else {
            process_tile_candidates<K, K, true>(heap, qx, qy, tile_x, tile_y, 0, data_count, lane);
        }
    }
    __syncthreads();

    // Process remaining full tiles.
    for (int base = kTilePoints; base < full_limit; base += kTilePoints) {
        load_data_tile(data, base, data_count, tile_x, tile_y);
        __syncthreads();

        if (active) {
            process_tile_candidates<K, 0, false>(heap, qx, qy, tile_x, tile_y, base, 0, lane);
        }

        __syncthreads();
    }

    // Process the final partial tile, if any.
    if (full_limit > 0 && full_limit < data_count) {
        load_data_tile(data, full_limit, data_count, tile_x, tile_y);
        __syncthreads();

        if (active) {
            process_tile_candidates<K, 0, true>(heap, qx, qy, tile_x, tile_y,
                                                full_limit, data_count - full_limit, lane);
        }

        __syncthreads();
    }

    // Sort the final heap in ascending distance order so result[i * K + j] is the j-th neighbor.
    if (active && lane == 0) {
        heap_sort_ascending<K>(heap);
    }
    __syncwarp(kFullMask);

    // Write out the sorted results. Fields are assigned individually to avoid relying on any
    // device-side std::pair constructor/assignment support.
    if (active) {
        const size_t out_base = static_cast<size_t>(query_index) * static_cast<size_t>(K);
#pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            result[out_base + static_cast<size_t>(i)].first  = heap[i].index;
            result[out_base + static_cast<size_t>(i)].second = heap[i].dist;
        }
    }
}

template <int K>
inline void launch_knn_specialized(const float2* query,
                                   const int query_count,
                                   const float2* data,
                                   const int data_count,
                                   std::pair<int, float>* result) {
    const size_t shared_bytes =
        static_cast<size_t>(kQueriesPerBlock) * static_cast<size_t>(K) * sizeof(Candidate) +
        static_cast<size_t>(2 * kTilePoints) * sizeof(float);

    // K=1024 exceeds the default 48 KiB dynamic shared-memory limit, so opt in as needed.
    if (shared_bytes > (48u * 1024u)) {
        (void)cudaFuncSetAttribute(
            knn_kernel<K>,
            cudaFuncAttributeMaxDynamicSharedMemorySize,
            static_cast<int>(shared_bytes));
    }

    // This kernel is shared-memory dominated and benefits from maximizing the shared carveout.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks = (query_count + kQueriesPerBlock - 1) / kQueriesPerBlock;

    // Launch is intentionally asynchronous on the current default stream.
    knn_kernel<K><<<blocks, kBlockThreads, shared_bytes>>>(
        query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Runtime dispatch keeps the public interface simple while still giving the kernel compile-time
    // knowledge of K for heap sizing and loop specialization.
    switch (k) {
        case 32:   launch_knn_specialized<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_specialized<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_specialized<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_specialized<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_specialized<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_specialized<1024>(query, query_count, data, data_count, result); break;
        default:
            // The problem statement guarantees valid K, so this path is unreachable for valid input.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn2d_detail {

// Device code should not depend on std::pair constructors/operators from the host standard library.
// The interface, however, is fixed to std::pair<int, float>. We therefore write through an ABI-compatible
// POD view and validate the expected host layout at compile time.
struct alignas(alignof(std::pair<int, float>)) device_result_pair {
    int   first;
    float second;
};

static_assert(sizeof(device_result_pair) == sizeof(std::pair<int, float>),
              "run_knn assumes std::pair<int,float> has the plain {int,float} ABI layout.");
static_assert(alignof(device_result_pair) == alignof(std::pair<int, float>),
              "run_knn assumes std::pair<int,float> has the plain {int,float} ABI alignment.");

// Shared-memory tile and candidate-chunk sizes.
// A 256-point tile is large enough to amortize the block-wide synchronization, while a smaller 128-point
// candidate chunk keeps the per-warp transient buffer small enough that k=1024 still fits in shared memory
// with a useful number of query warps per block on A100/H100-class GPUs.
constexpr int kWarpSize              = 32;
constexpr int kLoadTilePoints        = 256;
constexpr int kCandidateChunkPoints  = 128;
constexpr unsigned kFullMask         = 0xFFFFFFFFu;

// Launch heuristic:
// - Exact 2D distance scans have very low arithmetic intensity, so increasing the number of query warps per block
//   improves reuse of the staged data tile.
// - Past a point, too many warps per block reduce grid-level parallelism and start to overtrade occupancy for reuse.
// - Ampere is best capped around 16 query warps/block; Hopper can afford a slightly higher cap.
// - We then choose the largest value up to that cap that still gives enough blocks to occupy most SMs.
constexpr int kAmperePreferredWarpCap = 16;
constexpr int kHopperPreferredWarpCap = 20;
constexpr int kMinSMCoveragePercent   = 85;

static_assert(kLoadTilePoints % kCandidateChunkPoints == 0, "Tile must be an integer number of candidate chunks.");
static_assert(kCandidateChunkPoints % kWarpSize == 0, "Candidate chunk must be an integer number of warp rounds.");

// Scalar max-heap helpers.
// Only lane 0 of each query warp mutates the heap. This is intentional: for k up to 1024,
// a fully parallel top-k structure would consume much more shared/register state and require
// substantially more synchronization. After the first few chunks the acceptance threshold tightens
// quickly, so heap updates become sparse and the serialized lane-0 maintenance is typically cheap.
__device__ __forceinline__ void sift_down_max(float *dist, int *idx, int root, int size) {
    float root_dist = dist[root];
    int   root_idx  = idx[root];

    int child = (root << 1) + 1;
    while (child < size) {
        int   larger_child = child;
        float larger_dist  = dist[child];

        const int right = child + 1;
        if (right < size) {
            const float right_dist = dist[right];
            if (right_dist > larger_dist) {
                larger_child = right;
                larger_dist  = right_dist;
            }
        }

        if (root_dist >= larger_dist) {
            break;
        }

        dist[root] = larger_dist;
        idx[root]  = idx[larger_child];

        root  = larger_child;
        child = (root << 1) + 1;
    }

    dist[root] = root_dist;
    idx[root]  = root_idx;
}

template <int K>
__device__ __forceinline__ void build_max_heap(float *dist, int *idx) {
    for (int root = (K >> 1) - 1; root >= 0; --root) {
        sift_down_max(dist, idx, root, K);
    }
}

template <int K>
__device__ __forceinline__ void heap_sort_ascending(float *dist, int *idx) {
    for (int end = K - 1; end > 0; --end) {
        const float tmp_dist = dist[end];
        dist[end] = dist[0];
        dist[0]   = tmp_dist;

        const int tmp_idx = idx[end];
        idx[end] = idx[0];
        idx[0]   = tmp_idx;

        sift_down_max(dist, idx, 0, end);
    }
}

// Kernel organization:
// - one warp owns one query,
// - multiple such warps live in the same block,
// - the block stages a tile of database points in shared memory,
// - each warp scans that tile against its query,
// - per-warp intermediate top-k state lives entirely in shared memory (no extra device allocations),
// - the transient candidate buffer is private to each warp and reused chunk by chunk.
template <int K, int LOAD_TILE_POINTS, int CANDIDATE_CHUNK_POINTS>
__global__ __launch_bounds__(1024, 1)
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                device_result_pair * __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert(LOAD_TILE_POINTS % CANDIDATE_CHUNK_POINTS == 0, "Invalid tile/chunk split.");
    static_assert(CANDIDATE_CHUNK_POINTS % kWarpSize == 0, "Chunk size must be a multiple of warp size.");

    const int warps_per_block = blockDim.x / kWarpSize;
    const int warp_id         = threadIdx.x / kWarpSize;
    const int lane            = threadIdx.x & (kWarpSize - 1);

    const int block_query_base = static_cast<int>(blockIdx.x) * warps_per_block;
    if (block_query_base >= query_count) {
        return;
    }

    const int query_idx = block_query_base + warp_id;
    const bool active   = (query_idx < query_count);

    extern __shared__ unsigned char smem_raw[];
    float2 *tile = reinterpret_cast<float2 *>(smem_raw);

    float *heap_dist = reinterpret_cast<float *>(tile + LOAD_TILE_POINTS);
    int   *heap_idx  = reinterpret_cast<int *>(heap_dist + warps_per_block * K);
    float *cand_dist = reinterpret_cast<float *>(heap_idx  + warps_per_block * K);
    int   *cand_idx  = reinterpret_cast<int *>(cand_dist + warps_per_block * CANDIDATE_CHUNK_POINTS);

    float *my_heap_dist = heap_dist + warp_id * K;
    int   *my_heap_idx  = heap_idx  + warp_id * K;
    float *my_cand_dist = cand_dist + warp_id * CANDIDATE_CHUNK_POINTS;
    int   *my_cand_idx  = cand_idx  + warp_id * CANDIDATE_CHUNK_POINTS;

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    int   heap_size = 0;
    float kth       = CUDART_INF_F;

    const unsigned lane_prefix_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
    constexpr int rounds_per_chunk  = CANDIDATE_CHUNK_POINTS / kWarpSize;

    for (int tile_base = 0; tile_base < data_count; tile_base += LOAD_TILE_POINTS) {
        int tile_count = data_count - tile_base;
        if (tile_count > LOAD_TILE_POINTS) {
            tile_count = LOAD_TILE_POINTS;
        }

        // Cooperative global->shared staging of the database tile.
        for (int t = threadIdx.x; t < tile_count; t += blockDim.x) {
            tile[t] = data[tile_base + t];
        }
        __syncthreads();

        // Consume the staged tile in smaller candidate chunks to keep transient per-warp state compact.
        for (int chunk_offset = 0; chunk_offset < tile_count; chunk_offset += CANDIDATE_CHUNK_POINTS) {
            int chunk_count = tile_count - chunk_offset;
            if (chunk_count > CANDIDATE_CHUNK_POINTS) {
                chunk_count = CANDIDATE_CHUNK_POINTS;
            }

            float threshold_lane0 = 0.0f;
            int   heap_full_lane0 = 0;
            if (lane == 0 && active) {
                heap_full_lane0 = (heap_size == K);
                threshold_lane0 = heap_full_lane0 ? kth : CUDART_INF_F;
            }

            const float threshold = __shfl_sync(kFullMask, threshold_lane0, 0);
            const bool  heap_full = (__shfl_sync(kFullMask, heap_full_lane0, 0) != 0);

            int buf_count = 0;

            const float2 *tile_chunk       = tile + chunk_offset;
            const int     global_chunk_base = tile_base + chunk_offset;

#pragma unroll
            for (int round = 0; round < rounds_per_chunk; ++round) {
                const int local = (round << 5) + lane;
                const bool valid = active && (local < chunk_count);

                float dist = 0.0f;
                if (valid) {
                    const float2 p = tile_chunk[local];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                }

                const bool qualify = valid && (!heap_full || (dist < threshold));
                const unsigned qualify_mask = __ballot_sync(kFullMask, qualify);
                const int nqual = __popc(qualify_mask);

                int base = 0;
                if (lane == 0) {
                    base = buf_count;
                    buf_count += nqual;
                }
                base = __shfl_sync(kFullMask, base, 0);

                if (qualify) {
                    const int pos = base + __popc(qualify_mask & lane_prefix_mask);
                    my_cand_dist[pos] = dist;
                    my_cand_idx[pos]  = global_chunk_base + local;
                }
            }

            // All candidate writes for this warp must be visible before lane 0 starts consuming them.
            __syncwarp();

            if (lane == 0 && active && buf_count > 0) {
                int i = 0;

                // Until the first K elements have been collected, simply append.
                // Once K is reached, build the max-heap once and switch to thresholded replacement.
                if (heap_size < K) {
                    int to_copy = K - heap_size;
                    if (to_copy > buf_count) {
                        to_copy = buf_count;
                    }

                    for (; i < to_copy; ++i) {
                        my_heap_dist[heap_size] = my_cand_dist[i];
                        my_heap_idx[heap_size]  = my_cand_idx[i];
                        ++heap_size;
                    }

                    if (heap_size == K) {
                        build_max_heap<K>(my_heap_dist, my_heap_idx);
                    }
                }

                if (heap_size == K) {
                    float current_kth = my_heap_dist[0];

                    for (; i < buf_count; ++i) {
                        const float cand_d = my_cand_dist[i];
                        if (cand_d < current_kth) {
                            my_heap_dist[0] = cand_d;
                            my_heap_idx[0]  = my_cand_idx[i];
                            sift_down_max(my_heap_dist, my_heap_idx, 0, K);
                            current_kth = my_heap_dist[0];
                        }
                    }

                    kth = current_kth;
                } else {
                    kth = CUDART_INF_F;
                }
            }
        }

        // Ensure all warps are finished with the current tile before it is overwritten by the next one.
        __syncthreads();
    }

    if (active) {
        // Final output must be ordered by ascending distance so that result[i*k + j] is the j-th nearest neighbor.
        if (lane == 0) {
            heap_sort_ascending<K>(my_heap_dist, my_heap_idx);
        }

        // The sorted shared-memory heap is now read by all lanes in the warp for coalesced global writes.
        __syncwarp();

        const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
        for (int i = lane; i < K; i += kWarpSize) {
            result[out_base + static_cast<std::size_t>(i)].first  = my_heap_idx[i];
            result[out_base + static_cast<std::size_t>(i)].second = my_heap_dist[i];
        }
    }
}

template <int K>
inline void launch_knn_impl(const float2 *query,
                            int query_count,
                            const float2 *data,
                            int data_count,
                            device_result_pair *result) {
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    int max_optin_smem = 0;
    int sm_count = 1;
    int cc_major = 8;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&max_optin_smem, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaDeviceGetAttribute(&cc_major, cudaDevAttrComputeCapabilityMajor, device);

    if (max_optin_smem <= 0) {
        // Safe fallback for modern devices if the query above unexpectedly fails.
        max_optin_smem = 98304;
    }
    if (sm_count <= 0) {
        sm_count = 1;
    }

    const int arch_preferred_cap = (cc_major >= 9) ? kHopperPreferredWarpCap : kAmperePreferredWarpCap;

    const int tile_bytes      = kLoadTilePoints * static_cast<int>(sizeof(float2));
    const int bytes_per_warp  = (K + kCandidateChunkPoints) * static_cast<int>(sizeof(float) + sizeof(int));

    int shared_cap = (max_optin_smem - tile_bytes) / bytes_per_warp;
    if (shared_cap < 1) {
        shared_cap = 1;
    }
    if (shared_cap > 32) {
        shared_cap = 32;
    }

    int preferred_cap = arch_preferred_cap;
    if (preferred_cap > shared_cap) {
        preferred_cap = shared_cap;
    }
    if (preferred_cap > query_count) {
        preferred_cap = query_count;
    }

    const int min_grid_blocks = (sm_count * kMinSMCoveragePercent + 99) / 100;

    // Pick the largest warps/block that still gives enough blocks to occupy most SMs.
    // This intentionally balances shared-memory data reuse against chip-level concurrency.
    int warps_per_block = preferred_cap;
    while (warps_per_block > 1) {
        const int grid_blocks = (query_count + warps_per_block - 1) / warps_per_block;
        if (grid_blocks >= min_grid_blocks) {
            break;
        }
        --warps_per_block;
    }

    const std::size_t smem_bytes =
        static_cast<std::size_t>(tile_bytes) +
        static_cast<std::size_t>(warps_per_block) * static_cast<std::size_t>(bytes_per_warp);

    (void)cudaFuncSetAttribute(
        knn_kernel<K, kLoadTilePoints, kCandidateChunkPoints>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));

    (void)cudaFuncSetAttribute(
        knn_kernel<K, kLoadTilePoints, kCandidateChunkPoints>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    (void)cudaFuncSetCacheConfig(
        knn_kernel<K, kLoadTilePoints, kCandidateChunkPoints>,
        cudaFuncCachePreferShared);

    const dim3 block(static_cast<unsigned>(warps_per_block * kWarpSize));
    const dim3 grid(static_cast<unsigned>((query_count + warps_per_block - 1) / warps_per_block));

    knn_kernel<K, kLoadTilePoints, kCandidateChunkPoints>
        <<<grid, block, smem_bytes>>>(query, query_count, data, data_count, result);
}

} // namespace knn2d_detail

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    auto *result_view = reinterpret_cast<knn2d_detail::device_result_pair *>(result);

    // k is guaranteed by the interface contract to be a power of two in [32, 1024].
    // Specializing on K lets the compiler see fixed heap sizes and shared-memory layouts.
    switch (k) {
        case 32:
            knn2d_detail::launch_knn_impl<32>(query, query_count, data, data_count, result_view);
            break;
        case 64:
            knn2d_detail::launch_knn_impl<64>(query, query_count, data, data_count, result_view);
            break;
        case 128:
            knn2d_detail::launch_knn_impl<128>(query, query_count, data, data_count, result_view);
            break;
        case 256:
            knn2d_detail::launch_knn_impl<256>(query, query_count, data, data_count, result_view);
            break;
        case 512:
            knn2d_detail::launch_knn_impl<512>(query, query_count, data, data_count, result_view);
            break;
        case 1024:
            knn2d_detail::launch_knn_impl<1024>(query, query_count, data, data_count, result_view);
            break;
        default:
            // Input contract says this does not happen.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>
#include <utility>

namespace {

// Targeted tuning for modern data-center GPUs (A100/H100 class):
// - 8 warps/block: one warp per query, so a block processes 8 queries and reuses one
//   shared-memory data tile across all 8.
// - 4096-point tiles: 32 KiB of shared memory for the cached dataset tile; large
//   enough to amortize block barriers and global-memory latency.
// - Overflow buffer capped at 256 for large K: this keeps the warp-local prune sort
//   small while preserving exactness via an in-place merge into the exact top-K list.
constexpr int kWarpSize        = 32;
constexpr int kWarpsPerBlock   = 8;
constexpr int kThreadsPerBlock = kWarpsPerBlock * kWarpSize;
constexpr int kDataTileSize    = 4096;
constexpr unsigned kFullMask   = 0xffffffffu;

// Distances are non-negative squared L2 values. For non-negative IEEE-754 floats,
// unsigned integer order of the bit pattern matches numerical order. Packing
// [distance_bits | index] into one 64-bit key therefore gives a sortable total
// order without carrying two separate arrays during selection and merge.
constexpr uint64_t kInfKey = (uint64_t{0x7f800000u} << 32) | uint64_t{0xffffffffu};

template <int K, int BUF_CAP>
constexpr std::size_t shared_storage_bytes() {
    return std::size_t(kWarpsPerBlock) * std::size_t(K + BUF_CAP) * sizeof(uint64_t) +
           std::size_t(2) * std::size_t(kDataTileSize) * sizeof(float);
}

__device__ __forceinline__ uint64_t pack_key(float dist, int idx) {
    return (uint64_t(__float_as_uint(dist)) << 32) | static_cast<uint32_t>(idx);
}

__device__ __forceinline__ float unpack_dist(uint64_t key) {
    return __uint_as_float(static_cast<unsigned>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(uint64_t key) {
    return static_cast<int>(static_cast<uint32_t>(key));
}

template <int N>
__device__ __forceinline__ void warp_bitonic_sort(uint64_t* arr, int lane) {
    static_assert((N & (N - 1)) == 0, "Bitonic sort size must be a power of two.");

    // One warp sorts one fixed-size shared-memory array. Each lane owns N/32 slots.
    for (int size = 2; size <= N; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int idx = lane; idx < N; idx += kWarpSize) {
                const int partner = idx ^ stride;
                if (partner > idx) {
                    const bool up = ((idx & size) == 0);
                    const uint64_t a = arr[idx];
                    const uint64_t b = arr[partner];
                    const bool a_le_b = (a <= b);
                    arr[idx]     = (up == a_le_b) ? a : b;
                    arr[partner] = (up == a_le_b) ? b : a;
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

template <int K, int BUF_CAP>
__device__ __forceinline__ void warp_prune(
    uint64_t* top,
    uint64_t* buf,
    int& top_count,
    int& buf_count,
    float& threshold,
    int lane) {

    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert((BUF_CAP & (BUF_CAP - 1)) == 0, "Buffer size must be a power of two.");

    if (buf_count == 0) {
        threshold = (top_count == K) ? unpack_dist(top[K - 1]) : CUDART_INF_F;
        return;
    }

    // Pad the inactive suffix with +inf so a fixed-size bitonic sort can be used.
#pragma unroll
    for (int i = buf_count + lane; i < BUF_CAP; i += kWarpSize) {
        buf[i] = kInfKey;
    }
    __syncwarp(kFullMask);

    warp_bitonic_sort<BUF_CAP>(buf, lane);

    const int merged_count = top_count + buf_count;
    const int new_top_count = (merged_count < K) ? merged_count : K;

    float new_threshold = CUDART_INF_F;

    if (lane == 0) {
        // Exact in-place merge without extra storage:
        // 1) Drop the largest merged_count - new_top_count items by walking the tails
        //    of the two sorted arrays.
        // 2) Merge the remaining prefixes from the back into top[].
        int i = top_count - 1;
        int j = buf_count - 1;
        int to_drop = merged_count - new_top_count;

        while (to_drop > 0) {
            if (j < 0 || (i >= 0 && top[i] >= buf[j])) {
                --i;
            } else {
                --j;
            }
            --to_drop;
        }

        int keep_top = i + 1;
        int keep_buf = j + 1;

        i = keep_top - 1;
        j = keep_buf - 1;
        int out = new_top_count - 1;

        while (j >= 0) {
            if (i >= 0 && top[i] > buf[j]) {
                top[out--] = top[i--];
            } else {
                top[out--] = buf[j--];
            }
        }

        if (new_top_count == K) {
            new_threshold = unpack_dist(top[K - 1]);
        }
    }

    __syncwarp(kFullMask);
    top_count = new_top_count;
    buf_count = 0;
    threshold = __shfl_sync(kFullMask, new_threshold, 0);
}

template <int K, int BUF_CAP>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result) {

    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert((BUF_CAP & (BUF_CAP - 1)) == 0, "Buffer size must be a power of two.");

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int qid     = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_id;
    const bool active = (qid < query_count);

    extern __shared__ uint64_t smem_u64[];

    // Layout of dynamic shared memory:
    // [ per-warp exact top-K keys ][ per-warp overflow buffer ][ tile_x ][ tile_y ]
    uint64_t* const all_top = smem_u64;
    uint64_t* const all_buf = all_top + kWarpsPerBlock * K;

    // The data tile is cached as SoA in shared memory to avoid the 2-way bank
    // conflicts that contiguous float2 accesses would create on 32-bank hardware.
    float* const tile_x = reinterpret_cast<float*>(all_buf + kWarpsPerBlock * BUF_CAP);
    float* const tile_y = tile_x + kDataTileSize;

    uint64_t* const top = all_top + warp_id * K;
    uint64_t* const buf = all_buf + warp_id * BUF_CAP;

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[qid];
        qx = q.x;
        qy = q.y;
    }
    if (active) {
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    int top_count = 0;
    int buf_count = 0;
    float threshold = CUDART_INF_F;

    for (int tile_base = 0; tile_base < data_count; tile_base += kDataTileSize) {
        const int remaining  = data_count - tile_base;
        const int tile_count = (remaining < kDataTileSize) ? remaining : kDataTileSize;

        // Cooperative block-wide load of the current data tile.
#pragma unroll
        for (int i = threadIdx.x; i < kDataTileSize; i += kThreadsPerBlock) {
            if (i < tile_count) {
                const float2 p = data[tile_base + i];
                tile_x[i] = p.x;
                tile_y[i] = p.y;
            }
        }
        __syncthreads();

        if (active) {
            // Process the shared-memory tile in warp-sized batches.
            for (int base = 0; base < tile_count; base += kWarpSize) {
                const int local = base + lane;
                const bool lane_valid = (local < tile_count);

                float dist = 0.0f;
                int global_idx = 0;

                if (lane_valid) {
                    const float dx = qx - tile_x[local];
                    const float dy = qy - tile_y[local];
                    dist = fmaf(dx, dx, dy * dy);
                    global_idx = tile_base + local;
                }

                // Exact thresholded admission:
                // - Before top[] is full, every candidate must be retained.
                // - Once top[] already stores K exact nearest items among the processed
                //   prefix, any candidate with dist >= threshold cannot possibly enter
                //   the final answer, even if buf[] has not been merged yet.
                bool accept = lane_valid && ((top_count < K) || (dist < threshold));
                unsigned mask = __ballot_sync(kFullMask, accept);
                int n = __popc(mask);

                if (n != 0) {
                    // If the current batch would overflow the buffer, first merge the
                    // buffered candidates into the exact top-K list and then reevaluate
                    // the current batch against the tighter threshold.
                    if (buf_count + n > BUF_CAP) {
                        warp_prune<K, BUF_CAP>(top, buf, top_count, buf_count, threshold, lane);
                        accept = lane_valid && ((top_count < K) || (dist < threshold));
                        mask = __ballot_sync(kFullMask, accept);
                        n = __popc(mask);
                    }

                    if (n != 0) {
                        const unsigned prefix_mask = (1u << lane) - 1u;
                        const int rank = __popc(mask & prefix_mask);

                        if (accept) {
                            buf[buf_count + rank] = pack_key(dist, global_idx);
                        }

                        __syncwarp(kFullMask);
                        buf_count += n;

                        if (buf_count == BUF_CAP) {
                            warp_prune<K, BUF_CAP>(top, buf, top_count, buf_count, threshold, lane);
                        }
                    }
                }
            }
        }

        __syncthreads();
    }

    if (active) {
        // Final exact merge of the residual buffer.
        warp_prune<K, BUF_CAP>(top, buf, top_count, buf_count, threshold, lane);

        // The output type is std::pair<int,float>; write only plain data members.
        const std::size_t out_base = static_cast<std::size_t>(qid) * static_cast<std::size_t>(K);
        for (int j = lane; j < K; j += kWarpSize) {
            const uint64_t key = top[j];
            result[out_base + j].first  = unpack_idx(key);
            result[out_base + j].second = unpack_dist(key);
        }
    }
}

template <int K, int BUF_CAP>
void launch_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result) {

    constexpr std::size_t kSmemBytes = shared_storage_bytes<K, BUF_CAP>();

    // Keep the configuration compatible with A100-class hardware as requested.
    static_assert(kSmemBytes <= 163840, "Shared-memory usage exceeds A100 per-block limit.");

    cudaFuncSetAttribute(
        knn_kernel<K, BUF_CAP>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kSmemBytes));

    cudaFuncSetAttribute(
        knn_kernel<K, BUF_CAP>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    knn_kernel<K, BUF_CAP><<<blocks, kThreadsPerBlock, kSmemBytes>>>(
        query, query_count, data, data_count, result);
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {

    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn<32,   32 >(query, query_count, data, data_count, result); break;
        case 64:   launch_knn<64,   64 >(query, query_count, data, data_count, result); break;
        case 128:  launch_knn<128,  128>(query, query_count, data, data_count, result); break;
        case 256:  launch_knn<256,  256>(query, query_count, data, data_count, result); break;
        case 512:  launch_knn<512,  256>(query, query_count, data, data_count, result); break;
        case 1024: launch_knn<1024, 256>(query, query_count, data, data_count, result); break;
        default:
            // Contract says k is always valid; keep the default branch side-effect free.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// Exact 2D squared-L2 k-NN tuned for A100/H100-class GPUs.
//
// Design summary:
//   * One warp computes one query.
//   * A block contains 8 warps = 8 concurrent queries, which lets each shared-memory
//     data tile be reused by 8 queries before the next global-memory fetch.
//   * The database is streamed in 2048-point tiles cached in shared memory.
//   * Each warp keeps a private top-K in shared memory plus a 32-entry candidate buffer.
//   * Distances and indices are packed into one 64-bit key: [distance_bits | index].
//     Because squared distances are non-negative, the IEEE-754 bit pattern is monotonic,
//     so plain integer comparison orders by distance first. The index provides a cheap,
//     deterministic tie-break (any tie resolution is acceptable per the problem statement).
//   * The expensive O(K) top-K merge is amortized by buffering candidates and only
//     sorting/merging when the 32-entry buffer fills or when the scan ends.
//   * No additional device memory is allocated; all scratch state lives in shared memory
//     or registers.

constexpr int kWarpSize        = 32;
constexpr int kWarpsPerBlock   = 8;
constexpr int kThreadsPerBlock = kWarpsPerBlock * kWarpSize;  // 256 threads/block
constexpr int kTilePoints      = 2048;                        // 16 KiB float2 tile
constexpr unsigned kFullMask   = 0xFFFFFFFFu;

using KnnKey = unsigned long long;

// Sentinel "larger than every real candidate" = [ +inf | 0xFFFFFFFF ].
// Every real point has a valid non-negative index, so even a real +inf distance is smaller.
constexpr KnnKey kInvalidKey =
    (static_cast<KnnKey>(0x7F800000u) << 32) | static_cast<KnnKey>(0xFFFFFFFFu);

static_assert(sizeof(KnnKey) == sizeof(float2), "This kernel expects float2 to be 8 bytes.");
static_assert(kTilePoints % kWarpSize == 0, "The shared tile must be a whole number of warps.");

// Shared-memory footprint in 8-byte slots:
//   tile[TILE_POINTS] + topk_cur[WARPS*K] + topk_tmp[WARPS*K] + candidate_buf[WARPS*32]
template <int K>
constexpr std::size_t shared_bytes() {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0,
                  "K must be a power of two in [32, 1024].");
    return static_cast<std::size_t>(kTilePoints + kWarpsPerBlock * (2 * K + kWarpSize)) *
           sizeof(KnnKey);
}

__device__ __forceinline__ KnnKey pack_key(float dist, int idx) {
    return (static_cast<KnnKey>(__float_as_uint(dist)) << 32) |
           static_cast<unsigned int>(idx);
}

__device__ __forceinline__ float unpack_dist(KnnKey key) {
    return __uint_as_float(static_cast<unsigned int>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(KnnKey key) {
    return static_cast<int>(static_cast<unsigned int>(key));
}

// 32-wide bitonic sort using warp shuffles.
// Each lane owns one key; after the network, lane order is ascending.
__device__ __forceinline__ void warp_bitonic_sort_32(KnnKey &key, int lane) {
#pragma unroll
    for (int k = 2; k <= kWarpSize; k <<= 1) {
#pragma unroll
        for (int j = k >> 1; j > 0; j >>= 1) {
            const KnnKey other = __shfl_xor_sync(kFullMask, key, j);

            // Standard bitonic direction logic for shuffle-xor compare/swap.
            const bool up         = ((lane & k) == 0);
            const bool keep_small = (((lane & j) == 0) == up);
            const bool take_other = keep_small ? (other < key) : (key < other);

            if (take_other) {
                key = other;
            }
        }
    }
}

// Merge-path partition for the first "diag" outputs of merging two sorted arrays a and b.
// Returns the number of elements taken from a on that diagonal.
__device__ __forceinline__ int merge_path_partition(
    const KnnKey *a, int a_count,
    const KnnKey *b, int b_count,
    int diag) {

    if (diag <= 0) {
        return 0;
    }
    if (diag >= a_count + b_count) {
        return a_count;
    }

    int low  = diag - b_count;
    int high = diag;

    if (low < 0) {
        low = 0;
    }
    if (high > a_count) {
        high = a_count;
    }

    // Binary search for the first valid partition.
    while (low < high) {
        const int mid = (low + high) >> 1;
        const int j   = diag - mid;

        if (j > 0 && mid < a_count && a[mid] < b[j - 1]) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    int i = low;
    int j = diag - i;

    // One-step correction for the complementary boundary.
    while (i > 0 && j < b_count && b[j] < a[i - 1]) {
        --i;
        ++j;
    }

    return i;
}

// Sorts the warp-private candidate buffer, discards stale entries that are no longer
// better than the latest worst top-K key, then merges the surviving prefix into top-K.
// current_worst_key is an upper bound on the true threshold while the buffer is non-empty;
// that makes lazy buffering exact: we may keep extra candidates, but we never drop a valid one.
template <int K>
__device__ __forceinline__ void flush_candidate_buffer(
    KnnKey *buf,
    int &buf_count,
    KnnKey *&cur_topk,
    KnnKey *&tmp_topk,
    int &current_valid,
    KnnKey &current_worst_key,
    int lane) {

    if (buf_count == 0) {
        return;
    }

    // Make prior shared-memory appends visible within the warp before reading the buffer.
    __syncwarp(kFullMask);

    KnnKey key = (lane < buf_count) ? buf[lane] : kInvalidKey;
    warp_bitonic_sort_32(key, lane);

    // The buffer is now sorted in registers. Only the prefix strictly smaller than the
    // current worst top-K key can still matter.
    const unsigned useful_mask =
        __ballot_sync(kFullMask, (lane < buf_count) && (key < current_worst_key));
    const int useful_count = __popc(useful_mask);

    // Materialize the sorted buffer back to shared memory for indexed merge-path access.
    buf[lane] = key;
    __syncwarp(kFullMask);

    if (useful_count == 0) {
        buf_count = 0;
        return;
    }

    const int new_valid = ((current_valid + useful_count) < K)
                              ? (current_valid + useful_count)
                              : K;

    // Parallel merge of cur_topk[0:current_valid) and buf[0:useful_count),
    // writing the first new_valid outputs into tmp_topk[0:new_valid).
    const int diag_begin = (lane * new_valid) >> 5;          // / 32
    const int diag_end   = ((lane + 1) * new_valid) >> 5;   // / 32

    const int a_begin = merge_path_partition(cur_topk, current_valid, buf, useful_count, diag_begin);
    const int a_end   = merge_path_partition(cur_topk, current_valid, buf, useful_count, diag_end);

    const int b_begin = diag_begin - a_begin;
    const int b_end   = diag_end - a_end;

    int ai = a_begin;
    int bi = b_begin;

    for (int out = diag_begin; out < diag_end; ++out) {
        const bool take_b = (bi < b_end) && (ai >= a_end || buf[bi] < cur_topk[ai]);
        tmp_topk[out] = take_b ? buf[bi++] : cur_topk[ai++];
    }

    __syncwarp(kFullMask);

    KnnKey *old = cur_topk;
    cur_topk = tmp_topk;
    tmp_topk = old;

    current_valid = new_valid;
    buf_count = 0;

    // Threshold for future pruning: if top-K is not full yet, keep using the sentinel
    // so that every real point still qualifies.
    KnnKey new_worst = kInvalidKey;
    if (current_valid == K && lane == 0) {
        new_worst = cur_topk[K - 1];
    }
    current_worst_key = __shfl_sync(kFullMask, new_worst, 0);
}

template <int K>
__global__ __launch_bounds__(kThreadsPerBlock)
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                std::pair<int, float> * __restrict__ result) {
    // One dynamic shared-memory allocation is partitioned into:
    //   [data tile][topk current][topk scratch][candidate buffers]
    // All regions are 8-byte aligned because both float2 and KnnKey are 8 bytes.
    extern __shared__ KnnKey smem64[];

    float2 *tile   = reinterpret_cast<float2 *>(smem64);
    KnnKey *topk0  = smem64 + kTilePoints;
    KnnKey *topk1  = topk0 + kWarpsPerBlock * K;
    KnnKey *cbufs  = topk1 + kWarpsPerBlock * K;

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int qid     = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_id;
    const bool active = (qid < query_count);

    // Warp-private regions in shared memory.
    KnnKey *cur_topk = topk0 + warp_id * K;
    KnnKey *tmp_topk = topk1 + warp_id * K;
    KnnKey *cbuf     = cbufs + warp_id * kWarpSize;

    int current_valid = 0;
    int cbuf_count = 0;
    KnnKey current_worst_key = kInvalidKey;

    // Load the query point once per warp, then broadcast via shuffles.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[qid];
        qx = q.x;
        qy = q.y;
    }
    if (active) {
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    // Stream the database in shared-memory tiles. Every block reuses each tile for 8 queries.
    for (int tile_begin = 0; tile_begin < data_count; tile_begin += kTilePoints) {
        int tile_count = data_count - tile_begin;
        if (tile_count > kTilePoints) {
            tile_count = kTilePoints;
        }

        // Cooperative global -> shared load of the current data tile.
        for (int i = threadIdx.x; i < tile_count; i += kThreadsPerBlock) {
            tile[i] = data[tile_begin + i];
        }
        __syncthreads();

        if (active) {
            // Each chunk maps one data point to one lane.
            for (int chunk = 0; chunk < tile_count; chunk += kWarpSize) {
                const int local_idx = chunk + lane;
                const bool lane_active = (local_idx < tile_count);

                KnnKey candidate_key = kInvalidKey;
                if (lane_active) {
                    const float2 p = tile[local_idx];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    const float dist = fmaf(dx, dx, dy * dy);  // squared L2
                    candidate_key = pack_key(dist, tile_begin + local_idx);
                }

                // A candidate is interesting iff it is strictly smaller than the current
                // worst top-K key. Before top-K is full, current_worst_key is kInvalidKey,
                // so every real point qualifies automatically.
                bool qualifies = lane_active && (candidate_key < current_worst_key);
                unsigned mask = __ballot_sync(kFullMask, qualifies);
                int qualifying_count = __popc(mask);

                if (qualifying_count == 0) {
                    continue;
                }

                // If the append would overflow the 32-entry buffer, first flush the existing
                // buffer, then re-test this chunk against the refreshed threshold.
                if (cbuf_count + qualifying_count > kWarpSize) {
                    flush_candidate_buffer<K>(
                        cbuf, cbuf_count, cur_topk, tmp_topk,
                        current_valid, current_worst_key, lane);

                    qualifies = lane_active && (candidate_key < current_worst_key);
                    mask = __ballot_sync(kFullMask, qualifies);
                    qualifying_count = __popc(mask);

                    if (qualifying_count == 0) {
                        continue;
                    }
                }

                if (qualifies) {
                    const unsigned rank = __popc(mask & ((1u << lane) - 1u));
                    cbuf[cbuf_count + static_cast<int>(rank)] = candidate_key;
                }

                cbuf_count += qualifying_count;

                if (cbuf_count == kWarpSize) {
                    flush_candidate_buffer<K>(
                        cbuf, cbuf_count, cur_topk, tmp_topk,
                        current_valid, current_worst_key, lane);
                }
            }
        }

        // Ensure all warps are done with the current shared tile before the block overwrites it.
        __syncthreads();
    }

    if (active) {
        // Final pending candidates.
        flush_candidate_buffer<K>(
            cbuf, cbuf_count, cur_topk, tmp_topk,
            current_valid, current_worst_key, lane);

        // cur_topk is sorted ascending, so it already matches the required output order.
        const std::size_t out_base = static_cast<std::size_t>(qid) * K;
        for (int i = lane; i < K; i += kWarpSize) {
            const KnnKey key = (i < current_valid) ? cur_topk[i] : kInvalidKey;
            result[out_base + i].first  = unpack_idx(key);
            result[out_base + i].second = unpack_dist(key);
        }
    }
}

template <int K>
inline void launch_knn_specialization(const float2 *query,
                                      int query_count,
                                      const float2 *data,
                                      int data_count,
                                      std::pair<int, float> *result) {
    constexpr std::size_t kSharedBytes = shared_bytes<K>();

    // Opt in to the larger shared-memory allocation used by the bigger K specializations.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kSharedBytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    // Asynchronous launch; caller can synchronize/overlap as desired.
    knn_kernel<K><<<blocks, kThreadsPerBlock, kSharedBytes>>>(
        query, query_count, data, data_count, result);

    // Surface launch-configuration errors without forcing a device-wide sync.
    (void)cudaPeekAtLastError();
}

}  // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_specialization<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_specialization<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_specialization<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_specialization<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_specialization<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_specialization<1024>(query, query_count, data, data_count, result); break;
        default:
            // Inputs are specified to be valid, so this is unreachable under the stated contract.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

// Tuned for modern datacenter GPUs (A100/H100 class):
// - 8 warps/block => 256 threads/block, a good balance between occupancy and
//   per-tile reuse of the streamed data set across queries.
// - 4096-point shared-memory tile => 32 KiB as SoA (x[] + y[]), which fits
//   comfortably while still being large enough to amortize synchronization.
//   It is also larger than the maximum legal K (1024), so the first tile always
//   contains the entire bootstrap set used to seed the top-K frontier.
constexpr int kWarpSize       = 32;
constexpr int kWarpsPerBlock  = 8;
constexpr int kThreadsPerBlock = kWarpsPerBlock * kWarpSize;
constexpr int kTilePoints     = 4096;
constexpr unsigned kFullMask  = 0xFFFFFFFFu;

using ResultPair = std::pair<int, float>;

__device__ __forceinline__ float sq_l2(const float qx, const float qy,
                                       const float px, const float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

__device__ __forceinline__ bool pair_less(const float da, const int ia,
                                          const float db, const int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

// Cooperative tile load:
// the global input is AoS (float2), but the shared tile is stored as SoA
// (x[] and y[] separately). This avoids the shared-memory bank behavior of
// repeated 64-bit float2 accesses in the hot inner loop.
template <int THREADS>
__device__ __forceinline__
void load_tile_soa(const float2* __restrict__ data,
                   const int base,
                   const int count,
                   float* __restrict__ sh_x,
                   float* __restrict__ sh_y) {
#pragma unroll 4
    for (int i = threadIdx.x; i < count; i += THREADS) {
        const float2 p = data[base + i];
        sh_x[i] = p.x;
        sh_y[i] = p.y;
    }
}

// Each lane owns K/32 entries of the current top-K frontier.
// Dynamic indexing into local arrays is intentionally avoided; all accesses are
// done through fully-unrolled constant-index loops so the compiler can scalarize
// the frontier into registers.
template <int ITEMS_PER_LANE>
__device__ __forceinline__
void refresh_lane_max(const float (&top_dist)[ITEMS_PER_LANE],
                      float& lane_max_val,
                      int& lane_max_slot) {
    lane_max_val  = top_dist[0];
    lane_max_slot = 0;
#pragma unroll
    for (int slot = 1; slot < ITEMS_PER_LANE; ++slot) {
        if (top_dist[slot] > lane_max_val) {
            lane_max_val  = top_dist[slot];
            lane_max_slot = slot;
        }
    }
}

__device__ __forceinline__
void reduce_warp_max(const float lane_max_val,
                     const int lane_max_slot,
                     const int lane,
                     float& warp_max_val,
                     int& warp_max_pos) {
    float best_val = lane_max_val;
    int   best_pos = lane + (lane_max_slot << 5);

#pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        const float other_val = __shfl_down_sync(kFullMask, best_val, offset);
        const int   other_pos = __shfl_down_sync(kFullMask, best_pos, offset);
        if ((other_val > best_val) || ((other_val == best_val) && (other_pos > best_pos))) {
            best_val = other_val;
            best_pos = other_pos;
        }
    }

    warp_max_val = __shfl_sync(kFullMask, best_val, 0);
    warp_max_pos = __shfl_sync(kFullMask, best_pos, 0);
}

template <int ITEMS_PER_LANE>
__device__ __forceinline__
void replace_owner_slot_and_refresh_lane_max(float (&top_dist)[ITEMS_PER_LANE],
                                             int (&top_idx)[ITEMS_PER_LANE],
                                             const int owner_slot,
                                             const float new_dist,
                                             const int new_idx,
                                             float& lane_max_val,
                                             int& lane_max_slot) {
#pragma unroll
    for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
        if (slot == owner_slot) {
            top_dist[slot] = new_dist;
            top_idx[slot]  = new_idx;
        }
    }
    refresh_lane_max(top_dist, lane_max_val, lane_max_slot);
}

// Process one shared-memory tile, in 32-point batches.
// One lane computes one candidate distance per batch; a ballot identifies which
// candidates beat the current threshold (the worst element currently in top-K).
// Qualified candidates are inserted one-by-one. Only the lane owning the current
// worst slot performs the replacement and local re-scan; the warp then reduces
// the per-lane maxima to refresh the acceptance threshold.
template <int ITEMS_PER_LANE>
__device__ __forceinline__
void process_tile_segment(const float* __restrict__ sh_x,
                          const float* __restrict__ sh_y,
                          const int base,
                          const int start,
                          const int count,
                          const float qx,
                          const float qy,
                          const int lane,
                          float (&top_dist)[ITEMS_PER_LANE],
                          int (&top_idx)[ITEMS_PER_LANE],
                          float& lane_max_val,
                          int& lane_max_slot,
                          float& warp_max_val,
                          int& warp_max_pos) {
    for (int pos_base = start; pos_base < count; pos_base += kWarpSize) {
        const int  pos   = pos_base + lane;
        const bool valid = (pos < count);

        float cand_dist = CUDART_INF_F;
        int   cand_idx  = -1;

        if (valid) {
            cand_dist = sq_l2(qx, qy, sh_x[pos], sh_y[pos]);
            cand_idx  = base + pos;
        }

        unsigned pending = __ballot_sync(kFullMask, valid && (cand_dist < warp_max_val));

        while (pending) {
            const int src_lane = __ffs(pending) - 1;
            const float sel_dist = __shfl_sync(kFullMask, cand_dist, src_lane);
            const int   sel_idx  = __shfl_sync(kFullMask, cand_idx,  src_lane);

            // Because the threshold may tighten after earlier insertions from the
            // same 32-point batch, re-check against the current warp threshold.
            if (sel_dist < warp_max_val) {
                const int owner_lane = warp_max_pos & 31;
                const int owner_slot = warp_max_pos >> 5;

                if (lane == owner_lane) {
                    replace_owner_slot_and_refresh_lane_max(
                        top_dist, top_idx, owner_slot, sel_dist, sel_idx,
                        lane_max_val, lane_max_slot
                    );
                }

                // Explicit warp barrier after intra-warp state mutation, per the
                // problem statement's requirement for synchronized communication.
                __syncwarp(kFullMask);
                reduce_warp_max(lane_max_val, lane_max_slot, lane, warp_max_val, warp_max_pos);
            }

            pending &= (pending - 1);
        }
    }
}

// Final ordering: bitonic sort of the K retained candidates.
// The scan stage keeps only an unsorted top-K set, because that minimizes the
// per-point update cost; sorting once at the end is cheaper than maintaining
// global order while streaming millions of points.
template <int K>
__device__ __forceinline__
void warp_bitonic_sort_shared(float* __restrict__ dist,
                              int* __restrict__ idx,
                              const int lane) {
#pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < K; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const bool ascending = ((i & size) == 0);

                    const float di = dist[i];
                    const float dj = dist[j];
                    const int   ii = idx[i];
                    const int   ij = idx[j];

                    const bool do_swap = ascending
                        ? pair_less(dj, ij, di, ii)   // ascending: swap if second < first
                        : pair_less(di, ii, dj, ij);  // descending: swap if first < second

                    if (do_swap) {
                        dist[i] = dj;
                        dist[j] = di;
                        idx[i]  = ij;
                        idx[j]  = ii;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
__launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
__global__ void knn_kernel(const float2* __restrict__ query,
                           const int query_count,
                           const float2* __restrict__ data,
                           const int data_count,
                           ResultPair* __restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");
    static_assert((TILE_POINTS % kWarpSize) == 0, "Tile size must be warp-aligned.");
    static_assert(K <= TILE_POINTS, "First tile must contain the whole bootstrap set.");

    constexpr int ITEMS_PER_LANE = K / kWarpSize;

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_id = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active = (query_id < query_count);

    // Dynamic shared memory is reused for two different phases:
    // 1) during the streaming scan: shared SoA tile (x[] + y[])
    // 2) during final ordering: per-warp scratch buffers for the bitonic sort
    extern __shared__ __align__(16) unsigned char smem_raw[];
    float* const sh_x = reinterpret_cast<float*>(smem_raw);
    float* const sh_y = sh_x + TILE_POINTS;

    // Query coordinates are loaded once by lane 0 and broadcast to the warp.
    float qx_lane0 = 0.0f;
    float qy_lane0 = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_id];
        qx_lane0 = q.x;
        qy_lane0 = q.y;
    }
    const float qx = __shfl_sync(kFullMask, qx_lane0, 0);
    const float qy = __shfl_sync(kFullMask, qy_lane0, 0);

    // Private top-K frontier for this query, striped across the warp lanes.
    float top_dist[ITEMS_PER_LANE];
    int   top_idx[ITEMS_PER_LANE];

    float lane_max_val = 0.0f;
    int   lane_max_slot = 0;
    float warp_max_val = 0.0f;
    int   warp_max_pos = 0;

    // ---------------------------
    // First tile: bootstrap top-K
    // ---------------------------
    const int first_tile_count = (data_count < TILE_POINTS) ? data_count : TILE_POINTS;
    load_tile_soa<WARPS_PER_BLOCK * kWarpSize>(data, 0, first_tile_count, sh_x, sh_y);
    __syncthreads();

    if (active) {
        // Seed the frontier directly with the first K points.
#pragma unroll
        for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
            const int pos = lane + (slot << 5);
            top_dist[slot] = sq_l2(qx, qy, sh_x[pos], sh_y[pos]);
            top_idx[slot]  = pos;
        }

        refresh_lane_max(top_dist, lane_max_val, lane_max_slot);
        reduce_warp_max(lane_max_val, lane_max_slot, lane, warp_max_val, warp_max_pos);

        // Process the remainder of the first tile with the normal streaming update.
        process_tile_segment(
            sh_x, sh_y,
            /*base=*/0,
            /*start=*/K,
            /*count=*/first_tile_count,
            qx, qy, lane,
            top_dist, top_idx,
            lane_max_val, lane_max_slot,
            warp_max_val, warp_max_pos
        );
    }

    __syncthreads();

    // ------------------------------------------
    // Remaining tiles: full streaming scan phase
    // ------------------------------------------
    for (int base = TILE_POINTS; base < data_count; base += TILE_POINTS) {
        const int tile_count = ((data_count - base) < TILE_POINTS) ? (data_count - base) : TILE_POINTS;

        load_tile_soa<WARPS_PER_BLOCK * kWarpSize>(data, base, tile_count, sh_x, sh_y);
        __syncthreads();

        if (active) {
            process_tile_segment(
                sh_x, sh_y,
                /*base=*/base,
                /*start=*/0,
                /*count=*/tile_count,
                qx, qy, lane,
                top_dist, top_idx,
                lane_max_val, lane_max_slot,
                warp_max_val, warp_max_pos
            );
        }

        __syncthreads();
    }

    // ---------------------------
    // Final sort and result write
    // ---------------------------
    if (active) {
        // Reuse the same dynamic shared-memory allocation as per-warp scratch.
        float* const sort_dist_all = reinterpret_cast<float*>(smem_raw);
        int* const sort_idx_all =
            reinterpret_cast<int*>(sort_dist_all + static_cast<size_t>(WARPS_PER_BLOCK) * K);

        float* const warp_sort_dist = sort_dist_all + static_cast<size_t>(warp_id) * K;
        int* const warp_sort_idx    = sort_idx_all  + static_cast<size_t>(warp_id) * K;

#pragma unroll
        for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
            const int pos = lane + (slot << 5);
            warp_sort_dist[pos] = top_dist[slot];
            warp_sort_idx[pos]  = top_idx[slot];
        }
        __syncwarp(kFullMask);

        warp_bitonic_sort_shared<K>(warp_sort_dist, warp_sort_idx, lane);

        const size_t out_base = static_cast<size_t>(query_id) * static_cast<size_t>(K);
#pragma unroll
        for (int pos = lane; pos < K; pos += kWarpSize) {
            result[out_base + pos].first  = warp_sort_idx[pos];
            result[out_base + pos].second = warp_sort_dist[pos];
        }
    }
}

template <int K>
void launch_knn_impl(const float2* query,
                     const int query_count,
                     const float2* data,
                     const int data_count,
                     ResultPair* result) {
    constexpr size_t kTileBytes =
        static_cast<size_t>(2) * kTilePoints * sizeof(float); // x[] + y[]
    constexpr size_t kSortBytes =
        static_cast<size_t>(kWarpsPerBlock) * K * (sizeof(float) + sizeof(int));
    constexpr size_t kSharedBytes = (kTileBytes > kSortBytes) ? kTileBytes : kSortBytes;

    // Opt in to the dynamic shared-memory footprint required by the chosen tile size
    // and by the worst-case final sort buffer (K=1024 => 64 KiB).
    cudaFuncSetAttribute(
        knn_kernel<K, kWarpsPerBlock, kTilePoints>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kSharedBytes)
    );

    // This kernel is explicitly shared-memory centric.
    cudaFuncSetAttribute(
        knn_kernel<K, kWarpsPerBlock, kTilePoints>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100
    );
    cudaFuncSetCacheConfig(
        knn_kernel<K, kWarpsPerBlock, kTilePoints>,
        cudaFuncCachePreferShared
    );

    const dim3 block(kThreadsPerBlock);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    // Deliberately asynchronous: no device-wide synchronization here.
    knn_kernel<K, kWarpsPerBlock, kTilePoints>
        <<<grid, block, kSharedBytes>>>(query, query_count, data, data_count, result);
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

#define KNN_LAUNCH_CASE(KVAL) \
    case KVAL:                \
        launch_knn_impl<KVAL>(query, query_count, data, data_count, result); \
        return

    switch (k) {
        KNN_LAUNCH_CASE(32);
        KNN_LAUNCH_CASE(64);
        KNN_LAUNCH_CASE(128);
        KNN_LAUNCH_CASE(256);
        KNN_LAUNCH_CASE(512);
        KNN_LAUNCH_CASE(1024);
        default:
            // Per the problem statement, k is always valid.
            return;
    }

#undef KNN_LAUNCH_CASE
}

#include <cuda_runtime.h>
#include <utility>
#include <type_traits>
#include <cstddef>

namespace knn_detail {

// Brute-force 2D k-NN specialized for the constraints in the prompt.
//
// Design choices:
//  - One warp computes one query.
//  - A block processes several queries at once, so each global-memory tile of `data` is
//    loaded once and reused by multiple query warps.
//  - Each warp owns a private top-k state stored as a max-heap in shared memory.
//    The heap root is the current worst accepted neighbor / rejection threshold.
//  - Each 32-point batch is processed warp-wide. Distances that do not beat the threshold
//    are rejected with only a compare. Distances that do beat the threshold are serialized
//    through lane 0 using ballots/shuffles; this keeps the common reject path extremely cheap.
//  - The shared-memory tile is stored as SoA (x[] and y[]) instead of float2[] to avoid the
//    64-bit shared-memory access pattern that would otherwise introduce unnecessary bank pressure.
//  - k is specialized at compile time for the six allowed values, so heap loops and per-warp
//    array addressing are constant-folded.

constexpr int WARP_SIZE = 32;
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

// Device code only needs a POD layout-compatible view of std::pair<int,float>.
// The public interface still uses std::pair<int,float>.
struct KnnPair {
    int   first;
    float second;
};

static_assert(std::is_standard_layout<KnnPair>::value, "KnnPair must be standard layout.");
static_assert(std::is_standard_layout<std::pair<int, float>>::value,
              "std::pair<int,float> must be standard layout for raw device storage use.");
static_assert(sizeof(KnnPair) == sizeof(std::pair<int, float>),
              "KnnPair must match std::pair<int,float> size.");
static_assert(alignof(KnnPair) == alignof(std::pair<int, float>),
              "KnnPair must match std::pair<int,float> alignment.");
static_assert(offsetof(KnnPair, first) == offsetof(std::pair<int, float>, first),
              "KnnPair.first must match std::pair<int,float>::first offset.");
static_assert(offsetof(KnnPair, second) == offsetof(std::pair<int, float>, second),
              "KnnPair.second must match std::pair<int,float>::second offset.");

inline int ceil_div_int(int x, int y) {
    return (x + y - 1) / y;
}

// The total number of active query warps is fixed by `query_count`.
// Therefore we maximize warps/block (to maximize tile reuse and cut global traffic)
// subject to still having at least one block available per SM, so that no SM goes idle
// only because the grid is too small.
inline int choose_warps_per_block(int query_count, int sm_count, int max_warps) {
    if (max_warps >= 32 && ceil_div_int(query_count, 32) >= sm_count) return 32;
    if (max_warps >= 16 && ceil_div_int(query_count, 16) >= sm_count) return 16;
    if (max_warps >= 8  && ceil_div_int(query_count, 8)  >= sm_count) return 8;
    return 4;  // Smallest useful block under the stated workload regime.
}

__device__ __forceinline__ float sq_l2_2d(float qx, float qy, float px, float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

// Standard max-heap sift-down on shared-memory arrays.
template <int K>
__device__ __forceinline__ void heap_sift_down(float* dist, int* idx, int root, int size) {
    float v_dist = dist[root];
    int   v_idx  = idx[root];
    int child = (root << 1) + 1;

    #pragma unroll 1
    while (child < size) {
        int max_child = child;
        const int right = child + 1;
        if (right < size && dist[right] > dist[child]) {
            max_child = right;
        }
        if (dist[max_child] <= v_dist) {
            break;
        }
        dist[root] = dist[max_child];
        idx[root]  = idx[max_child];
        root = max_child;
        child = (root << 1) + 1;
    }

    dist[root] = v_dist;
    idx[root]  = v_idx;
}

template <int K>
__device__ __forceinline__ void heap_build(float* dist, int* idx) {
    #pragma unroll 1
    for (int root = (K >> 1) - 1; root >= 0; --root) {
        heap_sift_down<K>(dist, idx, root, K);
    }
}

// Replace heap root with a better candidate and restore the max-heap property.
// This is the hot path for accepted candidates, so it uses the "hole" form rather
// than a store-followed-by-sift to reduce shared-memory traffic.
template <int K>
__device__ __forceinline__ void heap_replace_root(float* dist, int* idx, float new_dist, int new_idx) {
    int root = 0;
    int child = 1;

    #pragma unroll 1
    while (child < K) {
        int max_child = child;
        const int right = child + 1;
        if (right < K && dist[right] > dist[child]) {
            max_child = right;
        }
        if (dist[max_child] <= new_dist) {
            break;
        }
        dist[root] = dist[max_child];
        idx[root]  = idx[max_child];
        root = max_child;
        child = (root << 1) + 1;
    }

    dist[root] = new_dist;
    idx[root]  = new_idx;
}

// Final sort: max-heap -> ascending order, as required by result[i*k + j].
template <int K>
__device__ __forceinline__ void heap_sort_ascending(float* dist, int* idx) {
    #pragma unroll 1
    for (int end = K - 1; end > 0; --end) {
        const float top_dist = dist[0];
        const int   top_idx  = idx[0];
        dist[0]   = dist[end];
        idx[0]    = idx[end];
        dist[end] = top_dist;
        idx[end]  = top_idx;
        heap_sift_down<K>(dist, idx, 0, end);
    }
}

// Warp-wide scan of one shared-memory tile segment.
// Each iteration handles up to 32 candidates (one per lane).
// Only lanes whose candidate beats the current threshold participate in the
// serialized update loop; all other lanes pay only the compare.
template <int K>
__device__ __forceinline__ float scan_tile_segment(
    float qx, float qy,
    const float* tile_x, const float* tile_y,
    int global_base, int local_begin, int local_end,
    float* heap_dist, int* heap_idx,
    int lane, float worst)
{
    #pragma unroll 1
    for (int base = local_begin; base < local_end; base += WARP_SIZE) {
        const int pos = base + lane;

        float dist = 0.0f;
        int   index = -1;
        bool  pending = false;

        if (pos < local_end) {
            dist = sq_l2_2d(qx, qy, tile_x[pos], tile_y[pos]);
            index = global_base + pos;
            pending = (dist < worst);
        }

        while (true) {
            const unsigned pending_mask = __ballot_sync(FULL_MASK, pending);
            if (pending_mask == 0u) {
                break;
            }

            const int src_lane = __ffs(pending_mask) - 1;
            const float cand_dist = __shfl_sync(FULL_MASK, dist, src_lane);
            const int   cand_idx  = __shfl_sync(FULL_MASK, index, src_lane);

            // Only lane 0 mutates the heap; all lanes receive the new threshold by shuffle.
            if (lane == 0) {
                if (cand_dist < worst) {
                    heap_replace_root<K>(heap_dist, heap_idx, cand_dist, cand_idx);
                    worst = heap_dist[0];
                }
            }
            worst = __shfl_sync(FULL_MASK, worst, 0);

            if (lane == src_lane) {
                pending = false;
            }
            if (pending && !(dist < worst)) {
                pending = false;
            }
        }
    }

    return worst;
}

template <int K, int TILE_POINTS>
__global__ __launch_bounds__(1024, 2)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    KnnPair* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert((K % WARP_SIZE) == 0, "K must be a multiple of warp size.");
    static_assert(TILE_POINTS >= K, "The first tile must be large enough to seed the heap.");
    static_assert((TILE_POINTS % WARP_SIZE) == 0, "Tile size should be warp-aligned.");

    const int warps_per_block = blockDim.x >> 5;
    const int warp_id = threadIdx.x >> 5;
    const int lane    = threadIdx.x & (WARP_SIZE - 1);

    const int block_query_base = blockIdx.x * warps_per_block;
    if (block_query_base >= query_count) {
        return;  // Entire block inactive.
    }

    extern __shared__ __align__(16) unsigned char smem_raw[];

    // Shared layout:
    //   tile_x[TILE_POINTS]
    //   tile_y[TILE_POINTS]
    //   heap_dist[warps_per_block][K]
    //   heap_idx [warps_per_block][K]
    float* tile_x = reinterpret_cast<float*>(smem_raw);
    float* tile_y = tile_x + TILE_POINTS;
    float* all_heap_dist = tile_y + TILE_POINTS;
    int*   all_heap_idx  = reinterpret_cast<int*>(all_heap_dist + warps_per_block * K);

    const int q = block_query_base + warp_id;
    const bool active_query = (q < query_count);

    float qx = 0.0f;
    float qy = 0.0f;
    float worst = CUDART_INF_F;
    float* heap_dist = nullptr;
    int*   heap_idx  = nullptr;

    if (active_query) {
        const float2 qp = query[q];
        qx = qp.x;
        qy = qp.y;
        heap_dist = all_heap_dist + warp_id * K;
        heap_idx  = all_heap_idx  + warp_id * K;
    }

    // Process `data` in shared-memory tiles. Two block-wide barriers per tile:
    // one after the load, one before the next overwrite of the tile buffers.
    for (int tile_base = 0; tile_base < data_count; tile_base += TILE_POINTS) {
        int tile_size = data_count - tile_base;
        if (tile_size > TILE_POINTS) {
            tile_size = TILE_POINTS;
        }

        for (int i = threadIdx.x; i < tile_size; i += blockDim.x) {
            const float2 p = data[tile_base + i];
            tile_x[i] = p.x;
            tile_y[i] = p.y;
        }
        __syncthreads();

        if (active_query) {
            if (tile_base == 0) {
                // Seed the private top-k heap from the first K points.
                #pragma unroll
                for (int i = lane; i < K; i += WARP_SIZE) {
                    heap_dist[i] = sq_l2_2d(qx, qy, tile_x[i], tile_y[i]);
                    heap_idx[i]  = i;
                }
                __syncwarp();

                if (lane == 0) {
                    heap_build<K>(heap_dist, heap_idx);
                    worst = heap_dist[0];
                }
                worst = __shfl_sync(FULL_MASK, worst, 0);

                // Continue scanning the rest of the first tile.
                worst = scan_tile_segment<K>(
                    qx, qy, tile_x, tile_y,
                    tile_base, K, tile_size,
                    heap_dist, heap_idx, lane, worst);
            } else {
                worst = scan_tile_segment<K>(
                    qx, qy, tile_x, tile_y,
                    tile_base, 0, tile_size,
                    heap_dist, heap_idx, lane, worst);
            }
        }

        __syncthreads();
    }

    if (active_query) {
        // Convert the max-heap to ascending order so j=0 is the nearest neighbor.
        if (lane == 0) {
            heap_sort_ascending<K>(heap_dist, heap_idx);
        }
        __syncwarp();

        const int out_base = q * K;
        #pragma unroll
        for (int i = lane; i < K; i += WARP_SIZE) {
            result[out_base + i].first  = heap_idx[i];
            result[out_base + i].second = heap_dist[i];
        }
    }
}

template <int K, int TILE_POINTS>
inline void launch_knn_impl(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int warps_per_block)
{
    const int block_threads = warps_per_block * WARP_SIZE;
    const int grid_blocks   = ceil_div_int(query_count, warps_per_block);

    const size_t shared_bytes =
        (size_t(2) * TILE_POINTS + size_t(warps_per_block) * K) * sizeof(float) +
        (size_t(warps_per_block) * K) * sizeof(int);

    // The selected tile sizes are deliberately chosen so this stays within the
    // dynamic shared-memory budgets of A100/H100-class parts while still allowing
    // strong occupancy. Ask the runtime for the required carve-out explicitly.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, TILE_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shared_bytes));

    (void)cudaFuncSetAttribute(
        knn_kernel<K, TILE_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    knn_kernel<K, TILE_POINTS><<<grid_blocks, block_threads, shared_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<KnnPair*>(result));
}

}  // namespace knn_detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    int sm_count = 1;
    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    // Tile-size policy:
    //   k =  32,  64 : 8192 points/tile  (tiny heaps; large tiles reduce synchronization)
    //   k = 128      : 4096 points/tile
    //   k >= 256     : 2048 points/tile  (keeps large per-warp heaps within the shared budget
    //                                     even for many warps/block)
    using namespace knn_detail;

    switch (k) {
        case 32: {
            const int wpb = choose_warps_per_block(query_count, sm_count, 32);
            launch_knn_impl<32, 8192>(query, query_count, data, data_count, result, wpb);
            return;
        }
        case 64: {
            const int wpb = choose_warps_per_block(query_count, sm_count, 32);
            launch_knn_impl<64, 8192>(query, query_count, data, data_count, result, wpb);
            return;
        }
        case 128: {
            const int wpb = choose_warps_per_block(query_count, sm_count, 32);
            launch_knn_impl<128, 4096>(query, query_count, data, data_count, result, wpb);
            return;
        }
        case 256: {
            const int wpb = choose_warps_per_block(query_count, sm_count, 32);
            launch_knn_impl<256, 2048>(query, query_count, data, data_count, result, wpb);
            return;
        }
        case 512: {
            const int wpb = choose_warps_per_block(query_count, sm_count, 16);
            launch_knn_impl<512, 2048>(query, query_count, data, data_count, result, wpb);
            return;
        }
        case 1024: {
            const int wpb = choose_warps_per_block(query_count, sm_count, 8);
            launch_knn_impl<1024, 2048>(query, query_count, data, data_count, result, wpb);
            return;
        }
        default:
            // Per prompt, k is always valid; this path is only a defensive no-op.
            return;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace detail {

// Exact 2D k-NN for squared Euclidean distance.
//
// Design:
//   * One warp owns one query for the whole scan.
//   * A block stages the data set into shared-memory tiles so each global load is reused by many queries.
//   * The current top-k for a query is kept as an unsorted warp-private set distributed across the 32 lanes:
//       - each lane owns K/32 (distance, index) pairs in registers;
//       - the warp also tracks the current worst element in that set.
//   * Exactness does not require the set to stay sorted while scanning:
//       - if a new candidate is not better than the current worst, it cannot enter the top-k;
//       - otherwise it replaces one current worst element;
//       - this preserves the exact k smallest distances seen so far.
//   * Sorting is deferred until the very end, where each warp performs one bitonic sort over its final K pairs
//     and writes the results in ascending distance order.
//
// No additional device allocations are used. The same dynamic shared-memory buffer is deliberately overlaid:
//   * during the scan it is interpreted as a float2 tile of data points;
//   * after the scan it is reinterpreted as per-warp scratch for the final bitonic sort.
// The two lifetimes do not overlap, so the required shared memory is only max(tile_bytes, sort_scratch_bytes).

constexpr int kWarpSize = 32;
constexpr unsigned int kFullMask = 0xFFFFFFFFu;

struct alignas(8) Candidate {
    float dist;
    int idx;
};

struct ArgMaxPair {
    float dist;
    int lane;
};

__device__ __forceinline__ float sq_l2_2d(const float qx, const float qy, const float2& p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

template <int M>
__device__ __forceinline__ void recompute_local_worst(
    const float (&best_dist)[M],
    float& local_worst_dist,
    int& local_worst_slot) {
    local_worst_dist = best_dist[0];
    local_worst_slot = 0;
#pragma unroll
    for (int i = 1; i < M; ++i) {
        if (best_dist[i] > local_worst_dist) {
            local_worst_dist = best_dist[i];
            local_worst_slot = i;
        }
    }
}

// Warp-wide arg-max over one value per lane.
// The physical lane id is kept separate from the "best lane" carried by the reduction.
__device__ __forceinline__ ArgMaxPair warp_argmax(const float value_in, const int lane) {
    float best_value = value_in;
    int best_lane = lane;

#pragma unroll
    for (int offset = kWarpSize >> 1; offset > 0; offset >>= 1) {
        const float other_value = __shfl_down_sync(kFullMask, best_value, offset);
        const int other_lane = __shfl_down_sync(kFullMask, best_lane, offset);

        if (lane < kWarpSize - offset) {
            // Ties are arbitrary for correctness; choosing the smaller lane makes the owner deterministic.
            if ((other_value > best_value) || (other_value == best_value && other_lane < best_lane)) {
                best_value = other_value;
                best_lane = other_lane;
            }
        }
    }

    ArgMaxPair out;
    out.dist = __shfl_sync(kFullMask, best_value, 0);
    out.lane = __shfl_sync(kFullMask, best_lane, 0);
    return out;
}

// Warp-synchronous exact insertion into the distributed unsorted top-k.
// __shfl_sync / warp_argmax synchronize the participating warp lanes, so no extra __syncwarp() is needed here.
template <int M>
__device__ __forceinline__ void try_insert_candidate(
    const float cand_dist,
    const int cand_idx,
    float (&best_dist)[M],
    int (&best_idx)[M],
    float& local_worst_dist,
    int& local_worst_slot,
    float& global_worst_dist,
    int& global_worst_lane,
    const int lane) {
    if (cand_dist < global_worst_dist) {
        if (lane == global_worst_lane) {
            best_dist[local_worst_slot] = cand_dist;
            best_idx[local_worst_slot] = cand_idx;
            recompute_local_worst(best_dist, local_worst_dist, local_worst_slot);
        }

        const ArgMaxPair argmax = warp_argmax(local_worst_dist, lane);
        global_worst_dist = argmax.dist;
        global_worst_lane = argmax.lane;
    }
}

__device__ __forceinline__ bool candidate_less(const Candidate& a, const Candidate& b) {
    // Distances are the primary key. The index tie-break only makes the final order deterministic;
    // the problem statement allows any tie resolution.
    return (a.dist < b.dist) || (a.dist == b.dist && a.idx < b.idx);
}

template <int K>
__device__ __forceinline__ void sort_and_store_results(
    const float (&best_dist)[K / kWarpSize],
    const int (&best_idx)[K / kWarpSize],
    Candidate* warp_scratch,
    std::pair<int, float>* result_base,
    const int lane) {
    constexpr int M = K / kWarpSize;

    // Materialize the warp-private register state into shared memory once.
#pragma unroll
    for (int slot = 0; slot < M; ++slot) {
        const int pos = slot * kWarpSize + lane;
        warp_scratch[pos].dist = best_dist[slot];
        warp_scratch[pos].idx = best_idx[slot];
    }
    __syncwarp();

    // Final exact ordering: bitonic sort over K elements, one warp per query.
    // This is done once per query, so it is much cheaper than maintaining a fully sorted list during the scan.
#pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < K; i += kWarpSize) {
                const int ixj = i ^ stride;
                if (ixj > i) {
                    Candidate a = warp_scratch[i];
                    Candidate b = warp_scratch[ixj];
                    const bool ascending = ((i & size) == 0);
                    const bool do_swap = ascending ? candidate_less(b, a) : candidate_less(a, b);
                    if (do_swap) {
                        warp_scratch[i] = b;
                        warp_scratch[ixj] = a;
                    }
                }
            }
            __syncwarp();
        }
    }

    // Write sorted results back in row-major order.
    for (int pos = lane; pos < K; pos += kWarpSize) {
        result_base[pos].first = warp_scratch[pos].idx;
        result_base[pos].second = warp_scratch[pos].dist;
    }
}

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    std::pair<int, float>* __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert(K % kWarpSize == 0, "K must be divisible by the warp size.");
    static_assert(TILE_POINTS >= K, "The first tile must be large enough to seed the initial exact top-k.");
    static_assert(WARPS_PER_BLOCK > 0 && WARPS_PER_BLOCK * kWarpSize <= 1024, "Invalid block size.");

    constexpr int M = K / kWarpSize;

    const int tid = threadIdx.x;
    const int lane = tid & (kWarpSize - 1);
    const int warp_in_block = tid >> 5;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_in_block;
    const bool active = query_idx < query_count;

    extern __shared__ __align__(8) unsigned char smem[];
    float2* const data_tile = reinterpret_cast<float2*>(smem);

    // Shared-memory overlay:
    //   * phase 1: smem[0 .. tile_bytes) is a float2 tile
    //   * phase 2: smem[0 .. scratch_bytes) is Candidate scratch for all warps in the block
    Candidate* const sort_scratch = reinterpret_cast<Candidate*>(smem);
    Candidate* const my_scratch = sort_scratch + warp_in_block * K;

    const float qx = active ? query[query_idx].x : 0.0f;
    const float qy = active ? query[query_idx].y : 0.0f;

    // Warp-private distributed top-k state, fully resident in registers.
    float best_dist[M];
    int best_idx[M];

    float local_worst_dist = 0.0f;
    int local_worst_slot = 0;
    float global_worst_dist = CUDART_INF_F;
    int global_worst_lane = 0;

    // Main scan: process the entire data set in shared-memory tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_POINTS) {
        int tile_count = data_count - tile_start;
        if (tile_count > TILE_POINTS) {
            tile_count = TILE_POINTS;
        }

        // Cooperative block-wide load from global memory to shared memory.
        for (int i = tid; i < tile_count; i += blockDim.x) {
            data_tile[i] = data[tile_start + i];
        }
        __syncthreads();

        if (active) {
            if (tile_start == 0) {
                // Seed the exact top-k with the first K points.
                // This avoids a costly "empty-to-full" insertion phase and is exact because K <= TILE_POINTS.
#pragma unroll
                for (int slot = 0; slot < M; ++slot) {
                    const int local_idx = slot * kWarpSize + lane;
                    const float d = sq_l2_2d(qx, qy, data_tile[local_idx]);
                    best_dist[slot] = d;
                    best_idx[slot] = local_idx;  // tile_start == 0 here, so local index is the global index.
                }

                recompute_local_worst(best_dist, local_worst_dist, local_worst_slot);
                const ArgMaxPair argmax = warp_argmax(local_worst_dist, lane);
                global_worst_dist = argmax.dist;
                global_worst_lane = argmax.lane;
            }

            // The first K points of the first tile are already consumed by initialization.
            const int begin = (tile_start == 0) ? K : 0;

            // Process one 32-point group at a time so the warp stays synchronized.
            // Each lane computes one distance; any candidate better than the current threshold is inserted exactly.
            for (int group_base = begin; group_base < tile_count; group_base += kWarpSize) {
                const int local_idx = group_base + lane;

                float d = CUDART_INF_F;
                if (local_idx < tile_count) {
                    d = sq_l2_2d(qx, qy, data_tile[local_idx]);
                }

                // Lanes whose candidate is currently below the global worst enter the mask.
                // The mask is based on the threshold at the beginning of the 32-point group.
                // After every successful insertion the threshold can only decrease, so each candidate is rechecked
                // before insertion to preserve exactness.
                unsigned int mask = __ballot_sync(kFullMask, d < global_worst_dist);

                while (mask != 0u) {
                    const int src_lane = __ffs(mask) - 1;
                    const float cand_dist = __shfl_sync(kFullMask, d, src_lane);
                    const int cand_idx = tile_start + group_base + src_lane;

                    try_insert_candidate(
                        cand_dist,
                        cand_idx,
                        best_dist,
                        best_idx,
                        local_worst_dist,
                        local_worst_slot,
                        global_worst_dist,
                        global_worst_lane,
                        lane);

                    mask &= (mask - 1u);
                }
            }
        }

        // The tile storage is about to be overwritten on the next iteration, so all warps in the block
        // must finish reading it before the next cooperative load.
        __syncthreads();
    }

    // Final phase: reuse the same shared memory as per-warp scratch and sort once.
    if (active) {
        sort_and_store_results<K>(
            best_dist,
            best_idx,
            my_scratch,
            result + static_cast<std::size_t>(query_idx) * K,
            lane);
    }
}

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
inline void launch_knn_specialized(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    std::pair<int, float>* result) {
    constexpr std::size_t tile_bytes = static_cast<std::size_t>(TILE_POINTS) * sizeof(float2);
    constexpr std::size_t scratch_bytes = static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(Candidate);
    constexpr std::size_t shared_bytes = (tile_bytes > scratch_bytes) ? tile_bytes : scratch_bytes;

    // Opt in to large dynamic shared-memory allocations on modern data-center GPUs.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shared_bytes));

    // This kernel intentionally spends shared memory to reduce global traffic, so a shared-heavy carveout is preferred.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    (void)cudaFuncSetCacheConfig(
        knn_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>,
        cudaFuncCachePreferShared);

    const dim3 block(WARPS_PER_BLOCK * kWarpSize);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>
        <<<grid, block, shared_bytes>>>(query, query_count, data, data_count, result);
}

}  // namespace detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    // Launch configurations are tuned for A100/H100-class GPUs:
    //   * small/medium k use 16 warps/block to maximize shared-tile reuse across queries without hurting occupancy;
    //   * k=1024 uses 8 warps/block to stay out of the 1-block/SM regime while still reusing each tile across 8 queries;
    //   * tile size grows with k when it is "free" in shared-memory footprint because the final sort scratch dominates.
    //
    // The launch remains asynchronous, matching conventional CUDA runtime behavior.
    switch (k) {
        case 32:
            detail::launch_knn_specialized<32, 16, 4096>(query, query_count, data, data_count, result);
            break;
        case 64:
            detail::launch_knn_specialized<64, 16, 4096>(query, query_count, data, data_count, result);
            break;
        case 128:
            detail::launch_knn_specialized<128, 16, 4096>(query, query_count, data, data_count, result);
            break;
        case 256:
            detail::launch_knn_specialized<256, 16, 4096>(query, query_count, data, data_count, result);
            break;
        case 512:
            detail::launch_knn_specialized<512, 16, 8192>(query, query_count, data, data_count, result);
            break;
        case 1024:
            detail::launch_knn_specialized<1024, 8, 8192>(query, query_count, data, data_count, result);
            break;
        default:
            // Unreachable for valid inputs (k is guaranteed to be a power of two in [32, 1024]).
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

using ResultPair = std::pair<int, float>;
using U64 = unsigned long long;

// Tuned for modern data-center GPUs.
// - One warp computes one query, exactly as requested.
// - Data points are staged in shared memory in 2D tiles.
// - The tile is stored as SoA (x[] / y[]) instead of float2[] to avoid the shared-memory
//   bank pattern that contiguous 64-bit float2 accesses would create.
// - Each warp owns a private top-k structure: a max-heap of packed (distance, index) pairs.
//   The heap is kept in shared memory, but each warp uses a disjoint slice, so the copy is
//   private to that query.
//
// The tile size is chosen so that the first tile always contains the full warm-up set for the
// largest supported k (1024), which lets us seed the heap entirely from shared memory.
constexpr int kWarpSize      = 32;
constexpr int kMaxSupportedK = 1024;
constexpr int kTilePoints    = 2048;
constexpr size_t kTileSharedBytes = 2ull * kTilePoints * sizeof(float);

static_assert(kTilePoints >= kMaxSupportedK, "The first tile must contain the maximum supported k.");
static_assert((kTilePoints % kWarpSize) == 0, "Tile size must be a multiple of the warp size.");

constexpr int ceil_div_int(const int n, const int d) {
    return (n + d - 1) / d;
}

// Squared distances are always non-negative, so the IEEE-754 bit pattern of the float is
// monotonically ordered as an unsigned integer. We exploit that to compare candidates by
// integer key instead of by a {float,index} struct.
__device__ __forceinline__ unsigned distance_bits_2d(
    const float qx, const float qy,
    const float px, const float py)
{
    const float dx = qx - px;
    const float dy = qy - py;
    const float dist = __fmaf_rn(dx, dx, dy * dy);
    return __float_as_uint(dist);
}

__device__ __forceinline__ U64 pack_key(const unsigned dist_bits, const int idx) {
    return (static_cast<U64>(dist_bits) << 32) | static_cast<unsigned int>(idx);
}

__device__ __forceinline__ U64 make_key(
    const float qx, const float qy,
    const float px, const float py,
    const int idx)
{
    return pack_key(distance_bits_2d(qx, qy, px, py), idx);
}

// Standard binary-heap sift-down. Only lane 0 executes heap maintenance, which is efficient
// because once the heap is warm, only a small fraction of points survive the distance gate.
__device__ __forceinline__ void sift_down(U64* heap, int root, const int n) {
    U64 value = heap[root];

    while (true) {
        int child = (root << 1) + 1;
        if (child >= n) {
            break;
        }

        int best_child = child;
        U64 best_value = heap[child];

        const int right = child + 1;
        if (right < n) {
            const U64 right_value = heap[right];
            if (right_value > best_value) {
                best_child = right;
                best_value = right_value;
            }
        }

        if (best_value <= value) {
            break;
        }

        heap[root] = best_value;
        root = best_child;
    }

    heap[root] = value;
}

template <int K>
__device__ __forceinline__ void build_max_heap(U64* heap) {
#pragma unroll 1
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        sift_down(heap, i, K);
    }
}

template <int K>
__device__ __forceinline__ void heap_sort_ascending(U64* heap) {
#pragma unroll 1
    for (int end = K - 1; end > 0; --end) {
        const U64 tmp = heap[0];
        heap[0] = heap[end];
        heap[end] = tmp;
        sift_down(heap, 0, end);
    }
}

// Process a tile that has already been loaded into shared memory.
// The common path is cheap: every lane computes one distance and only compares it against
// the current worst top-k distance. Only surviving candidates are serialized through lane 0
// for exact heap maintenance.
template <int K>
__device__ __forceinline__ U64 process_loaded_tile(
    U64* heap,
    U64 worst,
    const float qx,
    const float qy,
    const float* sh_x,
    const float* sh_y,
    const int tile_base,
    const int tile_valid,
    const int start_local,
    const int lane)
{
    unsigned worst_dist_bits = static_cast<unsigned>(worst >> 32);

#pragma unroll 1
    for (int local_base = start_local; local_base < tile_valid; local_base += kWarpSize) {
        const int local = local_base + lane;

        bool eligible = false;
        U64 key = ~0ull;

        if (local < tile_valid) {
            const unsigned dist_bits = distance_bits_2d(qx, qy, sh_x[local], sh_y[local]);
            // Tie handling is intentionally minimal: the problem states that any tie resolution
            // is acceptable, so the fast gate only checks the distance.
            eligible = (dist_bits < worst_dist_bits);
            if (eligible) {
                key = pack_key(dist_bits, tile_base + local);
            }
        }

        unsigned mask = __ballot_sync(0xFFFFFFFFu, eligible);
        while (mask != 0u) {
            const int src_lane = __ffs(mask) - 1;
            const U64 candidate = __shfl_sync(0xFFFFFFFFu, key, src_lane);

            U64 new_worst = 0ull;
            if (lane == 0) {
                if (candidate < heap[0]) {
                    heap[0] = candidate;
                    sift_down(heap, 0, K);
                }
                new_worst = heap[0];
            }

            // The shuffle is the warp synchronization point for this update path.
            worst = __shfl_sync(0xFFFFFFFFu, new_worst, 0);
            worst_dist_bits = static_cast<unsigned>(worst >> 32);
            mask &= (mask - 1);
        }
    }

    return worst;
}

// Cooperative block-wide load of one data tile into shared memory.
template <int WARPS_PER_BLOCK>
__device__ __forceinline__ void load_tile_soa(
    const float2* __restrict__ data,
    const int data_count,
    const int tile_base,
    float* sh_x,
    float* sh_y)
{
    constexpr int kThreadsPerBlock = WARPS_PER_BLOCK * kWarpSize;

#pragma unroll 1
    for (int local = threadIdx.x; local < kTilePoints; local += kThreadsPerBlock) {
        const int global_idx = tile_base + local;
        if (global_idx < data_count) {
            const float2 p = data[global_idx];
            sh_x[local] = p.x;
            sh_y[local] = p.y;
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
__launch_bounds__(WARPS_PER_BLOCK * 32)
__global__ void knn2d_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    ResultPair* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32,1024].");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of the warp size.");

    __shared__ float sh_x[kTilePoints];
    __shared__ float sh_y[kTilePoints];
    extern __shared__ U64 sh_heaps[];

    const int tid     = threadIdx.x;
    const int warp_id = tid >> 5;
    const int lane    = tid & (kWarpSize - 1);

    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active = (query_idx < query_count);

    // Warp-private top-k buffer.
    U64* const heap = sh_heaps + static_cast<size_t>(warp_id) * static_cast<size_t>(K);

    // Lane 0 loads the query point once; the warp receives it through shuffles.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(0xFFFFFFFFu, qx, 0);
    qy = __shfl_sync(0xFFFFFFFFu, qy, 0);

    // First tile: guaranteed to contain the full warm-up set because kTilePoints >= max supported K.
    load_tile_soa<WARPS_PER_BLOCK>(data, data_count, 0, sh_x, sh_y);
    __syncthreads();

    const int first_valid = (data_count < kTilePoints) ? data_count : kTilePoints;
    U64 worst = ~0ull;

    if (active) {
        // Seed the heap with the first K candidates from the first shared-memory tile.
        for (int local = lane; local < K; local += kWarpSize) {
            heap[local] = make_key(qx, qy, sh_x[local], sh_y[local], local);
        }

        // The heap contents were written through shared memory, so we need a warp barrier before
        // lane 0 starts heap construction.
        __syncwarp(0xFFFFFFFFu);
        if (lane == 0) {
            build_max_heap<K>(heap);
        }
        __syncwarp(0xFFFFFFFFu);

        worst = __shfl_sync(0xFFFFFFFFu, (lane == 0) ? heap[0] : 0ull, 0);

        // Continue with the rest of the first tile.
        worst = process_loaded_tile<K>(heap, worst, qx, qy, sh_x, sh_y, 0, first_valid, K, lane);
    }

    // Ensure all warps are done with the current shared-memory tile before reusing it.
    __syncthreads();

    // Remaining tiles.
    for (int tile_base = kTilePoints; tile_base < data_count; tile_base += kTilePoints) {
        load_tile_soa<WARPS_PER_BLOCK>(data, data_count, tile_base, sh_x, sh_y);
        __syncthreads();

        if (active) {
            int tile_valid = data_count - tile_base;
            if (tile_valid > kTilePoints) {
                tile_valid = kTilePoints;
            }
            worst = process_loaded_tile<K>(heap, worst, qx, qy, sh_x, sh_y, tile_base, tile_valid, 0, lane);
        }

        __syncthreads();
    }

    if (active) {
        // Convert the max-heap to ascending order so result[i * k + j] is the j-th nearest neighbor.
        if (lane == 0) {
            heap_sort_ascending<K>(heap);
        }

        // Shared-memory hand-off from lane 0 to the full warp.
        __syncwarp(0xFFFFFFFFu);

        ResultPair* const out = result + static_cast<size_t>(query_idx) * static_cast<size_t>(K);

        // Write std::pair members individually so device code does not depend on std::pair
        // constructors or assignment operators being device-callable.
        for (int local = lane; local < K; local += kWarpSize) {
            const U64 key = heap[local];
            out[local].first  = static_cast<int>(static_cast<unsigned int>(key));
            out[local].second = __uint_as_float(static_cast<unsigned int>(key >> 32));
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
constexpr size_t dynamic_shared_bytes() {
    return static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(K) * sizeof(U64);
}

template <int K, int WARPS_PER_BLOCK>
constexpr size_t total_shared_bytes() {
    return kTileSharedBytes + dynamic_shared_bytes<K, WARPS_PER_BLOCK>();
}

template <int K, int WARPS_PER_BLOCK>
inline void launch_knn_specialized(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    ResultPair* result)
{
    constexpr int kThreadsPerBlock = WARPS_PER_BLOCK * kWarpSize;
    constexpr size_t kDynamicShared = dynamic_shared_bytes<K, WARPS_PER_BLOCK>();

    // Ask the runtime for the shared-memory-heavy configuration needed by this specialization.
    (void)cudaFuncSetAttribute(
        knn2d_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    (void)cudaFuncSetAttribute(
        knn2d_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kDynamicShared));

    const dim3 block(kThreadsPerBlock);
    const dim3 grid(ceil_div_int(query_count, WARPS_PER_BLOCK));

    knn2d_kernel<K, WARPS_PER_BLOCK>
        <<<grid, block, kDynamicShared>>>(query, query_count, data, data_count, result);
}

// Runtime policy for the number of warps per block.
//
// Larger blocks improve data-tile reuse because more queries consume the same shared-memory tile.
// Smaller blocks produce more grid blocks, which matters when the query batch is only in the
// low-thousands. The heuristic below keeps roughly 75% of the SM count covered by grid blocks
// and otherwise maximizes reuse.
template <int K>
inline int choose_warps_per_block(
    const int query_count,
    const int sm_count,
    const int max_optin_shared)
{
    const int min_grid_blocks = (3 * sm_count + 3) / 4;  // ceil(0.75 * sm_count)
    const size_t max_shared = static_cast<size_t>(max_optin_shared);

    if (total_shared_bytes<K, 32>() <= max_shared && ceil_div_int(query_count, 32) >= min_grid_blocks) return 32;
    if (total_shared_bytes<K, 16>() <= max_shared && ceil_div_int(query_count, 16) >= min_grid_blocks) return 16;
    if (total_shared_bytes<K,  8>() <= max_shared && ceil_div_int(query_count,  8) >= min_grid_blocks) return 8;
    if (total_shared_bytes<K,  4>() <= max_shared && ceil_div_int(query_count,  4) >= min_grid_blocks) return 4;
    if (total_shared_bytes<K,  2>() <= max_shared && ceil_div_int(query_count,  2) >= min_grid_blocks) return 2;
    return 1;
}

// k is runtime but only takes six values, so we fully specialize on K. That lets the compiler
// constant-fold heap sizes, warm-up loops, and output loops.
template <int K>
inline void launch_knn_for_k(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    ResultPair* result,
    const int sm_count,
    const int max_optin_shared)
{
    switch (choose_warps_per_block<K>(query_count, sm_count, max_optin_shared)) {
        case 32: launch_knn_specialized<K, 32>(query, query_count, data, data_count, result); break;
        case 16: launch_knn_specialized<K, 16>(query, query_count, data, data_count, result); break;
        case 8:  launch_knn_specialized<K,  8>(query, query_count, data, data_count, result); break;
        case 4:  launch_knn_specialized<K,  4>(query, query_count, data, data_count, result); break;
        case 2:  launch_knn_specialized<K,  2>(query, query_count, data, data_count, result); break;
        default: launch_knn_specialized<K,  1>(query, query_count, data, data_count, result); break;
    }
}

}  // namespace

void run_knn(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    std::pair<int, float>* result,
    const int k)
{
    if (query_count <= 0) {
        return;
    }

    // Conservative defaults are used only if the attribute queries fail; on the target A100/H100
    // class GPUs, these calls succeed and provide the actual device limits.
    int device = 0;
    int sm_count = 128;
    int max_optin_shared = 48 * 1024;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaDeviceGetAttribute(&max_optin_shared, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    switch (k) {
        case 32:   launch_knn_for_k<32>(query, query_count, data, data_count, result, sm_count, max_optin_shared); break;
        case 64:   launch_knn_for_k<64>(query, query_count, data, data_count, result, sm_count, max_optin_shared); break;
        case 128:  launch_knn_for_k<128>(query, query_count, data, data_count, result, sm_count, max_optin_shared); break;
        case 256:  launch_knn_for_k<256>(query, query_count, data, data_count, result, sm_count, max_optin_shared); break;
        case 512:  launch_knn_for_k<512>(query, query_count, data, data_count, result, sm_count, max_optin_shared); break;
        case 1024: launch_knn_for_k<1024>(query, query_count, data, data_count, result, sm_count, max_optin_shared); break;
        default:
            // Inputs are specified to be valid; this path exists only as a defensive no-op.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

// Exact 2D k-NN for large data sets on Ampere/Hopper-class GPUs.
//
// Design choices:
//
// 1) One warp computes one query exactly, as requested.
// 2) A block processes several queries at once so that one shared-memory tile of `data`
//    is reused by multiple warps/queries before the next global-memory load.
// 3) Each query owns a private top-k buffer stored as a warp-private max-heap in shared
//    memory.  The heap root is the current admission threshold.
// 4) All 32 lanes evaluate candidate distances in parallel.  Heap updates are performed
//    by lane 0 only.  This is intentional and efficient for exact top-k selection:
//    after the first few batches, accepted replacements become rare, so serializing only
//    the rare heap updates is substantially cheaper than forcing a full warp-wide sort or
//    merge on every candidate.
// 5) Tiles are single-buffered on purpose.  For K=512/1024 the per-warp heaps already
//    dominate shared-memory usage, and keeping occupancy high is more valuable than
//    double-buffering the data tile.
//
// Distances are squared Euclidean distances as required; no square root is taken.

namespace {

using ResultPair = std::pair<int, float>;

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

struct __align__(8) HeapEntry {
    float dist;
    int   idx;
};

static_assert(sizeof(HeapEntry) == 8, "HeapEntry must remain compact.");

// Squared L2 distance in 2D.  Using FMA keeps the instruction count low.
__device__ __forceinline__ float sq_l2_2d(const float2 p, const float qx, const float qy) {
    const float dx = p.x - qx;
    const float dy = p.y - qy;
    return fmaf(dx, dx, dy * dy);
}

// Standard max-heap sift-down.  Only lane 0 calls this, so it is optimized for
// low shared-memory traffic rather than wide parallelism.
__device__ __forceinline__ void sift_down(HeapEntry* heap, int root, const int size) {
    HeapEntry entry = heap[root];

    while (true) {
        int child = (root << 1) + 1;
        if (child >= size) {
            break;
        }

        const int right = child + 1;
        if (right < size && heap[right].dist > heap[child].dist) {
            child = right;
        }

        if (heap[child].dist <= entry.dist) {
            break;
        }

        heap[root] = heap[child];
        root = child;
    }

    heap[root] = entry;
}

template <int K>
__device__ __forceinline__ void build_max_heap(HeapEntry* heap) {
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        sift_down(heap, i, K);
    }
}

template <int K>
__device__ __forceinline__ void replace_heap_root(HeapEntry* heap, const float dist, const int idx) {
    heap[0].dist = dist;
    heap[0].idx  = idx;
    sift_down(heap, 0, K);
}

template <int K>
__device__ __forceinline__ void sort_heap_ascending(HeapEntry* heap) {
    // Standard in-place heapsort on a max-heap.  The final order is ascending by distance,
    // which matches result[q * k + j] = j-th nearest neighbor.
    for (int end = K - 1; end > 0; --end) {
        const HeapEntry tmp = heap[0];
        heap[0] = heap[end];
        heap[end] = tmp;
        sift_down(heap, 0, end);
    }
}

// Process one shared-memory tile of candidates for one query/warp.
//
// `heap_top` is broadcast to all lanes and is the current worst element of the retained
// top-k set.  Lanes first filter candidates locally against this threshold.  Any lane
// whose candidate might enter the heap is collected via ballot; those candidates are then
// replayed one-by-one to lane 0, which rechecks against the updated heap root before doing
// the exact heap replacement.
//
// This keeps the hot path (distance evaluation) fully parallel and makes the exact
// top-k update cost proportional to the number of actual replacements, not the number
// of scanned points.
template <int K>
__device__ __forceinline__ void process_tile_for_query(
    const float2* __restrict__ sh_data,
    const int batch_begin,
    const int local_begin,
    const int batch_count,
    const float qx,
    const float qy,
    HeapEntry* __restrict__ heap,
    const int lane,
    float& heap_top)
{
    #pragma unroll 1
    for (int base = local_begin; base < batch_count; base += kWarpSize) {
        const int local_idx = base + lane;

        float dist = CUDART_INF_F;
        int idx = -1;
        const bool valid = (local_idx < batch_count);

        if (valid) {
            const float2 p = sh_data[local_idx];
            dist = sq_l2_2d(p, qx, qy);
            idx = batch_begin + local_idx;
        }

        unsigned replace_mask = __ballot_sync(kFullMask, valid && (dist < heap_top));

        while (replace_mask != 0u) {
            const int src_lane = __ffs(replace_mask) - 1;
            const float cand_dist = __shfl_sync(kFullMask, dist, src_lane);
            const int cand_idx = __shfl_sync(kFullMask, idx, src_lane);

            if (lane == 0) {
                // Recheck against the *current* root because earlier insertions from the same
                // 32-point chunk may already have tightened the admission threshold.
                if (cand_dist < heap[0].dist) {
                    replace_heap_root<K>(heap, cand_dist, cand_idx);
                }
                heap_top = heap[0].dist;
            }

            heap_top = __shfl_sync(kFullMask, heap_top, 0);
            replace_mask &= (replace_mask - 1u);
        }
    }
}

template <int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    ResultPair* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(BATCH_POINTS >= K, "The first tile must be large enough to seed the heap.");
    static_assert((BATCH_POINTS % kWarpSize) == 0, "Tile size must be warp-aligned.");
    static_assert(WARPS_PER_BLOCK == 4 || WARPS_PER_BLOCK == 8 || WARPS_PER_BLOCK == 16,
                  "Only the tuned warp counts are supported.");

    extern __shared__ __align__(16) unsigned char smem_raw[];

    float2* const sh_data = reinterpret_cast<float2*>(smem_raw);
    HeapEntry* const sh_heaps =
        reinterpret_cast<HeapEntry*>(sh_data + BATCH_POINTS);

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_id = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active_query = (query_id < query_count);

    // Load the query once per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query && lane == 0) {
        const float2 q = query[query_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    HeapEntry* const heap = sh_heaps + static_cast<std::size_t>(warp_id) * K;
    float heap_top = CUDART_INF_F;

    // Scan the entire data set tile by tile.  Every tile is loaded once per block and
    // then reused by all WARPS_PER_BLOCK queries in the block.
    for (int batch_begin = 0; batch_begin < data_count; batch_begin += BATCH_POINTS) {
        int batch_count = data_count - batch_begin;
        if (batch_count > BATCH_POINTS) {
            batch_count = BATCH_POINTS;
        }

        // Cooperative global->shared load of the current data tile.
        #pragma unroll 1
        for (int i = threadIdx.x; i < batch_count; i += blockDim.x) {
            sh_data[i] = data[batch_begin + i];
        }

        // Shared tile must be visible to all warps before any warp starts consuming it.
        __syncthreads();

        if (active_query) {
            if (batch_begin == 0) {
                // Seed the exact top-k heap from the first K points.  We require BATCH_POINTS >= K,
                // so the entire seed lives in the first shared tile.
                #pragma unroll
                for (int pos = lane; pos < K; pos += kWarpSize) {
                    const float2 p = sh_data[pos];
                    heap[pos].dist = sq_l2_2d(p, qx, qy);
                    heap[pos].idx  = pos;
                }

                // Lane 0 heapifies the warp-private shared-memory buffer.  Because the heap
                // was written cooperatively by the whole warp, a warp barrier is required.
                __syncwarp(kFullMask);

                if (lane == 0) {
                    build_max_heap<K>(heap);
                    heap_top = heap[0].dist;
                }

                heap_top = __shfl_sync(kFullMask, heap_top, 0);
            }

            const int local_begin = (batch_begin == 0) ? K : 0;

            process_tile_for_query<K>(
                sh_data,
                batch_begin,
                local_begin,
                batch_count,
                qx,
                qy,
                heap,
                lane,
                heap_top);
        }

        // All warps in the block must be done with the current shared tile before it is
        // overwritten by the next global-memory batch.
        __syncthreads();
    }

    if (active_query) {
        // Convert the max-heap into ascending order for the required result layout.
        if (lane == 0) {
            sort_heap_ascending<K>(heap);
        }

        // The sorted heap is read by the whole warp, so we need a warp barrier after
        // lane 0 finishes the in-place heapsort.
        __syncwarp(kFullMask);

        const std::size_t out_base = static_cast<std::size_t>(query_id) * K;

        // Write std::pair members directly instead of constructing std::pair on device.
        #pragma unroll
        for (int pos = lane; pos < K; pos += kWarpSize) {
            result[out_base + pos].first  = heap[pos].idx;
            result[out_base + pos].second = heap[pos].dist;
        }
    }
}

static inline int ceil_div(const int n, const int d) {
    return (n + d - 1) / d;
}

template <int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
constexpr std::size_t shared_bytes() {
    return static_cast<std::size_t>(BATCH_POINTS) * sizeof(float2) +
           static_cast<std::size_t>(WARPS_PER_BLOCK) * static_cast<std::size_t>(K) * sizeof(HeapEntry);
}

// Heuristic for block width selection:
//
// Larger WARPS_PER_BLOCK improves reuse of each shared-memory data tile and therefore
// reduces global-memory traffic, but too large a block count can underfill the GPU when
// query_count is only in the low-thousands.  We therefore pick the largest block width
// whose grid still gives at least ~75% as many blocks as SMs.  This keeps almost all SMs
// occupied while preserving substantial cross-query tile reuse.
template <int MAX_WARPS_PER_BLOCK>
static inline int choose_warps_per_block(const int query_count, const int sm_count) {
    static_assert(MAX_WARPS_PER_BLOCK == 8 || MAX_WARPS_PER_BLOCK == 16,
                  "MAX_WARPS_PER_BLOCK must be 8 or 16.");

    if constexpr (MAX_WARPS_PER_BLOCK >= 16) {
        if (4LL * ceil_div(query_count, 16) >= 3LL * sm_count) {
            return 16;
        }
    }

    if constexpr (MAX_WARPS_PER_BLOCK >= 8) {
        if (4LL * ceil_div(query_count, 8) >= 3LL * sm_count) {
            return 8;
        }
    }

    return 4;
}

template <int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
static inline void launch_variant(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    ResultPair* result)
{
    constexpr std::size_t kSharedBytes = shared_bytes<K, WARPS_PER_BLOCK, BATCH_POINTS>();

    // This kernel is explicitly shared-memory heavy.  Ask the runtime for the largest
    // shared-memory carveout and opt in to the required dynamic shared-memory size.
    (void)cudaFuncSetCacheConfig(knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>, cudaFuncCachePreferShared);
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kSharedBytes));

    const dim3 block(WARPS_PER_BLOCK * kWarpSize);
    const dim3 grid(ceil_div(query_count, WARPS_PER_BLOCK));

    // Normal CUDA semantics: the launch is asynchronous with respect to the host.
    knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>
        <<<grid, block, kSharedBytes>>>(query, query_count, data, data_count, result);
}

template <int K>
static inline void dispatch_k(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    ResultPair* result,
    const int sm_count)
{
    // Tile sizes tuned to keep occupancy healthy while amortizing synchronization:
    // - K <= 256: 4096-point tiles work well and still leave ample shared memory.
    // - K >= 512: the per-warp heap becomes large enough that 2048-point tiles are the
    //   better occupancy / synchronization trade-off.
    constexpr int kBatchPoints = (K <= 256) ? 4096 : 2048;
    constexpr int kMaxWarpsPerBlock = (K == 1024) ? 8 : 16;

    static_assert(kBatchPoints >= K, "Tile must hold the initial heap seed.");
    static_assert(kMaxWarpsPerBlock == 8 || kMaxWarpsPerBlock == 16, "Unexpected launch policy.");

    const int warps_per_block = choose_warps_per_block<kMaxWarpsPerBlock>(query_count, sm_count);

    if constexpr (kMaxWarpsPerBlock == 16) {
        switch (warps_per_block) {
            case 16:
                launch_variant<K, 16, kBatchPoints>(query, query_count, data, data_count, result);
                return;
            case 8:
                launch_variant<K, 8, kBatchPoints>(query, query_count, data, data_count, result);
                return;
            default:
                launch_variant<K, 4, kBatchPoints>(query, query_count, data, data_count, result);
                return;
        }
    } else {
        switch (warps_per_block) {
            case 8:
                launch_variant<K, 8, kBatchPoints>(query, query_count, data, data_count, result);
                return;
            default:
                launch_variant<K, 4, kBatchPoints>(query, query_count, data, data_count, result);
                return;
        }
    }
}

} // anonymous namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    int sm_count = 1;
    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    switch (k) {
        case 32:
            dispatch_k<32>(query, query_count, data, data_count, result, sm_count);
            return;
        case 64:
            dispatch_k<64>(query, query_count, data, data_count, result, sm_count);
            return;
        case 128:
            dispatch_k<128>(query, query_count, data, data_count, result, sm_count);
            return;
        case 256:
            dispatch_k<256>(query, query_count, data, data_count, result, sm_count);
            return;
        case 512:
            dispatch_k<512>(query, query_count, data, data_count, result, sm_count);
            return;
        case 1024:
            dispatch_k<1024>(query, query_count, data, data_count, result, sm_count);
            return;
        default:
            // Per the problem statement this path should never be taken.
            return;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn2d_detail {

/*
Exact brute-force 2D k-NN tuned for modern data-center GPUs.

Key design points:
- One warp computes one query.
- A block stages a large batch of data points in shared memory and all query warps in
  the block reuse that batch. This is the main bandwidth optimization because the data
  set is large and is scanned in full for every query.
- Each warp owns a private intermediate top-k structure stored in shared memory:
  a max-heap of (distance, index). The heap root is the current kth-best distance and
  therefore the pruning threshold.
- Only lane 0 mutates the heap. This is intentional: once the heap is full, the
  threshold quickly rejects almost all points in typical large-data k-NN workloads,
  so the serialized heap maintenance cost is amortized while all 32 lanes keep the
  distance pipeline full.
- k is specialized at compile time for the only valid values:
  {32, 64, 128, 256, 512, 1024}. This avoids dynamic-k control flow in the hot path.
- No extra device memory is allocated; all temporary storage is dynamic shared memory.

Shared-memory budget:
- We reserve 80 KiB per block. On A100/H100-class parts this still allows two resident
  blocks per SM with an opt-in shared-memory carveout, while giving each block a large
  cached data tile.
- A cached point consumes 8 bytes in shared memory (x and y as two floats).
- A heap slot also consumes 8 bytes (distance float + index int).
- For a chosen number of warps per block W, tile_points = 80KiB/8 - W*K.
  We choose the largest practical W for each K to maximize tile reuse across queries.
*/

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xffffffffu;
constexpr int kSharedBudgetBytes = 80 * 1024;
constexpr int kSharedBudgetUnits = kSharedBudgetBytes / 8;  // 8 B per cached point or heap entry.

using result_pair = std::pair<int, float>;

template <int K, int WarpsPerBlock>
struct KnnConfig {
    static_assert(K == 32 || K == 64 || K == 128 || K == 256 || K == 512 || K == 1024,
                  "Unsupported K.");
    static_assert(WarpsPerBlock >= 1 && WarpsPerBlock <= 32, "Invalid warp count.");
    static constexpr int WARPS_PER_BLOCK = WarpsPerBlock;
    static constexpr int BLOCK_THREADS = WARPS_PER_BLOCK * kWarpSize;
    static constexpr int TILE_POINTS = kSharedBudgetUnits - WARPS_PER_BLOCK * K;
    static constexpr std::size_t SHARED_BYTES = kSharedBudgetBytes;

    static_assert(BLOCK_THREADS <= 1024, "Block too large.");
    static_assert(TILE_POINTS > 0, "No room left for the shared-memory tile.");
    static_assert((TILE_POINTS % kWarpSize) == 0, "Tile must be warp-aligned.");
};

template <int K>
struct KnnTraits : KnnConfig<K, (K <= 256 ? 32 : (K == 512 ? 16 : 8))> {};

// Plain squared L2 in 2D; the problem explicitly asks for squared Euclidean distance.
__device__ __forceinline__ float squared_l2_2d(const float qx,
                                               const float qy,
                                               const float px,
                                               const float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

// Generic sift-down used by heap build and heap-sort. The heap is a max-heap on distance.
__device__ __forceinline__ void sift_down(float* heap_dist,
                                          int* heap_idx,
                                          int root,
                                          int heap_size) {
    const float root_dist = heap_dist[root];
    const int root_idx = heap_idx[root];

    int child = (root << 1) + 1;
    while (child < heap_size) {
        int best_child = child;
        float best_child_dist = heap_dist[child];

        const int right = child + 1;
        if (right < heap_size) {
            const float right_dist = heap_dist[right];
            if (right_dist > best_child_dist) {
                best_child = right;
                best_child_dist = right_dist;
            }
        }

        if (best_child_dist <= root_dist) {
            break;
        }

        heap_dist[root] = best_child_dist;
        heap_idx[root] = heap_idx[best_child];
        root = best_child;
        child = (root << 1) + 1;
    }

    heap_dist[root] = root_dist;
    heap_idx[root] = root_idx;
}

template <int K>
__device__ __forceinline__ void build_max_heap(float* heap_dist, int* heap_idx) {
#pragma unroll 1
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        sift_down(heap_dist, heap_idx, i, K);
    }
}

template <int K>
__device__ __forceinline__ void replace_root_if_better(float* heap_dist,
                                                       int* heap_idx,
                                                       const float cand_dist,
                                                       const int cand_idx) {
    if (cand_dist >= heap_dist[0]) {
        return;
    }

    int root = 0;
    int child = 1;

    while (child < K) {
        int best_child = child;
        float best_child_dist = heap_dist[child];

        const int right = child + 1;
        if (right < K) {
            const float right_dist = heap_dist[right];
            if (right_dist > best_child_dist) {
                best_child = right;
                best_child_dist = right_dist;
            }
        }

        if (best_child_dist <= cand_dist) {
            break;
        }

        heap_dist[root] = best_child_dist;
        heap_idx[root] = heap_idx[best_child];
        root = best_child;
        child = (root << 1) + 1;
    }

    heap_dist[root] = cand_dist;
    heap_idx[root] = cand_idx;
}

// Append until the heap is full, then turn the buffer into a max-heap exactly once.
// After that, use the heap root as the pruning threshold.
template <int K>
__device__ __forceinline__ void heap_push_or_replace(float* heap_dist,
                                                     int* heap_idx,
                                                     int& heap_size,
                                                     float& threshold0,
                                                     const float cand_dist,
                                                     const int cand_idx) {
    if (heap_size < K) {
        heap_dist[heap_size] = cand_dist;
        heap_idx[heap_size] = cand_idx;
        ++heap_size;

        if (heap_size == K) {
            build_max_heap<K>(heap_dist, heap_idx);
            threshold0 = heap_dist[0];
        }
    } else if (cand_dist < threshold0) {
        replace_root_if_better<K>(heap_dist, heap_idx, cand_dist, cand_idx);
        threshold0 = heap_dist[0];
    }
}

// In-place heap-sort of the max-heap. Result is ascending by distance, which matches
// result[i * k + j] being the j-th nearest neighbor.
template <int K>
__device__ __forceinline__ void heap_sort_ascending(float* heap_dist, int* heap_idx) {
#pragma unroll 1
    for (int end = K - 1; end > 0; --end) {
        const float max_dist = heap_dist[0];
        const int max_idx = heap_idx[0];

        heap_dist[0] = heap_dist[end];
        heap_idx[0] = heap_idx[end];
        heap_dist[end] = max_dist;
        heap_idx[end] = max_idx;

        sift_down(heap_dist, heap_idx, 0, end);
    }
}

// Write std::pair members directly to avoid relying on a device-side pair assignment operator.
__device__ __forceinline__ void store_result(result_pair* out,
                                             const std::size_t pos,
                                             const int idx,
                                             const float dist) {
    out[pos].first = idx;
    out[pos].second = dist;
}

template <int K>
__global__ __launch_bounds__(KnnTraits<K>::BLOCK_THREADS, 2)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                result_pair* __restrict__ result) {
    using Traits = KnnTraits<K>;

    // Shared layout:
    //   s_data_x[TILE_POINTS]
    //   s_data_y[TILE_POINTS]
    //   s_heap_dist[WARPS_PER_BLOCK * K]
    //   s_heap_idx [WARPS_PER_BLOCK * K]
    //
    // The shared data tile is stored as SoA instead of float2 AoS so that a warp walking
    // 32 consecutive points performs conflict-free 32-bit shared loads.
    extern __shared__ unsigned char shared_raw[];
    float* const s_data_x = reinterpret_cast<float*>(shared_raw);
    float* const s_data_y = s_data_x + Traits::TILE_POINTS;
    float* const s_heap_dist = s_data_y + Traits::TILE_POINTS;
    int* const s_heap_idx = reinterpret_cast<int*>(s_heap_dist + Traits::WARPS_PER_BLOCK * K);

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_idx = static_cast<int>(blockIdx.x) * Traits::WARPS_PER_BLOCK + warp_id;
    const bool warp_active = (query_idx < query_count);

    // Each warp gets a disjoint K-slot heap segment in shared memory.
    float* const warp_heap_dist = s_heap_dist + warp_id * K;
    int* const warp_heap_idx = s_heap_idx + warp_id * K;

    float qx = 0.0f;
    float qy = 0.0f;
    if (warp_active) {
        float2 q = make_float2(0.0f, 0.0f);
        if (lane == 0) {
            q = query[query_idx];
        }
        qx = __shfl_sync(kFullMask, q.x, 0);
        qy = __shfl_sync(kFullMask, q.y, 0);
    }

    // Only lane 0 owns the logical heap state; the rest of the warp sees it via shuffles.
    int heap_size = 0;
    float threshold0 = CUDART_INF_F;

    constexpr int kLoadIters =
        (Traits::TILE_POINTS + Traits::BLOCK_THREADS - 1) / Traits::BLOCK_THREADS;

    for (int data_base = 0; data_base < data_count; data_base += Traits::TILE_POINTS) {
        int tile_count = data_count - data_base;
        if (tile_count > Traits::TILE_POINTS) {
            tile_count = Traits::TILE_POINTS;
        }

        // Cooperative block-wide load of the next data tile.
#pragma unroll
        for (int it = 0; it < kLoadIters; ++it) {
            const int t = threadIdx.x + it * Traits::BLOCK_THREADS;
            if (t < tile_count) {
                const float2 p = data[data_base + t];
                s_data_x[t] = p.x;
                s_data_y[t] = p.y;
            }
        }
        __syncthreads();

        if (warp_active) {
            // Process the shared tile in warp-sized micro-batches.
            //
            // Correctness note:
            //   The pruning threshold is sampled once per 32-point micro-batch.
            //   This is exact because once the heap is full, the kth-best distance
            //   can only decrease. A stale threshold may admit extra candidates,
            //   but it cannot hide a true top-k candidate.
#pragma unroll 1
            for (int local_block = 0; local_block < tile_count; local_block += kWarpSize) {
                const int local = local_block + lane;
                const bool valid = (local < tile_count);

                float dist = 0.0f;
                int idx = 0;
                if (valid) {
                    dist = squared_l2_2d(qx, qy, s_data_x[local], s_data_y[local]);
                    idx = data_base + local;
                }

                const int heap_size_lane0 = __shfl_sync(kFullMask, heap_size, 0);
                const bool heap_full = (heap_size_lane0 == K);
                const float threshold = __shfl_sync(kFullMask, threshold0, 0);

                const bool accept = valid && (!heap_full || dist < threshold);
                unsigned accept_mask = __ballot_sync(kFullMask, accept);

                // All lanes participate in the shuffles; only lane 0 updates the heap.
                while (accept_mask != 0u) {
                    const int src_lane = __ffs(accept_mask) - 1;
                    const float cand_dist = __shfl_sync(kFullMask, dist, src_lane);
                    const int cand_idx = __shfl_sync(kFullMask, idx, src_lane);

                    if (lane == 0) {
                        heap_push_or_replace<K>(
                            warp_heap_dist, warp_heap_idx, heap_size, threshold0, cand_dist, cand_idx);
                    }

                    accept_mask &= accept_mask - 1;
                }

                __syncwarp(kFullMask);
            }
        }

        // Ensure every warp is done reading the tile before the next block-wide load reuses it.
        __syncthreads();
    }

    if (warp_active) {
        if (lane == 0) {
            // data_count >= K by contract, so the heap is guaranteed to be full here.
            heap_sort_ascending<K>(warp_heap_dist, warp_heap_idx);
        }

        __syncwarp(kFullMask);

        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

#pragma unroll
        for (int j = lane; j < K; j += kWarpSize) {
            store_result(result, out_base + static_cast<std::size_t>(j),
                         warp_heap_idx[j], warp_heap_dist[j]);
        }
    }
}

template <int K>
inline void launch_knn_variant(const float2* query,
                               const int query_count,
                               const float2* data,
                               const int data_count,
                               result_pair* result) {
    using Traits = KnnTraits<K>;

    // These kernels are intentionally shared-memory heavy; request the carveout explicitly.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(Traits::SHARED_BYTES));
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(Traits::BLOCK_THREADS);
    const dim3 grid((query_count + Traits::WARPS_PER_BLOCK - 1) / Traits::WARPS_PER_BLOCK);

    // Launch-only wrapper by design: inputs and outputs are device pointers, so keeping the
    // call asynchronous on the default stream is usually the most useful behavior.
    knn_kernel<K><<<grid, block, Traits::SHARED_BYTES>>>(query, query_count, data, data_count, result);
}

}  // namespace knn2d_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn2d_detail::launch_knn_variant<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn2d_detail::launch_knn_variant<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn2d_detail::launch_knn_variant<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn2d_detail::launch_knn_variant<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn2d_detail::launch_knn_variant<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn2d_detail::launch_knn_variant<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // Input contract says k is always valid; keep the default case as a no-op.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace knn_detail {

// Warp-per-query, shared-memory tiled k-NN for 2D points.
//
// Key design choices:
//  - One warp owns one query for the full scan.
//  - The database is streamed in 2048-point tiles staged in shared memory.
//    The tile is stored as SoA (x[] and y[]) to avoid the shared-memory bank conflict pattern
//    that contiguous float2 loads would create.
//  - Each query keeps a private top-K max-heap in shared memory. Only lane 0 mutates that heap.
//    This is intentional: after the first K points, only a small fraction of candidates beat the
//    current K-th best threshold, so the expensive heap maintenance is sparse while all 32 lanes
//    still stay busy on distance evaluation and candidate voting.
//  - K only takes six legal values, so the kernel is specialized at compile time for K.
//  - The host picks 4/8/16/32 warps per block based on query_count and SM count, selecting the
//    largest value that still leaves roughly >= 1 block/SM. This balances tile reuse against
//    grid-level parallelism on A100/H100-class GPUs.

constexpr int kWarpSize   = 32;
constexpr int kTilePoints = 2048;  // 16 KiB shared tile (x[] + y[]).
constexpr unsigned kFullMask = 0xffffffffu;
constexpr int kA100MaxOptinSharedPerBlock = 163840;  // Strictest target in the requested class.

static_assert((kTilePoints % kWarpSize) == 0, "Tile size must be warp aligned.");
static_assert(kTilePoints >= 1024, "The first tile must always contain all legal K values.");

using ResultPair = std::pair<int, float>;

struct alignas(8) Neighbor {
    float dist;
    int   idx;
};
static_assert(sizeof(Neighbor) == 8, "Neighbor must stay compact.");
static_assert((2 * kTilePoints * static_cast<int>(sizeof(float))) % alignof(Neighbor) == 0,
              "Heap storage must stay aligned behind the shared tile.");

__device__ __forceinline__ float squared_l2_2d(float qx, float qy, float x, float y) {
    const float dx = qx - x;
    const float dy = qy - y;
    return fmaf(dx, dx, dy * dy);
}

// Sift a single node down inside a max-heap. Implemented with the standard "hole" method to
// minimize shared-memory traffic.
__device__ __forceinline__ void sift_down_max_heap(Neighbor* heap, int size, int root) {
    Neighbor value = heap[root];
    int child = (root << 1) + 1;

    while (child < size) {
        int right = child + 1;
        if (right < size && heap[right].dist > heap[child].dist) {
            child = right;
        }
        if (heap[child].dist <= value.dist) {
            break;
        }
        heap[root] = heap[child];
        root = child;
        child = (root << 1) + 1;
    }
    heap[root] = value;
}

template <int K>
__device__ __forceinline__ void build_max_heap(Neighbor* heap) {
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        sift_down_max_heap(heap, K, i);
    }
}

// Heap sort over the already-built max-heap. Final order is ascending distance, which matches
// the output contract result[i * k + j] = j-th nearest neighbor.
template <int K>
__device__ __forceinline__ void heap_sort_ascending(Neighbor* heap) {
    for (int end = K - 1; end > 0; --end) {
        const Neighbor max_value = heap[0];
        const Neighbor tail      = heap[end];
        heap[end] = max_value;

        int root  = 0;
        int child = 1;
        while (child < end) {
            int right = child + 1;
            if (right < end && heap[right].dist > heap[child].dist) {
                child = right;
            }
            if (heap[child].dist <= tail.dist) {
                break;
            }
            heap[root] = heap[child];
            root = child;
            child = (root << 1) + 1;
        }
        heap[root] = tail;
    }
}

// Full-tile path: the iteration count is compile-time known, so the compiler can unroll it.
template <int BLOCK_THREADS>
__device__ __forceinline__ void load_full_tile_to_shared(
    const float2* __restrict__ data_src,
    float* __restrict__ tile_x,
    float* __restrict__ tile_y)
{
#pragma unroll
    for (int i = static_cast<int>(threadIdx.x); i < kTilePoints; i += BLOCK_THREADS) {
        const float2 p = data_src[i];
        tile_x[i] = p.x;
        tile_y[i] = p.y;
    }
}

// Initialize the per-query heap from the first K points of the first tile.
// Warp shuffles with the *_sync variants are the warp-scope synchronization primitive here.
template <int K>
__device__ __forceinline__ void init_heap_from_first_k(
    const float* __restrict__ tile_x,
    const float* __restrict__ tile_y,
    float qx, float qy,
    Neighbor* __restrict__ heap,
    int lane)
{
    int write_base = 0;

    for (int off = 0; off < K; off += kWarpSize) {
        const float x    = tile_x[off + lane];
        const float y    = tile_y[off + lane];
        const float dist = squared_l2_2d(qx, qy, x, y);
        const int   idx  = off + lane;  // First tile starts at global index 0.

#pragma unroll
        for (int src = 0; src < kWarpSize; ++src) {
            const float dist_src = __shfl_sync(kFullMask, dist, src);
            const int   idx_src  = __shfl_sync(kFullMask, idx,  src);
            if (lane == 0) {
                heap[write_base + src].dist = dist_src;
                heap[write_base + src].idx  = idx_src;
            }
        }
        write_base += kWarpSize;
    }

    if (lane == 0) {
        build_max_heap<K>(heap);
    }
}

// Scan one [start, end) range inside the currently cached tile.
template <int K>
__device__ __forceinline__ void process_tile_range(
    const float* __restrict__ tile_x,
    const float* __restrict__ tile_y,
    int tile_base,
    int start,
    int end,
    float qx, float qy,
    Neighbor* __restrict__ heap,
    int lane)
{
    // Only lane 0 owns the heap root in a live register; other lanes just receive it by shuffle.
    float worst_lane = CUDART_INF_F;
    if (lane == 0) {
        worst_lane = heap[0].dist;
    }

    for (int off = start; off < end; off += kWarpSize) {
        float dist = CUDART_INF_F;
        int   idx  = -1;

        const int local = off + lane;
        if (local < end) {
            const float x = tile_x[local];
            const float y = tile_y[local];
            dist = squared_l2_2d(qx, qy, x, y);
            idx  = tile_base + local;
        }

        const float worst = __shfl_sync(kFullMask, worst_lane, 0);
        unsigned candidate_mask = __ballot_sync(kFullMask, dist < worst);

        // Every lane executes the same sequence of shuffles; only lane 0 performs the actual
        // heap update. Candidates are rechecked against the updated root before replacement.
        while (candidate_mask) {
            const int src_lane = __ffs(candidate_mask) - 1;
            const float cand_dist = __shfl_sync(kFullMask, dist, src_lane);
            const int   cand_idx  = __shfl_sync(kFullMask, idx,  src_lane);

            if (lane == 0 && cand_dist < worst_lane) {
                heap[0].dist = cand_dist;
                heap[0].idx  = cand_idx;
                sift_down_max_heap(heap, K, 0);
                worst_lane = heap[0].dist;
            }
            candidate_mask &= candidate_mask - 1;
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    ResultPair* __restrict__ result)
{
    static_assert(K == 32 || K == 64 || K == 128 || K == 256 || K == 512 || K == 1024,
                  "Illegal K specialization.");
    static_assert(WARPS_PER_BLOCK == 4 || WARPS_PER_BLOCK == 8 ||
                  WARPS_PER_BLOCK == 16 || WARPS_PER_BLOCK == 32,
                  "Unsupported warp count.");
    static_assert(K <= kTilePoints, "The first tile must contain the initial heap population.");

    constexpr int BLOCK_THREADS = WARPS_PER_BLOCK * kWarpSize;

    const int lane             = static_cast<int>(threadIdx.x) & (kWarpSize - 1);
    const int warp_id_in_block = static_cast<int>(threadIdx.x) >> 5;
    const int block_query_base = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK;

    // Entire block can exit before any barrier if it covers no queries.
    if (block_query_base >= query_count) {
        return;
    }

    const int  query_idx    = block_query_base + warp_id_in_block;
    const bool active_query = (query_idx < query_count);

    extern __shared__ __align__(16) unsigned char smem_raw[];
    float*   tile_x = reinterpret_cast<float*>(smem_raw);
    float*   tile_y = tile_x + kTilePoints;
    Neighbor* heaps = reinterpret_cast<Neighbor*>(tile_y + kTilePoints);

    // Each warp gets a private K-entry heap in shared memory.
    Neighbor* heap = heaps + warp_id_in_block * K;

    // Load the query once per warp and broadcast it.
    float qx_lane = 0.0f;
    float qy_lane = 0.0f;
    if (lane == 0 && active_query) {
        const float2 q = query[query_idx];
        qx_lane = q.x;
        qy_lane = q.y;
    }
    const float qx = __shfl_sync(kFullMask, qx_lane, 0);
    const float qy = __shfl_sync(kFullMask, qy_lane, 0);

    // ----- First tile: it always contains at least K points because K <= 1024 < 2048.
    int tile_count = (data_count < kTilePoints) ? data_count : kTilePoints;
    if (tile_count == kTilePoints) {
        load_full_tile_to_shared<BLOCK_THREADS>(data, tile_x, tile_y);
    } else {
        for (int i = static_cast<int>(threadIdx.x); i < tile_count; i += BLOCK_THREADS) {
            const float2 p = data[i];
            tile_x[i] = p.x;
            tile_y[i] = p.y;
        }
    }

    // Shared tile is read by all warps, so a block-wide barrier is required.
    __syncthreads();

    if (active_query) {
        init_heap_from_first_k<K>(tile_x, tile_y, qx, qy, heap, lane);
        if (tile_count > K) {
            process_tile_range<K>(tile_x, tile_y, 0, K, tile_count, qx, qy, heap, lane);
        }
    }

    // Another block-wide barrier is required before reusing the shared tile storage.
    __syncthreads();

    // ----- Remaining tiles.
    for (int tile_base = kTilePoints; tile_base < data_count; tile_base += kTilePoints) {
        tile_count = data_count - tile_base;
        if (tile_count > kTilePoints) {
            tile_count = kTilePoints;
        }

        const float2* tile_src = data + tile_base;
        if (tile_count == kTilePoints) {
            load_full_tile_to_shared<BLOCK_THREADS>(tile_src, tile_x, tile_y);
        } else {
            for (int i = static_cast<int>(threadIdx.x); i < tile_count; i += BLOCK_THREADS) {
                const float2 p = tile_src[i];
                tile_x[i] = p.x;
                tile_y[i] = p.y;
            }
        }

        __syncthreads();

        if (active_query) {
            process_tile_range<K>(tile_x, tile_y, tile_base, 0, tile_count, qx, qy, heap, lane);
        }

        __syncthreads();
    }

    // Final per-query writeback.
    if (active_query && lane == 0) {
        heap_sort_ascending<K>(heap);

        ResultPair* out = result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
        for (int i = 0; i < K; ++i) {
            out[i].first  = heap[i].idx;
            out[i].second = heap[i].dist;
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
inline void launch_specialized(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result)
{
    constexpr int BLOCK_THREADS = WARPS_PER_BLOCK * kWarpSize;
    constexpr std::size_t smem_bytes =
        (2ull * kTilePoints * sizeof(float)) +
        (static_cast<std::size_t>(WARPS_PER_BLOCK) * static_cast<std::size_t>(K) * sizeof(Neighbor));

    static_assert(smem_bytes <= static_cast<std::size_t>(kA100MaxOptinSharedPerBlock),
                  "Chosen launch configuration exceeds A100 shared-memory limits.");

    // The target GPUs support opt-in shared memory above 48 KiB.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int grid_blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    knn_kernel<K, WARPS_PER_BLOCK><<<grid_blocks, BLOCK_THREADS, smem_bytes>>>(
        query, query_count, data, data_count, result);
}

// Dispatch helper for K. K=1024 cannot use 32 warps/block because its per-warp heap is 8 KiB.
template <int K>
inline void launch_k(
    int warps_per_block,
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result)
{
    if constexpr (K == 1024) {
        switch (warps_per_block) {
            case 16: launch_specialized<1024, 16>(query, query_count, data, data_count, result); break;
            case 8:  launch_specialized<1024,  8>(query, query_count, data, data_count, result); break;
            default: launch_specialized<1024,  4>(query, query_count, data, data_count, result); break;
        }
    } else {
        switch (warps_per_block) {
            case 32: launch_specialized<K, 32>(query, query_count, data, data_count, result); break;
            case 16: launch_specialized<K, 16>(query, query_count, data, data_count, result); break;
            case 8:  launch_specialized<K,  8>(query, query_count, data, data_count, result); break;
            default: launch_specialized<K,  4>(query, query_count, data, data_count, result); break;
        }
    }
}

// Choose the largest power-of-two number of query-warps per block that still leaves at least
// about one block per SM. This preserves enough grid parallelism for "thousands of queries"
// while maximizing tile reuse inside each block.
inline int select_warps_per_block(int max_warps_per_block, int query_count, int sm_count) {
    const auto enough_blocks = [query_count, sm_count](int warps_per_block) {
        return ((query_count + warps_per_block - 1) / warps_per_block) >= sm_count;
    };

    if (max_warps_per_block >= 32 && enough_blocks(32)) return 32;
    if (max_warps_per_block >= 16 && enough_blocks(16)) return 16;
    if (max_warps_per_block >= 8  && enough_blocks(8))  return 8;
    return 4;
}

}  // namespace knn_detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    // Query the active device so the block-size heuristic scales from A100 to H100.
    int sm_count = 108;  // Conservative default if the query fails.
    int device   = 0;
    if (cudaGetDevice(&device) == cudaSuccess) {
        int value = 0;
        if (cudaDeviceGetAttribute(&value, cudaDevAttrMultiProcessorCount, device) == cudaSuccess &&
            value > 0) {
            sm_count = value;
        }
    }

    const int max_warps_per_block = (k == 1024) ? 16 : 32;
    const int warps_per_block =
        knn_detail::select_warps_per_block(max_warps_per_block, query_count, sm_count);

    switch (k) {
        case 32:   knn_detail::launch_k<32>  (warps_per_block, query, query_count, data, data_count, result); break;
        case 64:   knn_detail::launch_k<64>  (warps_per_block, query, query_count, data, data_count, result); break;
        case 128:  knn_detail::launch_k<128> (warps_per_block, query, query_count, data, data_count, result); break;
        case 256:  knn_detail::launch_k<256> (warps_per_block, query, query_count, data, data_count, result); break;
        case 512:  knn_detail::launch_k<512> (warps_per_block, query, query_count, data, data_count, result); break;
        case 1024: knn_detail::launch_k<1024>(warps_per_block, query, query_count, data, data_count, result); break;
        default:
            // Per problem statement, k is always valid, so this path is unreachable.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// Exact 2D k-NN for large query/data sets on A100/H100-class GPUs.
//
// Design choices:
// - One warp computes one query, exactly as requested.
// - 16 warps/block (512 threads) maximizes data reuse: each shared-memory data batch is
//   consumed by 16 independent queries before the block advances.
// - A 2048-point batch keeps the worst-case shared-memory footprint (k=1024) below
//   Ampere's 163,840 B/block dynamic shared-memory limit while still amortizing
//   block-wide synchronization well.
// - The shared cache is stored as SoA (x[], y[]) instead of float2 AoS to avoid the
//   repeated shared-memory bank conflicts that an AoS layout would create when every
//   warp streams the cached points.
// - Each warp owns one private max-heap of K neighbors in shared memory. Only lane 0
//   mutates that heap; all 32 lanes stay busy on distance evaluation and use shuffles
//   to feed only potentially useful candidates to lane 0. This is exact and efficient:
//   after the initial fill, streaming top-k replacements are rare compared to the total
//   number of distance computations.
// - Distances are squared Euclidean distances as required; no sqrt is taken.

constexpr int WARP_SIZE            = 32;
constexpr int THREADS_PER_BLOCK    = 512;
constexpr int WARPS_PER_BLOCK      = THREADS_PER_BLOCK / WARP_SIZE;
constexpr int BATCH_POINTS         = 2048;
constexpr int FULL_BATCH_FLOAT4S   = BATCH_POINTS / 2;
constexpr unsigned FULL_MASK       = 0xffffffffu;
constexpr std::size_t AMPERE_MAX_DYNAMIC_SHARED_BYTES = 163840;

struct alignas(8) Neighbor {
    float dist;
    int   idx;
};

static_assert(THREADS_PER_BLOCK % WARP_SIZE == 0, "Block size must be a multiple of warp size.");
static_assert(BATCH_POINTS % WARP_SIZE == 0, "Batch size must be a multiple of warp size.");
static_assert(BATCH_POINTS % 2 == 0, "Batch size must be even for float4 vectorized loads.");
static_assert(FULL_BATCH_FLOAT4S == 2 * THREADS_PER_BLOCK,
              "The full-batch loader assumes exactly two float4 loads per thread.");
static_assert(sizeof(Neighbor) == 8, "Neighbor must stay compact.");
static_assert((2 * BATCH_POINTS * sizeof(float)) % alignof(Neighbor) == 0,
              "Shared-memory heap base must stay naturally aligned.");

template <int K>
constexpr std::size_t shared_bytes_for_k() {
    return 2ull * BATCH_POINTS * sizeof(float) +
           static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(Neighbor);
}

static_assert(shared_bytes_for_k<1024>() <= AMPERE_MAX_DYNAMIC_SHARED_BYTES,
              "Worst-case shared-memory footprint exceeds Ampere's per-block limit.");

__device__ __forceinline__ bool neighbor_worse(const Neighbor& a, const Neighbor& b) {
    return (a.dist > b.dist) || ((a.dist == b.dist) && (a.idx > b.idx));
}

__device__ __forceinline__ bool neighbor_better(const Neighbor& a, const Neighbor& b) {
    return neighbor_worse(b, a);
}

__device__ __forceinline__ void swap_neighbors(Neighbor& a, Neighbor& b) {
    const Neighbor tmp = a;
    a = b;
    b = tmp;
}

// Sift-down for a max-heap: the root stores the current worst kept neighbor.
template <int K>
__device__ __forceinline__ void sift_down_max(Neighbor* heap, int size, int root) {
    Neighbor value = heap[root];
    int child = (root << 1) + 1;

    while (child < size) {
        const int right = child + 1;
        if (right < size && neighbor_worse(heap[right], heap[child])) {
            child = right;
        }
        if (!neighbor_worse(heap[child], value)) {
            break;
        }
        heap[root] = heap[child];
        root = child;
        child = (root << 1) + 1;
    }

    heap[root] = value;
}

template <int K>
__device__ __forceinline__ void build_max_heap(Neighbor* heap) {
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        sift_down_max<K>(heap, K, i);
    }
}

template <int K>
__device__ __forceinline__ void sort_heap_ascending(Neighbor* heap) {
    // In-place heapsort of the max-heap. Result becomes ascending by distance
    // (and by index for the tie-breaker used inside the heap).
    for (int end = K - 1; end > 0; --end) {
        swap_neighbors(heap[0], heap[end]);
        sift_down_max<K>(heap, end, 0);
    }
}

template <int K>
__device__ __forceinline__ void insert_candidate(Neighbor* heap, int& heap_fill, const Neighbor& cand) {
    if (heap_fill < K) {
        heap[heap_fill++] = cand;
        if (heap_fill == K) {
            build_max_heap<K>(heap);
        }
    } else if (neighbor_better(cand, heap[0])) {
        heap[0] = cand;
        sift_down_max<K>(heap, K, 0);
    }
}

// Block-cooperative batch load into shared-memory SoA cache.
// The common full-batch path is manually unrolled: with the chosen constants each thread
// performs exactly two coalesced float4 loads (4 points/thread).
__device__ __forceinline__
void load_batch_soa(float* __restrict__ batch_x,
                    float* __restrict__ batch_y,
                    const float2* __restrict__ data,
                    int batch_start,
                    int batch_size) {
    const float4* __restrict__ g4 =
        reinterpret_cast<const float4*>(data + batch_start);

    if (batch_size == BATCH_POINTS) {
        const int chunk0 = threadIdx.x;
        const float4 v0 = g4[chunk0];
        const int j0 = chunk0 << 1;
        batch_x[j0]     = v0.x;
        batch_y[j0]     = v0.y;
        batch_x[j0 + 1] = v0.z;
        batch_y[j0 + 1] = v0.w;

        const int chunk1 = chunk0 + THREADS_PER_BLOCK;
        const float4 v1 = g4[chunk1];
        const int j1 = chunk1 << 1;
        batch_x[j1]     = v1.x;
        batch_y[j1]     = v1.y;
        batch_x[j1 + 1] = v1.z;
        batch_y[j1 + 1] = v1.w;
    } else {
        const int pair_chunks = batch_size >> 1;
        for (int chunk = threadIdx.x; chunk < pair_chunks; chunk += THREADS_PER_BLOCK) {
            const float4 v = g4[chunk];
            const int j = chunk << 1;
            batch_x[j]     = v.x;
            batch_y[j]     = v.y;
            batch_x[j + 1] = v.z;
            batch_y[j + 1] = v.w;
        }

        if ((batch_size & 1) && threadIdx.x == 0) {
            const float2 last = data[batch_start + batch_size - 1];
            batch_x[batch_size - 1] = last.x;
            batch_y[batch_size - 1] = last.y;
        }
    }
}

// Warp-local processing of one cached batch.
//
// Important correctness detail:
// - We build a warp-wide mask of lanes that may matter.
// - Then we replay those lanes in ascending lane order via shuffles.
// - Lane 0 rechecks each replayed candidate against the *current* heap root before
//   insertion. This preserves exact streaming semantics even though the threshold can
//   tighten within the 32-point tile.
template <int K, bool FULL_BATCH>
__device__ __forceinline__
void process_cached_batch(float qx,
                          float qy,
                          const float* __restrict__ batch_x,
                          const float* __restrict__ batch_y,
                          int batch_start,
                          int batch_size,
                          Neighbor* __restrict__ heap,
                          int& heap_fill,
                          int lane) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");

    const int limit = FULL_BATCH ? BATCH_POINTS : batch_size;

    for (int local = 0; local < limit; local += WARP_SIZE) {
        const int point = local + lane;
        const bool valid = FULL_BATCH || (point < batch_size);

        float px = 0.0f;
        float py = 0.0f;
        if (valid) {
            px = batch_x[point];
            py = batch_y[point];
        }

        const float dx = px - qx;
        const float dy = py - qy;
        const float dist = __fmaf_rn(dx, dx, dy * dy);  // squared L2
        const int data_idx = batch_start + point;

        // Broadcast the current fill state from lane 0. While the heap is not full yet,
        // every valid lane participates. Once the heap is full, a strict '< root' filter
        // is enough: ties are explicitly left unspecified by the interface, and avoiding
        // '<=' removes useless heap traffic.
        const int filled = __shfl_sync(FULL_MASK, (lane == 0) ? heap_fill : 0, 0);

        unsigned selected_mask;
        if (filled < K) {
            selected_mask = __ballot_sync(FULL_MASK, valid);
        } else {
            const float threshold =
                __shfl_sync(FULL_MASK, (lane == 0) ? heap[0].dist : 0.0f, 0);
            selected_mask = __ballot_sync(FULL_MASK, valid && (dist < threshold));
        }

        while (selected_mask) {
            const int src_lane = __ffs(static_cast<int>(selected_mask)) - 1;

            // All lanes must execute the shuffles; only lane 0 consumes the values.
            const float cand_dist = __shfl_sync(FULL_MASK, dist, src_lane);
            const int cand_idx    = __shfl_sync(FULL_MASK, data_idx, src_lane);

            if (lane == 0) {
                const Neighbor cand{cand_dist, cand_idx};
                insert_candidate<K>(heap, heap_fill, cand);
            }

            selected_mask &= (selected_mask - 1);
        }

        // Required on Volta+ due to independent thread scheduling: lane 0 mutates the
        // per-warp shared-memory heap while the other lanes are idle.
        __syncwarp(FULL_MASK);
    }
}

template <int K>
__global__ __launch_bounds__(THREADS_PER_BLOCK)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                std::pair<int, float>* __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");

    // int4 guarantees a 16-byte-aligned base for the dynamic shared-memory region.
    extern __shared__ int4 shared_base[];
    unsigned char* smem = reinterpret_cast<unsigned char*>(shared_base);

    float* batch_x = reinterpret_cast<float*>(smem);
    float* batch_y = batch_x + BATCH_POINTS;
    Neighbor* heap_base = reinterpret_cast<Neighbor*>(batch_y + BATCH_POINTS);

    const int warp_id = threadIdx.x >> 5;
    const int lane    = threadIdx.x & (WARP_SIZE - 1);
    const int qid     = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool valid_query = (qid < query_count);

    Neighbor* const heap = heap_base + static_cast<std::size_t>(warp_id) * K;

    // Lane 0 owns the heap metadata for the warp.
    int heap_fill = 0;

    float qx = 0.0f;
    float qy = 0.0f;
    if (valid_query && lane == 0) {
        const float2 q = query[qid];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    for (int batch_start = 0; batch_start < data_count; batch_start += BATCH_POINTS) {
        const int remaining  = data_count - batch_start;
        const int batch_size = (remaining > BATCH_POINTS) ? BATCH_POINTS : remaining;

        load_batch_soa(batch_x, batch_y, data, batch_start, batch_size);
        __syncthreads();

        if (valid_query) {
            if (batch_size == BATCH_POINTS) {
                process_cached_batch<K, true>(
                    qx, qy, batch_x, batch_y, batch_start, batch_size, heap, heap_fill, lane);
            } else {
                process_cached_batch<K, false>(
                    qx, qy, batch_x, batch_y, batch_start, batch_size, heap, heap_fill, lane);
            }
        }

        // Protect the shared batch buffer before it is overwritten by the next iteration.
        __syncthreads();
    }

    if (valid_query && lane == 0) {
        sort_heap_ascending<K>(heap);

        const std::size_t out_base =
            static_cast<std::size_t>(qid) * static_cast<std::size_t>(K);

        // Only lane 0 writes results. Output volume is tiny relative to the full scan,
        // so keeping the critical path simple is preferable here.
        for (int i = 0; i < K; ++i) {
            result[out_base + static_cast<std::size_t>(i)].first  = heap[i].idx;
            result[out_base + static_cast<std::size_t>(i)].second = heap[i].dist;
        }
    }
}

template <int K>
inline void launch_knn_impl(const float2* query,
                            int query_count,
                            const float2* data,
                            int data_count,
                            std::pair<int, float>* result) {
    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    const std::size_t smem_bytes = shared_bytes_for_k<K>();

    // Request the large dynamic shared-memory allocation and bias the SM carveout
    // toward shared memory. This is required for the k=1024 case on Ampere.
    cudaFuncSetAttribute(knn_kernel<K>,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         static_cast<int>(smem_bytes));
    cudaFuncSetAttribute(knn_kernel<K>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    // Intentionally asynchronous, like a normal CUDA launcher.
    knn_kernel<K><<<blocks, THREADS_PER_BLOCK, smem_bytes>>>(
        query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_impl<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_impl<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_impl<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_impl<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_impl<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_impl<1024>(query, query_count, data, data_count, result); break;
        default:
            // Per problem statement this path is unreachable (k is always valid).
            return;
    }
}

#include <cuda_runtime.h>
#include <math_constants.h>

#include <cstddef>
#include <cstdint>
#include <utility>

namespace knn_detail {

// Kernel design summary:
// - One warp computes one query.
// - 8 warps/block lets every shared-memory tile of data be reused by 8 queries.
// - The data tile is cached in shared memory in SoA form (x[] / y[]) so the hot
//   distance loop uses conflict-free 32-bit shared loads.
// - The current top-k set for each query is stored as a warp-private max-heap in
//   shared memory. The heap stores packed (distance_bits, index) pairs in 64 bits.
//   Squared Euclidean distances are non-negative, so IEEE-754 bit order is monotone
//   as an unsigned integer; raw 64-bit comparisons therefore implement
//   "distance first, index second" ordering. The prompt allows arbitrary tie handling.
// - Only lane 0 mutates the heap. After the warm-up phase, streaming top-k updates
//   become sparse, so a single-lane heap update is cheaper than carrying a large,
//   dynamically indexed per-thread structure that would otherwise risk local-memory
//   spills at k = 1024.
// - k is specialized at compile time (32, 64, 128, 256, 512, 1024) so heap depth,
//   shared-memory footprint, and initialization work are all fully known to the compiler.

constexpr unsigned FULL_MASK      = 0xffffffffu;
constexpr int      WARP_SIZE      = 32;
constexpr int      WARPS_PER_BLOCK = 8;
constexpr int      BLOCK_THREADS   = WARPS_PER_BLOCK * WARP_SIZE;

// 2048 is the largest power-of-two tile that keeps the worst-case kernel
// (k = 1024, 8 warps/block) at 80 KiB/block dynamic shared memory:
//   tile cache: 2 * 2048 * sizeof(float) = 16 KiB
//   warp heaps: 8 * 1024 * sizeof(uint64) = 64 KiB
// Total = 80 KiB, so two blocks still fit comfortably on A100/H100-class SMs.
constexpr int BATCH_POINTS = 2048;

using packed_neighbor_t = unsigned long long;
using output_pair_t     = std::pair<int, float>;

static_assert(BLOCK_THREADS == 256, "Expected 256-thread blocks.");
static_assert(BATCH_POINTS % BLOCK_THREADS == 0, "Batch size must be divisible by block size.");
static_assert(BATCH_POINTS % WARP_SIZE == 0, "Batch size must be divisible by warp size.");
static_assert((2 * BATCH_POINTS * static_cast<int>(sizeof(float))) % static_cast<int>(alignof(packed_neighbor_t)) == 0,
              "Heap region in dynamic shared memory must stay naturally aligned.");

constexpr int ilog2_constexpr(int x) {
    return (x <= 1) ? 0 : 1 + ilog2_constexpr(x >> 1);
}

template <int K>
constexpr int shared_bytes_for() {
    return 2 * BATCH_POINTS * static_cast<int>(sizeof(float)) +
           WARPS_PER_BLOCK * K * static_cast<int>(sizeof(packed_neighbor_t));
}

static_assert(shared_bytes_for<1024>() <= 96 * 1024,
              "Worst-case dynamic shared memory footprint must remain under the common opt-in limit.");

// Pack distance and index into one 64-bit word.
// High 32 bits: raw float bits of non-negative distance.
// Low  32 bits: index.
// Since all distances are squared L2 norms, they are non-negative, so unsigned
// integer comparison on the high 32 bits preserves the distance ordering.
__device__ __forceinline__ packed_neighbor_t pack_neighbor(float dist, int idx) {
    return (static_cast<packed_neighbor_t>(__float_as_uint(dist)) << 32) |
           static_cast<unsigned int>(idx);
}

__device__ __forceinline__ float unpack_distance(packed_neighbor_t v) {
    return __uint_as_float(static_cast<unsigned int>(v >> 32));
}

__device__ __forceinline__ int unpack_index(packed_neighbor_t v) {
    return static_cast<int>(static_cast<unsigned int>(v));
}

// Replace the root of a max-heap and sift the replacement down.
// Only lane 0 calls this; the heap lives in warp-private shared memory.
template <int K>
__device__ __forceinline__ void heap_replace_root_serial(
    packed_neighbor_t* __restrict__ heap,
    int heap_size,
    packed_neighbor_t value)
{
    constexpr int HEAP_LEVELS = ilog2_constexpr(K);

    int pos = 0;

#pragma unroll
    for (int level = 0; level < HEAP_LEVELS; ++level) {
        const int left = (pos << 1) + 1;
        if (left >= heap_size) {
            break;
        }

        int max_child_pos = left;
        packed_neighbor_t max_child = heap[left];

        const int right = left + 1;
        if (right < heap_size) {
            const packed_neighbor_t right_value = heap[right];
            if (right_value > max_child) {
                max_child = right_value;
                max_child_pos = right;
            }
        }

        if (max_child > value) {
            heap[pos] = max_child;
            pos = max_child_pos;
        } else {
            break;
        }
    }

    heap[pos] = value;
}

// Process one cached data batch for a single query/warp.
// FULL_BATCH is specialized so the common full-tile case has no bounds checks
// in the hot distance loop. The monotone root property lets us prefilter
// candidates with a ballot against the current root: if a candidate is not
// better than the root now, it can never become better later in the same step,
// because the root only decreases as inserts happen.
template <int K, bool FULL_BATCH>
__device__ __forceinline__ void process_cached_batch(
    float qx,
    float qy,
    const float* __restrict__ sm_x,
    const float* __restrict__ sm_y,
    int batch_base,
    int valid,
    packed_neighbor_t* __restrict__ warp_heap,
    packed_neighbor_t& root_pack,
    int lane,
    packed_neighbor_t inf_pack)
{
    constexpr int BATCH_STEPS = BATCH_POINTS / WARP_SIZE;
    const int steps = FULL_BATCH ? BATCH_STEPS : ((valid + WARP_SIZE - 1) / WARP_SIZE);

#pragma unroll 1
    for (int step = 0; step < steps; ++step) {
        const int sm_index = step * WARP_SIZE + lane;

        packed_neighbor_t cand_local = inf_pack;

        if constexpr (FULL_BATCH) {
            const float dx = qx - sm_x[sm_index];
            const float dy = qy - sm_y[sm_index];
            const float dist = __fmaf_rn(dx, dx, dy * dy);
            cand_local = pack_neighbor(dist, batch_base + sm_index);
        } else {
            if (sm_index < valid) {
                const float dx = qx - sm_x[sm_index];
                const float dy = qy - sm_y[sm_index];
                const float dist = __fmaf_rn(dx, dx, dy * dy);
                cand_local = pack_neighbor(dist, batch_base + sm_index);
            }
        }

        packed_neighbor_t root = __shfl_sync(FULL_MASK, root_pack, 0);
        unsigned int improve_mask = __ballot_sync(FULL_MASK, cand_local < root);

        while (improve_mask != 0u) {
            const int src_lane = __ffs(improve_mask) - 1;
            const packed_neighbor_t cand = __shfl_sync(FULL_MASK, cand_local, src_lane);

            root = __shfl_sync(FULL_MASK, root_pack, 0);
            if (cand < root) {
                if (lane == 0) {
                    heap_replace_root_serial<K>(warp_heap, K, cand);
                    root_pack = warp_heap[0];
                }
            }

            improve_mask &= (improve_mask - 1);
        }
    }
}

template <int K>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    output_pair_t* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert((K % WARP_SIZE) == 0, "K must be divisible by warp size.");

    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;
    constexpr int LOADS_PER_THREAD = BATCH_POINTS / BLOCK_THREADS;

    extern __shared__ unsigned char shared_raw[];

    // Shared-memory layout:
    // [ sm_x[BATCH_POINTS] | sm_y[BATCH_POINTS] | heaps[WARPS_PER_BLOCK][K] ]
    float* sm_x = reinterpret_cast<float*>(shared_raw);
    float* sm_y = sm_x + BATCH_POINTS;
    packed_neighbor_t* heaps = reinterpret_cast<packed_neighbor_t*>(sm_y + BATCH_POINTS);

    const int tid     = static_cast<int>(threadIdx.x);
    const int warp_id = tid >> 5;
    const int lane    = tid & (WARP_SIZE - 1);

    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active   = query_idx < query_count;

    packed_neighbor_t* warp_heap = heaps + warp_id * K;

    float qx = 0.0f;
    float qy = 0.0f;

    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }

    // Shuffle itself is the warp synchronization primitive here.
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    const packed_neighbor_t inf_pack = pack_neighbor(CUDART_INF_F, -1);
    packed_neighbor_t root_pack = inf_pack;

    if (active) {
        // Cooperative heap initialization: each lane writes K/32 heap slots.
#pragma unroll
        for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
            warp_heap[i * WARP_SIZE + lane] = inf_pack;
        }

        // Shared-memory communication within the warp requires a warp barrier.
        __syncwarp(FULL_MASK);
    }

    for (int batch_base = 0; batch_base < data_count; batch_base += BATCH_POINTS) {
        const int remaining = data_count - batch_base;
        const bool full_batch = (remaining >= BATCH_POINTS);
        const int valid = full_batch ? BATCH_POINTS : remaining;

        // Cooperative block-wide load of the next data tile into shared memory.
        if (full_batch) {
#pragma unroll
            for (int load = 0; load < LOADS_PER_THREAD; ++load) {
                const int sm_index = load * BLOCK_THREADS + tid;
                const float2 p = data[batch_base + sm_index];
                sm_x[sm_index] = p.x;
                sm_y[sm_index] = p.y;
            }
        } else {
#pragma unroll
            for (int load = 0; load < LOADS_PER_THREAD; ++load) {
                const int sm_index = load * BLOCK_THREADS + tid;
                if (sm_index < valid) {
                    const float2 p = data[batch_base + sm_index];
                    sm_x[sm_index] = p.x;
                    sm_y[sm_index] = p.y;
                }
            }
        }

        // Block-wide barrier for the shared tile.
        __syncthreads();

        if (active) {
            if (full_batch) {
                process_cached_batch<K, true>(qx, qy, sm_x, sm_y, batch_base, valid, warp_heap, root_pack, lane, inf_pack);
            } else {
                process_cached_batch<K, false>(qx, qy, sm_x, sm_y, batch_base, valid, warp_heap, root_pack, lane, inf_pack);
            }
        }

        // Ensure no warp starts overwriting the shared tile before all warps are done with it.
        __syncthreads();
    }

    // Final heap sort: repeatedly pop the current maximum and write backwards so
    // the output is ascending by distance. Only lane 0 writes std::pair members,
    // which avoids relying on any device-side std::pair constructors/operators.
    if (active && lane == 0) {
        output_pair_t* out = result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        for (int remaining = K; remaining > 0; --remaining) {
            const packed_neighbor_t best = warp_heap[0];
            out[remaining - 1].first  = unpack_index(best);
            out[remaining - 1].second = unpack_distance(best);

            if (remaining > 1) {
                heap_replace_root_serial<K>(warp_heap, remaining - 1, warp_heap[remaining - 1]);
            }
        }
    }
}

template <int K>
inline void launch_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    output_pair_t* result)
{
    constexpr int shared_bytes = shared_bytes_for<K>();

    // k = 1024 needs 80 KiB dynamic shared memory, so opt in explicitly.
    // Prefer shared memory over L1: this kernel is built around shared tiling and
    // a warp-private shared heap, while the data stream is essentially one-pass.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               shared_bytes);
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, shared_bytes>>>(query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k)
{
    // Asynchronous launch on the current/default stream.
    if (query_count <= 0) {
        return;
    }

#define KNN_LAUNCH_CASE(KVAL) \
    case KVAL:                \
        knn_detail::launch_knn<KVAL>(query, query_count, data, data_count, result); \
        break

    switch (k) {
        KNN_LAUNCH_CASE(32);
        KNN_LAUNCH_CASE(64);
        KNN_LAUNCH_CASE(128);
        KNN_LAUNCH_CASE(256);
        KNN_LAUNCH_CASE(512);
        KNN_LAUNCH_CASE(1024);
        default:
            // Per problem statement, k is always valid.
            break;
    }

#undef KNN_LAUNCH_CASE
}

#include <cuda_runtime.h>

#include <cstddef>
#include <type_traits>
#include <utility>

namespace knn_detail {

// Brute-force 2D k-NN specialized for modern NVIDIA data-center GPUs.
//
// Design summary:
// - One warp owns one query point.
// - A whole thread block streams the data set through shared memory in large tiles.
// - Each warp keeps its current top-k set as a private max-heap in shared memory.
//   This is the key choice: maintaining a heap makes accepted-candidate updates
//   O(log k) instead of O(k), which matters when k can be as large as 1024.
// - The heap is sorted only once, after the full scan, before writing results.
// - No extra device memory is allocated; only dynamic shared memory is used.
//
// Synchronization:
// - __syncthreads() protects the block-wide shared-memory data tile.
// - __syncwarp() protects the warp-private heap when one lane updates it and the
//   whole warp subsequently reads it.
// - __shfl_sync()/__ballot_sync() are used for warp-level broadcast/compaction.

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xffffffffu;

// `std::pair<int,float>` is the required public ABI, but its constructors / assignment
// operators are not guaranteed to be device-callable across all host standard library
// implementations. We therefore write the object representation of an equivalent trivial
// POD directly into the output buffer.
struct ResultPairPod {
    int first;
    float second;
};

static_assert(sizeof(ResultPairPod) == sizeof(std::pair<int, float>),
              "std::pair<int,float> must be an 8-byte {int,float} pair on this ABI.");
static_assert(std::is_trivially_copyable<std::pair<int, float>>::value,
              "std::pair<int,float> must be trivially copyable for raw byte stores.");

// Tuning choices for A100/H100-class GPUs:
// - For k <= 256, use 16 warps/block (512 threads) to maximize reuse of each shared
//   data tile across many simultaneous queries.
// - For k >= 512, use 8 warps/block (256 threads) to keep per-block shared memory
//   low enough to preserve good residency.
// - Use 4096 cached points per block except for k=1024, where the warp-private heaps
//   already consume 64 KiB and the tile is reduced to 2048 points to keep the total
//   dynamic shared memory at 80 KiB.
template <int K>
struct KnnConfig {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");

    static constexpr int BLOCK_THREADS   = (K <= 256) ? 512 : 256;
    static constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;
    static constexpr int BATCH_SIZE      = (K == 1024) ? 2048 : 4096;

    static_assert((BLOCK_THREADS % kWarpSize) == 0, "Block size must be warp-aligned.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    static_assert((BATCH_SIZE % kWarpSize) == 0, "Batch size must be warp-aligned.");
    static_assert((BATCH_SIZE % 2) == 0, "Batch size must stay even for 16-byte vector loads.");
};

template <int K>
constexpr std::size_t shared_memory_bytes() {
    return static_cast<std::size_t>(KnnConfig<K>::WARPS_PER_BLOCK) * static_cast<std::size_t>(K) *
               (sizeof(float) + sizeof(int)) +
           static_cast<std::size_t>(KnnConfig<K>::BATCH_SIZE) * sizeof(float2);
}

// Deterministic tie-breaks are used only to give the heap / final sort a total order.
// The API itself does not require any specific tie resolution.
__device__ __forceinline__ bool pair_better(float a_dist, int a_idx, float b_dist, int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__ bool pair_worse(float a_dist, int a_idx, float b_dist, int b_idx) {
    return (a_dist > b_dist) || ((a_dist == b_dist) && (a_idx > b_idx));
}

__device__ __forceinline__ float squared_l2(float qx, float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dy, dy, dx * dx);
}

__device__ __forceinline__ void swap_entry(float* dist, int* idx, int a, int b) {
    const float td = dist[a];
    dist[a] = dist[b];
    dist[b] = td;

    const int ti = idx[a];
    idx[a] = idx[b];
    idx[b] = ti;
}

// Classical sift-down for a max-heap ordered by (distance, index).
// Only lane 0 calls this helper.
__device__ __forceinline__ void sift_down_max_heap(float* dist, int* idx, int root, int heap_size) {
    int current = root;

    while (true) {
        const int left = (current << 1) + 1;
        if (left >= heap_size) {
            break;
        }

        const int right = left + 1;
        int child = left;

        if (right < heap_size && pair_worse(dist[right], idx[right], dist[left], idx[left])) {
            child = right;
        }

        if (!pair_worse(dist[child], idx[child], dist[current], idx[current])) {
            break;
        }

        swap_entry(dist, idx, current, child);
        current = child;
    }
}

template <int K>
__device__ __forceinline__ void build_max_heap(float* dist, int* idx) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    if (lane == 0) {
#pragma unroll 1
        for (int root = (K >> 1) - 1; root >= 0; --root) {
            sift_down_max_heap(dist, idx, root, K);
        }
    }

    __syncwarp(kFullMask);
}

template <int K>
__device__ __forceinline__ void maybe_replace_root(float* dist, int* idx,
                                                   float cand_dist, int cand_idx) {
    // Only lane 0 calls this helper.
    if (pair_better(cand_dist, cand_idx, dist[0], idx[0])) {
        dist[0] = cand_dist;
        idx[0] = cand_idx;
        sift_down_max_heap(dist, idx, 0, K);
    }
}

// Heapsort from a max-heap yields ascending order, which matches the required result layout.
// Only lane 0 performs the serial heap sort; the whole warp then writes the sorted output.
template <int K>
__device__ __forceinline__ void heap_sort_ascending(float* dist, int* idx) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    if (lane == 0) {
#pragma unroll 1
        for (int end = K - 1; end > 0; --end) {
            swap_entry(dist, idx, 0, end);
            sift_down_max_heap(dist, idx, 0, end);
        }
    }

    __syncwarp(kFullMask);
}

// Vectorized block-wide batch load.
// Each int4 copy transfers two consecutive float2 points (16 bytes).
template <int BLOCK_THREADS>
__device__ __forceinline__ void load_data_batch(const float2* __restrict__ data,
                                                int base,
                                                int batch_count,
                                                float2* __restrict__ batch_points) {
    const int tid = threadIdx.x;

    const int vec_count = batch_count >> 1;
    const int4* __restrict__ gvec = reinterpret_cast<const int4*>(data + base);
    int4* __restrict__ svec = reinterpret_cast<int4*>(batch_points);

    for (int i = tid; i < vec_count; i += BLOCK_THREADS) {
        svec[i] = gvec[i];
    }

    if ((batch_count & 1) && (tid == 0)) {
        batch_points[batch_count - 1] = data[base + batch_count - 1];
    }
}

template <int K>
__device__ __forceinline__ void initialize_heap_from_first_k(float qx, float qy,
                                                             const float2* batch_points,
                                                             float* heap_dist,
                                                             int* heap_idx) {
    const int lane = threadIdx.x & (kWarpSize - 1);

#pragma unroll
    for (int i = lane; i < K; i += kWarpSize) {
        heap_dist[i] = squared_l2(qx, qy, batch_points[i]);
        heap_idx[i]  = i;  // First batch starts at global index 0.
    }

    __syncwarp(kFullMask);
    build_max_heap<K>(heap_dist, heap_idx);
}

// Scan a cached shared-memory tile.
// The dominant work (distance evaluation) is fully warp-parallel.
// Heap maintenance is intentionally serialized in lane 0: once the heap is primed,
// very few candidates beat the current kth-best threshold, so serial O(log k)
// updates are typically much cheaper than keeping the whole heap warp-distributed.
template <int K>
__device__ __forceinline__ void process_cached_batch(float qx, float qy,
                                                     const float2* batch_points,
                                                     int base_index,
                                                     int start_local,
                                                     int batch_count,
                                                     float* heap_dist,
                                                     int* heap_idx) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int tile = start_local; tile < batch_count; tile += kWarpSize) {
        const int local = tile + lane;

        float cand_dist = CUDART_INF_F;
        int cand_index = -1;

        if (local < batch_count) {
            cand_dist = squared_l2(qx, qy, batch_points[local]);
            cand_index = base_index + local;
        }

        const float threshold =
            __shfl_sync(kFullMask, (lane == 0 ? heap_dist[0] : 0.0f), 0);

        unsigned pending =
            __ballot_sync(kFullMask, (local < batch_count) && (cand_dist < threshold));

        if (pending != 0u) {
            while (pending != 0u) {
                const int src_lane = __ffs(pending) - 1;

                const float selected_dist = __shfl_sync(kFullMask, cand_dist, src_lane);
                const int selected_index = __shfl_sync(kFullMask, cand_index, src_lane);

                if (lane == 0) {
                    maybe_replace_root<K>(heap_dist, heap_idx, selected_dist, selected_index);
                }

                pending &= (pending - 1);
            }

            __syncwarp(kFullMask);
        }
    }
}

__device__ __forceinline__ void store_result_pair(std::pair<int, float>* out,
                                                  std::size_t pos,
                                                  int index,
                                                  float distance) {
    const ResultPairPod pod{index, distance};

    unsigned char* dst =
        reinterpret_cast<unsigned char*>(out) + pos * sizeof(std::pair<int, float>);
    const unsigned char* src = reinterpret_cast<const unsigned char*>(&pod);

#pragma unroll
    for (int i = 0; i < static_cast<int>(sizeof(ResultPairPod)); ++i) {
        dst[i] = src[i];
    }
}

template <int K>
__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           std::pair<int, float>* __restrict__ result) {
    using Config = KnnConfig<K>;

    constexpr int BLOCK_THREADS   = Config::BLOCK_THREADS;
    constexpr int WARPS_PER_BLOCK = Config::WARPS_PER_BLOCK;
    constexpr int BATCH_SIZE      = Config::BATCH_SIZE;
    constexpr int TOTAL_TOPK      = WARPS_PER_BLOCK * K;

    // Declaring the dynamic shared segment as int4 guarantees 16-byte base alignment.
    extern __shared__ int4 shared_storage[];
    unsigned char* smem = reinterpret_cast<unsigned char*>(shared_storage);

    // Layout:
    //   [ warp0 heap distances | warp1 heap distances | ... ]
    //   [ warp0 heap indices   | warp1 heap indices   | ... ]
    //   [ block-wide cached data tile                         ]
    float* all_heap_dist = reinterpret_cast<float*>(smem);
    int* all_heap_idx = reinterpret_cast<int*>(all_heap_dist + TOTAL_TOPK);
    float2* batch_points = reinterpret_cast<float2*>(all_heap_idx + TOTAL_TOPK);

    const int tid = threadIdx.x;
    const int lane = tid & (kWarpSize - 1);
    const int warp_id = tid >> 5;

    const int query_index = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active = (query_index < query_count);

    float qx = 0.0f;
    float qy = 0.0f;

    if (active && (lane == 0)) {
        const float2 q = query[query_index];
        qx = q.x;
        qy = q.y;
    }

    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    float* heap_dist = all_heap_dist + warp_id * K;
    int* heap_idx = all_heap_idx + warp_id * K;

    for (int base = 0; base < data_count; base += BATCH_SIZE) {
        int batch_count = data_count - base;
        if (batch_count > BATCH_SIZE) {
            batch_count = BATCH_SIZE;
        }

        load_data_batch<BLOCK_THREADS>(data, base, batch_count, batch_points);
        __syncthreads();

        if (active) {
            if (base == 0) {
                initialize_heap_from_first_k<K>(qx, qy, batch_points, heap_dist, heap_idx);
                process_cached_batch<K>(qx, qy, batch_points, 0, K, batch_count, heap_dist, heap_idx);
            } else {
                process_cached_batch<K>(qx, qy, batch_points, base, 0, batch_count, heap_dist, heap_idx);
            }
        }

        // Ensure every warp has finished reading the current tile before the block overwrites it.
        __syncthreads();
    }

    if (active) {
        heap_sort_ascending<K>(heap_dist, heap_idx);

        const std::size_t out_base =
            static_cast<std::size_t>(query_index) * static_cast<std::size_t>(K);

#pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            store_result_pair(result, out_base + static_cast<std::size_t>(i),
                              heap_idx[i], heap_dist[i]);
        }
    }
}

template <int K>
inline void launch_knn_specialized(const float2* query,
                                   int query_count,
                                   const float2* data,
                                   int data_count,
                                   std::pair<int, float>* result) {
    using Config = KnnConfig<K>;
    constexpr std::size_t smem_bytes = shared_memory_bytes<K>();

    static_assert((smem_bytes % sizeof(int4)) == 0,
                  "The shared-memory layout relies on 16-byte alignment.");
    static_assert(smem_bytes <= (96u * 1024u),
                  "Chosen specialization exceeds the intended per-block shared-memory budget.");

    const dim3 block(Config::BLOCK_THREADS, 1, 1);
    const dim3 grid((query_count + Config::WARPS_PER_BLOCK - 1) / Config::WARPS_PER_BLOCK, 1, 1);

    // Opt in to the larger dynamic shared-memory footprint and strongly prefer SMEM
    // over L1 for this kernel. The target hardware is A100/H100-class, where this
    // configuration is appropriate.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    // Default-stream launch; the caller may synchronize externally as needed.
    knn_kernel<K><<<grid, block, smem_bytes>>>(query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn_detail::launch_knn_specialized<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_detail::launch_knn_specialized<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_detail::launch_knn_specialized<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_detail::launch_knn_specialized<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_detail::launch_knn_specialized<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_detail::launch_knn_specialized<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // Inputs are documented to be valid; keep a defensive default anyway.
            return;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstdint>
#include <cstddef>

namespace
{
    // Fixed block shape:
    // - 256 threads = 8 warps.
    // - 1 warp handles 1 query, so each CTA processes 8 queries.
    // This is a good fit for A100/H100 because each staged data tile is reused by 8 queries
    // while still leaving enough shared memory for k up to 1024.
    constexpr int kWarpSize        = 32;
    constexpr int kBlockThreads    = 256;
    constexpr int kWarpsPerBlock   = kBlockThreads / kWarpSize;

    // A100's opt-in per-CTA shared-memory limit; the chosen tile sizes below are kept within
    // this smaller limit so the same binary also runs well on H100.
    constexpr std::size_t kA100MaxOptinSharedBytes = 163840;

    // Packed key layout:
    //   high 32 bits = IEEE-754 bits of the (non-negative) squared distance
    //   low  32 bits = data index
    //
    // Because all distances here are non-negative, unsigned integer comparison on the packed
    // key is equivalent to lexicographic comparison on (distance, index). The index is used
    // only as a deterministic tie-breaker to make the ordering total; the problem statement
    // allows arbitrary tie resolution.
    using KeyT = unsigned long long;

    constexpr unsigned int kFullMask = 0xffffffffu;
    constexpr KeyT kMaxKey =
        ~KeyT{0};
    constexpr KeyT kInvalidKey =
        (KeyT{0x7f800000u} << 32) | KeyT{0xffffffffu};  // (+inf distance, invalid index)

    template <int K, int TILE_POINTS>
    constexpr std::size_t shared_bytes_for()
    {
        return static_cast<std::size_t>(TILE_POINTS) * sizeof(float2) +
               static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(2 * K) * sizeof(KeyT);
    }

    __device__ __forceinline__ KeyT pack_key(const float dist, const int idx)
    {
        return (static_cast<KeyT>(__float_as_uint(dist)) << 32) |
               static_cast<KeyT>(static_cast<std::uint32_t>(idx));
    }

    __device__ __forceinline__ int unpack_index(const KeyT key)
    {
        return static_cast<int>(static_cast<std::uint32_t>(key));
    }

    __device__ __forceinline__ float unpack_distance(const KeyT key)
    {
        return __uint_as_float(static_cast<unsigned int>(key >> 32));
    }

    // Warp-local bitonic sort of exactly 32 keys, ascending across lanes.
    // Each lane contributes one key and receives one key back.
    __device__ __forceinline__ KeyT warp_sort32_asc(KeyT key)
    {
        const int lane = threadIdx.x & (kWarpSize - 1);

        for (int k = 2; k <= kWarpSize; k <<= 1)
        {
            for (int j = k >> 1; j > 0; j >>= 1)
            {
                const KeyT other = __shfl_xor_sync(kFullMask, key, j);

                // Standard bitonic compare-exchange logic for XOR partners.
                const bool keep_small = (((lane & j) == 0) == ((lane & k) == 0));
                if (keep_small)
                {
                    if (other < key) key = other;
                }
                else
                {
                    if (key < other) key = other;
                }
            }
        }

        return key;
    }

    // Merge-path partition for merging:
    //   A = current top-k list in shared memory, length K, sorted ascending
    //   B = current 32-lane candidate list, sorted ascending, but only its first b_len entries matter
    //
    // For the output diagonal 'diag', return how many items are taken from A.
    // Because b_len <= 32, the binary-search window is also <= 32 entries wide, so this is cheap.
    template <int K>
    __device__ __forceinline__ int merge_path_partition(
        const KeyT* __restrict__ a,
        const int diag,
        const KeyT sorted_b_lane_value,
        const int b_len)
    {
        int low  = diag - b_len;
        int high = diag;

        if (low  < 0) low  = 0;
        if (high > K) high = K;

        while (low < high)
        {
            const int mid = (low + high) >> 1;
            const int j   = diag - mid;

            const KeyT a_mid  = (mid < K) ? a[mid] : kMaxKey;
            const KeyT b_jm1  = (j > 0) ? __shfl_sync(kFullMask, sorted_b_lane_value, j - 1) : KeyT{0};

            // If A[mid] is still smaller than B[j-1], then the partition needs more A-items.
            if ((j > 0) && (mid < K) && (a_mid < b_jm1))
            {
                low = mid + 1;
            }
            else
            {
                high = mid;
            }
        }

        return low;
    }

    // Core kernel:
    // - one warp owns one query
    // - the CTA stages a large batch of data points in shared memory
    // - each warp scans that tile in groups of 32 candidates
    // - each warp keeps its private top-k in warp-private shared memory as a sorted array of keys
    // - only candidate groups containing at least one key < current cutoff are sorted/merged
    //
    // The top-k list is stored in two shared-memory buffers (ping-pong) to avoid in-place merge
    // hazards and to avoid local-memory spills for large k (up to 1024).
    template <int K, int TILE_POINTS>
    __global__ __launch_bounds__(256)
    void knn_kernel(
        const float2* __restrict__ query,
        const int query_count,
        const float2* __restrict__ data,
        const int data_count,
        std::pair<int, float>* __restrict__ result)
    {
        static_assert((K & (K - 1)) == 0, "K must be a power of two.");
        static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
        static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");
        static_assert((TILE_POINTS % kBlockThreads) == 0, "Tile size must be divisible by block size.");
        static_assert((TILE_POINTS % kWarpSize) == 0, "Tile size must be divisible by warp size.");

        constexpr int kPerLane       = K / kWarpSize;
        constexpr int kLoadsPerThread = TILE_POINTS / kBlockThreads;

        extern __shared__ unsigned char smem_raw[];
        float2* tile = reinterpret_cast<float2*>(smem_raw);

        // Shared layout after the tile:
        //   [warp0 cur K][warp0 tmp K][warp1 cur K][warp1 tmp K]...
        KeyT* warp_buffers = reinterpret_cast<KeyT*>(tile + TILE_POINTS);

        const int lane       = threadIdx.x & (kWarpSize - 1);
        const int warp_local = threadIdx.x >> 5;
        const int query_idx  = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_local;
        const bool active    = (query_idx < query_count);

        KeyT* cur = warp_buffers + static_cast<std::size_t>(warp_local) * static_cast<std::size_t>(2 * K);
        KeyT* tmp = cur + K;

        // Initialize the current top-k buffer to +inf.
        #pragma unroll
        for (int pos = lane; pos < K; pos += kWarpSize)
        {
            cur[pos] = kInvalidKey;
        }
        __syncwarp();

        // Broadcast the query point once per warp.
        float qx = 0.0f;
        float qy = 0.0f;
        if ((lane == 0) && active)
        {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);

        // Current kth key. Starts at +inf and monotonically decreases.
        KeyT cutoff = kInvalidKey;

        for (int tile_base = 0; tile_base < data_count; tile_base += TILE_POINTS)
        {
            int tile_count = data_count - tile_base;
            if (tile_count > TILE_POINTS) tile_count = TILE_POINTS;

            // Cooperative CTA load of the current data tile into shared memory.
            #pragma unroll
            for (int load = 0; load < kLoadsPerThread; ++load)
            {
                const int local = load * kBlockThreads + threadIdx.x;
                if (local < tile_count)
                {
                    tile[local] = data[tile_base + local];
                }
            }
            __syncthreads();

            if (active)
            {
                // Process the staged tile 32 points at a time so that a warp naturally owns
                // one candidate per lane.
                #pragma unroll 1
                for (int round = 0; round < tile_count; round += kWarpSize)
                {
                    const int local = round + lane;

                    KeyT cand = kInvalidKey;
                    if (local < tile_count)
                    {
                        const float2 p = tile[local];
                        const float dx = qx - p.x;
                        const float dy = qy - p.y;
                        const float dist = fmaf(dx, dx, dy * dy);  // squared L2, no sqrt
                        cand = pack_key(dist, tile_base + local);
                    }

                    // Exact cutoff test:
                    // if cand >= cutoff, then cand cannot enter the new top-k because the current
                    // top-k already contains K keys <= cutoff under the packed-key ordering.
                    const unsigned int eligible_mask = __ballot_sync(kFullMask, cand < cutoff);
                    if (eligible_mask == 0u)
                    {
                        continue;
                    }

                    // Sort all 32 candidates. After sorting, the first m entries are exactly the
                    // keys that beat the current cutoff.
                    const int m = __popc(eligible_mask);
                    cand = warp_sort32_asc(cand);

                    // Each lane merges a contiguous slice of the output:
                    //   [lane * kPerLane, (lane + 1) * kPerLane)
                    // The candidate side is tiny (<= 32), so merge-path partitioning is cheap.
                    const int out_begin = lane * kPerLane;
                    int a_idx = merge_path_partition<K>(cur, out_begin, cand, m);
                    int b_idx = out_begin - a_idx;

                    KeyT last_out = kInvalidKey;

                    #pragma unroll
                    for (int i = 0; i < kPerLane; ++i)
                    {
                        const KeyT a_key = (a_idx < K) ? cur[a_idx] : kMaxKey;
                        const KeyT b_key = (b_idx < m) ? __shfl_sync(kFullMask, cand, b_idx) : kMaxKey;

                        const bool take_b = (b_idx < m) && ((a_idx == K) || (b_key < a_key));
                        const KeyT out_key = take_b ? b_key : a_key;

                        if (take_b)
                        {
                            ++b_idx;
                        }
                        else
                        {
                            ++a_idx;
                        }

                        tmp[out_begin + i] = out_key;
                        last_out = out_key;
                    }

                    // Shared-memory communication inside the warp requires an explicit warp barrier
                    // on modern GPUs with independent thread scheduling.
                    __syncwarp();

                    // Lane 31 owns the final output element K-1 of the merged list, i.e. the new cutoff.
                    cutoff = __shfl_sync(kFullMask, last_out, kWarpSize - 1);

                    // Swap ping-pong buffers.
                    KeyT* old = cur;
                    cur = tmp;
                    tmp = old;
                }
            }

            // All warps must finish consuming the staged tile before the next tile overwrites it.
            __syncthreads();
        }

        // Write the final sorted top-k back to global memory.
        // Results are sorted ascending by the packed key, i.e. by distance with an index tie-break.
        if (active)
        {
            std::pair<int, float>* out = result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

            #pragma unroll
            for (int pos = lane; pos < K; pos += kWarpSize)
            {
                const KeyT key = cur[pos];
                out[pos].first  = unpack_index(key);
                out[pos].second = unpack_distance(key);
            }
        }
    }

    template <int K, int TILE_POINTS>
    inline void launch_knn_impl(
        const float2* query,
        const int query_count,
        const float2* data,
        const int data_count,
        std::pair<int, float>* result)
    {
        constexpr std::size_t smem_bytes = shared_bytes_for<K, TILE_POINTS>();
        static_assert(smem_bytes <= kA100MaxOptinSharedBytes,
                      "Chosen (K, TILE_POINTS) configuration exceeds A100 shared-memory capacity.");

        const dim3 block(kBlockThreads);
        const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

        // Opt in to large dynamic shared memory; required for the larger-k specializations.
        cudaFuncSetAttribute(
            knn_kernel<K, TILE_POINTS>,
            cudaFuncAttributeMaxDynamicSharedMemorySize,
            static_cast<int>(smem_bytes));
        cudaFuncSetAttribute(
            knn_kernel<K, TILE_POINTS>,
            cudaFuncAttributePreferredSharedMemoryCarveout,
            100);

        knn_kernel<K, TILE_POINTS><<<grid, block, smem_bytes>>>(
            query, query_count, data, data_count, result);
    }
}  // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    // Asynchronous launch, matching normal CUDA library behavior.
    if (query_count <= 0)
    {
        return;
    }

    // Tile sizes are chosen for A100's 164 KiB shared-memory ceiling and therefore also fit H100.
    // Resulting A100 shared-memory footprints per CTA:
    //   k=  32 ->  36 KiB  (4 CTAs/SM)
    //   k=  64 ->  40 KiB  (4 CTAs/SM)
    //   k= 128 ->  48 KiB  (3 CTAs/SM)
    //   k= 256 ->  64 KiB  (2 CTAs/SM)
    //   k= 512 ->  80 KiB  (2 CTAs/SM)
    //   k=1024 -> 160 KiB  (1 CTA/SM, large tile to minimize barriers)
    switch (k)
    {
        case 32:   launch_knn_impl<32,   4096>(query, query_count, data, data_count, result); break;
        case 64:   launch_knn_impl<64,   4096>(query, query_count, data, data_count, result); break;
        case 128:  launch_knn_impl<128,  4096>(query, query_count, data, data_count, result); break;
        case 256:  launch_knn_impl<256,  4096>(query, query_count, data, data_count, result); break;
        case 512:  launch_knn_impl<512,  2048>(query, query_count, data, data_count, result); break;
        case 1024: launch_knn_impl<1024, 4096>(query, query_count, data, data_count, result); break;
        default:
            // Per the problem statement this path is unreachable.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace {

// Exact brute-force 2D k-NN specialized for the only six legal K values.
//
// Mapping:
//   * one warp computes one query;
//   * one 256-thread block owns 8 warps / 8 queries;
//   * the block streams the data set through a shared-memory tile;
//   * each warp computes one 32-point candidate chunk at a time (one candidate per lane),
//     sorts that chunk in-warp, then exact-merges it with its current sorted top-K.
//
// The top-K buffer is kept in shared memory rather than registers because K can be as large
// as 1024. Shared memory also enables exact warp-parallel merge-path updates with arbitrary
// indexing while keeping register pressure reasonable.
//
// Shared-memory layout intentionally uses SoA:
//   * tile points are cached as x[] and y[] (not float2) to avoid 64-bit shared-memory bank
//     issues on the hot read path;
//   * top-K is stored as separate dist[] and idx[] arrays for the same reason;
//   * one pad slot is inserted every 32 logical top-K elements. During the merge, lane l writes
//     a contiguous segment of K/32 logical outputs; the padding maps those blocked writes onto
//     distinct shared-memory banks.
constexpr int kWarpSize            = 32;
constexpr int kBlockThreads        = 256;   // 8 warps/block: good tile reuse without starving the grid at ~1k queries.
constexpr int kWarpsPerBlock       = kBlockThreads / kWarpSize;
constexpr int kTilePoints          = 1536;  // 6 point loads/thread/tile; still allows 2 resident blocks/SM at K=1024 on A100/H100.
constexpr int kTileLoadsPerThread  = kTilePoints / kBlockThreads;
constexpr unsigned kFullMask       = 0xFFFFFFFFu;
constexpr std::size_t kSharedAlign = 128;
constexpr int kPartitionSteps      = 5;     // merge-path search range is <= 32 because the second list always has 32 items.

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size.");
static_assert(kTilePoints % kWarpSize == 0, "Tile size must be a multiple of warp size.");
static_assert(kTileLoadsPerThread * kBlockThreads == kTilePoints, "Tile size must evenly distribute across the block.");

__host__ __device__ constexpr std::size_t align_up(std::size_t x, std::size_t a) {
    return (x + a - 1) & ~(a - 1);
}

template <int K>
struct KnnTraits {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static constexpr int ItemsPerThread = K / kWarpSize;
    static constexpr int PaddedK        = K + (K / kWarpSize);                 // one pad every 32 logical elements
    static constexpr int WorstPhys      = (K - 1) + ((K - 1) >> 5);            // physical shared index of logical K-1
};

template <int K>
struct SharedLayout {
    static constexpr std::size_t XOffset    = 0;
    static constexpr std::size_t YOffset    = align_up(XOffset    + kTilePoints * sizeof(float), kSharedAlign);
    static constexpr std::size_t TopDOffset = align_up(YOffset    + kTilePoints * sizeof(float), kSharedAlign);
    static constexpr std::size_t TopIOffset = align_up(TopDOffset + kWarpsPerBlock * KnnTraits<K>::PaddedK * sizeof(float), kSharedAlign);
    static constexpr std::size_t Bytes      = align_up(TopIOffset + kWarpsPerBlock * KnnTraits<K>::PaddedK * sizeof(int),   kSharedAlign);
};

static_assert(SharedLayout<1024>::Bytes <= 163840,
              "Chosen tile size exceeds the shared-memory budget targeted for A100/H100.");

__device__ __forceinline__ int topk_phys_index(const int logical) {
    // logical -> physical with one pad slot after every 32 logical elements
    return logical + (logical >> 5);
}

__device__ __forceinline__ bool pair_less(const float a_d, const int a_i,
                                          const float b_d, const int b_i) {
    // Index is only an internal deterministic tie-breaker; the problem statement allows any tie order.
    return (a_d < b_d) || ((a_d == b_d) && (a_i < b_i));
}

__device__ __forceinline__ void warp_bitonic_sort_32(float& d, int& i) {
    // Full warp-wide bitonic sort of 32 candidate pairs in ascending order.
    const int lane = threadIdx.x & (kWarpSize - 1);

#pragma unroll
    for (int size = 2; size <= kWarpSize; size <<= 1) {
#pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            const float od = __shfl_xor_sync(kFullMask, d, stride);
            const int   oi = __shfl_xor_sync(kFullMask, i, stride);

            const bool ascending = ((lane & size) == 0);
            const bool lower     = ((lane & stride) == 0);
            const bool want_min  = (lower == ascending);

            if (want_min) {
                if (pair_less(od, oi, d, i)) {
                    d = od;
                    i = oi;
                }
            } else {
                if (pair_less(d, i, od, oi)) {
                    d = od;
                    i = oi;
                }
            }
        }
    }
}

template <int K>
__device__ __forceinline__ int merge_path_partition(const float* top_d,
                                                    const int*   top_i,
                                                    const float  cand_d,
                                                    const int    cand_i,
                                                    const int    diag) {
    // Merge-path partition of A[K] (current top-K) and B[32] (sorted candidate chunk) for the
    // merged prefix of length "diag". Because |B|=32 exactly, the search interval is at most 32
    // wide, so five unrolled binary-search steps are sufficient.
    int low  = diag - kWarpSize;
    int high = diag;
    if (low  < 0) low  = 0;
    if (high > K) high = K;

#pragma unroll
    for (int iter = 0; iter < kPartitionSteps; ++iter) {
        if (low < high) {
            const int mid = (low + high) >> 1;
            const int b   = diag - mid; // 0..32

            bool b_left_is_less_than_a_mid = true;
            if (b > 0) {
                const float bd = __shfl_sync(kFullMask, cand_d, b - 1);
                const int phys = topk_phys_index(mid);
                const float ad = top_d[phys];

                if (bd < ad) {
                    b_left_is_less_than_a_mid = true;
                } else if (bd > ad) {
                    b_left_is_less_than_a_mid = false;
                } else {
                    const int bi = __shfl_sync(kFullMask, cand_i, b - 1);
                    const int ai = top_i[phys];
                    b_left_is_less_than_a_mid = (bi < ai);
                }
            }

            if (b_left_is_less_than_a_mid) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
    }

    return low;
}

template <int K>
__device__ __forceinline__ void merge_sorted_chunk(float* top_d,
                                                   int*   top_i,
                                                   float  cand_d,
                                                   int    cand_i) {
    // Exact merge-select of A[K] and B[32], keeping the smallest K items.
    //
    // Each lane owns a contiguous logical output segment of length K/32. It computes that segment
    // entirely from the old A and the current B into registers, the warp synchronizes, and only
    // then writes back to shared memory. This guarantees that every lane reads the old top-K.
    constexpr int ItemsPerThread = KnnTraits<K>::ItemsPerThread;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int diag = lane * ItemsPerThread;

    int a = merge_path_partition<K>(top_d, top_i, cand_d, cand_i, diag);
    int b = diag - a;

    float out_d[ItemsPerThread];
    int   out_i[ItemsPerThread];

#pragma unroll
    for (int t = 0; t < ItemsPerThread; ++t) {
        const bool has_b = (b < kWarpSize);
        const bool has_a = (a < K);

        float bd = 0.0f;
        float ad = 0.0f;
        int phys_a = 0;

        if (has_b) {
            bd = __shfl_sync(kFullMask, cand_d, b);
        }
        if (has_a) {
            phys_a = topk_phys_index(a);
            ad = top_d[phys_a];
        }

        if (has_b && (!has_a || (bd < ad))) {
            out_d[t] = bd;
            out_i[t] = __shfl_sync(kFullMask, cand_i, b);
            ++b;
        } else if (!has_b || (has_a && (ad < bd))) {
            out_d[t] = ad;
            out_i[t] = top_i[phys_a];
            ++a;
        } else {
            // Equal distance (or NaN/other unordered case): use the same deterministic tie-break
            // as everywhere else so sorting/merge remain consistent.
            const int bi = has_b ? __shfl_sync(kFullMask, cand_i, b) : INT_MAX;
            const int ai = has_a ? top_i[phys_a] : INT_MAX;
            if (bi < ai) {
                out_d[t] = bd;
                out_i[t] = bi;
                ++b;
            } else {
                out_d[t] = ad;
                out_i[t] = ai;
                ++a;
            }
        }
    }

    __syncwarp(kFullMask);

#pragma unroll
    for (int t = 0; t < ItemsPerThread; ++t) {
        const int logical = diag + t;
        const int phys    = topk_phys_index(logical);
        top_d[phys] = out_d[t];
        top_i[phys] = out_i[t];
    }

    __syncwarp(kFullMask);
}

template <int K>
__global__ __launch_bounds__(kBlockThreads)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                std::pair<int, float>* __restrict__ result) {
    constexpr int ItemsPerThread = KnnTraits<K>::ItemsPerThread;
    constexpr int PaddedK        = KnnTraits<K>::PaddedK;
    constexpr int WorstPhys      = KnnTraits<K>::WorstPhys;

    extern __shared__ __align__(128) unsigned char smem_raw[];

    float* const s_x     = reinterpret_cast<float*>(smem_raw + SharedLayout<K>::XOffset);
    float* const s_y     = reinterpret_cast<float*>(smem_raw + SharedLayout<K>::YOffset);
    float* const s_top_d = reinterpret_cast<float*>(smem_raw + SharedLayout<K>::TopDOffset);
    int*   const s_top_i = reinterpret_cast<int*>(smem_raw + SharedLayout<K>::TopIOffset);

    const int tid      = threadIdx.x;
    const int warp_id  = tid >> 5;
    const int lane     = tid & (kWarpSize - 1);
    const int query_id = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active  = (query_id < query_count);

    float* const warp_top_d = s_top_d + warp_id * PaddedK;
    int*   const warp_top_i = s_top_i + warp_id * PaddedK;

    float qx = 0.0f;
    float qy = 0.0f;

    if (active) {
        const float2 q = query[query_id];
        qx = q.x;
        qy = q.y;

        // Bootstrap with sorted sentinels. Because (+inf, INT_MAX) is already sorted, the exact
        // same merge path used for steady-state updates also handles initialization: the first
        // K/32 chunks simply replace infinities.
#pragma unroll
        for (int t = 0; t < ItemsPerThread; ++t) {
            const int logical = lane + t * kWarpSize;
            const int phys    = topk_phys_index(logical);
            warp_top_d[phys] = CUDART_INF_F;
            warp_top_i[phys] = INT_MAX;
        }
    }

    __syncwarp(kFullMask);

    for (int tile_base = 0; tile_base < data_count; tile_base += kTilePoints) {
        int tile_points = data_count - tile_base;
        if (tile_points > kTilePoints) tile_points = kTilePoints;

        // Whole block loads the next data tile into shared memory.
#pragma unroll
        for (int it = 0; it < kTileLoadsPerThread; ++it) {
            const int local = tid + it * kBlockThreads;
            if (local < tile_points) {
                const float2 p = data[tile_base + local];
                s_x[local] = p.x;
                s_y[local] = p.y;
            }
        }

        __syncthreads();

        if (active) {
            for (int chunk = 0; chunk < tile_points; chunk += kWarpSize) {
                const float worst_d = warp_top_d[WorstPhys];

                float cand_d = CUDART_INF_F;
                int   cand_i = INT_MAX;

                const int local = chunk + lane;
                if (local < tile_points) {
                    // Exact cheap pre-filter: if dx^2 already exceeds the current top-K threshold,
                    // the full squared distance cannot improve the result, so we skip the y load/FMA.
                    const float dx  = qx - s_x[local];
                    const float dx2 = dx * dx;
                    if (dx2 <= worst_d) {
                        const float dy = qy - s_y[local];
                        cand_d = __fmaf_rn(dy, dy, dx2);
                        cand_i = tile_base + local;
                    }
                }

                bool better = (cand_d < worst_d);
                if (!better && (cand_d == worst_d)) {
                    const int worst_i = warp_top_i[WorstPhys];
                    better = (cand_i < worst_i);
                }

                // Candidates that cannot beat the current threshold are turned into sentinels so
                // the downstream sort/merge logic stays branch-free and exact.
                if (!better) {
                    cand_d = CUDART_INF_F;
                    cand_i = INT_MAX;
                }

                // If no lane in the warp has a viable candidate, skip the expensive sort+merge.
                if (__any_sync(kFullMask, better)) {
                    warp_bitonic_sort_32(cand_d, cand_i);
                    merge_sorted_chunk<K>(warp_top_d, warp_top_i, cand_d, cand_i);
                }
            }
        }

        // Ensure every warp is done consuming the shared tile before the block overwrites it.
        __syncthreads();
    }

    if (active) {
        // The top-K buffer is kept sorted ascending, so output is already nearest-first.
        const std::size_t out_base = static_cast<std::size_t>(query_id) * static_cast<std::size_t>(K);

#pragma unroll
        for (int t = 0; t < ItemsPerThread; ++t) {
            const int logical = lane + t * kWarpSize;
            const int phys    = topk_phys_index(logical);
            result[out_base + static_cast<std::size_t>(logical)].first  = warp_top_i[phys];
            result[out_base + static_cast<std::size_t>(logical)].second = warp_top_d[phys];
        }
    }
}

template <int K>
inline void launch_knn_impl(const float2* query,
                            int query_count,
                            const float2* data,
                            int data_count,
                            std::pair<int, float>* result) {
    if (query_count <= 0) return;

    constexpr std::size_t smem_bytes = SharedLayout<K>::Bytes;

    // The kernel uses a large dynamic shared-memory region; opt in explicitly and prefer the
    // shared-heavy carveout because the algorithm is shared-memory centric.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    knn_kernel<K><<<blocks, kBlockThreads, smem_bytes>>>(query, query_count, data, data_count, result);
}

} // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) return;

    // Runtime dispatch over the only valid K values so the compiler sees K, loop trip counts,
    // shared-memory layout, and padding as compile-time constants.
    //
    // Intentionally asynchronous: callers can apply ordinary CUDA error checking/synchronization
    // outside this function if desired.
    switch (k) {
        case 32:   launch_knn_impl<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_impl<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_impl<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_impl<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_impl<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_impl<1024>(query, query_count, data, data_count, result); break;
        default:   break; // inputs are guaranteed valid by contract
    }
}

#include <cuda_runtime.h>

#include <cstddef>
#include <type_traits>
#include <utility>

namespace knn_detail {

// Problem-specific constants tuned for modern data-center GPUs.
// - 16 warps/block maximizes reuse of each shared-memory data tile across queries.
// - 4096 float2 points = 32 KiB of shared memory, which is a good balance between
//   occupancy and synchronization overhead on A100/H100-class GPUs.
constexpr unsigned FULL_MASK               = 0xFFFFFFFFu;
constexpr int      WARP_SIZE               = 32;
constexpr int      SELECT_WARPS_PER_BLOCK  = 16;
constexpr int      SELECT_THREADS_PER_BLOCK = SELECT_WARPS_PER_BLOCK * WARP_SIZE;
constexpr int      DATA_TILE_POINTS        = 4096;

constexpr int      SORT_WARPS_PER_BLOCK    = 4;
constexpr int      SORT_THREADS_PER_BLOCK  = SORT_WARPS_PER_BLOCK * WARP_SIZE;

static_assert(DATA_TILE_POINTS % WARP_SIZE == 0, "Tile size must be a multiple of warp size.");
static_assert(DATA_TILE_POINTS >= 1024, "The first tile must be large enough to seed the largest supported K.");

// Device-side POD mirror of std::pair<int,float>.
// We intentionally avoid constructing std::pair in device code because device annotations on
// standard-library constructors/operators vary across libstdc++/libc++ configurations.
// The output buffer is allocated by cudaMalloc, so treating it as raw storage with an identical POD
// layout is safe as long as size/alignment match.
struct PairIF {
    int   first;
    float second;
};

static_assert(std::is_trivially_copyable<PairIF>::value, "PairIF must be trivially copyable.");
static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>), "Unexpected std::pair<int,float> size.");
static_assert(alignof(PairIF) == alignof(std::pair<int, float>), "Unexpected std::pair<int,float> alignment.");

// Total ordering used only for the final output ordering.
// Tie resolution is arbitrary per the problem statement; using the index simply makes the order deterministic.
__device__ __forceinline__ bool pair_less(float a_dist, int a_idx, float b_dist, int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__ void swap_pair(float &a_dist, int &a_idx, float &b_dist, int &b_idx) {
    const float td = a_dist;
    const int   ti = a_idx;
    a_dist = b_dist;
    a_idx  = b_idx;
    b_dist = td;
    b_idx  = ti;
}

// Warp-wide argmax over each lane's current local worst distance.
// This identifies the globally worst stored entry among the distributed top-K reservoir.
// Replacing exactly that entry whenever a better candidate appears preserves the exact K smallest elements.
__device__ __forceinline__ void warp_argmax(float local_value, int lane,
                                            float &max_value, int &max_lane) {
    max_value = local_value;
    max_lane  = lane;

    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        const float other_value = __shfl_down_sync(FULL_MASK, max_value, offset);
        const int   other_lane  = __shfl_down_sync(FULL_MASK, max_lane,  offset);

        if ((other_value > max_value) || ((other_value == max_value) && (other_lane < max_lane))) {
            max_value = other_value;
            max_lane  = other_lane;
        }
    }

    max_value = __shfl_sync(FULL_MASK, max_value, 0);
    max_lane  = __shfl_sync(FULL_MASK, max_lane,  0);
}

// Predicated slot update used instead of true dynamic indexing.
// This is important for performance: dynamic indexing into fixed-size arrays often forces the compiler
// to spill them to local memory, while an unrolled predicated update lets it keep them scalarized in registers.
template <int ITEMS>
__device__ __forceinline__ void replace_slot(float (&dist)[ITEMS], int (&idx)[ITEMS],
                                             int slot, float new_dist, int new_idx) {
    #pragma unroll
    for (int i = 0; i < ITEMS; ++i) {
        if (slot == i) {
            dist[i] = new_dist;
            idx[i]  = new_idx;
        }
    }
}

// Scan one lane's private register-resident portion of the distributed reservoir to find its local worst item.
template <int ITEMS>
__device__ __forceinline__ void recompute_local_worst(const float (&dist)[ITEMS],
                                                      float &worst_dist, int &worst_slot) {
    worst_dist = dist[0];
    worst_slot = 0;

    #pragma unroll
    for (int i = 1; i < ITEMS; ++i) {
        if (dist[i] > worst_dist) {
            worst_dist = dist[i];
            worst_slot = i;
        }
    }
}

// Phase 1: exact top-K selection, but intentionally kept unordered.
// Each warp owns one query. A whole thread block loads a tile of data points into shared memory, and all warps
// reuse that tile. The per-query top-K is distributed across warp lanes: lane l owns K/32 entries.
//
// The hot path keeps the reservoir unordered and only tracks the current global worst element.
// This keeps update work low and, more importantly, avoids any need to keep the reservoir sorted during the
// full scan over millions of points. Final ordering is delegated to a tiny second kernel.
template <int K>
__global__ __launch_bounds__(SELECT_THREADS_PER_BLOCK, 1)
void knn_select_kernel(const float2 * __restrict__ query,
                       int query_count,
                       const float2 * __restrict__ data,
                       int data_count,
                       PairIF * __restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= WARP_SIZE && K <= 1024, "K out of supported range.");
    static_assert(DATA_TILE_POINTS >= K, "The first tile must be able to seed the initial reservoir.");

    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    __shared__ float2 s_data[DATA_TILE_POINTS];

    const int tid      = threadIdx.x;
    const int warp_id  = tid >> 5;
    const int lane     = tid & 31;
    const int query_id = static_cast<int>(blockIdx.x) * SELECT_WARPS_PER_BLOCK + warp_id;
    const bool valid_query = (query_id < query_count);

    // Load one query point per warp and broadcast it with shuffles so we do not issue 32 identical global loads.
    float qx = 0.0f;
    float qy = 0.0f;
    if (valid_query && lane == 0) {
        const float2 q = query[query_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Register-resident distributed reservoir.
    float best_dist[ITEMS_PER_LANE];
    int   best_idx [ITEMS_PER_LANE];

    #pragma unroll
    for (int i = 0; i < ITEMS_PER_LANE; ++i) {
        best_dist[i] = CUDART_INF_F;
        best_idx[i]  = -1;
    }

    float local_worst_dist = CUDART_INF_F;
    int   local_worst_slot = 0;
    float warp_worst_dist  = CUDART_INF_F;
    int   warp_worst_lane  = 0;

    // Because K <= 1024 and the tile is 4096 points, the first K points always fit in the first tile.
    // We exploit that by seeding the reservoir directly with the first K distances (one slot per lane per step)
    // before starting the usual replace-the-current-worst logic.
    int filled_slots = 0;

    for (int batch_base = 0; batch_base < data_count; batch_base += DATA_TILE_POINTS) {
        int batch_count = data_count - batch_base;
        if (batch_count > DATA_TILE_POINTS) batch_count = DATA_TILE_POINTS;

        // Cooperative block-wide load of a contiguous data tile into shared memory.
        for (int i = tid; i < batch_count; i += SELECT_THREADS_PER_BLOCK) {
            s_data[i] = data[batch_base + i];
        }
        __syncthreads();

        if (valid_query) {
            // Warp processes the tile in lock-step chunks of 32 points so every lane stays active for warp collectives.
            for (int t_base = 0; t_base < batch_count; t_base += WARP_SIZE) {

                // Fast-path warm-up: the first ITEMS_PER_LANE steps simply populate the reservoir.
                // For these steps, all lanes are guaranteed to be in-bounds by the DATA_TILE_POINTS >= K assertion.
                if (filled_slots < ITEMS_PER_LANE) {
                    const int    t        = t_base + lane;
                    const float2 p        = s_data[t];
                    const float  dx       = qx - p.x;
                    const float  dy       = qy - p.y;
                    const float  cand_dist = fmaf(dx, dx, dy * dy);
                    const int    cand_idx  = batch_base + t;

                    replace_slot(best_dist, best_idx, filled_slots, cand_dist, cand_idx);
                    ++filled_slots;

                    if (filled_slots == ITEMS_PER_LANE) {
                        recompute_local_worst(best_dist, local_worst_dist, local_worst_slot);
                        __syncwarp(FULL_MASK);
                        warp_argmax(local_worst_dist, lane, warp_worst_dist, warp_worst_lane);
                    }
                    continue;
                }

                const int t = t_base + lane;

                float cand_dist = CUDART_INF_F;
                int   cand_idx  = -1;

                if (t < batch_count) {
                    const float2 p  = s_data[t];
                    const float  dx = qx - p.x;
                    const float  dy = qy - p.y;
                    cand_dist = fmaf(dx, dx, dy * dy);
                    cand_idx  = batch_base + t;
                }

                // Only candidates better than the current K-th neighbor can matter.
                unsigned active = __ballot_sync(FULL_MASK, cand_dist < warp_worst_dist);

                // Process qualifying candidates in the natural lane/data order for this 32-point step.
                while (active) {
                    const int   sel_lane = __ffs(static_cast<int>(active)) - 1;
                    const float sel_dist = __shfl_sync(FULL_MASK, cand_dist, sel_lane);
                    const int   sel_idx  = __shfl_sync(FULL_MASK, cand_idx,  sel_lane);

                    // Only the lane that owns the current global worst slot performs the replacement.
                    if (lane == warp_worst_lane) {
                        replace_slot(best_dist, best_idx, local_worst_slot, sel_dist, sel_idx);
                        recompute_local_worst(best_dist, local_worst_dist, local_worst_slot);
                    }

                    if (lane == sel_lane) {
                        cand_dist = CUDART_INF_F; // consume this candidate
                    }

                    __syncwarp(FULL_MASK);
                    warp_argmax(local_worst_dist, lane, warp_worst_dist, warp_worst_lane);
                    active = __ballot_sync(FULL_MASK, cand_dist < warp_worst_dist);
                }
            }
        }

        // Required because the next tile load overwrites the same shared-memory buffer.
        __syncthreads();
    }

    // Store the exact but still unordered top-K into the output buffer.
    // Layout is interleaved by slot: rank = slot * 32 + lane.
    // A second kernel will sort each query's K pairs in-place without any extra device allocation.
    if (valid_query) {
        const std::size_t out_base = static_cast<std::size_t>(query_id) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
            const int rank = (slot << 5) + lane;
            result[out_base + static_cast<std::size_t>(rank)] = PairIF{best_idx[slot], best_dist[slot]};
        }
    }
}

// Phase 2: final in-place sort of each query's K output pairs.
// This kernel is intentionally separated from the long scan kernel above:
// - The selection phase stays register-resident and avoids dynamic-index spills.
// - Sorting K <= 1024 values per query is tiny compared to scanning millions of data points.
// - We reuse the already-allocated result array; no extra device memory is needed.
//
// The same interleaved ownership is used here: rank = slot * 32 + lane.
// Bitonic-sort stages are split as follows:
// - stride < 32  : partner is in another lane but the same slot
// - stride >= 32 : partner is in the same lane but another slot
//
// The split is important because in-lane partner stages must be handled pair-once to avoid
// overwriting one partner before the other partner has read the old value.
template <int K>
__global__ __launch_bounds__(SORT_THREADS_PER_BLOCK)
void knn_sort_kernel(PairIF * __restrict__ result, int query_count) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= WARP_SIZE && K <= 1024, "K out of supported range.");

    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    __shared__ float s_dist[SORT_WARPS_PER_BLOCK][K];
    __shared__ int   s_idx [SORT_WARPS_PER_BLOCK][K];

    const int tid      = threadIdx.x;
    const int warp_id  = tid >> 5;
    const int lane     = tid & 31;
    const int query_id = static_cast<int>(blockIdx.x) * SORT_WARPS_PER_BLOCK + warp_id;

    if (query_id >= query_count) {
        return;
    }

    float *warp_dist = s_dist[warp_id];
    int   *warp_idx  = s_idx [warp_id];

    const std::size_t base = static_cast<std::size_t>(query_id) * static_cast<std::size_t>(K);

    // Load this warp's query result slice from global memory into a warp-private shared-memory slice.
    #pragma unroll
    for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
        const int rank = (slot << 5) + lane;
        const PairIF p = result[base + static_cast<std::size_t>(rank)];
        warp_dist[rank] = p.second;
        warp_idx [rank] = p.first;
    }
    __syncwarp(FULL_MASK);

    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            if (stride >= WARP_SIZE) {
                // Same-lane partner stages: process each local pair exactly once.
                const int slot_xor = stride >> 5;

                #pragma unroll
                for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
                    const int partner_slot = slot ^ slot_xor;

                    if (partner_slot > slot) {
                        const int rank_a = (slot         << 5) + lane;
                        const int rank_b = (partner_slot << 5) + lane;

                        float a_dist = warp_dist[rank_a];
                        int   a_idx  = warp_idx [rank_a];
                        float b_dist = warp_dist[rank_b];
                        int   b_idx  = warp_idx [rank_b];

                        const bool ascending = ((rank_a & size) == 0);

                        if (ascending) {
                            if (pair_less(b_dist, b_idx, a_dist, a_idx)) {
                                swap_pair(a_dist, a_idx, b_dist, b_idx);
                            }
                        } else {
                            if (pair_less(a_dist, a_idx, b_dist, b_idx)) {
                                swap_pair(a_dist, a_idx, b_dist, b_idx);
                            }
                        }

                        warp_dist[rank_a] = a_dist;
                        warp_idx [rank_a] = a_idx;
                        warp_dist[rank_b] = b_dist;
                        warp_idx [rank_b] = b_idx;
                    }
                }
            } else {
                // Cross-lane partner stages: partner remains in the same slot, so every rank can update independently.
                #pragma unroll
                for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
                    const int rank    = (slot << 5) + lane;
                    const int partner = rank ^ stride;

                    const float self_dist  = warp_dist[rank];
                    const int   self_idx   = warp_idx [rank];
                    const float other_dist = warp_dist[partner];
                    const int   other_idx  = warp_idx [partner];

                    const bool ascending = ((rank & size) == 0);
                    const bool keep_min  = ((rank < partner) == ascending);

                    float out_dist = self_dist;
                    int   out_idx  = self_idx;

                    if (keep_min) {
                        if (pair_less(other_dist, other_idx, self_dist, self_idx)) {
                            out_dist = other_dist;
                            out_idx  = other_idx;
                        }
                    } else {
                        if (pair_less(self_dist, self_idx, other_dist, other_idx)) {
                            out_dist = other_dist;
                            out_idx  = other_idx;
                        }
                    }

                    warp_dist[rank] = out_dist;
                    warp_idx [rank] = out_idx;
                }
            }

            __syncwarp(FULL_MASK);
        }
    }

    // Write the final sorted neighbors back to global memory.
    #pragma unroll
    for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
        const int rank = (slot << 5) + lane;
        result[base + static_cast<std::size_t>(rank)] = PairIF{warp_idx[rank], warp_dist[rank]};
    }
}

template <int K>
inline void launch_knn_impl(const float2 *query,
                            int query_count,
                            const float2 *data,
                            int data_count,
                            PairIF *result) {
    const dim3 select_block(SELECT_THREADS_PER_BLOCK);
    const dim3 select_grid((query_count + SELECT_WARPS_PER_BLOCK - 1) / SELECT_WARPS_PER_BLOCK);
    knn_select_kernel<K><<<select_grid, select_block>>>(query, query_count, data, data_count, result);

    const dim3 sort_block(SORT_THREADS_PER_BLOCK);
    const dim3 sort_grid((query_count + SORT_WARPS_PER_BLOCK - 1) / SORT_WARPS_PER_BLOCK);
    knn_sort_kernel<K><<<sort_grid, sort_block>>>(result, query_count);
}

} // namespace knn_detail

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    // Intentionally asynchronous: no device-wide synchronization or implicit error handling is inserted here.
    // The caller can synchronize/check launch errors according to its own stream-management policy.
    if (query_count <= 0) {
        return;
    }

    auto *pod_result = reinterpret_cast<knn_detail::PairIF *>(result);

    switch (k) {
        case 32:   knn_detail::launch_knn_impl<32>  (query, query_count, data, data_count, pod_result); break;
        case 64:   knn_detail::launch_knn_impl<64>  (query, query_count, data, data_count, pod_result); break;
        case 128:  knn_detail::launch_knn_impl<128> (query, query_count, data, data_count, pod_result); break;
        case 256:  knn_detail::launch_knn_impl<256> (query, query_count, data, data_count, pod_result); break;
        case 512:  knn_detail::launch_knn_impl<512> (query, query_count, data, data_count, pod_result); break;
        case 1024: knn_detail::launch_knn_impl<1024>(query, query_count, data, data_count, pod_result); break;
        default:
            // Per the problem statement, K is always a supported power of two in [32, 1024].
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace knn_cuda_detail {

// Exact brute-force k-NN for 2D points.
// Design summary:
//   * One warp owns one query.
//   * The thread block cooperatively stages a tile of data points in shared memory.
//   * Each warp keeps a private unsorted top-K buffer in its own shared-memory stripe.
//   * During the scan we only maintain the current worst element of that K-set.
//     A new candidate is interesting iff its distance is smaller than that threshold.
//   * Accepted candidates replace the current worst element; only the owner lane of
//     that element rescans its local stripe, then the warp recomputes the global worst
//     with a warp argmax.
//   * The final K results are sorted once at the end with an in-warp bitonic sort.
//
// This avoids heap maintenance in the hot path, keeps the tile cache in shared memory,
// and does not allocate any extra device memory.

constexpr int kWarpSize = 32;

// 80 KiB/block is a deliberate choice:
//   * It fits comfortably on A100/H100.
//   * On A100, 2 * 80 KiB = 160 KiB, so two such blocks can still reside per SM.
// The remaining shared memory after the per-warp top-K buffers is used for the data tile.
constexpr int kTargetSharedBytes = 80 * 1024;

// The block width is chosen as large as possible while still leaving room for at least
// 2048 cached data points. This maximizes data reuse across queries in the same block.
template <int K, int BLOCK_THREADS>
struct KnnConfig {
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(BLOCK_THREADS % kWarpSize == 0, "BLOCK_THREADS must be a multiple of 32.");
    static_assert(BLOCK_THREADS <= 1024, "BLOCK_THREADS exceeds the CUDA block-size limit.");

    static constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpSize;
    static constexpr int kTopKBytes = kWarpsPerBlock * K * (sizeof(float) + sizeof(int));
    static constexpr int kTilePoints =
        ((kTargetSharedBytes - kTopKBytes) / static_cast<int>(sizeof(float2)) / kWarpSize) * kWarpSize;
    static constexpr int kSharedBytes =
        static_cast<int>(sizeof(float2)) * kTilePoints + kTopKBytes;

    static_assert(kTilePoints >= 2048, "Tile is smaller than the intended minimum.");
    static_assert(kTilePoints >= K, "Tile must hold the initial K points.");
    static_assert(kSharedBytes <= kTargetSharedBytes, "Shared-memory budget exceeded.");
};

using ResultPair = std::pair<int, float>;

__device__ __forceinline__ void store_result(ResultPair *dst, int index, float dist) {
    // Write members directly to avoid depending on device-callable std::pair constructors.
    dst->first = index;
    dst->second = dist;
}

__device__ __forceinline__ bool pair_greater(float da, int ia, float db, int ib) {
    return (da > db) || ((da == db) && (ia > ib));
}

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ void warp_argmax(
    float lane_max_d,
    int lane_max_slot,
    float &global_max_d,
    int &global_max_lane,
    int &global_max_slot) {
    constexpr unsigned kFullMask = 0xFFFFFFFFu;
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    float best_d = lane_max_d;
    int best_lane = lane;
    int best_slot = lane_max_slot;

    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        const float other_d = __shfl_down_sync(kFullMask, best_d, offset);
        const int other_lane = __shfl_down_sync(kFullMask, best_lane, offset);
        const int other_slot = __shfl_down_sync(kFullMask, best_slot, offset);

        if (other_d > best_d) {
            best_d = other_d;
            best_lane = other_lane;
            best_slot = other_slot;
        }
    }

    global_max_d = __shfl_sync(kFullMask, best_d, 0);
    global_max_lane = __shfl_sync(kFullMask, best_lane, 0);
    global_max_slot = __shfl_sync(kFullMask, best_slot, 0);
}

template <int K>
__device__ __forceinline__ void rescan_lane_max(
    const float *warp_best_dist,
    float &lane_max_d,
    int &lane_max_slot) {
    constexpr int kItemsPerLane = K / kWarpSize;
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    lane_max_d = warp_best_dist[lane];
    lane_max_slot = 0;

    #pragma unroll
    for (int s = 1; s < kItemsPerLane; ++s) {
        const float d = warp_best_dist[(s << 5) + lane];
        if (d > lane_max_d) {
            lane_max_d = d;
            lane_max_slot = s;
        }
    }
}

template <int K>
__device__ __forceinline__ void initialize_topk(
    float qx,
    float qy,
    const float *s_data_x,
    const float *s_data_y,
    float *warp_best_dist,
    int *warp_best_idx) {
    constexpr int kItemsPerLane = K / kWarpSize;
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    #pragma unroll
    for (int s = 0; s < kItemsPerLane; ++s) {
        const int pos = (s << 5) + lane;
        const float dx = qx - s_data_x[pos];
        const float dy = qy - s_data_y[pos];
        const float d = fmaf(dx, dx, dy * dy);
        warp_best_dist[pos] = d;
        warp_best_idx[pos] = pos;
    }
}

template <int K>
__device__ __forceinline__ void process_tile(
    float qx,
    float qy,
    const float *s_data_x,
    const float *s_data_y,
    int tile_base,
    int start,
    int tile_count,
    float *warp_best_dist,
    int *warp_best_idx,
    float &lane_max_d,
    int &lane_max_slot,
    float &global_max_d,
    int &global_max_lane,
    int &global_max_slot) {
    constexpr unsigned kFullMask = 0xFFFFFFFFu;
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    // After the initial warm-up with the first K points, the number of accepted
    // candidates is typically small. The hot path is therefore:
    //   compare against the current threshold -> reject quickly.
    for (int t = start + lane; t < tile_count; t += kWarpSize) {
        const float dx = qx - s_data_x[t];
        const float dy = qy - s_data_y[t];
        const float d = fmaf(dx, dx, dy * dy);
        const int idx = tile_base + t;

        unsigned pending = __ballot_sync(kFullMask, d < global_max_d);

        while (pending != 0u) {
            const int src_lane = __ffs(static_cast<int>(pending)) - 1;
            const float cand_d = __shfl_sync(kFullMask, d, src_lane);
            const int cand_idx = __shfl_sync(kFullMask, idx, src_lane);

            // Re-check against the updated threshold: earlier accepted candidates
            // may have lowered it since the ballot was taken.
            if (cand_d < global_max_d) {
                if (lane == global_max_lane) {
                    const int pos = (global_max_slot << 5) + lane;
                    warp_best_dist[pos] = cand_d;
                    warp_best_idx[pos] = cand_idx;

                    // Only the lane that owned the replaced worst element needs to
                    // rescan its local stripe; other lanes' local maxima are unchanged.
                    rescan_lane_max<K>(warp_best_dist, lane_max_d, lane_max_slot);
                }

                warp_argmax(lane_max_d, lane_max_slot, global_max_d, global_max_lane, global_max_slot);
            }

            pending &= (pending - 1u);
        }
    }
}

template <int K>
__device__ __forceinline__ void sort_and_store(
    float *warp_best_dist,
    int *warp_best_idx,
    ResultPair *result,
    int query_idx) {
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    // Shared-memory bitonic sort over this warp's private K entries.
    // The buffer is intentionally unsorted during the scan; sorting only once
    // at the end is far cheaper than keeping the set globally ordered.
    __syncwarp();

    for (unsigned size = 2; size <= static_cast<unsigned>(K); size <<= 1) {
        for (unsigned stride = size >> 1; stride > 0; stride >>= 1) {
            for (int pos = lane; pos < K; pos += kWarpSize) {
                const int partner = static_cast<int>(static_cast<unsigned>(pos) ^ stride);

                if (partner > pos) {
                    const bool ascending = ((static_cast<unsigned>(pos) & size) == 0u);

                    const float a_d = warp_best_dist[pos];
                    const int a_i = warp_best_idx[pos];
                    const float b_d = warp_best_dist[partner];
                    const int b_i = warp_best_idx[partner];

                    const bool do_swap = ascending
                        ? pair_greater(a_d, a_i, b_d, b_i)
                        : pair_less(a_d, a_i, b_d, b_i);

                    if (do_swap) {
                        warp_best_dist[pos] = b_d;
                        warp_best_dist[partner] = a_d;
                        warp_best_idx[pos] = b_i;
                        warp_best_idx[partner] = a_i;
                    }
                }
            }

            __syncwarp();
        }
    }

    const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

    for (int pos = lane; pos < K; pos += kWarpSize) {
        store_result(result + out_base + static_cast<std::size_t>(pos),
                     warp_best_idx[pos],
                     warp_best_dist[pos]);
    }
}

template <int K, int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS)
void knn_kernel(
    const float2 *__restrict__ query,
    int query_count,
    const float2 *__restrict__ data,
    int data_count,
    ResultPair *__restrict__ result) {
    using Config = KnnConfig<K, BLOCK_THREADS>;
    constexpr int kWarpsPerBlock = Config::kWarpsPerBlock;
    constexpr int kTilePoints = Config::kTilePoints;
    constexpr unsigned kFullMask = 0xFFFFFFFFu;

    // Shared layout:
    //   s_data_x[TilePoints]
    //   s_data_y[TilePoints]
    //   s_best_dist[WarpsPerBlock * K]
    //   s_best_idx [WarpsPerBlock * K]
    //
    // The staged data tile is stored as SoA instead of AoS(float2) to avoid the
    // 64-bit shared-memory bank conflicts that would arise from warp-wide float2 loads.
    extern __shared__ __align__(16) unsigned char shared_mem[];
    float *s_data_x = reinterpret_cast<float *>(shared_mem);
    float *s_data_y = s_data_x + kTilePoints;
    float *s_best_dist = s_data_y + kTilePoints;
    int *s_best_idx = reinterpret_cast<int *>(s_best_dist + kWarpsPerBlock * K);

    const int tid = static_cast<int>(threadIdx.x);
    const int lane = tid & (kWarpSize - 1);
    const int warp_id = tid >> 5;
    const int query_idx = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_id;
    const bool warp_active = (query_idx < query_count);

    float *warp_best_dist = s_best_dist + warp_id * K;
    int *warp_best_idx = s_best_idx + warp_id * K;

    float qx = 0.0f;
    float qy = 0.0f;

    if (warp_active) {
        float2 q;
        if (lane == 0) {
            q = query[query_idx];
        }
        qx = __shfl_sync(kFullMask, q.x, 0);
        qy = __shfl_sync(kFullMask, q.y, 0);
    }

    // First tile: load once, initialize each active warp's private top-K from the first K data points,
    // then continue with the remaining points in that tile.
    int first_tile_count = (data_count < kTilePoints) ? data_count : kTilePoints;
    for (int i = tid; i < first_tile_count; i += BLOCK_THREADS) {
        const float2 p = data[i];
        s_data_x[i] = p.x;
        s_data_y[i] = p.y;
    }
    __syncthreads();

    float lane_max_d = 0.0f;
    int lane_max_slot = 0;
    float global_max_d = 0.0f;
    int global_max_lane = 0;
    int global_max_slot = 0;

    if (warp_active) {
        initialize_topk<K>(qx, qy, s_data_x, s_data_y, warp_best_dist, warp_best_idx);
        rescan_lane_max<K>(warp_best_dist, lane_max_d, lane_max_slot);
        warp_argmax(lane_max_d, lane_max_slot, global_max_d, global_max_lane, global_max_slot);

        process_tile<K>(
            qx, qy,
            s_data_x, s_data_y,
            0, K, first_tile_count,
            warp_best_dist, warp_best_idx,
            lane_max_d, lane_max_slot,
            global_max_d, global_max_lane, global_max_slot);
    }
    __syncthreads();

    // Remaining tiles.
    for (int tile_base = kTilePoints; tile_base < data_count; tile_base += kTilePoints) {
        const int remaining = data_count - tile_base;
        const int tile_count = (remaining < kTilePoints) ? remaining : kTilePoints;

        for (int i = tid; i < tile_count; i += BLOCK_THREADS) {
            const float2 p = data[tile_base + i];
            s_data_x[i] = p.x;
            s_data_y[i] = p.y;
        }
        __syncthreads();

        if (warp_active) {
            process_tile<K>(
                qx, qy,
                s_data_x, s_data_y,
                tile_base, 0, tile_count,
                warp_best_dist, warp_best_idx,
                lane_max_d, lane_max_slot,
                global_max_d, global_max_lane, global_max_slot);
        }
        __syncthreads();
    }

    if (warp_active) {
        sort_and_store<K>(warp_best_dist, warp_best_idx, result, query_idx);
    }
}

template <int K, int BLOCK_THREADS>
inline void launch_knn_impl(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    ResultPair *result) {
    using Config = KnnConfig<K, BLOCK_THREADS>;

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + Config::kWarpsPerBlock - 1) / Config::kWarpsPerBlock);

    // Opt in to the full dynamic shared-memory budget used by this kernel.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        Config::kSharedBytes);

    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    knn_kernel<K, BLOCK_THREADS><<<grid, block, Config::kSharedBytes>>>(
        query, query_count, data, data_count, result);
}

} // namespace knn_cuda_detail

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    // Largest practical block for each K while still leaving room for a useful shared tile:
    //   K in {  32,   64,  128,  256 } -> 32 warps/block (1024 threads)
    //   K = 512                           -> 16 warps/block (512 threads)
    //   K = 1024                          ->  8 warps/block (256 threads)
    //
    // This maximizes reuse of the staged data tile across many queries in the same block.
    switch (k) {
        case 32:
            knn_cuda_detail::launch_knn_impl<32, 1024>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_cuda_detail::launch_knn_impl<64, 1024>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_cuda_detail::launch_knn_impl<128, 1024>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_cuda_detail::launch_knn_impl<256, 1024>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_cuda_detail::launch_knn_impl<512, 512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_cuda_detail::launch_knn_impl<1024, 256>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem statement guarantees valid K, so this path is only a safeguard.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace knn_detail {

// Brute-force 2D k-NN specialized for modern data-center GPUs.
//
// Key design choices:
//  - One warp (32 threads) owns one query.
//  - The full thread block cooperatively stages a tile of the data set into shared memory.
//  - Each warp keeps a private top-k state as a max-heap in shared memory.
//    Only lane 0 mutates that heap; all 32 lanes still participate in the distance scan.
//  - Candidate filtering is warp-wide: for each warp-step (up to 32 candidates, one/lane),
//    only distances strictly smaller than the current worst top-k distance are compacted
//    into a tiny 32-entry scratch buffer. This is fast because once the heap is full,
//    accepted replacements become very rare.
//  - No additional device memory is allocated; all temporary storage lives in dynamic
//    shared memory.
//  - Distances are squared L2 distances, exactly as requested.
//
// Two CTA configurations are provided:
//  - 256 threads / 8 warps / 8 queries per block
//  - 512 threads / 16 warps / 16 queries per block
// A simple heuristic chooses the larger CTA when query_count is large enough that the
// reduced grid size is still acceptable; in return, data tiles are reused across more
// queries, reducing total global-memory traffic.

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

__device__ __forceinline__ float squared_l2(const float qx, const float qy,
                                            const float px, const float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

// Standard max-heap sift-down. The heap stores the current top-k nearest neighbors,
// so the heap root is the current *worst* (largest distance) among the kept neighbors.
__device__ __forceinline__ void max_heap_sift_down(float* dist, int* idx, int root, int count) {
    float root_dist = dist[root];
    int root_idx = idx[root];
    int i = root;

    while (true) {
        int child = (i << 1) + 1;
        if (child >= count) {
            break;
        }

        const int right = child + 1;
        if (right < count && dist[right] > dist[child]) {
            child = right;
        }

        if (dist[child] <= root_dist) {
            break;
        }

        dist[i] = dist[child];
        idx[i] = idx[child];
        i = child;
    }

    dist[i] = root_dist;
    idx[i] = root_idx;
}

template <int K>
__device__ __forceinline__ void build_max_heap(float* dist, int* idx) {
#pragma unroll 1
    for (int i = (K >> 1) - 1; i >= 0; --i) {
        max_heap_sift_down(dist, idx, i, K);
    }
}

// Lane-0-only helper: consume the candidates compacted for one warp-step.
// During the initial fill phase, candidates are appended until K items are present;
// then the heap is built once. After that, only candidates better than the current
// worst distance replace the heap root.
template <int K>
__device__ __forceinline__ void consume_accepted(float* heap_dist, int* heap_idx,
                                                 int& heap_count, float& worst,
                                                 const float* scratch_dist,
                                                 const int* scratch_idx,
                                                 int accepted) {
#pragma unroll 1
    for (int t = 0; t < accepted; ++t) {
        const float d = scratch_dist[t];
        const int id = scratch_idx[t];

        if (heap_count < K) {
            heap_dist[heap_count] = d;
            heap_idx[heap_count] = id;
            ++heap_count;

            if (heap_count == K) {
                build_max_heap<K>(heap_dist, heap_idx);
                worst = heap_dist[0];
            }
        } else if (d < worst) {
            heap_dist[0] = d;
            heap_idx[0] = id;
            max_heap_sift_down(heap_dist, heap_idx, 0, K);
            worst = heap_dist[0];
        }
    }
}

// Lane-0-only finalization: repeatedly pop the max-heap root and write it from the
// back of the output slice. This yields ascending order by distance in result[0..K-1].
template <int K>
__device__ __forceinline__ void drain_heap_to_result_ascending(float* heap_dist, int* heap_idx,
                                                               std::pair<int, float>* out) {
#pragma unroll 1
    for (int end = K - 1; end > 0; --end) {
        out[end].first = heap_idx[0];
        out[end].second = heap_dist[0];

        heap_dist[0] = heap_dist[end];
        heap_idx[0] = heap_idx[end];
        max_heap_sift_down(heap_dist, heap_idx, 0, end);
    }

    out[0].first = heap_idx[0];
    out[0].second = heap_dist[0];
}

// One warp-step helper:
//  - each lane has at most one candidate
//  - accepted lanes are compacted into a 32-entry warp-private scratch buffer
//  - lane 0 consumes the compacted list and updates the heap
//
// The scratch buffer is intentionally only 32 entries deep (one per lane), which keeps
// the shared-memory footprint tiny even for K = 1024.
template <int K>
__device__ __forceinline__ void process_step(float dist, int global_idx, bool accept,
                                             unsigned lane_mask_lt, int lane,
                                             float* scratch_dist, int* scratch_idx,
                                             float* heap_dist, int* heap_idx,
                                             int& heap_count, float& worst) {
    const unsigned mask = __ballot_sync(kFullMask, accept);

    if (mask != 0u) {
        const int prefix = __popc(mask & lane_mask_lt);

        if (accept) {
            scratch_dist[prefix] = dist;
            scratch_idx[prefix] = global_idx;
        }

        const int accepted = __popc(mask);

        // Make scratch writes visible before lane 0 consumes them.
        __syncwarp(kFullMask);

        if (lane == 0) {
            consume_accepted<K>(heap_dist, heap_idx, heap_count, worst,
                                scratch_dist, scratch_idx, accepted);
        }

        // Ensure the updated threshold (worst distance) is ready before the next step.
        __syncwarp(kFullMask);
    }
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
constexpr size_t shared_bytes_for() {
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;
    return static_cast<size_t>(2) * BATCH_POINTS * sizeof(float) +                  // batch x/y
           static_cast<size_t>(WARPS_PER_BLOCK) * K * (sizeof(float) + sizeof(int)) + // heap
           static_cast<size_t>(WARPS_PER_BLOCK) * kWarpSize *
               (sizeof(float) + sizeof(int));                                       // 32-entry scratch/warp
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           std::pair<int, float>* __restrict__ result) {
    static_assert((BLOCK_THREADS % kWarpSize) == 0, "BLOCK_THREADS must be a multiple of 32.");
    static_assert((BATCH_POINTS % kWarpSize) == 0, "BATCH_POINTS must be a multiple of 32.");
    static_assert((BATCH_POINTS % BLOCK_THREADS) == 0,
                  "BATCH_POINTS must be an integer multiple of BLOCK_THREADS.");
    static_assert((BATCH_POINTS & (BATCH_POINTS - 1)) == 0,
                  "BATCH_POINTS is used with a power-of-two full/tail split.");

    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;
    constexpr int LOAD_ITERS = BATCH_POINTS / BLOCK_THREADS;
    constexpr int BATCH_STEPS = BATCH_POINTS / kWarpSize;

    extern __shared__ unsigned char smem_raw[];

    // Shared-memory layout:
    //   [batch_x | batch_y | per-warp heap dist | per-warp heap idx | per-warp scratch dist | per-warp scratch idx]
    //
    // The staged batch is stored in SoA form (x[] / y[]) rather than as float2[] to avoid
    // the mild bank-conflict pattern of consecutive 64-bit shared loads.
    float* sm_batch_x = reinterpret_cast<float*>(smem_raw);
    float* sm_batch_y = sm_batch_x + BATCH_POINTS;

    float* sm_heap_dist_all = sm_batch_y + BATCH_POINTS;
    int* sm_heap_idx_all =
        reinterpret_cast<int*>(sm_heap_dist_all + WARPS_PER_BLOCK * K);

    float* sm_scratch_dist_all =
        reinterpret_cast<float*>(sm_heap_idx_all + WARPS_PER_BLOCK * K);
    int* sm_scratch_idx_all =
        reinterpret_cast<int*>(sm_scratch_dist_all + WARPS_PER_BLOCK * kWarpSize);

    const int tid = threadIdx.x;
    const int warp = tid >> 5;
    const int lane = tid & (kWarpSize - 1);
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active = (query_idx < query_count);

    float* heap_dist = sm_heap_dist_all + warp * K;
    int* heap_idx = sm_heap_idx_all + warp * K;
    float* scratch_dist = sm_scratch_dist_all + warp * kWarpSize;
    int* scratch_idx = sm_scratch_idx_all + warp * kWarpSize;

    float qx = 0.0f;
    float qy = 0.0f;

    if (active) {
        float2 q = make_float2(0.0f, 0.0f);
        if (lane == 0) {
            q = query[query_idx];
        }
        qx = __shfl_sync(kFullMask, q.x, 0);
        qy = __shfl_sync(kFullMask, q.y, 0);
    }

    // These variables are only semantically meaningful on lane 0, but they are kept as
    // ordinary scalars so lane 0 can broadcast the threshold with __shfl_sync.
    int heap_count = 0;
    float worst = CUDART_INF_F;

    // Separate the hot path (full batches) from the single tail batch to remove all
    // per-candidate bounds checks for almost the entire scan.
    const int full_end = data_count & ~(BATCH_POINTS - 1);

    for (int base = 0; base < full_end; base += BATCH_POINTS) {
#pragma unroll
        for (int it = 0; it < LOAD_ITERS; ++it) {
            const int i = tid + it * BLOCK_THREADS;
            const float2 p = data[base + i];
            sm_batch_x[i] = p.x;
            sm_batch_y[i] = p.y;
        }

        __syncthreads();

        if (active) {
            for (int step = 0; step < BATCH_STEPS; ++step) {
                const int batch_i = step * kWarpSize + lane;
                const float threshold = __shfl_sync(kFullMask, worst, 0);

                const float px = sm_batch_x[batch_i];
                const float py = sm_batch_y[batch_i];
                const float dist = squared_l2(qx, qy, px, py);

                process_step<K>(dist, base + batch_i, dist < threshold,
                                lane_mask_lt, lane,
                                scratch_dist, scratch_idx,
                                heap_dist, heap_idx,
                                heap_count, worst);
            }
        }

        // Required because the next outer-loop iteration overwrites the staged batch.
        __syncthreads();
    }

    if (full_end < data_count) {
        const int tail_n = data_count - full_end;

        for (int i = tid; i < tail_n; i += BLOCK_THREADS) {
            const float2 p = data[full_end + i];
            sm_batch_x[i] = p.x;
            sm_batch_y[i] = p.y;
        }

        __syncthreads();

        if (active) {
            for (int step_base = 0; step_base < tail_n; step_base += kWarpSize) {
                const int batch_i = step_base + lane;
                const bool valid = (batch_i < tail_n);
                const float threshold = __shfl_sync(kFullMask, worst, 0);

                float dist = CUDART_INF_F;
                if (valid) {
                    dist = squared_l2(qx, qy, sm_batch_x[batch_i], sm_batch_y[batch_i]);
                }

                process_step<K>(dist, full_end + batch_i, valid && (dist < threshold),
                                lane_mask_lt, lane,
                                scratch_dist, scratch_idx,
                                heap_dist, heap_idx,
                                heap_count, worst);
            }
        }

        // No post-processing __syncthreads() is required here because the kernel ends
        // its data scan after the tail tile; each warp now only touches its private heap.
    }

    if (active && lane == 0) {
        drain_heap_to_result_ascending<K>(heap_dist, heap_idx, result + query_idx * K);
    }
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
inline void launch_knn_config(const float2* query,
                              int query_count,
                              const float2* data,
                              int data_count,
                              std::pair<int, float>* result) {
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;
    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    if (blocks <= 0) {
        return;
    }

    constexpr size_t smem_bytes = shared_bytes_for<K, BLOCK_THREADS, BATCH_POINTS>();

    // Opt in to the larger dynamic shared-memory budget required by the K=1024 path and
    // bias the kernel toward shared memory. The target hardware in the prompt (A100/H100)
    // supports these settings.
    (void)cudaFuncSetAttribute(knn_kernel<K, BLOCK_THREADS, BATCH_POINTS>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K, BLOCK_THREADS, BATCH_POINTS>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    // The launch is intentionally asynchronous with respect to the host.
    knn_kernel<K, BLOCK_THREADS, BATCH_POINTS>
        <<<blocks, BLOCK_THREADS, smem_bytes>>>(query, query_count, data, data_count, result);
}

template <int K>
inline void launch_knn_adaptive(const float2* query,
                                int query_count,
                                const float2* data,
                                int data_count,
                                std::pair<int, float>* result,
                                int sm_count) {
    // 1024-point tiles are large enough to amortize CTA-wide barriers and small enough to
    // fit alongside the per-warp K-sized heaps at K = 1024.
    constexpr int BATCH_POINTS = 1024;

    // Heuristic:
    //  - 16-query CTAs (512 threads) double batch reuse vs 8-query CTAs.
    //  - For smaller query batches, 8-query CTAs preserve a denser grid and avoid
    //    underfilling the GPU.
    //
    // The threshold is intentionally simple and bandwidth-oriented.
    if (query_count >= (sm_count << 3)) {
        launch_knn_config<K, 512, BATCH_POINTS>(query, query_count, data, data_count, result);
    } else {
        launch_knn_config<K, 256, BATCH_POINTS>(query, query_count, data, data_count, result);
    }
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    int sm_count = 1;
    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

#define KNN_LAUNCH_CASE(KVAL) \
    case KVAL: \
        knn_detail::launch_knn_adaptive<KVAL>(query, query_count, data, data_count, result, sm_count); \
        break

    switch (k) {
        KNN_LAUNCH_CASE(32);
        KNN_LAUNCH_CASE(64);
        KNN_LAUNCH_CASE(128);
        KNN_LAUNCH_CASE(256);
        KNN_LAUNCH_CASE(512);
        KNN_LAUNCH_CASE(1024);
        default:
            // Per the API contract, k is always valid.
            break;
    }

#undef KNN_LAUNCH_CASE
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace knn_detail {

/*
Exact exhaustive 2D k-NN on modern NVIDIA GPUs.

Design choices:
- One warp computes one query end-to-end.
- The thread block cooperatively stages a batch of data points into shared memory.
- Shared memory uses a structure-of-arrays layout (x[] and y[]) even though the input is float2:
  this avoids the shared-memory bank conflict pattern that a direct float2 cache would create.
- Each warp keeps its current top-K entirely on-chip, distributed across warp lanes:
    lane l owns the entries at global positions l, l+32, l+64, ...
  so each lane stores K/32 (distance, index) pairs in registers.
- The distributed top-K buffer is kept globally sorted at all times.
- For every new candidate that beats the current worst entry, insertion is warp-cooperative:
  only the first affected 32-element "slot" needs a ballot/shuffle based insertion; all later
  slots are just warp-wide right shifts carrying displaced boundary elements forward.
- K is specialized at compile time (32,64,128,256,512,1024), which gives the compiler a fixed
  register footprint and fully unrolled slot-manipulation loops.

The code intentionally does not allocate any additional device memory.
*/

constexpr unsigned kFullMask = 0xffffffffu;
constexpr int kWarpSize = 32;

/*
A 4096-point batch occupies 32 KiB in shared memory in SoA form:
    4096 * 2 * sizeof(float) = 32768 bytes
This stays below the default 48 KiB dynamic shared-memory limit, so no extra function
attributes are needed, while still being large enough to amortize block-wide synchronization.
*/
constexpr int kSharedBatchPoints = 4096;
constexpr std::size_t kSharedBytes =
    static_cast<std::size_t>(2) * static_cast<std::size_t>(kSharedBatchPoints) * sizeof(float);

constexpr int kSmallBlockThreads = 256;  // 8 queries/block
constexpr int kLargeBlockThreads = 512;  // 16 queries/block
constexpr int kSmallWarpsPerBlock = kSmallBlockThreads / kWarpSize;
constexpr int kLargeWarpsPerBlock = kLargeBlockThreads / kWarpSize;

static_assert((kSharedBatchPoints % kWarpSize) == 0, "Shared batch size must be a multiple of 32.");
static_assert((kSmallBlockThreads % kWarpSize) == 0, "Block size must be a multiple of 32.");
static_assert((kLargeBlockThreads % kWarpSize) == 0, "Block size must be a multiple of 32.");
static_assert(kSharedBytes <= (48u * 1024u), "Shared batch intentionally fits under 48 KiB.");

/*
Strict total order for (distance, index). The problem allows arbitrary tie resolution;
using the index as a secondary key simply makes the order deterministic and keeps the
warp insertion logic well-defined.
*/
__device__ __forceinline__ bool pair_less(float a_dist, int a_idx, float b_dist, int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

/*
Write field-wise so the kernel does not depend on a device-side std::pair constructor or
assignment operator. This matches the requested output layout.
*/
__device__ __forceinline__ void store_result(std::pair<int, float>* result, int out, int idx, float dist) {
    result[out].first = idx;
    result[out].second = dist;
}

/*
Warp-cooperative insertion into the distributed sorted top-K buffer.

Layout:
- Each lane stores ITEMS_PER_LANE = K/32 entries in registers.
- Slot s consists of top_dist[s] / top_idx[s] across all 32 lanes.
- The full K-entry sequence is:
    slot 0 (lanes 0..31), slot 1 (lanes 0..31), ...

Important optimization:
- Lane 31 owns the last element of every slot, i.e. the slot boundaries.
- We first find the earliest slot whose boundary is larger than the candidate.
- The candidate is inserted into that one slot using ballot/shuffle operations.
- The displaced boundary element from that slot is guaranteed to be <= every element
  of the next slot, so every later slot update is just a right shift with lane 0
  receiving the carry value.
*/
template <int K>
__device__ __forceinline__ void insert_candidate(
    float (&top_dist)[K / kWarpSize],
    int (&top_idx)[K / kWarpSize],
    float cand_dist,
    int cand_idx,
    int lane)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "Unsupported K specialization.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of 32.");

    constexpr int ITEMS_PER_LANE = K / kWarpSize;

    // Find the first affected slot by scanning slot boundaries in lane 31.
    int start_slot = ITEMS_PER_LANE - 1;
    if (lane == (kWarpSize - 1)) {
        #pragma unroll
        for (int s = 0; s < ITEMS_PER_LANE - 1; ++s) {
            if ((s < start_slot) && pair_less(cand_dist, cand_idx, top_dist[s], top_idx[s])) {
                start_slot = s;
            }
        }
    }
    start_slot = __shfl_sync(kFullMask, start_slot, kWarpSize - 1);

    float carry_dist = cand_dist;
    int carry_idx = cand_idx;

    #pragma unroll
    for (int s = 0; s < ITEMS_PER_LANE; ++s) {
        if (s == start_slot) {
            const float cur_dist = top_dist[s];
            const int cur_idx = top_idx[s];

            const float slot_last_dist = __shfl_sync(kFullMask, cur_dist, kWarpSize - 1);
            const int slot_last_idx = __shfl_sync(kFullMask, cur_idx, kWarpSize - 1);

            const unsigned less_mask =
                __ballot_sync(kFullMask, pair_less(cur_dist, cur_idx, carry_dist, carry_idx));
            const int insert_pos = __popc(less_mask);

            const float prev_dist = __shfl_up_sync(kFullMask, cur_dist, 1);
            const int prev_idx = __shfl_up_sync(kFullMask, cur_idx, 1);

            // insert_pos is guaranteed to be < 32 because start_slot was chosen so that
            // the candidate is better than the boundary element of this slot.
            if (lane == insert_pos) {
                top_dist[s] = carry_dist;
                top_idx[s] = carry_idx;
            } else if (lane > insert_pos) {
                top_dist[s] = prev_dist;
                top_idx[s] = prev_idx;
            }

            carry_dist = slot_last_dist;
            carry_idx = slot_last_idx;
        } else if (s > start_slot) {
            const float cur_dist = top_dist[s];
            const int cur_idx = top_idx[s];

            const float slot_last_dist = __shfl_sync(kFullMask, cur_dist, kWarpSize - 1);
            const int slot_last_idx = __shfl_sync(kFullMask, cur_idx, kWarpSize - 1);

            const float prev_dist = __shfl_up_sync(kFullMask, cur_dist, 1);
            const int prev_idx = __shfl_up_sync(kFullMask, cur_idx, 1);

            // Later slots are always affected at position 0.
            if (lane == 0) {
                top_dist[s] = carry_dist;
                top_idx[s] = carry_idx;
            } else {
                top_dist[s] = prev_dist;
                top_idx[s] = prev_idx;
            }

            carry_dist = slot_last_dist;
            carry_idx = slot_last_idx;
        }
    }
}

template <int K, int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS)
void knn_kernel(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "Unsupported K specialization.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of 32.");
    static_assert((BLOCK_THREADS % kWarpSize) == 0, "Block size must be a multiple of 32.");

    constexpr int ITEMS_PER_LANE = K / kWarpSize;
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;

    extern __shared__ float shared_mem[];
    float* const sh_x = shared_mem;
    float* const sh_y = shared_mem + kSharedBatchPoints;

    const int tid = static_cast<int>(threadIdx.x);
    const int lane = tid & (kWarpSize - 1);
    const int warp = tid >> 5;

    const int query_index = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp;
    const bool query_active = (query_index < query_count);

    // Broadcast the query point from lane 0 of each warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (query_active && lane == 0) {
        const float2 q = query[query_index];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Warp-private top-K buffer, distributed across lanes and kept globally sorted.
    float top_dist[ITEMS_PER_LANE];
    int top_idx[ITEMS_PER_LANE];

    #pragma unroll
    for (int s = 0; s < ITEMS_PER_LANE; ++s) {
        top_dist[s] = CUDART_INF_F;
        top_idx[s] = INT_MAX;
    }

    float worst_dist = CUDART_INF_F;
    int worst_idx = INT_MAX;

    // Process the data set in block-cached batches.
    for (int batch_start = 0; batch_start < data_count; batch_start += kSharedBatchPoints) {
        int current_batch = data_count - batch_start;
        if (current_batch > kSharedBatchPoints) {
            current_batch = kSharedBatchPoints;
        }

        // Cooperative global->shared staging for the whole block.
        for (int i = tid; i < current_batch; i += BLOCK_THREADS) {
            const float2 p = data[batch_start + i];
            sh_x[i] = p.x;
            sh_y[i] = p.y;
        }
        __syncthreads();

        if (query_active) {
            /*
            Iterate by warp-wide 32-point strips, not by "for (j = lane; j < ...; j += 32)" with
            per-lane trip counts. This guarantees that every lane executes the same number of
            warp-synchronous iterations, and tail lanes simply contribute an inactive +inf candidate.
            */
            const int strip_count = (current_batch + kWarpSize - 1) / kWarpSize;

            #pragma unroll 1
            for (int strip = 0; strip < strip_count; ++strip) {
                const int point_in_batch = strip * kWarpSize + lane;

                float cand_dist = CUDART_INF_F;
                int cand_idx = INT_MAX;

                if (point_in_batch < current_batch) {
                    const float dx = qx - sh_x[point_in_batch];
                    const float dy = qy - sh_y[point_in_batch];
                    cand_dist = __fmaf_rn(dx, dx, dy * dy);  // squared L2 distance
                    cand_idx = batch_start + point_in_batch;
                }

                /*
                The acceptance threshold is the current worst element in our total order.
                That threshold is monotone non-increasing over time, so lanes that are inactive
                now can never become active later in the scan.
                */
                unsigned active_mask =
                    __ballot_sync(kFullMask, pair_less(cand_dist, cand_idx, worst_dist, worst_idx));

                // Process active candidates in increasing data index order (lane order within the strip).
                while (active_mask) {
                    const int src_lane = __ffs(active_mask) - 1;
                    const float ins_dist = __shfl_sync(kFullMask, cand_dist, src_lane);
                    const int ins_idx = __shfl_sync(kFullMask, cand_idx, src_lane);

                    // Re-check against the current threshold because earlier insertions in this strip
                    // may have tightened it.
                    if (pair_less(ins_dist, ins_idx, worst_dist, worst_idx)) {
                        insert_candidate<K>(top_dist, top_idx, ins_dist, ins_idx, lane);
                        worst_dist = __shfl_sync(kFullMask, top_dist[ITEMS_PER_LANE - 1], kWarpSize - 1);
                        worst_idx = __shfl_sync(kFullMask, top_idx[ITEMS_PER_LANE - 1], kWarpSize - 1);
                    }

                    active_mask &= (active_mask - 1);
                }
            }
        }

        // All warps must finish consuming the cached batch before the next batch overwrites it.
        __syncthreads();
    }

    if (query_active) {
        const int base = query_index * K;

        #pragma unroll
        for (int s = 0; s < ITEMS_PER_LANE; ++s) {
            const int out = base + s * kWarpSize + lane;
            store_result(result, out, top_idx[s], top_dist[s]);
        }
    }
}

template <int K, int BLOCK_THREADS>
inline void launch_kernel(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;
    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K, BLOCK_THREADS><<<grid, block, kSharedBytes>>>(
        query, query_count, data, data_count, result);
}

inline void dispatch_small_block(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    // K is specialized so the register-resident top-K buffer size is known at compile time.
    switch (k) {
        case 32:   launch_kernel<32,   kSmallBlockThreads>(query, query_count, data, data_count, result); break;
        case 64:   launch_kernel<64,   kSmallBlockThreads>(query, query_count, data, data_count, result); break;
        case 128:  launch_kernel<128,  kSmallBlockThreads>(query, query_count, data, data_count, result); break;
        case 256:  launch_kernel<256,  kSmallBlockThreads>(query, query_count, data, data_count, result); break;
        case 512:  launch_kernel<512,  kSmallBlockThreads>(query, query_count, data, data_count, result); break;
        case 1024: launch_kernel<1024, kSmallBlockThreads>(query, query_count, data, data_count, result); break;
        default: break;  // Inputs are guaranteed valid; this is only a defensive fallback.
    }
}

inline void dispatch_large_block(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    /*
    512-thread blocks double shared-batch reuse (16 queries/block instead of 8), but they also
    produce fewer blocks. We only use this path when the host-side heuristic says there are
    enough queries to keep the GPU populated, and we intentionally leave K=1024 on the smaller
    block size to keep register pressure conservative.
    */
    switch (k) {
        case 32:  launch_kernel<32,  kLargeBlockThreads>(query, query_count, data, data_count, result); break;
        case 64:  launch_kernel<64,  kLargeBlockThreads>(query, query_count, data, data_count, result); break;
        case 128: launch_kernel<128, kLargeBlockThreads>(query, query_count, data, data_count, result); break;
        case 256: launch_kernel<256, kLargeBlockThreads>(query, query_count, data, data_count, result); break;
        case 512: launch_kernel<512, kLargeBlockThreads>(query, query_count, data, data_count, result); break;
        default:  dispatch_small_block(query, query_count, data, data_count, result, k); break;
    }
}

inline bool use_large_block_heuristic(int query_count, int k) {
    // Keep the largest register footprint (K=1024) on the smaller block size.
    if (k > 512) {
        return false;
    }

    int device = 0;
    int sm_count = 0;

    if (cudaGetDevice(&device) != cudaSuccess) {
        return false;
    }
    if (cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device) != cudaSuccess) {
        return false;
    }

    /*
    Use 512-thread blocks once they still provide at least one block per SM.
    In the intended "thousands of queries" regime this is a good tradeoff:
    we increase data reuse substantially without under-filling the GPU.
    */
    return query_count >= (sm_count * kLargeWarpsPerBlock);
}

}  // namespace knn_detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0 || data_count <= 0) {
        return;
    }

    if (knn_detail::use_large_block_heuristic(query_count, k)) {
        knn_detail::dispatch_large_block(query, query_count, data, data_count, result, k);
    } else {
        knn_detail::dispatch_small_block(query, query_count, data, data_count, result, k);
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

// Exact brute-force 2D k-NN for k in {32, 64, 128, 256, 512, 1024}.
//
// Main design choices:
//
// 1) One warp computes one query, exactly as requested.
// 2) The thread block stages a contiguous tile of data points into shared memory;
//    all warps in the block reuse that tile, which is critical because data_count
//    is typically orders of magnitude larger than query_count.
// 3) Each warp owns a private shared-memory segment of 2*K entries:
//      - [0, K)   : current committed top-K, kept sorted ascending by distance
//      - [K, 2*K) : unsorted candidate buffer
//    When the candidate buffer fills, the warp bitonically sorts 2*K entries
//    and keeps the first K. This amortizes maintenance cost and avoids
//    per-candidate O(K) insertion work.
// 4) Distances are squared Euclidean distances and are non-negative. Therefore
//    IEEE-754 bitwise ordering of the float distance matches numeric ordering.
//    We pack {distance_bits, index} into one 64-bit key, so the warp sorts one
//    integer array instead of separate distance/index arrays.
// 5) No extra device allocations are used; all temporary state lives in shared
//    memory or registers.
//
// On A100/H100-class GPUs, 8 warps per block is preferred because each staged
// data tile is reused by 8 queries. If per-block shared memory is too small for
// a given K, the launcher falls back to 4 warps per block, then to 2 warps with
// a smaller tile that still stays within the default 48 KiB dynamic shared limit.

typedef unsigned long long Key;

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xffffffffu;
constexpr Key kSentinelKey = (Key(0x7f800000u) << 32) | Key(0xffffffffu); // +inf distance, max index
constexpr size_t kDefaultDynamicSharedBytes = 48u * 1024u;

constexpr int kPreferredTilePoints = 2048; // 16 KiB shared tile of float2
constexpr int kFallbackTilePoints  = 1024; // 8 KiB fallback tile

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
struct KernelTraits {
    static constexpr int kBlockThreads = WARPS_PER_BLOCK * kWarpSize;
    static constexpr size_t kSharedBytes =
        size_t(WARPS_PER_BLOCK) * size_t(2 * K) * sizeof(Key) +
        size_t(TILE_POINTS) * sizeof(float2);
};

__device__ __forceinline__ Key pack_key(float dist, unsigned idx) {
    return (Key(__float_as_uint(dist)) << 32) | Key(idx);
}

__device__ __forceinline__ float unpack_distance(Key key) {
    return __uint_as_float(static_cast<unsigned>(key >> 32));
}

__device__ __forceinline__ int unpack_index(Key key) {
    return static_cast<int>(static_cast<unsigned>(key));
}

__device__ __forceinline__ float squared_l2_distance(float qx, float qy, const float2 &p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

// Warp-local bitonic sort in shared memory.
//
// The network is intentionally kept as loops instead of fully unrolling the whole
// thing for large N (up to 2048). The scan over data points is the dominant cost;
// keeping the sort code compact reduces code size and register pressure while still
// being fast enough because flushes are comparatively infrequent.
template <int N>
__device__ __forceinline__ void bitonic_sort_keys(Key *keys, int lane) {
    static_assert((N & (N - 1)) == 0, "Bitonic sort length must be a power of two.");

    #pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll 1
            for (int i = lane; i < N; i += kWarpSize) {
                const int partner = i ^ stride;
                if (partner > i) {
                    const Key a = keys[i];
                    const Key b = keys[partner];
                    const bool ascending = ((i & size) == 0);
                    const bool do_swap = ascending ? (b < a) : (a < b);
                    if (do_swap) {
                        keys[i] = b;
                        keys[partner] = a;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

template <int K>
__device__ __forceinline__ void initialize_topk(
    float qx,
    float qy,
    const float2 *tile,
    Key *warp_keys,
    int lane)
{
    #pragma unroll
    for (int i = lane; i < K; i += kWarpSize) {
        const float dist = squared_l2_distance(qx, qy, tile[i]);
        warp_keys[i] = pack_key(dist, static_cast<unsigned>(i));
    }
    __syncwarp(kFullMask);
    bitonic_sort_keys<K>(warp_keys, lane);
}

template <int K>
__device__ __forceinline__ void flush_candidate_buffer(
    Key *warp_keys,
    int lane,
    int candidate_count)
{
    // Fill the unused tail of the second half with sentinels so sorting 2*K items
    // always leaves the real best K entries in [0, K).
    for (int pos = candidate_count + lane; pos < K; pos += kWarpSize) {
        warp_keys[K + pos] = kSentinelKey;
    }
    __syncwarp(kFullMask);
    bitonic_sort_keys<2 * K>(warp_keys, lane);
}

// Push one warp-wide batch of up to 32 candidate points into the candidate buffer.
//
// "worst" is the current kth element of the committed top-K in [0, K). Buffered
// candidates can only tighten the true threshold, never loosen it, so rejecting
// dist >= worst is always safe.
template <int K>
__device__ __forceinline__ void enqueue_candidate(
    Key key,
    float dist,
    bool valid,
    Key *warp_keys,
    int lane,
    unsigned lane_prefix_mask,
    int &buffer_count,
    float &worst)
{
    bool pass = valid && (dist < worst);
    unsigned mask = __ballot_sync(kFullMask, pass);
    int accepted = __popc(mask);

    if (accepted == 0) {
        return;
    }

    if (buffer_count + accepted > K) {
        flush_candidate_buffer<K>(warp_keys, lane, buffer_count);
        buffer_count = 0;
        worst = unpack_distance(warp_keys[K - 1]);

        // Re-evaluate against the tightened threshold after compaction.
        pass = valid && (dist < worst);
        mask = __ballot_sync(kFullMask, pass);
        accepted = __popc(mask);

        if (accepted == 0) {
            return;
        }
    }

    if (pass) {
        const int rank = __popc(mask & lane_prefix_mask);
        warp_keys[K + buffer_count + rank] = key;
    }

    __syncwarp(kFullMask);
    buffer_count += accepted;

    if (buffer_count == K) {
        flush_candidate_buffer<K>(warp_keys, lane, buffer_count);
        buffer_count = 0;
        worst = unpack_distance(warp_keys[K - 1]);
    }
}

template <int K, int TILE_POINTS, bool FULL_TILE>
__device__ __forceinline__ void process_tile_candidates(
    float qx,
    float qy,
    const float2 *tile,
    int tile_begin,
    int tile_count,
    int start,
    Key *warp_keys,
    int lane,
    unsigned lane_prefix_mask,
    int &buffer_count)
{
    float worst = unpack_distance(warp_keys[K - 1]);
    const int limit = FULL_TILE ? TILE_POINTS : tile_count;

    #pragma unroll 1
    for (int base = start; base < limit; base += kWarpSize) {
        const int local_idx = base + lane;
        const bool valid = FULL_TILE || (local_idx < tile_count);

        Key key = 0;
        float dist = 0.0f;

        if (valid) {
            const float2 p = tile[local_idx];
            dist = squared_l2_distance(qx, qy, p);
            key = pack_key(dist, static_cast<unsigned>(tile_begin + local_idx));
        }

        enqueue_candidate<K>(
            key,
            dist,
            valid,
            warp_keys,
            lane,
            lane_prefix_mask,
            buffer_count,
            worst);
    }
}

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
__global__ void knn2d_kernel(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    std::pair<int, float> * __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024, "K out of supported range.");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    static_assert(TILE_POINTS >= K, "The first tile must contain at least K points.");

    extern __shared__ __align__(16) unsigned char shared_raw[];
    Key *s_keys = reinterpret_cast<Key *>(shared_raw);
    float2 *s_tile = reinterpret_cast<float2 *>(s_keys + WARPS_PER_BLOCK * (2 * K));

    const int warp_in_block = threadIdx.x >> 5;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const unsigned lane_prefix_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);

    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_in_block;
    const bool active = (query_idx < query_count);

    Key *warp_keys = s_keys + warp_in_block * (2 * K);

    // Load the query once per warp and broadcast its coordinates.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    int buffer_count = 0;

    // Cooperative global->shared staging of the data set, one contiguous tile at a time.
    for (int tile_begin = 0; tile_begin < data_count; tile_begin += TILE_POINTS) {
        int tile_count = data_count - tile_begin;
        if (tile_count > TILE_POINTS) {
            tile_count = TILE_POINTS;
        }

        for (int i = threadIdx.x; i < tile_count; i += blockDim.x) {
            s_tile[i] = data[tile_begin + i];
        }
        __syncthreads();

        if (active) {
            if (tile_begin == 0) {
                initialize_topk<K>(qx, qy, s_tile, warp_keys, lane);
            }

            const int start = (tile_begin == 0) ? K : 0;

            if (tile_count == TILE_POINTS) {
                process_tile_candidates<K, TILE_POINTS, true>(
                    qx, qy, s_tile, tile_begin, tile_count, start,
                    warp_keys, lane, lane_prefix_mask, buffer_count);
            } else {
                process_tile_candidates<K, TILE_POINTS, false>(
                    qx, qy, s_tile, tile_begin, tile_count, start,
                    warp_keys, lane, lane_prefix_mask, buffer_count);
            }
        }

        // All warps must finish reading the current tile before the block overwrites it.
        __syncthreads();
    }

    if (active) {
        if (buffer_count > 0) {
            flush_candidate_buffer<K>(warp_keys, lane, buffer_count);
        }

        const size_t out_base = size_t(query_idx) * size_t(K);

        // Direct member stores avoid relying on any device-callable std::pair constructors.
        #pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            const Key key = warp_keys[i];
            result[out_base + i].first  = unpack_index(key);
            result[out_base + i].second = unpack_distance(key);
        }
    }
}

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
inline void launch_knn_variant(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result)
{
    constexpr size_t shared_bytes = KernelTraits<K, WARPS_PER_BLOCK, TILE_POINTS>::kSharedBytes;
    constexpr int block_threads = KernelTraits<K, WARPS_PER_BLOCK, TILE_POINTS>::kBlockThreads;

    if (shared_bytes > kDefaultDynamicSharedBytes) {
        cudaFuncSetAttribute(
            knn2d_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>,
            cudaFuncAttributeMaxDynamicSharedMemorySize,
            static_cast<int>(shared_bytes));

        cudaFuncSetAttribute(
            knn2d_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>,
            cudaFuncAttributePreferredSharedMemoryCarveout,
            100);
    }

    const dim3 block(block_threads);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn2d_kernel<K, WARPS_PER_BLOCK, TILE_POINTS>
        <<<grid, block, shared_bytes>>>(query, query_count, data, data_count, result);
}

template <int K>
inline void launch_knn_best(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result)
{
    int device = 0;
    int max_optin_shared = 0;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&max_optin_shared, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    // Prefer 8 warps/block for maximum tile reuse on A100/H100-class GPUs.
    // Fall back to 4 warps if the shared-memory budget for this K is smaller,
    // then to 2 warps with a 1024-point tile that always fits inside 48 KiB.
    if (max_optin_shared >= static_cast<int>(KernelTraits<K, 8, kPreferredTilePoints>::kSharedBytes)) {
        launch_knn_variant<K, 8, kPreferredTilePoints>(query, query_count, data, data_count, result);
    } else if (max_optin_shared >= static_cast<int>(KernelTraits<K, 4, kPreferredTilePoints>::kSharedBytes)) {
        launch_knn_variant<K, 4, kPreferredTilePoints>(query, query_count, data, data_count, result);
    } else {
        launch_knn_variant<K, 2, kFallbackTilePoints>(query, query_count, data, data_count, result);
    }
}

} // anonymous namespace

// As usual for a CUDA launch wrapper, this function is asynchronous with respect
// to the host. The caller may synchronize explicitly or rely on subsequent CUDA
// operations (e.g. cudaMemcpy) that imply synchronization.
void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            launch_knn_best<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            launch_knn_best<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            launch_knn_best<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            launch_knn_best<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            launch_knn_best<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            launch_knn_best<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // Per the problem statement, k is always valid.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <type_traits>
#include <cstddef>
#include <climits>

namespace {

// Exact 2D k-NN for large query_count/data_count on modern NVIDIA data-center GPUs.
//
// Design summary:
// - One warp computes one query, exactly as requested.
// - One 256-thread block holds 8 independent queries, so every data point loaded into
//   shared memory is reused by 8 warps before being evicted.
// - Data are processed in 1024-point shared-memory batches. 1024 is large enough to
//   seed the maximum supported k (1024) from the very first batch without an extra pass.
// - Each warp stores its exact top-k in warp-private shared memory. Since k can be 1024,
//   a register-only representation would be too expensive; shared memory is the right fit.
// - The top-k buffer is double-buffered because the update step is a parallel truncated merge.
// - The top-k arrays are padded by one slot after every full group of 32 logical items
//   (except the last group). This removes the pathological bank conflicts that otherwise
//   appear when each lane writes a contiguous K/32 segment during the merge.
// - For every 32 cached data points, each lane computes one candidate distance. If none of
//   the 32 candidates beats the current kth distance, the update is skipped entirely.
//   Otherwise the 32 candidates are sorted in-register with warp shuffles and merged in
//   parallel with the current sorted top-k using merge-path partitioning.
// - Distances are squared Euclidean distances, as required.
// - Ties are allowed to resolve arbitrarily by the problem statement. Internally we use
//   (distance, index) ordering only to make sorts and merges deterministic. Candidates at
//   exactly the current cutoff distance are intentionally ignored because any tie resolution
//   is acceptable.

constexpr int kWarpSize = 32;
constexpr int kWarpShift = 5;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

// Hyper-parameters chosen for A100/H100-class GPUs.
// 8 warps/block gives high shared-memory reuse. For k=1024 it yields the same 8 active
// warps/SM as two 4-warp blocks would, but doubles reuse of the cached data batch.
// 1024 points/batch keeps the data cache modest (8 KiB) while guaranteeing the first batch
// always contains the initial seed for every supported k.
constexpr int kWarpsPerBlock = 8;
constexpr int kThreadsPerBlock = kWarpsPerBlock * kWarpSize;
constexpr int kBatchPoints = 1024;

static_assert(kBatchPoints >= 1024, "Batch size must cover the maximum supported k");

// The public API uses std::pair<int,float>. Device code stores into an equivalent POD
// because the standard-library type itself is not a convenient device-side storage type.
struct ResultEntry {
    int first;
    float second;
};

static_assert(sizeof(ResultEntry) == sizeof(std::pair<int, float>),
              "std::pair<int,float> must occupy exactly 8 bytes");
static_assert(alignof(ResultEntry) == alignof(std::pair<int, float>),
              "Unexpected std::pair<int,float> alignment");

template<int K>
struct TopLayout {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0,
                  "K must be a power of two in [32, 1024]");
    static_assert(K % kWarpSize == 0, "K must be a multiple of 32");
    static constexpr int kItemsPerLane = K / kWarpSize;
    // One padding slot after each full group of 32 logical elements except the last one.
    static constexpr int kPaddedSize = K + (K / kWarpSize) - 1;
};

__device__ __forceinline__ bool pair_less(const float a_d, const int a_i,
                                          const float b_d, const int b_i) {
    return (a_d < b_d) || ((a_d == b_d) && (a_i < b_i));
}

__device__ __forceinline__ bool pair_greater(const float a_d, const int a_i,
                                             const float b_d, const int b_i) {
    return pair_less(b_d, b_i, a_d, a_i);
}

__device__ __forceinline__ int top_phys(const int logical) {
    // Shared-memory padding map:
    // [0..31]   -> [0..31]
    // [32..63]  -> [33..64]
    // [64..95]  -> [66..97]
    // ...
    return logical + (logical >> kWarpShift);
}

__device__ __forceinline__ float sq_l2(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

template<int THREADS_PER_BLOCK, int BATCH_POINTS>
__device__ __forceinline__ void load_data_batch(float2* sh_data,
                                                const float2* __restrict__ data,
                                                const int base,
                                                const int count) {
    constexpr int kLoadsPerThread = (BATCH_POINTS + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
    const int tid = threadIdx.x;
    #pragma unroll
    for (int it = 0; it < kLoadsPerThread; ++it) {
        const int idx = tid + it * THREADS_PER_BLOCK;
        if (idx < count) {
            sh_data[idx] = data[base + idx];
        }
    }
}

__device__ __forceinline__ void warp_bitonic_sort32(float& d, int& i) {
    const unsigned lane = static_cast<unsigned>(threadIdx.x) & (kWarpSize - 1);

    #pragma unroll
    for (unsigned size = 2; size <= kWarpSize; size <<= 1) {
        #pragma unroll
        for (unsigned stride = size >> 1; stride > 0; stride >>= 1) {
            const float other_d = __shfl_xor_sync(kFullMask, d, stride);
            const int   other_i = __shfl_xor_sync(kFullMask, i, stride);

            const bool lane_low   = ((lane & stride) == 0u);
            const bool ascending  = ((lane & size) == 0u);
            const bool self_gt    = pair_greater(d, i, other_d, other_i);
            const bool take_other = lane_low ? (self_gt == ascending)
                                             : (self_gt != ascending);

            if (take_other) {
                d = other_d;
                i = other_i;
            }
        }
    }
}

template<int K>
__device__ __forceinline__ void warp_bitonic_sort_shared(float* d, int* i) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll
            for (int logical = lane; logical < K; logical += kWarpSize) {
                const int partner = logical ^ stride;
                if (partner > logical) {
                    const int phys_a = top_phys(logical);
                    const int phys_b = top_phys(partner);

                    const float a_d = d[phys_a];
                    const int   a_i = i[phys_a];
                    const float b_d = d[phys_b];
                    const int   b_i = i[phys_b];

                    const bool ascending = ((logical & size) == 0);
                    const bool swap = ascending ? pair_greater(a_d, a_i, b_d, b_i)
                                                : pair_less(a_d, a_i, b_d, b_i);

                    if (swap) {
                        d[phys_a] = b_d;
                        i[phys_a] = b_i;
                        d[phys_b] = a_d;
                        i[phys_b] = a_i;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

template<int K>
__device__ __forceinline__ int merge_path_find_b(const float* src_d, const int* src_i,
                                                 const float* cand_d, const int* cand_i,
                                                 const int m,
                                                 const int diag) {
    int low = diag - K;
    if (low < 0) low = 0;
    int high = (diag < m) ? diag : m;

    // Lower_bound on the merge diagonal over B's rank.
    while (low < high) {
        const int mid = (low + high) >> 1;
        const int a = diag - mid;

        const bool right_ok =
            (a == 0) || (mid == m) ||
            !pair_less(cand_d[mid], cand_i[mid],
                       src_d[top_phys(a - 1)], src_i[top_phys(a - 1)]);

        if (right_ok) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

template<int K>
__device__ __forceinline__ float warp_merge_topk(const float* src_d, const int* src_i,
                                                 float* dst_d, int* dst_i,
                                                 const float* cand_d, const int* cand_i,
                                                 const int m) {
    constexpr int ITEMS_PER_LANE = TopLayout<K>::kItemsPerLane;
    const int lane = threadIdx.x & (kWarpSize - 1);

    // Each lane writes one contiguous logical segment of the first K merged outputs.
    const int out_begin = lane * ITEMS_PER_LANE;
    const int out_end   = out_begin + ITEMS_PER_LANE;

    const int b_begin = merge_path_find_b<K>(src_d, src_i, cand_d, cand_i, m, out_begin);
    const int b_end   = merge_path_find_b<K>(src_d, src_i, cand_d, cand_i, m, out_end);

    int a = out_begin - b_begin;
    int b = b_begin;

    const int a_end = out_end - b_end;
    const int b_end_local = b_end;

    float last_d = CUDART_INF_F;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        bool take_b = false;
        if (b < b_end_local) {
            if (a >= a_end) {
                take_b = true;
            } else {
                const int phys_a = top_phys(a);
                take_b = pair_less(cand_d[b], cand_i[b], src_d[phys_a], src_i[phys_a]);
            }
        }

        float out_d;
        int out_i;

        if (take_b) {
            out_d = cand_d[b];
            out_i = cand_i[b];
            ++b;
        } else {
            const int phys_a = top_phys(a);
            out_d = src_d[phys_a];
            out_i = src_i[phys_a];
            ++a;
        }

        const int phys_out = top_phys(out_begin + t);
        dst_d[phys_out] = out_d;
        dst_i[phys_out] = out_i;
        last_d = out_d;
    }

    __syncwarp(kFullMask);
    // Lane 31 owns the logical tail [K - K/32, K), so its last output is the new cutoff.
    return last_d;
}

template<int K>
__device__ __forceinline__ void process_cached_batch(const float qx, const float qy,
                                                     const float2* sh_data,
                                                     const int start_pos,
                                                     const int batch_count,
                                                     const int global_base,
                                                     float*& src_d, int*& src_i,
                                                     float*& dst_d, int*& dst_i,
                                                     float* cand_d, int* cand_i,
                                                     float& worst) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int chunk = start_pos; chunk < batch_count; chunk += kWarpSize) {
        const int local_idx = chunk + lane;

        float d = CUDART_INF_F;
        int i = INT_MAX;

        if (local_idx < batch_count) {
            const float2 p = sh_data[local_idx];
            d = sq_l2(qx, qy, p);
            i = global_base + local_idx;
        }

        // Strict "< worst" is sufficient because the problem allows arbitrary tie resolution.
        const unsigned any_better = __ballot_sync(kFullMask, d < worst);
        if (any_better) {
            // Update with 32 candidates simultaneously:
            // sort the 32 lane-local candidates, then perform one parallel truncated merge.
            warp_bitonic_sort32(d, i);

            const int m = __popc(__ballot_sync(kFullMask, d < worst));

            cand_d[lane] = d;
            cand_i[lane] = i;
            __syncwarp(kFullMask);

            const float new_tail = warp_merge_topk<K>(src_d, src_i, dst_d, dst_i,
                                                      cand_d, cand_i, m);

            float* tmp_d = src_d;
            src_d = dst_d;
            dst_d = tmp_d;

            int* tmp_i = src_i;
            src_i = dst_i;
            dst_i = tmp_i;

            worst = __shfl_sync(kFullMask, new_tail, kWarpSize - 1);
        }
    }
}

template<int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize, 1)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                ResultEntry* __restrict__ result) {
    static_assert(BATCH_POINTS >= K, "The first batch must contain the initial top-k seed");
    static_assert(BATCH_POINTS % kWarpSize == 0, "Batch size must be a multiple of 32");

    extern __shared__ unsigned char smem_raw[];

    float2* sh_data = reinterpret_cast<float2*>(smem_raw);

    constexpr int PADDED_K = TopLayout<K>::kPaddedSize;

    float* sh_top0_d = reinterpret_cast<float*>(sh_data + BATCH_POINTS);
    int*   sh_top0_i = reinterpret_cast<int*>(sh_top0_d + WARPS_PER_BLOCK * PADDED_K);
    float* sh_top1_d = reinterpret_cast<float*>(sh_top0_i + WARPS_PER_BLOCK * PADDED_K);
    int*   sh_top1_i = reinterpret_cast<int*>(sh_top1_d + WARPS_PER_BLOCK * PADDED_K);
    float* sh_cand_d = reinterpret_cast<float*>(sh_top1_i + WARPS_PER_BLOCK * PADDED_K);
    int*   sh_cand_i = reinterpret_cast<int*>(sh_cand_d + WARPS_PER_BLOCK * kWarpSize);

    const int tid = threadIdx.x;
    const int lane = tid & (kWarpSize - 1);
    const int warp_id = tid >> kWarpShift;
    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active = (query_idx < query_count);

    // One query load per warp; broadcast to all 32 lanes.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    float* src_d = sh_top0_d + warp_id * PADDED_K;
    int*   src_i = sh_top0_i + warp_id * PADDED_K;
    float* dst_d = sh_top1_d + warp_id * PADDED_K;
    int*   dst_i = sh_top1_i + warp_id * PADDED_K;
    float* cand_d = sh_cand_d + warp_id * kWarpSize;
    int*   cand_i = sh_cand_i + warp_id * kWarpSize;

    // Cooperative load of the first shared-memory batch.
    const int first_batch_count = (data_count < BATCH_POINTS) ? data_count : BATCH_POINTS;
    load_data_batch<WARPS_PER_BLOCK * kWarpSize, BATCH_POINTS>(sh_data, data, 0, first_batch_count);
    __syncthreads();

    float worst = CUDART_INF_F;

    if (active) {
        // Seed the exact top-k from the first K cached points instead of starting from +inf.
        // This avoids the expensive early phase where nearly every candidate would qualify.
        constexpr int ITEMS_PER_LANE = TopLayout<K>::kItemsPerLane;

        #pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int logical = t * kWarpSize + lane;
            const int phys = top_phys(logical);
            const float2 p = sh_data[logical];
            src_d[phys] = sq_l2(qx, qy, p);
            src_i[phys] = logical;
        }

        __syncwarp(kFullMask);
        warp_bitonic_sort_shared<K>(src_d, src_i);

        if (lane == 0) {
            worst = src_d[top_phys(K - 1)];
        }
        worst = __shfl_sync(kFullMask, worst, 0);

        // The first batch may contain more than K points; process the remainder normally.
        process_cached_batch<K>(qx, qy, sh_data,
                                K, first_batch_count, 0,
                                src_d, src_i, dst_d, dst_i,
                                cand_d, cand_i,
                                worst);
    }

    // Ensure the whole block has finished consuming the first batch before it is overwritten.
    __syncthreads();

    // Remaining batches.
    for (int base = BATCH_POINTS; base < data_count; base += BATCH_POINTS) {
        const int batch_count = ((data_count - base) < BATCH_POINTS) ? (data_count - base) : BATCH_POINTS;
        load_data_batch<WARPS_PER_BLOCK * kWarpSize, BATCH_POINTS>(sh_data, data, base, batch_count);
        __syncthreads();

        if (active) {
            process_cached_batch<K>(qx, qy, sh_data,
                                    0, batch_count, base,
                                    src_d, src_i, dst_d, dst_i,
                                    cand_d, cand_i,
                                    worst);
        }

        __syncthreads();
    }

    if (active) {
        constexpr int ITEMS_PER_LANE = TopLayout<K>::kItemsPerLane;
        ResultEntry* out = result + static_cast<size_t>(query_idx) * K;

        // Write back in a striped pattern so the warp performs coalesced global stores.
        #pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int logical = t * kWarpSize + lane;
            const int phys = top_phys(logical);
            out[logical].first  = src_i[phys];
            out[logical].second = src_d[phys];
        }
    }
}

template<int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
constexpr size_t knn_shared_bytes() {
    return
        static_cast<size_t>(BATCH_POINTS) * sizeof(float2) +
        static_cast<size_t>(WARPS_PER_BLOCK) * TopLayout<K>::kPaddedSize * sizeof(float) +
        static_cast<size_t>(WARPS_PER_BLOCK) * TopLayout<K>::kPaddedSize * sizeof(int) +
        static_cast<size_t>(WARPS_PER_BLOCK) * TopLayout<K>::kPaddedSize * sizeof(float) +
        static_cast<size_t>(WARPS_PER_BLOCK) * TopLayout<K>::kPaddedSize * sizeof(int) +
        static_cast<size_t>(WARPS_PER_BLOCK) * kWarpSize * sizeof(float) +
        static_cast<size_t>(WARPS_PER_BLOCK) * kWarpSize * sizeof(int);
}

template<int K>
inline void launch_knn_case(const float2* query,
                            const int query_count,
                            const float2* data,
                            const int data_count,
                            ResultEntry* result) {
    constexpr size_t kSharedBytes = knn_shared_bytes<K, kWarpsPerBlock, kBatchPoints>();
    auto kernel = knn_kernel<K, kWarpsPerBlock, kBatchPoints>;

    // This kernel is intentionally shared-memory-heavy. Opt into the required dynamic
    // shared memory and bias the cache policy toward shared memory.
    (void)cudaFuncSetAttribute(kernel,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(kSharedBytes));
    (void)cudaFuncSetCacheConfig(kernel, cudaFuncCachePreferShared);

    const int grid = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;
    kernel<<<grid, kThreadsPerBlock, kSharedBytes>>>(query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    ResultEntry* out = reinterpret_cast<ResultEntry*>(result);

    // Compile-time specialization on K lets the compiler fully know:
    // - K/32 items per lane,
    // - the shared-memory layout,
    // - the sort/merge loop trip counts.
    switch (k) {
        case 32:   launch_knn_case<32>(query, query_count, data, data_count, out);   return;
        case 64:   launch_knn_case<64>(query, query_count, data, data_count, out);   return;
        case 128:  launch_knn_case<128>(query, query_count, data, data_count, out);  return;
        case 256:  launch_knn_case<256>(query, query_count, data, data_count, out);  return;
        case 512:  launch_knn_case<512>(query, query_count, data, data_count, out);  return;
        case 1024: launch_knn_case<1024>(query, query_count, data, data_count, out); return;
        default:   return;  // Unreachable for valid inputs.
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn_detail {

// ----------------------------------------------------------------------------
// Exact warp-per-query k-NN for 2D points.
//
// Design choices tuned for modern data-center GPUs (A100/H100 class):
//   * One warp computes one query, as requested.
//   * A 256-thread block contains 8 warps, so each shared-memory data tile is
//     reused by 8 independent queries before the block moves on.
//   * No extra device memory is allocated. All temporary state lives in shared
//     memory and registers.
//   * Each warp owns a private top-k buffer in shared memory. Because k can be
//     as large as 1024, shared memory is the right place for the exact
//     intermediate result.
//   * Distances and indices are stored as a single packed 64-bit key:
//         high 32 bits = raw IEEE-754 bits of the non-negative distance,
//         low  32 bits = index.
//     For non-negative floats, unsigned integer order matches numeric order, so
//     one 64-bit comparison orders by (distance, index).
//   * The first k points bootstrap the top-k buffer, then a warp-wide bitonic
//     sort makes it ordered once.
//   * Later points are processed in shared-memory tiles. Each lane evaluates its
//     own subset of tile points, compacting all "better than current kth"
//     candidates from the tile into a warp-private candidate buffer. The warp
//     then sorts that candidate batch and merges it into the intermediate top-k
//     result.
//   * For k = 1024, a 128-point tile keeps the shared-memory footprint low
//     enough to preserve good occupancy on A100-class parts. For smaller k,
//     256-point tiles reduce synchronization and per-tile overhead.
// ----------------------------------------------------------------------------

constexpr int kWarpSize       = 32;
constexpr int kBlockThreads   = 256;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr unsigned kFullMask  = 0xffffffffu;

using Key = unsigned long long;

static_assert(sizeof(float2) == sizeof(Key), "float2 must occupy 8 bytes");

constexpr Key kInfKey =
    (static_cast<Key>(0x7f800000u) << 32) | static_cast<Key>(0xffffffffu);

template <int K, int TILE>
struct KernelTraits {
    static_assert((K & (K - 1)) == 0, "k must be a power of two");
    static_assert(K >= 32 && K <= 1024, "supported k range is [32, 1024]");
    static_assert(TILE == 128 || TILE == 256, "supported tile sizes are 128 and 256");
    static_assert((TILE & (TILE - 1)) == 0, "tile size must be a power of two");
    static_assert((K % kWarpSize) == 0, "k must be a multiple of 32");
    static_assert((TILE % kWarpSize) == 0, "tile size must be a multiple of 32");

    enum {
        ItemsPerThread = TILE / kWarpSize,
        SharedBytes =
            static_cast<int>(sizeof(float2) * TILE +
                             sizeof(Key) * kWarpsPerBlock * (K + TILE))
    };
};

template <int K>
struct DefaultTile {
    enum { Value = 256 };
};

template <>
struct DefaultTile<1024> {
    enum { Value = 128 };
};

__device__ __forceinline__ Key pack_key(const float dist, const unsigned idx) {
    // Distances are squared L2 norms, hence non-negative. For non-negative
    // floats, the raw IEEE-754 bit pattern is monotonic as an unsigned integer.
    return (static_cast<Key>(__float_as_uint(dist)) << 32) | static_cast<Key>(idx);
}

__device__ __forceinline__ float unpack_distance(const Key key) {
    return __uint_as_float(static_cast<unsigned int>(key >> 32));
}

__device__ __forceinline__ int unpack_index(const Key key) {
    return static_cast<int>(static_cast<unsigned int>(key));
}

__device__ __forceinline__ float l2_sq(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

__device__ __forceinline__ int warp_sum_int(int v) {
    #pragma unroll
    for (int offset = kWarpSize / 2; offset > 0; offset >>= 1) {
        v += __shfl_down_sync(kFullMask, v, offset);
    }
    return __shfl_sync(kFullMask, v, 0);
}

__device__ __forceinline__ int warp_exclusive_scan_int(const int v) {
    int x = v;
    const int lane = threadIdx.x & (kWarpSize - 1);
    #pragma unroll
    for (int offset = 1; offset < kWarpSize; offset <<= 1) {
        const int y = __shfl_up_sync(kFullMask, x, offset);
        if (lane >= offset) {
            x += y;
        }
    }
    return x - v;
}

template <int LEN>
__device__ __forceinline__ void warp_bitonic_sort_shared(Key* const buf) {
    // One warp sorts one power-of-two shared-memory buffer.
    const int lane = threadIdx.x & (kWarpSize - 1);

    #pragma unroll
    for (int size = 2; size <= LEN; size <<= 1) {
        #pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll
            for (int i = lane; i < LEN; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    Key a = buf[i];
                    Key b = buf[j];
                    const bool ascending = ((i & size) == 0);
                    if (ascending) {
                        if (a > b) {
                            buf[i] = b;
                            buf[j] = a;
                        }
                    } else {
                        if (a < b) {
                            buf[i] = b;
                            buf[j] = a;
                        }
                    }
                }
            }
            __syncwarp();
        }
    }
}

template <int TILE>
__device__ __forceinline__ int candidate_sort_length(const int total);

template <>
__device__ __forceinline__ int candidate_sort_length<128>(const int total) {
    if (total <= 32) return 32;
    if (total <= 64) return 64;
    return 128;
}

template <>
__device__ __forceinline__ int candidate_sort_length<256>(const int total) {
    if (total <= 32)  return 32;
    if (total <= 64)  return 64;
    if (total <= 128) return 128;
    return 256;
}

template <int TILE>
__device__ __forceinline__ void sort_candidate_buffer(Key* const buf, const int len);

template <>
__device__ __forceinline__ void sort_candidate_buffer<128>(Key* const buf, const int len) {
    if (len == 32) {
        warp_bitonic_sort_shared<32>(buf);
    } else if (len == 64) {
        warp_bitonic_sort_shared<64>(buf);
    } else {
        warp_bitonic_sort_shared<128>(buf);
    }
}

template <>
__device__ __forceinline__ void sort_candidate_buffer<256>(Key* const buf, const int len) {
    if (len == 32) {
        warp_bitonic_sort_shared<32>(buf);
    } else if (len == 64) {
        warp_bitonic_sort_shared<64>(buf);
    } else if (len == 128) {
        warp_bitonic_sort_shared<128>(buf);
    } else {
        warp_bitonic_sort_shared<256>(buf);
    }
}

template <int K, int TILE>
__global__ __launch_bounds__(256, 2)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                std::pair<int, float>* __restrict__ result) {
    typedef KernelTraits<K, TILE> Traits;

    extern __shared__ Key smem[];

    // Shared-memory layout:
    //   [ data tile (float2[TILE]) ][ per-warp best[K] ][ per-warp candidates[TILE] ]
    float2* const s_data = reinterpret_cast<float2*>(smem);
    Key* const s_best    = reinterpret_cast<Key*>(s_data + TILE);
    Key* const s_cand    = s_best + kWarpsPerBlock * K;

    const int tid     = threadIdx.x;
    const int lane    = tid & (kWarpSize - 1);
    const int warp_id = tid >> 5;

    const int query_idx   = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active_warp = (query_idx < query_count);

    Key* const best = s_best + warp_id * K;
    Key* const cand = s_cand + warp_id * TILE;

    // Broadcast the query point from lane 0 of the owning warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active_warp) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // ------------------------------------------------------------------------
    // Phase 1: bootstrap the top-k list from the first K data points.
    // ------------------------------------------------------------------------
    for (int batch_start = 0; batch_start < K; batch_start += TILE) {
        int tile_count = K - batch_start;
        if (tile_count > TILE) tile_count = TILE;

        // The whole block cooperatively caches the current data tile.
        if (tid < tile_count) {
            s_data[tid] = data[batch_start + tid];
        }
        __syncthreads();

        if (active_warp) {
            #pragma unroll
            for (int item = 0; item < Traits::ItemsPerThread; ++item) {
                const int pos = lane + item * kWarpSize;
                if (pos < tile_count) {
                    const int data_idx = batch_start + pos;
                    best[data_idx] = pack_key(l2_sq(qx, qy, s_data[pos]),
                                              static_cast<unsigned>(data_idx));
                }
            }
        }
        __syncthreads();
    }

    if (active_warp) {
        warp_bitonic_sort_shared<K>(best);
    }
    __syncthreads();

    // ------------------------------------------------------------------------
    // Phase 2: stream the remainder of the data set in shared-memory tiles.
    //
    // Each lane evaluates its own subset of the tile and keeps every point that
    // beats the current kth distance. These lane-local candidates are compacted
    // into a contiguous warp-private candidate buffer, sorted, and merged into
    // the intermediate top-k result.
    // ------------------------------------------------------------------------
    for (int batch_start = K; batch_start < data_count; batch_start += TILE) {
        int tile_count = data_count - batch_start;
        if (tile_count > TILE) tile_count = TILE;

        if (tid < tile_count) {
            s_data[tid] = data[batch_start + tid];
        }
        __syncthreads();

        if (active_warp) {
            // Read the current kth key once and broadcast it within the warp.
            // Filtering by distance alone is sufficient because the problem
            // allows arbitrary tie handling.
            Key threshold_key = 0;
            if (lane == 0) {
                threshold_key = best[K - 1];
            }
            threshold_key = __shfl_sync(kFullMask, threshold_key, 0);
            const float threshold_dist = unpack_distance(threshold_key);

            // Keep the tile-local candidates in registers. The array index is a
            // compile-time constant thanks to full unrolling, so this remains
            // register-backed rather than spilling to local memory.
            Key local_keys[Traits::ItemsPerThread];
            unsigned valid_mask = 0u;
            int local_count = 0;

            #pragma unroll
            for (int item = 0; item < Traits::ItemsPerThread; ++item) {
                const int pos = lane + item * kWarpSize;
                Key key = kInfKey;

                if (pos < tile_count) {
                    const int data_idx = batch_start + pos;
                    const float dist = l2_sq(qx, qy, s_data[pos]);
                    if (dist < threshold_dist) {
                        key = pack_key(dist, static_cast<unsigned>(data_idx));
                        valid_mask |= (1u << item);
                        ++local_count;
                    }
                }

                local_keys[item] = key;
            }

            const int total_candidates = warp_sum_int(local_count);

            if (total_candidates > 0) {
                // Compact all lane-local candidates into a contiguous warp-
                // private shared buffer using an exclusive scan over counts.
                const int base = warp_exclusive_scan_int(local_count);
                int out = base;

                #pragma unroll
                for (int item = 0; item < Traits::ItemsPerThread; ++item) {
                    if (valid_mask & (1u << item)) {
                        cand[out++] = local_keys[item];
                    }
                }

                // Round the populated prefix up to the next power-of-two sort
                // network size, so sparse tiles do not pay for a full-tile sort.
                const int sort_len = candidate_sort_length<TILE>(total_candidates);

                for (int i = total_candidates + lane; i < sort_len; i += kWarpSize) {
                    cand[i] = kInfKey;
                }
                __syncwarp();

                sort_candidate_buffer<TILE>(cand, sort_len);
                __syncwarp();

                if (lane == 0) {
                    // Determine how many sorted candidates survive into the new
                    // top-k. Let r be that number. Since both arrays are sorted,
                    // r is the largest value such that:
                    //     cand[r - 1] < best[K - r]
                    int lo = 0;
                    int hi = (total_candidates < K) ? total_candidates : K;

                    while (lo < hi) {
                        const int mid = (lo + hi + 1) >> 1;
                        if (cand[mid - 1] < best[K - mid]) {
                            lo = mid;
                        } else {
                            hi = mid - 1;
                        }
                    }

                    const int r = lo;

                    // In-place backward merge.
                    //
                    // Only cand[0 .. r-1] survive. They displace exactly r
                    // elements from the tail of best[], so best[0 .. K-r-1] has
                    // exactly r free slots above it. That makes a backward merge
                    // into best[] safe without any extra storage.
                    int i = K - r - 1;
                    int j = r - 1;
                    int dst = K - 1;

                    while (j >= 0) {
                        if (i >= 0 && best[i] > cand[j]) {
                            best[dst--] = best[i--];
                        } else {
                            best[dst--] = cand[j--];
                        }
                    }
                }

                __syncwarp();
            }
        }

        __syncthreads();
    }

    // The top-k buffer is kept sorted ascending, so writing results is a simple
    // strided warp store.
    if (active_warp) {
        const size_t out_base =
            static_cast<size_t>(query_idx) * static_cast<size_t>(K);

        for (int i = lane; i < K; i += kWarpSize) {
            const Key key = best[i];
            result[out_base + static_cast<size_t>(i)].first  = unpack_index(key);
            result[out_base + static_cast<size_t>(i)].second = unpack_distance(key);
        }
    }
}

template <int K, int TILE>
inline void launch_knn_impl(const float2* query,
                            const int query_count,
                            const float2* data,
                            const int data_count,
                            std::pair<int, float>* result) {
    // Opt into the shared-memory size required by the chosen specialization.
    // The kernel itself remains asynchronous; the caller can synchronize if
    // host-side completion is needed.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, TILE>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        KernelTraits<K, TILE>::SharedBytes);

    (void)cudaFuncSetAttribute(
        knn_kernel<K, TILE>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    knn_kernel<K, TILE><<<grid, block, KernelTraits<K, TILE>::SharedBytes>>>(
        query, query_count, data, data_count, result);
}

template <int K>
inline void launch_knn_for_k(const float2* query,
                             const int query_count,
                             const float2* data,
                             const int data_count,
                             std::pair<int, float>* result) {
    launch_knn_impl<K, DefaultTile<K>::Value>(
        query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Dispatch to a compile-time specialization so the sort network size, the
    // per-warp top-k storage, and the tile-local candidate storage are all
    // fixed constants. That lets the compiler unroll the hot inner loops.
    switch (k) {
        case 32:
            knn_detail::launch_knn_for_k<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_detail::launch_knn_for_k<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_detail::launch_knn_for_k<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_detail::launch_knn_for_k<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_detail::launch_knn_for_k<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_detail::launch_knn_for_k<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem statement guarantees a valid power-of-two k in
            // [32, 1024], so this path is unreachable for valid callers.
            break;
    }
}

#include <cuda_runtime.h>
#include <climits>
#include <utility>

// Exact brute-force k-NN for 2D float points.
//
// Design summary:
//   * One warp owns one query.
//   * The whole block streams the data set through shared memory in batches.
//   * Each warp keeps its current top-k in a warp-private max-heap stored in shared memory.
//     Shared memory is used instead of registers/local memory because k can be as large as 1024.
//   * Each 32-point chunk of the current batch is processed by one warp in parallel.
//   * Candidate updates are cooperative:
//       - sparse chunks: warp ballot + prefix compaction into a warp-private scratch buffer,
//       - dense chunks: cooperative 32-lane bitonic sort first, then heap updates in sorted order.
//   * No extra device memory is allocated; all temporary state lives in shared memory.
//
// Notes:
//   * Distances are squared Euclidean distances, as requested.
//   * Ties are allowed to resolve arbitrarily. Internally we use index as a deterministic
//     secondary key for heap/order stability, but the fast acceptance test compares distance only.
//   * Output is sorted ascending by distance for each query, so result[i * k + j] is the j-th
//     nearest neighbor of query[i].

namespace knn_detail {

using result_pair_t = std::pair<int, float>;

constexpr int kWarpThreads          = 32;
constexpr unsigned kFullMask        = 0xffffffffu;
constexpr int kBatchLoadsPerThread  = 4;   // Four float2 loads per thread is a good balance.
constexpr int kDenseSortThreshold   = 8;   // Sort only when many lanes survive the threshold.

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool pair_greater(float da, int ia, float db, int ib) {
    return (da > db) || ((da == db) && (ia > ib));
}

// Sift one heap node down in a max-heap.
// The "worst" (largest distance, then largest index) element is kept at the root.
// count is the current heap size.
__device__ __forceinline__ void heap_sift_down(float* heap_dist, int* heap_index, int start, int count) {
    float vd = heap_dist[start];
    int   vi = heap_index[start];
    int pos = start;

    #pragma unroll 1
    while (true) {
        const int left = (pos << 1) + 1;
        if (left >= count) {
            break;
        }

        const int right = left + 1;
        int child = left;
        if (right < count && pair_greater(heap_dist[right], heap_index[right], heap_dist[left], heap_index[left])) {
            child = right;
        }

        if (!pair_greater(heap_dist[child], heap_index[child], vd, vi)) {
            break;
        }

        heap_dist[pos]  = heap_dist[child];
        heap_index[pos] = heap_index[child];
        pos = child;
    }

    heap_dist[pos]  = vd;
    heap_index[pos] = vi;
}

template <int K>
__device__ __forceinline__ void build_max_heap(float* heap_dist, int* heap_index) {
    // O(K) heap construction; done once per query after the first K candidates have been loaded.
    #pragma unroll 1
    for (int parent = (K >> 1) - 1; parent >= 0; --parent) {
        heap_sift_down(heap_dist, heap_index, parent, K);
    }
}

template <int K>
__device__ __forceinline__ void heap_sort_ascending(float* heap_dist, int* heap_index) {
    // Final O(K log K) sort. This is serialized in lane 0 on purpose:
    // the scan over millions of points dominates runtime, so a simple in-place heapsort is best.
    #pragma unroll 1
    for (int end = K - 1; end > 0; --end) {
        const float td = heap_dist[0];
        heap_dist[0]   = heap_dist[end];
        heap_dist[end] = td;

        const int ti   = heap_index[0];
        heap_index[0]  = heap_index[end];
        heap_index[end]= ti;

        heap_sift_down(heap_dist, heap_index, 0, end);
    }
}

// 32-lane ascending bitonic sort on (distance, index).
// Used only for dense update chunks; inactive lanes carry (+inf, INT_MAX).
__device__ __forceinline__ void warp_bitonic_sort_32(float& d, int& i) {
    const int lane = threadIdx.x & (kWarpThreads - 1);

    #pragma unroll
    for (int k = 2; k <= kWarpThreads; k <<= 1) {
        #pragma unroll
        for (int j = k >> 1; j > 0; j >>= 1) {
            const float od = __shfl_xor_sync(kFullMask, d, j);
            const int   oi = __shfl_xor_sync(kFullMask, i, j);

            // Standard bitonic compare-exchange rule with XOR partners.
            const bool take_min = (((lane & k) == 0) == ((lane & j) == 0));
            if (take_min) {
                if (pair_greater(d, i, od, oi)) {
                    d = od;
                    i = oi;
                }
            } else {
                if (pair_less(d, i, od, oi)) {
                    d = od;
                    i = oi;
                }
            }
        }
    }
}

template <int K, int BLOCK_THREADS>
constexpr size_t knn_shared_bytes() {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert(BLOCK_THREADS == 128 || BLOCK_THREADS == 256 || BLOCK_THREADS == 512, "Unsupported block size.");
    static_assert((BLOCK_THREADS % kWarpThreads) == 0, "Block size must be a multiple of 32.");

    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpThreads;
    constexpr int BATCH_POINTS    = BLOCK_THREADS * kBatchLoadsPerThread;

    // Layout:
    //   sh_x[BATCH_POINTS]
    //   sh_y[BATCH_POINTS]
    //   heap_dist[WARPS_PER_BLOCK * K]
    //   heap_index[WARPS_PER_BLOCK * K]
    //   scratch_dist[WARPS_PER_BLOCK * 32]
    //   scratch_index[WARPS_PER_BLOCK * 32]
    return sizeof(float) * (2 * BATCH_POINTS + WARPS_PER_BLOCK * K + WARPS_PER_BLOCK * kWarpThreads) +
           sizeof(int)   * (WARPS_PER_BLOCK * K + WARPS_PER_BLOCK * kWarpThreads);
}

// Guard against accidentally exceeding A100's opt-in per-block dynamic shared-memory limit
// if tuning constants are changed later.
static_assert(knn_shared_bytes<1024, 512>() <= 163840, "Worst-case shared-memory footprint must fit A100/H100.");

template <int K, int BLOCK_THREADS>
__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           result_pair_t* __restrict__ result) {
    static_assert((BLOCK_THREADS % kWarpThreads) == 0, "Block size must be a multiple of 32.");

    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpThreads;
    constexpr int BATCH_POINTS    = BLOCK_THREADS * kBatchLoadsPerThread;

    extern __shared__ unsigned char smem_raw[];

    // Shared-memory batch cache.
    // We store x and y separately instead of as float2 to avoid 64-bit shared-memory bank conflicts.
    float* sh_x = reinterpret_cast<float*>(smem_raw);
    float* sh_y = sh_x + BATCH_POINTS;

    // Warp-private top-k heaps.
    float* heap_dist_all = sh_y + BATCH_POINTS;
    int*   heap_index_all = reinterpret_cast<int*>(heap_dist_all + WARPS_PER_BLOCK * K);

    // Warp-private candidate scratch space (compaction/sorted dense updates).
    float* scratch_dist_all = reinterpret_cast<float*>(heap_index_all + WARPS_PER_BLOCK * K);
    int*   scratch_index_all = reinterpret_cast<int*>(scratch_dist_all + WARPS_PER_BLOCK * kWarpThreads);

    const int tid              = threadIdx.x;
    const int lane             = tid & (kWarpThreads - 1);
    const int warp_id_in_block = tid >> 5;

    const int query_idx   = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id_in_block;
    const bool active_query = (query_idx < query_count);

    float* const heap_dist    = heap_dist_all + warp_id_in_block * K;
    int*   const heap_index   = heap_index_all + warp_id_in_block * K;
    float* const scratch_dist = scratch_dist_all + warp_id_in_block * kWarpThreads;
    int*   const scratch_index= scratch_index_all + warp_id_in_block * kWarpThreads;

    // One lane fetches the query point; the warp receives it via shuffles.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active_query) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Stream the database through shared memory in batches.
    for (int batch_start = 0; batch_start < data_count; batch_start += BATCH_POINTS) {
        const int remaining   = data_count - batch_start;
        const int batch_count = (remaining < BATCH_POINTS) ? remaining : BATCH_POINTS;

        // Whole-block cooperative load into shared memory.
        // The batch size is chosen so that each thread loads exactly four float2 values when full.
        #pragma unroll
        for (int it = 0; it < kBatchLoadsPerThread; ++it) {
            const int t = tid + it * BLOCK_THREADS;
            if (t < batch_count) {
                const float2 p = data[batch_start + t];
                sh_x[t] = p.x;
                sh_y[t] = p.y;
            }
        }

        __syncthreads();

        if (active_query) {
            // Consume the shared-memory batch in 32-point chunks, one point per lane.
            #pragma unroll 1
            for (int chunk = 0; chunk < batch_count; chunk += kWarpThreads) {
                const int local_idx  = chunk + lane;
                const int global_idx = batch_start + local_idx;
                const int global_chunk_start = batch_start + chunk;

                float dist = CUDART_INF_F;
                if (local_idx < batch_count) {
                    const float dx = qx - sh_x[local_idx];
                    const float dy = qy - sh_y[local_idx];
                    dist = fmaf(dx, dx, dy * dy);
                }

                // Initialization:
                // the first K candidates are copied directly into the warp-private heap storage.
                // Because K is always a multiple of 32, initialization boundaries align with warp chunks.
                if (global_chunk_start < K) {
                    const int slot = global_idx;  // slot == data index for the first K points
                    heap_dist[slot]  = dist;
                    heap_index[slot] = slot;

                    if (global_chunk_start + kWarpThreads == K) {
                        __syncwarp(kFullMask);
                        if (lane == 0) {
                            build_max_heap<K>(heap_dist, heap_index);
                        }
                        __syncwarp(kFullMask);
                    }
                    continue;
                }

                // Fast rejection against the current worst top-k distance.
                float threshold = 0.0f;
                if (lane == 0) {
                    threshold = heap_dist[0];
                }
                threshold = __shfl_sync(kFullMask, threshold, 0);

                // Ties can be handled arbitrarily, so the fast mask compares distance only.
                const bool better = (local_idx < batch_count) && (dist < threshold);
                const unsigned better_mask = __ballot_sync(kFullMask, better);

                if (better_mask == 0u) {
                    continue;
                }

                const int better_count = __popc(better_mask);

                if (better_count > kDenseSortThreshold) {
                    // Dense-update path:
                    // many lanes survived the threshold, so it pays to sort the 32-lane candidate
                    // chunk cooperatively first. Once candidates are sorted, lane 0 can stop
                    // inserting as soon as the heap root drops below the remaining candidates.
                    float cand_dist = better ? dist : CUDART_INF_F;
                    int   cand_index = better ? global_idx : INT_MAX;

                    warp_bitonic_sort_32(cand_dist, cand_index);

                    scratch_dist[lane]  = cand_dist;
                    scratch_index[lane] = cand_index;
                    __syncwarp(kFullMask);

                    if (lane == 0) {
                        #pragma unroll 1
                        for (int c = 0; c < better_count; ++c) {
                            const float cd = scratch_dist[c];
                            if (!(cd < heap_dist[0])) {
                                break;
                            }
                            heap_dist[0]  = cd;
                            heap_index[0] = scratch_index[c];
                            heap_sift_down(heap_dist, heap_index, 0, K);
                        }
                    }

                    __syncwarp(kFullMask);
                } else {
                    // Sparse-update path:
                    // ballot + prefix compaction is cheaper than sorting the full warp.
                    if (better) {
                        const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);
                        const unsigned rank = __popc(better_mask & lane_mask_lt);
                        scratch_dist[rank]  = dist;
                        scratch_index[rank] = global_idx;
                    }
                    __syncwarp(kFullMask);

                    if (lane == 0) {
                        #pragma unroll 1
                        for (int c = 0; c < better_count; ++c) {
                            const float cd = scratch_dist[c];
                            if (cd < heap_dist[0]) {
                                heap_dist[0]  = cd;
                                heap_index[0] = scratch_index[c];
                                heap_sift_down(heap_dist, heap_index, 0, K);
                            }
                        }
                    }

                    __syncwarp(kFullMask);
                }
            }
        }

        // Make sure no warp still reads the current batch before the block overwrites shared memory.
        __syncthreads();
    }

    if (active_query) {
        if (lane == 0) {
            heap_sort_ascending<K>(heap_dist, heap_index);
        }
        __syncwarp(kFullMask);

        const size_t out_base = static_cast<size_t>(query_idx) * static_cast<size_t>(K);

        // Member-wise stores avoid depending on any device-side std::pair constructor/operator=.
        #pragma unroll 1
        for (int j = lane; j < K; j += kWarpThreads) {
            result[out_base + static_cast<size_t>(j)].first  = heap_index[j];
            result[out_base + static_cast<size_t>(j)].second = heap_dist[j];
        }
    }
}

template <int K, int BLOCK_THREADS>
inline void launch_knn_variant(const float2* query,
                               int query_count,
                               const float2* data,
                               int data_count,
                               result_pair_t* result) {
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpThreads;
    constexpr size_t SHMEM_BYTES  = knn_shared_bytes<K, BLOCK_THREADS>();

    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // The kernel is shared-memory heavy by construction; explicitly opt in to the larger
    // per-block shared-memory limit and request maximum shared-memory carveout.
    cudaFuncSetAttribute(knn_kernel<K, BLOCK_THREADS>,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         static_cast<int>(SHMEM_BYTES));
    cudaFuncSetAttribute(knn_kernel<K, BLOCK_THREADS>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    knn_kernel<K, BLOCK_THREADS><<<blocks, BLOCK_THREADS, SHMEM_BYTES>>>(
        query, query_count, data, data_count, result);
}

template <int BLOCK_THREADS>
inline void dispatch_k(const float2* query,
                       int query_count,
                       const float2* data,
                       int data_count,
                       result_pair_t* result,
                       int k) {
    // k is restricted to a small fixed set, so compile-time specialization is worth it.
    // This lets the compiler know the heap size and shared-memory layout exactly.
    switch (k) {
        case 32:   launch_knn_variant<32,   BLOCK_THREADS>(query, query_count, data, data_count, result); break;
        case 64:   launch_knn_variant<64,   BLOCK_THREADS>(query, query_count, data, data_count, result); break;
        case 128:  launch_knn_variant<128,  BLOCK_THREADS>(query, query_count, data, data_count, result); break;
        case 256:  launch_knn_variant<256,  BLOCK_THREADS>(query, query_count, data, data_count, result); break;
        case 512:  launch_knn_variant<512,  BLOCK_THREADS>(query, query_count, data, data_count, result); break;
        case 1024: launch_knn_variant<1024, BLOCK_THREADS>(query, query_count, data, data_count, result); break;
        default:   break;  // Inputs are guaranteed valid by the problem statement.
    }
}

inline int choose_block_threads(int query_count) {
    // Heuristic:
    // choose the largest queries-per-block tile that still gives at least one grid block per SM.
    // Larger blocks improve batch reuse and amortize synchronization better, but too-large blocks
    // reduce the number of blocks and can leave SMs idle when query_count is only in the low
    // thousands. The 128/256/512 set maps to 4/8/16 queries per block respectively.
    int sms = 108;  // Safe default matching A100-class hardware if the query fails.
    int device = 0;

    if (cudaGetDevice(&device) == cudaSuccess) {
        int queried_sms = 0;
        if (cudaDeviceGetAttribute(&queried_sms, cudaDevAttrMultiProcessorCount, device) == cudaSuccess &&
            queried_sms > 0) {
            sms = queried_sms;
        }
    }

    if (query_count >= sms * 16) {
        return 512;
    }
    if (query_count >= sms * 8) {
        return 256;
    }
    return 128;
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    // Normal CUDA semantics: asynchronous launch, no extra device allocation, no implicit sync.
    if (query_count <= 0) {
        return;
    }

    const int block_threads = knn_detail::choose_block_threads(query_count);

    switch (block_threads) {
        case 512:
            knn_detail::dispatch_k<512>(query, query_count, data, data_count, result, k);
            break;
        case 256:
            knn_detail::dispatch_k<256>(query, query_count, data, data_count, result, k);
            break;
        default:
            knn_detail::dispatch_k<128>(query, query_count, data, data_count, result, k);
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>

namespace {

// Exact warp-per-query k-NN for 2D points.
//
// Design choices tuned for modern data-center GPUs (A100/H100 class):
// - One warp computes one query.
// - A 256-thread block = 8 warps = 8 queries per block.
// - Data points are streamed in 1024-point tiles. 1024 is the maximum supported k,
//   so the whole initial top-k seed always comes from a single tile.
// - Each warp keeps its private exact top-k in shared memory (not local memory),
//   which avoids massive register pressure / local-memory spills for k up to 1024.
// - Candidate updates are buffered: lanes compact all points that beat the current
//   worst kept distance, then the warp sorts that small buffer and merges it into
//   the exact top-k cooperatively.
// - The top-k / candidate buffers are private per warp, but stored in shared memory;
//   warp-local synchronization uses __syncwarp(), while tile loading uses __syncthreads().
//
// Exactness note:
// The current threshold (worst distance in top-k) only decreases over time. Delaying
// a merge therefore can only admit extra candidates, never reject a true neighbor.
// This lets us amortize expensive exact merges without losing correctness.

constexpr int WARP_SIZE               = 32;
constexpr int BLOCK_THREADS           = 256;
constexpr int WARPS_PER_BLOCK         = BLOCK_THREADS / WARP_SIZE;
constexpr int BATCH_POINTS            = 1024;  // 256 threads * 4 loads/thread
constexpr int LOADS_PER_THREAD        = BATCH_POINTS / BLOCK_THREADS;
constexpr int PARTIAL_FLUSH_THRESHOLD = WARP_SIZE;  // flush a partially filled buffer once it reaches one warp's worth

static_assert(BLOCK_THREADS % WARP_SIZE == 0, "BLOCK_THREADS must be a multiple of warp size");
static_assert(BATCH_POINTS % BLOCK_THREADS == 0, "BATCH_POINTS must be divisible by BLOCK_THREADS");

struct alignas(8) Neighbor {
    float dist;
    int   idx;
};

template <int K>
struct KnnTraits {
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024]");
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    static_assert(K % WARP_SIZE == 0, "K must be divisible by warp size");

    static constexpr int items_per_lane = K / WARP_SIZE;

    // Candidate buffer cap:
    // - For small K, match K exactly.
    // - For large K, cap at 128 so that for K=1024 the whole block stays at 80 KiB:
    //     tile (8 KiB) + 8 warps * topk (8 KiB each) + 8 warps * cand (1 KiB each)
    //   which allows 2 resident 256-thread blocks / SM on A100 (164 KiB shared mem).
    static constexpr int buffer_cap = (K < 128 ? K : 128);

    static constexpr size_t shared_bytes =
        BATCH_POINTS * sizeof(float2) +
        WARPS_PER_BLOCK * K * sizeof(Neighbor) +
        WARPS_PER_BLOCK * buffer_cap * sizeof(Neighbor);
};

__device__ __forceinline__ float sq_l2_2d(float qx, float qy, const float2& p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

__device__ __forceinline__ Neighbor pos_inf_neighbor() {
    Neighbor n;
    n.dist = CUDART_INF_F;
    n.idx  = INT_MAX;
    return n;
}

// In-place bitonic sort over a warp-private shared-memory array of power-of-two length N.
// Only one warp accesses the array, so __syncwarp() is sufficient.
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(Neighbor* arr) {
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    for (int size = 2; size <= N; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += WARP_SIZE) {
                const int ixj = i ^ stride;
                if (ixj > i) {
                    const bool ascending = ((i & size) == 0);

                    Neighbor a = arr[i];
                    Neighbor b = arr[ixj];

                    const bool do_swap = ascending ? (a.dist > b.dist) : (a.dist < b.dist);
                    if (do_swap) {
                        arr[i]   = b;
                        arr[ixj] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Merge-path / co-rank partitioning for merging A[0:K) and B[0:n), both sorted ascending by distance.
// Ties are resolved stably in favor of A; tie behavior is otherwise unconstrained by the API.
template <int K>
__device__ __forceinline__ int co_rank(int diag, const Neighbor* A, const Neighbor* B, int n) {
    int low  = diag - n;
    if (low < 0) low = 0;

    int high = (diag < K) ? diag : K;

    while (low <= high) {
        const int i = (low + high) >> 1;
        const int j = diag - i;

        const float a_im1 = (i > 0) ? A[i - 1].dist : -CUDART_INF_F;
        const float a_i   = (i < K) ? A[i].dist     :  CUDART_INF_F;
        const float b_jm1 = (j > 0) ? B[j - 1].dist : -CUDART_INF_F;
        const float b_j   = (j < n) ? B[j].dist     :  CUDART_INF_F;

        if (a_im1 > b_j) {
            high = i - 1;
        } else if (b_jm1 >= a_i) {
            low = i + 1;
        } else {
            return i;
        }
    }

    return low;
}

// Exact merge of the current sorted top-k with a sorted candidate list.
// Each lane produces a contiguous output segment of length K/32 entirely in registers,
// then writes it back in-place to topk. This avoids a second shared-memory top-k buffer.
template <int K>
__device__ __forceinline__ void merge_topk_with_candidates(Neighbor* topk, const Neighbor* cand, int cand_count) {
    constexpr int ITEMS_PER_LANE = KnnTraits<K>::items_per_lane;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    const int out_begin = lane * ITEMS_PER_LANE;
    const int out_end   = out_begin + ITEMS_PER_LANE;

    const int a_begin = co_rank<K>(out_begin, topk, cand, cand_count);
    const int a_end   = co_rank<K>(out_end,   topk, cand, cand_count);
    int b_begin       = out_begin - a_begin;
    int b_end         = out_end   - a_end;

    int ai = a_begin;
    int bi = b_begin;

    // Primitive arrays are easier for the compiler to scalarize into registers than an array of structs.
    float out_dist[ITEMS_PER_LANE];
    int   out_idx [ITEMS_PER_LANE];

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const bool a_valid = (ai < a_end);
        const bool b_valid = (bi < b_end);

        const float a_dist = a_valid ? topk[ai].dist : CUDART_INF_F;
        const int   a_idx  = a_valid ? topk[ai].idx  : INT_MAX;

        const float b_dist = b_valid ? cand[bi].dist : CUDART_INF_F;
        const int   b_idx  = b_valid ? cand[bi].idx  : INT_MAX;

        // Stable A-before-B on ties.
        const bool take_b = b_valid && (!a_valid || (b_dist < a_dist));

        out_dist[t] = take_b ? b_dist : a_dist;
        out_idx [t] = take_b ? b_idx  : a_idx;

        if (take_b) {
            ++bi;
        } else {
            ++ai;
        }
    }

    // Nobody writes topk until every lane has finished reading from it.
    __syncwarp();

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        topk[out_begin + t].dist = out_dist[t];
        topk[out_begin + t].idx  = out_idx[t];
    }

    __syncwarp();
}

// Sort the current candidate buffer and merge it into the exact top-k.
template <int K>
__device__ __forceinline__ void flush_candidates(Neighbor* topk, Neighbor* cand, int& buf_count, float& threshold) {
    if (buf_count == 0) {
        return;
    }

    constexpr int BUFFER_CAP = KnnTraits<K>::buffer_cap;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Sort only the smallest power-of-two region that covers the current number of candidates.
    int sort_n = 32;
    if constexpr (BUFFER_CAP > 32) {
        if (buf_count > 32) {
            sort_n = 64;
        }
        if constexpr (BUFFER_CAP > 64) {
            if (buf_count > 64) {
                sort_n = 128;
            }
        }
    }

    // Pad the tail with +inf so bitonic sort keeps all real candidates at the front.
    for (int i = lane; i < sort_n; i += WARP_SIZE) {
        if (i >= buf_count) {
            cand[i] = pos_inf_neighbor();
        }
    }
    __syncwarp();

    if (sort_n == 32) {
        bitonic_sort_shared<32>(cand);
    } else if constexpr (BUFFER_CAP >= 64) {
        if (sort_n == 64) {
            bitonic_sort_shared<64>(cand);
        } else if constexpr (BUFFER_CAP >= 128) {
            bitonic_sort_shared<128>(cand);
        }
    }

    merge_topk_with_candidates<K>(topk, cand, buf_count);

    threshold = topk[K - 1].dist;
    buf_count = 0;
}

// Process tile[start:end) for one warp/query.
// Lanes compute one candidate each per 32-point sub-iteration, compact all points that pass the
// current threshold into the warp-private candidate buffer, and flush that buffer as needed.
template <int K>
__device__ __forceinline__ void process_tile_range(
    const float2* tile,
    int start,
    int end,
    int global_base,
    float qx,
    float qy,
    Neighbor* topk,
    Neighbor* cand,
    int& buf_count,
    float& threshold)
{
    constexpr int BUFFER_CAP = KnnTraits<K>::buffer_cap;
    constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

    const int lane = threadIdx.x & (WARP_SIZE - 1);

    for (int offset = start; offset < end; offset += WARP_SIZE) {
        const int local_idx = offset + lane;
        const bool valid_lane = (local_idx < end);

        float candidate_dist = CUDART_INF_F;
        int   candidate_idx  = -1;

        if (valid_lane) {
            const float2 p = tile[local_idx];
            candidate_dist = sq_l2_2d(qx, qy, p);
            candidate_idx  = global_base + local_idx;
        }

        bool keep = valid_lane && (candidate_dist < threshold);
        unsigned mask = __ballot_sync(FULL_MASK, keep);
        int n = __popc(mask);

        if (n == 0) {
            continue;
        }

        // If the current buffered candidates do not fit together with this warp-wide batch,
        // flush the buffer first, then re-test against the tighter threshold.
        if (buf_count + n > BUFFER_CAP) {
            flush_candidates<K>(topk, cand, buf_count, threshold);

            keep = valid_lane && (candidate_dist < threshold);
            mask = __ballot_sync(FULL_MASK, keep);
            n    = __popc(mask);

            if (n == 0) {
                continue;
            }
        }

        if (keep) {
            const unsigned lower_lane_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
            const int rank = __popc(mask & lower_lane_mask);

            cand[buf_count + rank].dist = candidate_dist;
            cand[buf_count + rank].idx  = candidate_idx;
        }

        // Shared-memory writes above must be visible before a possible flush reads the buffer.
        __syncwarp();

        buf_count += n;

        if (buf_count == BUFFER_CAP) {
            flush_candidates<K>(topk, cand, buf_count, threshold);
        }
    }
}

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result)
{
    constexpr int ITEMS_PER_LANE = KnnTraits<K>::items_per_lane;
    constexpr int BUFFER_CAP     = KnnTraits<K>::buffer_cap;
    constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

    extern __shared__ unsigned char smem_raw[];

    // Dynamic shared-memory layout:
    // [data tile | topk for all warps | candidate buffers for all warps]
    float2*  tile     = reinterpret_cast<float2*>(smem_raw);
    Neighbor* topk_all = reinterpret_cast<Neighbor*>(tile + BATCH_POINTS);
    Neighbor* cand_all = topk_all + WARPS_PER_BLOCK * K;

    const int tid      = threadIdx.x;
    const int lane     = tid & (WARP_SIZE - 1);
    const int warp_id  = tid >> 5;
    const int query_id = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active  = (query_id < query_count);

    Neighbor* topk = topk_all + warp_id * K;
    Neighbor* cand = cand_all + warp_id * BUFFER_CAP;

    // Load the query point once per warp and broadcast it with shuffles.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    int   buf_count = 0;
    float threshold = CUDART_INF_F;

    for (int batch_base = 0; batch_base < data_count; batch_base += BATCH_POINTS) {
        int valid = data_count - batch_base;
        if (valid > BATCH_POINTS) {
            valid = BATCH_POINTS;
        }

        // Whole block cooperatively loads the current data tile into shared memory.
        #pragma unroll
        for (int i = 0; i < LOADS_PER_THREAD; ++i) {
            const int local = i * BLOCK_THREADS + tid;
            if (local < valid) {
                tile[local] = data[batch_base + local];
            }
        }

        __syncthreads();

        if (active) {
            if (batch_base == 0) {
                // Seed the exact top-k from the first K points of the first tile.
                // K is always <= 1024, so this seed is entirely contained in this tile.
                #pragma unroll
                for (int t = 0; t < ITEMS_PER_LANE; ++t) {
                    const int pos = t * WARP_SIZE + lane;
                    const float2 p = tile[pos];
                    topk[pos].dist = sq_l2_2d(qx, qy, p);
                    topk[pos].idx  = pos;  // batch_base == 0 here
                }

                __syncwarp();
                bitonic_sort_shared<K>(topk);
                threshold = topk[K - 1].dist;

                // Process the remainder of the first tile and then flush it unconditionally.
                // This bootstrap makes the threshold much tighter before scanning the long tail.
                if (valid > K) {
                    process_tile_range<K>(tile, K, valid, batch_base, qx, qy, topk, cand, buf_count, threshold);
                }
                flush_candidates<K>(topk, cand, buf_count, threshold);
            } else {
                process_tile_range<K>(tile, 0, valid, batch_base, qx, qy, topk, cand, buf_count, threshold);

                // Heuristic partial flush:
                // if at least one warp's worth of candidates has accumulated by the end of a tile,
                // pay the merge cost now to keep the threshold reasonably current.
                if (buf_count >= PARTIAL_FLUSH_THRESHOLD) {
                    flush_candidates<K>(topk, cand, buf_count, threshold);
                }
            }
        }

        // All warps must finish consuming this tile before the block overwrites shared memory.
        __syncthreads();
    }

    if (active) {
        // Final exact merge for any buffered tail candidates.
        flush_candidates<K>(topk, cand, buf_count, threshold);

        // topk is kept sorted ascending by distance, so writing it out directly yields
        // result[query_id * K + j] = j-th nearest neighbor (index, squared distance).
        const int out_base = query_id * K;

        #pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int pos = t * WARP_SIZE + lane;
            result[out_base + pos].first  = topk[pos].idx;
            result[out_base + pos].second = topk[pos].dist;
        }
    }
}

template <int K>
void launch_knn_impl(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    constexpr size_t SHARED_BYTES = KnnTraits<K>::shared_bytes;

    // Opt in to the required dynamic shared-memory footprint.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHARED_BYTES));

    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // Asynchronous launch on the default stream, matching normal CUDA runtime semantics.
    knn_kernel<K><<<blocks, BLOCK_THREADS, SHARED_BYTES>>>(
        query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_impl<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_impl<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_impl<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_impl<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_impl<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_impl<1024>(query, query_count, data, data_count, result); break;
        default:
            // Inputs are guaranteed valid by contract; keep the default branch for safety.
            break;
    }
}

#include <cuda_runtime.h>

#include <climits>
#include <cstddef>
#include <type_traits>
#include <utility>

namespace {

// Exact brute-force 2D k-NN for modern NVIDIA GPUs.
//
// Design:
// - One warp owns one query for the entire scan.
// - The whole CTA streams the database through a shared-memory tile so every loaded point
//   is reused by all warps in the block.
// - Each warp keeps a private top-k list in shared memory. A second private buffer is used
//   as a merge destination so updates are fully warp-parallel and never suffer in-place
//   read-after-write hazards.
// - Updates are batch-oriented:
//     * common sparse case: if exactly one new candidate beats the current threshold,
//       insert it with a warp-parallel shift.
//     * general case: sort the 32 per-lane candidates cooperatively, then merge the
//       sorted 32-way batch with the current top-k cooperatively.
// - k is dispatched at runtime to a compile-time specialization so K/32 is constant,
//   which lets the compiler fully unroll the per-lane work.
//
// Distances are squared Euclidean distances as requested.
//
// Note on the result type:
// Writing std::pair<int,float> directly in device code is awkward on many standard library
// implementations because pair's constructors/operators are often host-only. The output
// memory comes from cudaMalloc (raw storage), so we write through a trivial ABI-compatible
// proxy {int,float}. This relies on the standard CUDA toolchain's de-facto pair layout.
struct ResultPairDevice {
    int   first;
    float second;
};

static_assert(std::is_trivially_copyable<std::pair<int, float>>::value,
              "std::pair<int,float> must be trivially copyable for device-side raw writes.");
static_assert(sizeof(ResultPairDevice) == sizeof(std::pair<int, float>),
              "Unexpected std::pair<int,float> layout; device result proxy size mismatch.");

constexpr int      WARP_THREADS  = 32;
constexpr unsigned FULL_MASK     = 0xffffffffu;
constexpr int      INVALID_INDEX = INT_MAX;
constexpr float    INF_DISTANCE  = CUDART_INF_F;

// Deterministic total order used only internally to sort/merge candidates.
// The problem allows arbitrary tie resolution; the index tie-break is just a convenient
// way to make the order total and deterministic.
__device__ __forceinline__ bool pair_less(float a_dist, int a_idx,
                                          float b_dist, int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

// 32-way bitonic sort over one (distance,index) pair per lane.
__device__ __forceinline__ void warp_sort32(float &dist, int &idx, int lane) {
#pragma unroll
    for (int size = 2; size <= WARP_THREADS; size <<= 1) {
#pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            const float other_dist = __shfl_xor_sync(FULL_MASK, dist, stride);
            const int   other_idx  = __shfl_xor_sync(FULL_MASK, idx,  stride);

            const bool lower_lane = ((lane & stride) == 0);
            const bool ascending  = ((lane & size) == 0);
            const bool want_min   = ascending ? lower_lane : !lower_lane;
            const bool self_less  = pair_less(dist, idx, other_dist, other_idx);
            const bool take_other = want_min ? !self_less : self_less;

            dist = take_other ? other_dist : dist;
            idx  = take_other ? other_idx  : idx;
        }
    }
}

// Fast path for the common post-convergence case where exactly one new candidate beats the
// current k-th distance. Lane 0 finds the insertion point; the whole warp materializes the
// shifted output in parallel.
template <int K>
__device__ __forceinline__ void warp_single_insert(const float *cur_dist,
                                                   const int   *cur_idx,
                                                   float cand_dist,
                                                   int   cand_idx,
                                                   float *out_dist,
                                                   int   *out_idx,
                                                   int lane) {
    constexpr int CHUNK = K / WARP_THREADS;

    int pos = 0;
    if (lane == 0) {
        int lo = 0;
        int hi = K;
        while (lo < hi) {
            const int mid = (lo + hi) >> 1;
            if (pair_less(cur_dist[mid], cur_idx[mid], cand_dist, cand_idx)) {
                lo = mid + 1;
            } else {
                hi = mid;
            }
        }
        pos = lo;
    }
    pos = __shfl_sync(FULL_MASK, pos, 0);

    const int base = lane * CHUNK;
#pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        const int out = base + t;
        if (out < pos) {
            out_dist[out] = cur_dist[out];
            out_idx[out]  = cur_idx[out];
        } else if (out == pos) {
            out_dist[out] = cand_dist;
            out_idx[out]  = cand_idx;
        } else {
            out_dist[out] = cur_dist[out - 1];
            out_idx[out]  = cur_idx[out - 1];
        }
    }
}

// General warp-parallel merge:
// - A[0..K) is the current sorted top-k.
// - B[0..32) is the sorted per-lane candidate batch (with +inf sentinels for inactive lanes).
// - We keep only the first K outputs of merge(A,B).
//
// Lane l owns the contiguous output strip [l*CHUNK, (l+1)*CHUNK). Its strip start is found
// by a tiny merge-path search over the candidate axis. Because B has only 32 elements, this
// search is cheap and fully unrolled.
template <int K>
__device__ __forceinline__ void warp_merge32(const float *cur_dist,
                                             const int   *cur_idx,
                                             float cand_dist,
                                             int   cand_idx,
                                             float *out_dist,
                                             int   *out_idx,
                                             int lane) {
    constexpr int CHUNK = K / WARP_THREADS;
    constexpr int MERGE_SEARCH_ITERS = 6;  // ceil(log2(32 + 1))

    const int diag = lane * CHUNK;

    int low  = 0;
    int high = (diag < WARP_THREADS) ? diag : WARP_THREADS;

#pragma unroll
    for (int iter = 0; iter < MERGE_SEARCH_ITERS; ++iter) {
        if (low < high) {
            const int mid = (low + high + 1) >> 1;
            const int a   = diag - mid;

            const float b_prev_dist = __shfl_sync(FULL_MASK, cand_dist, mid - 1);
            const int   b_prev_idx  = __shfl_sync(FULL_MASK, cand_idx,  mid - 1);

            const float a_curr_dist = (a < K) ? cur_dist[a] : INF_DISTANCE;
            const int   a_curr_idx  = (a < K) ? cur_idx[a]  : INVALID_INDEX;

            if (pair_less(b_prev_dist, b_prev_idx, a_curr_dist, a_curr_idx)) {
                low = mid;
            } else {
                high = mid - 1;
            }
        }
    }

    int a = diag - low;
    int b = low;

    const int out_base = diag;
#pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        const float a_dist = (a < K) ? cur_dist[a] : INF_DISTANCE;
        const int   a_idx  = (a < K) ? cur_idx[a]  : INVALID_INDEX;

        const float b_dist = (b < WARP_THREADS) ? __shfl_sync(FULL_MASK, cand_dist, b) : INF_DISTANCE;
        const int   b_idx  = (b < WARP_THREADS) ? __shfl_sync(FULL_MASK, cand_idx,  b) : INVALID_INDEX;

        const bool take_b = pair_less(b_dist, b_idx, a_dist, a_idx);

        out_dist[out_base + t] = take_b ? b_dist : a_dist;
        out_idx [out_base + t] = take_b ? b_idx  : a_idx;

        b += take_b ? 1 : 0;
        a += take_b ? 0 : 1;
    }
}

template <int K>
__global__ void knn2d_kernel(const float2 * __restrict__ query,
                             int query_count,
                             const float2 * __restrict__ data,
                             int data_count,
                             ResultPairDevice * __restrict__ result) {
    static_assert(K >= WARP_THREADS && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");

    constexpr int CHUNK = K / WARP_THREADS;

    // Shared-memory layout:
    //   [ block-wide data tile | per-warp cur_dist | per-warp cur_idx |
    //     per-warp nxt_dist    | per-warp nxt_idx ]
    extern __shared__ unsigned char smem_raw[];
    float2 *tile = reinterpret_cast<float2 *>(smem_raw);

    const int warps_per_block = blockDim.x / WARP_THREADS;

    float *dist_buf0 = reinterpret_cast<float *>(tile + blockDim.x);
    int   *idx_buf0  = reinterpret_cast<int *>(dist_buf0 + warps_per_block * K);
    float *dist_buf1 = reinterpret_cast<float *>(idx_buf0  + warps_per_block * K);
    int   *idx_buf1  = reinterpret_cast<int *>(dist_buf1 + warps_per_block * K);

    const int tid     = threadIdx.x;
    const int lane    = tid & (WARP_THREADS - 1);
    const int warp_id = tid >> 5;

    const int query_idx = blockIdx.x * warps_per_block + warp_id;
    const bool active   = (query_idx < query_count);

    float *cur_dist = dist_buf0 + warp_id * K;
    int   *cur_idx  = idx_buf0  + warp_id * K;
    float *nxt_dist = dist_buf1 + warp_id * K;
    int   *nxt_idx  = idx_buf1  + warp_id * K;

    // Initialize the current top-k buffer to (+inf, invalid).
#pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        const int pos = t * WARP_THREADS + lane;
        cur_dist[pos] = INF_DISTANCE;
        cur_idx[pos]  = INVALID_INDEX;
    }

    // Broadcast the warp's query point once.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    if (active) {
        qx = __shfl_sync(FULL_MASK, qx, 0);
        qy = __shfl_sync(FULL_MASK, qy, 0);
    }

    // Keep the current threshold in a register and update it only when the top-k changes.
    float threshold = INF_DISTANCE;

    // Stream the full dataset through a shared tile.
    for (int tile_base = 0; tile_base < data_count; tile_base += blockDim.x) {
        const int g = tile_base + tid;
        if (g < data_count) {
            tile[tid] = data[g];
        }

        __syncthreads();

        int tile_count = data_count - tile_base;
        if (tile_count > blockDim.x) tile_count = blockDim.x;

        if (active) {
            // Each warp consumes the tile in 32-point micro-batches so every lane naturally
            // owns one candidate in the batch.
            for (int local_base = 0; local_base < tile_count; local_base += WARP_THREADS) {
                const int local = local_base + lane;

                float cand_dist = INF_DISTANCE;
                int   cand_idx  = INVALID_INDEX;

                if (local < tile_count) {
                    const float2 p  = tile[local];
                    const float  dx = qx - p.x;
                    const float  dy = qy - p.y;
                    cand_dist = fmaf(dx, dx, dy * dy);
                    cand_idx  = tile_base + local;
                }

                const bool qualifies = (cand_dist < threshold);
                const unsigned mask  = __ballot_sync(FULL_MASK, qualifies);

                if (mask != 0u) {
                    const int count = __popc(mask);

                    if (count == 1) {
                        // Sparse-update fast path.
                        const int src_lane = __ffs(mask) - 1;
                        const float best_dist = __shfl_sync(FULL_MASK, cand_dist, src_lane);
                        const int   best_idx  = __shfl_sync(FULL_MASK, cand_idx,  src_lane);

                        warp_single_insert<K>(cur_dist, cur_idx, best_dist, best_idx,
                                              nxt_dist, nxt_idx, lane);
                    } else {
                        // General batch-update path:
                        // 1) keep only candidates below the current threshold,
                        // 2) sort the 32-lane candidate batch cooperatively,
                        // 3) merge it cooperatively with the current top-k.
                        if (!qualifies) {
                            cand_dist = INF_DISTANCE;
                            cand_idx  = INVALID_INDEX;
                        }

                        warp_sort32(cand_dist, cand_idx, lane);
                        warp_merge32<K>(cur_dist, cur_idx, cand_dist, cand_idx,
                                        nxt_dist, nxt_idx, lane);
                    }

                    // Shared-memory ordering for the per-warp private buffers.
                    __syncwarp(FULL_MASK);

                    float *tmp_dist = cur_dist; cur_dist = nxt_dist; nxt_dist = tmp_dist;
                    int   *tmp_idx  = cur_idx;  cur_idx  = nxt_idx;  nxt_idx  = tmp_idx;

                    if (lane == 0) {
                        threshold = cur_dist[K - 1];
                    }
                    threshold = __shfl_sync(FULL_MASK, threshold, 0);
                }
            }
        }

        // The tile is about to be overwritten by the next global-memory batch.
        __syncthreads();
    }

    if (active) {
        const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        // Strided final write so each iteration issues a coalesced 32-wide store.
#pragma unroll
        for (int t = 0; t < CHUNK; ++t) {
            const int pos = t * WARP_THREADS + lane;
            result[out_base + pos].first  = cur_idx[pos];
            result[out_base + pos].second = cur_dist[pos];
        }
    }
}

// Shared-memory footprint per resident warp:
// - one warp's worth of staged data points in the block-wide tile: 32 * sizeof(float2)
// - two private K-entry buffers for distances and indices
template <int K>
static inline std::size_t shared_bytes_per_warp() {
    return static_cast<std::size_t>(WARP_THREADS) * sizeof(float2) +
           static_cast<std::size_t>(2) * K * (sizeof(float) + sizeof(int));
}

// Host-side launch helper.
// The block-shape heuristic is intentionally reuse-biased:
// loading the data tile once and reusing it across many resident queries is the dominant
// optimization for this exact all-pairs scan. We only shrink the CTA width when the query
// count is small enough that very wide CTAs would starve the grid.
template <int K>
static inline void launch_knn_typed(const float2 *query,
                                    int query_count,
                                    const float2 *data,
                                    int data_count,
                                    ResultPairDevice *result) {
    if (query_count <= 0) return;

    int device = 0;
    cudaGetDevice(&device);

    cudaDeviceProp prop{};
    cudaGetDeviceProperties(&prop, device);

    const int max_threads_warps = prop.maxThreadsPerBlock / WARP_THREADS;
    const std::size_t shared_limit =
        static_cast<std::size_t>(prop.sharedMemPerBlockOptin > 0 ?
                                 prop.sharedMemPerBlockOptin :
                                 prop.sharedMemPerBlock);

    const std::size_t per_warp_smem = shared_bytes_per_warp<K>();

    int max_warps_by_shared = static_cast<int>(shared_limit / per_warp_smem);
    if (max_warps_by_shared < 1) max_warps_by_shared = 1;

    int max_warps = (max_threads_warps < max_warps_by_shared) ? max_threads_warps : max_warps_by_shared;
    if (max_warps > query_count) max_warps = query_count;
    if (max_warps < 1) max_warps = 1;

    // Aim for roughly half as many CTAs as SMs before shrinking CTAs any further.
    // These CTAs are long-running and already carry many warps each, so this keeps enough
    // grid-level parallelism while preserving strong tile reuse.
    int target_blocks = (prop.multiProcessorCount > 1) ? ((prop.multiProcessorCount + 1) / 2) : 1;
    int reuse_cap_warps = query_count / target_blocks;
    if (reuse_cap_warps < 1) reuse_cap_warps = 1;

    int warps_per_block = (max_warps < reuse_cap_warps) ? max_warps : reuse_cap_warps;

    // Round down to an even number of warps when possible; this tends to produce
    // scheduler-friendly CTA shapes without materially changing the reuse trade-off.
    if (warps_per_block > 1) {
        warps_per_block &= ~1;
    }
    if (warps_per_block < 1) warps_per_block = 1;

    const int block_threads = warps_per_block * WARP_THREADS;
    const std::size_t shared_bytes = per_warp_smem * static_cast<std::size_t>(warps_per_block);
    const int grid_blocks = (query_count + warps_per_block - 1) / warps_per_block;

    // Opt in to the required dynamic shared memory. The launch remains asynchronous;
    // callers can synchronize or query errors outside this function as needed.
    cudaFuncSetAttribute(knn2d_kernel<K>,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         static_cast<int>(shared_bytes));
    cudaFuncSetAttribute(knn2d_kernel<K>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    knn2d_kernel<K><<<grid_blocks, block_threads, shared_bytes>>>(
        query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) return;

    ResultPairDevice *result_proxy = reinterpret_cast<ResultPairDevice *>(result);

    // Runtime dispatch over the small fixed set of supported K values.
    switch (k) {
        case 32:   launch_knn_typed<32>(query, query_count, data, data_count, result_proxy);   break;
        case 64:   launch_knn_typed<64>(query, query_count, data, data_count, result_proxy);   break;
        case 128:  launch_knn_typed<128>(query, query_count, data, data_count, result_proxy);  break;
        case 256:  launch_knn_typed<256>(query, query_count, data, data_count, result_proxy);  break;
        case 512:  launch_knn_typed<512>(query, query_count, data, data_count, result_proxy);  break;
        case 1024: launch_knn_typed<1024>(query, query_count, data, data_count, result_proxy); break;
        default:
            // By contract k is always valid, so this path is unreachable for correct callers.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

// One warp owns one query, exactly as requested.
constexpr int WARP_SIZE = 32;

// Tuned for A100/H100-class GPUs:
// - 16 warps/block lets one data tile be reused by 16 concurrent queries.
// - 1024 cached float2 points/tile means exactly two global loads/thread/tile.
constexpr int BLOCK_THREADS = 512;
constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / WARP_SIZE;
constexpr int TILE_POINTS = 1024;
constexpr int CANDIDATE_BUFFER = WARP_SIZE;
constexpr unsigned FULL_MASK = 0xffffffffu;

static_assert(BLOCK_THREADS % WARP_SIZE == 0, "Block size must be a multiple of warp size.");
static_assert(TILE_POINTS % WARP_SIZE == 0, "Tile size must be a multiple of warp size.");
static_assert(TILE_POINTS >= 1024, "The first tile must be able to hold the largest supported k.");

// Per-thread constant lane mask used for warp-local prefix sums.
__device__ __forceinline__ unsigned lane_mask_lt() {
    unsigned m;
    asm volatile("mov.u32 %0, %%lanemask_lt;" : "=r"(m));
    return m;
}

// Squared Euclidean distance in 2D; no sqrt, as required.
__device__ __forceinline__ float squared_l2(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

// In-register bitonic sort of exactly 32 (distance, index) pairs distributed one per lane.
// Ascending by distance; ties are intentionally left unspecified.
__device__ __forceinline__ void warp_sort32(float& dist, int& idx, const int lane) {
#pragma unroll
    for (int k = 2; k <= WARP_SIZE; k <<= 1) {
#pragma unroll
        for (int j = k >> 1; j > 0; j >>= 1) {
            const float peer_dist = __shfl_xor_sync(FULL_MASK, dist, j);
            const int   peer_idx  = __shfl_xor_sync(FULL_MASK, idx,  j);

            const bool ascending = ((lane & k) == 0);
            const bool swap = ascending ? (dist > peer_dist) : (dist < peer_dist);
            if (swap) {
                dist = peer_dist;
                idx  = peer_idx;
            }
        }
    }
}

// One-time initialization sort of the first K distances kept in warp-private shared memory.
// This is deliberately not aggressively unrolled to avoid code size blow-up for K=1024.
template <int K>
__device__ __forceinline__ void warp_sort_shared_topk(float* dist, int* idx, const int lane) {
#pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll 1
            for (int i = lane; i < K; i += WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const float di = dist[i];
                    const float dj = dist[j];
                    const int   ii = idx[i];
                    const int   ij = idx[j];

                    const bool ascending = ((i & size) == 0);
                    const bool swap = ascending ? (di > dj) : (di < dj);
                    if (swap) {
                        dist[i] = dj;
                        idx[i]  = ij;
                        dist[j] = di;
                        idx[j]  = ii;
                    }
                }
            }
            // Only the owning warp touches this segment, so __syncwarp is sufficient.
            __syncwarp();
        }
    }
}

// Parallel merge of:
//   A = current sorted top-K in shared memory (length K)
//   B = 32 sorted candidate pairs distributed one per lane (length 32)
// producing the smallest K elements of A union B back into A.
//
// Each lane computes exactly K/32 output elements in registers.
// That avoids a second K-sized shared-memory buffer while still updating K values
// cooperatively across the whole warp.
template <int K>
__device__ __forceinline__ void warp_merge_topk(
    float* top_dist,
    int* top_idx,
    float cand_dist_lane,
    int cand_idx_lane,
    const int lane)
{
    constexpr int K_PER_LANE = K / WARP_SIZE;

    float out_dist[K_PER_LANE];
    int   out_idx[K_PER_LANE];

    // Merge-path partition for the beginning of this lane's output interval.
    const int diag = lane * K_PER_LANE;
    int low = 0;
    int high = (diag < CANDIDATE_BUFFER) ? diag : CANDIDATE_BUFFER;
    int part_b = 0;
    bool found = false;

    while (low <= high) {
        const int b = (low + high) >> 1;
        const int a = diag - b;

        const float a_right = (a < K) ? top_dist[a] : CUDART_INF_F;
        const float a_left  = (a > 0) ? top_dist[a - 1] : -CUDART_INF_F;
        const float b_right = (b < CANDIDATE_BUFFER) ? __shfl_sync(FULL_MASK, cand_dist_lane, b) : CUDART_INF_F;
        const float b_left  = (b > 0) ? __shfl_sync(FULL_MASK, cand_dist_lane, b - 1) : -CUDART_INF_F;

        if (b > 0 && a < K && b_left > a_right) {
            high = b - 1;  // took too many from B
        } else if (a > 0 && b < CANDIDATE_BUFFER && a_left > b_right) {
            low = b + 1;   // took too few from B
        } else {
            part_b = b;
            found = true;
            break;
        }
    }
    if (!found) {
        part_b = low;
    }

    int a = diag - part_b;
    int b = part_b;

#pragma unroll
    for (int i = 0; i < K_PER_LANE; ++i) {
        const float av = (a < K) ? top_dist[a] : CUDART_INF_F;
        const int   ai = (a < K) ? top_idx[a]  : -1;

        float bv = CUDART_INF_F;
        int   bi = -1;
        if (b < CANDIDATE_BUFFER) {
            bv = __shfl_sync(FULL_MASK, cand_dist_lane, b);
            bi = __shfl_sync(FULL_MASK, cand_idx_lane,  b);
        }

        // Strict '<' is intentional; tie handling is unspecified by the API.
        const bool take_b = (bv < av);
        out_dist[i] = take_b ? bv : av;
        out_idx[i]  = take_b ? bi : ai;

        b += static_cast<int>(take_b);
        a += static_cast<int>(!take_b);
    }

    // Make sure nobody overwrites the old shared-memory top-K before every lane
    // has finished reading from it.
    __syncwarp();

    const int out_base = diag;
#pragma unroll
    for (int i = 0; i < K_PER_LANE; ++i) {
        top_dist[out_base + i] = out_dist[i];
        top_idx[out_base + i]  = out_idx[i];
    }

    __syncwarp();
}

// Merge a sorted 32-candidate warp vector into the current top-K if it can improve it.
template <int K>
__device__ __forceinline__ float warp_merge_sorted_candidates(
    float* top_dist,
    int* top_idx,
    float cand_dist_lane,
    int cand_idx_lane,
    const int lane,
    float worst_dist)
{
    const float best_candidate = __shfl_sync(FULL_MASK, cand_dist_lane, 0);
    if (best_candidate < worst_dist) {
        warp_merge_topk<K>(top_dist, top_idx, cand_dist_lane, cand_idx_lane, lane);

        float w = 0.0f;
        if (lane == 0) {
            w = top_dist[K - 1];
        }
        worst_dist = __shfl_sync(FULL_MASK, w, 0);
    }
    return worst_dist;
}

// Flush a partially filled candidate buffer (<= 32 elements) stored in warp-private shared memory.
template <int K>
__device__ __forceinline__ float warp_flush_candidates(
    float* top_dist,
    int* top_idx,
    const float* cand_dist_buf,
    const int* cand_idx_buf,
    const int buf_count,
    const int lane,
    float worst_dist)
{
    // Required because candidate buffer entries were produced by different lanes.
    __syncwarp();

    float cand_dist = (lane < buf_count) ? cand_dist_buf[lane] : CUDART_INF_F;
    int   cand_idx  = (lane < buf_count) ? cand_idx_buf[lane]  : -1;

    warp_sort32(cand_dist, cand_idx, lane);
    return warp_merge_sorted_candidates<K>(top_dist, top_idx, cand_dist, cand_idx, lane, worst_dist);
}

// Consume one shared-memory tile for one query warp.
// The exact current top-K stays in shared memory; improving points are buffered in batches of up to 32.
// This drastically reduces expensive K-way merges after the initial K fill, while remaining exact.
template <int K>
__device__ __forceinline__ void process_tile_for_query(
    const float2* tile,
    const int tile_base,
    const int start_offset,
    const int tile_count,
    const float qx,
    const float qy,
    float* top_dist,
    int* top_idx,
    float* cand_dist_buf,
    int* cand_idx_buf,
    const int lane,
    const unsigned lane_lt_mask,
    float& worst_dist,
    int& buf_count)
{
#pragma unroll 1
    for (int chunk = start_offset; chunk < tile_count; chunk += WARP_SIZE) {
        const int local_idx = chunk + lane;

        float dist = CUDART_INF_F;
        int data_idx = -1;
        if (local_idx < tile_count) {
            const float2 p = tile[local_idx];
            dist = squared_l2(qx, qy, p);
            data_idx = tile_base + local_idx;
        }

        // Strict '<' is enough because tie resolution is unspecified.
        bool better = (dist < worst_dist);
        unsigned mask = __ballot_sync(FULL_MASK, better);
        int count = __popc(mask);

        if (count == 0) {
            continue;
        }

        // Fast path: if the buffer is empty and all 32 lanes produced improving candidates,
        // sort and merge the chunk directly without touching the shared candidate buffer.
        if (buf_count == 0 && count == CANDIDATE_BUFFER) {
            warp_sort32(dist, data_idx, lane);
            worst_dist = warp_merge_sorted_candidates<K>(top_dist, top_idx, dist, data_idx, lane, worst_dist);
            continue;
        }

        // If the current chunk would overflow the candidate buffer, flush the buffer first,
        // then re-test the current chunk against the tighter threshold.
        if (buf_count + count > CANDIDATE_BUFFER) {
            worst_dist = warp_flush_candidates<K>(
                top_dist, top_idx, cand_dist_buf, cand_idx_buf, buf_count, lane, worst_dist);
            buf_count = 0;

            better = (dist < worst_dist);
            mask = __ballot_sync(FULL_MASK, better);
            count = __popc(mask);

            if (count == 0) {
                continue;
            }

            if (count == CANDIDATE_BUFFER) {
                warp_sort32(dist, data_idx, lane);
                worst_dist = warp_merge_sorted_candidates<K>(top_dist, top_idx, dist, data_idx, lane, worst_dist);
                continue;
            }
        }

        const int rank = __popc(mask & lane_lt_mask);
        if (better) {
            cand_dist_buf[buf_count + rank] = dist;
            cand_idx_buf[buf_count + rank] = data_idx;
        }
        buf_count += count;

        if (buf_count == CANDIDATE_BUFFER) {
            worst_dist = warp_flush_candidates<K>(
                top_dist, top_idx, cand_dist_buf, cand_idx_buf, buf_count, lane, worst_dist);
            buf_count = 0;
        }
    }
}

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 1)
void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    std::pair<int, float>* __restrict__ result)
{
    extern __shared__ __align__(16) unsigned char smem_raw[];

    // Shared-memory layout:
    //   [data tile][top-K distances][top-K indices][candidate distances][candidate indices]
    float2* tile = reinterpret_cast<float2*>(smem_raw);
    unsigned char* ptr = reinterpret_cast<unsigned char*>(tile + TILE_POINTS);

    float* top_dist = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * K * sizeof(float);

    int* top_idx = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * K * sizeof(int);

    float* cand_dist = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * CANDIDATE_BUFFER * sizeof(float);

    int* cand_idx = reinterpret_cast<int*>(ptr);

    const int warp_id = threadIdx.x >> 5;
    const int lane = threadIdx.x & (WARP_SIZE - 1);
    const unsigned lane_lt_mask = lane_mask_lt();

    const int qidx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active = (qidx < query_count);

    float qx = 0.0f;
    float qy = 0.0f;
    if (active) {
        const float2 q = query[qidx];
        qx = q.x;
        qy = q.y;
    }

    float* my_top_dist = top_dist + warp_id * K;
    int*   my_top_idx  = top_idx  + warp_id * K;
    float* my_cand_dist = cand_dist + warp_id * CANDIDATE_BUFFER;
    int*   my_cand_idx  = cand_idx  + warp_id * CANDIDATE_BUFFER;

    float worst_dist = CUDART_INF_F;
    int buf_count = 0;

    // First tile:
    // - everyone cooperatively loads it
    // - each active warp initializes its private top-K from the first K data points
    // - the remainder of the tile is processed with the normal buffered-update path
    const int first_tile_count = (data_count < TILE_POINTS) ? data_count : TILE_POINTS;
    for (int i = threadIdx.x; i < first_tile_count; i += BLOCK_THREADS) {
        tile[i] = data[i];
    }
    __syncthreads();

    if (active) {
#pragma unroll
        for (int i = lane; i < K; i += WARP_SIZE) {
            const float2 p = tile[i];
            my_top_dist[i] = squared_l2(qx, qy, p);
            my_top_idx[i] = i;
        }
        __syncwarp();

        warp_sort_shared_topk<K>(my_top_dist, my_top_idx, lane);

        float w = 0.0f;
        if (lane == 0) {
            w = my_top_dist[K - 1];
        }
        worst_dist = __shfl_sync(FULL_MASK, w, 0);

        process_tile_for_query<K>(
            tile, 0, K, first_tile_count,
            qx, qy,
            my_top_dist, my_top_idx,
            my_cand_dist, my_cand_idx,
            lane, lane_lt_mask,
            worst_dist, buf_count);
    }

    __syncthreads();

    // Remaining tiles.
    for (int tile_base = TILE_POINTS; tile_base < data_count; tile_base += TILE_POINTS) {
        const int remaining = data_count - tile_base;
        const int tile_count = (remaining < TILE_POINTS) ? remaining : TILE_POINTS;

        for (int i = threadIdx.x; i < tile_count; i += BLOCK_THREADS) {
            tile[i] = data[tile_base + i];
        }
        __syncthreads();

        if (active) {
            process_tile_for_query<K>(
                tile, tile_base, 0, tile_count,
                qx, qy,
                my_top_dist, my_top_idx,
                my_cand_dist, my_cand_idx,
                lane, lane_lt_mask,
                worst_dist, buf_count);
        }

        __syncthreads();
    }

    if (active) {
        if (buf_count > 0) {
            worst_dist = warp_flush_candidates<K>(
                my_top_dist, my_top_idx, my_cand_dist, my_cand_idx, buf_count, lane, worst_dist);
        }

        const size_t out_base = static_cast<size_t>(qidx) * K;
#pragma unroll
        for (int i = lane; i < K; i += WARP_SIZE) {
            result[out_base + i].first = my_top_idx[i];
            result[out_base + i].second = my_top_dist[i];
        }
    }
}

template <int K>
constexpr size_t shared_bytes_for_kernel() {
    return static_cast<size_t>(TILE_POINTS) * sizeof(float2) +
           static_cast<size_t>(WARPS_PER_BLOCK) * (
               static_cast<size_t>(K) * sizeof(float) +
               static_cast<size_t>(K) * sizeof(int) +
               static_cast<size_t>(CANDIDATE_BUFFER) * sizeof(float) +
               static_cast<size_t>(CANDIDATE_BUFFER) * sizeof(int));
}

template <int K>
inline void launch_knn_variant(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    std::pair<int, float>* result)
{
    constexpr size_t SHMEM_BYTES = shared_bytes_for_kernel<K>();

    // Worst case (K=1024) needs opt-in shared memory on A100/H100-class GPUs.
    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHMEM_BYTES));
    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int grid_blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    knn_kernel<K><<<grid_blocks, BLOCK_THREADS, SHMEM_BYTES>>>(
        query, query_count, data, data_count, result);
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    // Dispatch to compile-time specializations:
    // k is guaranteed to be one of {32, 64, 128, 256, 512, 1024}.
    switch (k) {
        case 32:   launch_knn_variant<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_variant<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_variant<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_variant<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_variant<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_variant<1024>(query, query_count, data, data_count, result); break;
        default:
            // Unreachable for valid inputs.
            break;
    }

    // Intentionally no synchronization here:
    // the API keeps normal CUDA asynchronous launch semantics.
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace {

// The hardware warp size is fixed at 32 on NVIDIA GPUs.
constexpr int WARP_SIZE_CONST   = 32;

// 256 threads = 8 warps/query-workers per block.
// This is a good A100/H100 trade-off:
//   * enough warps per block to reuse each shared-memory data batch 8x,
//   * still modest shared-memory usage,
//   * manageable register pressure even for k = 1024.
constexpr int BLOCK_THREADS     = 256;
constexpr int WARPS_PER_BLOCK   = BLOCK_THREADS / WARP_SIZE_CONST;
constexpr unsigned FULL_MASK    = 0xffffffffu;

// Invalid/sentinel entry.
// Distance is +inf; index is negative so it is distinguishable from a real point
// even if a real squared distance overflows to +inf.
constexpr float INVALID_DIST    = CUDART_INF_F;
constexpr int   INVALID_INDEX   = -1;

static_assert(BLOCK_THREADS % WARP_SIZE_CONST == 0, "BLOCK_THREADS must be a multiple of 32");

__device__ __forceinline__ int lane_id() {
    return threadIdx.x & (WARP_SIZE_CONST - 1);
}

__device__ __forceinline__ int warp_id_in_block() {
    return threadIdx.x >> 5;
}

// "Better" means "should appear earlier in the sorted top-k list".
// Ordering is primarily by distance. Ties are intentionally arbitrary except for one
// special case: a real candidate must beat an unused sentinel slot when both hold +inf.
// This lets genuine +inf distances fill the queue correctly if the arithmetic overflows.
__device__ __forceinline__ bool better(const float a_dist, const int a_idx,
                                       const float b_dist, const int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx >= 0) && (b_idx < 0));
}

// Keep either the minimum or the maximum of (self, other), according to the ordering above.
__device__ __forceinline__ void compare_exchange_keep(float &self_dist, int &self_idx,
                                                      const float other_dist, const int other_idx,
                                                      const bool keep_min) {
    const bool take_other = keep_min ? better(other_dist, other_idx, self_dist, self_idx)
                                     : better(self_dist, self_idx, other_dist, other_idx);
    if (take_other) {
        self_dist = other_dist;
        self_idx  = other_idx;
    }
}

// Full 32-way bitonic sort in ascending order.
//
// Each lane owns one (distance, index) pair. Communication is via warp shuffles;
// those collectives are warp-synchronous, so no extra __syncwarp() is required here.
__device__ __forceinline__ void warp_bitonic_sort_32(float &dist, int &idx) {
    const int lane = lane_id();

#pragma unroll
    for (int k = 2; k <= WARP_SIZE_CONST; k <<= 1) {
#pragma unroll
        for (int j = k >> 1; j > 0; j >>= 1) {
            const float other_dist = __shfl_xor_sync(FULL_MASK, dist, j);
            const int   other_idx  = __shfl_xor_sync(FULL_MASK, idx,  j);

            const bool lower_lane = ((lane & j) == 0);
            const bool dir_asc    = ((lane & k) == 0);
            const bool keep_min   = (lower_lane == dir_asc);

            compare_exchange_keep(dist, idx, other_dist, other_idx, keep_min);
        }
    }
}

// Bitonic merge for a 32-element bitonic sequence to ascending order.
__device__ __forceinline__ void warp_bitonic_merge_32(float &dist, int &idx) {
    const int lane = lane_id();

#pragma unroll
    for (int j = WARP_SIZE_CONST >> 1; j > 0; j >>= 1) {
        const float other_dist = __shfl_xor_sync(FULL_MASK, dist, j);
        const int   other_idx  = __shfl_xor_sync(FULL_MASK, idx,  j);

        const bool lower_lane = ((lane & j) == 0);
        compare_exchange_keep(dist, idx, other_dist, other_idx, lower_lane);
    }
}

// Merge two already-sorted 32-element ascending sequences A and B.
// Input : lane i holds A[i] and B[i].
// Output: A becomes the smallest 32 merged elements (ascending),
//         B becomes the largest  32 merged elements (ascending).
//
// Implementation detail:
//   1) Reverse B to make A || reverse(B) a 64-element bitonic sequence.
//   2) First compare-exchange between the lower and upper halves.
//   3) Each half is now a 32-element bitonic sequence; merge each half independently.
__device__ __forceinline__ void merge_sorted_32x32(float &a_dist, int &a_idx,
                                                   float &b_dist, int &b_idx) {
    const int lane = lane_id();

    const float b_rev_dist = __shfl_sync(FULL_MASK, b_dist, (WARP_SIZE_CONST - 1) - lane);
    const int   b_rev_idx  = __shfl_sync(FULL_MASK, b_idx,  (WARP_SIZE_CONST - 1) - lane);

    float lo_dist, hi_dist;
    int   lo_idx,  hi_idx;

    if (better(a_dist, a_idx, b_rev_dist, b_rev_idx)) {
        lo_dist = a_dist;     lo_idx = a_idx;
        hi_dist = b_rev_dist; hi_idx = b_rev_idx;
    } else {
        lo_dist = b_rev_dist; lo_idx = b_rev_idx;
        hi_dist = a_dist;     hi_idx = a_idx;
    }

    warp_bitonic_merge_32(lo_dist, lo_idx);
    warp_bitonic_merge_32(hi_dist, hi_idx);

    a_dist = lo_dist; a_idx = lo_idx;
    b_dist = hi_dist; b_idx = hi_idx;
}

__device__ __forceinline__ float squared_l2_2d(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

// One warp handles exactly one query.
// K is specialized at compile time so that:
//   * the private top-k state can stay in registers,
//   * merge loops can be fully unrolled,
//   * the compiler can aggressively optimize the hot path.
template <int K>
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           std::pair<int, float> * __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024]");
    static_assert(K % WARP_SIZE_CONST == 0, "K must be a multiple of warp size");

    constexpr int ITEMS_PER_LANE = K / WARP_SIZE_CONST;
    constexpr int LAST_CHUNK     = ITEMS_PER_LANE - 1;

    // Shared-memory cache for one data batch.
    // Every thread loads one float2, then all 8 warps reuse the batch.
    __shared__ float2 sh_data[BLOCK_THREADS];

    const int lane   = lane_id();
    const int warp   = warp_id_in_block();
    const int q_base = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK;
    const int qid    = q_base + warp;

    // Uniform early exit for a completely out-of-range block.
    if (q_base >= query_count) {
        return;
    }

    const bool active = (qid < query_count);

    // Load the query point once per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[qid];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Warp-private top-k state.
    // Layout is "striped" by 32-element chunks:
    //   top_dist[t] / top_idx[t] in lane i stores global rank (t * 32 + i).
    // Each chunk is always sorted across lanes, and the chunks are globally ordered.
    float top_dist[ITEMS_PER_LANE];
    int   top_idx[ITEMS_PER_LANE];

#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        top_dist[t] = INVALID_DIST;
        top_idx[t]  = INVALID_INDEX;
    }

    // Iterate over the data set in shared-memory batches.
    for (int batch_base = 0; batch_base < data_count; batch_base += BLOCK_THREADS) {
        int points_in_batch = data_count - batch_base;
        if (points_in_batch > BLOCK_THREADS) points_in_batch = BLOCK_THREADS;

        // Cooperative block-wide load of the next batch into shared memory.
        if (threadIdx.x < points_in_batch) {
            sh_data[threadIdx.x] = data[batch_base + threadIdx.x];
        }

        // Whole-block barrier is required because all warps consume the shared batch.
        __syncthreads();

        // Process the shared batch as 8 packets of 32 candidates.
        // Each packet is:
        //   1) distance-evaluated in parallel by the warp,
        //   2) pruned against the current worst top-k element,
        //   3) sorted cooperatively,
        //   4) merged chunk-by-chunk into the private top-k state.
#pragma unroll
        for (int g = 0; g < WARPS_PER_BLOCK; ++g) {
            const int local_idx = g * WARP_SIZE_CONST + lane;

            float cand_dist = INVALID_DIST;
            int   cand_idx  = INVALID_INDEX;

            if (active && local_idx < points_in_batch) {
                const float2 p = sh_data[local_idx];
                cand_dist = squared_l2_2d(qx, qy, p);
                cand_idx  = batch_base + local_idx;
            }

            // Current pruning threshold = worst element in the sorted top-k list.
            const float worst_dist = __shfl_sync(FULL_MASK, top_dist[LAST_CHUNK], WARP_SIZE_CONST - 1);
            const int   worst_idx  = __shfl_sync(FULL_MASK, top_idx[LAST_CHUNK],  WARP_SIZE_CONST - 1);

            const bool relevant = better(cand_dist, cand_idx, worst_dist, worst_idx);

            // If no lane has a candidate better than the current threshold, skip the entire
            // packet update. This is critical: once the queue stabilizes, most packets are discarded
            // before the expensive sort/merge path.
            if (__any_sync(FULL_MASK, relevant)) {
                if (!relevant) {
                    cand_dist = INVALID_DIST;
                    cand_idx  = INVALID_INDEX;
                }

                // Sort the 32-candidate packet.
                warp_bitonic_sort_32(cand_dist, cand_idx);

                // Cascade the packet through the K/32 sorted chunks.
                // After each merge:
                //   * top_[t] receives the smaller half,
                //   * (cand_dist, cand_idx) carries the larger half to the next chunk.
#pragma unroll
                for (int t = 0; t < ITEMS_PER_LANE; ++t) {
                    merge_sorted_32x32(top_dist[t], top_idx[t], cand_dist, cand_idx);
                }
            }
        }

        // Whole-block barrier before the next batch overwrites shared memory.
        __syncthreads();
    }

    // Store the final top-k list in row-major query-major layout:
    //   result[qid * K + j] is the j-th nearest neighbor of query[qid].
    if (active) {
        const std::size_t out_base = static_cast<std::size_t>(qid) * static_cast<std::size_t>(K);

#pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const std::size_t out_idx = out_base + static_cast<std::size_t>(t * WARP_SIZE_CONST + lane);
            result[out_idx].first  = top_idx[t];
            result[out_idx].second = top_dist[t];
        }
    }
}

} // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    // K is runtime-known but constrained to six power-of-two values.
    // Compile-time specialization keeps the warp-private state register-resident
    // and fully unrolls the fixed-size merge network.
#define KNN_LAUNCH_CASE(KVAL) \
    case KVAL: \
        knn_kernel<KVAL><<<grid, block>>>(query, query_count, data, data_count, result); \
        break

    switch (k) {
        KNN_LAUNCH_CASE(32);
        KNN_LAUNCH_CASE(64);
        KNN_LAUNCH_CASE(128);
        KNN_LAUNCH_CASE(256);
        KNN_LAUNCH_CASE(512);
        KNN_LAUNCH_CASE(1024);
        default:
            // Per the problem statement, k is always valid.
            break;
    }

#undef KNN_LAUNCH_CASE
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>
#include <utility>

namespace knn_detail {

// Optimized warp-per-query 2D k-NN for large query/data sets.
//
// Design choices tuned for modern data-center GPUs (A100/H100 class):
//   * One warp computes one query.
//   * A 256-thread block contains 8 warps, so each shared-memory data tile is
//     reused by 8 queries before the next tile is loaded.
//   * The block caches 1024 data points per tile. This is large enough to
//     materially reduce barrier overhead versus a 256-point tile, while still
//     fitting comfortably together with the K=1024 per-warp working set.
//   * K is specialized at compile time (32/64/128/256/512/1024) so that the
//     sort/merge networks remain static and branch-free with respect to K.
//
// Per-warp temporary state in shared memory:
//   neighbors[0 .. K-1]     : current sorted top-K
//   neighbors[K .. 2K-1]    : unsorted buffer of newly accepted candidates
//
// Multiple candidates are inserted simultaneously:
//   * Each round processes 32 candidates (one per lane).
//   * Passing lanes compact themselves into the buffer via ballot + prefix rank.
//   * When the buffer would overflow, it is flushed:
//       - sort buffer ascending
//       - first flush: copy buffer into top-K
//       - later flushes: reverse the buffer and bitonic-merge [top-K | buffer]
//
// The kth-best threshold only decreases as more points are seen. Therefore,
// keeping a stale threshold while candidates are buffered is safe: it can only
// admit extra candidates (more work), never reject a true neighbor.

using result_pair_t = std::pair<int, float>;
using packed_neighbor_t = std::uint64_t;

constexpr int kWarpSize       = 32;
constexpr int kBlockThreads   = 256;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr int kTilePoints     = 1024;   // 4 loads per thread, 32 rounds per full tile
constexpr unsigned kFullMask  = 0xffffffffu;

// Packed key = [distance_bits | index_bits].
// Squared Euclidean distances are non-negative, so IEEE-754 bit ordering for
// float is monotone under unsigned integer comparison. The index occupies the
// low 32 bits and acts as a deterministic tie-breaker.
constexpr packed_neighbor_t kInfPacked =
    (static_cast<packed_neighbor_t>(0x7f800000u) << 32) |
    static_cast<packed_neighbor_t>(0xffffffffu);

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size.");
static_assert(kTilePoints % kWarpSize == 0, "Tile size must be a multiple of warp size.");
static_assert(kTilePoints == 4 * kBlockThreads,
              "The tile loader below is intentionally unrolled for four loads per thread.");

__device__ __forceinline__ packed_neighbor_t pack_neighbor(const float dist, const int idx) {
    return (static_cast<packed_neighbor_t>(__float_as_uint(dist)) << 32) |
           static_cast<std::uint32_t>(idx);
}

__device__ __forceinline__ float unpack_distance(const packed_neighbor_t packed) {
    return __uint_as_float(static_cast<unsigned int>(packed >> 32));
}

__device__ __forceinline__ int unpack_index(const packed_neighbor_t packed) {
    return static_cast<int>(static_cast<std::uint32_t>(packed));
}

// Standard in-place bitonic sort on a power-of-two number of elements in shared memory.
template <int N>
__device__ __forceinline__ void warp_bitonic_sort_asc(packed_neighbor_t* a) {
    static_assert((N & (N - 1)) == 0, "Bitonic sort size must be a power of two.");

    const int lane = threadIdx.x & (kWarpSize - 1);

    #pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += kWarpSize) {
                const int partner = i ^ stride;
                if (partner > i) {
                    const bool ascending = ((i & size) == 0);
                    packed_neighbor_t ai = a[i];
                    packed_neighbor_t aj = a[partner];

                    if ((ascending && ai > aj) || (!ascending && ai < aj)) {
                        a[i]       = aj;
                        a[partner] = ai;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Bitonic merge for a power-of-two array that is already bitonic and must end up ascending.
template <int N>
__device__ __forceinline__ void warp_bitonic_merge_asc(packed_neighbor_t* a) {
    static_assert((N & (N - 1)) == 0, "Bitonic merge size must be a power of two.");

    const int lane = threadIdx.x & (kWarpSize - 1);

    #pragma unroll 1
    for (int stride = N >> 1; stride > 0; stride >>= 1) {
        for (int i = lane; i < N; i += kWarpSize) {
            const int partner = i ^ stride;
            if (partner > i) {
                packed_neighbor_t ai = a[i];
                packed_neighbor_t aj = a[partner];

                if (ai > aj) {
                    a[i]       = aj;
                    a[partner] = ai;
                }
            }
        }
        __syncwarp(kFullMask);
    }
}

// Flush the warp-private buffer into the sorted top-K state.
template <int K>
__device__ __forceinline__ void flush_buffer(
    packed_neighbor_t* neighbors,
    int&               buf_count,
    bool&              top_ready,
    float&             threshold)
{
    if (buf_count == 0) {
        return;
    }

    const int lane = threadIdx.x & (kWarpSize - 1);

    // Pad the unused part of the buffer with +inf so that sorting/merging can
    // operate on fixed-size power-of-two arrays.
    __syncwarp(kFullMask);
    for (int i = lane + buf_count; i < K; i += kWarpSize) {
        neighbors[K + i] = kInfPacked;
    }
    __syncwarp(kFullMask);

    // Sort buffered candidates ascending.
    warp_bitonic_sort_asc<K>(neighbors + K);

    if (!top_ready) {
        // First flush: initialize the exact top-K from the first K points seen.
        for (int i = lane; i < K; i += kWarpSize) {
            neighbors[i] = neighbors[K + i];
        }
        top_ready = true;
    } else {
        // Later flushes: top-K is already ascending, so reverse the ascending
        // buffer into descending order. Concatenating [ascending | descending]
        // forms a bitonic sequence, which can be fully sorted with a bitonic merge.
        for (int i = lane; i < (K >> 1); i += kWarpSize) {
            packed_neighbor_t tmp            = neighbors[K + i];
            neighbors[K + i]                 = neighbors[(2 * K - 1) - i];
            neighbors[(2 * K - 1) - i]       = tmp;
        }
        __syncwarp(kFullMask);

        warp_bitonic_merge_asc<2 * K>(neighbors);
    }

    __syncwarp(kFullMask);

    // Publish the new exact kth threshold to the whole warp.
    float new_threshold = 0.0f;
    if (lane == 0) {
        new_threshold = unpack_distance(neighbors[K - 1]);
    }
    threshold = __shfl_sync(kFullMask, new_threshold, 0);
    buf_count = 0;
}

template <int K>
constexpr std::size_t shared_bytes_for() {
    return static_cast<std::size_t>(kTilePoints) * sizeof(float2) +
           static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(2 * K) * sizeof(packed_neighbor_t);
}

// Fits within the A100 opt-in per-block shared-memory limit (163,840 bytes).
static_assert(shared_bytes_for<1024>() <= 163840u,
              "The largest specialization must fit within A100/H100-class shared memory.");

template <int K>
__global__ __launch_bounds__(kBlockThreads)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    result_pair_t* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0,
                  "K must be a supported power of two in [32, 1024].");

    extern __shared__ unsigned char smem_raw[];

    float2* tile = reinterpret_cast<float2*>(smem_raw);
    packed_neighbor_t* neighbor_storage =
        reinterpret_cast<packed_neighbor_t*>(tile + kTilePoints);

    const int tid  = threadIdx.x;
    const int lane = tid & (kWarpSize - 1);
    const int warp = tid >> 5;

    const int qid = blockIdx.x * kWarpsPerBlock + warp;
    const bool active_warp = (qid < query_count);

    packed_neighbor_t* warp_neighbors = neighbor_storage + warp * (2 * K);

    float qx = 0.0f;
    float qy = 0.0f;
    float threshold = CUDART_INF_F;
    int   buf_count = 0;
    bool  top_ready = false;

    if (active_warp) {
        if (lane == 0) {
            const float2 q = query[qid];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    for (int tile_start = 0; tile_start < data_count; tile_start += kTilePoints) {
        const int remaining  = data_count - tile_start;
        const int batch_count = (remaining < kTilePoints) ? remaining : kTilePoints;

        // Cooperative block load: 1024 points per tile, 4 points per thread.
        const int load0 = tid;
        const int load1 = tid + kBlockThreads;
        const int load2 = tid + 2 * kBlockThreads;
        const int load3 = tid + 3 * kBlockThreads;

        if (load0 < batch_count) tile[load0] = data[tile_start + load0];
        if (load1 < batch_count) tile[load1] = data[tile_start + load1];
        if (load2 < batch_count) tile[load2] = data[tile_start + load2];
        if (load3 < batch_count) tile[load3] = data[tile_start + load3];

        __syncthreads();

        if (active_warp) {
            // Each round handles 32 candidates from the shared tile.
            #pragma unroll 1
            for (int base = 0; base < batch_count; base += kWarpSize) {
                const int  local_idx = base + lane;
                const bool valid     = (local_idx < batch_count);
                const int  data_idx  = tile_start + local_idx;

                float dist = CUDART_INF_F;
                if (valid) {
                    const float2 p  = tile[local_idx];
                    const float  dx = qx - p.x;
                    const float  dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                }

                bool pass = valid && (!top_ready || dist < threshold);
                unsigned mask = __ballot_sync(kFullMask, pass);
                int accepted_count = __popc(mask);

                // Flush only if this round would overflow the buffer. This keeps
                // the exact threshold reasonably fresh without forcing a flush
                // after every accepted candidate when K is small.
                if (buf_count + accepted_count > K) {
                    flush_buffer<K>(warp_neighbors, buf_count, top_ready, threshold);

                    // Re-evaluate the current round against the new exact threshold.
                    pass = valid && (!top_ready || dist < threshold);
                    mask = __ballot_sync(kFullMask, pass);
                    accepted_count = __popc(mask);
                }

                if (accepted_count) {
                    const unsigned lower_lanes = (lane == 0) ? 0u : ((1u << lane) - 1u);
                    const int rank = __popc(mask & lower_lanes);

                    if (pass) {
                        warp_neighbors[K + buf_count + rank] = pack_neighbor(dist, data_idx);
                    }

                    buf_count += accepted_count;
                }
            }
        }

        __syncthreads();
    }

    if (active_warp) {
        // Final exact top-K.
        flush_buffer<K>(warp_neighbors, buf_count, top_ready, threshold);

        const std::size_t out_base = static_cast<std::size_t>(qid) * static_cast<std::size_t>(K);

        // The top-K array is already sorted nearest-to-farthest.
        for (int i = lane; i < K; i += kWarpSize) {
            const packed_neighbor_t packed = warp_neighbors[i];
            result[out_base + static_cast<std::size_t>(i)].first  = unpack_index(packed);
            result[out_base + static_cast<std::size_t>(i)].second = unpack_distance(packed);
        }
    }
}

template <int K>
inline void launch_knn_specialized(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    result_pair_t* result)
{
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0,
                  "Unsupported K specialization.");

    constexpr int shared_bytes = static_cast<int>(shared_bytes_for<K>());

    // Opt into the large dynamic shared-memory footprint required by the warp-private
    // top-K state, and bias the SM carveout toward shared memory.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               shared_bytes);
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    knn_kernel<K><<<blocks, kBlockThreads, shared_bytes>>>(
        query, query_count, data, data_count, result);
}

} // namespace knn_detail

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    // The launch is intentionally asynchronous; callers can choose their own
    // synchronization and error-handling policy around this API.
    if (query_count <= 0) {
        return;
    }

    // Monomorphize K so that the top-K networks are fully specialized.
    switch (k) {
        case 32:   knn_detail::launch_knn_specialized<32>(query, query_count, data, data_count, result);   return;
        case 64:   knn_detail::launch_knn_specialized<64>(query, query_count, data, data_count, result);   return;
        case 128:  knn_detail::launch_knn_specialized<128>(query, query_count, data, data_count, result);  return;
        case 256:  knn_detail::launch_knn_specialized<256>(query, query_count, data, data_count, result);  return;
        case 512:  knn_detail::launch_knn_specialized<512>(query, query_count, data, data_count, result);  return;
        case 1024: knn_detail::launch_knn_specialized<1024>(query, query_count, data, data_count, result); return;
        default:   return; // Unreachable for valid inputs, kept for interface robustness.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace {

// One warp computes one query, and each block processes 8 queries concurrently.
// This keeps the block size at 256 threads, which is a sweet spot on A100/H100
// while maximizing reuse of each staged data tile across multiple queries.
constexpr int kWarpSize        = 32;
constexpr int kWarpsPerBlock   = 8;
constexpr int kThreadsPerBlock = kWarpSize * kWarpsPerBlock;
constexpr unsigned kFullMask   = 0xffffffffu;

// The result ordering only needs to be consistent, not stable, so we impose a
// total order by sorting by (distance, index).  Distances are squared L2 and are
// therefore non-negative; for non-negative IEEE-754 floats, the raw bit pattern
// is monotone under unsigned comparison.  We exploit that by packing:
//
//   key[63:32] = raw float bits of distance
//   key[31: 0] = data index
//
// Then a single 64-bit unsigned compare implements the desired ordering.
using packed_t = unsigned long long;
constexpr unsigned kInvalidIndex = 0x7fffffffu;
constexpr packed_t kSentinel =
    (packed_t{0x7f800000u} << 32) | packed_t{kInvalidIndex};  // (+inf, invalid)

using result_pair_t = std::pair<int, float>;

static_assert(sizeof(float2)  == sizeof(packed_t), "float2 must be 8 bytes");
static_assert(sizeof(packed_t) == 8,               "packed_t must be 8 bytes");

// Runtime shared-memory limits are queried once per call so that the launcher can
// pick larger tiles on GPUs with larger per-block/per-SM shared memory (e.g. H100)
// while remaining A100-safe.
struct DeviceSharedCaps {
    int max_block_optin = 0;
    int max_sm_shared   = 0;
};

inline DeviceSharedCaps query_device_shared_caps() {
    DeviceSharedCaps caps{};
    int device = 0;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&caps.max_block_optin,
                           cudaDevAttrMaxSharedMemoryPerBlockOptin,
                           device);
    cudaDeviceGetAttribute(&caps.max_sm_shared,
                           cudaDevAttrMaxSharedMemoryPerMultiprocessor,
                           device);
    return caps;
}

template <int K, int TILE_POINTS>
constexpr int shared_bytes() {
    // Shared layout:
    //   [ TILE_POINTS * float2 ] [ kWarpsPerBlock * (2*K) * packed_t ]
    // Each warp owns:
    //   - top-K sorted array in slots [0, K)
    //   - K-sized unsorted append buffer in slots [K, 2K)
    return TILE_POINTS * static_cast<int>(sizeof(float2)) +
           kWarpsPerBlock * 2 * K * static_cast<int>(sizeof(packed_t));
}

template <int K, int TILE_POINTS>
inline bool supports_shared(const DeviceSharedCaps& caps) {
    constexpr int bytes = shared_bytes<K, TILE_POINTS>();
    return bytes <= caps.max_block_optin;
}

template <int K, int TILE_POINTS>
inline bool supports_two_blocks_per_sm(const DeviceSharedCaps& caps) {
    constexpr int bytes = shared_bytes<K, TILE_POINTS>();
    return bytes <= caps.max_block_optin &&
           (2ll * static_cast<long long>(bytes)) <=
               static_cast<long long>(caps.max_sm_shared);
}

__device__ __forceinline__ unsigned lane_mask_lt() {
    unsigned mask;
    asm volatile("mov.u32 %0, %%lanemask_lt;" : "=r"(mask));
    return mask;
}

__device__ __forceinline__ packed_t pack_candidate(const float dist,
                                                   const int   idx) {
    return (static_cast<packed_t>(__float_as_uint(dist)) << 32) |
           static_cast<packed_t>(static_cast<unsigned>(idx));
}

__device__ __forceinline__ float unpack_distance(const packed_t value) {
    return __uint_as_float(static_cast<unsigned>(value >> 32));
}

__device__ __forceinline__ int unpack_index(const packed_t value) {
    return static_cast<int>(static_cast<unsigned>(value));
}

__device__ __forceinline__ packed_t make_candidate(const float qx,
                                                   const float qy,
                                                   const float2 p,
                                                   const int idx) {
    const float dx   = qx - p.x;
    const float dy   = qy - p.y;
    const float dist = fmaf(dx, dx, dy * dy);  // squared Euclidean distance
    return pack_candidate(dist, idx);
}

template <int N>
__device__ __forceinline__ void warp_bitonic_sort(packed_t* values) {
    static_assert((N & (N - 1)) == 0, "bitonic sort length must be a power of two");
    static_assert(N >= kWarpSize,      "bitonic sort length must be at least one warp");

    const int lane = threadIdx.x & (kWarpSize - 1);

    // Generic power-of-two bitonic sort executed by a single warp over shared memory.
    // Each lane owns the positions lane, lane+32, lane+64, ...
    for (int size = 2; size <= N; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll 1
            for (int pos = lane; pos < N; pos += kWarpSize) {
                const int partner = pos ^ stride;
                if (partner > pos) {
                    const bool up = ((pos & size) == 0);
                    const packed_t a = values[pos];
                    const packed_t b = values[partner];
                    if ((up && a > b) || (!up && a < b)) {
                        values[pos]     = b;
                        values[partner] = a;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

template <int K>
__device__ __forceinline__ packed_t warp_read_cutoff(const packed_t* knn) {
    packed_t cutoff = kSentinel;
    if ((threadIdx.x & (kWarpSize - 1)) == 0) {
        cutoff = knn[K - 1];
    }
    return __shfl_sync(kFullMask, cutoff, 0);
}

template <int K>
__device__ __forceinline__ void flush_buffer(packed_t* knn, const int buf_count) {
    // knn[0, K)   : current sorted top-K
    // knn[K, 2K)  : unsorted buffer with buf_count valid entries
    //
    // Flush strategy:
    //   1) Pad the unused buffer suffix with sentinels.
    //   2) Sort only the buffer (size K), not the whole 2K state.
    //   3) Merge sorted top-K and sorted buffer to keep the smallest K keys.
    //
    // Sorting only the buffer keeps maintenance cheaper than re-sorting all 2K
    // elements every time the buffer fills.
    const int lane = threadIdx.x & (kWarpSize - 1);
    packed_t* const buffer = knn + K;

    for (int pos = buf_count + lane; pos < K; pos += kWarpSize) {
        buffer[pos] = kSentinel;
    }
    __syncwarp(kFullMask);

    warp_bitonic_sort<K>(buffer);
    __syncwarp(kFullMask);

    // The merge is done by lane 0 only.  This is acceptable because the costly
    // part is the warp-wide sort, and buffering makes flushes infrequent once
    // the cutoff stabilizes.  The merge itself is linear and in-place.
    if (lane == 0) {
        int i = K - 1;       // end of top-K range [0, K)
        int j = 2 * K - 1;   // end of buffer range [K, 2K)

        // Discard the largest K keys from the union of the two sorted arrays.
        // The remaining prefixes contain exactly the smallest K keys.
        for (int discard = 0; discard < K; ++discard) {
            if (i < 0) {
                --j;
            } else if (j < K) {
                --i;
            } else if (knn[j] >= knn[i]) {
                --j;
            } else {
                --i;
            }
        }

        // Backward in-place merge of the kept prefixes into knn[0, K).
        int out = K - 1;
        while (out >= 0) {
            if (j < K) {
                knn[out--] = knn[i--];
            } else if (i < 0) {
                knn[out--] = knn[j--];
            } else if (knn[j] >= knn[i]) {
                knn[out--] = knn[j--];
            } else {
                knn[out--] = knn[i--];
            }
        }
    }

    __syncwarp(kFullMask);
}

template <int K, int TILE_POINTS>
__global__ __launch_bounds__(kThreadsPerBlock)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                result_pair_t* __restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024]");
    static_assert((TILE_POINTS % kWarpSize) == 0, "Tile size must be warp-aligned");
    static_assert(TILE_POINTS >= K, "Chosen tile must hold at least one initial top-K");

    // Shared memory is addressed in 8-byte units because both float2 and packed_t
    // are 8 bytes.  The first TILE_POINTS slots hold the staged data tile; the rest
    // hold per-warp top-K + buffer state.
    extern __shared__ packed_t smem[];
    float2* const sh_data   = reinterpret_cast<float2*>(smem);
    packed_t* const sh_knn  = smem + TILE_POINTS;

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_idx = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool valid = (query_idx < query_count);

    // Per-warp private K-NN state in shared memory.
    packed_t* const knn = sh_knn + warp_id * (2 * K);

    // One query point is loaded once by lane 0 and broadcast to the whole warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (valid && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    const unsigned lt_mask  = lane_mask_lt();
    const unsigned lane_bit = 1u << lane;

    int filled    = 0;          // number of valid entries currently in knn[0, K)
    int buf_count = 0;          // number of valid entries currently in knn[K, 2K)
    packed_t cutoff = kSentinel;

    for (int tile_base = 0; tile_base < data_count; tile_base += TILE_POINTS) {
        const int remaining  = data_count - tile_base;
        const int tile_count = (remaining < TILE_POINTS) ? remaining : TILE_POINTS;

        // Stage the current data tile once per block; all 8 warps will reuse it.
        for (int i = threadIdx.x; i < tile_count; i += blockDim.x) {
            sh_data[i] = data[tile_base + i];
        }
        __syncthreads();

        if (valid) {
            for (int chunk = 0; chunk < tile_count; chunk += kWarpSize) {
                const int offset = chunk + lane;

                packed_t candidate = kSentinel;
                if (offset < tile_count) {
                    candidate = make_candidate(qx, qy, sh_data[offset], tile_base + offset);
                }

                if (filled < K) {
                    // Initial fill: the first K candidates are written directly,
                    // then sorted once to establish the initial cutoff.
                    knn[filled + lane] = candidate;
                    filled += kWarpSize;

                    if (filled == K) {
                        __syncwarp(kFullMask);
                        warp_bitonic_sort<K>(knn);
                        cutoff = warp_read_cutoff<K>(knn);
                    }
                    continue;
                }

                // Admission test against the current cutoff.  Warp ballot + prefix
                // compacts all admitted candidates from this 32-point chunk into
                // contiguous buffer slots in one shot.
                unsigned mask = __ballot_sync(kFullMask, candidate < cutoff);
                int count = __popc(mask);

                if (count != 0) {
                    // If the current admissions would overflow the K-sized buffer,
                    // flush first, then re-test against the tighter cutoff.  This
                    // prevents overflow and reduces future buffer pressure.
                    if (buf_count != 0 && (buf_count + count) > K) {
                        flush_buffer<K>(knn, buf_count);
                        buf_count = 0;
                        cutoff = warp_read_cutoff<K>(knn);

                        mask  = __ballot_sync(kFullMask, candidate < cutoff);
                        count = __popc(mask);
                    }

                    if (count != 0) {
                        const int rank = __popc(mask & lt_mask);
                        if (mask & lane_bit) {
                            knn[K + buf_count + rank] = candidate;
                        }
                        buf_count += count;

                        if (buf_count == K) {
                            flush_buffer<K>(knn, buf_count);
                            buf_count = 0;
                            cutoff = warp_read_cutoff<K>(knn);
                        }
                    }
                }
            }
        }

        // Ensure no warp overwrites the staged tile before all warps in the block
        // are done consuming it.
        __syncthreads();
    }

    if (valid) {
        if (buf_count != 0) {
            flush_buffer<K>(knn, buf_count);
        }

        // Write the final sorted top-K to global memory.  We write std::pair members
        // directly to avoid relying on device-qualified std::pair constructors or
        // assignments; only raw member stores are needed here.
        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        for (int pos = lane; pos < K; pos += kWarpSize) {
            result[out_base + pos].first  = unpack_index(knn[pos]);
            result[out_base + pos].second = unpack_distance(knn[pos]);  // squared distance
        }
    }
}

template <int K, int TILE_POINTS>
inline void launch_knn_specialized(const float2* query,
                                  const int query_count,
                                  const float2* data,
                                  const int data_count,
                                  result_pair_t* result) {
    constexpr int shmem = shared_bytes<K, TILE_POINTS>();

    // The largest specialization used here is the H100-optimized K=1024,
    // TILE_POINTS=8192 path at 196608 bytes of dynamic shared memory.
    static_assert(shmem <= 196608, "specialization exceeds intended shared-memory budget");

    // Modern A100/H100-class GPUs require explicit opt-in for large dynamic shared
    // memory.  Prefer the shared-memory carveout because this kernel intentionally
    // uses shared memory as its main bandwidth-amortization mechanism.
    cudaFuncSetAttribute(knn_kernel<K, TILE_POINTS>,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         shmem);
    cudaFuncSetAttribute(knn_kernel<K, TILE_POINTS>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    // Default-stream launch is intentionally asynchronous, matching standard CUDA
    // semantics.  The caller can synchronize externally if needed.
    knn_kernel<K, TILE_POINTS><<<blocks, kThreadsPerBlock, shmem>>>(
        query, query_count, data, data_count, result);
}

} // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Tile sizes are chosen to balance:
    //   - reuse of the staged data tile across 8 concurrent query warps,
    //   - shared memory consumed by the per-warp top-K + buffer state,
    //   - occupancy on A100/H100.
    //
    // The launcher queries shared-memory limits at runtime so that larger tiles
    // can be used on devices that support them (notably H100) while preserving
    // A100-friendly fallbacks.
    const DeviceSharedCaps caps = query_device_shared_caps();

    switch (k) {
        case 32:
            // 8192-point tile keeps the block around 68 KiB shared.
            launch_knn_specialized<32, 8192>(query, query_count, data, data_count, result);
            break;

        case 64:
            // 8192-point tile keeps the block around 72 KiB shared.
            launch_knn_specialized<64, 8192>(query, query_count, data, data_count, result);
            break;

        case 128:
            // 8192-point tile keeps the block around 80 KiB shared.
            launch_knn_specialized<128, 8192>(query, query_count, data, data_count, result);
            break;

        case 256:
            // A100-friendly default: 4096-point tile (64 KiB/block).
            // H100-friendly upgrade: 8192-point tile (96 KiB/block) while still
            // allowing two resident blocks per SM.
            if (supports_two_blocks_per_sm<256, 8192>(caps)) {
                launch_knn_specialized<256, 8192>(query, query_count, data, data_count, result);
            } else {
                launch_knn_specialized<256, 4096>(query, query_count, data, data_count, result);
            }
            break;

        case 512:
            // A100-friendly default: 2048-point tile (80 KiB/block).
            // H100-friendly upgrade: 4096-point tile (96 KiB/block) while still
            // allowing two resident blocks per SM.
            if (supports_two_blocks_per_sm<512, 4096>(caps)) {
                launch_knn_specialized<512, 4096>(query, query_count, data, data_count, result);
            } else {
                launch_knn_specialized<512, 2048>(query, query_count, data, data_count, result);
            }
            break;

        case 1024:
            // The K=1024 per-warp state is large enough that this path is dominated
            // by shared-memory capacity rather than thread count.  We therefore keep
            // 8 queries per block for maximal tile reuse and simply spend the extra
            // shared-memory headroom on the largest tile the device can support.
            if (supports_shared<1024, 8192>(caps)) {
                launch_knn_specialized<1024, 8192>(query, query_count, data, data_count, result);
            } else {
                launch_knn_specialized<1024, 4096>(query, query_count, data, data_count, result);
            }
            break;

        default:
            // Per problem statement, k is always a valid power of two in [32, 1024].
            break;
    }
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>
#include <type_traits>
