namespace {

// Warp-centric exact k-NN for 2D points.
// Design choices tuned for modern datacenter GPUs (A100/H100):
// - One warp computes one query.
// - A 256-thread block (8 warps) cooperatively stages 256 data points into shared memory.
//   This is the largest practical block size that still leaves enough shared memory for the
//   per-warp top-k state when K == 1024.
// - Each warp keeps its private top-k as a sorted array of 64-bit keys in shared memory.
//   Key layout: [high 32 bits = squared-distance float bits][low 32 bits = data index].
//   Since squared distances are non-negative, unsigned integer ordering of the float bit pattern
//   matches the numeric ordering of the distance; the low 32 bits then break ties by index.
// - For each tile, only candidates strictly better than the current threshold are compacted.
//   Survivors are sorted in place and merged with the current top-k via a warp-parallel
//   merge-path partition. This updates K/32 output positions per lane at once.
// - No auxiliary device memory is allocated; all temporary state lives in dynamic shared memory.

constexpr int kWarpSize      = 32;
constexpr int kBlockThreads  = 256;
constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
constexpr int kTilePoints    = kBlockThreads;
constexpr int kTileIters     = kTilePoints / kWarpSize;
constexpr unsigned kFullMask = 0xffffffffu;

// Sentinel key larger than any valid finite-distance key and also larger than any real +inf key,
// because the low 32 bits are set to the maximal index value.
constexpr uint64_t kInfKey = 0x7f800000ffffffffULL;

// The public API uses std::pair<int, float>. Device code writes through a trivial POD view with
// the same expected 8-byte {int, float} payload. This avoids depending on device annotations
// in the host STL implementation while keeping the externally visible interface unchanged.
struct ResultPair {
    int   first;
    float second;
};

static_assert(sizeof(float2) == sizeof(uint64_t), "float2 is expected to be 8 bytes.");
static_assert(sizeof(ResultPair) == 8, "ResultPair is expected to be 8 bytes.");
static_assert(offsetof(ResultPair, second) == sizeof(int), "Unexpected ResultPair layout.");
static_assert(std::is_trivially_copyable<ResultPair>::value, "ResultPair must be trivially copyable.");
static_assert(std::is_standard_layout<ResultPair>::value, "ResultPair must be standard layout.");
static_assert(sizeof(std::pair<int, float>) == sizeof(ResultPair),
              "Unexpected std::pair<int, float> size; this implementation expects 8 bytes.");

// Dynamic shared-memory footprint:
//   tile:      256 x float2
//   per warp:  top[K] + tmp[K] + cand[256], all as uint64_t keys
template <int K>
constexpr std::size_t shared_mem_bytes() {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    return sizeof(float2) * kTilePoints +
           sizeof(uint64_t) * (2 * kWarpsPerBlock * K + kWarpsPerBlock * kTilePoints);
}

// A100 supports 163840 B/block of dynamic shared memory; H100 supports more.
static_assert(shared_mem_bytes<1024>() <= 163840,
              "The chosen block/tile configuration must fit the A100 shared-memory budget.");

__device__ __forceinline__ uint64_t pack_key_bits(uint32_t dist_bits, uint32_t idx) {
    return (static_cast<uint64_t>(dist_bits) << 32) | static_cast<uint64_t>(idx);
}

__device__ __forceinline__ float unpack_dist(uint64_t key) {
    return __uint_as_float(static_cast<uint32_t>(key >> 32));
}

__device__ __forceinline__ int unpack_index(uint64_t key) {
    return static_cast<int>(static_cast<uint32_t>(key));
}

// In-warp bitonic sort of N keys stored in warp-private shared memory.
// N is always a power of two and at most 1024.
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(uint64_t* keys) {
    static_assert((N & (N - 1)) == 0, "Bitonic sort size must be a power of two.");

    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int size = 2; size <= N; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int i = lane; i < N; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const uint64_t a = keys[i];
                    const uint64_t b = keys[j];
                    const bool ascending = ((i & size) == 0);
                    const bool do_swap  = ascending ? (a > b) : (a < b);

                    if (do_swap) {
                        keys[i] = b;
                        keys[j] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

__device__ __forceinline__ void sort_candidates_shared(uint64_t* cand, int count_pow2) {
    switch (count_pow2) {
        case 32:  bitonic_sort_shared<32>(cand);  break;
        case 64:  bitonic_sort_shared<64>(cand);  break;
        case 128: bitonic_sort_shared<128>(cand); break;
        default:  bitonic_sort_shared<256>(cand); break;
    }
}

// Merge-path partition for two sorted arrays A and B.
// Returns the number of items taken from A in the first "diag" outputs of A merge B.
__device__ __forceinline__ int merge_path_partition(
    const uint64_t* A, int A_count,
    const uint64_t* B, int B_count,
    int diag) {

    int low = diag - B_count;
    if (low < 0) low = 0;

    int high = (diag < A_count) ? diag : A_count;

    while (low <= high) {
        const int a = (low + high) >> 1;
        const int b = diag - a;

        const bool move_left  = (a > 0)        && (b < B_count) && (B[b]     < A[a - 1]);
        const bool move_right = (b > 0)        && (a < A_count) && (A[a]     < B[b - 1]);

        if (move_left) {
            high = a - 1;
        } else if (move_right) {
            low = a + 1;
        } else {
            return a;
        }
    }

    return low;
}

// Warp-parallel merge of the current sorted top-k and a sorted candidate list.
// Each lane writes K/32 consecutive outputs.
template <int K>
__device__ __forceinline__ void merge_topk_shared(
    const uint64_t* top,
    const uint64_t* cand,
    int cand_count,
    uint64_t* out) {

    constexpr int kItemsPerLane = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int out_begin = lane * kItemsPerLane;

    int a = merge_path_partition(top, K, cand, cand_count, out_begin);
    int b = out_begin - a;

#pragma unroll
    for (int n = 0; n < kItemsPerLane; ++n) {
        const uint64_t a_key = (a < K)          ? top[a]  : kInfKey;
        const uint64_t b_key = (b < cand_count) ? cand[b] : kInfKey;
        const bool take_a = (a_key <= b_key);

        out[out_begin + n] = take_a ? a_key : b_key;
        a += static_cast<int>(take_a);
        b += static_cast<int>(!take_a);
    }
}

// Process a subset [begin_p, valid_count) of the current shared-memory tile for one warp/query.
// The loop always executes a fixed 8 iterations (one per 32-point subgroup in a 256-point tile),
// which keeps all lanes converged at each ballot even for partial tiles and shifted begin_p.
template <int K>
__device__ __forceinline__ void process_tile_candidates(
    const float2* tile,
    int tile_base_index,
    int begin_p,
    int valid_count,
    float qx,
    float qy,
    uint64_t*& top,
    uint64_t*& tmp,
    uint64_t* cand,
    uint32_t& threshold_bits,
    uint32_t& threshold_idx) {

    const int lane = threadIdx.x & (kWarpSize - 1);
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    int cand_count = 0;

#pragma unroll
    for (int g = 0; g < kTileIters; ++g) {
        const int p = begin_p + g * kWarpSize + lane;

        bool pass = false;
        uint64_t key = 0;

        if (p < valid_count) {
            const float2 pt = tile[p];
            const float dx = qx - pt.x;
            const float dy = qy - pt.y;
            const float dist = fmaf(dx, dx, dy * dy);

            const uint32_t dist_bits = __float_as_uint(dist);
            const uint32_t idx = static_cast<uint32_t>(tile_base_index + p);

            pass = (dist_bits < threshold_bits) ||
                   ((dist_bits == threshold_bits) && (idx < threshold_idx));

            if (pass) {
                key = pack_key_bits(dist_bits, idx);
            }
        }

        const unsigned mask = __ballot_sync(kFullMask, pass);
        if (pass) {
            const int local_rank = __popc(mask & lane_mask_lt);
            cand[cand_count + local_rank] = key;
        }
        cand_count += __popc(mask);
    }

    __syncwarp();

    if (cand_count == 0) {
        return;
    }

    int merge_count = cand_count;

    if (cand_count > 1) {
        int cand_n = 32;
        if (cand_count > 32) {
            cand_n = (cand_count <= 64) ? 64 : ((cand_count <= 128) ? 128 : 256);
        }

        for (int i = lane + cand_count; i < cand_n; i += kWarpSize) {
            cand[i] = kInfKey;
        }
        __syncwarp();

        sort_candidates_shared(cand, cand_n);
        merge_count = cand_n;
    }

    merge_topk_shared<K>(top, cand, merge_count, tmp);
    __syncwarp();

    uint64_t* old_top = top;
    top = tmp;
    tmp = old_top;

    const uint64_t threshold_key = top[K - 1];
    threshold_bits = static_cast<uint32_t>(threshold_key >> 32);
    threshold_idx  = static_cast<uint32_t>(threshold_key);
}

template <int K>
__global__ __launch_bounds__(kBlockThreads, 1)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    ResultPair* __restrict__ result) {

    constexpr int kMainBase = (K < kTilePoints) ? kTilePoints : K;

    extern __shared__ __align__(8) uint64_t smem_u64[];

    // Shared-memory layout:
    //   [0 .. tile-1]              : float2 tile[256]
    //   [tile .. tile+warps*K-1]   : top keys
    //   [.. next warps*K ..]       : tmp keys
    //   [.. next warps*256 ..]     : candidate keys
    float2*  sh_tile   = reinterpret_cast<float2*>(smem_u64);
    uint64_t* top_base = reinterpret_cast<uint64_t*>(sh_tile + kTilePoints);
    uint64_t* tmp_base = top_base + kWarpsPerBlock * K;
    uint64_t* cand_base = tmp_base + kWarpsPerBlock * K;

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int qid     = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_id;
    const bool active = (qid < query_count);

    float2 q;
    q.x = 0.0f;
    q.y = 0.0f;
    if (lane == 0 && active) {
        q = query[qid];
    }

    const float qx = __shfl_sync(kFullMask, q.x, 0);
    const float qy = __shfl_sync(kFullMask, q.y, 0);

    uint64_t* top  = top_base  + warp_id * K;
    uint64_t* tmp  = tmp_base  + warp_id * K;
    uint64_t* cand = cand_base + warp_id * kTilePoints;

    uint32_t threshold_bits = 0x7f800000u;
    uint32_t threshold_idx  = 0xffffffffu;

    // Initialization:
    // - For K < 256, consume the entire first 256-point tile so the threshold tightens early.
    // - For K >= 256, fill top[] with the first K points (which is tile-aligned for the
    //   supported K values 256/512/1024), then sort once.
    if constexpr (K < kTilePoints) {
        const int global = threadIdx.x;
        if (global < data_count) {
            sh_tile[threadIdx.x] = data[global];
        }
        __syncthreads();

        if (active) {
#pragma unroll
            for (int p = lane; p < K; p += kWarpSize) {
                const float2 pt = sh_tile[p];
                const float dx = qx - pt.x;
                const float dy = qy - pt.y;
                const float dist = fmaf(dx, dx, dy * dy);
                top[p] = pack_key_bits(__float_as_uint(dist), static_cast<uint32_t>(p));
            }

            __syncwarp();
            bitonic_sort_shared<K>(top);
            __syncwarp();

            const uint64_t threshold_key = top[K - 1];
            threshold_bits = static_cast<uint32_t>(threshold_key >> 32);
            threshold_idx  = static_cast<uint32_t>(threshold_key);

            const int first_tile_valid = (data_count < kTilePoints) ? data_count : kTilePoints;
            process_tile_candidates<K>(
                sh_tile, 0, K, first_tile_valid, qx, qy,
                top, tmp, cand, threshold_bits, threshold_idx);
        }

        __syncthreads();
    } else {
        for (int base = 0; base < K; base += kTilePoints) {
            // For the supported K >= 256 cases, this initialization region is always full.
            sh_tile[threadIdx.x] = data[base + threadIdx.x];
            __syncthreads();

            if (active) {
#pragma unroll
                for (int t = 0; t < kTileIters; ++t) {
                    const int p = t * kWarpSize + lane;
                    const float2 pt = sh_tile[p];
                    const float dx = qx - pt.x;
                    const float dy = qy - pt.y;
                    const float dist = fmaf(dx, dx, dy * dy);
                    top[base + p] = pack_key_bits(__float_as_uint(dist),
                                                  static_cast<uint32_t>(base + p));
                }
            }

            __syncthreads();
        }

        if (active) {
            bitonic_sort_shared<K>(top);
            __syncwarp();

            const uint64_t threshold_key = top[K - 1];
            threshold_bits = static_cast<uint32_t>(threshold_key >> 32);
            threshold_idx  = static_cast<uint32_t>(threshold_key);
        }

        __syncthreads();
    }

    // Main streaming pass over the remaining data, tile by tile.
    for (int base = kMainBase; base < data_count; base += kTilePoints) {
        const int global = base + threadIdx.x;
        if (global < data_count) {
            sh_tile[threadIdx.x] = data[global];
        }
        __syncthreads();

        if (active) {
            int valid = data_count - base;
            if (valid > kTilePoints) {
                valid = kTilePoints;
            }

            process_tile_candidates<K>(
                sh_tile, base, 0, valid, qx, qy,
                top, tmp, cand, threshold_bits, threshold_idx);
        }

        __syncthreads();
    }

    // The final top-k is already globally sorted by ascending (distance, index).
    if (active) {
        ResultPair* out = result + static_cast<std::size_t>(qid) * static_cast<std::size_t>(K);

#pragma unroll
        for (int j = lane; j < K; j += kWarpSize) {
            const uint64_t key = top[j];
            out[j].first  = unpack_index(key);
            out[j].second = unpack_dist(key);
        }
    }
}

template <int K>
inline void launch_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result) {

    const std::size_t smem = shared_mem_bytes<K>();

    // The public interface is void, so launch/configuration errors are intentionally not
    // propagated here; callers can use standard CUDA error handling around run_knn().
    static_cast<void>(cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100));

    static_cast<void>(cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem)));

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    knn_kernel<K><<<grid, block, smem>>>(
        query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {

    if (query_count <= 0) {
        return;
    }

    auto* result_view = reinterpret_cast<ResultPair*>(result);

    switch (k) {
        case 32:   launch_knn<32>(query, query_count, data, data_count, result_view);   break;
        case 64:   launch_knn<64>(query, query_count, data, data_count, result_view);   break;
        case 128:  launch_knn<128>(query, query_count, data, data_count, result_view);  break;
        case 256:  launch_knn<256>(query, query_count, data, data_count, result_view);  break;
        case 512:  launch_knn<512>(query, query_count, data, data_count, result_view);  break;
        case 1024: launch_knn<1024>(query, query_count, data, data_count, result_view); break;
        default:   break;  // Inputs are specified to be valid; keep a safe fallback.
    }
}

#include <cuda_runtime.h>

#include <cstddef>
#include <utility>

// Exact brute-force 2D k-NN on the GPU.
// Design choices tuned for modern data-center GPUs (A100/H100):
//   * One warp computes one query.
//   * One 256-thread block = 8 warps = 8 queries processed concurrently.
//   * Each block streams the data set in shared-memory tiles that are reused by all 8 warps.
//   * For each warp/query, two K-sized shared-memory arrays are reserved:
//       - current top-K (sorted ascending by distance)
//       - candidate buffer (unsorted while filling, then sorted and merged)
//     These two arrays ping-pong, so no third K-sized scratch buffer is needed.
//   * The shared-memory tile is stored as SoA (x[], y[]) instead of float2[] to avoid
//     shared-memory bank conflicts on repeated warp reads.
//
// The interface is fixed to std::pair<int, float>.  Device code writes through a POD
// mirror with matching size/alignment.  This is the ABI used by mainstream CUDA host
// toolchains for pair<int,float>; the static_asserts catch obvious mismatches.
struct alignas(alignof(std::pair<int, float>)) PairIF {
    int first;
    float second;
};

static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>),
              "std::pair<int,float> must match PairIF size");
static_assert(alignof(PairIF) == alignof(std::pair<int, float>),
              "std::pair<int,float> must match PairIF alignment");

constexpr int KNN_WARP_SIZE = 32;
constexpr int KNN_WARPS_PER_BLOCK = 8;
constexpr int KNN_BLOCK_THREADS = KNN_WARP_SIZE * KNN_WARPS_PER_BLOCK;

// A100 exposes 160 KiB (= 163840 B) opt-in shared memory per block.
// For K <= 512, we keep the whole block at 80 KiB so that two blocks can reside per SM.
// For K == 1024, two blocks are impossible anyway, so we use almost the full 160 KiB
// and keep a small 4 KiB guard band.
constexpr int KNN_A100_MAX_OPTIN_SHARED_BYTES = 160 * 1024;
constexpr int KNN_TWO_BLOCKS_SHARED_BUDGET = KNN_A100_MAX_OPTIN_SHARED_BYTES / 2;
constexpr int KNN_ONE_BLOCK_GUARD_BYTES = 4 * 1024;
constexpr unsigned KNN_FULL_MASK = 0xffffffffu;

template <int K>
struct KNNLaunchConfig {
    static_assert(K == 32 || K == 64 || K == 128 || K == 256 || K == 512 || K == 1024,
                  "Unsupported K");

    static constexpr int top_and_buffer_bytes =
        2 * KNN_WARPS_PER_BLOCK * K * static_cast<int>(sizeof(float) + sizeof(int));

    static constexpr int block_shared_budget_bytes =
        (K <= 512) ? KNN_TWO_BLOCKS_SHARED_BUDGET
                   : (KNN_A100_MAX_OPTIN_SHARED_BYTES - KNN_ONE_BLOCK_GUARD_BYTES);

    static constexpr int tile_points =
        (block_shared_budget_bytes - top_and_buffer_bytes) / static_cast<int>(sizeof(float2));

    static constexpr int shared_bytes =
        top_and_buffer_bytes + tile_points * static_cast<int>(sizeof(float2));

    static_assert(tile_points > 0, "Tile must be positive");
    static_assert((tile_points % KNN_BLOCK_THREADS) == 0,
                  "Tile size must be a multiple of blockDim for balanced cooperative loads");
    static_assert(shared_bytes <= KNN_A100_MAX_OPTIN_SHARED_BYTES,
                  "Shared-memory footprint exceeds A100 opt-in limit");
};

template <typename T>
__device__ __forceinline__ void knn_swap_ptrs(T*& a, T*& b) {
    T* tmp = a;
    a = b;
    b = tmp;
}

// Full bitonic sort of K key/value pairs in warp-private shared memory.
// The array is sorted ascending by distance.
template <int K>
__device__ __forceinline__ void knn_sort_shared_pairs(float* dist, int* idx) {
    const int lane = threadIdx.x & (KNN_WARP_SIZE - 1);

    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int i = lane; i < K; i += KNN_WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const float di = dist[i];
                    const float dj = dist[j];
                    const int ii = idx[i];
                    const int ij = idx[j];

                    const bool ascending = ((i & size) == 0);
                    const bool do_swap = ascending ? (dj < di) : (di < dj);

                    if (do_swap) {
                        dist[i] = dj;
                        idx[i] = ij;
                        dist[j] = di;
                        idx[j] = ii;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Merge-path partition on the first `diag` outputs of two sorted arrays A and B,
// both of length K, both sorted ascending.  Returns how many elements come from A.
// This variant is stable with respect to A on equal keys.
template <int K>
__device__ __forceinline__ int knn_merge_path_partition(const float* a, const float* b, int diag) {
    int low = 0;
    int high = diag;  // diag is only ever in [0, K] here.

    while (low < high) {
        const int mid = (low + high) >> 1;
        const int b_prev = diag - mid - 1;

        if (b_prev >= 0 && a[mid] <= b[b_prev]) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    return low;
}

// Flushes the warp-private candidate buffer into the running top-K:
//   1) pad tail with +inf / -1 if buffer is only partially full
//   2) sort the K candidates in shared memory
//   3) if this is the first flush, the sorted buffer simply becomes the top-K
//   4) otherwise, warp-parallel merge-path computes the first K outputs of
//      merge(top, buffer), writes them into the buffer array, and then swaps pointers
template <int K>
__device__ __forceinline__ void knn_flush_buffer(
    float*& top_d,
    int*& top_i,
    float*& buf_d,
    int*& buf_i,
    int& buf_count,
    bool& top_empty,
    float& kth_dist)
{
    constexpr int ITEMS_PER_LANE = K / KNN_WARP_SIZE;
    const int lane = threadIdx.x & (KNN_WARP_SIZE - 1);

    if (buf_count < K) {
        for (int pos = buf_count + lane; pos < K; pos += KNN_WARP_SIZE) {
            buf_d[pos] = CUDART_INF_F;
            buf_i[pos] = -1;
        }
    }

    // Makes all earlier candidate writes visible before sorting.
    __syncwarp();

    knn_sort_shared_pairs<K>(buf_d, buf_i);

    if (top_empty) {
        // First full/partial sorted buffer directly becomes the running top-K.
        knn_swap_ptrs(top_d, buf_d);
        knn_swap_ptrs(top_i, buf_i);
        top_empty = false;
    } else {
        const int out_begin = lane * ITEMS_PER_LANE;
        const int out_end = out_begin + ITEMS_PER_LANE;

        const int a_begin = knn_merge_path_partition<K>(top_d, buf_d, out_begin);
        const int a_end = knn_merge_path_partition<K>(top_d, buf_d, out_end);
        const int b_begin = out_begin - a_begin;
        const int b_end = out_end - a_end;

        float merged_d[ITEMS_PER_LANE];
        int merged_i[ITEMS_PER_LANE];

        int a_pos = a_begin;
        int b_pos = b_begin;

#pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const float da = (a_pos < a_end) ? top_d[a_pos] : CUDART_INF_F;
            const float db = (b_pos < b_end) ? buf_d[b_pos] : CUDART_INF_F;

            if (da <= db) {
                merged_d[t] = da;
                merged_i[t] = top_i[a_pos];
                ++a_pos;
            } else {
                merged_d[t] = db;
                merged_i[t] = buf_i[b_pos];
                ++b_pos;
            }
        }

        // Keep reads from top/buf completely separated from the output writes.
        __syncwarp();

#pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            buf_d[out_begin + t] = merged_d[t];
            buf_i[out_begin + t] = merged_i[t];
        }

        __syncwarp();

        // The merged output was written into the buffer arrays; make them the new top-K.
        knn_swap_ptrs(top_d, buf_d);
        knn_swap_ptrs(top_i, buf_i);
    }

    float local_kth = (lane == KNN_WARP_SIZE - 1) ? top_d[K - 1] : 0.0f;
    kth_dist = __shfl_sync(KNN_FULL_MASK, local_kth, KNN_WARP_SIZE - 1);
    buf_count = 0;
}

template <int K>
__launch_bounds__(KNN_BLOCK_THREADS)
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    PairIF* __restrict__ result)
{
    using Cfg = KNNLaunchConfig<K>;
    constexpr int TILE_POINTS = Cfg::tile_points;
    constexpr int ITEMS_PER_LANE = K / KNN_WARP_SIZE;

    const int tid = threadIdx.x;
    const int warp_id = tid >> 5;
    const int lane = tid & (KNN_WARP_SIZE - 1);
    const int query_id = blockIdx.x * KNN_WARPS_PER_BLOCK + warp_id;
    const bool active_query = (query_id < query_count);

    // Shared-memory layout:
    //   tile_x[TILE_POINTS], tile_y[TILE_POINTS],
    //   top/buf dist+index arrays for each warp
    extern __shared__ unsigned char smem_raw[];
    float* tile_x = reinterpret_cast<float*>(smem_raw);
    float* tile_y = tile_x + TILE_POINTS;
    float* shared_a_d = tile_y + TILE_POINTS;
    int* shared_a_i = reinterpret_cast<int*>(shared_a_d + KNN_WARPS_PER_BLOCK * K);
    float* shared_b_d = reinterpret_cast<float*>(shared_a_i + KNN_WARPS_PER_BLOCK * K);
    int* shared_b_i = reinterpret_cast<int*>(shared_b_d + KNN_WARPS_PER_BLOCK * K);

    const int warp_base = warp_id * K;

    float* top_d = shared_a_d + warp_base;
    int* top_i = shared_a_i + warp_base;
    float* buf_d = shared_b_d + warp_base;
    int* buf_i = shared_b_i + warp_base;

    // Query point lives in registers for the whole scan.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query && lane == 0) {
        const float2 q = query[query_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(KNN_FULL_MASK, qx, 0);
    qy = __shfl_sync(KNN_FULL_MASK, qy, 0);

    int buf_count = 0;
    bool top_empty = true;
    float kth_dist = CUDART_INF_F;

    const unsigned lower_lane_mask =
        (lane == 0) ? 0u : ((1u << lane) - 1u);

    // Stream the data set through shared memory in tiles.
    for (int base = 0; base < data_count; base += TILE_POINTS) {
        int tile_count = data_count - base;
        if (tile_count > TILE_POINTS) {
            tile_count = TILE_POINTS;
        }

        // Whole block cooperatively loads the next tile to shared memory.
        for (int t = tid; t < tile_count; t += KNN_BLOCK_THREADS) {
            const float2 p = data[base + t];
            tile_x[t] = p.x;
            tile_y[t] = p.y;
        }

        __syncthreads();

        if (active_query) {
            // Process the cached tile in warp-sized chunks so all warp collectives
            // operate on a uniform control flow.
            for (int tile_off = 0; tile_off < tile_count; tile_off += KNN_WARP_SIZE) {
                const int local = tile_off + lane;

                float dist = 0.0f;
                int idx = -1;
                bool active = false;

                if (local < tile_count) {
                    const float dx = qx - tile_x[local];
                    const float dy = qy - tile_y[local];
                    dist = __fmaf_rn(dx, dx, dy * dy);  // squared L2 distance
                    idx = base + local;
                    active = (dist < kth_dist);         // strictly closer than current K-th
                }

                // Append all qualifying lanes into the warp-private candidate buffer.
                // If the append would overflow the buffer, the surviving lanes are
                // re-evaluated after the flush because the K-th threshold tightens.
                unsigned mask = __ballot_sync(KNN_FULL_MASK, active);
                while (mask) {
                    const int rank = __popc(mask & lower_lane_mask);
                    const int count = __popc(mask);
                    const int space = K - buf_count;
                    const int inserted = (count < space) ? count : space;

                    if (active && rank < space) {
                        const int pos = buf_count + rank;
                        buf_d[pos] = dist;
                        buf_i[pos] = idx;
                    }

                    const bool remain = active && (rank >= space);
                    buf_count += inserted;

                    if (buf_count == K) {
                        knn_flush_buffer<K>(top_d, top_i, buf_d, buf_i,
                                            buf_count, top_empty, kth_dist);
                    }

                    active = remain && (dist < kth_dist);
                    mask = __ballot_sync(KNN_FULL_MASK, active);
                }
            }
        }

        // The tile storage is reused by the next batch.
        __syncthreads();
    }

    if (active_query && buf_count > 0) {
        knn_flush_buffer<K>(top_d, top_i, buf_d, buf_i,
                            buf_count, top_empty, kth_dist);
    }

    if (active_query) {
        const std::size_t out_base =
            static_cast<std::size_t>(query_id) * static_cast<std::size_t>(K);

        // Strided writeback avoids shared-memory bank conflicts on the final readout
        // and keeps global stores naturally coalesced.
#pragma unroll
        for (int pos = lane; pos < K; pos += KNN_WARP_SIZE) {
            PairIF out;
            out.first = top_i[pos];
            out.second = top_d[pos];
            result[out_base + static_cast<std::size_t>(pos)] = out;
        }
    }
}

template <int K>
inline void knn_launch(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    PairIF* result)
{
    using Cfg = KNNLaunchConfig<K>;
    constexpr int SHARED_BYTES = Cfg::shared_bytes;

    // Opt in to the required dynamic shared-memory footprint and strongly prefer
    // the shared-memory carve-out because this kernel is intentionally shared-heavy.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        SHARED_BYTES);
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(KNN_BLOCK_THREADS);
    const dim3 grid((query_count + KNN_WARPS_PER_BLOCK - 1) / KNN_WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, SHARED_BYTES>>>(query, query_count, data, data_count, result);
}

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    PairIF* out = reinterpret_cast<PairIF*>(result);

    // K is guaranteed to be a supported power of two.  Compile-time specialization
    // lets the compiler fully know K, shared-memory footprint, and per-lane work.
    switch (k) {
        case 32:
            knn_launch<32>(query, query_count, data, data_count, out);
            break;
        case 64:
            knn_launch<64>(query, query_count, data, data_count, out);
            break;
        case 128:
            knn_launch<128>(query, query_count, data, data_count, out);
            break;
        case 256:
            knn_launch<256>(query, query_count, data, data_count, out);
            break;
        case 512:
            knn_launch<512>(query, query_count, data, data_count, out);
            break;
        case 1024:
            knn_launch<1024>(query, query_count, data, data_count, out);
            break;
        default:
            // The problem statement guarantees validity; this is only a defensive no-op.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>

namespace knn_detail {

/*
  High-level design:

  - One query is owned by one warp, as requested.
  - One thread block contains 8 warps (256 threads), so a block processes 8 queries at once.
    This is a good compromise on A100/H100: it gives substantial reuse of each shared-memory
    data tile across multiple queries while still keeping enough blocks in flight.

  - For each warp / query:
      * The current top-k ("intermediate result") is kept as a private warp-distributed copy
        in registers: lane L owns ranks {L, L+32, L+64, ...}.
      * The candidate buffer of size k lives in shared memory.
      * An additional shared-memory scratch region of size k is used only while merging; this
        does not allocate any extra device memory outside the kernel.

  - The block walks over the dataset in tiles cached in shared memory.
    All threads cooperatively load one tile of data points.
    Each warp computes distances from its own query to the cached tile and appends only
    candidates with distance < current k-th neighbor into its shared candidate buffer.

  - When the candidate buffer becomes full (or would overflow), the warp merges it with the
    register-resident top-k:
      * pad unused candidate slots with +inf
      * spill the current top-k to the second half of the shared workspace
      * sort the 2k (candidate + top-k) pairs in shared memory with a warp-cooperative bitonic sort
      * reload the first k pairs back to registers

    This shared-memory merge avoids random indexed access into register arrays, which would
    otherwise risk local-memory spills and hurt performance.

  - Distances returned are squared Euclidean distances, exactly as required.
*/

constexpr int WARP_SIZE = 32;
constexpr int WARPS_PER_BLOCK = 8;
constexpr int BLOCK_THREADS = WARPS_PER_BLOCK * WARP_SIZE;
constexpr unsigned FULL_MASK = 0xffffffffu;

struct alignas(std::pair<int, float>) PairIF {
    int first;
    float second;
};

static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>), "std::pair<int,float> must match PairIF size");
static_assert(alignof(PairIF) == alignof(std::pair<int, float>), "std::pair<int,float> must match PairIF alignment");

template <int K>
struct KernelConfig {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "k must be a power of two in [32,1024]");
    enum {
        kItemsPerThread = K / WARP_SIZE,
        // Per warp: k candidate pairs + k scratch pairs used during merge.
        kWorksetBytes = WARPS_PER_BLOCK * (2 * K) * (int(sizeof(float)) + int(sizeof(int))),
        // k=1024 forces 1 block/SM from shared memory on A100/H100 with the chosen 8-warps/block design.
        // Smaller k can sustain 2 blocks/SM, so the host launcher sizes the tile accordingly.
        kPreferredBlocksPerSM = (K == 1024 ? 1 : 2)
    };
};

__device__ __forceinline__ unsigned lane_mask_lt() {
    unsigned m;
    asm volatile("mov.u32 %0, %%lanemask_lt;" : "=r"(m));
    return m;
}

__device__ __forceinline__ bool pair_less(float ad, int ai, float bd, int bi) {
    return (ad < bd) || (ad == bd && ai < bi);
}

__device__ __forceinline__ bool pair_greater(float ad, int ai, float bd, int bi) {
    return pair_less(bd, bi, ad, ai);
}

template <int SLOT, int ITEMS>
struct InitTop {
    __device__ __forceinline__ static void run(float (&top_dist)[ITEMS], int (&top_idx)[ITEMS]) {
        top_dist[SLOT] = CUDART_INF_F;
        top_idx[SLOT] = INT_MAX;
        InitTop<SLOT + 1, ITEMS>::run(top_dist, top_idx);
    }
};

template <int ITEMS>
struct InitTop<ITEMS, ITEMS> {
    __device__ __forceinline__ static void run(float (&)[ITEMS], int (&)[ITEMS]) {}
};

template <int SLOT, int ITEMS, int K>
struct SpillTopToShared {
    __device__ __forceinline__ static void run(
        const float (&top_dist)[ITEMS],
        const int (&top_idx)[ITEMS],
        float *work_dist,
        int *work_idx,
        int lane) {
        const int pos = K + (SLOT << 5) + lane;
        work_dist[pos] = top_dist[SLOT];
        work_idx[pos] = top_idx[SLOT];
        SpillTopToShared<SLOT + 1, ITEMS, K>::run(top_dist, top_idx, work_dist, work_idx, lane);
    }
};

template <int ITEMS, int K>
struct SpillTopToShared<ITEMS, ITEMS, K> {
    __device__ __forceinline__ static void run(
        const float (&)[ITEMS],
        const int (&)[ITEMS],
        float *,
        int *,
        int) {}
};

template <int SLOT, int ITEMS>
struct LoadTopFromShared {
    __device__ __forceinline__ static void run(
        float (&top_dist)[ITEMS],
        int (&top_idx)[ITEMS],
        const float *work_dist,
        const int *work_idx,
        int lane) {
        const int pos = (SLOT << 5) + lane;
        top_dist[SLOT] = work_dist[pos];
        top_idx[SLOT] = work_idx[pos];
        LoadTopFromShared<SLOT + 1, ITEMS>::run(top_dist, top_idx, work_dist, work_idx, lane);
    }
};

template <int ITEMS>
struct LoadTopFromShared<ITEMS, ITEMS> {
    __device__ __forceinline__ static void run(
        float (&)[ITEMS],
        int (&)[ITEMS],
        const float *,
        const int *,
        int) {}
};

template <int SLOT, int ITEMS>
struct StoreResults {
    __device__ __forceinline__ static void run(
        const float (&top_dist)[ITEMS],
        const int (&top_idx)[ITEMS],
        PairIF *result,
        int base_out,
        int lane) {
        const int pos = base_out + (SLOT << 5) + lane;
        result[pos].first = top_idx[SLOT];
        result[pos].second = top_dist[SLOT];
        StoreResults<SLOT + 1, ITEMS>::run(top_dist, top_idx, result, base_out, lane);
    }
};

template <int ITEMS>
struct StoreResults<ITEMS, ITEMS> {
    __device__ __forceinline__ static void run(
        const float (&)[ITEMS],
        const int (&)[ITEMS],
        PairIF *,
        int,
        int) {}
};

template <int N>
__device__ __forceinline__ void sort_shared_bitonic(float *dist, int *idx) {
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Keep the fixed-size network as loops instead of fully unrolling it;
    // this controls code size while remaining efficient because merges are
    // relatively rare after the distance threshold becomes selective.
    #pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll 1
            for (int i = lane; i < N; i += WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const float di = dist[i];
                    const int ii = idx[i];
                    const float dj = dist[j];
                    const int ij = idx[j];

                    const bool ascending = ((i & size) == 0);
                    const bool do_swap = ascending ? pair_greater(di, ii, dj, ij)
                                                   : pair_less(di, ii, dj, ij);
                    if (do_swap) {
                        dist[i] = dj;
                        idx[i]  = ij;
                        dist[j] = di;
                        idx[j]  = ii;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
}

template <int K>
__device__ __forceinline__ void merge_candidate_buffer(
    float (&top_dist)[KernelConfig<K>::kItemsPerThread],
    int (&top_idx)[KernelConfig<K>::kItemsPerThread],
    float *work_dist,
    int *work_idx,
    int candidate_count) {
    enum { ITEMS = KernelConfig<K>::kItemsPerThread };
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Ensure all previous candidate writes are visible to the warp.
    __syncwarp(FULL_MASK);

    // Pad the unused candidate slots with sentinels so the fixed-size sort remains valid.
    for (int i = lane; i < K; i += WARP_SIZE) {
        if (i >= candidate_count) {
            work_dist[i] = CUDART_INF_F;
            work_idx[i]  = INT_MAX;
        }
    }

    // Copy the private register-resident top-k into the scratch half of shared memory.
    SpillTopToShared<0, ITEMS, K>::run(top_dist, top_idx, work_dist, work_idx, lane);
    __syncwarp(FULL_MASK);

    // Sort candidate[0..K) + top[K..2K), then keep the smallest K.
    sort_shared_bitonic<2 * K>(work_dist, work_idx);

    // Reload the new top-k back into the private register copy.
    LoadTopFromShared<0, ITEMS>::run(top_dist, top_idx, work_dist, work_idx, lane);
    __syncwarp(FULL_MASK);
}

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(
    const float2 *__restrict__ query,
    int query_count,
    const float2 *__restrict__ data,
    int data_count,
    PairIF *__restrict__ result,
    int tile_points) {
    enum { ITEMS = KernelConfig<K>::kItemsPerThread };

    extern __shared__ unsigned char smem_raw[];

    // Shared-memory layout:
    //   [tile_points x float2]                                : cached input tile
    //   [WARPS_PER_BLOCK x (2K) x float]                      : per-warp candidate buffer + merge scratch distances
    //   [WARPS_PER_BLOCK x (2K) x int]                        : per-warp candidate buffer + merge scratch indices
    float2 *tile = reinterpret_cast<float2 *>(smem_raw);
    float *work_dist_all = reinterpret_cast<float *>(tile + tile_points);
    int *work_idx_all = reinterpret_cast<int *>(work_dist_all + WARPS_PER_BLOCK * (2 * K));

    const int tid = threadIdx.x;
    const int lane = tid & (WARP_SIZE - 1);
    const int warp = tid >> 5;

    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active_query = (query_idx < query_count);

    float *my_work_dist = work_dist_all + warp * (2 * K);
    int *my_work_idx = work_idx_all + warp * (2 * K);

    float top_dist[ITEMS];
    int top_idx[ITEMS];
    InitTop<0, ITEMS>::run(top_dist, top_idx);

    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    float kth = CUDART_INF_F;
    int buf_count = 0;

    for (int base = 0; base < data_count; base += tile_points) {
        const int remaining = data_count - base;
        const int valid = (remaining < tile_points) ? remaining : tile_points;

        // Cooperative tile load by the whole block.
        for (int i = tid; i < valid; i += BLOCK_THREADS) {
            tile[i] = data[base + i];
        }
        __syncthreads();

        if (active_query) {
            // Process the tile in warp-sized chunks so warp ballots compact the accepted candidates.
            for (int j = 0; j < valid; j += WARP_SIZE) {
                const int local = j + lane;

                bool pred = false;
                float dist = 0.0f;
                int gidx = base + local;

                if (local < valid) {
                    const float2 p = tile[local];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = __fmaf_rn(dx, dx, dy * dy);
                    pred = (dist < kth);  // strict, as requested ("not closer than" gets skipped)
                }

                unsigned pass = __ballot_sync(FULL_MASK, pred);
                int pass_count = __popc(pass);

                // If the current warp-sized batch would overflow the buffer, merge the buffer first.
                if (buf_count + pass_count > K) {
                    if (buf_count > 0) {
                        merge_candidate_buffer<K>(top_dist, top_idx, my_work_dist, my_work_idx, buf_count);
                        buf_count = 0;
                        kth = __shfl_sync(FULL_MASK, top_dist[ITEMS - 1], WARP_SIZE - 1);
                    }

                    // Re-evaluate the current 32 candidates against the tighter threshold.
                    pred = false;
                    if (local < valid) {
                        pred = (dist < kth);
                    }
                    pass = __ballot_sync(FULL_MASK, pred);
                    pass_count = __popc(pass);
                }

                if (pred) {
                    const int pos = buf_count + __popc(pass & lane_mask_lt());
                    my_work_dist[pos] = dist;
                    my_work_idx[pos] = gidx;
                }
                buf_count += pass_count;

                if (buf_count == K) {
                    merge_candidate_buffer<K>(top_dist, top_idx, my_work_dist, my_work_idx, buf_count);
                    buf_count = 0;
                    kth = __shfl_sync(FULL_MASK, top_dist[ITEMS - 1], WARP_SIZE - 1);
                }
            }
        }

        // All warps in the block must finish with the tile before it is overwritten.
        __syncthreads();
    }

    if (active_query) {
        if (buf_count > 0) {
            merge_candidate_buffer<K>(top_dist, top_idx, my_work_dist, my_work_idx, buf_count);
        }

        // Store the final top-k in ascending order of squared distance.
        StoreResults<0, ITEMS>::run(top_dist, top_idx, result, query_idx * K, lane);
    }
}

inline int shared_budget_bytes(int preferred_blocks_per_sm) {
    // Reasonable fallbacks if attribute queries are unavailable for some reason.
    int per_sm = (preferred_blocks_per_sm == 1) ? (160 * 1024) : (80 * 1024);
    int per_block_optin = per_sm;

    int device = 0;
    if (cudaGetDevice(&device) == cudaSuccess) {
        int value = 0;
        if (cudaDeviceGetAttribute(&value, cudaDevAttrMaxSharedMemoryPerMultiprocessor, device) == cudaSuccess && value > 0) {
            per_sm = value;
        }
        value = 0;
        if (cudaDeviceGetAttribute(&value, cudaDevAttrMaxSharedMemoryPerBlockOptin, device) == cudaSuccess && value > 0) {
            per_block_optin = value;
        }
    }

    int budget = per_sm / preferred_blocks_per_sm;
    if (budget > per_block_optin) {
        budget = per_block_optin;
    }

    // Shared-memory allocation granularity is naturally coarse; rounding down to 256 B keeps
    // the launch arithmetic predictable.
    budget &= ~255;
    return budget;
}

template <int K>
inline void launch_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result) {
    typedef KernelConfig<K> Cfg;

    int preferred_blocks = Cfg::kPreferredBlocksPerSM;
    int budget = shared_budget_bytes(preferred_blocks);

    // If the requested residency leaves no room for even one warp-sized tile, fall back to 1 block/SM.
    const int min_tile_bytes = int(sizeof(float2) * WARP_SIZE);
    if (budget < Cfg::kWorksetBytes + min_tile_bytes) {
        preferred_blocks = 1;
        budget = shared_budget_bytes(1);
    }

    int available_tile_bytes = budget - Cfg::kWorksetBytes;
    if (available_tile_bytes < min_tile_bytes) {
        available_tile_bytes = min_tile_bytes;
    }

    int tile_points = available_tile_bytes / int(sizeof(float2));
    tile_points = (tile_points / WARP_SIZE) * WARP_SIZE;
    if (tile_points < WARP_SIZE) {
        tile_points = WARP_SIZE;
    }

    // Avoid allocating a larger tile than the dataset needs.
    const int max_needed_points = ((data_count - 1) / WARP_SIZE + 1) * WARP_SIZE;
    if (tile_points > max_needed_points) {
        tile_points = max_needed_points;
    }

    const int shared_bytes = Cfg::kWorksetBytes + tile_points * int(sizeof(float2));
    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    (void)cudaFuncSetAttribute(knn_kernel<K>, cudaFuncAttributeMaxDynamicSharedMemorySize, shared_bytes);
    (void)cudaFuncSetAttribute(knn_kernel<K>, cudaFuncAttributePreferredSharedMemoryCarveout, 100);

    knn_kernel<K><<<blocks, BLOCK_THREADS, shared_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<PairIF *>(result),
        tile_points);
}

}  // namespace knn_detail

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   knn_detail::launch_knn<32>(query, query_count, data, data_count, result); break;
        case 64:   knn_detail::launch_knn<64>(query, query_count, data, data_count, result); break;
        case 128:  knn_detail::launch_knn<128>(query, query_count, data, data_count, result); break;
        case 256:  knn_detail::launch_knn<256>(query, query_count, data, data_count, result); break;
        case 512:  knn_detail::launch_knn<512>(query, query_count, data, data_count, result); break;
        case 1024: knn_detail::launch_knn<1024>(query, query_count, data, data_count, result); break;
        default:   break;  // inputs are guaranteed valid; this is a defensive no-op
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn_detail {

// Warp-specialized k-NN for 2D points.
// Key design points, matching the requested execution model:
//   * one warp computes one query;
//   * the whole block stages a tile of input data points in shared memory;
//   * each warp owns a private shared-memory slice:
//       [0, K)   : current top-K intermediate result (sorted after every flush)
//       [K, 2*K) : unsorted candidate buffer
//   * candidates farther than the current K-th neighbor are rejected early;
//   * when the candidate buffer fills or would overflow, the warp merges
//     "intermediate result + candidates" cooperatively.
//
// The merge path is implemented as a full in-place bitonic sort of 2*K items
// inside the warp's private shared-memory slice. For this problem size
// (K <= 1024) and expected acceptance rate (it drops quickly once the threshold
// tightens), this is a robust and fast shared-memory-heavy strategy on A100/H100
// without requiring any extra device allocation.

using ResultPair = std::pair<int, float>;

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

// Cooperative in-warp bitonic sort over shared-memory arrays.
// Distances are the primary key; indices are only used as a deterministic
// tie-breaker (the API allows arbitrary tie resolution anyway).
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(float* dist, int* idx, int lane) {
    static_assert((N & (N - 1)) == 0, "Bitonic sort length must be a power of two.");

    for (int size = 2; size <= N; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += kWarpSize) {
                const int partner = i ^ stride;
                if (partner > i) {
                    const float di = dist[i];
                    const float dp = dist[partner];
                    const int ii = idx[i];
                    const int ip = idx[partner];

                    const bool ascending = ((i & size) == 0);
                    const bool do_swap =
                        ascending ? ((di > dp) || ((di == dp) && (ii > ip)))
                                  : ((di < dp) || ((di == dp) && (ii < ip)));

                    if (do_swap) {
                        dist[i] = dp;
                        dist[partner] = di;
                        idx[i] = ip;
                        idx[partner] = ii;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Flush the candidate buffer into the intermediate top-K.
// The first K entries hold the current intermediate result; the second K
// entries are the candidate buffer. Missing candidate slots are padded with +inf
// so the final 2*K in-place sort leaves the K smallest items in [0, K).
template <int K>
__device__ __forceinline__ void merge_candidate_buffer(
    float* dist, int* idx, int lane, int& cand_count, float& threshold) {
    if (cand_count == 0) {
        return;
    }

#pragma unroll
    for (int pos = K + lane; pos < 2 * K; pos += kWarpSize) {
        if ((pos - K) >= cand_count) {
            dist[pos] = CUDART_INF_F;
            idx[pos] = -1;
        }
    }
    __syncwarp(kFullMask);

    bitonic_sort_shared<2 * K>(dist, idx, lane);

    float kth = 0.0f;
    if (lane == 0) {
        kth = dist[K - 1];
    }
    threshold = __shfl_sync(kFullMask, kth, 0);
    cand_count = 0;
}

template <int K, int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                ResultPair* __restrict__ result) {
    static_assert((K & (K - 1)) == 0 && K >= 32 && K <= 1024,
                  "K must be a power of two in [32, 1024].");
    static_assert(BLOCK_THREADS % kWarpSize == 0,
                  "BLOCK_THREADS must be a multiple of warp size.");

    constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpSize;
    constexpr int kTileSteps = BLOCK_THREADS / kWarpSize;
    constexpr std::size_t kPerWarpFloatBytes =
        static_cast<std::size_t>(2 * K) * sizeof(float);
    constexpr std::size_t kPerWarpIntBytes =
        static_cast<std::size_t>(2 * K) * sizeof(int);
    constexpr std::size_t kPerWarpBytes = kPerWarpFloatBytes + kPerWarpIntBytes;

    extern __shared__ unsigned char shared_raw[];

    // Shared-memory layout:
    //   tile_x[BLOCK_THREADS]
    //   tile_y[BLOCK_THREADS]
    //   warp 0: dist[2*K], idx[2*K]
    //   warp 1: dist[2*K], idx[2*K]
    //   ...
    // Splitting the staged data tile into SoA (x/y) avoids the bank behavior of
    // repeated float2 accesses while keeping the same total byte footprint.
    float* tile_x = reinterpret_cast<float*>(shared_raw);
    float* tile_y = tile_x + BLOCK_THREADS;
    unsigned char* warp_storage = reinterpret_cast<unsigned char*>(tile_y + BLOCK_THREADS);

    const int warp_local = threadIdx.x >> 5;
    const int lane = threadIdx.x & (kWarpSize - 1);

    unsigned char* my_storage =
        warp_storage + static_cast<std::size_t>(warp_local) * kPerWarpBytes;
    float* dist = reinterpret_cast<float*>(my_storage);                      // [0, 2*K)
    int* idx = reinterpret_cast<int*>(my_storage + kPerWarpFloatBytes);     // [0, 2*K)

    const int query_idx = blockIdx.x * kWarpsPerBlock + warp_local;
    const bool valid = (query_idx < query_count);

    // One query point per warp; lane 0 loads, then broadcasts.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && valid) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Initialize the intermediate result to +inf / invalid index.
    if (valid) {
#pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            dist[i] = CUDART_INF_F;
            idx[i] = -1;
        }
        __syncwarp(kFullMask);
    }

    int cand_count = 0;
    float threshold = CUDART_INF_F;

    // Stream over the data set in block-sized tiles staged in shared memory.
    // All threads participate in the tile load, even if their warp has no valid
    // query in the tail block; that keeps the cooperative load fully coalesced.
    for (int tile_base = 0; tile_base < data_count; tile_base += BLOCK_THREADS) {
        const int global_idx = tile_base + threadIdx.x;
        if (global_idx < data_count) {
            const float2 p = data[global_idx];
            tile_x[threadIdx.x] = p.x;
            tile_y[threadIdx.x] = p.y;
        }
        __syncthreads();

        const int remaining = data_count - tile_base;
        const int tile_count = (remaining < BLOCK_THREADS) ? remaining : BLOCK_THREADS;

        // Each warp walks the cached tile with one element per lane per step.
        // The loop trip count is fixed by BLOCK_THREADS, which keeps the warp
        // fully converged for ballot/shuffle usage; inactive lanes simply use
        // has_elem == false on the tail step of the last tile.
        for (int step = 0; step < kTileSteps; ++step) {
            const int j = step * kWarpSize + lane;
            const bool has_elem = valid && (j < tile_count);

            float d = 0.0f;
            if (has_elem) {
                const float dx = qx - tile_x[j];
                const float dy = qy - tile_y[j];
                d = fmaf(dx, dx, dy * dy);  // squared Euclidean distance
            }

            bool pass = has_elem && (d < threshold);
            unsigned pass_mask = __ballot_sync(kFullMask, pass);
            int pass_count = __popc(pass_mask);

            // If this warp-sized insertion would overflow the K-entry candidate
            // buffer, first flush the current buffer, then re-test the current
            // warp chunk against the tighter post-merge threshold.
            if (cand_count + pass_count > K) {
                merge_candidate_buffer<K>(dist, idx, lane, cand_count, threshold);

                pass = has_elem && (d < threshold);
                pass_mask = __ballot_sync(kFullMask, pass);
                pass_count = __popc(pass_mask);
            }

            const unsigned lane_mask_lt = (1u << lane) - 1u;
            const int local_offset = __popc(pass_mask & lane_mask_lt);

            if (pass) {
                const int out = K + cand_count + local_offset;
                dist[out] = d;
                idx[out] = tile_base + j;
            }
            __syncwarp(kFullMask);

            cand_count += pass_count;

            // Flush immediately when the buffer becomes full. This both satisfies
            // the requested behavior and tightens the rejection threshold early.
            if (cand_count == K) {
                merge_candidate_buffer<K>(dist, idx, lane, cand_count, threshold);
            }
        }

        // Ensure every warp is done consuming the staged tile before it is reused
        // by the next block-wide cooperative load.
        __syncthreads();
    }

    if (valid && cand_count > 0) {
        merge_candidate_buffer<K>(dist, idx, lane, cand_count, threshold);
    }

    // The first K entries are sorted ascending by distance after the final flush.
    if (valid) {
        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

#pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            result[out_base + i].first = idx[i];
            result[out_base + i].second = dist[i];
        }
    }
}

template <int K, int BLOCK_THREADS>
constexpr std::size_t shared_bytes_for_kernel() {
    return static_cast<std::size_t>(2 * BLOCK_THREADS) * sizeof(float) +
           static_cast<std::size_t>(BLOCK_THREADS / kWarpSize) *
               (static_cast<std::size_t>(2 * K) * sizeof(float) +
                static_cast<std::size_t>(2 * K) * sizeof(int));
}

inline int current_sm_count() {
    int device = 0;
    if (cudaGetDevice(&device) != cudaSuccess) {
        return 0;
    }
    int sms = 0;
    if (cudaDeviceGetAttribute(&sms, cudaDevAttrMultiProcessorCount, device) != cudaSuccess) {
        return 0;
    }
    return (sms > 0) ? sms : 0;
}

// Host-side launcher for a single (K, BLOCK_THREADS) specialization.
// The kernel is heavily shared-memory bound by design, so we explicitly opt in
// to the required dynamic shared-memory size and request a full shared carveout.
template <int K, int BLOCK_THREADS>
inline void launch_knn_kernel(const float2* query,
                              int query_count,
                              const float2* data,
                              int data_count,
                              ResultPair* result) {
    constexpr std::size_t shmem = shared_bytes_for_kernel<K, BLOCK_THREADS>();

    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shmem));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpSize;
    const int grid = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    knn_kernel<K, BLOCK_THREADS><<<grid, BLOCK_THREADS, shmem>>>(
        query, query_count, data, data_count, result);
}

// Block-size heuristic:
//   * 256 threads  => 8 queries/block
//   * 512 threads  => 16 queries/block
//
// For the prompt's "low-thousands" query counts on large GPUs, 1024-thread
// blocks would too often reduce the number of resident blocks below the number
// of SMs. The 256/512 choice is a better compromise:
//
//   * 256 threads keeps enough independent blocks in flight when query_count is
//     only modestly above 1k;
//   * 512 threads doubles data-tile reuse and halves block-wide tile barriers
//     once there are enough queries to populate all SMs with 16-query blocks.
template <int K>
inline void dispatch_for_k(const float2* query,
                           int query_count,
                           const float2* data,
                           int data_count,
                           ResultPair* result,
                           int sm_count) {
    const bool use_512 = (sm_count > 0) && (query_count >= 16 * sm_count);
    if (use_512) {
        launch_knn_kernel<K, 512>(query, query_count, data, data_count, result);
    } else {
        launch_knn_kernel<K, 256>(query, query_count, data, data_count, result);
    }
}

// K=1024 needs 256-thread blocks to stay within the A100/H100 per-block shared
// memory budget while still keeping 8 queries/block.
template <>
inline void dispatch_for_k<1024>(const float2* query,
                                 int query_count,
                                 const float2* data,
                                 int data_count,
                                 ResultPair* result,
                                 int /*sm_count*/) {
    launch_knn_kernel<1024, 256>(query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    // Standard CUDA convention: asynchronous launch on the current default stream.
    if (query_count <= 0) {
        return;
    }

    const int sm_count = knn_detail::current_sm_count();

    switch (k) {
        case 32:
            knn_detail::dispatch_for_k<32>(query, query_count, data, data_count, result, sm_count);
            break;
        case 64:
            knn_detail::dispatch_for_k<64>(query, query_count, data, data_count, result, sm_count);
            break;
        case 128:
            knn_detail::dispatch_for_k<128>(query, query_count, data, data_count, result, sm_count);
            break;
        case 256:
            knn_detail::dispatch_for_k<256>(query, query_count, data, data_count, result, sm_count);
            break;
        case 512:
            knn_detail::dispatch_for_k<512>(query, query_count, data, data_count, result, sm_count);
            break;
        case 1024:
            knn_detail::dispatch_for_k<1024>(query, query_count, data, data_count, result, sm_count);
            break;
        default:
            // By contract, k is always a valid power of two in [32, 1024].
            break;
    }
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>
#include <type_traits>
#include <utility>

namespace {

// Exact brute-force k-NN for 2D points in squared Euclidean distance.
//
// Design choices tuned for modern data-center GPUs (A100/H100 class):
// - One warp computes one query.
// - A 256-thread block therefore processes 8 queries at once. This is a good compromise:
//   enough data-tile reuse inside a block, while still creating enough blocks for
//   query counts in the low thousands.
// - Legal k values are only {32, 64, 128, 256, 512, 1024}, so we specialize on K.
//   That gives fixed-size per-lane top-k storage and lets the compiler optimize
//   register usage and loop structure aggressively.
// - Each warp keeps the current top-k in a private register array.
// - Each warp also owns a k-entry candidate buffer in shared memory.
// - Data points are loaded tile-by-tile into shared memory by the whole block.
// - When the candidate buffer fills (or would overflow), the warp:
//     1) pads the candidate buffer with +inf,
//     2) sorts it with a warp-local bitonic network,
//     3) merges it with the current top-k using merge path.
//
// Distances are returned as squared L2 norms, exactly as requested.

constexpr int WARP_SIZE = 32;
constexpr int BLOCK_THREADS = 256;
constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / WARP_SIZE;

// For non-negative floats, IEEE-754 bit order matches numeric order.  Packing the
// distance in the upper 32 bits and the index in the lower 32 bits lets us move
// (distance,index) as a single 64-bit word during shared-memory sorts/merges.
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;
constexpr std::uint64_t INF_KEY = 0x7F800000FFFFFFFFull;  // +inf distance, index -1.
constexpr std::size_t A100_MAX_SMEM_BYTES = 163840;

// Device code should not depend on std::pair having device constructors/operators.
// The result buffer is raw cudaMalloc memory; we reinterpret it as this trivially
// assignable POD, while asserting the common ABI layout.
struct ResultPair {
    int first;
    float second;
};

static_assert(sizeof(ResultPair) == sizeof(std::pair<int, float>),
              "std::pair<int,float> layout mismatch");
static_assert(alignof(ResultPair) == alignof(std::pair<int, float>),
              "std::pair<int,float> alignment mismatch");

constexpr int ct_log2(int v) {
    return (v <= 1) ? 0 : 1 + ct_log2(v >> 1);
}

__device__ __forceinline__ std::uint64_t pack_key(int idx, float dist) {
    return (static_cast<std::uint64_t>(__float_as_uint(dist)) << 32) |
           static_cast<std::uint32_t>(idx);
}

__device__ __forceinline__ int unpack_idx(std::uint64_t key) {
    return static_cast<int>(static_cast<std::uint32_t>(key));
}

__device__ __forceinline__ float unpack_dist(std::uint64_t key) {
    return __uint_as_float(static_cast<std::uint32_t>(key >> 32));
}

// The warp-private top-k is kept in registers in "lane-chunked" logical order:
// lane l owns logical positions [l * ITEMS_PER_LANE, ..., l * ITEMS_PER_LANE + ITEMS_PER_LANE - 1].
//
// When spilling that array to shared memory for a merge, we store it in an interleaved
// physical layout best_sh[lane + 32 * t].  That spill pattern is shared-memory friendly.
// This helper maps a logical index back to that physical interleaved layout.
template <int K>
__device__ __forceinline__ std::uint64_t best_logical_load(
    const std::uint64_t* __restrict__ best_sh,
    int logical_idx) {
    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;
    constexpr int ITEMS_LOG2 = ct_log2(ITEMS_PER_LANE);
    constexpr int ITEMS_MASK = ITEMS_PER_LANE - 1;

    const int owner_lane = logical_idx >> ITEMS_LOG2;
    const int owner_off  = logical_idx & ITEMS_MASK;
    return best_sh[owner_lane + owner_off * WARP_SIZE];
}

// Warp-local bitonic sort for exactly K keys in shared memory.
// K is always a power of two and at most 1024.
template <int K>
__device__ __forceinline__ void sort_candidate_buffer(
    std::uint64_t* __restrict__ cand_sh,
    int lane) {
    static_assert(K >= WARP_SIZE && (K & (K - 1)) == 0, "K must be a power of two in [32,1024]");
    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int t = 0; t < ITEMS_PER_LANE; ++t) {
                const int i = lane + t * WARP_SIZE;
                const int j = i ^ stride;
                if (j > i) {
                    const bool ascending = ((i & size) == 0);
                    const std::uint64_t a = cand_sh[i];
                    const std::uint64_t b = cand_sh[j];
                    const bool do_swap = ascending ? (a > b) : (a < b);
                    if (do_swap) {
                        cand_sh[i] = b;
                        cand_sh[j] = a;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
}

// Standard merge-path partition for two sorted arrays of equal length K.
// A is the current best set (stored in the interleaved shared-memory layout above),
// B is the sorted candidate buffer in contiguous shared memory.
template <int K>
__device__ __forceinline__ int merge_path_partition(
    const std::uint64_t* __restrict__ best_sh,
    const std::uint64_t* __restrict__ cand_sh,
    int diag) {
    int low  = (diag > K) ? (diag - K) : 0;
    int high = (diag < K) ? diag : K;

    while (low < high) {
        const int mid = (low + high) >> 1;
        const int b   = diag - mid;

        const std::uint64_t a_key  = (mid < K) ? best_logical_load<K>(best_sh, mid) : INF_KEY;
        const std::uint64_t b_left = (b > 0) ? cand_sh[b - 1] : 0ull;

        // We advance "mid" while A[mid] belongs before B[b-1].
        if ((b > 0) && (mid < K) && (a_key <= b_left)) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }
    return low;
}

// Flush the warp's candidate buffer into the current best set.
// best_keys[] is the private register copy of the current top-k, lane-chunked.
// cand_sh[] is the shared candidate buffer, contiguous.
// best_sh[] is shared scratch for the current best set, written in interleaved layout.
// Returns the updated k-th distance, broadcast to the whole warp.
template <int K>
__device__ __forceinline__ float merge_candidate_buffer(
    std::uint64_t* __restrict__ best_sh,
    std::uint64_t* __restrict__ cand_sh,
    std::uint64_t (&best_keys)[K / WARP_SIZE],
    int cand_count,
    int lane) {
    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    // Spill current best to shared scratch in the interleaved physical layout.
    // At the same time, pad the unused tail of the candidate buffer with +inf,
    // so we can always sort/merge exactly K elements.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int phys = lane + t * WARP_SIZE;
        best_sh[phys] = best_keys[t];
        if (phys >= cand_count) {
            cand_sh[phys] = INF_KEY;
        }
    }
    __syncwarp(FULL_MASK);

    // Sort candidates in-place.
    sort_candidate_buffer<K>(cand_sh, lane);

    // Each lane produces one contiguous chunk of the merged top-k.
    const int out_begin = lane * ITEMS_PER_LANE;
    int a = merge_path_partition<K>(best_sh, cand_sh, out_begin);
    int b = out_begin - a;

#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const std::uint64_t a_key = (a < K) ? best_logical_load<K>(best_sh, a) : INF_KEY;
        const std::uint64_t b_key = (b < K) ? cand_sh[b] : INF_KEY;
        const bool take_a = (a_key <= b_key);
        best_keys[t] = take_a ? a_key : b_key;
        a += static_cast<int>(take_a);
        b += static_cast<int>(!take_a);
    }

    // Lane 31 owns the last logical chunk, and its last register is the global k-th item.
    float kth_dist = unpack_dist(best_keys[ITEMS_PER_LANE - 1]);
    kth_dist = __shfl_sync(FULL_MASK, kth_dist, WARP_SIZE - 1);
    return kth_dist;
}

template <int K, int BATCH_POINTS>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    ResultPair* __restrict__ result) {
    static_assert(K >= WARP_SIZE && K <= 1024 && (K & (K - 1)) == 0,
                  "K must be a power of two in [32,1024]");
    static_assert(BATCH_POINTS % WARP_SIZE == 0, "BATCH_POINTS must be a multiple of 32");
    static_assert((BATCH_POINTS & 1) == 0, "BATCH_POINTS must be even for float4 tile loads");

    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    // Shared-memory layout:
    //   [batch tile of float2 points][candidate buffers][best scratch buffers]
    //
    // uint4 gives us 16-byte alignment so float4 tile loads into shared memory are aligned.
    extern __shared__ uint4 smem_u4[];
    float2* batch = reinterpret_cast<float2*>(smem_u4);
    std::uint64_t* cand_all = reinterpret_cast<std::uint64_t*>(batch + BATCH_POINTS);
    std::uint64_t* best_all = cand_all + WARPS_PER_BLOCK * K;

    const int warp_id   = threadIdx.x >> 5;
    const int lane      = threadIdx.x & (WARP_SIZE - 1);
    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active_query = (query_idx < query_count);

    std::uint64_t* cand_sh = cand_all + warp_id * K;
    std::uint64_t* best_sh = best_all + warp_id * K;

    // One query point per warp; load once and broadcast.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active_query) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Private register-resident current top-k, lane-chunked.
    std::uint64_t best_keys[ITEMS_PER_LANE];
#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        best_keys[t] = INF_KEY;
    }

    float kth_dist = CUDART_INF_F;
    int cand_count = 0;

    const unsigned lane_bit     = 1u << lane;
    const unsigned lane_mask_lt = lane_bit - 1u;

    for (int tile_base = 0; tile_base < data_count; tile_base += BATCH_POINTS) {
        int batch_count = data_count - tile_base;
        if (batch_count > BATCH_POINTS) {
            batch_count = BATCH_POINTS;
        }

        // Cooperative, vectorized tile load:
        // data is float2[], so loading two points at a time as float4 halves the number of
        // load instructions. cudaMalloc alignment plus even tile starts make this safe here.
        const int pair_count = batch_count >> 1;
        float4* batch4 = reinterpret_cast<float4*>(batch);
        const float4* data4 = reinterpret_cast<const float4*>(data + tile_base);

        for (int i = threadIdx.x; i < pair_count; i += BLOCK_THREADS) {
            batch4[i] = data4[i];
        }
        if ((batch_count & 1) && threadIdx.x == 0) {
            batch[batch_count - 1] = data[tile_base + batch_count - 1];
        }

        // Whole block must finish populating the shared tile before any warp consumes it.
        __syncthreads();

        if (active_query) {
            // Walk the tile in warp-sized groups so each lane handles one point per group.
            for (int group = 0; group < batch_count; group += WARP_SIZE) {
                const int local_idx = group + lane;
                const bool point_active = (local_idx < batch_count);

                float dist = 0.0f;
                const int data_idx = tile_base + local_idx;

                if (point_active) {
                    const float2 p = batch[local_idx];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = __fmaf_rn(dx, dx, dy * dy);
                }

                // Problem statement only requires pruning by the k-th distance, not by any
                // tie-break rule, so a strict distance comparison is sufficient.
                unsigned mask = __ballot_sync(FULL_MASK, point_active && (dist < kth_dist));

                // Rare overflow case: the current group would not fit into the candidate buffer.
                // Flush current candidates first, then re-evaluate the current group against the
                // tighter post-merge threshold.
                while (mask != 0u) {
                    const int accepted = __popc(mask);

                    if ((cand_count > 0) && (cand_count + accepted > K)) {
                        kth_dist = merge_candidate_buffer<K>(best_sh, cand_sh, best_keys, cand_count, lane);
                        cand_count = 0;
                        mask = __ballot_sync(FULL_MASK, point_active && (dist < kth_dist));
                        continue;
                    }

                    const int base = cand_count;

                    if (mask & lane_bit) {
                        const int rank = __popc(mask & lane_mask_lt);
                        cand_sh[base + rank] = pack_key(data_idx, dist);
                    }

                    cand_count = base + accepted;

                    if (cand_count == K) {
                        kth_dist = merge_candidate_buffer<K>(best_sh, cand_sh, best_keys, cand_count, lane);
                        cand_count = 0;
                    }
                    break;
                }
            }
        }

        // The block reuses the same shared tile buffer on the next iteration.
        __syncthreads();
    }

    if (active_query) {
        if (cand_count > 0) {
            kth_dist = merge_candidate_buffer<K>(best_sh, cand_sh, best_keys, cand_count, lane);
            (void)kth_dist;
        }

        // Write back the final lane-chunked top-k.
        // This store pattern is not the most coalesced possible, but the output traffic is tiny
        // relative to the O(query_count * data_count) distance work and data-tile traffic.
        const std::size_t out_base = static_cast<std::size_t>(query_idx) * K;
        const int chunk_base = lane * ITEMS_PER_LANE;

#pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const std::uint64_t key = best_keys[t];
            ResultPair& dst = result[out_base + chunk_base + t];
            dst.first  = unpack_idx(key);
            dst.second = unpack_dist(key);
        }
    }
}

template <int K, int BATCH_POINTS>
inline void launch_knn_specialized(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result) {
    constexpr std::size_t SHARED_BYTES =
        static_cast<std::size_t>(BATCH_POINTS) * sizeof(float2) +
        static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(std::uint64_t) * 2u;

    static_assert(SHARED_BYTES <= A100_MAX_SMEM_BYTES,
                  "Chosen kernel configuration exceeds A100 shared-memory capacity");

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    // Opt into the required dynamic shared memory size for this specialization.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BATCH_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHARED_BYTES));

    knn_kernel<K, BATCH_POINTS><<<grid, block, SHARED_BYTES>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<ResultPair*>(result));
}

}  // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    // Batch-size heuristics:
    // - K <= 256: 4096-point tiles. Shared memory still allows 2-4 blocks/SM on A100,
    //   which is a good balance of tile reuse and occupancy.
    // - K >= 512: 2048-point tiles. Larger K consumes more warp-private/shared state,
    //   so a smaller tile keeps the block within the A100 shared-memory budget.
    switch (k) {
        case 32:
            launch_knn_specialized<32, 4096>(query, query_count, data, data_count, result);
            break;
        case 64:
            launch_knn_specialized<64, 4096>(query, query_count, data, data_count, result);
            break;
        case 128:
            launch_knn_specialized<128, 4096>(query, query_count, data, data_count, result);
            break;
        case 256:
            launch_knn_specialized<256, 4096>(query, query_count, data, data_count, result);
            break;
        case 512:
            launch_knn_specialized<512, 2048>(query, query_count, data, data_count, result);
            break;
        case 1024:
            launch_knn_specialized<1024, 2048>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem statement guarantees valid k, so this path is only defensive.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>
#include <type_traits>
#include <utility>

namespace knn_cuda_detail {

// Exact brute-force 2D k-NN specialized for modern NVIDIA data-center GPUs.
//
// Design summary:
//  - One warp computes one query.
//  - The whole block stages a batch of input data points into shared memory.
//  - The staged batch is stored in shared memory as SoA (x[] / y[]) rather than AoS
//    to avoid the 64-bit shared-memory bank conflicts that float2 would cause in
//    the hot distance-computation loop.
//  - Each warp owns two disjoint on-chip arrays:
//      * topk[] : the current intermediate k nearest neighbors for that query.
//      * cand[] : a k-entry candidate buffer.
//    Both arrays live in shared memory, but each warp has a private, non-overlapping
//    slice, which satisfies the "private copy per query" requirement without using
//    any extra global/device memory.
//  - Distances and indices are packed into one 64-bit key:
//        high 32 bits = IEEE-754 bits of the non-negative squared distance
//        low  32 bits = data-point index
//    Because squared distances are non-negative, unsigned integer ordering of the
//    float bit pattern matches numeric ordering, so one integer compare orders
//    (distance, index) lexicographically.
//  - When the candidate buffer fills, it is sorted cooperatively by the warp with a
//    bitonic network, then merged with topk[] using a warp-parallel merge-path merge.
//    The merge is stable with A-before-B tie handling so equal sentinels remain correct.
//
// Tuning summary (chosen to fit A100's 160 KiB/block opt-in shared-memory limit while
// maximizing reuse of each loaded data batch):
//   k=32   -> 32 warps/block, batch=8192  (80 KiB/block, enables 2 resident blocks/SM)
//   k=64   -> 32 warps/block, batch=6144  (80 KiB/block, enables 2 resident blocks/SM)
//   k=128  -> 32 warps/block, batch=12288 (160 KiB/block, maximizes reuse per batch)
//   k=256  -> 32 warps/block, batch=4096  (160 KiB/block)
//   k=512  -> 16 warps/block, batch=4096  (160 KiB/block)
//   k=1024 ->  8 warps/block, batch=4096  (160 KiB/block)

constexpr int kWarpSize = 32;
constexpr std::size_t kMaxOptinDynamicSharedBytesA100 = 163840;

using KeyT = std::uint64_t;

// We write into device memory allocated for std::pair<int,float>. To avoid relying on
// std::pair being device-constructible, the kernel uses an ABI-compatible POD overlay.
// Mainstream CUDA host compilers lay out std::pair<int,float> as two adjacent 32-bit
// scalars; the size check below enforces that assumption at compile time.
struct ResultPairABI {
    int first;
    float second;
};
static_assert(sizeof(ResultPairABI) == sizeof(std::pair<int, float>),
              "std::pair<int,float> is expected to occupy 8 bytes.");

constexpr unsigned kInfBits = 0x7f800000u;
constexpr KeyT kInfKey =
    (static_cast<KeyT>(kInfBits) << 32) | static_cast<KeyT>(0xffffffffu);

template <int K>
struct KnnConfig;

template <>
struct KnnConfig<32> {
    static constexpr int kWarpsPerBlock = 32;
    static constexpr int kBatchPoints = 8192;
};

template <>
struct KnnConfig<64> {
    static constexpr int kWarpsPerBlock = 32;
    static constexpr int kBatchPoints = 6144;
};

template <>
struct KnnConfig<128> {
    static constexpr int kWarpsPerBlock = 32;
    static constexpr int kBatchPoints = 12288;
};

template <>
struct KnnConfig<256> {
    static constexpr int kWarpsPerBlock = 32;
    static constexpr int kBatchPoints = 4096;
};

template <>
struct KnnConfig<512> {
    static constexpr int kWarpsPerBlock = 16;
    static constexpr int kBatchPoints = 4096;
};

template <>
struct KnnConfig<1024> {
    static constexpr int kWarpsPerBlock = 8;
    static constexpr int kBatchPoints = 4096;
};

template <int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
constexpr std::size_t shared_storage_bytes() {
    return static_cast<std::size_t>(BATCH_POINTS) * sizeof(float) * 2u +  // x[] + y[]
           static_cast<std::size_t>(WARPS_PER_BLOCK) * static_cast<std::size_t>(K) *
               sizeof(KeyT) * 2u;  // topk[] + cand[]
}

__device__ __forceinline__ KeyT pack_key(const unsigned dist_bits, const unsigned idx) {
    return (static_cast<KeyT>(dist_bits) << 32) | static_cast<KeyT>(idx);
}

__device__ __forceinline__ unsigned key_dist_bits(const KeyT key) {
    return static_cast<unsigned>(key >> 32);
}

__device__ __forceinline__ float key_dist(const KeyT key) {
    return __uint_as_float(key_dist_bits(key));
}

__device__ __forceinline__ int key_index(const KeyT key) {
    return static_cast<int>(static_cast<unsigned>(key));
}

// Warp-cooperative bitonic sort in shared memory for one warp-private array.
// One warp handles one array; after every stage we use __syncwarp() because Volta+
// allows independent thread scheduling.
template <int N>
__device__ __forceinline__ void warp_bitonic_sort(KeyT* arr) {
    static_assert((N & (N - 1)) == 0, "N must be a power of two.");
    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int size = 2; size <= N; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int i = lane; i < N; i += kWarpSize) {
                const int partner = i ^ stride;
                if (partner > i) {
                    const KeyT a = arr[i];
                    const KeyT b = arr[partner];
                    const bool ascending = ((i & size) == 0);
                    if ((ascending && (b < a)) || (!ascending && (a < b))) {
                        arr[i] = b;
                        arr[partner] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Merge-path partition for the first "diag" outputs of a stable merge of A and B.
// Stability is A-before-B on equal keys. That detail matters because padding uses
// identical +inf sentinels on both inputs.
template <int K>
__device__ __forceinline__ int merge_path_partition(const KeyT* a,
                                                    const KeyT* b,
                                                    const int diag) {
    int low = (diag > K) ? (diag - K) : 0;
    int high = (diag < K) ? diag : K;

    while (low <= high) {
        const int a_count = (low + high) >> 1;
        const int b_count = diag - a_count;

        const bool move_left =
            (a_count > 0) && (b_count < K) && (b[b_count] < a[a_count - 1]);
        const bool move_right =
            (b_count > 0) && (a_count < K) && !(b[b_count - 1] < a[a_count]);

        if (move_left) {
            high = a_count - 1;
        } else if (move_right) {
            low = a_count + 1;
        } else {
            return a_count;
        }
    }
    return low;
}

// Merge two sorted K-element arrays (topk and cand) and keep only the first K outputs.
// Each lane computes K/32 contiguous outputs into registers, then writes them back.
template <int K>
__device__ __forceinline__ void merge_sorted_topk(KeyT* topk, const KeyT* cand) {
    constexpr int ITEMS_PER_LANE = K / kWarpSize;
    static_assert(ITEMS_PER_LANE >= 1, "K must be at least warp size.");
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int out_begin = lane * ITEMS_PER_LANE;

    KeyT local_out[ITEMS_PER_LANE];

    int a_pos = merge_path_partition<K>(topk, cand, out_begin);
    int b_pos = out_begin - a_pos;

#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const bool take_a =
            (b_pos >= K) || ((a_pos < K) && !(cand[b_pos] < topk[a_pos]));
        local_out[t] = take_a ? topk[a_pos++] : cand[b_pos++];
    }

    // Ensure all lanes finished reading the old topk[] before any lane overwrites it.
    __syncwarp();

#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        topk[out_begin + t] = local_out[t];
    }

    __syncwarp();
}

// Pad the candidate buffer to K with +inf, sort it, merge it into topk[], and return
// the new kth-neighbor distance bits (topk[K-1].distance).
template <int K>
__device__ __forceinline__ unsigned merge_buffer_into_topk(KeyT* topk,
                                                           KeyT* cand,
                                                           const int cand_count) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    if (cand_count < K) {
#pragma unroll
        for (int i = cand_count + lane; i < K; i += kWarpSize) {
            cand[i] = kInfKey;
        }
    }

    __syncwarp();
    warp_bitonic_sort<K>(cand);
    merge_sorted_topk<K>(topk, cand);
    return key_dist_bits(topk[K - 1]);
}

template <int K, int WARPS_PER_BLOCK, int BATCH_POINTS>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                ResultPairABI* __restrict__ result) {
    static_assert((K & (K - 1)) == 0 && K >= 32 && K <= 1024,
                  "Supported K values are powers of two in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");
    static_assert((BATCH_POINTS % kWarpSize) == 0,
                  "Batch size must be a multiple of warp size.");
    static_assert(WARPS_PER_BLOCK * kWarpSize <= 1024,
                  "Block size exceeds CUDA limit.");
    static_assert(shared_storage_bytes<K, WARPS_PER_BLOCK, BATCH_POINTS>() <=
                      kMaxOptinDynamicSharedBytesA100,
                  "Shared-memory footprint exceeds the A100-compatible limit.");

    constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * kWarpSize;

    // One dynamically allocated shared-memory slab:
    //   [ batch_x[BATCH_POINTS] | batch_y[BATCH_POINTS] | topk[warps][K] | cand[warps][K] ]
    extern __shared__ unsigned long long smem_ull[];

    float* const batch_x = reinterpret_cast<float*>(smem_ull);
    float* const batch_y = batch_x + BATCH_POINTS;
    KeyT* const topk_all = reinterpret_cast<KeyT*>(batch_y + BATCH_POINTS);
    KeyT* const cand_all = topk_all + (WARPS_PER_BLOCK * K);

    const int tid = threadIdx.x;
    const int lane = tid & (kWarpSize - 1);
    const int warp_id = tid >> 5;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active_query = (query_idx < query_count);

    KeyT* const topk = topk_all + warp_id * K;
    KeyT* const cand = cand_all + warp_id * K;

    // Warp-private state for this query.
    // topk[] is kept globally sorted in ascending distance order.
#pragma unroll
    for (int i = lane; i < K; i += kWarpSize) {
        topk[i] = kInfKey;
    }
    __syncwarp();

    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active_query) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(0xffffffffu, qx, 0);
    qy = __shfl_sync(0xffffffffu, qy, 0);

    const unsigned lower_lane_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);

    unsigned kth_bits = kInfBits;
    int cand_count = 0;
    bool done = false;

    for (int batch_begin = 0; batch_begin < data_count; batch_begin += BATCH_POINTS) {
        const int remaining = data_count - batch_begin;
        const int batch_count = (remaining < BATCH_POINTS) ? remaining : BATCH_POINTS;

        // Cooperative block-wide load from global memory into shared memory.
        // AoS in global memory -> SoA in shared memory for conflict-free hot reads.
        for (int i = tid; i < batch_count; i += THREADS_PER_BLOCK) {
            const float2 p = data[batch_begin + i];
            batch_x[i] = p.x;
            batch_y[i] = p.y;
        }

        __syncthreads();

        if (active_query && !done) {
            // Iterate in warp-sized chunks so every lane participates in every ballot.
            for (int base = 0; base < batch_count; base += kWarpSize) {
                const int local_i = base + lane;
                const bool valid = (local_i < batch_count);

                float dist = 0.0f;
                unsigned dist_bits = 0u;

                if (valid) {
                    const float dx = qx - batch_x[local_i];
                    const float dy = qy - batch_y[local_i];
                    dist = fmaf(dx, dx, dy * dy);
                    dist_bits = __float_as_uint(dist);
                }

                // Strictly closer only: the prompt explicitly allows arbitrary tie handling.
                bool accept = valid && (dist_bits < kth_bits);
                unsigned mask = __ballot_sync(0xffffffffu, accept);
                int accepted = __popc(mask);

                if (accepted) {
                    // If the current ballot would overflow the candidate buffer, merge the
                    // existing buffer first. Then re-test the current ballot against the
                    // tighter kth threshold produced by the merge.
                    if (cand_count + accepted > K) {
                        kth_bits = merge_buffer_into_topk<K>(topk, cand, cand_count);
                        cand_count = 0;

                        if (kth_bits == 0u) {
                            // Squared distances are non-negative, so once kth == 0, no future
                            // point can be strictly closer.
                            done = true;
                            break;
                        }

                        accept = valid && (dist_bits < kth_bits);
                        mask = __ballot_sync(0xffffffffu, accept);
                        accepted = __popc(mask);
                    }

                    if (accepted) {
                        if (accept) {
                            const int rank = __popc(mask & lower_lane_mask);
                            cand[cand_count + rank] =
                                pack_key(dist_bits, static_cast<unsigned>(batch_begin + local_i));
                        }

                        cand_count += accepted;
                        __syncwarp();

                        if (cand_count == K) {
                            kth_bits = merge_buffer_into_topk<K>(topk, cand, cand_count);
                            cand_count = 0;

                            if (kth_bits == 0u) {
                                done = true;
                                break;
                            }
                        }
                    }
                }
            }
        }

        __syncthreads();
    }

    if (active_query) {
        if (!done && cand_count > 0) {
            kth_bits = merge_buffer_into_topk<K>(topk, cand, cand_count);
            (void)kth_bits;
        }

        ResultPairABI* const out = result + static_cast<std::size_t>(query_idx) * K;

#pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            const KeyT key = topk[i];
            out[i].first = key_index(key);
            out[i].second = key_dist(key);
        }
    }
}

template <int K>
inline void launch_specialized(const float2* query,
                               const int query_count,
                               const float2* data,
                               const int data_count,
                               std::pair<int, float>* result) {
    constexpr int WARPS_PER_BLOCK = KnnConfig<K>::kWarpsPerBlock;
    constexpr int BATCH_POINTS = KnnConfig<K>::kBatchPoints;
    constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * kWarpSize;
    constexpr std::size_t SHARED_BYTES =
        shared_storage_bytes<K, WARPS_PER_BLOCK, BATCH_POINTS>();

    static_assert(SHARED_BYTES <= kMaxOptinDynamicSharedBytesA100,
                  "Launch configuration exceeds the A100-compatible shared-memory budget.");

    // Opt in to large dynamic shared memory. The wrapper intentionally remains
    // asynchronous; callers retain full control over stream synchronization and
    // error handling.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHARED_BYTES));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    knn_kernel<K, WARPS_PER_BLOCK, BATCH_POINTS>
        <<<blocks, THREADS_PER_BLOCK, SHARED_BYTES>>>(
            query,
            query_count,
            data,
            data_count,
            reinterpret_cast<ResultPairABI*>(result));
}

}  // namespace knn_cuda_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn_cuda_detail::launch_specialized<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_cuda_detail::launch_specialized<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_cuda_detail::launch_specialized<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_cuda_detail::launch_specialized<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_cuda_detail::launch_specialized<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_cuda_detail::launch_specialized<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The prompt guarantees valid k (power of two in [32, 1024]).
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

// Tuned warp-per-query 2D k-NN for modern NVIDIA data-center GPUs (A100/H100 class).
//
// Core design:
//   * One warp computes one query.
//   * The current top-K is kept as a warp-private sorted array distributed across the 32 lanes.
//     Each lane owns K/32 (indices, distances) pairs in private per-thread storage.
//   * Each warp also owns a K-entry candidate buffer in shared memory.
//   * The whole block stages a batch of data points in shared memory so every loaded point
//     is reused by all query-warps in the block.
//   * Shared memory uses SoA for the data tile (x[] and y[]) to avoid the 64-bit shared-memory
//     bank conflicts that a float2 AoS layout would create.
//   * When the candidate buffer fills, it is sorted in shared memory with a warp-wide bitonic
//     network and then merged with the current top-K via merge-path. This keeps the top-K
//     globally sorted, so the K-th distance is always cheap to read and can be used for pruning.
//
// No extra device allocations are performed; all scratch space is per-thread private state or
// per-block shared memory.
//
// The host entry point intentionally only launches the kernel on the default stream; it does not
// insert a device-wide synchronization so callers can pipeline it with other GPU work.

namespace {

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

// Runtime-tunable tile sizes. The launcher picks among these based on the selected
// warps-per-block and the device's opt-in shared-memory capacity.
//
// 2048 points is the conservative "keep at least 2 resident blocks if possible" tile.
// 4096 points is the preferred large tile when it does not hurt residency.
// 8192 points is only used when the kernel is already forced into a 1-block-per-SM regime;
// on H100-class parts it reduces refill/barrier overhead for the heaviest K values.
constexpr int kMinBatchPoints                  = 32;
constexpr int kPreferredBatchTwoBlockSmall     = 2048;
constexpr int kPreferredBatchTwoBlockLarge     = 4096;
constexpr int kPreferredBatchOneBlockHeavy     = 8192;

// Total-order comparator used by the sort/merge code.
// Distances are the primary key; index is a deterministic tiebreaker so merge-path partitions
// are unambiguous. The public API does not require any specific tie resolution.
__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ float squared_l2(float qx, float qy, float px, float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return fmaf(dx, dx, dy * dy);
}

// In-place bitonic sort of K (distance, index) pairs stored in shared memory.
// K is a power of two in [32, 1024]. One warp cooperatively sorts one buffer.
// The loops are intentionally kept rolled to avoid massive code growth for K=1024;
// merge events are relatively infrequent compared to the streaming distance phase.
template <int K>
__device__ __forceinline__ void warp_bitonic_sort_shared(float* dist, int* idx, int lane) {
    #pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll 1
            for (int i = lane; i < K; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const bool ascending = ((i & size) == 0);

                    const float di = dist[i];
                    const float dj = dist[j];
                    const int   ii = idx[i];
                    const int   ij = idx[j];

                    const bool do_swap =
                        ascending ? pair_less(dj, ij, di, ii)
                                  : pair_less(di, ii, dj, ij);

                    if (do_swap) {
                        dist[i] = dj;
                        idx[i]  = ij;
                        dist[j] = di;
                        idx[j]  = ii;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Merge-path partition for the first `diag` outputs of merge(A, B),
// where A and B are both length-K sorted arrays.
template <int K>
__device__ __forceinline__ int merge_path_partition(
    int diag,
    const float* a_dist, const int* a_idx,
    const float* b_dist, const int* b_idx)
{
    int lo = (diag > K) ? (diag - K) : 0;
    int hi = (diag < K) ? diag : K;

    while (lo < hi) {
        const int mid = (lo + hi) >> 1;
        const int j   = diag - mid;

        const bool move_right =
            (mid < K) && (j > 0) &&
            pair_less(a_dist[mid], a_idx[mid], b_dist[j - 1], b_idx[j - 1]);

        if (move_right) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    return lo;
}

// Merge the warp's candidate buffer with the current top-K.
//
// Inputs:
//   * top_dist/top_idx : warp-private current top-K, globally sorted across the warp
//   * s_cand_*         : shared-memory candidate buffer for this warp
//   * s_top_*          : shared-memory temporary copy of the current top-K
//
// Output:
//   * top_dist/top_idx updated in place to the new top-K, still globally sorted
//   * return value is the new K-th distance, broadcast from lane 31
template <int K>
__device__ __forceinline__ float merge_buffer_warp(
    float (&top_dist)[K / kWarpSize],
    int   (&top_idx )[K / kWarpSize],
    float* s_cand_dist, int* s_cand_idx,
    float* s_top_dist,  int* s_top_idx,
    int candidate_count,
    int lane)
{
    constexpr int kItemsPerThread = K / kWarpSize;

    // Ensure all previous candidate writes are visible within the warp.
    __syncwarp(kFullMask);

    // Copy the current top-K from warp-private storage to shared memory so every lane can
    // access it randomly during merge-path partitioning and merging.
    #pragma unroll
    for (int i = 0; i < kItemsPerThread; ++i) {
        const int pos = lane * kItemsPerThread + i;
        s_top_dist[pos] = top_dist[i];
        s_top_idx [pos] = top_idx [i];
    }

    // Pad the inactive tail of the candidate buffer with sentinels so the sort can always
    // run on a full power-of-two array.
    for (int pos = candidate_count + lane; pos < K; pos += kWarpSize) {
        s_cand_dist[pos] = CUDART_INF_F;
        s_cand_idx [pos] = -1;
    }

    __syncwarp(kFullMask);

    // Sort candidates ascending by (distance, index).
    warp_bitonic_sort_shared<K>(s_cand_dist, s_cand_idx, lane);

    // Each lane merges a contiguous stripe of size K/32 from the first K outputs.
    const int diag = lane * kItemsPerThread;
    int a = merge_path_partition<K>(diag, s_top_dist, s_top_idx, s_cand_dist, s_cand_idx);
    int b = diag - a;

    #pragma unroll
    for (int i = 0; i < kItemsPerThread; ++i) {
        const bool take_a =
            (a < K) &&
            ((b >= K) || !pair_less(s_cand_dist[b], s_cand_idx[b], s_top_dist[a], s_top_idx[a]));

        if (take_a) {
            top_dist[i] = s_top_dist[a];
            top_idx [i] = s_top_idx [a];
            ++a;
        } else {
            top_dist[i] = s_cand_dist[b];
            top_idx [i] = s_cand_idx [b];
            ++b;
        }
    }

    // Lane 31 owns the last global slot of the distributed top-K.
    return __shfl_sync(kFullMask, top_dist[kItemsPerThread - 1], 31);
}

template <int K, int WARPS_PER_BLOCK>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result,
    int batch_points)
{
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024]");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size");
    static_assert(WARPS_PER_BLOCK >= 1 && WARPS_PER_BLOCK <= 32, "Invalid warps-per-block");
    static_assert(WARPS_PER_BLOCK * kWarpSize <= 1024, "Block is too large");

    constexpr int kItemsPerThread = K / kWarpSize;

    const int tid  = threadIdx.x;
    const int lane = tid & (kWarpSize - 1);
    const int warp = tid >> 5;

    const int block_query_base = blockIdx.x * WARPS_PER_BLOCK;
    if (block_query_base >= query_count) {
        return;
    }

    const int query_idx = block_query_base + warp;
    const bool active   = (query_idx < query_count);

    // Shared-memory layout:
    //   [cand_dist][cand_idx][top_dist_tmp][top_idx_tmp][tile_x][tile_y]
    extern __shared__ int shared_i32[];
    unsigned char* shared_ptr = reinterpret_cast<unsigned char*>(shared_i32);

    float* s_cand_dist_all = reinterpret_cast<float*>(shared_ptr);
    shared_ptr += static_cast<size_t>(WARPS_PER_BLOCK) * K * sizeof(float);

    int* s_cand_idx_all = reinterpret_cast<int*>(shared_ptr);
    shared_ptr += static_cast<size_t>(WARPS_PER_BLOCK) * K * sizeof(int);

    float* s_top_dist_all = reinterpret_cast<float*>(shared_ptr);
    shared_ptr += static_cast<size_t>(WARPS_PER_BLOCK) * K * sizeof(float);

    int* s_top_idx_all = reinterpret_cast<int*>(shared_ptr);
    shared_ptr += static_cast<size_t>(WARPS_PER_BLOCK) * K * sizeof(int);

    float* s_tile_x = reinterpret_cast<float*>(shared_ptr);
    shared_ptr += static_cast<size_t>(batch_points) * sizeof(float);

    float* s_tile_y = reinterpret_cast<float*>(shared_ptr);

    const int warp_offset = warp * K;

    float* s_cand_dist = s_cand_dist_all + warp_offset;
    int*   s_cand_idx  = s_cand_idx_all  + warp_offset;
    float* s_top_dist  = s_top_dist_all  + warp_offset;
    int*   s_top_idx   = s_top_idx_all   + warp_offset;

    // One query is loaded once per warp and broadcast via shuffles.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Warp-private current top-K. These arrays are the "private copy" requested by the prompt.
    // The global order is:
    //   lane 0 owns ranks [0, K/32),
    //   lane 1 owns ranks [K/32, 2*K/32), ...
    float top_dist[kItemsPerThread];
    int   top_idx [kItemsPerThread];

    #pragma unroll
    for (int i = 0; i < kItemsPerThread; ++i) {
        top_dist[i] = CUDART_INF_F;
        top_idx [i] = -1;
    }

    float kth = CUDART_INF_F;
    int buffer_count = 0;

    // Stream over the data set in shared-memory tiles.
    for (int batch_start = 0; batch_start < data_count; batch_start += batch_points) {
        int batch_count = data_count - batch_start;
        if (batch_count > batch_points) {
            batch_count = batch_points;
        }

        // Cooperative block load into shared memory.
        for (int i = tid; i < batch_count; i += blockDim.x) {
            const float2 p = data[batch_start + i];
            s_tile_x[i] = p.x;
            s_tile_y[i] = p.y;
        }

        __syncthreads();

        if (active) {
            // All 32 lanes must participate in every ballot. Therefore the loop is organized
            // in warp-sized rounds with explicit bounds checks for the tail.
            for (int base = 0; base < batch_count; base += kWarpSize) {
                const int off = base + lane;

                float dist = CUDART_INF_F;
                int   idx  = -1;
                bool  keep = false;

                if (off < batch_count) {
                    const float px = s_tile_x[off];
                    const float py = s_tile_y[off];
                    dist = squared_l2(qx, qy, px, py);
                    idx  = batch_start + off;

                    // Strictly closer than the current K-th neighbor; ties can be dropped.
                    keep = (dist < kth);
                }

                unsigned mask = __ballot_sync(kFullMask, keep);
                int num = __popc(mask);

                if (num) {
                    // If this round would overflow the shared candidate buffer, first merge
                    // the existing buffered candidates into the current top-K.
                    if (buffer_count + num > K) {
                        kth = merge_buffer_warp<K>(
                            top_dist, top_idx,
                            s_cand_dist, s_cand_idx,
                            s_top_dist, s_top_idx,
                            buffer_count, lane);
                        buffer_count = 0;

                        // Re-evaluate the current round under the tightened threshold.
                        keep = (off < batch_count) && (dist < kth);
                        mask = __ballot_sync(kFullMask, keep);
                        num  = __popc(mask);
                    }

                    if (num) {
                        if (keep) {
                            const unsigned lower_mask = (1u << lane) - 1u;
                            const int rank = __popc(mask & lower_mask);
                            s_cand_dist[buffer_count + rank] = dist;
                            s_cand_idx [buffer_count + rank] = idx;
                        }

                        buffer_count += num;

                        // Merge immediately when the buffer reaches K candidates.
                        if (buffer_count == K) {
                            kth = merge_buffer_warp<K>(
                                top_dist, top_idx,
                                s_cand_dist, s_cand_idx,
                                s_top_dist, s_top_idx,
                                buffer_count, lane);
                            buffer_count = 0;
                        }
                    }
                }
            }
        }

        // The whole block must finish reading the staged tile before it is overwritten.
        __syncthreads();
    }

    if (active) {
        if (buffer_count > 0) {
            kth = merge_buffer_warp<K>(
                top_dist, top_idx,
                s_cand_dist, s_cand_idx,
                s_top_dist, s_top_idx,
                buffer_count, lane);
            (void)kth;
        }

        // Write the final globally sorted top-K for this query.
        const size_t out_base =
            static_cast<size_t>(query_idx) * static_cast<size_t>(K) +
            static_cast<size_t>(lane) * static_cast<size_t>(kItemsPerThread);

        #pragma unroll
        for (int i = 0; i < kItemsPerThread; ++i) {
            result[out_base + i].first  = top_idx[i];
            result[out_base + i].second = top_dist[i];
        }
    }
}

inline int ceil_div_int(int a, int b) {
    return (a + b - 1) / b;
}

// Shared bytes for one warp/query:
//   candidate buffer: K * (float + int)
//   merge temp copy : K * (float + int)
// Total = 2 * K * (4 + 4) = 16 * K bytes.
inline size_t fixed_shared_bytes_runtime(int k, int warps_per_block) {
    return static_cast<size_t>(k) * static_cast<size_t>(warps_per_block) * 16u;
}

template <int K, int WARPS_PER_BLOCK>
inline size_t dynamic_shared_bytes(int batch_points) {
    return static_cast<size_t>(K) * static_cast<size_t>(WARPS_PER_BLOCK) * 16u +
           static_cast<size_t>(batch_points) * 2u * sizeof(float);
}

// Warps-per-block selection heuristic:
//
// We want as many query-warps in a block as possible because staged data is reused by every warp,
// but we also do not want the grid to become so small that it under-fills the SMs.
// Because each block scans the entire data set, blocks are long-lived, so "at least ~1 block per SM
// in the grid" is a good target; going far beyond that is less important than reuse.
//
// Candidate warp counts are powers of two. The heavy K values are capped by shared-memory usage.
inline int choose_warps_per_block(int k, int query_count, int sm_count, int max_dynamic_smem) {
    const int candidates[] = {32, 16, 8, 4};
    const int max_w =
        (k <= 256) ? 32 :
        (k == 512) ? 16 :
                     8;

    int chosen = 0;

    for (int i = 0; i < 4; ++i) {
        const int w = candidates[i];
        if (w > max_w) {
            continue;
        }

        // Require enough space for at least a minimal data tile.
        const size_t fixed = fixed_shared_bytes_runtime(k, w);
        const size_t min_total =
            fixed + static_cast<size_t>(kMinBatchPoints) * 2u * sizeof(float);

        if (min_total > static_cast<size_t>(max_dynamic_smem)) {
            continue;
        }

        chosen = w;

        // Prefer the largest warp count that still yields at least ~one block per SM.
        if (ceil_div_int(query_count, w) >= sm_count) {
            return w;
        }
    }

    return chosen;
}

// Batch-size selection heuristic:
//
// 1) If a 4096-point tile still allows >= 2 resident blocks by shared memory, use 4096.
// 2) Else if 2048 still allows >= 2 resident blocks, use 2048.
// 3) Else the kernel is already effectively in a 1-block-per-SM regime, so use a deeper tile
//    (up to 8192, clamped by device shared memory). This mainly helps the large-K cases on H100.
//
// This strikes a balance between fewer barriers/refills and not over-allocating shared memory
// on lighter kernels where extra occupancy still matters.
inline int choose_batch_points(int k, int warps_per_block, int max_dynamic_smem) {
    const size_t fixed    = fixed_shared_bytes_runtime(k, warps_per_block);
    const size_t max_smem = static_cast<size_t>(max_dynamic_smem);

    if (fixed + static_cast<size_t>(kMinBatchPoints) * 2u * sizeof(float) > max_smem) {
        return 0;
    }

    const int max_fit =
        static_cast<int>((max_smem - fixed) / (2u * sizeof(float)));

    const size_t bytes_2048 =
        fixed + static_cast<size_t>(kPreferredBatchTwoBlockSmall) * 2u * sizeof(float);
    const size_t bytes_4096 =
        fixed + static_cast<size_t>(kPreferredBatchTwoBlockLarge) * 2u * sizeof(float);

    int preferred = 0;
    if (bytes_4096 <= max_smem && (max_smem / bytes_4096) >= 2u) {
        preferred = kPreferredBatchTwoBlockLarge;
    } else if (bytes_2048 <= max_smem && (max_smem / bytes_2048) >= 2u) {
        preferred = kPreferredBatchTwoBlockSmall;
    } else {
        preferred = kPreferredBatchOneBlockHeavy;
    }

    int batch_points = preferred;
    if (batch_points > max_fit) {
        batch_points = max_fit;
    }

    // Keep the warp-round inner loop aligned.
    batch_points &= ~31;

    if (batch_points < kMinBatchPoints) {
        batch_points = kMinBatchPoints;
    }

    return batch_points;
}

template <int K, int WARPS_PER_BLOCK>
inline void launch_knn_specialized(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int batch_points)
{
    const size_t smem_bytes = dynamic_shared_bytes<K, WARPS_PER_BLOCK>(batch_points);

    // Opt in to large dynamic shared-memory allocations on Ampere/Hopper.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));

    // Heavily shared-memory-centric kernel: bias the carveout toward shared memory.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks  = ceil_div_int(query_count, WARPS_PER_BLOCK);
    const int threads = WARPS_PER_BLOCK * kWarpSize;

    knn_kernel<K, WARPS_PER_BLOCK><<<blocks, threads, smem_bytes>>>(
        query, query_count, data, data_count, result, batch_points);

    // Preserve CUDA's usual async execution model while still surfacing launch failures.
    (void)cudaPeekAtLastError();
}

template <int K>
inline void dispatch_warps_up_to_32(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int warps_per_block,
    int batch_points)
{
    switch (warps_per_block) {
        case 32:
            launch_knn_specialized<K, 32>(query, query_count, data, data_count, result, batch_points);
            break;
        case 16:
            launch_knn_specialized<K, 16>(query, query_count, data, data_count, result, batch_points);
            break;
        case 8:
            launch_knn_specialized<K, 8>(query, query_count, data, data_count, result, batch_points);
            break;
        default:
            launch_knn_specialized<K, 4>(query, query_count, data, data_count, result, batch_points);
            break;
    }
}

template <int K>
inline void dispatch_warps_up_to_16(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int warps_per_block,
    int batch_points)
{
    switch (warps_per_block) {
        case 16:
            launch_knn_specialized<K, 16>(query, query_count, data, data_count, result, batch_points);
            break;
        case 8:
            launch_knn_specialized<K, 8>(query, query_count, data, data_count, result, batch_points);
            break;
        default:
            launch_knn_specialized<K, 4>(query, query_count, data, data_count, result, batch_points);
            break;
    }
}

template <int K>
inline void dispatch_warps_up_to_8(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int warps_per_block,
    int batch_points)
{
    switch (warps_per_block) {
        case 8:
            launch_knn_specialized<K, 8>(query, query_count, data, data_count, result, batch_points);
            break;
        default:
            launch_knn_specialized<K, 4>(query, query_count, data, data_count, result, batch_points);
            break;
    }
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    (void)cudaGetDevice(&device);

    int sm_count = 0;
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count <= 0) {
        sm_count = 1;
    }

    int max_dynamic_smem = 0;
    (void)cudaDeviceGetAttribute(&max_dynamic_smem, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);
    if (max_dynamic_smem <= 0) {
        (void)cudaDeviceGetAttribute(&max_dynamic_smem, cudaDevAttrMaxSharedMemoryPerBlock, device);
    }
    if (max_dynamic_smem <= 0) {
        max_dynamic_smem = 48 * 1024;
    }

    const int warps_per_block = choose_warps_per_block(k, query_count, sm_count, max_dynamic_smem);
    if (warps_per_block == 0) {
        return;
    }

    const int batch_points = choose_batch_points(k, warps_per_block, max_dynamic_smem);
    if (batch_points == 0) {
        return;
    }

    switch (k) {
        case 32:
            dispatch_warps_up_to_32<32>(query, query_count, data, data_count, result, warps_per_block, batch_points);
            break;
        case 64:
            dispatch_warps_up_to_32<64>(query, query_count, data, data_count, result, warps_per_block, batch_points);
            break;
        case 128:
            dispatch_warps_up_to_32<128>(query, query_count, data, data_count, result, warps_per_block, batch_points);
            break;
        case 256:
            dispatch_warps_up_to_32<256>(query, query_count, data, data_count, result, warps_per_block, batch_points);
            break;
        case 512:
            dispatch_warps_up_to_16<512>(query, query_count, data, data_count, result, warps_per_block, batch_points);
            break;
        case 1024:
            dispatch_warps_up_to_8<1024>(query, query_count, data, data_count, result, warps_per_block, batch_points);
            break;
        default:
            // The prompt guarantees valid K, so this path is only a safety net.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>
#include <utility>

namespace {

using ResultPair = std::pair<int, float>;

// Tuned for A100/H100-class GPUs as requested.
// - 256 threads/block = 8 warps/block, one query per warp.
// - 4096-point shared-memory data tile.
//   For K=1024, the per-warp top-k state plus the tile uses exactly 160 KiB,
//   i.e. A100's opt-in per-block dynamic shared-memory limit.
constexpr int kWarpSize       = 32;
constexpr int kWarpsPerBlock  = 8;
constexpr int kThreadsPerBlock = kWarpSize * kWarpsPerBlock;
constexpr int kBatchPoints    = 4096;
constexpr unsigned kFullMask  = 0xFFFFFFFFu;

// Packed (distance, index) key layout:
//   high 32 bits : IEEE-754 bits of non-negative squared distance
//   low  32 bits : unsigned representation of the point index
// Squared Euclidean distances are non-negative, so unsigned integer ordering on the
// high word matches numeric float ordering. This lets the merge path compare one
// 64-bit key instead of separate (distance, index) fields.
constexpr uint64_t kPackedInf = (uint64_t{0x7F800000u} << 32) | 0xFFFFFFFFu;

static_assert(kBatchPoints % kWarpSize == 0, "Batch size must be a multiple of warp size.");

template <int K>
constexpr std::size_t shared_bytes_for_k() {
    return static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(2 * K) * sizeof(uint64_t) +
           static_cast<std::size_t>(2 * kBatchPoints) * sizeof(float);
}

static_assert(shared_bytes_for_k<1024>() == 160u * 1024u,
              "Worst-case K=1024 variant must fit A100's 160 KiB opt-in shared memory.");

__device__ __forceinline__ uint64_t pack_key(const float dist, const int idx) {
    return (static_cast<uint64_t>(__float_as_uint(dist)) << 32) |
           static_cast<uint32_t>(idx);
}

__device__ __forceinline__ float unpack_dist(const uint64_t key) {
    return __uint_as_float(static_cast<uint32_t>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(const uint64_t key) {
    return static_cast<int>(static_cast<uint32_t>(key));
}

// One warp sorts its own 2*K packed keys in shared memory.
// Loops are intentionally kept rolled to avoid massive code size for the 2048-element case.
template <int N>
__device__ __forceinline__ void warp_bitonic_sort(uint64_t* keys) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    #pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += kWarpSize) {
                const int ixj = i ^ stride;
                if (ixj > i) {
                    const uint64_t a = keys[i];
                    const uint64_t b = keys[ixj];
                    const bool ascending = ((i & size) == 0);
                    if (ascending ? (a > b) : (a < b)) {
                        keys[i] = b;
                        keys[ixj] = a;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Merge the current intermediate result [0, K) with the candidate buffer [K, 2K).
// If the candidate buffer is only partially filled, pad the unused tail with +inf so the
// same 2*K network handles both full and partial merges.
template <int K>
__device__ __forceinline__ void merge_candidates(uint64_t* warp_keys, int& cand_count, float& kth_dist) {
    if (cand_count == 0) return;

    const int lane = threadIdx.x & (kWarpSize - 1);

    // Ensure all prior candidate writes are visible to the warp before sorting.
    __syncwarp(kFullMask);

    if (cand_count < K) {
        #pragma unroll
        for (int pos = K + cand_count + lane; pos < 2 * K; pos += kWarpSize) {
            warp_keys[pos] = kPackedInf;
        }
    }

    __syncwarp(kFullMask);
    warp_bitonic_sort<2 * K>(warp_keys);

    float new_kth = CUDART_INF_F;
    if (lane == 0) {
        new_kth = unpack_dist(warp_keys[K - 1]);
    }
    kth_dist = __shfl_sync(kFullMask, new_kth, 0);
    cand_count = 0;
}

template <int K>
__global__ __launch_bounds__(kThreadsPerBlock)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                ResultPair* __restrict__ result) {
    extern __shared__ __align__(16) unsigned char smem_raw[];

    // Shared-memory layout:
    //   topk_keys: 8 warps * (2*K packed keys/warp)
    //     [0, K)  : warp-private intermediate top-k result
    //     [K, 2K) : warp-private candidate buffer
    //   batch_x / batch_y: block-wide cached data tile in SoA layout
    //
    // Using SoA for the cached data tile avoids the 2-way bank conflicts that would arise
    // if consecutive lanes read consecutive float2 values directly from shared memory.
    uint64_t* const topk_keys = reinterpret_cast<uint64_t*>(smem_raw);
    float* const batch_x = reinterpret_cast<float*>(topk_keys + kWarpsPerBlock * (2 * K));
    float* const batch_y = batch_x + kBatchPoints;

    const int tid      = threadIdx.x;
    const int lane     = tid & (kWarpSize - 1);
    const int warp     = tid >> 5;
    const int query_idx = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp;
    const bool active  = (query_idx < query_count);

    uint64_t* const warp_keys = topk_keys + warp * (2 * K);

    // The prompt asks for a private copy of the intermediate top-k per query.
    // Here it is a warp-private shared-memory region; this avoids local-memory spills
    // when K is as large as 1024.
    if (active) {
        #pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            warp_keys[i] = kPackedInf;
        }
    }

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    int cand_count = 0;
    float kth_dist = CUDART_INF_F;

    for (int batch_start = 0; batch_start < data_count; batch_start += kBatchPoints) {
        int batch_count = data_count - batch_start;
        if (batch_count > kBatchPoints) batch_count = kBatchPoints;

        // Whole block cooperatively loads the next data tile into shared memory.
        for (int i = tid; i < batch_count; i += kThreadsPerBlock) {
            const float2 p = data[batch_start + i];
            batch_x[i] = p.x;
            batch_y[i] = p.y;
        }
        __syncthreads();

        if (active) {
            // Warp processes the tile 32 points at a time so ballot+prefix can compact
            // accepted candidates into the shared candidate buffer.
            for (int tile = 0; tile < batch_count; tile += kWarpSize) {
                const int point = tile + lane;
                const bool valid = (point < batch_count);

                float dist = CUDART_INF_F;
                int idx = -1;
                if (valid) {
                    const float dx = qx - batch_x[point];
                    const float dy = qy - batch_y[point];
                    dist = __fmaf_rn(dx, dx, dy * dy);
                    idx = batch_start + point;
                }

                bool accept = valid && (dist < kth_dist);
                unsigned mask = __ballot_sync(kFullMask, accept);
                int n_accept = __popc(mask);

                // The warp discovers up to 32 candidates at once. If appending the whole set
                // would overflow the K-sized candidate buffer, merge the current buffer first,
                // tighten the threshold, and then re-test the just computed distances.
                if (cand_count + n_accept > K) {
                    merge_candidates<K>(warp_keys, cand_count, kth_dist);

                    accept = valid && (dist < kth_dist);
                    mask = __ballot_sync(kFullMask, accept);
                    n_accept = __popc(mask);
                }

                if (accept) {
                    const unsigned prior_lanes = (lane == 0) ? 0u : ((1u << lane) - 1u);
                    const int rank = __popc(mask & prior_lanes);
                    warp_keys[K + cand_count + rank] = pack_key(dist, idx);
                }

                cand_count += n_accept;

                // Immediate merge as soon as the candidate buffer becomes full.
                if (cand_count == K) {
                    merge_candidates<K>(warp_keys, cand_count, kth_dist);
                }
            }
        }

        // No warp may start overwriting the shared data tile for the next batch until all
        // warps are done reading the current tile.
        __syncthreads();
    }

    if (active) {
        // Final partial merge after the last cached batch.
        merge_candidates<K>(warp_keys, cand_count, kth_dist);

        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            const uint64_t key = warp_keys[i];
            // Write fields separately to avoid relying on any device-side std::pair
            // constructors or assignment operators.
            result[out_base + static_cast<std::size_t>(i)].first  = unpack_idx(key);
            result[out_base + static_cast<std::size_t>(i)].second = unpack_dist(key);
        }
    }
}

template <int K>
inline void launch_knn_specialized(const float2* query,
                                   const int query_count,
                                   const float2* data,
                                   const int data_count,
                                   ResultPair* result) {
    constexpr std::size_t smem_bytes = shared_bytes_for_k<K>();

    // This kernel is intentionally shared-memory heavy. Request the full dynamic shared-memory
    // budget and bias the SM carveout toward shared memory on A100/H100-class devices.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(kThreadsPerBlock);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);
    knn_kernel<K><<<grid, block, smem_bytes>>>(query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Dispatch to one of the six legal K specializations so K is compile-time constant inside
    // the hot loop and inside the merge network.
    switch (k) {
        case 32:
            launch_knn_specialized<32>(query, query_count, data, data_count, result);
            return;
        case 64:
            launch_knn_specialized<64>(query, query_count, data, data_count, result);
            return;
        case 128:
            launch_knn_specialized<128>(query, query_count, data, data_count, result);
            return;
        case 256:
            launch_knn_specialized<256>(query, query_count, data, data_count, result);
            return;
        case 512:
            launch_knn_specialized<512>(query, query_count, data, data_count, result);
            return;
        case 1024:
            launch_knn_specialized<1024>(query, query_count, data, data_count, result);
            return;
        default:
            return;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>
#include <utility>

namespace {

// One warp processes one query. A 256-thread block therefore handles 8 queries at once,
// which gives a good balance between occupancy and reuse of the shared-memory data batch.
constexpr int kWarpSize       = 32;
constexpr int kBlockThreads   = 256;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr unsigned kFullMask  = 0xffffffffu;

// Packed sortable key:
//   high 32 bits = IEEE-754 bits of the non-negative squared distance
//   low  32 bits = data index
//
// For non-negative floats, unsigned integer order matches floating-point order, so a single
// 64-bit integer comparison implements lexicographic ordering by (distance, index).
// This gives deterministic tie-breaking by smaller data index essentially for free.
using pair_key_t = unsigned long long;
constexpr pair_key_t kInfKey =
    (static_cast<pair_key_t>(0x7f800000u) << 32) | static_cast<pair_key_t>(0xffffffffu);

// Shared memory budget is tuned against A100's 163,840-byte opt-in shared-memory limit.
// H100 has more, so these choices also fit there.
constexpr std::size_t kA100MaxOptInShared = 163840u;

__device__ __forceinline__ pair_key_t pack_key(float dist, int idx) {
    return (static_cast<pair_key_t>(__float_as_uint(dist)) << 32) |
           static_cast<unsigned int>(idx);
}

__device__ __forceinline__ float unpack_dist(pair_key_t key) {
    return __uint_as_float(static_cast<unsigned int>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(pair_key_t key) {
    // Real indices are non-negative, but the sentinel 0xffffffff becomes -1 here,
    // which is a sensible "invalid" value if it ever escapes (it should not at the end).
    return static_cast<int>(static_cast<unsigned int>(key));
}

// In-place bitonic sort of K packed (distance, index) keys in shared memory.
// K is always a power of two in [32, 1024].
template <int K>
__device__ __forceinline__ void bitonic_sort_shared(pair_key_t* keys) {
    const int lane = threadIdx.x & (kWarpSize - 1);

    #pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll 1
            for (int pos = lane; pos < K; pos += kWarpSize) {
                const int partner = pos ^ stride;
                if (partner > pos) {
                    const bool ascending = ((pos & size) == 0);
                    pair_key_t a = keys[pos];
                    pair_key_t b = keys[partner];
                    if (ascending ? (b < a) : (a < b)) {
                        keys[pos]     = b;
                        keys[partner] = a;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Merge-path partition for two sorted arrays A and B of equal length K.
// Returns i such that A[0..i) and B[0..diag-i) contain exactly the first "diag" merged elements.
template <int K>
__device__ __forceinline__ int merge_path_partition(const pair_key_t* a,
                                                    const pair_key_t* b,
                                                    int diag) {
    int low  = (diag > K) ? (diag - K) : 0;
    int high = (diag < K) ? diag : K;

    while (low <= high) {
        const int i = (low + high) >> 1;
        const int j = diag - i;

        if (i > 0 && j < K && a[i - 1] > b[j]) {
            high = i - 1;
        } else if (j > 0 && i < K && b[j - 1] > a[i]) {
            low = i + 1;
        } else {
            return i;
        }
    }

    return low;
}

// Merge the shared-memory candidate buffer with the warp-private top-K result.
// The warp-private top-K lives distributed across lane-local registers:
// each lane owns K/32 consecutive sorted keys.
// During the merge, the current top-K is staged to shared memory so the warp can do
// random accesses for merge-path partitioning without any extra device allocations.
template <int K>
__device__ __forceinline__ void merge_buffer(pair_key_t (&top)[K / kWarpSize],
                                             pair_key_t* warp_store,
                                             int& buf_count,
                                             pair_key_t& kth_key) {
    constexpr int CHUNK = K / kWarpSize;

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int base = lane * CHUNK;

    pair_key_t* curr = warp_store;      // [0, K)   : staging area for current top-K
    pair_key_t* cand = warp_store + K;  // [K, 2K)  : candidate buffer

    // Stage the current top-K into shared memory.
    #pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        curr[base + t] = top[t];
    }

    // Pad the unused tail of the candidate buffer with +inf so we can sort exactly K elements.
    #pragma unroll
    for (int pos = lane; pos < K; pos += kWarpSize) {
        if (pos >= buf_count) {
            cand[pos] = kInfKey;
        }
    }

    __syncwarp(kFullMask);

    // Sort only the candidate side; the current top-K is already sorted.
    bitonic_sort_shared<K>(cand);

    // Parallel merge of two sorted K-element lists. Each lane writes its own CHUNK outputs
    // directly back into its register-resident "top" segment.
    const int diag = base;
    int ai = merge_path_partition<K>(curr, cand, diag);
    int bi = diag - ai;

    #pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        const pair_key_t av = (ai < K) ? curr[ai] : kInfKey;
        const pair_key_t bv = (bi < K) ? cand[bi] : kInfKey;
        const bool take_a = (av <= bv);
        top[t] = take_a ? av : bv;
        ai += static_cast<int>(take_a);
        bi += static_cast<int>(!take_a);
    }

    buf_count = 0;

    // The final (K-1)-th key is owned by lane 31, local slot CHUNK-1.
    kth_key = __shfl_sync(kFullMask, top[CHUNK - 1], 31);
}

template <int K, int DATA_BATCH>
__global__ __launch_bounds__(kBlockThreads)
void knn2d_kernel(const float2* __restrict__ query,
                  int query_count,
                  const float2* __restrict__ data,
                  int data_count,
                  std::pair<int, float>* __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    static_assert((DATA_BATCH % kWarpSize) == 0, "Batch size must be a multiple of warp size.");

    constexpr int CHUNK = K / kWarpSize;

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int q_idx   = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active = (q_idx < query_count);

    // Shared-memory layout:
    //   sh_data[DATA_BATCH]                            : cached data points for the current batch
    //   sh_keys[kWarpsPerBlock * 2 * K]              : per-warp [current-top staging | candidate buffer]
    extern __shared__ float2 shmem[];
    float2* sh_data = shmem;
    pair_key_t* sh_keys = reinterpret_cast<pair_key_t*>(sh_data + DATA_BATCH);
    pair_key_t* warp_store = sh_keys + static_cast<std::size_t>(warp_id) * (2 * K);
    pair_key_t* cand = warp_store + K;

    // Warp-private intermediate result: each lane keeps CHUNK consecutive sorted entries.
    pair_key_t top[CHUNK];
    #pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        top[t] = kInfKey;
    }

    pair_key_t kth_key = kInfKey;
    int buf_count = 0;  // Uniform across the warp.

    // Load the query point once and broadcast it across the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[q_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Scan the database in shared-memory batches.
    for (int batch_begin = 0; batch_begin < data_count; batch_begin += DATA_BATCH) {
        const int remaining  = data_count - batch_begin;
        const int batch_size = (remaining < DATA_BATCH) ? remaining : DATA_BATCH;
        const float2* batch_ptr = data + batch_begin;

        // Cooperative block-wide load into shared memory.
        for (int i = threadIdx.x; i < batch_size; i += kBlockThreads) {
            sh_data[i] = batch_ptr[i];
        }
        __syncthreads();

        if (active) {
            // Each 32-point step maps naturally to one warp iteration:
            // lane t evaluates the t-th point in the step.
            #pragma unroll 1
            for (int base = 0; base < batch_size; base += kWarpSize) {
                const int step_remaining = batch_size - base;
                const int step_capacity  = (step_remaining < kWarpSize) ? step_remaining : kWarpSize;

                // To avoid a spill path for a partially full buffer, merge slightly early when
                // fewer than "step_capacity" slots remain. This is exact and usually beneficial:
                // it tightens the threshold sooner and therefore increases skipping.
                if (buf_count > K - step_capacity) {
                    merge_buffer<K>(top, warp_store, buf_count, kth_key);
                }

                const int local_idx = base + lane;

                pair_key_t candidate_key = kInfKey;
                bool keep = false;

                if (local_idx < batch_size) {
                    const float2 p = sh_data[local_idx];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    const float dist = fmaf(dx, dx, dy * dy);
                    candidate_key = pack_key(dist, batch_begin + local_idx);

                    // Skip anything that is not better than the current K-th best entry.
                    keep = (candidate_key < kth_key);
                }

                const unsigned mask = __ballot_sync(kFullMask, keep);
                const int num_kept = __popc(mask);

                if (keep) {
                    const unsigned lower = mask & ((1u << lane) - 1u);
                    const int rank = __popc(lower);
                    cand[buf_count + rank] = candidate_key;
                }

                buf_count += num_kept;

                // Exact "buffer full" merge.
                if (buf_count == K) {
                    merge_buffer<K>(top, warp_store, buf_count, kth_key);
                }
            }
        }

        // No need for a trailing barrier after the last batch.
        if (batch_begin + batch_size < data_count) {
            __syncthreads();
        }
    }

    if (active) {
        // Final partial-buffer merge, if any candidates remain.
        if (buf_count > 0) {
            merge_buffer<K>(top, warp_store, buf_count, kth_key);
        }

        // Write the sorted top-K for this query.
        std::pair<int, float>* out = result + static_cast<std::size_t>(q_idx) * K;
        const int base = lane * CHUNK;

        #pragma unroll
        for (int t = 0; t < CHUNK; ++t) {
            const pair_key_t key = top[t];
            out[base + t].first  = unpack_idx(key);
            out[base + t].second = unpack_dist(key);
        }
    }
}

template <int K, int DATA_BATCH>
void launch_knn_impl(const float2* query,
                     int query_count,
                     const float2* data,
                     int data_count,
                     std::pair<int, float>* result) {
    constexpr std::size_t shared_bytes =
        static_cast<std::size_t>(DATA_BATCH) * sizeof(float2) +
        static_cast<std::size_t>(kWarpsPerBlock) * 2ull * static_cast<std::size_t>(K) * sizeof(pair_key_t);

    static_assert(shared_bytes <= kA100MaxOptInShared,
                  "Chosen kernel configuration exceeds the A100 opt-in shared-memory limit.");

    // Opt in to the large shared-memory carveout needed by the tuned batch sizes.
    cudaFuncSetAttribute(knn2d_kernel<K, DATA_BATCH>,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         static_cast<int>(shared_bytes));
    cudaFuncSetAttribute(knn2d_kernel<K, DATA_BATCH>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;
    knn2d_kernel<K, DATA_BATCH><<<blocks, kBlockThreads, shared_bytes>>>(
        query, query_count, data, data_count, result);
}

}  // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Batch-size tuning:
    //   K = 32/64/128 : 8192-point batches keep 2 resident blocks/SM on A100.
    //   K = 256       : 4096-point batches keep 2 resident blocks/SM.
    //   K = 512       : 2048-point batches are the largest power-of-two choice that still keeps 2 blocks/SM.
    //   K = 1024      : occupancy is 1 block/SM regardless, so use 4096 points; this exactly matches
    //                   the A100 163,840-byte opt-in shared-memory limit.
    switch (k) {
        case 32:   launch_knn_impl<32,   8192>(query, query_count, data, data_count, result); break;
        case 64:   launch_knn_impl<64,   8192>(query, query_count, data, data_count, result); break;
        case 128:  launch_knn_impl<128,  8192>(query, query_count, data, data_count, result); break;
        case 256:  launch_knn_impl<256,  4096>(query, query_count, data, data_count, result); break;
        case 512:  launch_knn_impl<512,  2048>(query, query_count, data, data_count, result); break;
        case 1024: launch_knn_impl<1024, 4096>(query, query_count, data, data_count, result); break;
        default:   break;  // Per the problem statement, this path is unreachable.
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

// Exact warp-per-query 2D k-NN.
//
// High-level structure:
// - One warp owns one query.
// - The block cooperatively loads a 2048-point tile from global memory into shared memory.
//   The tile is reused by several queries at once, reducing global traffic.
// - The current top-k for each query is kept privately by the owning warp in registers.
//   The list is distributed in a striped layout:
//       logical_position = local_slot * 32 + lane
//   This is important because it turns every bitonic-network stride into one of two cheap cases:
//     * stride < 32  -> partner is in another lane, same local slot  -> use warp shuffles
//     * stride >= 32 -> partner is in the same lane, another slot    -> pure local exchange
// - Candidates that beat the current k-th distance are appended into a per-warp shared-memory buffer.
// - Whenever that buffer fills, it is merged with the private top-k:
//     1) sort the candidate buffer in shared memory with a warp-local bitonic sort
//     2) apply a "half-cleaner" against the current sorted top-k by comparing top[p] with cand[k-1-p]
//     3) bitonic-merge the resulting bitonic sequence back into a sorted top-k
//   This avoids materializing a 2k temporary array.
// - Distances are squared Euclidean distances, exactly as requested.
//
// Tuning notes for A100/H100-class GPUs:
// - 2048 points/tile = 16 KiB shared memory for the input tile (stored as SoA x[] and y[]).
// - With this tile size:
//     * K=512  and 16 warps/block -> ~80 KiB/block
//     * K=1024 and  8 warps/block -> ~80 KiB/block
//   Both fit two resident blocks/SM on modern data-center GPUs when opt-in shared memory is enabled.
// - The launch policy below picks the largest queries-per-block that still leaves enough blocks to
//   keep SMs busy for the given query count.

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xffffffffu;
constexpr int kDataTilePoints = 2048;

static_assert((kDataTilePoints % kWarpSize) == 0, "The shared-memory tile must be a multiple of warp size.");
static_assert(kDataTilePoints >= 1024, "The first tile must be able to seed the largest supported K.");

// Total order for the sorting network.
// The prompt does not constrain tie handling, but a deterministic total order is convenient.
__device__ __forceinline__ bool pair_less(const float da, const int ia, const float db, const int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ void swap_pair(float &ad, int &ai, float &bd, int &bi) {
    const float td = ad; ad = bd; bd = td;
    const int   ti = ai; ai = bi; bi = ti;
}

__device__ __forceinline__ float squared_l2(const float qx, const float qy,
                                            const float px, const float py) {
    const float dx = px - qx;
    const float dy = py - qy;
    return fmaf(dx, dx, dy * dy);
}

// Full bitonic sort of K register-resident elements distributed across the warp in striped layout.
template <int K, int ITEMS_PER_THREAD>
__device__ __forceinline__
void bitonic_sort_striped_regs(float (&dist)[ITEMS_PER_THREAD],
                               int   (&idx )[ITEMS_PER_THREAD],
                               const int lane) {
#pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll
        for (int stride = (size >> 1); stride > 0; stride >>= 1) {
            if (stride < kWarpSize) {
                // Inter-lane exchange, same local slot.
#pragma unroll
                for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                    const int p = (t << 5) + lane;

                    const float other_d = __shfl_xor_sync(kFullMask, dist[t], stride);
                    const int   other_i = __shfl_xor_sync(kFullMask, idx [t], stride);

                    const bool low      = ((lane & stride) == 0);
                    const bool ascending = ((p & size) == 0);
                    const bool keep_min = (ascending == low);

                    if (keep_min) {
                        if (pair_less(other_d, other_i, dist[t], idx[t])) {
                            dist[t] = other_d;
                            idx [t] = other_i;
                        }
                    } else {
                        if (pair_less(dist[t], idx[t], other_d, other_i)) {
                            dist[t] = other_d;
                            idx [t] = other_i;
                        }
                    }
                }
            } else {
                // Intra-lane exchange between local slots.
                const int slot_xor = (stride >> 5);
#pragma unroll
                for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                    const int u = t ^ slot_xor;
                    if (t < u) {
                        const int p_low = (t << 5) + lane;
                        const bool ascending = ((p_low & size) == 0);

                        if (ascending) {
                            if (pair_less(dist[u], idx[u], dist[t], idx[t])) {
                                swap_pair(dist[t], idx[t], dist[u], idx[u]);
                            }
                        } else {
                            if (pair_less(dist[t], idx[t], dist[u], idx[u])) {
                                swap_pair(dist[t], idx[t], dist[u], idx[u]);
                            }
                        }
                    }
                }
            }
        }
    }
}

// Bitonic merge of a K-element bitonic sequence held in registers in striped layout.
// This is cheaper than a full sort and is used after the half-cleaner merge step.
template <int K, int ITEMS_PER_THREAD>
__device__ __forceinline__
void bitonic_merge_striped_regs(float (&dist)[ITEMS_PER_THREAD],
                                int   (&idx )[ITEMS_PER_THREAD],
                                const int lane) {
#pragma unroll
    for (int stride = (K >> 1); stride > 0; stride >>= 1) {
        if (stride < kWarpSize) {
            // Inter-lane exchange, same local slot.
#pragma unroll
            for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                const float other_d = __shfl_xor_sync(kFullMask, dist[t], stride);
                const int   other_i = __shfl_xor_sync(kFullMask, idx [t], stride);
                const bool low = ((lane & stride) == 0);

                if (low) {
                    if (pair_less(other_d, other_i, dist[t], idx[t])) {
                        dist[t] = other_d;
                        idx [t] = other_i;
                    }
                } else {
                    if (pair_less(dist[t], idx[t], other_d, other_i)) {
                        dist[t] = other_d;
                        idx [t] = other_i;
                    }
                }
            }
        } else {
            // Intra-lane exchange between local slots.
            const int slot_xor = (stride >> 5);
#pragma unroll
            for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                const int u = t ^ slot_xor;
                if (t < u) {
                    if (pair_less(dist[u], idx[u], dist[t], idx[t])) {
                        swap_pair(dist[t], idx[t], dist[u], idx[u]);
                    }
                }
            }
        }
    }
}

// Full bitonic sort of a K-element candidate buffer stored in shared memory in striped layout.
// Warp-local __syncwarp() barriers are sufficient because each warp owns a disjoint buffer.
template <int K>
__device__ __forceinline__
void bitonic_sort_striped_shared(float *dist,
                                 int   *idx,
                                 const int lane) {
    constexpr int ITEMS_PER_THREAD = K / kWarpSize;

#pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll
        for (int stride = (size >> 1); stride > 0; stride >>= 1) {
            if (stride < kWarpSize) {
                // Inter-lane exchange, same local slot.
#pragma unroll
                for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                    const int p = (t << 5) + lane;

                    float self_d = dist[p];
                    int   self_i = idx [p];

                    const float other_d = __shfl_xor_sync(kFullMask, self_d, stride);
                    const int   other_i = __shfl_xor_sync(kFullMask, self_i, stride);

                    const bool low       = ((lane & stride) == 0);
                    const bool ascending = ((p & size) == 0);
                    const bool keep_min  = (ascending == low);

                    if (keep_min) {
                        if (pair_less(other_d, other_i, self_d, self_i)) {
                            self_d = other_d;
                            self_i = other_i;
                        }
                    } else {
                        if (pair_less(self_d, self_i, other_d, other_i)) {
                            self_d = other_d;
                            self_i = other_i;
                        }
                    }

                    dist[p] = self_d;
                    idx [p] = self_i;
                }
            } else {
                // Intra-lane exchange between local slots.
                const int slot_xor = (stride >> 5);
#pragma unroll
                for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                    const int u = t ^ slot_xor;
                    if (t < u) {
                        const int p_low = (t << 5) + lane;
                        const int p_high = (u << 5) + lane;

                        float low_d  = dist[p_low];
                        int   low_i  = idx [p_low];
                        float high_d = dist[p_high];
                        int   high_i = idx [p_high];

                        const bool ascending = ((p_low & size) == 0);

                        if (ascending) {
                            if (pair_less(high_d, high_i, low_d, low_i)) {
                                dist[p_low ] = high_d;
                                idx [p_low ] = high_i;
                                dist[p_high] = low_d;
                                idx [p_high] = low_i;
                            }
                        } else {
                            if (pair_less(low_d, low_i, high_d, high_i)) {
                                dist[p_low ] = high_d;
                                idx [p_low ] = high_i;
                                dist[p_high] = low_d;
                                idx [p_high] = low_i;
                            }
                        }
                    }
                }
            }

            __syncwarp(kFullMask);
        }
    }
}

// Merge the shared-memory candidate buffer into the register-resident top-k.
//
// The candidate buffer is first padded with +inf to length K and sorted.
// Then the "half-cleaner" compares top[p] with cand[K-1-p] (candidate list reversed).
// Keeping the smaller element in top[p] yields a K-element bitonic sequence that already
// contains the K smallest elements of the 2K union. A final bitonic merge sorts it.
template <int K, int ITEMS_PER_THREAD>
__device__ __forceinline__
float merge_candidate_buffer(float (&top_dist)[ITEMS_PER_THREAD],
                             int   (&top_idx )[ITEMS_PER_THREAD],
                             float *cand_dist,
                             int   *cand_idx,
                             const int cand_count,
                             const int lane) {
    __syncwarp(kFullMask);

    // Pad the unused tail with +inf so that a partial final buffer can reuse the same full sort.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        const int p = (t << 5) + lane;
        if (p >= cand_count) {
            cand_dist[p] = CUDART_INF_F;
            cand_idx [p] = -1;
        }
    }

    __syncwarp(kFullMask);

    bitonic_sort_striped_shared<K>(cand_dist, cand_idx, lane);

    // Half-cleaner against the candidate sequence reversed.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        const int reversed_pos = ((ITEMS_PER_THREAD - 1 - t) << 5) + (31 - lane);
        const float d = cand_dist[reversed_pos];
        const int   i = cand_idx [reversed_pos];

        if (pair_less(d, i, top_dist[t], top_idx[t])) {
            top_dist[t] = d;
            top_idx [t] = i;
        }
    }

    bitonic_merge_striped_regs<K, ITEMS_PER_THREAD>(top_dist, top_idx, lane);

    // The last logical position is always owned by lane 31, last local slot.
    return __shfl_sync(kFullMask, top_dist[ITEMS_PER_THREAD - 1], 31);
}

template <int K, int BLOCK_WARPS>
__global__ __launch_bounds__(BLOCK_WARPS * kWarpSize, 2)
void knn_kernel(const float2 *__restrict__ query,
                const int query_count,
                const float2 *__restrict__ data,
                const int data_count,
                std::pair<int, float> *__restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "Unsupported K.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    static_assert(kDataTilePoints >= K, "The first shared-memory tile must cover the seeding set.");

    constexpr int ITEMS_PER_THREAD = K / kWarpSize;
    constexpr int BLOCK_THREADS = BLOCK_WARPS * kWarpSize;

    extern __shared__ unsigned char smem_raw[];

    // Store the input tile in SoA form to avoid 8-byte shared-memory bank conflicts on float2 reads.
    float *const sm_data_x = reinterpret_cast<float *>(smem_raw);
    float *const sm_data_y = sm_data_x + kDataTilePoints;

    // Per-warp candidate buffers in shared memory.
    float *const sm_cand_dist = sm_data_y + kDataTilePoints;
    int   *const sm_cand_idx  = reinterpret_cast<int *>(sm_cand_dist + BLOCK_WARPS * K);

    const int warp_id = (threadIdx.x >> 5);
    const int lane    = (threadIdx.x & 31);
    const int query_idx = blockIdx.x * BLOCK_WARPS + warp_id;
    const bool valid_query = (query_idx < query_count);

    const int warp_buffer_base = warp_id * K;
    float *const cand_dist = sm_cand_dist + warp_buffer_base;
    int   *const cand_idx  = sm_cand_idx  + warp_buffer_base;

    // Private per-query top-k, distributed across the warp in striped layout.
    float top_dist[ITEMS_PER_THREAD];
    int   top_idx [ITEMS_PER_THREAD];

    float qx = 0.0f;
    float qy = 0.0f;
    float kth = CUDART_INF_F;
    int cand_count = 0;
    bool initialized = false;

    // Lane-mask prefix used for warp-synchronous compaction into the candidate buffer.
    const unsigned lane_mask_lt = (1u << lane) - 1u;

    if (valid_query) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    for (int tile_base = 0; tile_base < data_count; tile_base += kDataTilePoints) {
        const int remaining = data_count - tile_base;
        const int batch_size = (remaining < kDataTilePoints) ? remaining : kDataTilePoints;

        // Cooperative global->shared load of the current data tile.
        for (int i = threadIdx.x; i < batch_size; i += BLOCK_THREADS) {
            const float2 p = data[tile_base + i];
            sm_data_x[i] = p.x;
            sm_data_y[i] = p.y;
        }

        __syncthreads();

        if (valid_query) {
            int scan_start = 0;

            // Seed the private top-k from the first K points of the very first tile.
            // This gives a finite k-th threshold before the candidate-buffer phase begins.
            if (!initialized) {
#pragma unroll
                for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                    const int p = (t << 5) + lane;
                    top_dist[t] = squared_l2(qx, qy, sm_data_x[p], sm_data_y[p]);
                    top_idx [t] = p;  // tile_base == 0 here
                }

                bitonic_sort_striped_regs<K, ITEMS_PER_THREAD>(top_dist, top_idx, lane);
                kth = __shfl_sync(kFullMask, top_dist[ITEMS_PER_THREAD - 1], 31);

                initialized = true;
                scan_start = K;
            }

            // Process the tile 32 points at a time; each lane handles one point in the group.
            for (int group_base = scan_start; group_base < batch_size; group_base += kWarpSize) {
                const int local_idx = group_base + lane;
                const bool in_range = (local_idx < batch_size);

                float d = 0.0f;
                int data_idx = tile_base + local_idx;
                bool take = false;

                if (in_range) {
                    d = squared_l2(qx, qy, sm_data_x[local_idx], sm_data_y[local_idx]);

                    // Strictly better only: equal-distance ties may be dropped, which is allowed.
                    take = (d < kth);
                }

                const unsigned mask = __ballot_sync(kFullMask, take);
                const int n = __popc(mask);

                if (n != 0) {
                    const int rank = __popc(mask & lane_mask_lt);

                    if (cand_count + n <= K) {
                        if (take) {
                            cand_dist[cand_count + rank] = d;
                            cand_idx [cand_count + rank] = data_idx;
                        }

                        cand_count += n;

                        if (cand_count == K) {
                            kth = merge_candidate_buffer<K, ITEMS_PER_THREAD>(
                                top_dist, top_idx, cand_dist, cand_idx, cand_count, lane);
                            cand_count = 0;
                        }
                    } else {
                        // The current 32-point group would overflow the K-entry candidate buffer.
                        // Fill the remaining slots, merge immediately, then keep any leftover
                        // candidates from this same group that are still better than the new threshold.
                        const int fill = K - cand_count;

                        if (take && rank < fill) {
                            cand_dist[cand_count + rank] = d;
                            cand_idx [cand_count + rank] = data_idx;
                        }

                        kth = merge_candidate_buffer<K, ITEMS_PER_THREAD>(
                            top_dist, top_idx, cand_dist, cand_idx, K, lane);

                        bool keep_after_merge = take && (rank >= fill) && (d < kth);
                        const unsigned rem_mask = __ballot_sync(kFullMask, keep_after_merge);
                        const int rem_n = __popc(rem_mask);
                        const int rem_rank = __popc(rem_mask & lane_mask_lt);

                        if (keep_after_merge) {
                            cand_dist[rem_rank] = d;
                            cand_idx [rem_rank] = data_idx;
                        }

                        cand_count = rem_n;
                    }
                }
            }
        }

        // All warps must finish consuming the current tile before the block overwrites it.
        __syncthreads();
    }

    if (valid_query) {
        // Final partial-buffer merge, if any candidates remain.
        if (cand_count != 0) {
            (void)merge_candidate_buffer<K, ITEMS_PER_THREAD>(
                top_dist, top_idx, cand_dist, cand_idx, cand_count, lane);
        }

        // Store the sorted top-k back in row-major order.
        const int out_base = query_idx * K;
#pragma unroll
        for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
            const int p = (t << 5) + lane;
            result[out_base + p].first  = top_idx[t];
            result[out_base + p].second = top_dist[t];
        }
    }
}

// More warps/block means more reuse of each shared-memory data tile and therefore less global traffic
// per query. But if query_count is modest, overly large blocks reduce the number of blocks in flight.
// The heuristic below picks the largest of {16, 8, 4} warps/block that still gives roughly one block/SM.
inline int choose_block_warps(const int k, const int query_count) {
    int device = 0;
    (void)cudaGetDevice(&device);

    int sm_count = 1;
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count <= 0) sm_count = 1;

    if (k == 1024) {
        return (query_count >= 8 * sm_count) ? 8 : 4;
    }

    if (query_count >= 16 * sm_count) return 16;
    if (query_count >= 8  * sm_count) return 8;
    return 4;
}

template <int K, int BLOCK_WARPS>
inline void launch_knn(const float2 *query,
                       const int query_count,
                       const float2 *data,
                       const int data_count,
                       std::pair<int, float> *result) {
    constexpr int BLOCK_THREADS = BLOCK_WARPS * kWarpSize;
    constexpr size_t SHMEM_BYTES =
        size_t(2) * size_t(kDataTilePoints) * sizeof(float) +
        size_t(BLOCK_WARPS) * size_t(K) * (sizeof(float) + sizeof(int));

    // Opt in to the dynamic shared-memory size required by the chosen specialization.
    (void)cudaFuncSetAttribute(knn_kernel<K, BLOCK_WARPS>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(SHMEM_BYTES));
    (void)cudaFuncSetAttribute(knn_kernel<K, BLOCK_WARPS>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + BLOCK_WARPS - 1) / BLOCK_WARPS);

    // Intentionally asynchronous; the caller can synchronize or inspect errors as desired.
    knn_kernel<K, BLOCK_WARPS><<<grid, block, SHMEM_BYTES>>>(
        query, query_count, data, data_count, result);
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) return;

    const int block_warps = choose_block_warps(k, query_count);

    switch (k) {
        case 32:
            if (block_warps >= 16) launch_knn<32, 16>(query, query_count, data, data_count, result);
            else if (block_warps >= 8) launch_knn<32, 8>(query, query_count, data, data_count, result);
            else launch_knn<32, 4>(query, query_count, data, data_count, result);
            break;

        case 64:
            if (block_warps >= 16) launch_knn<64, 16>(query, query_count, data, data_count, result);
            else if (block_warps >= 8) launch_knn<64, 8>(query, query_count, data, data_count, result);
            else launch_knn<64, 4>(query, query_count, data, data_count, result);
            break;

        case 128:
            if (block_warps >= 16) launch_knn<128, 16>(query, query_count, data, data_count, result);
            else if (block_warps >= 8) launch_knn<128, 8>(query, query_count, data, data_count, result);
            else launch_knn<128, 4>(query, query_count, data, data_count, result);
            break;

        case 256:
            if (block_warps >= 16) launch_knn<256, 16>(query, query_count, data, data_count, result);
            else if (block_warps >= 8) launch_knn<256, 8>(query, query_count, data, data_count, result);
            else launch_knn<256, 4>(query, query_count, data, data_count, result);
            break;

        case 512:
            if (block_warps >= 16) launch_knn<512, 16>(query, query_count, data, data_count, result);
            else if (block_warps >= 8) launch_knn<512, 8>(query, query_count, data, data_count, result);
            else launch_knn<512, 4>(query, query_count, data, data_count, result);
            break;

        case 1024:
            if (block_warps >= 8) launch_knn<1024, 8>(query, query_count, data, data_count, result);
            else launch_knn<1024, 4>(query, query_count, data, data_count, result);
            break;

        default:
            // Inputs are guaranteed valid by the problem statement, so this path is unreachable.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstdint>
#include <cstddef>

namespace knn_detail {

// The interface requires std::pair<int, float> in device memory.
// Writing fields individually avoids depending on any host/device annotation on pair assignment.
using result_pair_t = std::pair<int, float>;

// A packed key stores [distance_bits | index] in one 64-bit word.
// Distances are squared Euclidean distances, hence non-negative; for non-negative IEEE-754 floats,
// unsigned integer order matches numeric order, so a plain integer compare is enough.
using packed_key_t = std::uint64_t;

constexpr int      kWarpSize      = 32;
constexpr unsigned kFullMask      = 0xFFFFFFFFu;
constexpr int      kBlockThreads  = 256;   // 8 warps/block => 8 queries/block.
constexpr int      kBatchPoints   = 2048;  // 16 KiB tile of float2 points.
constexpr int      kSentinelIndex = 0x7FFFFFFF;

// Tuning rationale for A100/H100-class GPUs:
// * One warp computes one query, so block size is chosen in warps, not arbitrary threads.
// * 256 threads/block keeps grid granularity high for query counts in the low thousands.
// * 2048 cached data points amortize global memory loads well.
// * Worst-case shared memory footprint at K=1024 is:
//       2048 * sizeof(float2) + 8 warps * (2 * 1024 * sizeof(uint64_t))
//     = 16 KiB + 128 KiB = 144 KiB/block,
//   which fits comfortably under the opt-in per-block shared-memory budget on A100/H100.

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
struct KernelConfig {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    static_assert(BLOCK_THREADS % kWarpSize == 0, "BLOCK_THREADS must be a multiple of 32.");
    static_assert(BATCH_POINTS % kWarpSize == 0, "BATCH_POINTS must be a multiple of 32.");
    static_assert(BATCH_POINTS % BLOCK_THREADS == 0, "BATCH_POINTS should be divisible by BLOCK_THREADS for fully unrolled cooperative loads.");

    static constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpSize;
    static constexpr std::size_t kBatchBytes =
        static_cast<std::size_t>(BATCH_POINTS) * sizeof(float2);
    static constexpr std::size_t kPerWarpStateBytes =
        static_cast<std::size_t>(2) * K * sizeof(packed_key_t); // [0, K): top-K, [K, 2K): candidate buffer
    static constexpr std::size_t kSharedBytes =
        kBatchBytes + static_cast<std::size_t>(kWarpsPerBlock) * kPerWarpStateBytes;

    static_assert((kBatchBytes % alignof(packed_key_t)) == 0, "Shared-memory layout must preserve packed_key_t alignment.");
};

__device__ __forceinline__ packed_key_t pack_key(const float dist, const int idx) {
    return (static_cast<packed_key_t>(__float_as_uint(dist)) << 32) |
           static_cast<std::uint32_t>(idx);
}

__device__ __forceinline__ float unpack_dist(const packed_key_t key) {
    return __uint_as_float(static_cast<std::uint32_t>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(const packed_key_t key) {
    return static_cast<int>(static_cast<std::uint32_t>(key));
}

__device__ __forceinline__ void store_result_pair(result_pair_t* dst, const int idx, const float dist) {
    dst->first  = idx;
    dst->second = dist;
}

// Full ascending bitonic sort of a power-of-two segment in shared memory.
// Only one warp touches the segment, so __syncwarp is sufficient.
template <int N>
__device__ __forceinline__ void bitonic_sort_segment(packed_key_t* base, const int lane) {
#pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const packed_key_t ai = base[i];
                    const packed_key_t aj = base[j];
                    const bool up = ((i & size) == 0);
                    const bool do_swap = up ? (ai > aj) : (ai < aj);
                    if (do_swap) {
                        base[i] = aj;
                        base[j] = ai;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Ascending bitonic merge of a segment that is already known to be bitonic.
template <int N>
__device__ __forceinline__ void bitonic_merge_segment(packed_key_t* base, const int lane) {
#pragma unroll 1
    for (int stride = N >> 1; stride > 0; stride >>= 1) {
        for (int i = lane; i < N; i += kWarpSize) {
            const int j = i ^ stride;
            if (j > i) {
                const packed_key_t ai = base[i];
                const packed_key_t aj = base[j];
                if (ai > aj) {
                    base[i] = aj;
                    base[j] = ai;
                }
            }
        }
        __syncwarp(kFullMask);
    }
}

// Merge the candidate buffer into the already-sorted top-K array.
// Storage layout for one warp/query:
//   storage[0 .. K-1]     : current top-K, sorted ascending
//   storage[K .. 2K-1]    : candidate buffer, compacted at the front, unsorted
//
// To avoid needing an extra 3rd K-sized buffer, the merge is done as:
//   1) pad unused candidate slots with +INF,
//   2) sort the candidate buffer ascending,
//   3) bitonic split top[i] against cand[K-1-i], which moves the smallest K elements into top
//      as a bitonic sequence,
//   4) bitonic-merge only top back to ascending order.
// This is cheaper than sorting the full 2K union and satisfies the "no extra device memory" rule.
template <int K>
__device__ __forceinline__ float merge_buffer_into_top(
    packed_key_t* storage,
    const int lane,
    const int valid_count,
    const packed_key_t inf_key)
{
    packed_key_t* const top  = storage;
    packed_key_t* const cand = storage + K;

    if (valid_count < K) {
        for (int i = lane; i < K; i += kWarpSize) {
            if (i >= valid_count) {
                cand[i] = inf_key;
            }
        }
    }

    // Make all candidate writes/padding visible before sorting.
    __syncwarp(kFullMask);

    bitonic_sort_segment<K>(cand, lane);

    // Bitonic split: compare the ascending top half with the descending candidate half.
    // We only need the smaller side; the larger side can be discarded because the next merge
    // overwrites/re-pads the candidate area anyway.
    for (int i = lane; i < K; i += kWarpSize) {
        const int j = K - 1 - i;
        const packed_key_t a = top[i];
        const packed_key_t b = cand[j];
        if (a > b) {
            top[i] = b;
        }
    }

    __syncwarp(kFullMask);

    bitonic_merge_segment<K>(top, lane);

    float kth = 0.0f;
    if (lane == 0) {
        kth = unpack_dist(top[K - 1]);
    }
    return __shfl_sync(kFullMask, kth, 0);
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    result_pair_t* __restrict__ result)
{
    using Cfg = KernelConfig<K, BLOCK_THREADS, BATCH_POINTS>;

    const int lane          = threadIdx.x & (kWarpSize - 1);
    const int warp_in_block = threadIdx.x >> 5;
    const int query_idx     = static_cast<int>(blockIdx.x) * Cfg::kWarpsPerBlock + warp_in_block;
    const bool active_query = (query_idx < query_count);

    // Shared-memory layout:
    //   [batch tile of BATCH_POINTS float2]
    //   [per-warp 2*K packed_key_t state]
    extern __shared__ packed_key_t smem_u64[];
    unsigned char* const smem      = reinterpret_cast<unsigned char*>(smem_u64);
    float2* const batch            = reinterpret_cast<float2*>(smem);
    packed_key_t* const warp_state = reinterpret_cast<packed_key_t*>(smem + Cfg::kBatchBytes);

    packed_key_t* const my_state =
        warp_state + static_cast<std::size_t>(warp_in_block) * (2 * K);

    const unsigned lane_mask_lt = (1u << lane) - 1u;
    const packed_key_t inf_key  = pack_key(CUDART_INF_F, kSentinelIndex);

    float qx = 0.0f;
    float qy = 0.0f;
    float kth = CUDART_INF_F;
    int   buf_count = 0;

    if (active_query) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);

        // Top-K lives in the warp-private slice of shared memory.
        // K can be as large as 1024, so a full register-resident copy would be too large;
        // shared memory keeps it private to the warp without spilling to local/global memory.
        for (int i = lane; i < K; i += kWarpSize) {
            my_state[i] = inf_key;
        }

        __syncwarp(kFullMask);
    }

    for (int batch_base = 0; batch_base < data_count; batch_base += BATCH_POINTS) {
        const int remaining = data_count - batch_base;
        const int batch_n   = (remaining < BATCH_POINTS) ? remaining : BATCH_POINTS;
        const float2* const tile = data + batch_base;

        // Whole-block cooperative load of the current data tile into shared memory.
        // With the chosen tuning parameters this loop has exactly 8 iterations/thread.
#pragma unroll
        for (int i = threadIdx.x; i < BATCH_POINTS; i += BLOCK_THREADS) {
            if (i < batch_n) {
                batch[i] = tile[i];
            }
        }

        __syncthreads();

        if (active_query) {
            // Process the shared-memory tile in warp-wide stripes of 32 points.
            // This keeps all warp-wide ballots/shuffles structurally aligned even for tail tiles.
#pragma unroll 1
            for (int j_base = 0; j_base < BATCH_POINTS; j_base += kWarpSize) {
                if (j_base >= batch_n) {
                    break;
                }

                const int j = j_base + lane;

                float dist = 0.0f;
                int   idx  = 0;
                bool  accept = false;

                if (j < batch_n) {
                    const float2 p = batch[j];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                    idx = batch_base + j;

                    // Skip candidates that are not closer than the current K-th neighbor.
                    accept = (dist < kth);
                }

                // Warp-wide compact append into the candidate buffer without atomics:
                // ballot -> prefix rank -> dense write.
                unsigned active_mask = __ballot_sync(kFullMask, accept);

                while (active_mask != 0u) {
                    const int rank    = accept ? __popc(active_mask & lane_mask_lt) : 0;
                    const int pending = __popc(active_mask);
                    const int space   = K - buf_count;
                    const int take    = (pending < space) ? pending : space;

                    if (accept && rank < take) {
                        my_state[K + buf_count + rank] = pack_key(dist, idx);
                    }

                    // Candidate writes must be visible before a possible merge.
                    __syncwarp(kFullMask);

                    buf_count += take;

                    if (accept && rank < take) {
                        accept = false;
                    }

                    if (buf_count == K) {
                        kth = merge_buffer_into_top<K>(my_state, lane, K, inf_key);
                        buf_count = 0;
                    }

                    // If the previous append overflowed the buffer, the remaining accepted lanes
                    // stay live and immediately continue with the now-empty buffer.
                    active_mask = __ballot_sync(kFullMask, accept);
                }
            }
        }

        // All warps must be done reading the current tile before the block overwrites it.
        __syncthreads();
    }

    if (active_query) {
        if (buf_count != 0) {
            kth = merge_buffer_into_top<K>(my_state, lane, buf_count, inf_key);
            (void)kth;
        }

        result_pair_t* const out =
            result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        for (int i = lane; i < K; i += kWarpSize) {
            const packed_key_t key = my_state[i];
            store_result_pair(out + i, unpack_idx(key), unpack_dist(key));
        }
    }
}

template <int K>
static inline void launch_knn_impl(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    result_pair_t* result)
{
    using Cfg = KernelConfig<K, kBlockThreads, kBatchPoints>;

    static_assert(Cfg::kSharedBytes <= (144u * 1024u),
                  "Chosen launch policy must stay within the intended A100/H100 shared-memory budget.");

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + Cfg::kWarpsPerBlock - 1) / Cfg::kWarpsPerBlock);

    // Opt in to the large dynamic shared-memory footprint and bias the carveout toward shared memory.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, kBlockThreads, kBatchPoints>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(Cfg::kSharedBytes));

    (void)cudaFuncSetAttribute(
        knn_kernel<K, kBlockThreads, kBatchPoints>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    // Standard CUDA launch semantics: asynchronous with respect to the host.
    knn_kernel<K, kBlockThreads, kBatchPoints>
        <<<grid, block, Cfg::kSharedBytes>>>(query, query_count, data, data_count, result);
}

} // namespace knn_detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn_detail::launch_knn_impl<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_detail::launch_knn_impl<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_detail::launch_knn_impl<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_detail::launch_knn_impl<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_detail::launch_knn_impl<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_detail::launch_knn_impl<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem statement guarantees valid K, so this path is unreachable.
            break;
    }
}

#include <cuda_runtime.h>

#include <climits>
#include <cstddef>
#include <type_traits>
#include <utility>

namespace knn_detail {

// This implementation targets the stated workload regime:
// - one warp computes one query,
// - the whole block cooperatively tiles the data array into shared memory,
// - each warp keeps a private top-k in a striped register/local layout,
// - each warp also owns a shared-memory candidate buffer of size k and a shared counter,
// - whenever the candidate buffer fills (or would overflow), it is merged with the
//   current top-k using all 32 threads in the warp.
//
// The kernel returns squared Euclidean distances exactly as requested, i.e. no sqrt.

constexpr int kWarpThreads = 32;
constexpr unsigned kFullMask = 0xffffffffu;
// A100's opt-in per-block dynamic shared-memory limit; H100 is larger.
// Launch configurations below are chosen to remain valid for both.
constexpr int kA100OptinSharedBytes = 163840;

// Device result memory is declared as std::pair<int, float>* in the public interface.
// We use a layout-compatible POD for device-side writes.
struct ResultPair {
    int first;
    float second;
};

static_assert(sizeof(ResultPair) == sizeof(std::pair<int, float>),
              "ResultPair must match std::pair<int, float> size");
static_assert(alignof(ResultPair) == alignof(std::pair<int, float>),
              "ResultPair must match std::pair<int, float> alignment");

__device__ __forceinline__ bool pair_less(float a_dist, int a_idx, float b_dist, int b_idx) {
    // Distances define the ordering. The index is only a deterministic tie-breaker;
    // the problem statement does not constrain tie handling.
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__ int prefix_rank(unsigned mask, int lane) {
    // Rank of this lane among active bits in mask, counting only lower-numbered lanes.
    const unsigned lower_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
    return __popc(mask & lower_mask);
}

__device__ __forceinline__ float squared_l2(float qx, float qy, const float2 &p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

template <int N>
__device__ __forceinline__ void bitonic_sort_shared(float *dist_buf, int *idx_buf, int lane) {
    static_assert((N & (N - 1)) == 0, "bitonic sort size must be a power of two");

    // Shared-memory bitonic sort over N key/value pairs owned by one warp.
    // We deliberately keep this generic across all legal K values. Because each merge
    // processes at most 2K elements and K <= 1024, N <= 2048.
#pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll 1
            for (int i = lane; i < N; i += kWarpThreads) {
                const int partner = i ^ stride;
                if (partner > i) {
                    const float a_dist = dist_buf[i];
                    const float b_dist = dist_buf[partner];
                    const int a_idx = idx_buf[i];
                    const int b_idx = idx_buf[partner];

                    const bool ascending = ((i & size) == 0);
                    const bool do_swap =
                        ascending ? pair_less(b_dist, b_idx, a_dist, a_idx)
                                  : pair_less(a_dist, a_idx, b_dist, b_idx);

                    if (do_swap) {
                        dist_buf[i] = b_dist;
                        idx_buf[i] = b_idx;
                        dist_buf[partner] = a_dist;
                        idx_buf[partner] = a_idx;
                    }
                }
            }
            // The buffer is warp-private, so warp-level synchronization is sufficient.
            __syncwarp();
        }
    }
}

template <int K>
__device__ __forceinline__ void merge_candidate_buffer(
    float *warp_dist,
    int *warp_idx,
    int *warp_count,
    float (&best_dist)[K / kWarpThreads],
    int (&best_idx)[K / kWarpThreads],
    int lane,
    float &max_distance,
    int &candidate_count) {
    static_assert(K % kWarpThreads == 0, "K must be divisible by the warp size");
    constexpr int kChunk = K / kWarpThreads;

    // Shared layout for this warp:
    //   [0, K)   : candidate buffer
    //   [K, 2K)  : temporary copy of the current top-k
    //
    // The current top-k is already globally sorted. The candidate buffer is not.
    // We therefore build a 2K-element array in shared memory and run a full bitonic sort.
    // The smallest K entries are then stored back into the register-striped top-k.
#pragma unroll
    for (int t = 0; t < kChunk; ++t) {
        const int pos = lane + t * kWarpThreads;
        warp_dist[K + pos] = best_dist[t];
        warp_idx[K + pos] = best_idx[t];
    }

    // Pad the unused candidate slots with +inf / INT_MAX so they sort to the end.
    if (candidate_count < K) {
        for (int pos = candidate_count + lane; pos < K; pos += kWarpThreads) {
            warp_dist[pos] = CUDART_INF_F;
            warp_idx[pos] = INT_MAX;
        }
    }

    __syncwarp();
    bitonic_sort_shared<2 * K>(warp_dist, warp_idx, lane);

#pragma unroll
    for (int t = 0; t < kChunk; ++t) {
        const int pos = lane + t * kWarpThreads;
        best_dist[t] = warp_dist[pos];
        best_idx[t] = warp_idx[pos];
    }

    if (lane == 0) {
        *warp_count = 0;
    }
    __syncwarp();

    candidate_count = 0;

    // The k-th nearest neighbor is the last element in the globally sorted top-k.
    float kth = 0.0f;
    if (lane == kWarpThreads - 1) {
        kth = best_dist[kChunk - 1];
    }
    max_distance = __shfl_sync(kFullMask, kth, kWarpThreads - 1);
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
constexpr std::size_t shared_bytes_for_kernel() {
    static_assert(BLOCK_THREADS % kWarpThreads == 0, "BLOCK_THREADS must be warp-aligned");
    static_assert(BATCH_POINTS % kWarpThreads == 0, "BATCH_POINTS must be a multiple of 32");

    constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpThreads;

    return static_cast<std::size_t>(BATCH_POINTS) * sizeof(float2) +
           static_cast<std::size_t>(kWarpsPerBlock) * sizeof(int) +
           static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(2 * K) * sizeof(float) +
           static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(2 * K) * sizeof(int);
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
__global__ void knn_kernel(
    const float2 *__restrict__ query,
    int query_count,
    const float2 *__restrict__ data,
    int data_count,
    ResultPair *__restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024]");
    static_assert(K % kWarpThreads == 0, "K must be divisible by 32");
    static_assert(BLOCK_THREADS % kWarpThreads == 0, "BLOCK_THREADS must be warp-aligned");
    static_assert(BATCH_POINTS % kWarpThreads == 0, "BATCH_POINTS must be a multiple of 32");

    constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpThreads;
    constexpr int kChunk = K / kWarpThreads;

    // Use an int4-backed extern shared allocation to guarantee a sufficiently aligned base.
    extern __shared__ int4 smem_base[];
    unsigned char *smem = reinterpret_cast<unsigned char *>(smem_base);

    // Dynamic shared-memory layout:
    //   [BATCH_POINTS x float2]              block-wide data tile
    //   [kWarpsPerBlock x int]               per-warp candidate counters
    //   [kWarpsPerBlock x (2K) x float]      per-warp distances (candidate + temp)
    //   [kWarpsPerBlock x (2K) x int]        per-warp indices   (candidate + temp)
    float2 *s_data = reinterpret_cast<float2 *>(smem);
    int *s_counts = reinterpret_cast<int *>(s_data + BATCH_POINTS);
    float *s_buf_dist = reinterpret_cast<float *>(s_counts + kWarpsPerBlock);
    int *s_buf_idx = reinterpret_cast<int *>(s_buf_dist + kWarpsPerBlock * (2 * K));

    const int tid = threadIdx.x;
    const int warp_id = tid / kWarpThreads;
    const int lane = tid & (kWarpThreads - 1);
    const int query_idx = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active = (query_idx < query_count);

    if (lane == 0) {
        s_counts[warp_id] = 0;
    }

    // One query point per warp. Load once and broadcast via warp shuffles.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Warp-private top-k in striped layout:
    // lane L owns global positions L, L+32, L+64, ...
    float best_dist[kChunk];
    int best_idx[kChunk];
#pragma unroll
    for (int t = 0; t < kChunk; ++t) {
        best_dist[t] = CUDART_INF_F;
        best_idx[t] = INT_MAX;
    }

    float max_distance = CUDART_INF_F;
    int candidate_count = 0;

    float *warp_dist = s_buf_dist + warp_id * (2 * K);
    int *warp_idx = s_buf_idx + warp_id * (2 * K);

    for (int batch_start = 0; batch_start < data_count; batch_start += BATCH_POINTS) {
        const int current = ((data_count - batch_start) < BATCH_POINTS) ? (data_count - batch_start) : BATCH_POINTS;
        const float2 *batch_data = data + batch_start;

        // Whole-block cooperative load of the next data tile.
        for (int i = tid; i < current; i += BLOCK_THREADS) {
            s_data[i] = batch_data[i];
        }
        __syncthreads();

        if (active) {
            // Each iteration processes one warp-wide micro-batch of up to 32 points.
            // We first compute a ballot of lanes that qualify under the current threshold.
            // If inserting all of them would overflow the fixed-size candidate buffer, we merge first,
            // recompute the qualification under the updated threshold, and then reserve space.
#pragma unroll 1
            for (int base = 0; base < current; base += kWarpThreads) {
                const int local = base + lane;
                const bool valid = (local < current);

                float dist = CUDART_INF_F;
                if (valid) {
                    dist = squared_l2(qx, qy, s_data[local]);
                }

                bool qualify = valid && (dist < max_distance);
                unsigned mask = __ballot_sync(kFullMask, qualify);
                int hits = __popc(mask);

                if (hits) {
                    if (candidate_count + hits > K) {
                        merge_candidate_buffer<K>(
                            warp_dist, warp_idx, &s_counts[warp_id],
                            best_dist, best_idx, lane, max_distance, candidate_count);

                        qualify = valid && (dist < max_distance);
                        mask = __ballot_sync(kFullMask, qualify);
                        hits = __popc(mask);
                    }

                    if (hits) {
                        // One atomicAdd per warp-wide micro-batch, not per candidate.
                        // This still satisfies the requirement while reducing atomic traffic.
                        int base_pos = 0;
                        if (lane == 0) {
                            base_pos = atomicAdd(&s_counts[warp_id], hits);
                        }
                        base_pos = __shfl_sync(kFullMask, base_pos, 0);

                        if (qualify) {
                            const int pos = base_pos + prefix_rank(mask, lane);
                            warp_dist[pos] = dist;
                            warp_idx[pos] = batch_start + local;
                        }

                        candidate_count = base_pos + hits;

                        // If the buffer is now full, merge immediately.
                        __syncwarp();
                        if (candidate_count == K) {
                            merge_candidate_buffer<K>(
                                warp_dist, warp_idx, &s_counts[warp_id],
                                best_dist, best_idx, lane, max_distance, candidate_count);
                        }
                    }
                }
            }
        }

        // The next tile reuses the same shared-memory region for s_data.
        __syncthreads();
    }

    // Flush any remaining candidates after the final batch.
    if (active && candidate_count > 0) {
        merge_candidate_buffer<K>(
            warp_dist, warp_idx, &s_counts[warp_id],
            best_dist, best_idx, lane, max_distance, candidate_count);
    }

    if (active) {
        ResultPair *out = result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
#pragma unroll
        for (int t = 0; t < kChunk; ++t) {
            const int pos = lane + t * kWarpThreads;
            out[pos] = ResultPair{best_idx[t], best_dist[t]};
        }
    }
}

template <int K, int BLOCK_THREADS, int BATCH_POINTS>
inline void launch_knn_config(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    ResultPair *result) {
    constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpThreads;
    constexpr std::size_t kSharedBytes = shared_bytes_for_kernel<K, BLOCK_THREADS, BATCH_POINTS>();

    static_assert(kSharedBytes <= static_cast<std::size_t>(kA100OptinSharedBytes),
                  "Configuration exceeds A100 shared-memory limit");

    const int grid_x = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    // Preferred tuning for the stated workload:
    // 256 threads/block = 8 query-warps per block.
    // This balances two competing goals:
    // 1) enough blocks to keep >100-SM parts busy when query_count is only in the low thousands,
    // 2) enough queries per block to amortize each shared-memory data tile.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS, BATCH_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(kSharedBytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS, BATCH_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    knn_kernel<K, BLOCK_THREADS, BATCH_POINTS>
        <<<grid_x, BLOCK_THREADS, kSharedBytes>>>(query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    auto *out = reinterpret_cast<knn_detail::ResultPair *>(result);

    // Launch configurations are chosen for modern datacenter GPUs with large shared memory.
    // Batch sizes are occupancy-aware:
    // - K <= 256 : 2720 points keeps 3 blocks/SM at K=256 on 164KB-SMEM parts.
    // - K == 512 : 2016 points keeps 2 blocks/SM.
    // - K == 1024: 1 block/SM is unavoidable, so the batch is enlarged to 4064 points
    //              to reduce synchronization and global-to-shared staging overhead.
    switch (k) {
        case 32:
            knn_detail::launch_knn_config<32, 256, 2720>(query, query_count, data, data_count, out);
            break;
        case 64:
            knn_detail::launch_knn_config<64, 256, 2720>(query, query_count, data, data_count, out);
            break;
        case 128:
            knn_detail::launch_knn_config<128, 256, 2720>(query, query_count, data, data_count, out);
            break;
        case 256:
            knn_detail::launch_knn_config<256, 256, 2720>(query, query_count, data, data_count, out);
            break;
        case 512:
            knn_detail::launch_knn_config<512, 256, 2016>(query, query_count, data, data_count, out);
            break;
        case 1024:
            knn_detail::launch_knn_config<1024, 256, 4064>(query, query_count, data, data_count, out);
            break;
        default:
            // Inputs are stated to be valid; this default is only a defensive fallback.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstdint>
#include <utility>

namespace knn2d_internal {

// One warp owns one query.
constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xffffffffu;

// Packed representation of one (index, distance) pair.
// High 32 bits store the IEEE-754 bits of the non-negative squared distance,
// low 32 bits store the data-point index. Because all distances here are
// squared Euclidean distances, they are non-negative, so integer ordering of
// the float bits matches numerical ordering. This lets the merge path sort a
// single 64-bit key per neighbor candidate.
constexpr uint32_t kInfBits = 0x7f800000u;
constexpr uint32_t kEmptyIndexBits = 0xffffffffu;
constexpr uint64_t kEmptyKey =
    (static_cast<uint64_t>(kInfBits) << 32) | static_cast<uint64_t>(kEmptyIndexBits);

// The public interface uses std::pair<int, float>. On device we write a POD
// with the same binary footprint so we do not rely on std::pair being fully
// device-annotated by the host standard library implementation.
struct ResultPairRaw {
    int first;
    float second;
};

static_assert(sizeof(ResultPairRaw) == 8, "Unexpected ResultPairRaw size.");
static_assert(sizeof(std::pair<int, float>) == sizeof(ResultPairRaw),
              "std::pair<int,float> must be 8 bytes for this implementation.");

// Kernel configuration:
// - 8 warps/block gives good data reuse because one shared-memory batch of data
//   points is reused by 8 simultaneous queries, while still leaving enough block
//   granularity for query counts in the low thousands.
// - K is specialized at compile time to keep each warp's private top-k storage
//   fixed-size and efficiently addressable.
template <int K>
struct KernelConfig {
    static_assert(K >= 32 && K <= 1024, "K out of supported range.");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");

    static constexpr int WARPS_PER_BLOCK = 8;
    static constexpr int THREADS = WARPS_PER_BLOCK * kWarpSize;
    static constexpr int ITEMS_PER_LANE = K / kWarpSize;

    // Per warp we need 2*K packed keys in shared memory:
    //   [0, K)   : scratch area for the current top-k
    //   [K, 2*K) : candidate buffer
    static constexpr int REGION_ENTRIES = 2 * K;
    static constexpr int FIXED_BYTES =
        WARPS_PER_BLOCK * REGION_ENTRIES * static_cast<int>(sizeof(uint64_t)) +
        WARPS_PER_BLOCK * static_cast<int>(sizeof(int));
};

__device__ __forceinline__ uint64_t pack_key(float dist, int idx) {
    return (static_cast<uint64_t>(__float_as_uint(dist)) << 32) |
           static_cast<uint32_t>(idx);
}

__device__ __forceinline__ float unpack_distance(uint64_t key) {
    return __uint_as_float(static_cast<uint32_t>(key >> 32));
}

__device__ __forceinline__ int unpack_index(uint64_t key) {
    return static_cast<int>(static_cast<uint32_t>(key));
}

// Classic bitonic sort on a per-warp shared-memory segment of power-of-two size.
// N is 2*K, so it is always a power of two by construction.
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(uint64_t* keys) {
    const int lane = threadIdx.x & (kWarpSize - 1);

#pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll 1
            for (int i = lane; i < N; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const uint64_t a = keys[i];
                    const uint64_t b = keys[j];
                    const bool ascending = ((i & size) == 0);
                    const bool do_swap = ascending ? (a > b) : (a < b);
                    if (do_swap) {
                        keys[i] = b;
                        keys[j] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Merge the shared candidate buffer [K, 2*K) with the warp-private top-k state.
// The result is written back into the warp-private striped layout:
//   top_keys[t] holds global rank lane + 32*t.
template <int K>
__device__ __forceinline__ void merge_candidate_buffer(
    uint64_t* warp_keys,
    int* warp_count,
    int candidate_count,
    uint64_t (&top_keys)[KernelConfig<K>::ITEMS_PER_LANE],
    float& max_distance) {
    constexpr int ITEMS_PER_LANE = KernelConfig<K>::ITEMS_PER_LANE;
    const int lane = threadIdx.x & (kWarpSize - 1);

    // Copy current top-k into the first half of the per-warp shared region.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int pos = lane + t * kWarpSize;
        warp_keys[pos] = top_keys[t];
    }

    // Pad the unused part of the candidate buffer with +inf so a single sort of
    // 2*K elements can perform the full merge/select.
#pragma unroll
    for (int pos = lane; pos < K; pos += kWarpSize) {
        if (pos >= candidate_count) {
            warp_keys[K + pos] = kEmptyKey;
        }
    }

    __syncwarp();

    bitonic_sort_shared<2 * K>(warp_keys);

    // Reload the K smallest keys back into the warp-private striped layout.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int pos = lane + t * kWarpSize;
        top_keys[t] = warp_keys[pos];
    }

    // The k-th nearest neighbor is the last element of the sorted top-k.
    float lane_last = 0.0f;
    if (lane == (kWarpSize - 1)) {
        lane_last = unpack_distance(top_keys[ITEMS_PER_LANE - 1]);
    }
    max_distance = __shfl_sync(kFullMask, lane_last, kWarpSize - 1);

    // Reset the shared candidate count after the merge.
    if (lane == 0) {
        *warp_count = 0;
    }
    __syncwarp();
}

template <int K>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    ResultPairRaw* __restrict__ result,
    int batch_points) {
    using Cfg = KernelConfig<K>;
    constexpr int ITEMS_PER_LANE = Cfg::ITEMS_PER_LANE;

    const int tid = static_cast<int>(threadIdx.x);
    const int warp = tid >> 5;
    const int lane = tid & (kWarpSize - 1);
    const int query_idx = static_cast<int>(blockIdx.x) * Cfg::WARPS_PER_BLOCK + warp;
    const bool active = (query_idx < query_count);

    // Shared layout:
    //   [0, batch_points)                              : cached data points
    //   [batch_points, batch_points + warps*2*K)      : packed per-warp key regions
    //   [..]                                           : per-warp candidate counts
    extern __shared__ __align__(16) unsigned char shared_storage[];
    auto* sh_data = reinterpret_cast<float2*>(shared_storage);
    auto* sh_keys = reinterpret_cast<uint64_t*>(sh_data + batch_points);
    auto* sh_count =
        reinterpret_cast<int*>(sh_keys + Cfg::WARPS_PER_BLOCK * Cfg::REGION_ENTRIES);

    uint64_t* const warp_keys = sh_keys + warp * Cfg::REGION_ENTRIES;
    int* const warp_count = sh_count + warp;

    if (lane == 0) {
        *warp_count = 0;
    }
    __syncthreads();

    // Warp-private intermediate result: K packed (index, distance) pairs,
    // striped across the 32 lanes, i.e. lane owns positions lane + 32*t.
    uint64_t top_keys[ITEMS_PER_LANE];
#pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        top_keys[t] = kEmptyKey;
    }

    float max_distance = CUDART_INF_F;
    int buffer_count = 0;  // local mirror of the shared candidate count

    float qx = 0.0f;
    float qy = 0.0f;
    if (active) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    // Iterate over the data set in shared-memory batches.
    for (int batch_base = 0; batch_base < data_count; batch_base += batch_points) {
        const int remaining = data_count - batch_base;
        const int current_batch = (remaining < batch_points) ? remaining : batch_points;

        // Cooperative block-wide global->shared load of the current batch.
        for (int i = tid; i < current_batch; i += Cfg::THREADS) {
            sh_data[i] = data[batch_base + i];
        }
        __syncthreads();

        if (active) {
            // Process the cached batch in warp-sized tiles. Each lane handles one
            // candidate point per tile.
            for (int tile = 0; tile < current_batch; tile += kWarpSize) {
                const int local_idx = tile + lane;

                float dist = 0.0f;
                int data_idx = 0;
                bool take = false;

                if (local_idx < current_batch) {
                    const float2 p = sh_data[local_idx];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);  // squared L2; no sqrt
                    data_idx = batch_base + local_idx;
                    take = (dist < max_distance);
                }

                const unsigned candidate_mask = __ballot_sync(kFullMask, take);
                const int candidate_lanes = __popc(candidate_mask);

                if (candidate_lanes != 0) {
                    // If the current tile would overflow the candidate buffer, first
                    // merge the existing buffer into the intermediate top-k.
                    if (buffer_count + candidate_lanes > K) {
                        merge_candidate_buffer<K>(
                            warp_keys, warp_count, buffer_count, top_keys, max_distance);
                        buffer_count = 0;
                    }

                    // Required by the problem statement: add each surviving candidate
                    // with atomicAdd on the shared candidate count.
                    if (take) {
                        const int pos = atomicAdd(warp_count, 1);
                        warp_keys[K + pos] = pack_key(dist, data_idx);
                    }

                    buffer_count += candidate_lanes;
                    __syncwarp();

                    // Merge immediately once the candidate buffer becomes full.
                    if (buffer_count == K) {
                        merge_candidate_buffer<K>(
                            warp_keys, warp_count, buffer_count, top_keys, max_distance);
                        buffer_count = 0;
                    }
                }
            }
        }

        __syncthreads();
    }

    if (active) {
        // Final merge for the partially filled candidate buffer, if any.
        if (buffer_count != 0) {
            merge_candidate_buffer<K>(
                warp_keys, warp_count, buffer_count, top_keys, max_distance);
        }

        // Write the final sorted top-k for this query.
        const int out_base = query_idx * K;
#pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int out_pos = out_base + lane + t * kWarpSize;
            const uint64_t key = top_keys[t];

            ResultPairRaw out;
            out.first = unpack_index(key);
            out.second = unpack_distance(key);
            result[out_pos] = out;
        }
    }
}

// Batch-size heuristic:
// - If the fixed per-query shared state is small enough, target two resident
//   blocks/SM by budgeting half of the SM shared memory per block.
// - If the fixed state already forces a single block/SM (notably K=1024 on SM80),
//   use the full per-block shared-memory limit to maximize data reuse.
// - Round to a multiple of one warp so the per-warp processing loop stays aligned.
template <int K>
inline int compute_batch_points(int max_block_smem, int max_sm_smem) {
    using Cfg = KernelConfig<K>;

    int budget = max_block_smem;
    const int two_block_budget = max_sm_smem / 2;
    if (Cfg::FIXED_BYTES <= two_block_budget) {
        budget = (max_block_smem < two_block_budget) ? max_block_smem : two_block_budget;
    }

    const int available = budget - Cfg::FIXED_BYTES;
    if (available <= 0) {
        return 0;
    }

    const int raw_points = available / static_cast<int>(sizeof(float2));
    return (raw_points / kWarpSize) * kWarpSize;
}

template <int K>
inline void launch_knn_kernel(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPairRaw* result) {
    using Cfg = KernelConfig<K>;

    // Default to SM80-safe values; overwrite with runtime values when available.
    int device = 0;
    int max_block_smem = 163840;
    int max_sm_smem = 163840;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(
        &max_block_smem, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);
    (void)cudaDeviceGetAttribute(
        &max_sm_smem, cudaDevAttrMaxSharedMemoryPerMultiprocessor, device);

    const int batch_points = compute_batch_points<K>(max_block_smem, max_sm_smem);
    if (batch_points <= 0) {
        return;
    }

    const int shared_bytes =
        Cfg::FIXED_BYTES + batch_points * static_cast<int>(sizeof(float2));
    const dim3 block(Cfg::THREADS);
    const dim3 grid((query_count + Cfg::WARPS_PER_BLOCK - 1) / Cfg::WARPS_PER_BLOCK);

    (void)cudaFuncSetAttribute(
        knn_kernel<K>, cudaFuncAttributeMaxDynamicSharedMemorySize, shared_bytes);
    (void)cudaFuncSetAttribute(
        knn_kernel<K>, cudaFuncAttributePreferredSharedMemoryCarveout, 100);

    knn_kernel<K><<<grid, block, static_cast<size_t>(shared_bytes)>>>(
        query, query_count, data, data_count, result, batch_points);

    // Surface launch/configuration errors without forcing device synchronization.
    (void)cudaPeekAtLastError();
}

}  // namespace knn2d_internal

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    auto* raw_result = reinterpret_cast<knn2d_internal::ResultPairRaw*>(result);

    // Dispatch on K so the compiler sees fixed-size warp-private top-k storage.
    switch (k) {
        case 32:
            knn2d_internal::launch_knn_kernel<32>(
                query, query_count, data, data_count, raw_result);
            break;
        case 64:
            knn2d_internal::launch_knn_kernel<64>(
                query, query_count, data, data_count, raw_result);
            break;
        case 128:
            knn2d_internal::launch_knn_kernel<128>(
                query, query_count, data, data_count, raw_result);
            break;
        case 256:
            knn2d_internal::launch_knn_kernel<256>(
                query, query_count, data, data_count, raw_result);
            break;
        case 512:
            knn2d_internal::launch_knn_kernel<512>(
                query, query_count, data, data_count, raw_result);
            break;
        case 1024:
            knn2d_internal::launch_knn_kernel<1024>(
                query, query_count, data, data_count, raw_result);
            break;
        default:
            // The problem statement guarantees a valid power-of-two K in [32, 1024].
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>
#include <cstdint>

/*
  Optimized warp-per-query 2D k-NN for squared Euclidean distance.

  Key design choices, matching the requested algorithmic structure:
  - One warp (32 threads) owns one query.
  - The intermediate top-k result is kept privately by that warp in registers:
      each lane stores K/32 sorted neighbors.
  - Each warp/query also owns:
      * a shared-memory candidate buffer of size K,
      * a shared shared-memory integer counter for the current candidate count.
  - Input data are processed in block-wide shared-memory tiles.
  - Distances are filtered against max_distance (current k-th neighbor distance).
  - Admitted candidates use atomicAdd on the per-warp shared counter to reserve slots.
  - When the candidate buffer becomes full, the warp merges it with the private top-k.
  - Final leftover candidates are merged after the last data tile.
  - No extra device/global memory is allocated.

  Merge strategy:
  - The candidate buffer is unsorted by construction.
  - On merge, the current sorted top-k is staged to shared memory.
  - The candidate buffer is sorted in shared memory with a warp-parallel bitonic sort
    (K is guaranteed to be a power of two).
  - The two sorted K-length arrays are then merged with a warp-parallel merge-path
    partitioning, keeping only the smallest K elements back in registers.

  Tuning:
  - 8 warps/block (256 threads): good balance between data-tile reuse and occupancy.
  - 2048-point shared-memory tiles: 16 KiB tile, still fits alongside the largest
    K=1024 per-warp scratch on A100/H100-class GPUs using opt-in dynamic shared memory.
*/

namespace {

constexpr int kWarpSize                 = 32;
constexpr int kWarpsPerBlock            = 8;
constexpr int kThreadsPerBlock          = kWarpsPerBlock * kWarpSize;
constexpr int kTilePoints               = 2048;
constexpr std::size_t kMaxOptInSmemB    = 163840;  // A100/H100-class opt-in per-block limit.

static_assert(kThreadsPerBlock <= 1024, "Invalid block size.");
static_assert((kTilePoints % kWarpSize) == 0, "Tile size must be a multiple of warp size.");

struct alignas(8) NeighborPair {
    float dist;
    int   idx;
};

static_assert(sizeof(NeighborPair) == 8, "Unexpected NeighborPair layout.");

template <typename T>
__host__ __device__ __forceinline__ constexpr std::size_t align_up_size(std::size_t x) {
    return (x + alignof(T) - 1) & ~(std::size_t(alignof(T)) - 1);
}

template <typename T>
__host__ __device__ __forceinline__ constexpr std::uintptr_t align_up_ptr(std::uintptr_t x) {
    return (x + alignof(T) - 1) & ~(std::uintptr_t(alignof(T)) - 1);
}

template <int K>
__host__ __device__ __forceinline__ constexpr std::size_t dynamic_shared_bytes() {
    std::size_t bytes = 0;
    bytes = align_up_size<float2>(bytes);
    bytes += std::size_t(kTilePoints) * sizeof(float2);
    bytes = align_up_size<NeighborPair>(bytes);
    bytes += std::size_t(kWarpsPerBlock) * std::size_t(K) * sizeof(NeighborPair);  // candidate buffers
    bytes = align_up_size<NeighborPair>(bytes);
    bytes += std::size_t(kWarpsPerBlock) * std::size_t(K) * sizeof(NeighborPair);  // merge scratch for top-k
    return bytes;
}

static_assert(dynamic_shared_bytes<1024>() <= kMaxOptInSmemB,
              "Worst-case shared-memory footprint exceeds the target GPU limit.");

__device__ __forceinline__ bool pair_less(const NeighborPair& a, const NeighborPair& b) {
    // Total order: distance first, index second. Ties are unconstrained by the prompt,
    // but a total order keeps the sort/merge deterministic and well-defined.
    return (a.dist < b.dist) || ((a.dist == b.dist) && (a.idx < b.idx));
}

__device__ __forceinline__ bool pair_less_equal(const NeighborPair& a, const NeighborPair& b) {
    return !pair_less(b, a);
}

template <int K>
__device__ __forceinline__ int merge_path_search(const NeighborPair* a,
                                                 const NeighborPair* b,
                                                 int diag) {
    // Standard merge-path partition on the diagonal "diag" for two sorted arrays
    // of equal length K. Returns how many items are taken from 'a' in the first
    // 'diag' output elements.
    int low  = (diag > K) ? (diag - K) : 0;
    int high = (diag < K) ? diag : K;

    while (low < high) {
        const int mid = (low + high) >> 1;
        // Compare b[diag - 1 - mid] < a[mid]
        if (pair_less(b[diag - 1 - mid], a[mid])) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

template <int K>
__device__ __forceinline__ void bitonic_sort_shared(NeighborPair* vals, int lane) {
    // Warp-parallel bitonic sort over K elements in shared memory.
    // K is a power of two in [32, 1024].
    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int i = lane; i < K; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    NeighborPair a = vals[i];
                    NeighborPair b = vals[j];
                    const bool ascending = ((i & size) == 0);
                    const bool do_swap   = ascending ? pair_less(b, a) : pair_less(a, b);
                    if (do_swap) {
                        vals[i] = b;
                        vals[j] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

template <int K>
__device__ __forceinline__ void merge_buffer(NeighborPair* cand,
                                             NeighborPair* top_smem,
                                             int count,
                                             int lane,
                                             NeighborPair (&top)[K / kWarpSize],
                                             float& max_distance) {
    constexpr int ITEMS_PER_LANE = K / kWarpSize;

    // 1) Stage the current sorted top-k from registers to shared memory.
#pragma unroll
    for (int i = 0; i < ITEMS_PER_LANE; ++i) {
        top_smem[lane * ITEMS_PER_LANE + i] = top[i];
    }

    // 2) Pad the candidate buffer to length K with +inf sentinels so that the
    //    same fixed-size sort/merge code works for both full and partial buffers.
    for (int pos = count + lane; pos < K; pos += kWarpSize) {
        cand[pos].dist = CUDART_INF_F;
        cand[pos].idx  = INT_MAX;
    }
    __syncwarp();

    // 3) Sort the shared candidate buffer.
    bitonic_sort_shared<K>(cand, lane);

    // 4) Merge the sorted current top-k and the sorted candidate buffer.
    //    Each lane owns a contiguous output segment of length ITEMS_PER_LANE.
    const int out_begin = lane * ITEMS_PER_LANE;
    const int out_end   = out_begin + ITEMS_PER_LANE;

    const int a_begin = merge_path_search<K>(top_smem, cand, out_begin);
    const int a_end   = merge_path_search<K>(top_smem, cand, out_end);

    int ai            = a_begin;
    int bi            = out_begin - a_begin;
    const int a_limit = a_end;
    const int b_limit = out_end - a_end;

#pragma unroll
    for (int i = 0; i < ITEMS_PER_LANE; ++i) {
        const bool take_a =
            (bi >= b_limit) ||
            ((ai < a_limit) && pair_less_equal(top_smem[ai], cand[bi]));
        top[i] = take_a ? top_smem[ai++] : cand[bi++];
    }

    // The k-th smallest entry is the last one, owned by lane 31.
    const float lane_last = top[ITEMS_PER_LANE - 1].dist;
    max_distance = __shfl_sync(0xFFFFFFFFu, lane_last, kWarpSize - 1);
}

template <int K>
__launch_bounds__(kThreadsPerBlock)
__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           std::pair<int, float>* __restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= 32 && K <= 1024, "K out of supported range.");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");

    constexpr int ITEMS_PER_LANE = K / kWarpSize;

    const int lane      = threadIdx.x & (kWarpSize - 1);
    const int warp      = threadIdx.x >> 5;
    const int query_idx = int(blockIdx.x) * kWarpsPerBlock + warp;
    const bool active   = (query_idx < query_count);

    // Lower-lane bit mask used to rank candidates inside a warp chunk.
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    // Tiny shared state that is truly static: one candidate count per warp/query.
    // Large arrays remain dynamic shared memory so we can opt-in above 48 KiB.
    __shared__ int s_count[kWarpsPerBlock];

    extern __shared__ unsigned char shared_raw[];
    std::uintptr_t smem = align_up_ptr<float2>(reinterpret_cast<std::uintptr_t>(shared_raw));

    float2* s_data = reinterpret_cast<float2*>(smem);
    smem += std::size_t(kTilePoints) * sizeof(float2);

    smem = align_up_ptr<NeighborPair>(smem);
    NeighborPair* s_cand = reinterpret_cast<NeighborPair*>(smem);
    smem += std::size_t(kWarpsPerBlock) * std::size_t(K) * sizeof(NeighborPair);

    smem = align_up_ptr<NeighborPair>(smem);
    NeighborPair* s_top = reinterpret_cast<NeighborPair*>(smem);

    NeighborPair* cand     = s_cand + std::size_t(warp) * K;
    NeighborPair* top_smem = s_top  + std::size_t(warp) * K;

    // Private intermediate top-k in registers, kept globally sorted.
    NeighborPair top[ITEMS_PER_LANE];
#pragma unroll
    for (int i = 0; i < ITEMS_PER_LANE; ++i) {
        top[i].dist = CUDART_INF_F;
        top[i].idx  = INT_MAX;
    }

    float max_distance = CUDART_INF_F;

    if (lane == 0) {
        s_count[warp] = 0;
    }
    __syncthreads();

    // Load the query once per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(0xFFFFFFFFu, qx, 0);
    qy = __shfl_sync(0xFFFFFFFFu, qy, 0);

    // Iterate over the dataset in shared-memory tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += kTilePoints) {
        const int remaining = data_count - tile_start;
        const int tile_count = (remaining < kTilePoints) ? remaining : kTilePoints;

        // Block-wide cooperative load of the current data tile into shared memory.
        for (int i = threadIdx.x; i < tile_count; i += kThreadsPerBlock) {
            s_data[i] = data[tile_start + i];
        }
        __syncthreads();

        if (active) {
            // Process the shared tile in warp-sized chunks of 32 points.
            //
            // This is important: because K >= 32, each lane holds at most one
            // "pending" candidate per chunk. If the shared candidate buffer is
            // nearly full, we can fill the remaining slots, merge once, and then
            // reconsider only the leftover lanes from this same 32-point chunk.
            for (int base = 0; base < tile_count; base += kWarpSize) {
                NeighborPair candidate;
                candidate.dist = 0.0f;
                candidate.idx  = 0;
                bool pending   = false;

                const int local = base + lane;
                if (local < tile_count) {
                    const float2 p = s_data[local];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;

                    // Squared Euclidean distance; no sqrt, as requested.
                    candidate.dist = fmaf(dx, dx, dy * dy);
                    candidate.idx  = tile_start + local;

                    // Strict '<' is sufficient because ties may be resolved arbitrarily.
                    pending = (candidate.dist < max_distance);
                }

                while (true) {
                    const unsigned pending_mask = __ballot_sync(0xFFFFFFFFu, pending);
                    if (pending_mask == 0u) {
                        break;
                    }

                    const int current_count = s_count[warp];
                    const int free_slots    = K - current_count;
                    const int hit_count     = __popc(pending_mask);

                    if (hit_count <= free_slots) {
                        // Everything fits into the candidate buffer.
                        // Use atomicAdd exactly as requested to reserve per-candidate slots.
                        if (pending) {
                            const int slot = atomicAdd(&s_count[warp], 1);
                            cand[slot] = candidate;
                        }
                        __syncwarp();

                        // If this insertion made the buffer full, merge immediately.
                        if (s_count[warp] == K) {
                            merge_buffer<K>(cand, top_smem, K, lane, top, max_distance);
                            if (lane == 0) {
                                s_count[warp] = 0;
                            }
                            __syncwarp();
                        }
                        break;
                    } else {
                        // Not everything fits. Keep the first 'free_slots' pending lanes
                        // (ranked by lane id), fill the buffer, merge, then re-test the
                        // leftover lanes against the new, tighter max_distance.
                        const int rank     = __popc(pending_mask & lane_mask_lt);
                        const bool take_now = pending && (rank < free_slots);

                        if (take_now) {
                            const int slot = atomicAdd(&s_count[warp], 1);
                            cand[slot] = candidate;
                        }
                        __syncwarp();

                        // By construction, the buffer is now exactly full.
                        merge_buffer<K>(cand, top_smem, K, lane, top, max_distance);
                        if (lane == 0) {
                            s_count[warp] = 0;
                        }
                        __syncwarp();

                        // Only leftover lanes survive, and only if they still beat the
                        // updated kth-distance threshold.
                        pending = pending && !take_now && (candidate.dist < max_distance);
                    }
                }
            }
        }

        // All warps must finish reading the tile before the next block-wide load.
        __syncthreads();
    }

    // Final merge of any leftover partial candidate buffer.
    if (active) {
        const int final_count = s_count[warp];
        if (final_count > 0) {
            merge_buffer<K>(cand, top_smem, final_count, lane, top, max_distance);
        }

        // Store the final sorted top-k for this query.
        // Write fields directly instead of constructing std::pair on device.
        const std::size_t out_base =
            std::size_t(query_idx) * std::size_t(K) +
            std::size_t(lane) * std::size_t(ITEMS_PER_LANE);

#pragma unroll
        for (int i = 0; i < ITEMS_PER_LANE; ++i) {
            result[out_base + std::size_t(i)].first  = top[i].idx;
            result[out_base + std::size_t(i)].second = top[i].dist;
        }
    }
}

template <int K>
void launch_knn_specialization(const float2* query,
                               int query_count,
                               const float2* data,
                               int data_count,
                               std::pair<int, float>* result) {
    constexpr std::size_t smem_bytes = dynamic_shared_bytes<K>();
    static_assert(smem_bytes <= kMaxOptInSmemB, "Shared-memory requirement too large.");

    // Required to opt in above the legacy 48 KiB dynamic shared-memory limit.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));

    // This kernel is shared-memory heavy by design; prefer shared over L1.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(kThreadsPerBlock, 1, 1);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock, 1, 1);

    // Asynchronous launch on the current stream (default-stream semantics here).
    knn_kernel<K><<<grid, block, smem_bytes>>>(query, query_count, data, data_count, result);

    // Surface launch-configuration/shared-memory errors early without synchronizing.
    (void)cudaPeekAtLastError();
}

}  // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Compile-time dispatch keeps K static, which is essential here:
    // - register storage is K/32 per lane,
    // - the candidate sort is specialized for each power-of-two K,
    // - merge scratch size is fixed and known to the compiler.
    switch (k) {
        case 32:   launch_knn_specialization<32>(query, query_count, data, data_count, result);   return;
        case 64:   launch_knn_specialization<64>(query, query_count, data, data_count, result);   return;
        case 128:  launch_knn_specialization<128>(query, query_count, data, data_count, result);  return;
        case 256:  launch_knn_specialization<256>(query, query_count, data, data_count, result);  return;
        case 512:  launch_knn_specialization<512>(query, query_count, data, data_count, result);  return;
        case 1024: launch_knn_specialization<1024>(query, query_count, data, data_count, result); return;
        default:
            // Per the problem statement, k is always valid.
            return;
    }
}

#include <cuda_runtime.h>

#include <climits>
#include <cstddef>
#include <utility>

/*
  Optimized warp-centric k-NN for 2D float points.

  Key design choices:
  - One warp computes one query.
  - The intermediate top-k for a query is warp-private and distributed across the 32 lanes:
      each lane owns K/32 (distance, index) pairs in registers.
  - Each warp also owns a K-entry candidate buffer in shared memory plus a shared counter.
  - The whole block streams the dataset through a shared-memory tile so that every loaded
    data point is reused by all warps in the block.
  - Candidate insertion uses a warp-aggregated atomicAdd on the per-warp shared counter,
    exactly as requested, to reserve contiguous slots in the candidate buffer.
  - Whenever the candidate buffer reaches K entries, it is merged with the warp-private
    intermediate result and max_distance is refreshed from the current k-th neighbor.
  - K is specialized at compile time for the only legal values {32,64,128,256,512,1024}
    so that the warp-private top-k stays in registers and merge/search loop bounds are known.
*/

namespace {

constexpr int WARP_THREADS     = 32;
constexpr unsigned FULL_MASK   = 0xFFFFFFFFu;

/*
  1024-point tiles keep the shared-memory footprint under the default 48 KiB dynamic
  shared-memory budget for all launch configurations used below:

    K <= 512 : 8 warps/block
    K = 1024 : 4 warps/block

  That avoids any need for dynamic shared-memory attribute tuning while still amortizing
  block-wide tile loads over multiple queries.
*/
constexpr int DATA_TILE_POINTS = 1024;

/*
  The public interface uses std::pair<int,float>. Device code writes a layout-compatible
  POD instead of depending on device availability of std::pair operations.
*/
struct PairIF {
    int   first;
    float second;
};

static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>),
              "std::pair<int,float> is not 8 bytes on this platform.");

template <int N>
struct StaticLog2 {
    static constexpr int value = 1 + StaticLog2<(N >> 1)>::value;
};

template <>
struct StaticLog2<1> {
    static constexpr int value = 0;
};

struct DistIndex {
    float dist;
    int   idx;
};

__device__ __forceinline__ DistIndex make_pos_inf()
{
    DistIndex v;
    v.dist = CUDART_INF_F;
    v.idx  = INT_MAX;
    return v;
}

__device__ __forceinline__ DistIndex make_neg_inf()
{
    DistIndex v;
    v.dist = -CUDART_INF_F;
    v.idx  = INT_MIN;
    return v;
}

/*
  Deterministic total order used only inside sort/merge.
  The user only requires max_distance to be the distance of the k-th neighbor, so the
  filter still uses strict "dist < max_distance" as requested; ties do not need special
  handling there.
*/
__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib)
{
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool pair_less(const DistIndex &a, const DistIndex &b)
{
    return pair_less(a.dist, a.idx, b.dist, b.idx);
}

/*
  Fetch an arbitrary element from the warp-distributed top-k array.
  Position p is owned by lane (p mod 32), slot (p / 32).
*/
__device__ __forceinline__ DistIndex warp_get_top(const float *top_dist, const int *top_idx, int pos)
{
    const int lane  = threadIdx.x & (WARP_THREADS - 1);
    const int owner = pos & (WARP_THREADS - 1);
    const int slot  = pos >> 5;

    float d = (lane == owner) ? top_dist[slot] : 0.0f;
    int   i = (lane == owner) ? top_idx[slot]  : 0;

    DistIndex v;
    v.dist = __shfl_sync(FULL_MASK, d, owner);
    v.idx  = __shfl_sync(FULL_MASK, i, owner);
    return v;
}

__device__ __forceinline__ DistIndex cand_get(const float *cand_dist, const int *cand_idx, int pos)
{
    DistIndex v;
    v.dist = cand_dist[pos];
    v.idx  = cand_idx[pos];
    return v;
}

/*
  Bitonic sort of the per-warp candidate buffer in shared memory.

  Only one warp touches each buffer, so warp-wide barriers are sufficient.
  The buffer is padded with +inf sentinels up to K so the whole sort/merge path can
  operate on fixed-size power-of-two arrays.
*/
template <int K>
__device__ __forceinline__ void sort_candidate_buffer(float *cand_dist, int *cand_idx, int count)
{
    const int lane = threadIdx.x & (WARP_THREADS - 1);

    for (int pos = lane; pos < K; pos += WARP_THREADS) {
        if (pos >= count) {
            cand_dist[pos] = CUDART_INF_F;
            cand_idx[pos]  = INT_MAX;
        }
    }
    __syncwarp(FULL_MASK);

#pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int pos = lane; pos < K; pos += WARP_THREADS) {
                const int partner = pos ^ stride;

                if (pos < partner) {
                    const float a_d = cand_dist[pos];
                    const int   a_i = cand_idx[pos];
                    const float b_d = cand_dist[partner];
                    const int   b_i = cand_idx[partner];

                    const bool up   = ((pos & size) == 0);
                    const bool swap = up ? pair_less(b_d, b_i, a_d, a_i)
                                         : pair_less(a_d, a_i, b_d, b_i);

                    if (swap) {
                        cand_dist[pos]     = b_d;
                        cand_idx[pos]      = b_i;
                        cand_dist[partner] = a_d;
                        cand_idx[partner]  = a_i;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
}

/*
  Return merged rank p from:
    A = current warp-private sorted top-k
    B = shared-memory sorted candidate buffer (padded to K with +inf)

  This uses a fixed-iteration binary search so that every lane executes the same shuffle
  sequence; that keeps warp shuffles well-defined even though the search decisions are lane-
  dependent.
*/
template <int K>
__device__ __forceinline__ DistIndex merged_rank(const float *top_dist,
                                                 const int   *top_idx,
                                                 const float *cand_dist,
                                                 const int   *cand_idx,
                                                 int p)
{
    constexpr int LOG2_K = StaticLog2<K>::value;

    int low  = 0;
    int high = p;

#pragma unroll
    for (int iter = 0; iter < LOG2_K + 1; ++iter) {
        const int i = (low + high) >> 1;
        const int j = p - i;

        const DistIndex a_im1 = (i > 0) ? warp_get_top(top_dist, top_idx, i - 1) : make_neg_inf();
        const DistIndex a_i   = warp_get_top(top_dist, top_idx, i);
        const DistIndex b_j   = cand_get(cand_dist, cand_idx, j);
        const DistIndex b_jm1 = (j > 0) ? cand_get(cand_dist, cand_idx, j - 1) : make_neg_inf();

        const bool go_left  = pair_less(b_j, a_im1);  // a[i-1] > b[j]
        const bool go_right = (!go_left) && pair_less(a_i, b_jm1); // b[j-1] > a[i]
        const bool found    = !(go_left || go_right);

        low  = found ? i : (go_right ? (i + 1) : low);
        high = found ? i : (go_left  ? (i - 1) : high);
    }

    const int i = low;
    const int j = p - i;

    const DistIndex a_i = warp_get_top(top_dist, top_idx, i);
    const DistIndex b_j = cand_get(cand_dist, cand_idx, j);

    return pair_less(b_j, a_i) ? b_j : a_i;
}

/*
  Merge the shared candidate buffer with the warp-private top-k.

  Important optimization:
  - The merge writes output ranks from high to low.
  - Output rank p only depends on input ranks <= p.
  - Therefore, higher slots can be overwritten in place without needing a second K-sized
    warp-private array.

  A warp barrier is placed before each slot-group write to ensure every lane has finished
  reading the old values from the current slot-group.
*/
template <int K>
__device__ __forceinline__ void merge_candidate_buffer(float *top_dist,
                                                       int   *top_idx,
                                                       float *cand_dist,
                                                       int   *cand_idx,
                                                       int   *cand_count,
                                                       float &max_distance)
{
    constexpr int ITEMS_PER_LANE = K / WARP_THREADS;

    const int lane = threadIdx.x & (WARP_THREADS - 1);

    int count = (lane == 0) ? *cand_count : 0;
    count = __shfl_sync(FULL_MASK, count, 0);

    if (count == 0) {
        return;
    }

    sort_candidate_buffer<K>(cand_dist, cand_idx, count);

    for (int slot = ITEMS_PER_LANE - 1; slot >= 0; --slot) {
        const int p = (slot << 5) + lane;
        const DistIndex out = merged_rank<K>(top_dist, top_idx, cand_dist, cand_idx, p);

        __syncwarp(FULL_MASK);
        top_dist[slot] = out.dist;
        top_idx[slot]  = out.idx;
    }

    /*
      The k-th neighbor is always position K-1, which belongs to lane 31 and the last slot
      because K is a multiple of 32.
    */
    max_distance = __shfl_sync(FULL_MASK, top_dist[ITEMS_PER_LANE - 1], WARP_THREADS - 1);

    if (lane == 0) {
        *cand_count = 0;
    }
    __syncwarp(FULL_MASK);
}

/*
  Insert at most one candidate per lane for the current 32-point chunk.

  The caller already computed the initial pending mask with __ballot_sync.
  We reserve buffer space with a single warp-aggregated atomicAdd on the per-warp shared
  counter, then use per-lane ranks inside that reservation to write candidates contiguously.

  If the reservation fills or overflows the buffer, the buffer is merged immediately so
  max_distance stays current, exactly as requested.
*/
template <int K>
__device__ __forceinline__ void insert_candidate_group(unsigned pending_mask,
                                                       bool pending,
                                                       int candidate_idx,
                                                       float candidate_dist,
                                                       float *top_dist,
                                                       int   *top_idx,
                                                       float *cand_dist,
                                                       int   *cand_idx,
                                                       int   *cand_count,
                                                       float &max_distance)
{
    const int lane = threadIdx.x & (WARP_THREADS - 1);
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    while (pending_mask != 0u) {
        const int pending_count = __popc(pending_mask);

        int base = 0;
        if (lane == 0) {
            base = atomicAdd(cand_count, pending_count);
        }
        base = __shfl_sync(FULL_MASK, base, 0);

        const int rank = __popc(pending_mask & lane_mask_lt);

        int take = 0;
        if (base < K) {
            const int space = K - base;
            take = (pending_count < space) ? pending_count : space;
        }

        if (pending && rank < take) {
            const int pos = base + rank;
            cand_dist[pos] = candidate_dist;
            cand_idx[pos]  = candidate_idx;
        }

        __syncwarp(FULL_MASK);

        /*
          If the buffer is not yet full, we are done for this chunk.
          If it became exactly full or overflowed, we force a merge now.
        */
        if (base + pending_count < K) {
            break;
        }

        if (lane == 0) {
            *cand_count = K;
        }
        __syncwarp(FULL_MASK);

        merge_candidate_buffer<K>(top_dist, top_idx, cand_dist, cand_idx, cand_count, max_distance);

        /*
          Candidates that overflowed the full buffer are reconsidered against the updated
          max_distance. This can discard many of them immediately after the merge.
        */
        if (base + pending_count == K) {
            pending = false;
        } else {
            pending = pending && (rank >= take) && (candidate_dist < max_distance);
        }

        pending_mask = __ballot_sync(FULL_MASK, pending);
    }
}

template <int K, int BLOCK_WARPS>
constexpr std::size_t shared_bytes_for_kernel()
{
    return std::size_t(DATA_TILE_POINTS) * sizeof(float2) +
           std::size_t(BLOCK_WARPS) * sizeof(int) +
           std::size_t(BLOCK_WARPS) * std::size_t(K) * (sizeof(float) + sizeof(int));
}

template <int K, int BLOCK_WARPS>
__launch_bounds__(BLOCK_WARPS * WARP_THREADS)
__global__ void knn_kernel(const float2 *__restrict__ query,
                           int query_count,
                           const float2 *__restrict__ data,
                           int data_count,
                           PairIF *__restrict__ result)
{
    static_assert((K % WARP_THREADS) == 0, "K must be a multiple of 32.");
    static_assert((BLOCK_WARPS * WARP_THREADS) <= 1024, "Block size exceeds CUDA limit.");

    constexpr int ITEMS_PER_LANE = K / WARP_THREADS;
    constexpr int BLOCK_THREADS  = BLOCK_WARPS * WARP_THREADS;

    const int lane = threadIdx.x & (WARP_THREADS - 1);
    const int warp = threadIdx.x >> 5;

    const int query_idx = static_cast<int>(blockIdx.x) * BLOCK_WARPS + warp;
    const bool active   = (query_idx < query_count);

    /*
      Shared-memory layout:
        [DATA_TILE_POINTS * float2]
        [BLOCK_WARPS * int counters]
        [BLOCK_WARPS * (K floats + K ints) candidate buffers]
    */
    extern __shared__ unsigned char smem[];

    float2 *s_data = reinterpret_cast<float2 *>(smem);

    unsigned char *ptr = reinterpret_cast<unsigned char *>(s_data + DATA_TILE_POINTS);

    int *s_counts = reinterpret_cast<int *>(ptr);
    ptr += std::size_t(BLOCK_WARPS) * sizeof(int);

    constexpr std::size_t PER_WARP_BUFFER_BYTES =
        std::size_t(K) * sizeof(float) + std::size_t(K) * sizeof(int);

    unsigned char *warp_buffer = ptr + std::size_t(warp) * PER_WARP_BUFFER_BYTES;
    float *warp_cand_dist = reinterpret_cast<float *>(warp_buffer);
    int   *warp_cand_idx  = reinterpret_cast<int *>(warp_buffer + std::size_t(K) * sizeof(float));
    int   *warp_count     = s_counts + warp;

    /*
      Warp-private intermediate top-k.
      Each lane owns K/32 entries; together, the warp holds the full sorted top-k.
    */
    float top_dist[ITEMS_PER_LANE];
    int   top_idx[ITEMS_PER_LANE];

#pragma unroll
    for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
        top_dist[slot] = CUDART_INF_F;
        top_idx[slot]  = INT_MAX;
    }

    if (lane == 0) {
        *warp_count = 0;
    }

    /*
      One thread loads the query point and broadcasts it to the whole warp.
    */
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    float max_distance = CUDART_INF_F;

    /*
      Stream the full dataset through a block-shared tile. Every warp reuses the same tile
      for its own query before the block moves to the next batch.
    */
    for (int tile_base = 0; tile_base < data_count; tile_base += DATA_TILE_POINTS) {
        int tile_size = data_count - tile_base;
        if (tile_size > DATA_TILE_POINTS) {
            tile_size = DATA_TILE_POINTS;
        }

#pragma unroll
        for (int load = threadIdx.x; load < DATA_TILE_POINTS; load += BLOCK_THREADS) {
            if (load < tile_size) {
                s_data[load] = data[tile_base + load];
            }
        }

        __syncthreads();

        if (active) {
            /*
              Process the tile in 32-point chunks: lane l handles tile element chunk+l.
              A warp ballot identifies the candidates that beat max_distance, then a single
              atomicAdd reserves contiguous slots in the warp-local shared candidate buffer.
            */
            for (int chunk = 0; chunk < tile_size; chunk += WARP_THREADS) {
                const int local_idx = chunk + lane;

                float dist = 0.0f;
                int data_idx = tile_base + local_idx;
                bool pass = false;

                if (local_idx < tile_size) {
                    const float2 p = s_data[local_idx];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);  // squared L2 distance
                    pass = (dist < max_distance);
                }

                const unsigned pass_mask = __ballot_sync(FULL_MASK, pass);
                if (pass_mask != 0u) {
                    insert_candidate_group<K>(pass_mask,
                                              pass,
                                              data_idx,
                                              dist,
                                              top_dist,
                                              top_idx,
                                              warp_cand_dist,
                                              warp_cand_idx,
                                              warp_count,
                                              max_distance);
                }
            }
        }

        __syncthreads();
    }

    /*
      Flush any partially filled candidate buffer after the last data tile.
    */
    if (active) {
        int count = (lane == 0) ? *warp_count : 0;
        count = __shfl_sync(FULL_MASK, count, 0);

        if (count > 0) {
            merge_candidate_buffer<K>(top_dist,
                                      top_idx,
                                      warp_cand_dist,
                                      warp_cand_idx,
                                      warp_count,
                                      max_distance);
        }

        /*
          The final warp-private top-k is already sorted in ascending distance order.
          Distances are squared Euclidean distances, per the interface contract.
        */
        PairIF *out = result + std::size_t(query_idx) * std::size_t(K);

#pragma unroll
        for (int slot = 0; slot < ITEMS_PER_LANE; ++slot) {
            const int pos = (slot << 5) + lane;
            out[pos].first  = top_idx[slot];
            out[pos].second = top_dist[slot];
        }
    }
}

template <int K, int BLOCK_WARPS>
void launch_knn(const float2 *query,
                int query_count,
                const float2 *data,
                int data_count,
                PairIF *result)
{
    static_assert(shared_bytes_for_kernel<K, BLOCK_WARPS>() <= (48u * 1024u),
                  "Chosen tile/block configuration exceeds the default 48 KiB shared-memory budget.");

    const dim3 block(BLOCK_WARPS * WARP_THREADS);
    const dim3 grid((query_count + BLOCK_WARPS - 1) / BLOCK_WARPS);
    constexpr std::size_t shared_bytes = shared_bytes_for_kernel<K, BLOCK_WARPS>();

    knn_kernel<K, BLOCK_WARPS><<<grid, block, shared_bytes>>>(query,
                                                              query_count,
                                                              data,
                                                              data_count,
                                                              result);
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0) {
        return;
    }

    PairIF *device_result = reinterpret_cast<PairIF *>(result);

    /*
      Dispatch over the only legal K values. The selected block sizes are chosen so that:
      - K <= 512 uses 8 warps/block for good tile reuse and enough blocks for typical
        query counts in the low-thousands on A100/H100-class GPUs.
      - K = 1024 uses 4 warps/block to keep per-thread state and shared-memory usage balanced.
    */
    switch (k) {
        case 32:
            launch_knn<32, 8>(query, query_count, data, data_count, device_result);
            break;
        case 64:
            launch_knn<64, 8>(query, query_count, data, data_count, device_result);
            break;
        case 128:
            launch_knn<128, 8>(query, query_count, data, data_count, device_result);
            break;
        case 256:
            launch_knn<256, 8>(query, query_count, data, data_count, device_result);
            break;
        case 512:
            launch_knn<512, 8>(query, query_count, data, data_count, device_result);
            break;
        case 1024:
            launch_knn<1024, 4>(query, query_count, data, data_count, device_result);
            break;
        default:
            /*
              Per the problem statement this path is unreachable, but keep a silent return
              so the interface remains well-defined even if called incorrectly.
            */
            break;
    }
}

#include <cuda_runtime.h>

#include <climits>
#include <cstddef>
#include <utility>

namespace knn_detail {

// Warp-per-query k-NN for 2D points.
// Design summary:
//   * one warp owns one query;
//   * the intermediate top-k result is warp-private and kept in registers;
//   * each warp also owns a shared-memory candidate buffer of k (index, distance) pairs
//     plus one shared counter updated via atomicAdd;
//   * the whole block cooperatively stages the input data in shared memory batches;
//   * merges are warp-private and use only __syncwarp(), while batch loads use __syncthreads().
//
// Hyper-parameters chosen for A100/H100-class GPUs:
//   * 256 threads/block = 8 warps/block = 8 queries/block;
//   * 2048 data points per shared-memory batch.
//
// With k = 1024, the kernel uses:
//   * 16 KiB static shared memory for the staged data batch,
//   * 64 KiB dynamic shared memory for 8 candidate buffers,
//   * 32 B for the 8 candidate counters.
// Total = 81,952 B/block, which is small enough for the target GPUs while still
// giving 8-way reuse of each staged data point across queries.

constexpr int WARP_LANES       = 32;
constexpr int THREADS_PER_BLOCK = 256;
constexpr int WARPS_PER_BLOCK   = THREADS_PER_BLOCK / WARP_LANES;
constexpr int BATCH_POINTS      = 2048;
constexpr int LOADS_PER_THREAD  = BATCH_POINTS / THREADS_PER_BLOCK;
constexpr unsigned FULL_MASK    = 0xFFFFFFFFu;
constexpr int INVALID_INDEX     = INT_MAX;

static_assert(THREADS_PER_BLOCK % WARP_LANES == 0, "Block size must be a whole number of warps.");
static_assert(BATCH_POINTS % THREADS_PER_BLOCK == 0, "Batch size is chosen to allow a fully unrolled full-batch load path.");

// Device code does not rely on std::pair ABI details directly. Instead it writes a POD with
// the same expected layout. The static_asserts enforce the only properties we need.
struct alignas(alignof(std::pair<int, float>)) PairIF {
    int   first;
    float second;
};

static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>), "std::pair<int,float> must be layout-compatible with {int,float}.");
static_assert(alignof(PairIF) == alignof(std::pair<int, float>), "std::pair<int,float> alignment mismatch.");

template <int K>
constexpr int dynamic_smem_bytes() {
    // Dynamic shared layout:
    //   int   cand_count[WARPS_PER_BLOCK]
    //   int   cand_idx  [WARPS_PER_BLOCK][K]
    //   float cand_dist [WARPS_PER_BLOCK][K]
    return WARPS_PER_BLOCK * static_cast<int>(sizeof(int)) +
           WARPS_PER_BLOCK * K * static_cast<int>(sizeof(int)) +
           WARPS_PER_BLOCK * K * static_cast<int>(sizeof(float));
}

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    // Distances are compared first; index is only a deterministic tie-breaker.
    // The problem statement does not constrain tie handling, so any deterministic
    // policy is acceptable.
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ void compare_swap_shared(float* dist, int* idx, int a, int b, bool ascending) {
    const float da = dist[a];
    const float db = dist[b];
    const int   ia = idx[a];
    const int   ib = idx[b];

    const bool do_swap = ascending ? pair_less(db, ib, da, ia)
                                   : pair_less(da, ia, db, ib);

    if (do_swap) {
        dist[a] = db;
        idx[a]  = ib;
        dist[b] = da;
        idx[b]  = ia;
    }
}

template <int K>
__device__ __forceinline__ void bitonic_sort_shared(float* dist, int* idx, int lane) {
    // Full in-place bitonic sort of K shared-memory pairs.
    // This is only executed when the candidate buffer is merged, i.e. relatively infrequently.
    #pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < K; i += WARP_LANES) {
                const int j = i ^ stride;
                if (j > i) {
                    const bool ascending = ((i & size) == 0);
                    compare_swap_shared(dist, idx, i, j, ascending);
                }
            }
            __syncwarp();
        }
    }
}

template <int K>
__device__ __forceinline__ void bitonic_merge_shared(float* dist, int* idx, int lane) {
    // The first phase of the merge creates the low half as a bitonic sequence.
    // This function performs only the bitonic-merge half, not a full sort.
    #pragma unroll 1
    for (int stride = K >> 1; stride > 0; stride >>= 1) {
        for (int i = lane; i < K; i += WARP_LANES) {
            const int j = i ^ stride;
            if (j > i) {
                compare_swap_shared(dist, idx, i, j, true);
            }
        }
        __syncwarp();
    }
}

template <int K>
__device__ __forceinline__ void merge_candidates(
    float* cand_dist,
    int* cand_idx,
    int* cand_count_ptr,
    int lane,
    int count,
    float (&local_dist)[K / WARP_LANES],
    int (&local_idx)[K / WARP_LANES],
    float& max_distance)
{
    constexpr int LOCAL_K = K / WARP_LANES;

    // Pad the inactive part of the candidate buffer with (+inf, INVALID_INDEX) so that the
    // full K-wide bitonic sort can be reused even when the buffer is only partially filled.
    for (int pos = lane; pos < K; pos += WARP_LANES) {
        if (pos >= count) {
            cand_dist[pos] = CUDART_INF_F;
            cand_idx[pos]  = INVALID_INDEX;
        }
    }
    __syncwarp();

    // Candidate buffer -> ascending order.
    bitonic_sort_shared<K>(cand_dist, cand_idx, lane);

    // The current top-k and the candidate list are both ascending.
    // Compare the current top-k against the reversed candidate list:
    //
    //   low[i] = min(topk[i], cand[K-1-i])
    //
    // Those K minima are exactly the K smallest elements of the union, but only in bitonic
    // order. We therefore write that low half back to shared memory and finish with an
    // in-place bitonic merge.
    //
    // The register-resident top-k is stored in an interleaved layout:
    //   lane l owns global positions l, l+32, l+64, ...
    // This layout keeps the shared-memory copies and the final global writes naturally
    // warp-coalesced / bank-friendly.
    int pos = lane;
    #pragma unroll
    for (int t = 0; t < LOCAL_K; ++t, pos += WARP_LANES) {
        const int rev = K - 1 - pos;
        const float bd = cand_dist[rev];
        const int   bi = cand_idx[rev];

        if (pair_less(bd, bi, local_dist[t], local_idx[t])) {
            local_dist[t] = bd;
            local_idx[t]  = bi;
        }
    }

    // All reads from the sorted candidate buffer must complete before any lane overwrites it.
    __syncwarp();

    pos = lane;
    #pragma unroll
    for (int t = 0; t < LOCAL_K; ++t, pos += WARP_LANES) {
        cand_dist[pos] = local_dist[t];
        cand_idx[pos]  = local_idx[t];
    }
    __syncwarp();

    // Bitonic low half -> sorted ascending new top-k.
    bitonic_merge_shared<K>(cand_dist, cand_idx, lane);

    pos = lane;
    #pragma unroll
    for (int t = 0; t < LOCAL_K; ++t, pos += WARP_LANES) {
        local_dist[t] = cand_dist[pos];
        local_idx[t]  = cand_idx[pos];
    }

    // The k-th nearest neighbor lives at global position K-1, i.e. lane 31, local slot LOCAL_K-1.
    const float lane_max = local_dist[LOCAL_K - 1];
    max_distance = __shfl_sync(FULL_MASK, lane_max, WARP_LANES - 1);

    if (lane == 0) {
        *cand_count_ptr = 0;
    }
    __syncwarp();
}

template <int K>
__global__ __launch_bounds__(THREADS_PER_BLOCK, 2)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    PairIF* __restrict__ result)
{
    constexpr int LOCAL_K = K / WARP_LANES;

    const int lane          = threadIdx.x & (WARP_LANES - 1);
    const int warp_in_block = threadIdx.x >> 5;
    const int query_idx     = blockIdx.x * WARPS_PER_BLOCK + warp_in_block;
    const bool active       = (query_idx < query_count);

    // Static shared memory for the staged data batch.
    __shared__ float2 sh_data[BATCH_POINTS];

    // Dynamic shared memory for the per-warp candidate buffers.
    extern __shared__ unsigned char smem_raw[];
    int*   cand_count    = reinterpret_cast<int*>(smem_raw);
    int*   cand_idx_all  = cand_count + WARPS_PER_BLOCK;
    float* cand_dist_all = reinterpret_cast<float*>(cand_idx_all + WARPS_PER_BLOCK * K);

    int*   my_count = cand_count + warp_in_block;
    int*   my_idx   = cand_idx_all + warp_in_block * K;
    float* my_dist  = cand_dist_all + warp_in_block * K;

    if (lane == 0) {
        *my_count = 0;
    }

    // Warp-private intermediate top-k in registers. All entries start as +inf.
    float local_dist[LOCAL_K];
    int   local_idx[LOCAL_K];

    #pragma unroll
    for (int t = 0; t < LOCAL_K; ++t) {
        local_dist[t] = CUDART_INF_F;
        local_idx[t]  = INVALID_INDEX;
    }

    // Broadcast the query point from lane 0 to the whole warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Warp-local shadow of the shared candidate count.
    // The shared variable still exists exactly as requested and is updated via atomicAdd;
    // this mirror just avoids a shared-memory reload at every 32-point tile.
    int count = 0;

    // "filled" tracks how many real neighbors are already present in the intermediate top-k.
    // It is only needed during bootstrap, while max_distance is still +inf.
    int filled = 0;

    float max_distance = CUDART_INF_F;

    for (int batch_start = 0; batch_start < data_count; batch_start += BATCH_POINTS) {
        const int remaining = data_count - batch_start;
        int batch_size = 0;

        // Fast path for the common case: a full 2048-point batch.
        if (remaining >= BATCH_POINTS) {
            batch_size = BATCH_POINTS;
            #pragma unroll
            for (int i = 0; i < LOADS_PER_THREAD; ++i) {
                const int local_offset = threadIdx.x + i * THREADS_PER_BLOCK;
                sh_data[local_offset] = data[batch_start + local_offset];
            }
        } else {
            batch_size = remaining;
            for (int local_offset = threadIdx.x; local_offset < batch_size; local_offset += THREADS_PER_BLOCK) {
                sh_data[local_offset] = data[batch_start + local_offset];
            }
        }

        __syncthreads();

        if (active) {
            // Process the shared batch in warp-sized tiles so that at most 32 new candidates
            // can be appended before the next opportunity to flush/merge.
            for (int tile = 0; tile < batch_size; tile += WARP_LANES) {
                int points_in_tile = batch_size - tile;
                if (points_in_tile > WARP_LANES) {
                    points_in_tile = WARP_LANES;
                }

                // Flush before the next tile if the private candidate buffer cannot safely accept
                // all points from that tile.
                if (count > K - points_in_tile) {
                    merge_candidates<K>(my_dist, my_idx, my_count, lane, count, local_dist, local_idx, max_distance);
                    filled += count;
                    if (filled > K) {
                        filled = K;
                    }
                    count = 0;
                }

                float dist = 0.0f;
                int data_idx = 0;
                bool accept = false;

                if (lane < points_in_tile) {
                    data_idx = batch_start + tile + lane;
                    const float2 p = sh_data[tile + lane];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                    accept = (dist < max_distance);
                }

                // Warp-aggregated candidate insertion:
                // one atomicAdd reserves a contiguous range, and each accepting lane computes
                // its own position via a prefix within the ballot mask.
                const unsigned mask = __ballot_sync(FULL_MASK, accept);
                const int n = __popc(mask);

                int base = 0;
                if (lane == 0 && n > 0) {
                    base = atomicAdd(my_count, n);
                }
                base = __shfl_sync(FULL_MASK, base, 0);

                if (accept) {
                    const unsigned lower_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
                    const int offset = __popc(mask & lower_mask);
                    const int pos = base + offset;

                    // The pre-flush condition guarantees pos < K. The guard is defensive.
                    if (pos < K) {
                        my_idx[pos] = data_idx;
                        my_dist[pos] = dist;
                    }
                }

                // Ensure all candidate writes complete before a possible merge in the next step.
                __syncwarp();

                if (n > 0) {
                    count = base + n;
                }

                // Bootstrap optimization:
                // as soon as the union of the current top-k and the current candidate buffer
                // contains at least K real points, merge immediately so that max_distance
                // becomes finite and aggressive filtering can begin.
                if (filled < K && (filled + count) >= K) {
                    merge_candidates<K>(my_dist, my_idx, my_count, lane, count, local_dist, local_idx, max_distance);
                    filled += count;
                    if (filled > K) {
                        filled = K;
                    }
                    count = 0;
                }
            }
        }

        // The staged data batch is block-shared, so the whole block must finish consuming it
        // before it can be overwritten by the next global-memory batch.
        __syncthreads();
    }

    if (active) {
        // Final leftover candidates, if any.
        if (count > 0) {
            merge_candidates<K>(my_dist, my_idx, my_count, lane, count, local_dist, local_idx, max_distance);
        }

        PairIF* out = result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        // The register layout is already in global sorted order:
        // positions lane, lane+32, lane+64, ...
        int pos = lane;
        #pragma unroll
        for (int t = 0; t < LOCAL_K; ++t, pos += WARP_LANES) {
            out[pos].first  = local_idx[t];
            out[pos].second = local_dist[t];
        }
    }
}

template <int K>
inline void launch_knn_typed(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    const int grid = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    const int smem = dynamic_smem_bytes<K>();

    // Request the large dynamic shared-memory budget needed by the worst-case K values.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        smem);

    // The kernel is intentionally shared-memory heavy; prefer shared memory over L1.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    knn_kernel<K><<<grid, THREADS_PER_BLOCK, smem>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<PairIF*>(result));
}

} // namespace knn_detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    // Standard CUDA behavior: asynchronous launch on the current stream, with no extra device
    // allocations. All inputs are assumed valid as stated by the problem.
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   knn_detail::launch_knn_typed<32>(query, query_count, data, data_count, result);   break;
        case 64:   knn_detail::launch_knn_typed<64>(query, query_count, data, data_count, result);   break;
        case 128:  knn_detail::launch_knn_typed<128>(query, query_count, data, data_count, result);  break;
        case 256:  knn_detail::launch_knn_typed<256>(query, query_count, data, data_count, result);  break;
        case 512:  knn_detail::launch_knn_typed<512>(query, query_count, data, data_count, result);  break;
        case 1024: knn_detail::launch_knn_typed<1024>(query, query_count, data, data_count, result); break;
        default:   break; // k is guaranteed valid by the problem statement.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>
#include <cstdint>

namespace {

// Warp-per-query 2D k-NN for modern data-center NVIDIA GPUs.
//
// Design choices:
// - One warp computes one query exactly as requested.
// - A 256-thread block = 8 warps = 8 queries/block. This is a practical balance:
//   enough inter-query reuse of the shared data tile, while still yielding enough
//   blocks when query_count is only in the low-thousands on ~100+ SM GPUs.
// - A 2048-point data tile is the largest tile that still keeps 2 resident blocks/SM
//   possible for K <= 512 with this block size on A100/H100-class shared-memory budgets.
// - Each warp keeps its current top-k privately in registers as packed 64-bit keys.
// - Each warp owns a shared-memory candidate buffer of exactly k entries plus a shared
//   counter updated via atomicAdd as required.
// - Merge cost is reduced by exploiting the fact that the current top-k is already sorted:
//     1) sort only the candidate buffer,
//     2) reverse it,
//     3) bitonic-merge current-top (ascending) with candidates (descending).
//
// Packed-key optimization:
//   key = (float_bits(distance) << 32) | index
// Distances are squared Euclidean distances and therefore non-negative. For non-negative
// IEEE-754 floats, unsigned integer bit order matches numeric order, so unsigned 64-bit
// comparison on the packed key implements lexicographic ordering by (distance, index).
// This halves shared-memory traffic in compare/swap relative to separate dist/index arrays.

constexpr int kWarpSize       = 32;
constexpr unsigned kFullMask  = 0xffffffffu;
constexpr int kBlockThreads   = 256;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr int kDataTile       = 2048;

constexpr std::size_t kTileBytes  = static_cast<std::size_t>(kDataTile) * sizeof(float2);
constexpr std::size_t kCountBytes = static_cast<std::size_t>(kWarpsPerBlock) * sizeof(unsigned int);

// +inf distance, maximal valid tie-break index.
constexpr std::uint64_t kPackedSentinel =
    (static_cast<std::uint64_t>(0x7f800000u) << 32) | 0x7fffffffu;

// Shared-memory layout uses uint64_t as the base type so the dynamic shared-memory base
// is naturally 8-byte aligned for both float2 tiles and packed keys.
static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a whole number of warps.");
static_assert(kDataTile % kWarpSize == 0, "Tile size must be a whole number of warps.");
static_assert((kTileBytes % alignof(std::uint64_t)) == 0, "Tile must keep packed-key alignment.");
static_assert(((kTileBytes + kCountBytes) % alignof(std::uint64_t)) == 0,
              "Counts must keep packed-key alignment.");

template <int K>
constexpr std::size_t shared_bytes_for_kernel() {
    static_assert(K >= kWarpSize && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");
    return kTileBytes + kCountBytes +
           static_cast<std::size_t>(kWarpsPerBlock) * 2u * static_cast<std::size_t>(K) *
               sizeof(std::uint64_t);
}

// A100/H100-class devices can opt in to this per-block dynamic shared-memory size.
// The chosen configuration stays below the A100 163 KiB per-block opt-in limit.
static_assert(shared_bytes_for_kernel<1024>() <= 166912,
              "Shared-memory configuration exceeds the target per-block limit.");

__device__ __forceinline__ std::uint64_t pack_key(const float dist, const int idx) {
    return (static_cast<std::uint64_t>(__float_as_uint(dist)) << 32) |
           static_cast<std::uint32_t>(idx);
}

__device__ __forceinline__ float unpack_dist(const std::uint64_t key) {
    return __uint_as_float(static_cast<unsigned int>(key >> 32));
}

__device__ __forceinline__ int unpack_idx(const std::uint64_t key) {
    return static_cast<int>(static_cast<std::uint32_t>(key));
}

template <int K>
__device__ __forceinline__
void merge_buffer_into_topk(
    const int lane,
    std::uint64_t (&top)[K / kWarpSize],
    float &max_distance,
    unsigned int &buffer_count,
    unsigned int *const __restrict__ shared_count,
    std::uint64_t *const __restrict__ work)
{
    constexpr int kItemsPerLane = K / kWarpSize;

    // The private top-k is stored in an interleaved lane-major layout:
    //   logical slot = item * 32 + lane
    // This makes staging to/from shared memory naturally coalesced at warp granularity.
#pragma unroll
    for (int item = 0; item < kItemsPerLane; ++item) {
        work[item * kWarpSize + lane] = top[item];
    }

    // Candidate buffer occupies work[K : 2K). Pad the unused tail with sentinels so the
    // sort/merge logic is uniform regardless of the current candidate count.
    for (int pos = lane; pos < K; pos += kWarpSize) {
        if (static_cast<unsigned int>(pos) >= buffer_count) {
            work[K + pos] = kPackedSentinel;
        }
    }
    __syncwarp();

    // Sort only the candidate half (ascending).
#pragma unroll 1
    for (unsigned int size = 2; size <= static_cast<unsigned int>(K); size <<= 1) {
#pragma unroll 1
        for (unsigned int stride = size >> 1; stride > 0; stride >>= 1) {
            for (unsigned int i = static_cast<unsigned int>(lane); i < static_cast<unsigned int>(K); i += kWarpSize) {
                const unsigned int partner = i ^ stride;
                if (partner > i) {
                    const unsigned int a_pos = K + i;
                    const unsigned int b_pos = K + partner;

                    const std::uint64_t a = work[a_pos];
                    const std::uint64_t b = work[b_pos];

                    const bool ascending = ((i & size) == 0u);
                    if (ascending ? (b < a) : (a < b)) {
                        work[a_pos] = b;
                        work[b_pos] = a;
                    }
                }
            }
            __syncwarp();
        }
    }

    // Reverse the candidate half so that [0:K) is ascending and [K:2K) is descending,
    // i.e. the whole 2K sequence is bitonic.
    for (unsigned int i = static_cast<unsigned int>(lane); i < static_cast<unsigned int>(K >> 1); i += kWarpSize) {
        const unsigned int a_pos = K + i;
        const unsigned int b_pos = (2u * static_cast<unsigned int>(K) - 1u) - i;

        const std::uint64_t a = work[a_pos];
        const std::uint64_t b = work[b_pos];
        work[a_pos] = b;
        work[b_pos] = a;
    }
    __syncwarp();

    // Bitonic merge of the already-bitonic 2K sequence into ascending order.
#pragma unroll 1
    for (unsigned int stride = static_cast<unsigned int>(K); stride > 0; stride >>= 1) {
        for (unsigned int i = static_cast<unsigned int>(lane); i < 2u * static_cast<unsigned int>(K); i += kWarpSize) {
            const unsigned int partner = i ^ stride;
            if (partner > i) {
                const std::uint64_t a = work[i];
                const std::uint64_t b = work[partner];
                if (b < a) {
                    work[i] = b;
                    work[partner] = a;
                }
            }
        }
        __syncwarp();
    }

    // Reload the first K logical slots as the new private top-k.
#pragma unroll
    for (int item = 0; item < kItemsPerLane; ++item) {
        top[item] = work[item * kWarpSize + lane];
    }

    // The worst retained distance sits at logical slot K-1, which maps to
    // lane 31, local item (K/32 - 1).
    float tail = 0.0f;
    if (lane == (kWarpSize - 1)) {
        tail = unpack_dist(top[kItemsPerLane - 1]);
    }
    max_distance = __shfl_sync(kFullMask, tail, kWarpSize - 1);

    // Keep the required shared count in sync with the now-empty candidate buffer.
    if (lane == 0) {
        *shared_count = 0u;
    }
    __syncwarp();
    buffer_count = 0u;
}

template <int K>
__device__ __forceinline__
void maybe_insert_candidate(
    const int lane,
    const unsigned int lane_lt_mask,
    const bool valid,
    const float dist,
    const int idx,
    std::uint64_t (&top)[K / kWarpSize],
    float &max_distance,
    unsigned int &buffer_count,
    unsigned int *const __restrict__ shared_count,
    std::uint64_t *const __restrict__ work)
{
    // Strictly lower than max_distance exactly as requested.
    bool accept = valid && (dist < max_distance);
    unsigned int mask = __ballot_sync(kFullMask, accept);
    if (mask == 0u) {
        return;
    }

    unsigned int add = __popc(mask);

    // If the whole warp's accepted points would overflow the candidate buffer,
    // flush the current buffer first, then re-test against the tighter threshold.
    if (buffer_count + add > static_cast<unsigned int>(K)) {
        merge_buffer_into_topk<K>(lane, top, max_distance, buffer_count, shared_count, work);

        accept = valid && (dist < max_distance);
        mask = __ballot_sync(kFullMask, accept);
        if (mask == 0u) {
            return;
        }
        add = __popc(mask);
    }

    // One shared atomicAdd per warp-round reserves a contiguous range of slots;
    // each accepting lane then computes its own offset with a warp-local prefix sum.
    unsigned int base = 0u;
    if (lane == 0) {
        base = atomicAdd(shared_count, add);
    }
    base = __shfl_sync(kFullMask, base, 0);

    if (accept) {
        const unsigned int offset = __popc(mask & lane_lt_mask);
        work[K + base + offset] = pack_key(dist, idx);
    }

    // Needed so a subsequent merge sees all candidate writes.
    __syncwarp();

    buffer_count = base + add;

    // Flush immediately when the buffer becomes full so max_distance tightens as early
    // as possible and later candidates can be rejected cheaply.
    if (buffer_count == static_cast<unsigned int>(K)) {
        merge_buffer_into_topk<K>(lane, top, max_distance, buffer_count, shared_count, work);
    }
}

template <int K>
__global__ __launch_bounds__(kBlockThreads, 1)
void knn_kernel(
    const float2 *const __restrict__ query,
    const int query_count,
    const float2 *const __restrict__ data,
    const int data_count,
    std::pair<int, float> *const __restrict__ result)
{
    constexpr int kItemsPerLane = K / kWarpSize;

    // Dynamic shared-memory layout:
    //   [0, kDataTile)                   : float2 data tile
    //   [kDataTile, kDataTile + warps)   : per-warp candidate counts
    //   [rest]                           : per-warp work area of 2*K packed keys
    //                                      [0:K)   = staged current top-k
    //                                      [K:2K)  = candidate buffer
    extern __shared__ std::uint64_t smem_u64[];

    float2 *const tile = reinterpret_cast<float2 *>(smem_u64);
    unsigned int *const counts = reinterpret_cast<unsigned int *>(tile + kDataTile);
    std::uint64_t *const work_all = reinterpret_cast<std::uint64_t *>(counts + kWarpsPerBlock);

    const int warp_id = threadIdx.x >> 5;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const unsigned int lane_lt_mask = (1u << lane) - 1u;

    const int query_idx = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active = (query_idx < query_count);

    if (lane == 0) {
        counts[warp_id] = 0u;
    }

    // Private per-query intermediate top-k.
    std::uint64_t top[kItemsPerLane];
#pragma unroll
    for (int item = 0; item < kItemsPerLane; ++item) {
        top[item] = kPackedSentinel;
    }

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    std::uint64_t *const work = work_all + static_cast<std::size_t>(warp_id) * (2u * static_cast<std::size_t>(K));
    unsigned int *const shared_count = counts + warp_id;

    unsigned int buffer_count = 0u;
    float max_distance = CUDART_INF_F;

    for (int tile_base = 0; tile_base < data_count; tile_base += kDataTile) {
        const int remaining = data_count - tile_base;
        const int tile_count = (remaining < kDataTile) ? remaining : kDataTile;

        // Cooperative load of the next data tile by the whole block.
        for (int i = threadIdx.x; i < tile_count; i += kBlockThreads) {
            tile[i] = data[tile_base + i];
        }
        __syncthreads();

        if (active) {
            // Warp collectives require all 32 lanes to participate with the same mask.
            // Therefore the tile is processed in warp-sized rounds and invalid lanes
            // on the partial tail simply contribute accept=false.
            const int rounds = (tile_count + kWarpSize - 1) / kWarpSize;
#pragma unroll 1
            for (int round = 0; round < rounds; ++round) {
                const int j = round * kWarpSize + lane;
                const bool valid = (j < tile_count);

                float dist = 0.0f;
                if (valid) {
                    const float2 p = tile[j];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = __fmaf_rn(dx, dx, dy * dy);
                }

                maybe_insert_candidate<K>(
                    lane,
                    lane_lt_mask,
                    valid,
                    dist,
                    tile_base + j,
                    top,
                    max_distance,
                    buffer_count,
                    shared_count,
                    work);
            }
        }

        // Prevent any warp from overwriting the shared tile while other warps still use it.
        __syncthreads();
    }

    if (active) {
        if (buffer_count != 0u) {
            merge_buffer_into_topk<K>(lane, top, max_distance, buffer_count, shared_count, work);
        }

        // Coalesced warp write-back of the final sorted top-k.
        const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
#pragma unroll
        for (int item = 0; item < kItemsPerLane; ++item) {
            const std::uint64_t key = top[item];
            const std::size_t pos = out_base + static_cast<std::size_t>(item) * kWarpSize + static_cast<std::size_t>(lane);
            result[pos].first = unpack_idx(key);
            result[pos].second = unpack_dist(key);
        }
    }
}

template <int K>
inline void launch_knn_kernel(
    const float2 *query,
    const int query_count,
    const float2 *data,
    const int data_count,
    std::pair<int, float> *result)
{
    constexpr std::size_t shared_bytes = shared_bytes_for_kernel<K>();

    // Opt in to the larger per-block shared-memory budget used by this kernel.
    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shared_bytes));
    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    knn_kernel<K><<<grid, block, shared_bytes>>>(query, query_count, data, data_count, result);
}

} // namespace

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    // No extra device memory is allocated; all temporary state lives in registers/shared.
    switch (k) {
        case 32:   launch_knn_kernel<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_kernel<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_kernel<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_kernel<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_kernel<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_kernel<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs are specified to be valid.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstdint>
#include <cstddef>

namespace knn_cuda_detail {

// Warp-per-query k-NN for 2D points.
//
// Design summary:
//   * One warp processes one query end-to-end.
//   * The whole block stages a batch of data points in shared memory; every warp reuses it.
//   * Per query, both the current top-k and the candidate buffer live in a warp-private
//     slice of shared memory. This avoids register/local-memory pressure for k up to 1024.
//   * Each logical (distance, index) pair is packed into one sortable 64-bit key:
//       high 32 bits = IEEE-754 bits of the non-negative squared distance
//       low  32 bits = data index
//     Since squared distances are non-negative, ordering by the high 32 bits matches
//     numeric distance ordering. The low 32 bits provide a deterministic tie-break.
//   * Candidate insertion uses one shared-memory atomicAdd per warp-round to reserve a
//     contiguous slot range, then warp ballot/prefix logic scatters accepting lanes into
//     that range. This satisfies the required atomicAdd usage while minimizing atomic traffic.
//   * When the candidate buffer is full (or would overflow), it is merged with the current
//     top-k by an in-place bitonic sort over 2k keys; the first k outputs become the new
//     intermediate result.
//
// Hyper-parameters:
//   * 8 warps/block (256 threads) gives good data reuse for the staged batch.
//   * 2016 staged points/batch = 63 warp-rounds. This is large enough to amortize the
//     block-wide synchronization cost while keeping shared-memory usage favorable across k.
//     For reference, the total shared footprint is about:
//       - k = 512  -> ~79.8 KiB / CTA
//       - k = 1024 -> ~143.8 KiB / CTA
//     which is appropriate for A100/H100-class GPUs with opt-in dynamic shared memory.

constexpr int kWarpSize = 32;
constexpr int kWarpsPerBlock = 8;
constexpr int kThreadsPerBlock = kWarpsPerBlock * kWarpSize;
constexpr int kDataBatchPoints = 2016;

using key_t = unsigned long long;

constexpr unsigned int kInvalidIndex = 0xffffffffu;
constexpr key_t kInvalidKey =
    (static_cast<key_t>(0x7f800000u) << 32) | static_cast<key_t>(kInvalidIndex);

static_assert(kDataBatchPoints % kWarpSize == 0, "Batch size must be a multiple of 32.");

__host__ __device__ constexpr std::size_t align_up(std::size_t value, std::size_t alignment) {
    return (value + alignment - 1) & ~(alignment - 1);
}

template <int K, int WARPS_PER_BLOCK = kWarpsPerBlock, int DATA_BATCH_POINTS = kDataBatchPoints>
__host__ __device__ constexpr std::size_t shared_bytes() {
    std::size_t bytes = 0;
    bytes = align_up(bytes, alignof(float2));
    bytes += static_cast<std::size_t>(DATA_BATCH_POINTS) * sizeof(float2);
    bytes = align_up(bytes, alignof(int));
    bytes += static_cast<std::size_t>(WARPS_PER_BLOCK) * sizeof(int);
    bytes = align_up(bytes, alignof(key_t));
    bytes += static_cast<std::size_t>(WARPS_PER_BLOCK) * static_cast<std::size_t>(2 * K) * sizeof(key_t);
    return bytes;
}

__device__ __forceinline__ key_t pack_key(const float distance, const int index) {
    return (static_cast<key_t>(__float_as_uint(distance)) << 32) |
           static_cast<key_t>(static_cast<unsigned int>(index));
}

__device__ __forceinline__ float unpack_distance(const key_t key) {
    return __uint_as_float(static_cast<unsigned int>(key >> 32));
}

__device__ __forceinline__ int unpack_index(const key_t key) {
    return static_cast<int>(static_cast<unsigned int>(key));
}

// Merge the warp-private candidate buffer with the warp-private current top-k.
// Layout of warp_keys:
//   [0, K)   : current intermediate top-k, sorted ascending by (distance, index)
//   [K, 2K)  : candidate buffer, candidate_count valid entries followed by garbage
//
// The merge is done in place by padding the unused candidate slots with +inf keys and
// running a bitonic sort over the full 2K-key segment. Because 2K is also a power of two,
// the first K entries after sorting are exactly the updated top-k. This keeps the merge
// entirely in shared memory and needs no extra device allocation.
template <int K>
__device__ __forceinline__ float merge_candidate_buffer(key_t* warp_keys,
                                                        int* candidate_count_ptr,
                                                        const int candidate_count) {
    constexpr int N = 2 * K;
    const unsigned mask = 0xffffffffu;
    const int lane = threadIdx.x & (kWarpSize - 1);

    if (candidate_count == 0) {
        return unpack_distance(warp_keys[K - 1]);
    }

    // Pad unused candidate slots with +inf so the 2K-key sort behaves as a merge with
    // invalid elements automatically sinking to the end.
    #pragma unroll
    for (int i = lane + candidate_count; i < K; i += kWarpSize) {
        warp_keys[K + i] = kInvalidKey;
    }
    __syncwarp(mask);

    // Full in-place bitonic sort. K is bounded (<= 1024) and merges are much less frequent
    // than distance evaluations on the intended problem sizes, so this simple no-temp merge
    // strategy performs well while staying compact and robust.
    #pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll 1
            for (int i = lane; i < N; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const key_t a = warp_keys[i];
                    const key_t b = warp_keys[j];
                    const bool up = ((i & size) == 0);
                    if (up ? (a > b) : (a < b)) {
                        warp_keys[i] = b;
                        warp_keys[j] = a;
                    }
                }
            }
            __syncwarp(mask);
        }
    }

    // The buffer has been fully consumed by the merge.
    if (lane == 0) {
        *candidate_count_ptr = 0;
    }
    __syncwarp(mask);

    return unpack_distance(warp_keys[K - 1]);
}

// One warp owns one query from start to finish. The whole block repeatedly stages batches
// of data points into shared memory so that each batch load is reused by every warp in the
// block. The shared-memory state per query is:
//
//   * best_keys[0:K]  : the current intermediate top-k
//   * cand_keys[0:K]  : the candidate buffer
//   * candidate_count : number of currently stored candidates (shared, updated by atomicAdd)
//
// A register mirror of candidate_count is kept in every lane; because reservations are done
// warp-wide with a single atomicAdd, this mirror stays exact and avoids rereading shared
// memory in the hot loop.
template <int K, int WARPS_PER_BLOCK = kWarpsPerBlock, int DATA_BATCH_POINTS = kDataBatchPoints>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize, 1)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                std::pair<int, float>* __restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");

    // Dynamic shared-memory layout:
    //   float2 batch[DATA_BATCH_POINTS]
    //   int    candidate_count[WARPS_PER_BLOCK]
    //   key_t  packed_entries[WARPS_PER_BLOCK][2*K]
    extern __shared__ key_t smem_base[];
    unsigned char* const smem = reinterpret_cast<unsigned char*>(smem_base);

    std::size_t offset = 0;
    offset = align_up(offset, alignof(float2));
    float2* const sh_data = reinterpret_cast<float2*>(smem + offset);
    offset += static_cast<std::size_t>(DATA_BATCH_POINTS) * sizeof(float2);

    offset = align_up(offset, alignof(int));
    int* const sh_candidate_count = reinterpret_cast<int*>(smem + offset);
    offset += static_cast<std::size_t>(WARPS_PER_BLOCK) * sizeof(int);

    offset = align_up(offset, alignof(key_t));
    key_t* const sh_keys = reinterpret_cast<key_t*>(smem + offset);

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp = threadIdx.x >> 5;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active = (query_idx < query_count);
    const unsigned mask = 0xffffffffu;

    key_t* const warp_keys = sh_keys + static_cast<std::size_t>(warp) * static_cast<std::size_t>(2 * K);
    key_t* const best_keys = warp_keys;
    key_t* const cand_keys = warp_keys + K;
    int* const candidate_count_ptr = sh_candidate_count + warp;

    float qx = 0.0f;
    float qy = 0.0f;
    float max_distance = CUDART_INF_F;
    int candidate_count = 0;  // Register mirror of *candidate_count_ptr.

    if (active) {
        float qx_local = 0.0f;
        float qy_local = 0.0f;
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx_local = q.x;
            qy_local = q.y;
        }
        qx = __shfl_sync(mask, qx_local, 0);
        qy = __shfl_sync(mask, qy_local, 0);

        // Start with an all-+inf top-k. max_distance therefore stays +inf until at least
        // K real points have been merged in.
        #pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            best_keys[i] = kInvalidKey;
        }

        if (lane == 0) {
            *candidate_count_ptr = 0;
        }
    }

    // Even inactive warps in the final partial block must participate in the block-level
    // synchronization for shared batch loading.
    __syncthreads();

    for (int data_base = 0; data_base < data_count; data_base += DATA_BATCH_POINTS) {
        int batch_count = data_count - data_base;
        if (batch_count > DATA_BATCH_POINTS) {
            batch_count = DATA_BATCH_POINTS;
        }

        // Cooperative, fully coalesced load of the current data batch into shared memory.
        for (int i = threadIdx.x; i < batch_count; i += blockDim.x) {
            sh_data[i] = data[data_base + i];
        }
        __syncthreads();

        if (active) {
            // Process the batch one warp-sized round at a time. Each lane handles at most
            // one cached point per round.
            for (int round_base = 0; round_base < batch_count; round_base += kWarpSize) {
                const int local_idx = round_base + lane;
                const bool valid = (local_idx < batch_count);
                const int global_idx = data_base + local_idx;

                float dist = 0.0f;
                if (valid) {
                    const float2 p = sh_data[local_idx];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                }

                // Use the current kth distance as the rejection threshold. Strict '<' is
                // intentional and allowed by the specification.
                bool accept = valid && (dist < max_distance);
                unsigned accept_mask = __ballot_sync(mask, accept);
                int num_accept = __popc(accept_mask);

                // If the whole round would overflow the candidate buffer, merge first so the
                // threshold can shrink before any of the round's candidates are committed.
                if (candidate_count + num_accept > K) {
                    max_distance = merge_candidate_buffer<K>(warp_keys, candidate_count_ptr, candidate_count);
                    candidate_count = 0;

                    accept = valid && (dist < max_distance);
                    accept_mask = __ballot_sync(mask, accept);
                    num_accept = __popc(accept_mask);
                }

                if (num_accept != 0) {
                    int base_pos = 0;
                    if (lane == 0) {
                        // One warp-wide reservation atomic per round. This updates the
                        // required shared candidate count and returns the base slot for
                        // all new candidates in the round.
                        base_pos = atomicAdd(candidate_count_ptr, num_accept);
                    }
                    base_pos = __shfl_sync(mask, base_pos, 0);

                    if (accept) {
                        const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);
                        const int rank = __popc(accept_mask & lane_mask_lt);
                        cand_keys[base_pos + rank] = pack_key(dist, global_idx);
                    }

                    candidate_count += num_accept;
                }

                __syncwarp(mask);

                // Merge immediately when the buffer becomes full so max_distance tracks the
                // current kth neighbor as closely as possible.
                if (candidate_count == K) {
                    max_distance = merge_candidate_buffer<K>(warp_keys, candidate_count_ptr, candidate_count);
                    candidate_count = 0;
                }
            }
        }

        // The cached batch is reused by every warp in the block, so no warp may overwrite
        // it with the next batch until all warps are done with the current one.
        __syncthreads();
    }

    if (active) {
        // The problem statement explicitly requires a final merge if the candidate buffer
        // still contains unmerged entries.
        if (candidate_count != 0) {
            max_distance = merge_candidate_buffer<K>(warp_keys, candidate_count_ptr, candidate_count);
            candidate_count = 0;
        }

        (void)max_distance;

        // best_keys is already sorted ascending, so it is already in the required output
        // order. Write std::pair member-wise so no device-side std::pair constructor is needed.
        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            const key_t key = best_keys[i];
            result[out_base + static_cast<std::size_t>(i)].first = unpack_index(key);
            result[out_base + static_cast<std::size_t>(i)].second = unpack_distance(key);
        }
    }
}

template <int K>
inline void launch_knn_impl(const float2* query,
                            int query_count,
                            const float2* data,
                            int data_count,
                            std::pair<int, float>* result) {
    constexpr std::size_t smem_bytes =
        shared_bytes<K, kWarpsPerBlock, kDataBatchPoints>();

    // Opt in to the larger dynamic shared-memory allocation needed by the larger k cases.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, kWarpsPerBlock, kDataBatchPoints>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, kWarpsPerBlock, kDataBatchPoints>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;
    knn_kernel<K, kWarpsPerBlock, kDataBatchPoints>
        <<<blocks, kThreadsPerBlock, smem_bytes>>>(query, query_count, data, data_count, result);
}

}  // namespace knn_cuda_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // k is runtime-valued but comes from a small power-of-two set, so dispatch to
    // compile-time-specialized kernels and keep all k-dependent loop bounds/static layout
    // constants known to the compiler.
    switch (k) {
        case 32:
            knn_cuda_detail::launch_knn_impl<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_cuda_detail::launch_knn_impl<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_cuda_detail::launch_knn_impl<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_cuda_detail::launch_knn_impl<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_cuda_detail::launch_knn_impl<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_cuda_detail::launch_knn_impl<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The caller guarantees k is valid; this is only a defensive fallback.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace {

// One warp computes one query. Eight warps per block gives strong reuse of each
// loaded data batch while still fitting the worst-case k=1024 state in shared
// memory on A100/H100-class parts.
constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 8;
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;
constexpr unsigned FULL_MASK    = 0xffffffffu;

// Total order on (distance, index). The index tie-break is only used to make the
// sorting / merging networks deterministic; tie resolution was otherwise unspecified.
__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool pair_greater(float da, int ia, float db, int ib) {
    return pair_less(db, ib, da, ia);
}

__device__ __forceinline__ void swap_pair(float &da, int &ia, float &db, int &ib) {
    const float td = da;
    const int   ti = ia;
    da = db;
    ia = ib;
    db = td;
    ib = ti;
}

// Shared-memory compare/swap for a single K-element buffer.
__device__ __forceinline__ void compare_swap_shared(
    float *dist, int *idx, int a, int b, bool ascending)
{
    float da = dist[a];
    int   ia = idx[a];
    float db = dist[b];
    int   ib = idx[b];

    const bool do_swap = ascending ? pair_greater(da, ia, db, ib)
                                   : pair_less   (da, ia, db, ib);
    if (do_swap) {
        dist[a] = db;
        idx[a]  = ib;
        dist[b] = da;
        idx[b]  = ia;
    }
}

// Standard bitonic sort for a single K-element shared-memory buffer.
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(float *dist, int *idx, int lane)
{
#pragma unroll
    for (int size = 2; size <= N; size <<= 1) {
#pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const bool ascending = ((i & size) == 0);
                    compare_swap_shared(dist, idx, i, j, ascending);
                }
            }
            __syncwarp();
        }
    }
}

// Helpers to address the combined [best | candidate] 2K-element sequence.
template <int K>
__device__ __forceinline__ void load_combined(
    const float *best_dist, const int *best_idx,
    const float *cand_dist, const int *cand_idx,
    int pos, float &d, int &i)
{
    if (pos < K) {
        d = best_dist[pos];
        i = best_idx[pos];
    } else {
        pos -= K;
        d = cand_dist[pos];
        i = cand_idx[pos];
    }
}

template <int K>
__device__ __forceinline__ void store_combined(
    float *best_dist, int *best_idx,
    float *cand_dist, int *cand_idx,
    int pos, float d, int i)
{
    if (pos < K) {
        best_dist[pos] = d;
        best_idx[pos]  = i;
    } else {
        pos -= K;
        cand_dist[pos] = d;
        cand_idx[pos]  = i;
    }
}

// Reverse the candidate buffer in-place. If best is sorted ascending and candidate
// is sorted ascending, then [best, reverse(candidate)] is bitonic and can be
// merged with an O(K log K) bitonic-merge network instead of a full O(K log^2 K) sort.
template <int K>
__device__ __forceinline__ void reverse_shared(float *dist, int *idx, int lane)
{
    for (int i = lane; i < (K >> 1); i += WARP_SIZE) {
        const int j = K - 1 - i;
        float da = dist[i];
        int   ia = idx[i];
        float db = dist[j];
        int   ib = idx[j];
        dist[i] = db;
        idx[i]  = ib;
        dist[j] = da;
        idx[j]  = ia;
    }
    __syncwarp();
}

// Merge two already-sorted K-element buffers into sorted [best | candidate].
// After completion, the best K elements reside in best_*[0..K-1].
template <int K>
__device__ __forceinline__ void bitonic_merge_two_sorted_shared(
    float *best_dist, int *best_idx,
    float *cand_dist, int *cand_idx,
    int lane)
{
    reverse_shared<K>(cand_dist, cand_idx, lane);

    constexpr int N = 2 * K;
#pragma unroll
    for (int stride = N >> 1; stride > 0; stride >>= 1) {
        for (int i = lane; i < N; i += WARP_SIZE) {
            const int j = i ^ stride;
            if (j > i) {
                float di, dj;
                int   ii, ij;
                load_combined<K>(best_dist, best_idx, cand_dist, cand_idx, i, di, ii);
                load_combined<K>(best_dist, best_idx, cand_dist, cand_idx, j, dj, ij);

                if (pair_greater(di, ii, dj, ij)) {
                    store_combined<K>(best_dist, best_idx, cand_dist, cand_idx, i, dj, ij);
                    store_combined<K>(best_dist, best_idx, cand_dist, cand_idx, j, di, ii);
                }
            }
        }
        __syncwarp();
    }
}

// Merge the shared candidate buffer into the current top-k state.
// The candidate buffer is padded with (+inf, INT_MAX), sorted, and then merged
// with the current best buffer.
template <int K>
__device__ __forceinline__ void merge_candidate_buffer(
    float *best_dist, int *best_idx,
    float *cand_dist, int *cand_idx,
    int *cand_count_ptr,
    float &max_distance,
    int lane)
{
    int count = 0;
    if (lane == 0) count = *cand_count_ptr;
    count = __shfl_sync(FULL_MASK, count, 0);
    if (count == 0) return;

    for (int pos = lane; pos < K; pos += WARP_SIZE) {
        if (pos >= count) {
            cand_dist[pos] = CUDART_INF_F;
            cand_idx[pos]  = INT_MAX;
        }
    }
    __syncwarp();

    bitonic_sort_shared<K>(cand_dist, cand_idx, lane);
    bitonic_merge_two_sorted_shared<K>(best_dist, best_idx, cand_dist, cand_idx, lane);

    if (lane == 0) {
        *cand_count_ptr = 0;
        max_distance = best_dist[K - 1];
    }
    max_distance = __shfl_sync(FULL_MASK, max_distance, 0);
    __syncwarp();
}

// Scan one shared-memory data batch. The candidate slots are reserved with a
// warp-aggregated atomicAdd (still using atomicAdd exactly as requested, but only
// once per 32-point tile instead of once per candidate).
template <int K>
__device__ __forceinline__ void process_batch_points(
    float qx, float qy,
    int batch_global_start,
    int local_begin,
    int local_end,
    const float *batch_x,
    const float *batch_y,
    float *best_dist,
    int *best_idx,
    float *cand_dist,
    int *cand_idx,
    int *cand_count_ptr,
    float &max_distance,
    int lane)
{
    for (int base = local_begin; base < local_end; base += WARP_SIZE) {
        if (max_distance == 0.0f) break;  // squared distances are non-negative

        const int local_pos = base + lane;

        float d = CUDART_INF_F;
        int   idx = -1;
        bool  pass = false;

        if (local_pos < local_end) {
            const float dx = qx - batch_x[local_pos];
            const float dy = qy - batch_y[local_pos];
            d   = fmaf(dx, dx, dy * dy);
            idx = batch_global_start + local_pos;
            pass = (d < max_distance);
        }

        unsigned pass_mask = __ballot_sync(FULL_MASK, pass);
        int hits = __popc(pass_mask);
        if (hits == 0) continue;

        int current_count = 0;
        if (lane == 0) current_count = *cand_count_ptr;
        current_count = __shfl_sync(FULL_MASK, current_count, 0);

        // If the current tile would overflow the candidate buffer, flush the
        // existing candidates first, then re-evaluate the current tile against the
        // tightened max_distance.
        if (current_count + hits > K) {
            merge_candidate_buffer<K>(
                best_dist, best_idx, cand_dist, cand_idx, cand_count_ptr,
                max_distance, lane);

            pass = (local_pos < local_end) && (d < max_distance);
            pass_mask = __ballot_sync(FULL_MASK, pass);
            hits = __popc(pass_mask);
            if (hits == 0) continue;
        }

        int base_slot = 0;
        if (lane == 0) base_slot = atomicAdd(cand_count_ptr, hits);
        base_slot = __shfl_sync(FULL_MASK, base_slot, 0);

        if (pass) {
            const unsigned prior_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
            const int local_rank = __popc(pass_mask & prior_mask);
            const int slot = base_slot + local_rank;
            cand_dist[slot] = d;
            cand_idx[slot]  = idx;
        }

        // Publish the writes before a possible merge on the next line or in the
        // next tile iteration.
        __syncwarp();

        if (base_slot + hits == K) {
            merge_candidate_buffer<K>(
                best_dist, best_idx, cand_dist, cand_idx, cand_count_ptr,
                max_distance, lane);
        }
    }
}

// Kernel layout in shared memory:
// [best_idx][best_dist][cand_idx][cand_dist][cand_count][batch_x][batch_y]
template <int K>
__launch_bounds__(THREADS_PER_BLOCK)
__global__ void knn_kernel(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    std::pair<int, float> * __restrict__ result,
    int batch_capacity)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024]");

    extern __shared__ __align__(16) unsigned char smem_raw[];
    unsigned char *ptr = smem_raw;

    int   *best_idx_all  = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * K * sizeof(int);

    float *best_dist_all = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * K * sizeof(float);

    int   *cand_idx_all  = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * K * sizeof(int);

    float *cand_dist_all = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * K * sizeof(float);

    int   *cand_count    = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * sizeof(int);

    // Shared batch as SoA to avoid 64-bit shared-memory bank effects from float2.
    float *batch_x       = reinterpret_cast<float*>(ptr);
    float *batch_y       = batch_x + batch_capacity;

    const int tid      = threadIdx.x;
    const int lane     = tid & (WARP_SIZE - 1);
    const int warp_id  = tid >> 5;
    const int query_id = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active  = (query_id < query_count);

    float *best_dist = best_dist_all + warp_id * K;
    int   *best_idx  = best_idx_all  + warp_id * K;
    float *cand_dist = cand_dist_all + warp_id * K;
    int   *cand_idx  = cand_idx_all  + warp_id * K;
    int   *cand_count_ptr = cand_count + warp_id;

    if (tid < WARPS_PER_BLOCK) {
        cand_count[tid] = 0;
    }
    __syncthreads();

    float qx = 0.0f;
    float qy = 0.0f;
    float max_distance = CUDART_INF_F;

    if (active) {
        if (lane == 0) {
            const float2 q = query[query_id];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(FULL_MASK, qx, 0);
        qy = __shfl_sync(FULL_MASK, qy, 0);
    }

    constexpr int ITEMS_PER_LANE = K / WARP_SIZE;

    for (int batch_start = 0; batch_start < data_count; batch_start += batch_capacity) {
        int batch_count = data_count - batch_start;
        if (batch_count > batch_capacity) batch_count = batch_capacity;

        for (int i = tid; i < batch_count; i += THREADS_PER_BLOCK) {
            const float2 p = data[batch_start + i];
            batch_x[i] = p.x;
            batch_y[i] = p.y;
        }
        __syncthreads();

        if (active) {
            if (batch_start == 0) {
                // Initialize the private top-k state from the first K points.
#pragma unroll
                for (int t = 0, pos = lane; t < ITEMS_PER_LANE; ++t, pos += WARP_SIZE) {
                    const float dx = qx - batch_x[pos];
                    const float dy = qy - batch_y[pos];
                    best_dist[pos] = fmaf(dx, dx, dy * dy);
                    best_idx[pos]  = pos;
                }
                __syncwarp();

                bitonic_sort_shared<K>(best_dist, best_idx, lane);

                if (lane == 0) {
                    *cand_count_ptr = 0;
                    max_distance = best_dist[K - 1];
                }
                max_distance = __shfl_sync(FULL_MASK, max_distance, 0);

                if (batch_count > K && max_distance > 0.0f) {
                    process_batch_points<K>(
                        qx, qy,
                        batch_start,
                        K,
                        batch_count,
                        batch_x,
                        batch_y,
                        best_dist,
                        best_idx,
                        cand_dist,
                        cand_idx,
                        cand_count_ptr,
                        max_distance,
                        lane);
                }
            } else if (max_distance > 0.0f) {
                process_batch_points<K>(
                    qx, qy,
                    batch_start,
                    0,
                    batch_count,
                    batch_x,
                    batch_y,
                    best_dist,
                    best_idx,
                    cand_dist,
                    cand_idx,
                    cand_count_ptr,
                    max_distance,
                    lane);
            }
        }

        __syncthreads();
    }

    if (active) {
        // Final flush of the candidate buffer.
        merge_candidate_buffer<K>(
            best_dist, best_idx, cand_dist, cand_idx, cand_count_ptr,
            max_distance, lane);

        const std::size_t out_base = static_cast<std::size_t>(query_id) * static_cast<std::size_t>(K);

#pragma unroll
        for (int t = 0, pos = lane; t < ITEMS_PER_LANE; ++t, pos += WARP_SIZE) {
            result[out_base + pos].first  = best_idx[pos];
            result[out_base + pos].second = best_dist[pos];
        }
    }
}

// Shared memory excluding the [batch_x][batch_y] tail.
template <int K>
constexpr std::size_t shared_base_bytes()
{
    return static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(int)   +  // best_idx
           static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(float) +  // best_dist
           static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(int)   +  // cand_idx
           static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(float) +  // cand_dist
           static_cast<std::size_t>(WARPS_PER_BLOCK) * sizeof(int);         // cand_count
}

// Heuristic:
// - If two resident blocks/SM are feasible while still holding at least K batch points,
//   cap the per-block shared memory to ~1/2 of the opt-in maximum.
// - Otherwise, use the full opt-in maximum because occupancy is already limited to 1 block/SM.
template <int K>
inline int choose_batch_capacity(int optin_max_shared_per_block)
{
    const std::size_t optin_max = static_cast<std::size_t>(optin_max_shared_per_block);
    const std::size_t base      = shared_base_bytes<K>();
    const std::size_t min_total = base + static_cast<std::size_t>(K) * 2u * sizeof(float);

    std::size_t total_budget = (2u * min_total <= optin_max) ? (optin_max / 2u) : optin_max;
    if (total_budget < min_total) total_budget = min_total;

    return static_cast<int>((total_budget - base) / (2u * sizeof(float)));
}

template <int K>
inline void launch_knn_impl(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result)
{
    int device = 0;
    cudaGetDevice(&device);

    int optin_max_shared = 0;
    cudaDeviceGetAttribute(&optin_max_shared, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    const int batch_capacity = choose_batch_capacity<K>(optin_max_shared);
    const std::size_t dynamic_smem_bytes =
        shared_base_bytes<K>() + static_cast<std::size_t>(batch_capacity) * 2u * sizeof(float);

    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(dynamic_smem_bytes));

    // This kernel is shared-memory heavy and has little use for L1 compared to its
    // block-wide data reuse in shared memory.
    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(THREADS_PER_BLOCK);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, dynamic_smem_bytes>>>(
        query, query_count, data, data_count, result, batch_capacity);
}

} // namespace

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0) return;

    switch (k) {
        case 32:   launch_knn_impl<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_impl<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_impl<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_impl<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_impl<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_impl<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs were stated to be valid.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <type_traits>

namespace {

// Warp-specialized 2D k-NN.
// Design choices tuned for A100/H100-class GPUs:
//
// * One warp computes one query.
// * The resident top-K list stays in registers, distributed across the 32 lanes.
// * Each warp owns:
//     - a K-entry candidate buffer in shared memory,
//     - a shared mirror of the current top-K used only during sort/merge.
// * The whole block streams the database through shared memory in 1024-point tiles.
// * Candidate insertion uses a warp-aggregated atomicAdd as requested.
// * Merging avoids a 2K temporary buffer:
//     1) sort the candidate buffer in shared memory with a warp-local bitonic network;
//     2) merge the sorted candidates with the already-sorted top-K using merge-path.
//
// No extra device memory is allocated.

constexpr int WARP_SIZE = 32;
constexpr int WARPS_PER_BLOCK = 4;
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;
constexpr int BATCH_POINTS = 1024;
constexpr unsigned FULL_MASK = 0xffffffffu;

// POD mirror of the required output payload (index, squared distance).
// We use a trivial POD internally because raw cudaMalloc memory does not contain
// constructed std::pair objects. The ABI assumption is guarded by sizeof().
struct Neighbor {
    int   first;   // data-point index
    float second;  // squared Euclidean distance
};

static_assert(std::is_trivially_copyable<Neighbor>::value, "Neighbor must be trivially copyable.");
static_assert(sizeof(Neighbor) == sizeof(std::pair<int, float>),
              "std::pair<int,float> layout is not compatible with Neighbor on this toolchain.");
static_assert(BATCH_POINTS % WARP_SIZE == 0, "BATCH_POINTS must be a multiple of warp size.");

__device__ __forceinline__ Neighbor make_sentinel() {
    Neighbor n;
    n.first = INT_MAX;
    n.second = CUDART_INF_F;
    return n;
}

__device__ __forceinline__ bool neighbor_less(const Neighbor &a, const Neighbor &b) {
    return (a.second < b.second) || ((a.second == b.second) && (a.first < b.first));
}

__device__ __forceinline__ float squared_l2(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dy, dy, dx * dx);
}

// In-place bitonic sort of a K-element array in shared memory, owned by one warp.
// K is a power of two in [32, 1024].
template <int K>
__device__ __forceinline__ void warp_bitonic_sort_shared(Neighbor *arr, const int lane) {
    static_assert(K >= 32 && K <= 1024, "Unsupported K.");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");

    #pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < K; i += WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const Neighbor a = arr[i];
                    const Neighbor b = arr[j];
                    const bool up = ((i & size) == 0);
                    const bool do_swap = up ? neighbor_less(b, a) : neighbor_less(a, b);
                    if (do_swap) {
                        arr[i] = b;
                        arr[j] = a;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
}

// The resident top-K is stored as contiguous chunks:
//   lane 0 owns [0, ITEMS_PER_THREAD),
//   lane 1 owns [ITEMS_PER_THREAD, 2*ITEMS_PER_THREAD), ...
// Therefore lane 31 owns the global K-th element.
template <int K>
__device__ __forceinline__ float kth_distance(const Neighbor (&best)[K / WARP_SIZE]) {
    return __shfl_sync(FULL_MASK, best[(K / WARP_SIZE) - 1].second, WARP_SIZE - 1);
}

template <int K>
__device__ __forceinline__ void sort_register_best(
    Neighbor (&best)[K / WARP_SIZE],
    Neighbor *best_sh,
    const int lane)
{
    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        best_sh[lane * ITEMS_PER_THREAD + t] = best[t];
    }
    __syncwarp(FULL_MASK);

    warp_bitonic_sort_shared<K>(best_sh, lane);

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        best[t] = best_sh[lane * ITEMS_PER_THREAD + t];
    }
    __syncwarp(FULL_MASK);
}

// Merge-path co-rank for two sorted K-element arrays.
// Returns how many elements must be taken from A among the first p merged outputs.
template <int K>
__device__ __forceinline__ int co_rank(const int p, const Neighbor *a, const Neighbor *b) {
    int low  = 0;
    int high = p;

    while (low <= high) {
        const int i = (low + high) >> 1;
        const int j = p - i;

        if (i > 0 && j < K && neighbor_less(b[j], a[i - 1])) {
            high = i - 1;  // took too many from A
        } else if (j > 0 && i < K && !neighbor_less(b[j - 1], a[i])) {
            low = i + 1;   // took too few from A
        } else {
            return i;
        }
    }

    return low;
}

// Merge the shared candidate buffer into the resident top-K.
// The current top-K is first mirrored into shared memory because merge-path needs
// arbitrary indexed reads. The resident state after the merge stays in registers.
template <int K>
__device__ __forceinline__ void merge_candidates_into_best(
    Neighbor (&best)[K / WARP_SIZE],
    Neighbor *best_sh,
    Neighbor *cand_sh,
    int *cand_count,
    const int lane)
{
    int count = 0;
    if (lane == 0) {
        count = *cand_count;
    }
    count = __shfl_sync(FULL_MASK, count, 0);
    if (count == 0) {
        return;
    }

    const Neighbor sentinel = make_sentinel();

    // Pad to K with +inf so that both inputs to merge-path always have length K.
    for (int i = lane; i < K; i += WARP_SIZE) {
        if (i >= count) {
            cand_sh[i] = sentinel;
        }
    }
    __syncwarp(FULL_MASK);

    // Sort candidates in-place.
    warp_bitonic_sort_shared<K>(cand_sh, lane);

    // Publish the current sorted top-K to shared memory.
    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;
    #pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        best_sh[lane * ITEMS_PER_THREAD + t] = best[t];
    }
    __syncwarp(FULL_MASK);

    // Each lane owns one contiguous slice of the merged output.
    int i = co_rank<K>(lane * ITEMS_PER_THREAD, best_sh, cand_sh);
    int j = lane * ITEMS_PER_THREAD - i;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        Neighbor a = sentinel;
        Neighbor b = sentinel;
        if (i < K) a = best_sh[i];
        if (j < K) b = cand_sh[j];

        const bool take_a = !neighbor_less(b, a);
        best[t] = take_a ? a : b;
        i += static_cast<int>(take_a);
        j += static_cast<int>(!take_a);
    }

    __syncwarp(FULL_MASK);
    if (lane == 0) {
        *cand_count = 0;
    }
    __syncwarp(FULL_MASK);
}

// Process a [begin, end) subrange of the current shared-memory tile.
// Each iteration handles one warp-wide chunk of up to 32 points.
template <int K>
__device__ __forceinline__ void process_batch_points(
    const float2 *batch,
    const int begin,
    const int end,
    const int global_base,
    const float qx,
    const float qy,
    Neighbor (&best)[K / WARP_SIZE],
    Neighbor *best_sh,
    Neighbor *cand_sh,
    int *cand_count,
    const int lane,
    float &max_distance)
{
    for (int tile = begin; tile < end; tile += WARP_SIZE) {
        const int valid = ((end - tile) < WARP_SIZE) ? (end - tile) : WARP_SIZE;

        Neighbor candidate = make_sentinel();
        bool pass = false;

        if (lane < valid) {
            const float2 p = batch[tile + lane];
            candidate.first = global_base + tile + lane;
            candidate.second = squared_l2(qx, qy, p);
            pass = candidate.second < max_distance;
        }

        unsigned mask = __ballot_sync(FULL_MASK, pass);
        int n = __popc(mask);

        // If this chunk would overflow the fixed-size candidate buffer,
        // flush the existing buffer first, then re-test the chunk against the
        // tighter updated threshold (max_distance can only decrease).
        int count = 0;
        if (lane == 0) {
            count = *cand_count;
        }
        count = __shfl_sync(FULL_MASK, count, 0);

        if (count + n > K) {
            merge_candidates_into_best<K>(best, best_sh, cand_sh, cand_count, lane);
            max_distance = kth_distance<K>(best);

            pass = (lane < valid) && (candidate.second < max_distance);
            mask = __ballot_sync(FULL_MASK, pass);
            n = __popc(mask);
        }

        if (n != 0) {
            const int leader = __ffs(mask) - 1;
            int base = 0;

            // Warp-aggregated atomicAdd: one atomic per warp-chunk, as requested.
            if (lane == leader) {
                base = atomicAdd(cand_count, n);
            }
            base = __shfl_sync(FULL_MASK, base, leader);

            const unsigned prior = mask & ((lane == 0) ? 0u : ((1u << lane) - 1u));
            if (pass) {
                cand_sh[base + __popc(prior)] = candidate;
            }

            __syncwarp(FULL_MASK);

            // If the buffer became exactly full, merge immediately.
            if (base + n == K) {
                merge_candidates_into_best<K>(best, best_sh, cand_sh, cand_count, lane);
                max_distance = kth_distance<K>(best);
            }
        } else {
            __syncwarp(FULL_MASK);
        }
    }
}

template <int K>
__launch_bounds__(THREADS_PER_BLOCK, 2)
__global__ void knn_kernel(
    const float2 * __restrict__ query,
    const int query_count,
    const float2 * __restrict__ data,
    const int data_count,
    Neighbor * __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024, "Unsupported K.");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K <= BATCH_POINTS, "BATCH_POINTS must cover the initial K seed points.");

    extern __shared__ __align__(16) unsigned char smem_raw[];

    // Shared-memory layout:
    // [0, BATCH_POINTS)                          : cached data tile
    // [per warp: K entries]                     : shared mirror of current top-K
    // [per warp: K entries]                     : candidate buffer
    // [per warp: 1 int]                         : candidate count
    float2   *batch_data      = reinterpret_cast<float2*>(smem_raw);
    Neighbor *best_all        = reinterpret_cast<Neighbor*>(batch_data + BATCH_POINTS);
    Neighbor *cand_all        = best_all + WARPS_PER_BLOCK * K;
    int      *cand_count_all  = reinterpret_cast<int*>(cand_all + WARPS_PER_BLOCK * K);

    const int tid     = threadIdx.x;
    const int warp_id = tid >> 5;
    const int lane    = tid & 31;

    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active   = (query_idx < query_count);

    Neighbor *best_sh   = best_all + warp_id * K;
    Neighbor *cand_sh   = cand_all + warp_id * K;
    int      *cand_count = cand_count_all + warp_id;

    if (lane == 0) {
        *cand_count = 0;
    }
    __syncthreads();

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    Neighbor best[K / WARP_SIZE];
    float max_distance = CUDART_INF_F;
    bool initialized = false;

    for (int batch_start = 0; batch_start < data_count; batch_start += BATCH_POINTS) {
        int loaded = data_count - batch_start;
        if (loaded > BATCH_POINTS) {
            loaded = BATCH_POINTS;
        }

        // Cooperative block-wide load of the next data tile.
        for (int i = tid; i < loaded; i += THREADS_PER_BLOCK) {
            batch_data[i] = data[batch_start + i];
        }
        __syncthreads();

        if (active) {
            int begin = 0;

            // Seed the resident top-K from the first K data points.
            // Because BATCH_POINTS >= K and data_count >= K, this always fits in the first tile.
            if (!initialized) {
                constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;

                #pragma unroll
                for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
                    const int pos = lane * ITEMS_PER_THREAD + t;
                    best[t].first = pos;
                    best[t].second = squared_l2(qx, qy, batch_data[pos]);
                }

                sort_register_best<K>(best, best_sh, lane);
                max_distance = kth_distance<K>(best);
                initialized = true;
                begin = K;
            }

            process_batch_points<K>(
                batch_data,
                begin,
                loaded,
                batch_start,
                qx,
                qy,
                best,
                best_sh,
                cand_sh,
                cand_count,
                lane,
                max_distance);
        }

        __syncthreads();
    }

    if (active) {
        int remaining = 0;
        if (lane == 0) {
            remaining = *cand_count;
        }
        remaining = __shfl_sync(FULL_MASK, remaining, 0);
        if (remaining != 0) {
            merge_candidates_into_best<K>(best, best_sh, cand_sh, cand_count, lane);
        }

        Neighbor *out = result + static_cast<size_t>(query_idx) * K;
        constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;

        #pragma unroll
        for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
            out[lane * ITEMS_PER_THREAD + t] = best[t];
        }
    }
}

template <int K>
constexpr size_t shared_bytes_for_kernel() {
    return
        BATCH_POINTS * sizeof(float2) +
        2 * WARPS_PER_BLOCK * K * sizeof(Neighbor) +
        WARPS_PER_BLOCK * sizeof(int);
}

// K only takes six legal values, so dispatching to a fully specialized kernel
// gives the compiler exact register array sizes and fixed loop trip counts.
template <int K>
inline void launch_knn_template(
    const float2 *query,
    const int query_count,
    const float2 *data,
    const int data_count,
    std::pair<int, float> *result)
{
    constexpr size_t smem_bytes = shared_bytes_for_kernel<K>();

    // Opt in to the required amount of dynamic shared memory and bias the carveout
    // toward shared memory because this kernel is explicitly shared-memory-heavy.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(THREADS_PER_BLOCK);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, smem_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<Neighbor*>(result));
}

} // namespace

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_template<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_template<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_template<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_template<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_template<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_template<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs are stated to be valid; this is just a defensive fallback.
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn_detail {

// Warp-per-query design:
// - 1 warp computes the full k-NN result for 1 query.
// - The current top-k ("intermediate result") is private to the warp and kept in registers, distributed across lanes.
// - Each warp also owns a shared-memory candidate buffer of size k plus a shared candidate counter.
// - The whole block stages a batch of data points in shared memory so multiple query-warps reuse each global load.
//
// Chosen launch parameters:
// - 8 warps/block (256 threads): good balance between data reuse and enough blocks for the stated "thousands of queries" regime.
// - 1024 staged data points/block iteration: exactly 4 coalesced float2 loads/thread, large enough to amortize barriers,
//   and still below the A100 opt-in shared-memory limit even for k = 1024.
//
// The staged batch is stored as structure-of-arrays (x[] and y[]) rather than float2[] to avoid the avoidable
// shared-memory bank conflicts that consecutive float2 reads would create on 4-byte banks.

using ResultPair = std::pair<int, float>;

constexpr int WARP_SIZE        = 32;
constexpr int LAST_LANE        = WARP_SIZE - 1;
constexpr int WARPS_PER_BLOCK  = 8;
constexpr int BLOCK_THREADS    = WARPS_PER_BLOCK * WARP_SIZE;
constexpr int BATCH_POINTS     = 1024;
constexpr int LOAD_ITERS       = BATCH_POINTS / BLOCK_THREADS;
constexpr unsigned FULL_MASK   = 0xffffffffu;

static_assert(BATCH_POINTS % WARP_SIZE == 0, "BATCH_POINTS must be a multiple of the warp size.");
static_assert(BATCH_POINTS % BLOCK_THREADS == 0, "BATCH_POINTS is chosen so the block load loop is fully unrolled.");

template <int K>
constexpr std::size_t shared_bytes() {
    return
        sizeof(float) * BATCH_POINTS +                     // batch_x
        sizeof(float) * BATCH_POINTS +                     // batch_y
        sizeof(int)   * WARPS_PER_BLOCK +                  // per-warp candidate counts
        sizeof(int)   * WARPS_PER_BLOCK * K +              // candidate indices
        sizeof(float) * WARPS_PER_BLOCK * K +              // candidate distances
        sizeof(int)   * WARPS_PER_BLOCK * K +              // scratch indices for current top-k
        sizeof(float) * WARPS_PER_BLOCK * K;               // scratch distances for current top-k
}

template <int K>
__device__ __forceinline__ int co_rank(int diag, const float* a, const float* b) {
    // Merge-path / co-rank partition for two sorted arrays a[0:K) and b[0:K).
    // It returns how many elements of the first 'diag' outputs of the stable merge
    // (ties broken in favor of 'a') come from 'a'.
    int low  = (diag > K) ? (diag - K) : 0;
    int high = (diag < K) ? diag : K;

    while (low <= high) {
        const int i = (low + high) >> 1;
        const int j = diag - i;

        const float a_im1 = (i > 0) ? a[i - 1] : -CUDART_INF_F;
        const float a_i   = (i < K) ? a[i]     :  CUDART_INF_F;
        const float b_jm1 = (j > 0) ? b[j - 1] : -CUDART_INF_F;
        const float b_j   = (j < K) ? b[j]     :  CUDART_INF_F;

        if (a_im1 > b_j) {
            high = i - 1;
        } else if (b_jm1 >= a_i) {
            low = i + 1;
        } else {
            return i;
        }
    }

    return low;
}

template <int K>
__device__ __forceinline__ void bitonic_sort_shared(int lane, float* dist, int* idx) {
    // K is guaranteed to be a power of two, so a shared-memory bitonic sort is a natural fit.
    // Sorting happens only when the candidate buffer is flushed/merged, which is infrequent once max_distance stabilizes.
    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < K; i += WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const bool ascending = ((i & size) == 0);

                    const float di = dist[i];
                    const float dj = dist[j];
                    const int   ii = idx[i];
                    const int   ij = idx[j];

                    const bool do_swap = ascending ? (di > dj) : (di < dj);
                    if (do_swap) {
                        dist[i] = dj; dist[j] = di;
                        idx[i]  = ij; idx[j]  = ii;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
}

template <int K>
__device__ __forceinline__ void merge_candidates(
    int lane,
    int count,
    int   (&top_idx)[K / WARP_SIZE],
    float (&top_dist)[K / WARP_SIZE],
    float& max_distance,
    int*   cand_count_ptr,
    int*   cand_idx,
    float* cand_dist,
    int*   scratch_idx,
    float* scratch_dist)
{
    constexpr int CHUNK = K / WARP_SIZE;

    if (count == 0) {
        return;
    }

    // Spill the warp-private current top-k from registers to shared memory so the warp can access it randomly
    // during the merge-path partition/merge.
    #pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        const int pos = lane * CHUNK + t;
        scratch_idx[pos]  = top_idx[t];
        scratch_dist[pos] = top_dist[t];
    }

    // Pad the candidate buffer to exactly K entries with sentinels so the sort/merge logic stays branch-light.
    for (int pos = count + lane; pos < K; pos += WARP_SIZE) {
        cand_idx[pos]  = -1;
        cand_dist[pos] = CUDART_INF_F;
    }
    __syncwarp(FULL_MASK);

    bitonic_sort_shared<K>(lane, cand_dist, cand_idx);
    __syncwarp(FULL_MASK);

    // Each lane owns a contiguous CHUNK-sized segment of the merged top-k. This makes merge-path partitioning simple:
    // lane l produces outputs [l*CHUNK, (l+1)*CHUNK).
    const int out_begin = lane * CHUNK;
    const int out_end   = out_begin + CHUNK;

    int a_begin = co_rank<K>(out_begin, scratch_dist, cand_dist);
    int a_end   = __shfl_down_sync(FULL_MASK, a_begin, 1);
    if (lane == LAST_LANE) {
        a_end = co_rank<K>(K, scratch_dist, cand_dist);
    }

    int b_begin = out_begin - a_begin;
    int b_end   = out_end   - a_end;

    int a_pos = a_begin;
    int b_pos = b_begin;

    #pragma unroll
    for (int t = 0; t < CHUNK; ++t) {
        const bool take_a =
            (b_pos >= b_end) ||
            ((a_pos < a_end) && (scratch_dist[a_pos] <= cand_dist[b_pos]));

        if (take_a) {
            top_dist[t] = scratch_dist[a_pos];
            top_idx[t]  = scratch_idx[a_pos];
            ++a_pos;
        } else {
            top_dist[t] = cand_dist[b_pos];
            top_idx[t]  = cand_idx[b_pos];
            ++b_pos;
        }
    }

    __syncwarp(FULL_MASK);

    // Reset the shared candidate counter for the next accumulation round.
    if (lane == 0) {
        *cand_count_ptr = 0;
    }

    // The k-th nearest neighbor is the last element of the sorted top-k, owned by the last lane.
    const float lane_last = (lane == LAST_LANE) ? top_dist[CHUNK - 1] : 0.0f;
    max_distance = __shfl_sync(FULL_MASK, lane_last, LAST_LANE);

    __syncwarp(FULL_MASK);
}

__device__ __forceinline__ void store_result(ResultPair* dst, int idx, float dist) {
    // Writing fields individually avoids relying on any device-side std::pair helper functions.
    dst->first  = idx;
    dst->second = dist;
}

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    ResultPair* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024, "K must be within the supported range.");
    static_assert((K & (K - 1)) == 0,   "K must be a power of two.");
    static_assert((K % WARP_SIZE) == 0, "K must be divisible by the warp size.");

    constexpr int CHUNK = K / WARP_SIZE;

    // Dynamic shared-memory layout:
    // [batch_x | batch_y | cand_count[warps] | cand_idx[warps][K] | cand_dist[warps][K]
    //  | scratch_idx[warps][K] | scratch_dist[warps][K]]
    extern __shared__ unsigned char smem_raw[];
    unsigned char* smem = smem_raw;

    float* batch_x = reinterpret_cast<float*>(smem);
    smem += sizeof(float) * BATCH_POINTS;

    float* batch_y = reinterpret_cast<float*>(smem);
    smem += sizeof(float) * BATCH_POINTS;

    int* cand_count_all = reinterpret_cast<int*>(smem);
    smem += sizeof(int) * WARPS_PER_BLOCK;

    int* cand_idx_all = reinterpret_cast<int*>(smem);
    smem += sizeof(int) * WARPS_PER_BLOCK * K;

    float* cand_dist_all = reinterpret_cast<float*>(smem);
    smem += sizeof(float) * WARPS_PER_BLOCK * K;

    int* scratch_idx_all = reinterpret_cast<int*>(smem);
    smem += sizeof(int) * WARPS_PER_BLOCK * K;

    float* scratch_dist_all = reinterpret_cast<float*>(smem);

    const int warp_id     = threadIdx.x >> 5;
    const int lane        = threadIdx.x & (WARP_SIZE - 1);
    const int query_index = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active     = (query_index < query_count);

    int*   cand_count_ptr = cand_count_all + warp_id;
    int*   cand_idx       = cand_idx_all + warp_id * K;
    float* cand_dist      = cand_dist_all + warp_id * K;
    int*   scratch_idx    = scratch_idx_all + warp_id * K;
    float* scratch_dist   = scratch_dist_all + warp_id * K;

    // Warp-private intermediate top-k, distributed across lanes.
    int   top_idx[CHUNK];
    float top_dist[CHUNK];

    float qx = 0.0f;
    float qy = 0.0f;
    float max_distance = CUDART_INF_F;
    int buffer_count = 0;  // Register shadow of the per-warp shared candidate counter.

    if (active) {
        // One lane loads the query point, then broadcasts it to the whole warp.
        float qx_lane0 = 0.0f;
        float qy_lane0 = 0.0f;
        if (lane == 0) {
            const float2 q = query[query_index];
            qx_lane0 = q.x;
            qy_lane0 = q.y;
            *cand_count_ptr = 0;
        }
        qx = __shfl_sync(FULL_MASK, qx_lane0, 0);
        qy = __shfl_sync(FULL_MASK, qy_lane0, 0);

        #pragma unroll
        for (int t = 0; t < CHUNK; ++t) {
            top_idx[t]  = -1;
            top_dist[t] = CUDART_INF_F;
        }

        __syncwarp(FULL_MASK);
    }

    for (int batch_base = 0; batch_base < data_count; batch_base += BATCH_POINTS) {
        int batch_n = data_count - batch_base;
        if (batch_n > BATCH_POINTS) {
            batch_n = BATCH_POINTS;
        }

        // Cooperative block-wide load of the next data batch into shared memory.
        #pragma unroll
        for (int it = 0; it < LOAD_ITERS; ++it) {
            const int i = it * BLOCK_THREADS + threadIdx.x;
            if (i < batch_n) {
                const float2 p = data[batch_base + i];
                batch_x[i] = p.x;
                batch_y[i] = p.y;
            }
        }

        __syncthreads();

        if (active) {
            // Warp-synchronous scan of the cached batch. All 32 lanes participate every iteration,
            // even on the last partial tile, so warp collectives always use FULL_MASK safely.
            for (int tile = 0; tile < batch_n; tile += WARP_SIZE) {
                const int off   = tile + lane;
                const bool valid = (off < batch_n);

                float dist = CUDART_INF_F;
                int data_index = -1;

                if (valid) {
                    const float dx = qx - batch_x[off];
                    const float dy = qy - batch_y[off];
                    dist = fmaf(dx, dx, dy * dy);  // squared Euclidean distance
                    data_index = batch_base + off;
                }

                // Retry loop: if the current mini-tile would overflow the candidate buffer,
                // merge first, tighten max_distance, then re-test the very same distance.
                while (true) {
                    const bool pass = valid && (dist < max_distance);
                    const unsigned pass_mask = __ballot_sync(FULL_MASK, pass);
                    const int num_pass = __popc(pass_mask);

                    if (num_pass == 0) {
                        break;
                    }

                    if (buffer_count + num_pass > K) {
                        merge_candidates<K>(
                            lane, buffer_count,
                            top_idx, top_dist, max_distance,
                            cand_count_ptr, cand_idx, cand_dist,
                            scratch_idx, scratch_dist);
                        buffer_count = 0;
                        continue;
                    }

                    // Warp-aggregated reservation:
                    // one shared atomicAdd reserves a contiguous range for all passing lanes.
                    int base_pos = 0;
                    if (lane == 0) {
                        base_pos = atomicAdd(cand_count_ptr, num_pass);
                    }
                    base_pos = __shfl_sync(FULL_MASK, base_pos, 0);

                    if (pass) {
                        const unsigned lower_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
                        const int rank = __popc(pass_mask & lower_mask);
                        const int pos = base_pos + rank;
                        cand_idx[pos]  = data_index;
                        cand_dist[pos] = dist;
                    }

                    __syncwarp(FULL_MASK);

                    buffer_count += num_pass;

                    if (buffer_count == K) {
                        merge_candidates<K>(
                            lane, buffer_count,
                            top_idx, top_dist, max_distance,
                            cand_count_ptr, cand_idx, cand_dist,
                            scratch_idx, scratch_dist);
                        buffer_count = 0;
                    }

                    break;
                }
            }
        }

        // The next iteration overwrites the staged batch, so all warps in the block must be done with it.
        __syncthreads();
    }

    if (active) {
        if (buffer_count > 0) {
            merge_candidates<K>(
                lane, buffer_count,
                top_idx, top_dist, max_distance,
                cand_count_ptr, cand_idx, cand_dist,
                scratch_idx, scratch_dist);
        }

        // Output is already globally sorted by ascending distance.
        const std::size_t out_base =
            static_cast<std::size_t>(query_index) * static_cast<std::size_t>(K) +
            static_cast<std::size_t>(lane) * static_cast<std::size_t>(CHUNK);

        ResultPair* out = result + out_base;

        #pragma unroll
        for (int t = 0; t < CHUNK; ++t) {
            store_result(out + t, top_idx[t], top_dist[t]);
        }
    }
}

template <int K>
void launch_case(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    ResultPair* result)
{
    static_assert(shared_bytes<K>() <= 163840,
                  "Kernel configuration exceeds the A100 opt-in shared-memory limit.");

    constexpr std::size_t smem_bytes = shared_bytes<K>();

    // The public API returns void, so launch/error handling is intentionally left to the caller.
    // We still request the shared-memory carveout required by the chosen configuration.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));

    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    (void)cudaFuncSetCacheConfig(
        knn_kernel<K>,
        cudaFuncCachePreferShared);

    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    knn_kernel<K><<<blocks, BLOCK_THREADS, smem_bytes>>>(
        query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    // k is guaranteed by contract to be one of these values.
    switch (k) {
        case 32:   knn_detail::launch_case<32>(query, query_count, data, data_count, result);   break;
        case 64:   knn_detail::launch_case<64>(query, query_count, data, data_count, result);   break;
        case 128:  knn_detail::launch_case<128>(query, query_count, data, data_count, result);  break;
        case 256:  knn_detail::launch_case<256>(query, query_count, data, data_count, result);  break;
        case 512:  knn_detail::launch_case<512>(query, query_count, data, data_count, result);  break;
        case 1024: knn_detail::launch_case<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Unreachable under the stated preconditions.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace {

// Tuned for A100/H100-class GPUs:
// - 8 warps/block gives good data reuse while still keeping enough blocks in flight
//   when query_count is only in the low thousands.
// - 1024 cached data points/batch keeps the shared-memory footprint low enough to
//   allow two resident blocks/SM even for K=1024.
constexpr int kWarpSize        = 32;
constexpr int kWarpsPerBlock   = 8;
constexpr int kThreadsPerBlock = kWarpSize * kWarpsPerBlock;
constexpr int kDataBatchPoints = 1024;
constexpr unsigned kFullWarpMask = 0xffffffffu;

static_assert(kThreadsPerBlock <= 1024, "Block size exceeds CUDA limit.");
static_assert(kDataBatchPoints % kWarpSize == 0, "Batch size must be warp-aligned.");

// Device-side POD view of the host-side std::pair<int,float> API type.
// The kernel only needs the raw ABI layout, not the std::pair interface itself.
struct alignas(alignof(std::pair<int, float>)) PairIFPod {
    int   first;
    float second;
};

static_assert(sizeof(PairIFPod)  == sizeof(std::pair<int, float>), "Unexpected std::pair<int,float> size.");
static_assert(alignof(PairIFPod) == alignof(std::pair<int, float>), "Unexpected std::pair<int,float> alignment.");

__host__ __device__ constexpr size_t align_up(size_t x, size_t a) {
    return (x + a - 1) & ~(a - 1);
}

template <int K>
constexpr size_t shared_bytes_for_kernel() {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "K must be a power of two in [32, 1024].");
    static_assert(K % kWarpSize == 0, "K must be divisible by warp size.");
    static_assert(K <= kDataBatchPoints, "The first shared batch must hold the bootstrap top-K.");

    size_t bytes = 0;

    bytes = align_up(bytes, alignof(float2));
    bytes += kDataBatchPoints * sizeof(float2);

    bytes = align_up(bytes, alignof(int));
    bytes += kWarpsPerBlock * sizeof(int);            // candidate counts, one per warp/query

    bytes = align_up(bytes, alignof(int));
    bytes += kWarpsPerBlock * K * sizeof(int);        // candidate indices

    bytes = align_up(bytes, alignof(float));
    bytes += kWarpsPerBlock * K * sizeof(float);      // candidate distances

    return bytes;
}

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    // Any tie break is acceptable; index tie-break gives a deterministic total order.
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool keep_self(float self_d, int self_i, float other_d, int other_i, bool take_min) {
    // Returns whether the current element should keep its own value when compared
    // against "other", either for the min side or the max side of a compare-exchange.
    return take_min ? !pair_less(other_d, other_i, self_d, self_i)
                    : !pair_less(self_d, self_i, other_d, other_i);
}

__device__ __forceinline__ void compare_swap_local(float& a_d, int& a_i,
                                                   float& b_d, int& b_i,
                                                   bool ascending) {
    const bool swap_needed = ascending ? pair_less(b_d, b_i, a_d, a_i)
                                       : pair_less(a_d, a_i, b_d, b_i);
    if (swap_needed) {
        const float td = a_d; a_d = b_d; b_d = td;
        const int   ti = a_i; a_i = b_i; b_i = ti;
    }
}

__device__ __forceinline__ float squared_l2(float qx, float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

__device__ __forceinline__ int warp_prefix_rank(unsigned mask, int lane) {
    const unsigned lower = (lane == 0) ? 0u : ((1u << lane) - 1u);
    return __popc(mask & lower);
}

// Bitonic sort of K elements distributed across one warp's registers.
// Mapping: global position p = slot * 32 + lane, where each lane owns K/32 slots.
template <int K>
__device__ __forceinline__ void bitonic_sort_warp(float (&dist)[K / kWarpSize],
                                                  int   (&idx )[K / kWarpSize]) {
    constexpr int ITEMS = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);

    #pragma unroll
    for (int k_stage = 2; k_stage <= K; k_stage <<= 1) {
        #pragma unroll
        for (int j_stage = k_stage >> 1; j_stage > 0; j_stage >>= 1) {
            if (j_stage < kWarpSize) {
                // Inter-lane compare-exchange: partner differs only in the lane bits.
                #pragma unroll
                for (int t = 0; t < ITEMS; ++t) {
                    const int p = (t << 5) | lane;

                    const float self_d  = dist[t];
                    const int   self_i  = idx[t];
                    const float other_d = __shfl_xor_sync(kFullWarpMask, self_d, j_stage);
                    const int   other_i = __shfl_xor_sync(kFullWarpMask, self_i, j_stage);

                    const bool take_min = (((p & k_stage) == 0) ^ ((p & j_stage) != 0));
                    const bool keep     = keep_self(self_d, self_i, other_d, other_i, take_min);

                    dist[t] = keep ? self_d : other_d;
                    idx[t]  = keep ? self_i : other_i;
                }
            } else {
                // Intra-lane compare-exchange: partner differs only in the slot bits.
                const int offset = j_stage >> 5;

                #pragma unroll
                for (int t = 0; t < ITEMS; ++t) {
                    if ((t & offset) == 0) {
                        const int u = t ^ offset;
                        const int p = (t << 5) | lane;
                        const bool ascending = ((p & k_stage) == 0);
                        compare_swap_local(dist[t], idx[t], dist[u], idx[u], ascending);
                    }
                }
            }
            __syncwarp(kFullWarpMask);
        }
    }
}

// Bitonic sort of a warp-private shared-memory candidate buffer.
// The buffer is stored as two SoA arrays in shared memory. Unused entries are
// filled with +inf / INT_MAX before sorting so that short buffers can be sorted
// with the exact same network.
template <int K>
__device__ __forceinline__ void bitonic_sort_shared_buffer(int* cand_idx,
                                                           float* cand_dist,
                                                           int valid_count) {
    constexpr int ITEMS = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);

    valid_count = (valid_count < K) ? valid_count : K;

    if (valid_count < K) {
        #pragma unroll
        for (int t = 0; t < ITEMS; ++t) {
            const int p = (t << 5) | lane;
            if (p >= valid_count) {
                cand_dist[p] = CUDART_INF_F;
                cand_idx[p]  = INT_MAX;
            }
        }
    }
    __syncwarp(kFullWarpMask);

    #pragma unroll
    for (int k_stage = 2; k_stage <= K; k_stage <<= 1) {
        #pragma unroll
        for (int j_stage = k_stage >> 1; j_stage > 0; j_stage >>= 1) {
            if (j_stage < kWarpSize) {
                #pragma unroll
                for (int t = 0; t < ITEMS; ++t) {
                    const int p = (t << 5) | lane;

                    const float self_d  = cand_dist[p];
                    const int   self_i  = cand_idx[p];
                    const float other_d = __shfl_xor_sync(kFullWarpMask, self_d, j_stage);
                    const int   other_i = __shfl_xor_sync(kFullWarpMask, self_i, j_stage);

                    const bool take_min = (((p & k_stage) == 0) ^ ((p & j_stage) != 0));
                    const bool keep     = keep_self(self_d, self_i, other_d, other_i, take_min);

                    cand_dist[p] = keep ? self_d : other_d;
                    cand_idx[p]  = keep ? self_i : other_i;
                }
            } else {
                const int offset = j_stage >> 5;

                #pragma unroll
                for (int t = 0; t < ITEMS; ++t) {
                    if ((t & offset) == 0) {
                        const int u = t ^ offset;
                        const int p = (t << 5) | lane;
                        const int q = (u << 5) | lane;

                        float a_d = cand_dist[p];
                        int   a_i = cand_idx[p];
                        float b_d = cand_dist[q];
                        int   b_i = cand_idx[q];

                        const bool ascending = ((p & k_stage) == 0);
                        compare_swap_local(a_d, a_i, b_d, b_i, ascending);

                        cand_dist[p] = a_d; cand_idx[p] = a_i;
                        cand_dist[q] = b_d; cand_idx[q] = b_i;
                    }
                }
            }
            __syncwarp(kFullWarpMask);
        }
    }
}

// Merge shared candidate buffer into the register-resident intermediate top-K.
// The implementation follows the required sequence exactly:
//   1) sort candidate buffer ascending,
//   2) build a K-element bitonic merged sequence by pairwise min(buffer[i], top[K-1-i]),
//   3) sort the merged sequence ascending.
// To keep register pressure low for K=1024, the merged sequence is materialized back
// into the shared candidate buffer and sorted there; the updated top-K is then loaded
// back into registers.
template <int K>
__device__ __forceinline__ float merge_shared_buffer_into_top(int* cand_idx,
                                                              float* cand_dist,
                                                              int valid_count,
                                                              int   (&top_idx )[K / kWarpSize],
                                                              float (&top_dist)[K / kWarpSize]) {
    constexpr int ITEMS = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int rev_lane = (kWarpSize - 1) - lane;

    valid_count = (valid_count < K) ? valid_count : K;

    bitonic_sort_shared_buffer<K>(cand_idx, cand_dist, valid_count);

    // Step 2: write the K-element bitonic merged sequence back into the shared buffer.
    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = (t << 5) | lane;

        const float buf_d = cand_dist[p];
        const int   buf_i = cand_idx[p];

        const float top_rev_d = __shfl_sync(kFullWarpMask, top_dist[ITEMS - 1 - t], rev_lane);
        const int   top_rev_i = __shfl_sync(kFullWarpMask, top_idx [ITEMS - 1 - t], rev_lane);

        const bool take_buffer = keep_self(buf_d, buf_i, top_rev_d, top_rev_i, true);
        cand_dist[p] = take_buffer ? buf_d : top_rev_d;
        cand_idx[p]  = take_buffer ? buf_i : top_rev_i;
    }
    __syncwarp(kFullWarpMask);

    // Step 3: sort the merged bitonic sequence ascending.
    bitonic_sort_shared_buffer<K>(cand_idx, cand_dist, K);

    // Reload the updated top-K into the warp-private register copy.
    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = (t << 5) | lane;
        top_dist[t] = cand_dist[p];
        top_idx[t]  = cand_idx[p];
    }

    // Distance of the K-th nearest neighbor.
    return __shfl_sync(kFullWarpMask, top_dist[ITEMS - 1], kWarpSize - 1);
}

// Process one already-cached shared-memory batch of data points.
// The candidate buffer is appended to with a warp-aggregated shared-memory atomicAdd:
// a single atomic reserves a contiguous segment for all candidate lanes in the current
// micro-batch, and each participating lane computes its own position via a warp prefix.
template <int K>
__device__ __forceinline__ void process_loaded_batch(
    const float2* s_batch,
    int batch_base,
    int begin_offset,
    int batch_count,
    float qx,
    float qy,
    int* cand_idx,
    float* cand_dist,
    int* cand_count,
    int   (&top_idx )[K / kWarpSize],
    float (&top_dist)[K / kWarpSize],
    float& max_distance) {

    const int lane = threadIdx.x & (kWarpSize - 1);

    // Process one warp-sized micro-batch at a time so that if the candidate buffer becomes
    // full, at most 31 candidates overflow and need to be reconsidered after the flush.
    for (int step = begin_offset; step < batch_count; step += kWarpSize) {
        const int local = step + lane;
        const bool valid = (local < batch_count);

        float dist = 0.0f;
        int data_index = batch_base + local;
        bool is_candidate = false;

        if (valid) {
            const float2 p = s_batch[local];
            dist = squared_l2(qx, qy, p);
            is_candidate = (dist < max_distance);
        }

        const unsigned candidate_mask = __ballot_sync(kFullWarpMask, is_candidate);
        const int num_candidates = __popc(candidate_mask);

        int base = 0;
        if (lane == 0 && num_candidates != 0) {
            base = atomicAdd(cand_count, num_candidates);
        }
        base = __shfl_sync(kFullWarpMask, base, 0);

        bool overflow = false;
        if (is_candidate) {
            const int rank = warp_prefix_rank(candidate_mask, lane);
            const int pos  = base + rank;
            if (pos < K) {
                cand_idx[pos]  = data_index;
                cand_dist[pos] = dist;
            } else {
                overflow = true;
            }
        }

        __syncwarp(kFullWarpMask);

        if (num_candidates != 0 && (base + num_candidates) >= K) {
            max_distance = merge_shared_buffer_into_top<K>(cand_idx, cand_dist, K, top_idx, top_dist);

            if (lane == 0) {
                *cand_count = 0;
            }
            __syncwarp(kFullWarpMask);

            // Reconsider just the candidates from this triggering micro-batch that did not fit.
            const bool retry = overflow && (dist < max_distance);
            const unsigned retry_mask = __ballot_sync(kFullWarpMask, retry);
            const int retry_count = __popc(retry_mask);

            int retry_base = 0;
            if (lane == 0 && retry_count != 0) {
                retry_base = atomicAdd(cand_count, retry_count);
            }
            retry_base = __shfl_sync(kFullWarpMask, retry_base, 0);

            if (retry) {
                const int retry_rank = warp_prefix_rank(retry_mask, lane);
                const int retry_pos  = retry_base + retry_rank;
                cand_idx[retry_pos]  = data_index;
                cand_dist[retry_pos] = dist;
            }

            __syncwarp(kFullWarpMask);
        }
    }
}

template <int K>
__global__ __launch_bounds__(kThreadsPerBlock, 2)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                PairIFPod* __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "K must be a power of two in [32, 1024].");
    static_assert(K % kWarpSize == 0, "K must be divisible by warp size.");
    static_assert(K <= kDataBatchPoints, "Bootstrap top-K must fit into the first shared batch.");

    constexpr int ITEMS = K / kWarpSize;

    const int tid  = static_cast<int>(threadIdx.x);
    const int lane = tid & (kWarpSize - 1);
    const int warp = tid >> 5;

    const int query_idx = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp;
    const bool active_query = (query_idx < query_count);

    extern __shared__ unsigned char smem_raw[];

    // Dynamic shared-memory layout:
    //   [batch float2 cache][warp candidate counts][warp candidate indices][warp candidate distances]
    size_t offset = 0;

    offset = align_up(offset, alignof(float2));
    float2* s_batch = reinterpret_cast<float2*>(smem_raw + offset);
    offset += kDataBatchPoints * sizeof(float2);

    offset = align_up(offset, alignof(int));
    int* s_counts = reinterpret_cast<int*>(smem_raw + offset);
    offset += kWarpsPerBlock * sizeof(int);

    offset = align_up(offset, alignof(int));
    int* s_cand_idx_all = reinterpret_cast<int*>(smem_raw + offset);
    offset += kWarpsPerBlock * K * sizeof(int);

    offset = align_up(offset, alignof(float));
    float* s_cand_dist_all = reinterpret_cast<float*>(smem_raw + offset);

    int*   cand_count = s_counts + warp;
    int*   cand_idx   = s_cand_idx_all  + warp * K;
    float* cand_dist  = s_cand_dist_all + warp * K;

    float qx = 0.0f;
    float qy = 0.0f;
    float max_distance = CUDART_INF_F;

    // Warp-private intermediate top-K, distributed across registers.
    int   top_idx [ITEMS];
    float top_dist[ITEMS];

    // Load the first shared batch once.
    // This batch serves two purposes:
    //   1) initialize the register-resident top-K from the first K data points,
    //   2) continue the main scan with the remainder of the same cached batch if K < batch size.
    const int initial_batch_count = (data_count < kDataBatchPoints) ? data_count : kDataBatchPoints;
    for (int i = tid; i < initial_batch_count; i += kThreadsPerBlock) {
        s_batch[i] = data[i];
    }
    __syncthreads();

    if (active_query) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
            *cand_count = 0;
        }
        qx = __shfl_sync(kFullWarpMask, qx, 0);
        qy = __shfl_sync(kFullWarpMask, qy, 0);

        // Bootstrap the sorted intermediate result from the first K data points.
        #pragma unroll
        for (int t = 0; t < ITEMS; ++t) {
            const int p = (t << 5) | lane;  // p in [0, K)
            const float2 pt = s_batch[p];
            top_idx[t]  = p;
            top_dist[t] = squared_l2(qx, qy, pt);
        }

        bitonic_sort_warp<K>(top_dist, top_idx);
        max_distance = __shfl_sync(kFullWarpMask, top_dist[ITEMS - 1], kWarpSize - 1);
        __syncwarp(kFullWarpMask);

        // Continue processing the remainder of the already-cached first batch.
        process_loaded_batch<K>(s_batch,
                                /*batch_base=*/0,
                                /*begin_offset=*/K,
                                /*batch_count=*/initial_batch_count,
                                qx, qy,
                                cand_idx, cand_dist, cand_count,
                                top_idx, top_dist,
                                max_distance);
    }

    __syncthreads();

    // Process all remaining batches.
    for (int batch_base = kDataBatchPoints; batch_base < data_count; batch_base += kDataBatchPoints) {
        const int batch_count = ((data_count - batch_base) < kDataBatchPoints)
                              ? (data_count - batch_base)
                              :  kDataBatchPoints;

        for (int i = tid; i < batch_count; i += kThreadsPerBlock) {
            s_batch[i] = data[batch_base + i];
        }
        __syncthreads();

        if (active_query) {
            process_loaded_batch<K>(s_batch,
                                    batch_base,
                                    /*begin_offset=*/0,
                                    batch_count,
                                    qx, qy,
                                    cand_idx, cand_dist, cand_count,
                                    top_idx, top_dist,
                                    max_distance);
        }

        __syncthreads();
    }

    if (active_query) {
        int final_count = 0;
        if (lane == 0) {
            final_count = *cand_count;
        }
        final_count = __shfl_sync(kFullWarpMask, final_count, 0);
        final_count = (final_count < K) ? final_count : K;

        if (final_count > 0) {
            max_distance = merge_shared_buffer_into_top<K>(cand_idx, cand_dist, final_count, top_idx, top_dist);
            (void)max_distance;
        }

        const size_t out_base = static_cast<size_t>(query_idx) * static_cast<size_t>(K);

        #pragma unroll
        for (int t = 0; t < ITEMS; ++t) {
            const int p = (t << 5) | lane;
            result[out_base + p].first  = top_idx[t];
            result[out_base + p].second = top_dist[t];
        }
    }
}

template <int K>
void launch_knn(const float2* query,
                int query_count,
                const float2* data,
                int data_count,
                std::pair<int, float>* result) {
    constexpr size_t smem_bytes = shared_bytes_for_kernel<K>();

    // Required for kernels whose dynamic shared-memory use exceeds the default 48 KiB.
    static const bool configured = []() {
        (void)cudaFuncSetAttribute(knn_kernel<K>,
                                   cudaFuncAttributeMaxDynamicSharedMemorySize,
                                   static_cast<int>(smem_bytes));
        (void)cudaFuncSetAttribute(knn_kernel<K>,
                                   cudaFuncAttributePreferredSharedMemoryCarveout,
                                   100);
        return true;
    }();
    (void)configured;

    const dim3 block(kThreadsPerBlock);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    knn_kernel<K><<<grid, block, smem_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<PairIFPod*>(result));
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Intentionally asynchronous: caller retains normal CUDA stream/error handling control.
    switch (k) {
        case 32:   launch_knn<32>  (query, query_count, data, data_count, result); break;
        case 64:   launch_knn<64>  (query, query_count, data, data_count, result); break;
        case 128:  launch_knn<128> (query, query_count, data, data_count, result); break;
        case 256:  launch_knn<256> (query, query_count, data, data_count, result); break;
        case 512:  launch_knn<512> (query, query_count, data, data_count, result); break;
        case 1024: launch_knn<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs are specified to be valid; keep a no-op fallback.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace {

// Warp-centric 2D k-NN for modern NVIDIA GPUs.
//
// Design choices tuned for A100/H100-class hardware:
// - One warp owns one query.
// - A block cooperatively stages a tile of `data` into shared memory.
// - The current top-K ("intermediate result") is kept privately in registers,
//   distributed across the 32 lanes of the owning warp.
// - Each warp also owns a shared-memory candidate buffer of size K plus a
//   shared counter. Distances below the current K-th distance are appended to
//   that buffer via atomicAdd (warp-aggregated to cut atomic traffic).
// - When the buffer becomes full, it is merged into the private top-K with the
//   exact bitonic-sort / bitonic-merge procedure requested in the prompt.
// - K is template-specialized for the six valid powers of two, so per-lane
//   storage and the key loops are compile-time constants.
//
// Tile sizes:
// - K <= 512  -> 4096 staged points/block
// - K == 1024 -> 2048 staged points/block
//
// With 8 warps/block this keeps the shared-memory footprint in the ~35-80 KiB
// range, which is a good occupancy / reuse trade-off on Ampere/Hopper.
// Fallbacks to fewer warps/block are provided if the device reports a smaller
// dynamic shared-memory budget.

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool pair_greater(float da, int ia, float db, int ib) {
    return (da > db) || ((da == db) && (ia > ib));
}

__device__ __forceinline__ float squared_l2(float qx, float qy, const float2 &p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

// Select the lowest `n` set bits from `mask`.
// Any subset would work; lowest lanes keep rank computation trivial.
__device__ __forceinline__ unsigned select_lowest_n_bits(unsigned mask, int n) {
    unsigned out = 0u;
#pragma unroll
    for (int i = 0; i < kWarpSize; ++i) {
        if (i >= n) break;
        const int bit = __ffs(mask) - 1;
        out |= (1u << bit);
        mask &= (mask - 1u);
    }
    return out;
}

// After a merge, max_distance can only decrease. Re-filter the still-pending
// candidates so obviously-too-far points are dropped immediately.
__device__ __forceinline__ unsigned refresh_pending_mask(
    unsigned pending_mask,
    float lane_distance,
    float max_distance,
    int lane) {
    const bool pending = ((pending_mask >> lane) & 1u) != 0u;
    return __ballot_sync(kFullMask, pending && (lane_distance < max_distance));
}

// Bitonic sort of a warp-owned shared-memory array of power-of-two length N.
// Each lane processes the positions lane, lane+32, lane+64, ...
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(float *dist, int *idx, int lane) {
    static_assert((N & (N - 1)) == 0, "Bitonic sort size must be a power of two");
    static_assert(N >= kWarpSize, "Sort size must be at least one warp");

    for (int k = 2; k <= N; k <<= 1) {
        for (int j = k >> 1; j > 0; j >>= 1) {
#pragma unroll
            for (int pos = lane; pos < N; pos += kWarpSize) {
                const int partner = pos ^ j;
                if (partner > pos) {
                    const float di = dist[pos];
                    const float dj = dist[partner];
                    const int   ii = idx[pos];
                    const int   ij = idx[partner];

                    const bool ascending = ((pos & k) == 0);
                    const bool do_swap = ascending
                        ? pair_greater(di, ii, dj, ij)
                        : pair_less(di, ii, dj, ij);

                    if (do_swap) {
                        dist[pos] = dj;
                        dist[partner] = di;
                        idx[pos] = ij;
                        idx[partner] = ii;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Merge the warp-private sorted top-K in registers with the shared candidate
// buffer using the exact required sequence:
//
// 1) sort buffer ascending,
// 2) take pointwise min(buffer[i], best[K-1-i]) to build a bitonic sequence
//    containing the K smallest elements of both arrays,
// 3) bitonic-sort that merged sequence ascending.
//
// The candidate buffer is padded with (+inf, INT_MAX) so the same fixed-size
// bitonic sort works for both full and partially filled buffers.
template <int K>
__device__ __forceinline__ void merge_buffer_into_best(
    int *cand_count,
    int *cand_idx,
    float *cand_dist,
    int (&best_idx)[K / kWarpSize],
    float (&best_dist)[K / kWarpSize],
    float &max_distance,
    int lane) {

    constexpr int SlotsPerLane = K / kWarpSize;
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "Unsupported K");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size");

    int count = 0;
    if (lane == 0) count = *cand_count;
    count = __shfl_sync(kFullMask, count, 0);
    if (count == 0) return;

#pragma unroll
    for (int pos = lane; pos < K; pos += kWarpSize) {
        if (pos >= count) {
            cand_dist[pos] = CUDART_INF_F;
            cand_idx[pos] = INT_MAX;
        }
    }
    __syncwarp();

    // Step 1: sort the candidate buffer ascending.
    bitonic_sort_shared<K>(cand_dist, cand_idx, lane);

    // Step 2: build the required bitonic sequence of the best K elements.
#pragma unroll
    for (int s = 0; s < SlotsPerLane; ++s) {
        const int pos = lane + s * kWarpSize;

        const float rev_best_dist =
            __shfl_sync(kFullMask, best_dist[SlotsPerLane - 1 - s], kWarpSize - 1 - lane);
        const int rev_best_idx =
            __shfl_sync(kFullMask, best_idx[SlotsPerLane - 1 - s], kWarpSize - 1 - lane);

        const float cd = cand_dist[pos];
        const int ci = cand_idx[pos];

        if (!pair_less(cd, ci, rev_best_dist, rev_best_idx)) {
            cand_dist[pos] = rev_best_dist;
            cand_idx[pos] = rev_best_idx;
        }
    }
    __syncwarp();

    // Step 3: sort the merged bitonic sequence ascending.
    bitonic_sort_shared<K>(cand_dist, cand_idx, lane);

#pragma unroll
    for (int s = 0; s < SlotsPerLane; ++s) {
        const int pos = lane + s * kWarpSize;
        best_idx[s] = cand_idx[pos];
        best_dist[s] = cand_dist[pos];
    }

    const float lane_tail = best_dist[SlotsPerLane - 1];
    max_distance = __shfl_sync(kFullMask, lane_tail, kWarpSize - 1);

    // Only one warp touches its own counter, so a plain shared write is enough.
    if (lane == 0) *cand_count = 0;
    __syncwarp();
}

// Insert the current 32-lane candidate chunk into the shared candidate buffer.
// The prompt requires atomicAdd to update the candidate count; this uses a
// warp-aggregated variant so one atomic reserves a contiguous block of slots
// for many qualifying lanes at once.
template <int K>
__device__ __forceinline__ void insert_candidate_chunk(
    unsigned qualifying_mask,
    int lane_candidate_idx,
    float lane_candidate_dist,
    int *cand_count,
    int *cand_idx,
    float *cand_dist,
    int (&best_idx)[K / kWarpSize],
    float (&best_dist)[K / kWarpSize],
    float &max_distance,
    int lane) {

    const unsigned lane_bit = 1u << lane;

    while (qualifying_mask) {
        int current_count = 0;
        if (lane == 0) current_count = *cand_count;
        current_count = __shfl_sync(kFullMask, current_count, 0);

        if (current_count == K) {
            merge_buffer_into_best<K>(
                cand_count, cand_idx, cand_dist, best_idx, best_dist, max_distance, lane);
            qualifying_mask = refresh_pending_mask(
                qualifying_mask, lane_candidate_dist, max_distance, lane);
            continue;
        }

        const int available = K - current_count;
        const int pending = __popc(qualifying_mask);
        const int to_insert = (pending < available) ? pending : available;

        unsigned insert_mask = 0u;
        if (lane == 0) {
            insert_mask = select_lowest_n_bits(qualifying_mask, to_insert);
        }
        insert_mask = __shfl_sync(kFullMask, insert_mask, 0);

        int base = 0;
        if (lane == 0) {
            // Required atomicAdd on the shared candidate count.
            base = atomicAdd(cand_count, to_insert);
        }
        base = __shfl_sync(kFullMask, base, 0);

        if (insert_mask & lane_bit) {
            const unsigned prior_bits = (lane == 0) ? 0u : (lane_bit - 1u);
            const int rank = __popc(insert_mask & prior_bits);
            const int pos = base + rank;
            cand_idx[pos] = lane_candidate_idx;
            cand_dist[pos] = lane_candidate_dist;
        }
        __syncwarp();

        qualifying_mask &= ~insert_mask;
        current_count += to_insert;

        if (current_count == K) {
            merge_buffer_into_best<K>(
                cand_count, cand_idx, cand_dist, best_idx, best_dist, max_distance, lane);
            qualifying_mask = refresh_pending_mask(
                qualifying_mask, lane_candidate_dist, max_distance, lane);
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize, 2)
void knn_kernel(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int batch_points) {

    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "Unsupported K");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size");
    static_assert(WARPS_PER_BLOCK >= 1 && WARPS_PER_BLOCK <= 8, "Unexpected block shape");

    // Shared-memory layout:
    // [batch_points x float2 staged data]
    // [WARPS_PER_BLOCK x int candidate counts]
    // [WARPS_PER_BLOCK x K x int candidate indices]
    // [WARPS_PER_BLOCK x K x float candidate distances]
    extern __shared__ unsigned char shared_raw[];

    float2 *sh_data = reinterpret_cast<float2 *>(shared_raw);
    unsigned char *ptr =
        shared_raw + static_cast<std::size_t>(batch_points) * sizeof(float2);

    int *sh_cand_count = reinterpret_cast<int *>(ptr);
    ptr += static_cast<std::size_t>(WARPS_PER_BLOCK) * sizeof(int);

    int *sh_cand_idx = reinterpret_cast<int *>(ptr);
    ptr += static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(int);

    float *sh_cand_dist = reinterpret_cast<float *>(ptr);

    const int warp_id = threadIdx.x >> 5;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool query_active = (query_idx < query_count);

    int *cand_count = &sh_cand_count[warp_id];
    int *cand_idx = &sh_cand_idx[warp_id * K];
    float *cand_dist = &sh_cand_dist[warp_id * K];

    if (lane == 0) *cand_count = 0;
    __syncwarp();

    constexpr int SlotsPerLane = K / kWarpSize;
    int best_idx[SlotsPerLane];
    float best_dist[SlotsPerLane];
    bool best_initialized = false;
    float max_distance = CUDART_INF_F;

    float qx = 0.0f;
    float qy = 0.0f;
    if (query_active) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    for (int batch_start = 0; batch_start < data_count; batch_start += batch_points) {
        int current_batch = data_count - batch_start;
        if (current_batch > batch_points) current_batch = batch_points;

        // Whole block stages the next tile of data points into shared memory.
        for (int i = threadIdx.x; i < current_batch; i += blockDim.x) {
            sh_data[i] = data[batch_start + i];
        }
        __syncthreads();

        if (query_active) {
            int local_begin = 0;

            // Initialization uses the first K points of the first tile.
            // Host-side launch selection guarantees batch_points >= K.
            if (!best_initialized) {
#pragma unroll
                for (int s = 0; s < SlotsPerLane; ++s) {
                    const int pos = lane + s * kWarpSize;
                    cand_idx[pos] = pos;  // batch_start == 0 here
                    cand_dist[pos] = squared_l2(qx, qy, sh_data[pos]);
                }
                __syncwarp();

                bitonic_sort_shared<K>(cand_dist, cand_idx, lane);

#pragma unroll
                for (int s = 0; s < SlotsPerLane; ++s) {
                    const int pos = lane + s * kWarpSize;
                    best_idx[s] = cand_idx[pos];
                    best_dist[s] = cand_dist[pos];
                }

                const float lane_tail = best_dist[SlotsPerLane - 1];
                max_distance = __shfl_sync(kFullMask, lane_tail, kWarpSize - 1);

                best_initialized = true;
                local_begin = K;
            }

            // Process the tile in warp-sized chunks. Strict `< max_distance`
            // matches the prompt; equal distances may be broken arbitrarily.
            for (int local_base = local_begin; local_base < current_batch; local_base += kWarpSize) {
                const int local = local_base + lane;

                int data_idx = -1;
                float dist = CUDART_INF_F;
                bool qualifies = false;

                if (local < current_batch) {
                    data_idx = batch_start + local;
                    dist = squared_l2(qx, qy, sh_data[local]);
                    qualifies = (dist < max_distance);
                }

                const unsigned qualifying_mask =
                    __ballot_sync(kFullMask, qualifies);

                if (qualifying_mask) {
                    insert_candidate_chunk<K>(
                        qualifying_mask,
                        data_idx,
                        dist,
                        cand_count,
                        cand_idx,
                        cand_dist,
                        best_idx,
                        best_dist,
                        max_distance,
                        lane);
                }
            }
        }

        // All warps must finish reading this tile before the block overwrites it.
        __syncthreads();
    }

    if (query_active) {
        int tail_count = 0;
        if (lane == 0) tail_count = *cand_count;
        tail_count = __shfl_sync(kFullMask, tail_count, 0);

        if (tail_count > 0) {
            merge_buffer_into_best<K>(
                cand_count, cand_idx, cand_dist, best_idx, best_dist, max_distance, lane);
        }

        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

#pragma unroll
        for (int s = 0; s < SlotsPerLane; ++s) {
            const int pos = lane + s * kWarpSize;
            result[out_base + pos].first = best_idx[s];
            result[out_base + pos].second = best_dist[s];
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
constexpr std::size_t shared_overhead_bytes() {
    return static_cast<std::size_t>(WARPS_PER_BLOCK) * sizeof(int) +
           static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(int) +
           static_cast<std::size_t>(WARPS_PER_BLOCK) * K * sizeof(float);
}

template <int K>
constexpr int preferred_batch_points() {
    return (K == 1024) ? 2048 : 4096;
}

template <int K, int WARPS_PER_BLOCK>
bool launch_variant(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int max_dynamic_smem) {

    constexpr std::size_t overhead = shared_overhead_bytes<K, WARPS_PER_BLOCK>();

    if (max_dynamic_smem <= 0) return false;
    if (static_cast<std::size_t>(max_dynamic_smem) <= overhead) return false;

    const std::size_t available_batch_bytes =
        static_cast<std::size_t>(max_dynamic_smem) - overhead;

    int max_batch_points = static_cast<int>(
        (available_batch_bytes / sizeof(float2)) &
        ~static_cast<std::size_t>(kWarpSize - 1));

    if (max_batch_points < K) return false;

    int batch_points = preferred_batch_points<K>();
    if (batch_points > max_batch_points) batch_points = max_batch_points;
    if (batch_points < K) batch_points = K;

    const std::size_t shared_bytes =
        overhead + static_cast<std::size_t>(batch_points) * sizeof(float2);

    cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shared_bytes));

    cudaFuncSetAttribute(
        knn_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    cudaFuncSetCacheConfig(knn_kernel<K, WARPS_PER_BLOCK>, cudaFuncCachePreferShared);

    const dim3 block(WARPS_PER_BLOCK * kWarpSize);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K, WARPS_PER_BLOCK><<<grid, block, shared_bytes>>>(
        query, query_count, data, data_count, result, batch_points);

    return true;
}

template <int K>
void dispatch_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result) {

    int device = 0;
    cudaGetDevice(&device);

    int max_smem_default = 0;
    int max_smem_optin = 0;
    cudaDeviceGetAttribute(&max_smem_default, cudaDevAttrMaxSharedMemoryPerBlock, device);
    cudaDeviceGetAttribute(&max_smem_optin, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    int max_dynamic_smem = max_smem_default;
    if (max_smem_optin > max_dynamic_smem) max_dynamic_smem = max_smem_optin;
    if (max_dynamic_smem <= 0) max_dynamic_smem = 48 * 1024;

    // Prefer 8 warps/block for maximum staged-data reuse across queries, but
    // fall back if the device's dynamic shared-memory budget is smaller.
    if (launch_variant<K, 8>(query, query_count, data, data_count, result, max_dynamic_smem)) return;
    if (launch_variant<K, 4>(query, query_count, data, data_count, result, max_dynamic_smem)) return;
    if (launch_variant<K, 2>(query, query_count, data, data_count, result, max_dynamic_smem)) return;
    (void)launch_variant<K, 1>(query, query_count, data, data_count, result, max_dynamic_smem);
}

} // namespace

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k) {

    if (query_count <= 0) return;

    switch (k) {
        case 32:   dispatch_knn<32>(query, query_count, data, data_count, result); break;
        case 64:   dispatch_knn<64>(query, query_count, data, data_count, result); break;
        case 128:  dispatch_knn<128>(query, query_count, data, data_count, result); break;
        case 256:  dispatch_knn<256>(query, query_count, data, data_count, result); break;
        case 512:  dispatch_knn<512>(query, query_count, data, data_count, result); break;
        case 1024: dispatch_knn<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs are guaranteed valid by the prompt.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace knn_cuda_internal {

constexpr int WARP_SIZE = 32;
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

// Largest universal tile that keeps all chosen high-reuse CTA configurations
// below the opt-in per-block shared-memory budget of modern datacenter GPUs
// such as A100/H100, while noticeably reducing block-wide barrier frequency.
constexpr int DATA_TILE_POINTS = 2048;
constexpr std::size_t MAX_TARGET_SHARED_BYTES = 163840;

struct alignas(8) PairDI {
    float dist;
    int idx;
};

static_assert(sizeof(PairDI) == 8, "PairDI must remain compact.");
static_assert((DATA_TILE_POINTS % WARP_SIZE) == 0, "Tile size must be a multiple of the warp size.");

__device__ __forceinline__ PairDI make_pairdi(const float dist, const int idx) {
    PairDI p;
    p.dist = dist;
    p.idx = idx;
    return p;
}

__device__ __forceinline__ PairDI sentinel_pair() {
    return make_pairdi(CUDART_INF_F, INT_MAX);
}

// Tie handling is arbitrary per the prompt; we use index as a deterministic
// secondary key so the sorting network sees a total order.
__device__ __forceinline__ bool pair_less(const PairDI a, const PairDI b) {
    return (a.dist < b.dist) || ((a.dist == b.dist) && (a.idx < b.idx));
}

__device__ __forceinline__ PairDI pair_min(const PairDI a, const PairDI b) {
    return pair_less(b, a) ? b : a;
}

// In-place bitonic sort over a warp-private shared-memory array of length K.
// Lane t owns logical positions t, t + 32, t + 64, ...
template <int K>
__device__ __forceinline__ void bitonic_sort_shared(PairDI* const arr, const int lane) {
    for (int stage = 2; stage <= K; stage <<= 1) {
        for (int stride = stage >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int i = lane; i < K; i += WARP_SIZE) {
                const int j = i ^ stride;
                if (j > i) {
                    const PairDI a = arr[i];
                    const PairDI b = arr[j];
                    const bool up = ((i & stage) == 0);
                    const bool do_swap = up ? pair_less(b, a) : pair_less(a, b);
                    if (do_swap) {
                        arr[i] = b;
                        arr[j] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Flush the shared candidate buffer into the warp-private top-k.
//
// This follows the requested merge procedure exactly:
// 1. sort the shared candidate buffer ascending with bitonic sort;
// 2. build the bitonic "small half" using
//      merged[i] = min(buffer[i], result[k - i - 1]);
// 3. bitonic-sort that merged sequence ascending.
template <int K>
__device__ __forceinline__ void flush_buffer(
    PairDI* const cand,
    PairDI* const scratch,
    int* const count,
    float (&result_dist)[K / WARP_SIZE],
    int (&result_idx)[K / WARP_SIZE],
    const int lane,
    float& max_distance)
{
    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;

    __syncwarp();

    int c = 0;
    if (lane == 0) {
        c = *count;
    }
    c = __shfl_sync(FULL_MASK, c, 0);

    if (c == 0) {
        return;
    }

    const PairDI inf = sentinel_pair();

    // Pad the inactive tail with +inf sentinels so the full K-element buffer can
    // always be sorted by the fixed-size bitonic network.
#pragma unroll
    for (int i = lane; i < K; i += WARP_SIZE) {
        if (i >= c) {
            cand[i] = inf;
        }
    }
    __syncwarp();

    bitonic_sort_shared<K>(cand, lane);

    // Materialize the warp-private result into shared scratch so the merge can
    // read it in reverse order while still keeping the live top-k private between flushes.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        const int pos = t * WARP_SIZE + lane;
        scratch[pos] = make_pairdi(result_dist[t], result_idx[t]);
    }
    __syncwarp();

    // Build the bitonic "small half".
#pragma unroll
    for (int i = lane; i < K; i += WARP_SIZE) {
        cand[i] = pair_min(cand[i], scratch[K - 1 - i]);
    }
    __syncwarp();

    bitonic_sort_shared<K>(cand, lane);

    // Reload the updated top-k back into the warp-private copy.
#pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        const int pos = t * WARP_SIZE + lane;
        const PairDI v = cand[pos];
        result_dist[t] = v.dist;
        result_idx[t] = v.idx;
    }

    float last = 0.0f;
    if (lane == (WARP_SIZE - 1)) {
        last = result_dist[ITEMS_PER_THREAD - 1];
    }
    max_distance = __shfl_sync(FULL_MASK, last, WARP_SIZE - 1);

    if (lane == 0) {
        *count = 0;
    }
    __syncwarp();
}

// One warp handles one query. The block stages a tile of `data` into shared memory
// so all query warps in the block reuse the same global loads. No extra device memory
// is allocated: the live top-k is private to the warp, while the candidate buffer and
// merge scratch are warp-private slices of shared memory.
template <int K, int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS)
void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    std::pair<int, float>* __restrict__ result_out)
{
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K % WARP_SIZE) == 0, "K must be divisible by warp size.");
    static_assert((BLOCK_THREADS % WARP_SIZE) == 0, "Block size must be a multiple of warp size.");

    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / WARP_SIZE;

    extern __shared__ unsigned char smem_raw[];

    // Shared layout:
    //   [cached data tile][candidate buffers][merge scratch][candidate counts]
    float2* const s_data = reinterpret_cast<float2*>(smem_raw);
    PairDI* const s_cand = reinterpret_cast<PairDI*>(s_data + DATA_TILE_POINTS);
    PairDI* const s_scratch = s_cand + WARPS_PER_BLOCK * K;
    int* const s_count = reinterpret_cast<int*>(s_scratch + WARPS_PER_BLOCK * K);

    const int lane = threadIdx.x & (WARP_SIZE - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool valid_query = (query_idx < query_count);

    PairDI* const cand = s_cand + warp_id * K;
    PairDI* const scratch = s_scratch + warp_id * K;
    int* const count = s_count + warp_id;

    // Warp-private top-k distributed across the 32 lanes.
    float result_dist[ITEMS_PER_THREAD];
    int result_idx[ITEMS_PER_THREAD];
#pragma unroll
    for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
        result_dist[t] = CUDART_INF_F;
        result_idx[t] = INT_MAX;
    }

    if (lane == 0) {
        *count = 0;
    }

    // Broadcast the query point once and keep it in registers across the whole scan.
    float qx = 0.0f;
    float qy = 0.0f;
    if (valid_query && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Replicated across the warp; updated whenever the private top-k changes.
    float max_distance = CUDART_INF_F;

    __syncthreads();

    for (int tile_base = 0; tile_base < data_count; tile_base += DATA_TILE_POINTS) {
        int tile_count = data_count - tile_base;
        if (tile_count > DATA_TILE_POINTS) {
            tile_count = DATA_TILE_POINTS;
        }

        for (int i = threadIdx.x; i < tile_count; i += BLOCK_THREADS) {
            s_data[i] = data[tile_base + i];
        }
        __syncthreads();

        if (valid_query) {
            // Process the tile in warp-sized micro-batches. This lets the warp:
            //  - compute 32 distances in parallel,
            //  - ballot surviving candidates,
            //  - compact them with one warp-aggregated atomicAdd.
            for (int seg = 0; seg < tile_count; seg += WARP_SIZE) {
                const int local_i = seg + lane;
                const bool valid_point = (local_i < tile_count);

                float dist = 0.0f;
                const int idx = tile_base + local_i;

                if (valid_point) {
                    const float2 p = s_data[local_i];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                }

                unsigned mask = __ballot_sync(FULL_MASK, valid_point && (dist < max_distance));
                int num = __popc(mask);

                if (num != 0) {
                    // If this whole micro-batch could overflow the shared candidate buffer,
                    // flush first, then re-evaluate against the tighter threshold.
                    int current_count = 0;
                    if (lane == 0) {
                        current_count = *count;
                    }
                    current_count = __shfl_sync(FULL_MASK, current_count, 0);

                    if (current_count + num > K) {
                        flush_buffer<K>(cand, scratch, count, result_dist, result_idx, lane, max_distance);
                        mask = __ballot_sync(FULL_MASK, valid_point && (dist < max_distance));
                        num = __popc(mask);
                    }

                    if (num != 0) {
                        // The prompt requires atomicAdd for the candidate count update.
                        // We do it once per micro-batch and derive each lane's slot by
                        // adding its prefix within the ballot mask.
                        int base = 0;
                        if (lane == 0) {
                            base = atomicAdd(count, num);
                        }
                        base = __shfl_sync(FULL_MASK, base, 0);

                        const unsigned lane_bit = 1u << lane;
                        if (valid_point && (mask & lane_bit)) {
                            const unsigned prior = mask & (lane_bit - 1u);
                            const int pos = base + __popc(prior);
                            cand[pos] = make_pairdi(dist, idx);
                        }

                        __syncwarp();

                        // Flush immediately on a full candidate buffer.
                        if (base + num == K) {
                            flush_buffer<K>(cand, scratch, count, result_dist, result_idx, lane, max_distance);
                        }
                    }
                }
            }
        }

        // The next tile will overwrite s_data, so all warps must be done with it first.
        __syncthreads();
    }

    if (valid_query) {
        flush_buffer<K>(cand, scratch, count, result_dist, result_idx, lane, max_distance);

        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);
#pragma unroll
        for (int t = 0; t < ITEMS_PER_THREAD; ++t) {
            const std::size_t out_pos = out_base + static_cast<std::size_t>(t * WARP_SIZE + lane);
            result_out[out_pos].first = result_idx[t];
            result_out[out_pos].second = result_dist[t];
        }
    }
}

template <int K, int BLOCK_THREADS>
constexpr std::size_t shared_bytes_for_kernel() {
    return static_cast<std::size_t>(DATA_TILE_POINTS) * sizeof(float2) +
           static_cast<std::size_t>(2) * static_cast<std::size_t>(BLOCK_THREADS / WARP_SIZE) *
               static_cast<std::size_t>(K) * sizeof(PairDI) +
           static_cast<std::size_t>(BLOCK_THREADS / WARP_SIZE) * sizeof(int);
}

template <int K, int BLOCK_THREADS>
inline void launch_knn_impl(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    std::pair<int, float>* result)
{
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / WARP_SIZE;
    constexpr std::size_t SHMEM_BYTES = shared_bytes_for_kernel<K, BLOCK_THREADS>();
    static_assert(SHMEM_BYTES <= MAX_TARGET_SHARED_BYTES,
                  "Selected specialization exceeds the per-block shared-memory budget.");

    const dim3 block(BLOCK_THREADS);
    const unsigned int grid_x = static_cast<unsigned int>(
        (static_cast<std::size_t>(query_count) + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);
    const dim3 grid(grid_x);

    // Opt into the large dynamic shared-memory footprint needed by:
    //   - the cached data tile,
    //   - one candidate buffer per warp/query,
    //   - one merge scratch array per warp/query.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHMEM_BYTES));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, BLOCK_THREADS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    knn_kernel<K, BLOCK_THREADS><<<grid, block, SHMEM_BYTES>>>(
        query, query_count, data, data_count, result);
}

} // namespace knn_cuda_internal

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    // Hyper-parameter choice:
    // The dominant cost is repeatedly streaming the large `data` array. Therefore we pick
    // the largest number of query warps per block that still fits the shared-memory budget,
    // maximizing reuse of each cached data tile:
    //   k <= 256  -> 32 warps/block  (1024 threads)
    //   k == 512  -> 16 warps/block  ( 512 threads)
    //   k == 1024 ->  8 warps/block  ( 256 threads)
    switch (k) {
        case 32:
            knn_cuda_internal::launch_knn_impl<32, 1024>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_cuda_internal::launch_knn_impl<64, 1024>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_cuda_internal::launch_knn_impl<128, 1024>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_cuda_internal::launch_knn_impl<256, 1024>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_cuda_internal::launch_knn_impl<512, 512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_cuda_internal::launch_knn_impl<1024, 256>(query, query_count, data, data_count, result);
            break;
        default:
            // Inputs are guaranteed valid by the caller.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace {

// High-level design:
// - One warp owns one query for the whole kernel lifetime.
// - A whole thread block streams the data set through shared memory in batches.
// - Each warp keeps two private K-element shared-memory arrays:
//     1) result_* : current sorted top-K for its query.
//     2) buffer_* : candidate buffer filled via a warp-aggregated shared-memory atomicAdd.
// - Whenever the candidate buffer fills (or at the very end), the warp performs exactly the
//   merge requested by the prompt:
//     1) bitonic-sort the buffer ascending,
//     2) build the bitonic "min(buffer[i], result[K-1-i])" sequence,
//     3) bitonic-sort that sequence ascending to obtain the updated top-K.
//
// Implementation notes tuned for A100/H100:
// - 256 threads / 8 warps per block balance:
//     * shared-memory reuse of each loaded data batch across 8 queries,
//     * enough block-level parallelism for the "thousands of queries" regime,
//     * feasibility for K up to 1024 under A100's 160 KiB opt-in shared-memory limit.
// - Shared memory uses a structure-of-arrays layout (separate x/y, distance/index arrays) to
//   avoid the extra shared-memory bank conflicts that 8-byte AoS/float2 accesses would create.
// - Batch size is specialized per K and chosen as the largest warp-aligned value that preserves
//   a good A100-compatible active-block count for that K specialization.

using ResultPair = std::pair<int, float>;

constexpr int kWarpSize        = 32;
constexpr unsigned kFullMask   = 0xFFFFFFFFu;
constexpr int kWarpsPerBlock   = 8;
constexpr int kBlockThreads    = kWarpsPerBlock * kWarpSize;
constexpr int kInvalidIndex    = INT_MAX;
constexpr int kMaxOptInSmem    = 163840; // 160 KiB, the A100-compatible opt-in per-block limit.

static_assert(kBlockThreads == 256, "This kernel is tuned for 256 threads per block.");

// Per-K tuning:
// Each batch size is a multiple of 32 so that each warp processes whole chunks and the shared
// arrays remain naturally 128-byte aligned.
// Comments show the intended A100-compatible active-block target with 8 warps/block.
template <int K> struct KernelTuning;

template <> struct KernelTuning<32>   { static constexpr int batch_points = 2016; }; // 8 blocks/SM
template <> struct KernelTuning<64>   { static constexpr int batch_points = 2368; }; // 6 blocks/SM
template <> struct KernelTuning<128>  { static constexpr int batch_points = 2016; }; // 5 blocks/SM
template <> struct KernelTuning<256>  { static constexpr int batch_points = 2720; }; // 3 blocks/SM
template <> struct KernelTuning<512>  { static constexpr int batch_points = 2016; }; // 2 blocks/SM
template <> struct KernelTuning<1024> { static constexpr int batch_points = 4064; }; // 1 block /SM

template <int K>
constexpr std::size_t shared_bytes_for_kernel() {
    constexpr int B = KernelTuning<K>::batch_points;
    return
        static_cast<std::size_t>(2) * B * sizeof(float) +                   // batch_x, batch_y
        static_cast<std::size_t>(kWarpsPerBlock) * sizeof(int) +            // per-warp candidate counts
        static_cast<std::size_t>(2) * kWarpsPerBlock * K * sizeof(float) +  // result_dist, buffer_dist
        static_cast<std::size_t>(2) * kWarpsPerBlock * K * sizeof(int);     // result_idx,  buffer_idx
}

// Warp-private state: each warp gets disjoint shared-memory slices, so the state is private
// to one query even though it physically resides in shared memory.
struct WarpTopKState {
    float *result_dist;
    int   *result_idx;
    float *buffer_dist;
    int   *buffer_idx;
    int   *cand_count;
};

__device__ __forceinline__ bool pair_less(float a_dist, int a_idx,
                                          float b_dist, int b_idx) {
    // Sorting/merging uses a total order (distance, then index) to keep the bitonic network
    // deterministic. Candidate admission still uses only "dist < max_distance", exactly as
    // requested by the prompt, so ties at the threshold remain arbitrary.
    if (a_dist < b_dist) return true;
    if (a_dist > b_dist) return false;
    return a_idx < b_idx;
}

__device__ __forceinline__ float squared_distance(float qx, float qy,
                                                  float px, float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return __fmaf_rn(dx, dx, dy * dy);
}

template <int N>
__device__ __forceinline__ void bitonic_sort_asc(float *dist, int *idx) {
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    // The outer loops are intentionally not forcibly unrolled to keep instruction footprint
    // reasonable for N up to 1024. The innermost per-lane strided loop is unrolled because
    // its trip count is compile-time fixed (N / 32).
    #pragma unroll 1
    for (int size = 2; size <= N; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll
            for (int i = lane; i < N; i += kWarpSize) {
                const int j = i ^ stride;
                if (j > i) {
                    const float di = dist[i];
                    const float dj = dist[j];
                    const int   ii = idx[i];
                    const int   ij = idx[j];

                    const bool up = ((i & size) == 0);
                    const bool do_swap = up
                        ? pair_less(dj, ij, di, ii)
                        : pair_less(di, ii, dj, ij);

                    if (do_swap) {
                        dist[i] = dj; idx[i] = ij;
                        dist[j] = di; idx[j] = ii;
                    }
                }
            }
            __syncwarp();
        }
    }
}

template <int K>
__device__ __forceinline__ float flush_candidate_buffer(WarpTopKState &state) {
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    // Make sure all candidate writes are visible before the warp starts consuming the buffer.
    __syncwarp();

    int count = 0;
    if (lane == 0) {
        count = *state.cand_count;
    }
    count = __shfl_sync(kFullMask, count, 0);

    // Pad the unused tail with +inf so the full-K bitonic network can be reused unchanged.
    #pragma unroll
    for (int i = count + lane; i < K; i += kWarpSize) {
        state.buffer_dist[i] = CUDART_INF_F;
        state.buffer_idx[i]  = kInvalidIndex;
    }
    __syncwarp();

    // Step 1: sort the candidate buffer ascending.
    bitonic_sort_asc<K>(state.buffer_dist, state.buffer_idx);

    // Step 2: build the K-element bitonic sequence that contains the K smallest elements from
    //         buffer U result by taking minima against the reversed current result.
    #pragma unroll
    for (int i = lane; i < K; i += kWarpSize) {
        const int rev = K - 1 - i;

        const float bd = state.buffer_dist[i];
        const int   bi = state.buffer_idx[i];
        const float rd = state.result_dist[rev];
        const int   ri = state.result_idx[rev];

        if (pair_less(rd, ri, bd, bi)) {
            state.buffer_dist[i] = rd;
            state.buffer_idx[i]  = ri;
        }
    }
    __syncwarp();

    // Step 3: bitonic-sort the merged bitonic sequence ascending.
    bitonic_sort_asc<K>(state.buffer_dist, state.buffer_idx);

    // The freshly sorted data now lives in buffer_*. Swap the role of the two arrays instead
    // of copying K elements back.
    float *tmp_dist = state.result_dist;
    state.result_dist = state.buffer_dist;
    state.buffer_dist = tmp_dist;

    int *tmp_idx = state.result_idx;
    state.result_idx = state.buffer_idx;
    state.buffer_idx = tmp_idx;

    if (lane == 0) {
        *state.cand_count = 0;
    }
    __syncwarp();

    float max_distance = 0.0f;
    if (lane == 0) {
        max_distance = state.result_dist[K - 1];
    }
    return __shfl_sync(kFullMask, max_distance, 0);
}

template <int K>
__device__ __forceinline__ void process_cached_batch(
    float qx, float qy,
    const float *batch_x,
    const float *batch_y,
    int batch_base,
    int start,
    int tile_count,
    WarpTopKState &state,
    float &max_distance) {

    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);
    const unsigned lane_prefix_mask =
        (lane == 0) ? 0u : ((1u << static_cast<unsigned>(lane)) - 1u);

    // One cached point per lane per iteration, so at most 32 new candidates appear in a chunk.
    // Because K >= 32, a single pre-flush is enough to make room before insertion.
    for (int local_base = start; local_base < tile_count; local_base += kWarpSize) {
        const int local_idx = local_base + lane;

        bool  valid      = (local_idx < tile_count);
        bool  qualifies  = false;
        float dist       = 0.0f;
        int   global_idx = 0;

        if (valid) {
            const float px = batch_x[local_idx];
            const float py = batch_y[local_idx];
            dist = squared_distance(qx, qy, px, py);
            global_idx = batch_base + local_idx;

            // Strict '<' on max_distance follows the prompt exactly.
            qualifies = (dist < max_distance);
        }

        unsigned mask = __ballot_sync(kFullMask, qualifies);
        int num_new = __popc(mask);
        if (num_new == 0) {
            continue;
        }

        int current_count = 0;
        if (lane == 0) {
            current_count = *state.cand_count;
        }
        current_count = __shfl_sync(kFullMask, current_count, 0);

        // If the current chunk would overflow the K-sized buffer, flush first.
        if (current_count + num_new > K) {
            max_distance = flush_candidate_buffer<K>(state);

            // The flush may tighten max_distance. Re-test the already computed distances so we
            // do not enqueue obviously dominated candidates into the now-empty buffer.
            qualifies = valid && (dist < max_distance);
            mask = __ballot_sync(kFullMask, qualifies);
            num_new = __popc(mask);
            if (num_new == 0) {
                continue;
            }
        }

        // Warp-aggregated atomicAdd: one shared atomic per warp-chunk instead of one per lane,
        // while still using atomicAdd exactly as requested to reserve buffer positions.
        int base_slot = 0;
        if (lane == 0) {
            base_slot = atomicAdd(state.cand_count, num_new);
        }
        base_slot = __shfl_sync(kFullMask, base_slot, 0);

        if (qualifies) {
            const int rank = __popc(mask & lane_prefix_mask);
            state.buffer_dist[base_slot + rank] = dist;
            state.buffer_idx[base_slot + rank]  = global_idx;
        }
        __syncwarp();

        // If the insertion filled the buffer exactly, merge immediately so max_distance stays
        // as tight as possible for subsequent pruning.
        if (base_slot + num_new == K) {
            max_distance = flush_candidate_buffer<K>(state);
        }
    }
}

template <int K>
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           ResultPair * __restrict__ output) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= 32 && K <= 1024, "Supported K range is [32, 1024].");

    constexpr int kBatchPoints = KernelTuning<K>::batch_points;
    static_assert((kBatchPoints % kWarpSize) == 0, "Batch size must be warp-aligned.");
    static_assert(kBatchPoints > K, "The first batch must be able to seed the initial top-K.");

    extern __shared__ unsigned char shared_raw[];

    // Shared-memory layout (SoA to minimize bank conflicts):
    //   batch_x[kBatchPoints]
    //   batch_y[kBatchPoints]
    //   cand_count[kWarpsPerBlock]
    //   result_dist[kWarpsPerBlock * K]
    //   result_idx [kWarpsPerBlock * K]
    //   buffer_dist[kWarpsPerBlock * K]
    //   buffer_idx [kWarpsPerBlock * K]
    unsigned char *ptr = shared_raw;

    float *batch_x = reinterpret_cast<float *>(ptr);
    ptr += static_cast<std::size_t>(kBatchPoints) * sizeof(float);

    float *batch_y = reinterpret_cast<float *>(ptr);
    ptr += static_cast<std::size_t>(kBatchPoints) * sizeof(float);

    int *cand_count = reinterpret_cast<int *>(ptr);
    ptr += static_cast<std::size_t>(kWarpsPerBlock) * sizeof(int);

    float *result_dist_storage = reinterpret_cast<float *>(ptr);
    ptr += static_cast<std::size_t>(kWarpsPerBlock) * K * sizeof(float);

    int *result_idx_storage = reinterpret_cast<int *>(ptr);
    ptr += static_cast<std::size_t>(kWarpsPerBlock) * K * sizeof(int);

    float *buffer_dist_storage = reinterpret_cast<float *>(ptr);
    ptr += static_cast<std::size_t>(kWarpsPerBlock) * K * sizeof(float);

    int *buffer_idx_storage = reinterpret_cast<int *>(ptr);

    const int lane    = static_cast<int>(threadIdx.x) & (kWarpSize - 1);
    const int warp_id = static_cast<int>(threadIdx.x) >> 5;
    const int query_idx = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_id;
    const bool active = (query_idx < query_count);

    // Every warp owns one query and one private top-K state.
    const int warp_offset = warp_id * K;
    WarpTopKState state;
    state.result_dist = result_dist_storage + warp_offset;
    state.result_idx  = result_idx_storage  + warp_offset;
    state.buffer_dist = buffer_dist_storage + warp_offset;
    state.buffer_idx  = buffer_idx_storage  + warp_offset;
    state.cand_count  = cand_count + warp_id;

    if (lane == 0) {
        *state.cand_count = 0;
    }
    __syncwarp();

    float qx = 0.0f;
    float qy = 0.0f;
    float max_distance = CUDART_INF_F;

    if (active) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    for (int batch_base = 0; batch_base < data_count; batch_base += kBatchPoints) {
        int tile_count = data_count - batch_base;
        if (tile_count > kBatchPoints) {
            tile_count = kBatchPoints;
        }

        // Whole-block cooperative load of the next data batch into shared memory.
        for (int i = static_cast<int>(threadIdx.x); i < tile_count; i += kBlockThreads) {
            const float2 p = data[batch_base + i];
            batch_x[i] = p.x;
            batch_y[i] = p.y;
        }
        __syncthreads();

        if (active) {
            if (batch_base == 0) {
                // Seed the intermediate result with the first K data points.
                #pragma unroll
                for (int i = lane; i < K; i += kWarpSize) {
                    state.result_dist[i] = squared_distance(qx, qy, batch_x[i], batch_y[i]);
                    state.result_idx[i]  = i;
                }
                __syncwarp();

                // Invariant after this sort: result_* is ascending.
                bitonic_sort_asc<K>(state.result_dist, state.result_idx);

                if (lane == 0) {
                    max_distance = state.result_dist[K - 1];
                }
                max_distance = __shfl_sync(kFullMask, max_distance, 0);

                // Process the remainder of the first cached batch.
                process_cached_batch<K>(
                    qx, qy,
                    batch_x, batch_y,
                    batch_base,
                    K,
                    tile_count,
                    state,
                    max_distance);
            } else {
                // Process a regular cached batch.
                process_cached_batch<K>(
                    qx, qy,
                    batch_x, batch_y,
                    batch_base,
                    0,
                    tile_count,
                    state,
                    max_distance);
            }
        }

        // No barrier is needed after the final batch because the shared cache will not be reused.
        if (batch_base + tile_count < data_count) {
            __syncthreads();
        }
    }

    if (active) {
        int pending = 0;
        if (lane == 0) {
            pending = *state.cand_count;
        }
        pending = __shfl_sync(kFullMask, pending, 0);

        if (pending > 0) {
            max_distance = flush_candidate_buffer<K>(state);
            (void)max_distance;
        }

        // Write the final sorted top-K (indices + squared distances) back to global memory.
        ResultPair *out = output + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int i = lane; i < K; i += kWarpSize) {
            out[i].first  = state.result_idx[i];
            out[i].second = state.result_dist[i];
        }
    }
}

template <int K>
void launch_knn_specialized(const float2 *query,
                            int query_count,
                            const float2 *data,
                            int data_count,
                            ResultPair *output) {
    constexpr std::size_t smem_bytes = shared_bytes_for_kernel<K>();
    static_assert(smem_bytes <= kMaxOptInSmem,
                  "Shared-memory footprint exceeds the A100-compatible 160 KiB opt-in limit.");

    // Several specializations exceed the default 48 KiB dynamic shared-memory limit, so opt in.
    // Prefer shared-memory carveout because this kernel is explicitly shared-memory heavy.
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));

    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int grid = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    // Intentionally asynchronous: the caller owns synchronization and error handling policy.
    knn_kernel<K><<<grid, kBlockThreads, smem_bytes>>>(
        query, query_count, data, data_count, output);
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_specialized<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_specialized<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_specialized<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_specialized<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_specialized<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_specialized<1024>(query, query_count, data, data_count, result); break;
        default:
            // Per the prompt, inputs are always valid, so this path is unreachable in normal use.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn2d_detail {

// Targeted tuning choices for A100/H100-class GPUs:
//
// * One warp computes one query, exactly as requested.
// * 8 warps/block = 256 threads/block:
//   - enough warps per block to amortize each shared-memory data tile across 8 queries,
//   - still enough blocks when query_count is only in the low thousands on 100+ SM GPUs.
// * ~80 KiB dynamic shared memory/block:
//   - large enough to hold the per-warp candidate buffers plus a multi-thousand-point data tile,
//   - small enough that two such blocks still fit on 164 KiB/SM parts like A100.
constexpr int kWarpSize         = 32;
constexpr int kWarpsPerBlock    = 8;
constexpr int kThreadsPerBlock  = kWarpSize * kWarpsPerBlock;
constexpr unsigned kFullMask    = 0xFFFFFFFFu;
constexpr std::size_t kSharedBudgetBytes = 80ull * 1024ull;

// The public API uses std::pair<int,float>.  Device-side std::pair support is
// implementation-dependent, so the kernel writes through a POD with the same
// compact 8-byte ABI that all mainstream CUDA-supported standard libraries use
// for std::pair<int,float>.
struct ResultPair {
    int   first;
    float second;
};
static_assert(sizeof(ResultPair) == sizeof(std::pair<int, float>),
              "Unexpected std::pair<int,float> ABI: expected a compact 8-byte {int,float} layout.");

// Squared Euclidean distance in 2D; no square root is taken because the problem
// explicitly requests squared distances.
__device__ __forceinline__ float sq_l2_2d(const float qx, const float qy,
                                          const float px, const float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return __fmaf_rn(dx, dx, dy * dy);
}

// Bitonic sort of the warp-private intermediate top-k result.
//
// Storage layout:
//   global logical position p in [0, K)
//   is held by lane = p % 32, slot = p / 32.
//
// Because K is a power of two and a multiple of 32, the compare/swap network
// splits neatly into:
//   * stride < 32  -> partner lives in another lane, accessed with warp shuffles
//   * stride >= 32 -> partner lives in another local slot of the same lane
//
// The loops are intentionally fully unrolled.  This makes each slot index a
// compile-time constant after unrolling, which lets the compiler scalarize the
// per-lane arrays into registers instead of spilling them to local memory.
template <int K>
__device__ __forceinline__ void bitonic_sort_registers(float (&dist)[K / kWarpSize],
                                                       int (&idx)[K / kWarpSize]) {
    constexpr int ITEMS_PER_LANE = K / kWarpSize;
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    #pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            if (stride >= kWarpSize) {
                const int partner_delta = stride >> 5;

                #pragma unroll
                for (int t = 0; t < ITEMS_PER_LANE; ++t) {
                    const int partner_t = t ^ partner_delta;
                    if (partner_t > t) {
                        const int  p         = lane + t * kWarpSize;
                        const bool ascending = ((p & size) == 0);

                        const float a_d = dist[t];
                        const int   a_i = idx[t];
                        const float b_d = dist[partner_t];
                        const int   b_i = idx[partner_t];

                        const bool swap = ascending ? (a_d > b_d) : (a_d < b_d);
                        if (swap) {
                            dist[t]         = b_d;
                            idx[t]          = b_i;
                            dist[partner_t] = a_d;
                            idx[partner_t]  = a_i;
                        }
                    }
                }
            } else {
                const bool lower = ((lane & stride) == 0);

                #pragma unroll
                for (int t = 0; t < ITEMS_PER_LANE; ++t) {
                    const int  p         = lane + t * kWarpSize;
                    const bool ascending = ((p & size) == 0);

                    const float other_d = __shfl_xor_sync(kFullMask, dist[t], stride);
                    const int   other_i = __shfl_xor_sync(kFullMask, idx[t],  stride);

                    // In an ascending region the lower logical index keeps the min,
                    // the upper keeps the max.  In a descending region it is reversed.
                    const bool keep_min   = (lower == ascending);
                    const bool take_other = keep_min ? (other_d < dist[t]) : (other_d > dist[t]);

                    if (take_other) {
                        dist[t] = other_d;
                        idx[t]  = other_i;
                    }
                }
            }
        }
    }
}

// Bitonic sort of the shared-memory candidate buffer for one warp/query.
// Distances and indices are stored in separate arrays to avoid avoidable shared-
// memory bank conflicts from repeated 8-byte AoS accesses.
template <int K>
__device__ __forceinline__ void bitonic_sort_shared(float* dist, int* idx) {
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);

    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll
            for (int i = lane; i < K; i += kWarpSize) {
                const int l = i ^ stride;
                if (l > i) {
                    const bool ascending = ((i & size) == 0);

                    const float a_d = dist[i];
                    const int   a_i = idx[i];
                    const float b_d = dist[l];
                    const int   b_i = idx[l];

                    const bool swap = ascending ? (a_d > b_d) : (a_d < b_d);
                    if (swap) {
                        dist[i] = b_d;
                        idx[i]  = b_i;
                        dist[l] = a_d;
                        idx[l]  = a_i;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// Flushes one warp's shared candidate buffer into that warp's private
// intermediate top-k result.
//
// Required merge procedure:
//   0. intermediate result is already sorted ascending
//   1. sort the candidate buffer ascending with bitonic sort
//   2. form the bitonic sequence M[i] = min(buffer[i], result[K - i - 1])
//   3. bitonic-sort M ascending to obtain the updated intermediate result
//
// The candidate count is warp-private (one counter per warp), so only warp-local
// synchronization is necessary here.
template <int K>
__device__ __forceinline__ void flush_candidate_buffer(float* cand_dist,
                                                       int* cand_idx,
                                                       int* count_ptr,
                                                       float (&res_dist)[K / kWarpSize],
                                                       int (&res_idx)[K / kWarpSize],
                                                       float& max_distance) {
    constexpr int ITEMS_PER_LANE = K / kWarpSize;
    const int lane = static_cast<int>(threadIdx.x) & (kWarpSize - 1);
    volatile int* const count_v = reinterpret_cast<volatile int*>(count_ptr);

    int count = 0;
    if (lane == 0) {
        count = *count_v;
    }
    count = __shfl_sync(kFullMask, count, 0);

    if (count == 0) {
        return;
    }

    // Pad the not-yet-used tail with +INF so that a full K-element bitonic sort
    // still works for partially filled buffers.
    #pragma unroll
    for (int i = lane; i < K; i += kWarpSize) {
        if (i >= count) {
            cand_dist[i] = CUDART_INF_F;
            cand_idx[i]  = -1;
        }
    }
    __syncwarp(kFullMask);

    bitonic_sort_shared<K>(cand_dist, cand_idx);

    // Merge with the current result by pairing the ascending buffer with the
    // descending result.  With the cyclic lane/slot layout, logical position
    // K-1-(lane + 32*t) maps to source lane (31-lane), source slot (ITEMS-1-t).
    const int reverse_lane = (kWarpSize - 1) - lane;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int p = lane + t * kWarpSize;

        const float b_d = cand_dist[p];
        const int   b_i = cand_idx[p];

        const int   reverse_t = (ITEMS_PER_LANE - 1) - t;
        const float r_d = __shfl_sync(kFullMask, res_dist[reverse_t], reverse_lane);
        const int   r_i = __shfl_sync(kFullMask, res_idx[reverse_t],  reverse_lane);

        if (b_d < r_d) {
            res_dist[t] = b_d;
            res_idx[t]  = b_i;
        } else {
            res_dist[t] = r_d;
            res_idx[t]  = r_i;
        }
    }

    bitonic_sort_registers<K>(res_dist, res_idx);

    // The logical tail K-1 always lives in lane 31, local slot ITEMS_PER_LANE-1.
    max_distance = __shfl_sync(kFullMask, res_dist[ITEMS_PER_LANE - 1], kWarpSize - 1);

    if (lane == 0) {
        *count_v = 0;
    }
    __syncwarp(kFullMask);
}

template <int K>
__global__ __launch_bounds__(kThreadsPerBlock, 2)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                ResultPair* __restrict__ result,
                int tile_elems) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "K must be a power of two in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");

    constexpr int ITEMS_PER_LANE = K / kWarpSize;

    // Dynamic shared memory layout, all in SoA form:
    //   [tile_x: tile_elems floats]
    //   [tile_y: tile_elems floats]
    //   [candidate_dist: kWarpsPerBlock * K floats]
    //   [candidate_idx : kWarpsPerBlock * K ints]
    //   [candidate_cnt : kWarpsPerBlock ints]
    extern __shared__ unsigned char smem_raw[];
    float* s_tile_x = reinterpret_cast<float*>(smem_raw);
    float* s_tile_y = s_tile_x + tile_elems;
    float* s_cand_dist = s_tile_y + tile_elems;
    int*   s_cand_idx  = reinterpret_cast<int*>(s_cand_dist + kWarpsPerBlock * K);
    int*   s_cand_cnt  = s_cand_idx + kWarpsPerBlock * K;

    const int lane     = static_cast<int>(threadIdx.x) & (kWarpSize - 1);
    const int warp     = static_cast<int>(threadIdx.x) >> 5;
    const int query_id = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp;
    const bool active  = (query_id < query_count);

    float* const warp_cand_dist = s_cand_dist + warp * K;
    int*   const warp_cand_idx  = s_cand_idx  + warp * K;
    int*   const warp_cand_cnt  = s_cand_cnt  + warp;
    volatile int* const warp_cand_cnt_v = reinterpret_cast<volatile int*>(warp_cand_cnt);

    // Each warp owns exactly one candidate counter and one candidate buffer.
    if (lane == 0) {
        *warp_cand_cnt_v = 0;
    }

    // Load the query point once per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active) {
        if (lane == 0) {
            const float2 q = query[query_id];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    // The intermediate top-k result is warp-private and distributed across the
    // 32 lanes.  Each lane owns K/32 pairs in registers.
    float res_dist[ITEMS_PER_LANE];
    int   res_idx[ITEMS_PER_LANE];
    float max_distance = CUDART_INF_F;

    // Initialization: use the first K data points to seed the private result.
    // Those K points are shared across all warps in the block, so we stage them
    // once into shared memory instead of having every warp fetch them separately.
    for (int i = static_cast<int>(threadIdx.x); i < K; i += kThreadsPerBlock) {
        const float2 p = data[i];
        s_tile_x[i] = p.x;
        s_tile_y[i] = p.y;
    }
    __syncthreads();

    if (active) {
        #pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int p = lane + t * kWarpSize;
            res_dist[t] = sq_l2_2d(qx, qy, s_tile_x[p], s_tile_y[p]);
            res_idx[t]  = p;
        }

        bitonic_sort_registers<K>(res_dist, res_idx);
        max_distance = __shfl_sync(kFullMask, res_dist[ITEMS_PER_LANE - 1], kWarpSize - 1);
    }
    __syncthreads();

    // Main batched scan over the remaining data points.
    for (int tile_begin = K; tile_begin < data_count; tile_begin += tile_elems) {
        int tile_count = data_count - tile_begin;
        if (tile_count > tile_elems) {
            tile_count = tile_elems;
        }

        // Whole block cooperatively loads the next tile to shared memory.
        for (int i = static_cast<int>(threadIdx.x); i < tile_count; i += kThreadsPerBlock) {
            const float2 p = data[tile_begin + i];
            s_tile_x[i] = p.x;
            s_tile_y[i] = p.y;
        }
        __syncthreads();

        if (active) {
            // Process the tile in warp-sized micro-batches so that at most 32 new
            // candidates appear at once.  Since K >= 32, a pre-flush on impending
            // overflow guarantees the current micro-batch always fits.
            for (int base = 0; base < tile_count; base += kWarpSize) {
                const int  local_pos = base + lane;
                const bool valid     = (local_pos < tile_count);

                float dist = 0.0f;
                bool candidate = false;

                if (valid) {
                    dist = sq_l2_2d(qx, qy, s_tile_x[local_pos], s_tile_y[local_pos]);
                    candidate = (dist < max_distance);
                }

                const unsigned mask = __ballot_sync(kFullMask, candidate);
                const int num_candidates = __popc(mask);

                if (num_candidates != 0) {
                    // The counter is warp-private, so a volatile read by lane 0 is
                    // sufficient here.  atomicAdd is still used for the actual slot
                    // reservation, as requested.
                    int current_count = 0;
                    if (lane == 0) {
                        current_count = *warp_cand_cnt_v;
                    }
                    current_count = __shfl_sync(kFullMask, current_count, 0);

                    // The candidate buffer is exactly size K, so flush before we
                    // would overflow it.
                    if (current_count + num_candidates > K) {
                        flush_candidate_buffer<K>(warp_cand_dist,
                                                  warp_cand_idx,
                                                  warp_cand_cnt,
                                                  res_dist,
                                                  res_idx,
                                                  max_distance);
                    }

                    // Reserve one contiguous segment for the whole warp's accepted
                    // lanes.  This is much faster than one atomicAdd per candidate
                    // while preserving the required atomic slot assignment semantics.
                    int start = 0;
                    if (lane == 0) {
                        start = atomicAdd(warp_cand_cnt, num_candidates);
                    }
                    start = __shfl_sync(kFullMask, start, 0);

                    if (candidate) {
                        const unsigned lower_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
                        const int rank = __popc(mask & lower_mask);
                        const int write_pos = start + rank;

                        warp_cand_dist[write_pos] = dist;
                        warp_cand_idx[write_pos]  = tile_begin + local_pos;
                    }

                    // Make the just-written candidates visible before a possible
                    // immediate flush when the buffer hits exactly K entries.
                    __syncwarp(kFullMask);

                    if (start + num_candidates == K) {
                        flush_candidate_buffer<K>(warp_cand_dist,
                                                  warp_cand_idx,
                                                  warp_cand_cnt,
                                                  res_dist,
                                                  res_idx,
                                                  max_distance);
                    }
                }
            }
        }

        // All warps must finish reading the current shared tile before the block
        // overwrites it with the next one.
        __syncthreads();
    }

    if (active) {
        // Merge the final partially filled candidate buffer, if any.
        flush_candidate_buffer<K>(warp_cand_dist,
                                  warp_cand_idx,
                                  warp_cand_cnt,
                                  res_dist,
                                  res_idx,
                                  max_distance);

        // Write the final sorted k-NN list back in row-major order:
        // result[query_id * K + j] = {index, squared_distance}
        const std::size_t out_base = static_cast<std::size_t>(query_id) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int logical_pos = lane + t * kWarpSize;
            result[out_base + static_cast<std::size_t>(logical_pos)] =
                ResultPair{res_idx[t], res_dist[t]};
        }
    }
}

template <int K>
inline std::size_t shared_bytes_for_tile(int tile_elems) {
    // 2 * tile_elems floats for x/y plus:
    //   K * kWarpsPerBlock floats for candidate distances,
    //   K * kWarpsPerBlock ints   for candidate indices,
    //   kWarpsPerBlock ints       for candidate counts.
    return static_cast<std::size_t>(2 * tile_elems + 2 * kWarpsPerBlock * K + kWarpsPerBlock) * sizeof(float);
}

template <int K>
inline void launch_knn_specialized(const float2* query,
                                   int query_count,
                                   const float2* data,
                                   int data_count,
                                   std::pair<int, float>* result) {
    int device = 0;
    (void)cudaGetDevice(&device);

    int max_optin_shared = 0;
    (void)cudaDeviceGetAttribute(&max_optin_shared,
                                 cudaDevAttrMaxSharedMemoryPerBlockOptin,
                                 device);

    const std::size_t max_shared = (max_optin_shared > 0)
        ? static_cast<std::size_t>(max_optin_shared)
        : kSharedBudgetBytes;

    const std::size_t fixed_bytes =
        static_cast<std::size_t>(2 * kWarpsPerBlock * K + kWarpsPerBlock) * sizeof(float);

    // Need at least K staged points for the initialization pass because the first
    // K data points are loaded cooperatively into shared memory and sorted into
    // the initial private top-k.
    const std::size_t min_budget = fixed_bytes + static_cast<std::size_t>(2 * K) * sizeof(float);

    std::size_t budget = (kSharedBudgetBytes < max_shared) ? kSharedBudgetBytes : max_shared;
    if (budget < min_budget) {
        budget = min_budget;
    }
    if (budget > max_shared) {
        budget = max_shared;
    }

    int tile_elems = static_cast<int>((budget - fixed_bytes) / (2 * sizeof(float)));
    tile_elems &= ~(kWarpSize - 1);
    if (tile_elems < K) {
        tile_elems = K;
    }

    std::size_t smem_bytes = shared_bytes_for_tile<K>(tile_elems);
    while (smem_bytes > max_shared && tile_elems > K) {
        tile_elems -= kWarpSize;
        smem_bytes = shared_bytes_for_tile<K>(tile_elems);
    }

    // On the target GPUs (A100/H100-class), the required footprint for all
    // supported K values fits.  We intentionally do not add a slow fallback path.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);
    (void)cudaFuncSetCacheConfig(knn_kernel<K>, cudaFuncCachePreferShared);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;

    knn_kernel<K><<<blocks, kThreadsPerBlock, smem_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<ResultPair*>(result),
        tile_elems);
}

} // namespace knn2d_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Compile-time specialization on K is important here:
    // it keeps the per-lane K/32 intermediate result in registers and enables
    // full unrolling of the register-resident bitonic networks.
    switch (k) {
        case 32:   knn2d_detail::launch_knn_specialized<32>(query, query_count, data, data_count, result);   return;
        case 64:   knn2d_detail::launch_knn_specialized<64>(query, query_count, data, data_count, result);   return;
        case 128:  knn2d_detail::launch_knn_specialized<128>(query, query_count, data, data_count, result);  return;
        case 256:  knn2d_detail::launch_knn_specialized<256>(query, query_count, data, data_count, result);  return;
        case 512:  knn2d_detail::launch_knn_specialized<512>(query, query_count, data, data_count, result);  return;
        case 1024: knn2d_detail::launch_knn_specialized<1024>(query, query_count, data, data_count, result); return;
        default:
            // Per problem statement this path is unreachable because k is always a
            // supported power of two in [32, 1024].
            return;
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>

namespace {

// -----------------------------------------------------------------------------
// Kernel configuration tuned for modern datacenter GPUs (A100/H100 class).
//
// Design rationale:
// - One warp computes one query.
// - 256 threads/block = 8 warps/block = 8 queries per block.
//   This is a good balance between:
//     * enough queries per block to reuse the staged data batch,
//     * enough blocks in the grid when query_count is only in the low thousands,
//     * a worst-case shared-memory footprint that still permits 2 resident
//       blocks/SM for K=1024 on A100-class shared-memory limits.
// - 1792 staged points/block is the largest multiple of 256 that keeps the
//   worst-case block footprint below ~80 KiB even when each of the 8 warps owns
//   a 1024-entry candidate buffer. Each thread performs exactly 7 coalesced
//   float2 loads on full batches.
// -----------------------------------------------------------------------------
constexpr int kWarpSize       = 32;
constexpr int kBlockThreads   = 256;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr int kBatchPoints    = 1792;
constexpr int kBatchLoadIters = kBatchPoints / kBlockThreads;
constexpr unsigned kFullMask  = 0xFFFFFFFFu;

using ResultPair = std::pair<int, float>;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a whole number of warps.");
static_assert(kBatchPoints % kBlockThreads == 0, "Batch size chosen so that each thread performs an equal number of loads on full batches.");
static_assert(kBatchPoints % kWarpSize == 0, "Batch size must be a multiple of the warp size.");

// Lexicographic order on (distance, index).
// The problem statement does not constrain tie handling, but using the index as
// a secondary key gives a total order, which makes the bitonic networks
// deterministic and well-defined.
__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool pair_greater(float da, int ia, float db, int ib) {
    return (da > db) || ((da == db) && (ia > ib));
}

__device__ __forceinline__ void swap_pair(float &da, int &ia, float &db, int &ib) {
    const float td = da;
    const int   ti = ia;
    da = db; ia = ib;
    db = td; ib = ti;
}

__device__ __forceinline__ float squared_l2_2d(float qx, float qy, float px, float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    // Squared Euclidean distance in 2D. One FFMA is enough here.
    return fmaf(dx, dx, dy * dy);
}

// Shared-memory bitonic sort of K (distance,index) pairs in ascending order.
// The buffer is warp-private in shared memory. Each lane owns a contiguous chunk
// of K/32 elements:
//   logical positions handled by lane L are [L*CHUNK, L*CHUNK + CHUNK-1].
// Only the lower-index endpoint of each compare/swap pair performs the swap, so
// there are no write races. __syncwarp() after every substage provides the
// required shared-memory visibility.
template <int K>
__device__ __forceinline__ void shared_bitonic_sort_pairs(int *cand_idx, float *cand_dist) {
    constexpr int CHUNK = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int base = lane * CHUNK;

    #pragma unroll
    for (int stage = 2; stage <= K; stage <<= 1) {
        #pragma unroll
        for (int j = stage >> 1; j > 0; j >>= 1) {
            #pragma unroll
            for (int s = 0; s < CHUNK; ++s) {
                const int i = base + s;
                const int partner = i ^ j;

                if (partner > i) {
                    float di = cand_dist[i];
                    int   ii = cand_idx[i];
                    float dp = cand_dist[partner];
                    int   ip = cand_idx[partner];

                    const bool up = ((i & stage) == 0);
                    if (up ? pair_greater(di, ii, dp, ip)
                           : pair_less(di, ii, dp, ip)) {
                        cand_dist[i]       = dp;
                        cand_idx[i]        = ip;
                        cand_dist[partner] = di;
                        cand_idx[partner]  = ii;
                    }
                }
            }
            __syncwarp(kFullMask);
        }
    }
}

// The sequence produced by step 2 of the requested algorithm is already
// bitonic. Therefore step 3 needs only the final "bitonic merge" half of the
// Bitonic Sort network, not the full construction of bitonic runs again.
// This is still exactly the relevant sorting phase of Bitonic Sort.
template <int K>
__device__ __forceinline__ void shared_bitonic_merge_up_pairs(int *cand_idx, float *cand_dist) {
    constexpr int CHUNK = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int base = lane * CHUNK;

    #pragma unroll
    for (int j = K >> 1; j > 0; j >>= 1) {
        #pragma unroll
        for (int s = 0; s < CHUNK; ++s) {
            const int i = base + s;
            const int partner = i ^ j;

            if (partner > i) {
                float di = cand_dist[i];
                int   ii = cand_idx[i];
                float dp = cand_dist[partner];
                int   ip = cand_idx[partner];

                if (pair_greater(di, ii, dp, ip)) {
                    cand_dist[i]       = dp;
                    cand_idx[i]        = ip;
                    cand_dist[partner] = di;
                    cand_idx[partner]  = ii;
                }
            }
        }
        __syncwarp(kFullMask);
    }
}

// Flush the warp-private candidate buffer into the warp-private intermediate
// result. This implements the requested merge procedure:
//
// 1. Pad unused candidate slots with (+inf, INT_MAX).
// 2. Sort the candidate buffer in ascending order using Bitonic Sort.
// 3. Build the bitonic merged sequence in-place:
//      merged[i] = min(buffer[i], result[K-1-i]).
// 4. Sort that bitonic sequence ascending using the bitonic-merge phase.
// 5. Copy the updated top-K back into the warp-private intermediate result and
//    refresh max_distance = distance of the K-th nearest neighbor.
template <int K>
__device__ __forceinline__
void flush_candidate_buffer(float (&result_dist)[K / kWarpSize],
                            int   (&result_idx )[K / kWarpSize],
                            float &max_distance,
                            int   *count_ptr,
                            int   *cand_idx,
                            float *cand_dist) {
    constexpr int CHUNK = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int base = lane * CHUNK;

    __syncwarp(kFullMask);

    const int count = *count_ptr;
    if (count == 0) {
        return;
    }

    // Pad the inactive tail of the buffer with sentinels so that the network
    // can always sort exactly K elements.
    #pragma unroll
    for (int s = 0; s < CHUNK; ++s) {
        const int pos = base + s;
        if (pos >= count) {
            cand_idx[pos]  = INT_MAX;
            cand_dist[pos] = CUDART_INF_F;
        }
    }
    __syncwarp(kFullMask);

    // Step 1: full sort of the candidate buffer.
    shared_bitonic_sort_pairs<K>(cand_idx, cand_dist);

    // Step 2: form the first K elements of the union as a bitonic sequence.
    // Result is already sorted ascending in registers. Its reverse element for
    // logical position i is at position K-1-i, which maps to lane (31-lane)
    // and slot (CHUNK-1-s) under the contiguous-chunk distribution.
    #pragma unroll
    for (int s = 0; s < CHUNK; ++s) {
        const int pos = base + s;

        const float rev_dist =
            __shfl_sync(kFullMask, result_dist[CHUNK - 1 - s], 31 - lane);
        const int rev_idx =
            __shfl_sync(kFullMask, result_idx[CHUNK - 1 - s], 31 - lane);

        const float buf_dist = cand_dist[pos];
        const int   buf_idx  = cand_idx[pos];

        if (pair_less(rev_dist, rev_idx, buf_dist, buf_idx)) {
            cand_dist[pos] = rev_dist;
            cand_idx[pos]  = rev_idx;
        }
    }
    __syncwarp(kFullMask);

    // Step 3: the sequence is already bitonic, so only the merge phase is
    // needed to sort it ascending.
    shared_bitonic_merge_up_pairs<K>(cand_idx, cand_dist);

    // Update the private intermediate result.
    #pragma unroll
    for (int s = 0; s < CHUNK; ++s) {
        const int pos = base + s;
        result_dist[s] = cand_dist[pos];
        result_idx[s]  = cand_idx[pos];
    }

    // The global K-th element lives in lane 31, local slot CHUNK-1.
    max_distance = __shfl_sync(kFullMask, result_dist[CHUNK - 1], 31);

    if (lane == 0) {
        *count_ptr = 0;
    }
    __syncwarp(kFullMask);
}

template <int K>
__global__ __launch_bounds__(kBlockThreads, 2)
void knn_kernel(const float2    *__restrict__ query,
                int query_count,
                const float2    *__restrict__ data,
                int data_count,
                ResultPair      *__restrict__ result) {
    static_assert(K >= 32 && K <= 1024, "K must be between 32 and 1024.");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of the warp size.");

    constexpr int CHUNK = K / kWarpSize;

    // Dynamic shared-memory layout:
    //   [ staged data batch | per-warp counts | per-warp candidate indices | per-warp candidate distances ]
    extern __shared__ __align__(16) unsigned char smem[];
    float2 *const sh_data      = reinterpret_cast<float2*>(smem);
    int    *const sh_counts    = reinterpret_cast<int*>(sh_data + kBatchPoints);
    int    *const sh_cand_idx  = sh_counts + kWarpsPerBlock;
    float  *const sh_cand_dist = reinterpret_cast<float*>(sh_cand_idx + kWarpsPerBlock * K);

    const int tid     = threadIdx.x;
    const int warp_id = tid >> 5;
    const int lane    = tid & (kWarpSize - 1);

    const int query_idx   = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool query_live = (query_idx < query_count);

    // Warp-private intermediate top-K result. It is distributed across the
    // 32 lanes as CHUNK contiguous elements per lane.
    float result_dist[CHUNK];
    int   result_idx [CHUNK];

    #pragma unroll
    for (int s = 0; s < CHUNK; ++s) {
        result_dist[s] = CUDART_INF_F;
        result_idx [s] = INT_MAX;
    }

    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && query_live) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Per-warp candidate buffer in shared memory.
    int   *const count_ptr = sh_counts + warp_id;
    int   *const cand_idx  = sh_cand_idx  + warp_id * K;
    float *const cand_dist = sh_cand_dist + warp_id * K;

    if (lane == 0) {
        *count_ptr = 0;
    }
    __syncwarp(kFullMask);

    // max_distance = current K-th smallest distance.
    // It stays +inf until the intermediate result becomes fully populated.
    float max_distance = CUDART_INF_F;

    // Iterate over the database in staged batches.
    for (int batch_start = 0; batch_start < data_count; batch_start += kBatchPoints) {
        int batch_count = data_count - batch_start;
        if (batch_count > kBatchPoints) {
            batch_count = kBatchPoints;
        }

        // Cooperative block load into shared memory.
        #pragma unroll
        for (int it = 0; it < kBatchLoadIters; ++it) {
            const int local = tid + it * kBlockThreads;
            if (local < batch_count) {
                sh_data[local] = data[batch_start + local];
            }
        }
        __syncthreads();

        // Each live warp scans the staged batch 32 points at a time so that:
        // - every lane processes at most one candidate per iteration,
        // - the warp can ballot/filter those 32 distances,
        // - one warp-aggregated atomicAdd reserves output slots in the shared
        //   candidate buffer for all accepted lanes at once.
        if (query_live) {
            for (int local_base = 0; local_base < batch_count; local_base += kWarpSize) {
                const int local = local_base + lane;
                const bool valid = (local < batch_count);

                float dist = 0.0f;
                const int data_idx = batch_start + local;

                if (valid) {
                    const float2 p = sh_data[local];
                    dist = squared_l2_2d(qx, qy, p.x, p.y);
                }

                // The problem statement requests filtering only by distance.
                bool hit = valid && (dist < max_distance);
                unsigned hit_mask = __ballot_sync(kFullMask, hit);
                int hit_count = __popc(hit_mask);

                if (hit_count != 0) {
                    // Once max_distance is finite, proactively flushing the
                    // existing buffer when the current 32-point group would make
                    // it full is safe and profitable: after the flush, the
                    // threshold can only tighten, so the current group is
                    // immediately re-filtered against the new max_distance.
                    if (max_distance < CUDART_INF_F) {
                        int count = 0;
                        if (lane == 0) {
                            count = *count_ptr;
                        }
                        count = __shfl_sync(kFullMask, count, 0);

                        if (count > 0 && count + hit_count >= K) {
                            flush_candidate_buffer<K>(
                                result_dist, result_idx, max_distance,
                                count_ptr, cand_idx, cand_dist);

                            // Re-filter this same 32-point group against the
                            // updated threshold.
                            hit = valid && (dist < max_distance);
                            hit_mask = __ballot_sync(kFullMask, hit);
                            hit_count = __popc(hit_mask);
                        }
                    }

                    if (hit_count != 0) {
                        int base = 0;

                        // Warp-aggregated form of the required atomicAdd:
                        // one atomicAdd reserves hit_count contiguous slots,
                        // and the accepted lanes use their prefix rank in the
                        // hit mask to map into that reserved segment.
                        if (lane == 0) {
                            base = atomicAdd(count_ptr, hit_count);
                        }
                        base = __shfl_sync(kFullMask, base, 0);

                        if (hit) {
                            const unsigned lower_mask = (1u << lane) - 1u;
                            const int rank = __popc(hit_mask & lower_mask);
                            const int pos = base + rank;
                            cand_idx[pos]  = data_idx;
                            cand_dist[pos] = dist;
                        }
                        __syncwarp(kFullMask);

                        // If the buffer has just reached capacity, flush it.
                        // In practice this is mainly the initialization path
                        // before max_distance becomes finite, and the K=32 path.
                        if (base + hit_count == K) {
                            flush_candidate_buffer<K>(
                                result_dist, result_idx, max_distance,
                                count_ptr, cand_idx, cand_dist);
                        }
                    }
                }
            }
        }

        // All warps must finish using the staged batch before it is overwritten.
        __syncthreads();
    }

    // Flush the last partial candidate buffer, if any.
    if (query_live) {
        if (*count_ptr != 0) {
            flush_candidate_buffer<K>(
                result_dist, result_idx, max_distance,
                count_ptr, cand_idx, cand_dist);
        }

        // Store the final sorted top-K neighbors.
        const int out_base = query_idx * K;
        const int lane_base = lane * CHUNK;

        #pragma unroll
        for (int s = 0; s < CHUNK; ++s) {
            ResultPair &dst = result[out_base + lane_base + s];
            dst.first  = result_idx[s];
            dst.second = result_dist[s];
        }
    }
}

template <int K>
constexpr int shared_bytes() {
    return static_cast<int>(
        kBatchPoints * sizeof(float2) +
        kWarpsPerBlock * sizeof(int) +
        kWarpsPerBlock * K * sizeof(int) +
        kWarpsPerBlock * K * sizeof(float));
}

template <int K>
inline void launch_knn(const float2 *query,
                       int query_count,
                       const float2 *data,
                       int data_count,
                       ResultPair *result) {
    const int grid = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;
    const int smem = shared_bytes<K>();

    // The kernel is intentionally shared-memory heavy; request the larger
    // per-block dynamic shared-memory limit and prefer shared-memory carveout.
    cudaFuncSetAttribute(knn_kernel<K>,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         smem);
    cudaFuncSetAttribute(knn_kernel<K>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    knn_kernel<K><<<grid, kBlockThreads, smem>>>(
        query, query_count, data, data_count, result);
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    // Keep the API asynchronous like a normal CUDA kernel launch.
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn<32>  (query, query_count, data, data_count, result); break;
        case 64:   launch_knn<64>  (query, query_count, data, data_count, result); break;
        case 128:  launch_knn<128> (query, query_count, data, data_count, result); break;
        case 256:  launch_knn<256> (query, query_count, data, data_count, result); break;
        case 512:  launch_knn<512> (query, query_count, data, data_count, result); break;
        case 1024: launch_knn<1024>(query, query_count, data, data_count, result); break;
        default:
            // Per the problem statement, k is always valid.
            break;
    }
}

#include <cuda_runtime.h>
#include <algorithm>
#include <utility>

// Warp-centric exact k-NN for 2D points in squared Euclidean distance.
// - One warp handles one query.
// - The whole block stages the current data batch in shared memory.
// - Each warp owns two private shared-memory slices:
//     1) a sorted intermediate top-K result,
//     2) a candidate buffer with a shared count.
// - Candidate insertions use warp-aggregated atomicAdd on the per-warp shared counter.
// - Buffer flush / merge follows the requested procedure exactly:
//     sort buffer, half-cleaner against the reversed intermediate result, sort again.
// - No extra device memory is allocated.
//
// The tile size below is chosen for modern data-center GPUs (A100/H100 class).
// 2016 = 63 * 32 is the largest warp-aligned tile that still preserves favorable
// shared-memory fit on A100 for the hard cases K=512 and K=1024.
namespace {

constexpr int kWarpSize            = 32;
constexpr int kMaxWarpsPerBlock    = 32;
constexpr int kTilePoints          = 2016;
constexpr size_t kTileBytes        = static_cast<size_t>(kTilePoints) * sizeof(float2);
using Entry = unsigned long long;

static_assert(kTilePoints % kWarpSize == 0, "Tile size must be warp-aligned.");
static_assert(kTilePoints >= 1024, "The first tile must be large enough to bootstrap K=1024.");
static_assert(sizeof(std::pair<int, float>) == 8, "Unexpected std::pair<int,float> layout.");

// Distances are non-negative, so IEEE-754 bit patterns are monotonically ordered when
// reinterpreted as unsigned integers. Packing {distance_bits, index_bits} into one 64-bit
// word lets the compare/swap network move one payload instead of separate index+distance arrays.
__device__ __forceinline__ Entry pack_entry(const int index, const float distance) {
    return (static_cast<Entry>(__float_as_uint(distance)) << 32) |
           static_cast<unsigned int>(index);
}

__device__ __forceinline__ int unpack_index(const Entry e) {
    return static_cast<int>(static_cast<unsigned int>(e));
}

__device__ __forceinline__ float unpack_distance(const Entry e) {
    return __uint_as_float(static_cast<unsigned int>(e >> 32));
}

__device__ __forceinline__ Entry sentinel_entry() {
    return pack_entry(-1, CUDART_INF_F);
}

__device__ __forceinline__ float squared_l2(const float qx, const float qy, const float2& p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

template <int K>
__device__ __forceinline__ void bitonic_sort_shared(Entry* values) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32,1024].");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");

    constexpr int kItemsPerLane = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int size = 2; size <= K; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int t = 0; t < kItemsPerLane; ++t) {
                const int i = (t << 5) + lane;
                const int l = i ^ stride;
                if (l > i) {
                    const bool up = ((i & size) == 0);
                    const Entry a = values[i];
                    const Entry b = values[l];
                    const bool swap = up ? (a > b) : (a < b);
                    if (swap) {
                        values[i] = b;
                        values[l] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Flush the candidate buffer into the sorted intermediate top-K.
// If current_count < K, the remainder is padded with +inf sentinels so the same full-K merge path
// can be used for both regular flushes and the final partial flush.
template <int K>
__device__ __forceinline__ float merge_candidate_buffer_into_topk(
    Entry* topk_entries,
    Entry* candidate_entries,
    int* candidate_count,
    const int current_count)
{
    constexpr int kItemsPerLane = K / kWarpSize;
    const int lane = threadIdx.x & (kWarpSize - 1);

    if (current_count < K) {
        const Entry inf = sentinel_entry();
        for (int i = current_count + lane; i < K; i += kWarpSize) {
            candidate_entries[i] = inf;
        }
    }

    if (lane == 0) {
        *candidate_count = 0;
    }
    __syncwarp();

    // Step 1: sort the buffer ascending.
    bitonic_sort_shared<K>(candidate_entries);

    // Step 2: half-cleaner against the reversed sorted intermediate result.
    // The minima form a bitonic sequence that contains the true top-K of the union.
#pragma unroll
    for (int t = 0; t < kItemsPerLane; ++t) {
        const int i = (t << 5) + lane;
        const Entry a = candidate_entries[i];
        const Entry b = topk_entries[K - 1 - i];
        candidate_entries[i] = (a < b) ? a : b;
    }
    __syncwarp();

    // Step 3: sort the bitonic sequence ascending to restore the invariant.
    bitonic_sort_shared<K>(candidate_entries);

#pragma unroll
    for (int t = 0; t < kItemsPerLane; ++t) {
        const int i = (t << 5) + lane;
        topk_entries[i] = candidate_entries[i];
    }
    __syncwarp();

    return unpack_distance(topk_entries[K - 1]);
}

// Process one shared-memory tile of data points.
// The warp examines one 32-point packet at a time so it can:
// - ballot the points that beat max_distance,
// - reserve a contiguous segment in the candidate buffer with one atomicAdd,
// - keep the candidate buffer exact without ever dropping a valid point.
//
// If a packet would overflow the fixed-size candidate buffer, the current partial buffer is flushed
// first, max_distance is tightened, and the same packet is re-tested against the new threshold.
template <int K>
__device__ __forceinline__ void process_tile_packets(
    const float qx,
    const float qy,
    const float2* tile_points,
    const int start,
    const int tile_count,
    const int tile_base,
    Entry* topk_entries,
    Entry* candidate_entries,
    int* candidate_count,
    float& max_distance,
    int& buffer_count)
{
    constexpr unsigned kFullMask = 0xFFFFFFFFu;
    const int lane = threadIdx.x & (kWarpSize - 1);

    for (int packet_base = start; packet_base < tile_count; packet_base += kWarpSize) {
        const int local_idx = packet_base + lane;
        const bool valid = (local_idx < tile_count);

        float distance = 0.0f;
        Entry candidate = 0ull;

        if (valid) {
            const float2 p = tile_points[local_idx];
            distance = squared_l2(qx, qy, p);
            candidate = pack_entry(tile_base + local_idx, distance);
        }

        bool keep = valid && (distance < max_distance);
        unsigned keep_mask = __ballot_sync(kFullMask, keep);
        int keep_count = __popc(keep_mask);

        if (keep_count == 0) {
            continue;
        }

        // Flush early if this warp packet would overflow the fixed-size buffer.
        if (buffer_count + keep_count > K) {
            max_distance = merge_candidate_buffer_into_topk<K>(
                topk_entries, candidate_entries, candidate_count, buffer_count);
            buffer_count = 0;

            keep = valid && (distance < max_distance);
            keep_mask = __ballot_sync(kFullMask, keep);
            keep_count = __popc(keep_mask);

            if (keep_count == 0) {
                continue;
            }
        }

        const unsigned lower_lanes = (lane == 0) ? 0u : ((1u << lane) - 1u);
        const int prefix = __popc(keep_mask & lower_lanes);

        int base_pos = 0;
        if (lane == 0) {
            base_pos = atomicAdd(candidate_count, keep_count);
        }
        base_pos = __shfl_sync(kFullMask, base_pos, 0);

        if (keep) {
            candidate_entries[base_pos + prefix] = candidate;
        }
        __syncwarp();

        buffer_count = base_pos + keep_count;

        // The prompt asks for an immediate merge whenever the buffer becomes full.
        if (buffer_count == K) {
            max_distance = merge_candidate_buffer_into_topk<K>(
                topk_entries, candidate_entries, candidate_count, K);
            buffer_count = 0;
        }
    }
}

template <int K>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    const int query_count,
    const float2* __restrict__ data,
    const int data_count,
    std::pair<int, float>* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32,1024].");

    extern __shared__ __align__(16) unsigned char smem[];

    const int warps_per_block = blockDim.x >> 5;
    const int warp_id = threadIdx.x >> 5;
    const int lane = threadIdx.x & (kWarpSize - 1);
    const int query_id = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
    const bool active_query = (query_id < query_count);

    float2* const tile_points = reinterpret_cast<float2*>(smem);
    Entry* const topk_storage = reinterpret_cast<Entry*>(tile_points + kTilePoints);
    Entry* const candidate_storage = topk_storage + static_cast<size_t>(warps_per_block) * K;
    int* const candidate_counts = reinterpret_cast<int*>(candidate_storage + static_cast<size_t>(warps_per_block) * K);

    Entry* const topk_entries = topk_storage + static_cast<size_t>(warp_id) * K;
    Entry* const candidate_entries = candidate_storage + static_cast<size_t>(warp_id) * K;
    int* const candidate_count = candidate_counts + warp_id;

    // Load the query point once per warp, then broadcast it.
    float2 q = make_float2(0.0f, 0.0f);
    if (lane == 0 && active_query) {
        q = query[query_id];
    }
    const float qx = __shfl_sync(0xFFFFFFFFu, q.x, 0);
    const float qy = __shfl_sync(0xFFFFFFFFu, q.y, 0);

    float max_distance = CUDART_INF_F;
    int buffer_count = 0;

    // Iterate over the data set in shared-memory tiles.
    for (int tile_base = 0; tile_base < data_count; tile_base += kTilePoints) {
        int tile_count = data_count - tile_base;
        if (tile_count > kTilePoints) {
            tile_count = kTilePoints;
        }

        // Cooperative tile load.
        for (int i = threadIdx.x; i < tile_count; i += blockDim.x) {
            tile_points[i] = data[tile_base + i];
        }
        __syncthreads();

        if (active_query) {
            if (tile_base == 0) {
                // Bootstrap the sorted intermediate top-K from the first K data points of the first tile.
                // This avoids starting with max_distance = +inf for the whole data set.
                constexpr int kItemsPerLane = K / kWarpSize;
#pragma unroll
                for (int t = 0; t < kItemsPerLane; ++t) {
                    const int i = (t << 5) + lane;
                    const float2 p = tile_points[i];
                    topk_entries[i] = pack_entry(i, squared_l2(qx, qy, p));
                }

                if (lane == 0) {
                    *candidate_count = 0;
                }
                __syncwarp();

                bitonic_sort_shared<K>(topk_entries);
                max_distance = unpack_distance(topk_entries[K - 1]);
                buffer_count = 0;

                // The remainder of the first tile is handled through the candidate buffer path.
                process_tile_packets<K>(
                    qx, qy, tile_points, K, tile_count, tile_base,
                    topk_entries, candidate_entries, candidate_count,
                    max_distance, buffer_count);
            } else {
                process_tile_packets<K>(
                    qx, qy, tile_points, 0, tile_count, tile_base,
                    topk_entries, candidate_entries, candidate_count,
                    max_distance, buffer_count);
            }
        }

        __syncthreads();
    }

    if (active_query) {
        // Final partial flush, if any candidates remain buffered.
        if (buffer_count > 0) {
            (void)merge_candidate_buffer_into_topk<K>(
                topk_entries, candidate_entries, candidate_count, buffer_count);
        }

        const size_t out_base = static_cast<size_t>(query_id) * K;
        constexpr int kItemsPerLane = K / kWarpSize;
#pragma unroll
        for (int t = 0; t < kItemsPerLane; ++t) {
            const int i = (t << 5) + lane;
            const Entry e = topk_entries[i];
            result[out_base + i].first = unpack_index(e);
            result[out_base + i].second = unpack_distance(e);
        }
    }
}

template <int K>
__host__ __forceinline__ size_t shared_bytes_for_launch(const int warps_per_block) {
    return kTileBytes +
           static_cast<size_t>(warps_per_block) *
               (static_cast<size_t>(2) * K * sizeof(Entry) + sizeof(int));
}

template <int K>
void launch_knn_specialized(
    const float2* query,
    const int query_count,
    const float2* data,
    const int data_count,
    std::pair<int, float>* result)
{
    int device = 0;
    (void)cudaGetDevice(&device);

    int sm_count = 1;
    int max_dynamic_smem = 0;
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaDeviceGetAttribute(&max_dynamic_smem, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    if (max_dynamic_smem <= 0) {
        (void)cudaDeviceGetAttribute(&max_dynamic_smem, cudaDevAttrMaxSharedMemoryPerBlock, device);
    }

    const long long per_warp_bytes =
        static_cast<long long>(2LL * K * static_cast<long long>(sizeof(Entry)) + sizeof(int));
    const long long available_shared =
        static_cast<long long>(max_dynamic_smem) - static_cast<long long>(kTileBytes);

    int max_warps_shared = static_cast<int>(available_shared / per_warp_bytes);
    max_warps_shared = std::max(1, std::min(kMaxWarpsPerBlock, max_warps_shared));

    // Heuristic: choose the largest warp count that still leaves roughly one query-group block per SM.
    // This balances:
    //   - better shared-tile reuse with more warps/block,
    //   - enough blocks to keep the whole GPU busy when query_count is only a few thousand.
    const int warps_for_parallelism =
        std::max(1, (query_count + sm_count / 2) / sm_count);

    int warps_per_block = std::min(max_warps_shared, warps_for_parallelism);
    warps_per_block = std::min(warps_per_block, query_count);
    warps_per_block = std::max(1, warps_per_block);

    const int threads_per_block = warps_per_block * kWarpSize;
    const size_t smem_bytes = shared_bytes_for_launch<K>(warps_per_block);
    const int blocks = (query_count + warps_per_block - 1) / warps_per_block;

    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    knn_kernel<K><<<blocks, threads_per_block, smem_bytes>>>(
        query, query_count, data, data_count, result);
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_specialized<32>(query, query_count, data, data_count, result); break;
        case 64:   launch_knn_specialized<64>(query, query_count, data, data_count, result); break;
        case 128:  launch_knn_specialized<128>(query, query_count, data, data_count, result); break;
        case 256:  launch_knn_specialized<256>(query, query_count, data, data_count, result); break;
        case 512:  launch_knn_specialized<512>(query, query_count, data, data_count, result); break;
        case 1024: launch_knn_specialized<1024>(query, query_count, data, data_count, result); break;
        default:   break; // The problem statement guarantees valid K.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>
#include <climits>

namespace knn_detail {

/*
  Warp-per-query 2D k-NN for power-of-two K in [32, 1024].

  Key design choices for modern data-center GPUs:
  - One warp computes one query.
  - One 256-thread block = 8 query warps. This gives good reuse of each staged data batch while
    keeping the worst-case shared-memory footprint comfortably below 96 KiB per block.
  - Each block stages 1024 data points (8 KiB) in shared memory. That batch size keeps the K=1024
    case at ~72 KiB/block total dynamic shared memory, so A100/H100 can still run multiple blocks/SM.
  - The intermediate top-K result is private to the warp and stored in an interleaved layout:
      lane L owns positions L, L+32, L+64, ...
    This is important because the merge step needs result[K-1-i]; with this layout the reversed
    position always lives in the opposite lane (31-L), so one warp shuffle per element is enough.
  - The candidate buffer lives in shared memory exactly as requested. Insertions use atomicAdd,
    but in a warp-aggregated form: one shared atomic reserves space for all qualifying lanes of the
    current 32-point step, then each qualifying lane computes its own offset.
*/

constexpr int KNN_BLOCK_THREADS    = 256;
constexpr int KNN_WARPS_PER_BLOCK  = KNN_BLOCK_THREADS / 32;
constexpr int KNN_BATCH_POINTS     = 1024;
constexpr unsigned FULL_MASK       = 0xffffffffu;

static_assert(KNN_BLOCK_THREADS % 32 == 0, "Block size must be a multiple of warp size.");
static_assert(KNN_BATCH_POINTS % 32 == 0, "Batch size must be a multiple of warp size.");

template <int K>
constexpr std::size_t knn_shared_bytes() {
    return static_cast<std::size_t>(KNN_BATCH_POINTS) * sizeof(float2) +
           static_cast<std::size_t>(KNN_WARPS_PER_BLOCK) * sizeof(int) +
           static_cast<std::size_t>(KNN_WARPS_PER_BLOCK) * static_cast<std::size_t>(K) * (sizeof(int) + sizeof(float));
}

static_assert(knn_shared_bytes<1024>() <= 96u * 1024u,
              "Worst-case shared-memory footprint should stay below 96 KiB/block.");

__device__ __forceinline__ float distance_sq_2d(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

__device__ __forceinline__ bool pair_less(const float da, const int ia,
                                          const float db, const int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

/*
  Cooperative bitonic sort of K pairs (distance, index) stored in a warp-private slice of shared memory.
  Only one warp touches that slice, so __syncwarp() is sufficient between compare-exchange rounds.
*/
template <int K>
__device__ __forceinline__ void warp_bitonic_sort_shared(int* const buf_idx,
                                                         float* const buf_dist) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    constexpr int ITEMS_PER_LANE = K / 32;
    const int lane = threadIdx.x & 31;

    for (int stage = 2; stage <= K; stage <<= 1) {
        for (int stride = stage >> 1; stride > 0; stride >>= 1) {
            for (int t = 0; t < ITEMS_PER_LANE; ++t) {
                const int i = lane + (t << 5);
                const int l = i ^ stride;

                if (l > i) {
                    const float di = buf_dist[i];
                    const float dl = buf_dist[l];
                    const int   ii = buf_idx[i];
                    const int   il = buf_idx[l];

                    const bool ascending = ((i & stage) == 0);
                    const bool do_swap = ascending ? pair_less(dl, il, di, ii)
                                                   : pair_less(di, ii, dl, il);

                    if (do_swap) {
                        buf_dist[i] = dl;
                        buf_dist[l] = di;
                        buf_idx[i]  = il;
                        buf_idx[l]  = ii;
                    }
                }
            }
            __syncwarp();
        }
    }
}

/*
  Copy a sorted shared-memory buffer back into the warp-private interleaved top-K storage.
  The returned value is the current K-th neighbor distance, broadcast from lane 31.
*/
template <int K>
__device__ __forceinline__ float load_sorted_buffer_to_private(const int* const buf_idx,
                                                               const float* const buf_dist,
                                                               int (&best_idx)[K / 32],
                                                               float (&best_dist)[K / 32]) {
    constexpr int ITEMS_PER_LANE = K / 32;
    const int lane = threadIdx.x & 31;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int pos = lane + (t << 5);
        best_idx[t]   = buf_idx[pos];
        best_dist[t]  = buf_dist[pos];
    }

    const float lane_local_last = best_dist[ITEMS_PER_LANE - 1];
    return __shfl_sync(FULL_MASK, lane_local_last, 31);
}

/*
  Seed the intermediate result with the first K data points. This is a one-time cost per query;
  the main sweep over the very large dataset uses block-staged shared-memory batches.
*/
template <int K>
__device__ __forceinline__ float initialize_best_from_prefix(const float2* __restrict__ data,
                                                             const float qx,
                                                             const float qy,
                                                             int* const buf_idx,
                                                             float* const buf_dist,
                                                             int (&best_idx)[K / 32],
                                                             float (&best_dist)[K / 32]) {
    constexpr int ITEMS_PER_LANE = K / 32;
    const int lane = threadIdx.x & 31;

    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int pos = lane + (t << 5);
        const float2 p = data[pos];
        buf_idx[pos]  = pos;
        buf_dist[pos] = distance_sq_2d(qx, qy, p);
    }

    __syncwarp();
    warp_bitonic_sort_shared<K>(buf_idx, buf_dist);
    return load_sorted_buffer_to_private<K>(buf_idx, buf_dist, best_idx, best_dist);
}

/*
  Merge the shared-memory candidate buffer into the warp-private sorted intermediate result.

  Required procedure:
    1) Sort the buffer ascending with Bitonic Sort.
    2) Form the bitonic "small half" by taking min(buffer[i], result[K-1-i]).
    3) Sort that bitonic sequence ascending with Bitonic Sort.

  The merged result is written back to the private best_* arrays.
*/
template <int K>
__device__ __forceinline__ float flush_candidate_buffer(int* const buf_idx,
                                                        float* const buf_dist,
                                                        int* const buf_count,
                                                        const int candidate_count,
                                                        int (&best_idx)[K / 32],
                                                        float (&best_dist)[K / 32]) {
    constexpr int ITEMS_PER_LANE = K / 32;
    const int lane = threadIdx.x & 31;

    // Fill the unused tail with sentinels so the full-K sort/merge is always valid.
    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int pos = lane + (t << 5);
        if (pos >= candidate_count) {
            buf_idx[pos]  = INT_MAX;
            buf_dist[pos] = CUDART_INF_F;
        }
    }

    __syncwarp();
    warp_bitonic_sort_shared<K>(buf_idx, buf_dist);

    // Build the bitonic sequence of the smallest K elements directly back into the buffer.
    // With the interleaved private layout, result[K-1-(lane+32*t)] lives in lane (31-lane),
    // slot (ITEMS_PER_LANE-1-t).
    #pragma unroll
    for (int t = 0; t < ITEMS_PER_LANE; ++t) {
        const int pos = lane + (t << 5);

        float bd = buf_dist[pos];
        int   bi = buf_idx[pos];

        const float rd = __shfl_sync(FULL_MASK, best_dist[ITEMS_PER_LANE - 1 - t], 31 - lane);
        const int   ri = __shfl_sync(FULL_MASK, best_idx [ITEMS_PER_LANE - 1 - t], 31 - lane);

        if (pair_less(rd, ri, bd, bi)) {
            bd = rd;
            bi = ri;
        }

        buf_dist[pos] = bd;
        buf_idx[pos]  = bi;
    }

    __syncwarp();
    warp_bitonic_sort_shared<K>(buf_idx, buf_dist);

    const float max_distance = load_sorted_buffer_to_private<K>(buf_idx, buf_dist, best_idx, best_dist);

    if (lane == 0) {
        *buf_count = 0;
    }
    __syncwarp();

    return max_distance;
}

template <int K>
__global__ void knn_kernel(const float2* __restrict__ query,
                           const int query_count,
                           const float2* __restrict__ data,
                           const int data_count,
                           std::pair<int, float>* __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024].");
    constexpr int ITEMS_PER_LANE = K / 32;

    const int lane          = threadIdx.x & 31;
    const int warp_in_block = threadIdx.x >> 5;
    const int query_idx     = static_cast<int>(blockIdx.x) * KNN_WARPS_PER_BLOCK + warp_in_block;
    const bool active       = (query_idx < query_count);

    // Dynamic shared-memory layout:
    //   [ staged data batch | per-warp counts | per-warp candidate indices | per-warp candidate distances ]
    extern __shared__ __align__(16) unsigned char shared_raw[];
    float2* const sh_data     = reinterpret_cast<float2*>(shared_raw);
    int*    const sh_counts   = reinterpret_cast<int*>(sh_data + KNN_BATCH_POINTS);
    int*    const sh_buf_idx  = sh_counts + KNN_WARPS_PER_BLOCK;
    float*  const sh_buf_dist = reinterpret_cast<float*>(sh_buf_idx + KNN_WARPS_PER_BLOCK * K);

    int*   const buf_idx   = sh_buf_idx  + warp_in_block * K;
    float* const buf_dist  = sh_buf_dist + warp_in_block * K;
    int*   const buf_count = sh_counts   + warp_in_block;

    if (lane == 0) {
        *buf_count = 0;
    }
    __syncwarp();

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Private, warp-distributed intermediate result.
    int   best_idx[ITEMS_PER_LANE];
    float best_dist[ITEMS_PER_LANE];

    float max_distance = CUDART_INF_F;

    // Local shadow of the shared count. Only this warp updates its own counter, so the shadow stays
    // exact and avoids a shared-memory read before every 32-point step. atomicAdd is still used for
    // the actual reservation in the shared candidate buffer, as required.
    int candidate_count = 0;

    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    if (active) {
        max_distance = initialize_best_from_prefix<K>(data, qx, qy, buf_idx, buf_dist, best_idx, best_dist);
        if (lane == 0) {
            *buf_count = 0;
        }
        __syncwarp();
    }

    // Main sweep over the remaining points. The first K points already seeded the intermediate result.
    for (int batch_start = K; batch_start < data_count; batch_start += KNN_BATCH_POINTS) {
        int current_batch = data_count - batch_start;
        if (current_batch > KNN_BATCH_POINTS) {
            current_batch = KNN_BATCH_POINTS;
        }

        // Whole block stages the next batch into shared memory.
        for (int i = threadIdx.x; i < current_batch; i += KNN_BLOCK_THREADS) {
            sh_data[i] = data[batch_start + i];
        }
        __syncthreads();

        if (active) {
            // Process the staged batch in warp-sized steps of 32 points.
            // Pre-flushing if there is not enough room for the next step guarantees that the fixed-size
            // shared candidate buffer never overflows, without allocating any extra device memory.
            for (int p_base = 0; p_base < current_batch; p_base += 32) {
                int step_size = current_batch - p_base;
                if (step_size > 32) {
                    step_size = 32;
                }

                if (candidate_count > K - step_size) {
                    max_distance = flush_candidate_buffer<K>(buf_idx, buf_dist, buf_count, candidate_count,
                                                             best_idx, best_dist);
                    candidate_count = 0;
                }

                const int p = p_base + lane;
                const bool valid = (p < current_batch);

                float dist = 0.0f;
                if (valid) {
                    dist = distance_sq_2d(qx, qy, sh_data[p]);
                }

                const bool qualifies = valid && (dist < max_distance);
                const unsigned ballot = __ballot_sync(FULL_MASK, qualifies);
                const int n = __popc(ballot);

                if (n != 0) {
                    int base = 0;
                    if (lane == 0) {
                        base = atomicAdd(buf_count, n);
                    }
                    base = __shfl_sync(FULL_MASK, base, 0);

                    if (qualifies) {
                        const int offset = __popc(ballot & lane_mask_lt);
                        const int pos = base + offset;
                        buf_idx[pos]  = batch_start + p;
                        buf_dist[pos] = dist;
                    }

                    candidate_count += n;
                }

                __syncwarp();

                if (candidate_count == K) {
                    max_distance = flush_candidate_buffer<K>(buf_idx, buf_dist, buf_count, candidate_count,
                                                             best_idx, best_dist);
                    candidate_count = 0;
                }
            }
        }

        // All warps must be done reading sh_data before the next batch overwrites it.
        __syncthreads();
    }

    if (active) {
        if (candidate_count != 0) {
            max_distance = flush_candidate_buffer<K>(buf_idx, buf_dist, buf_count, candidate_count,
                                                     best_idx, best_dist);
            (void)max_distance;
        }

        // The private result is already sorted ascending, so writing it out preserves the required order.
        const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int t = 0; t < ITEMS_PER_LANE; ++t) {
            const int pos = lane + (t << 5);
            result[out_base + static_cast<std::size_t>(pos)].first  = best_idx[t];
            result[out_base + static_cast<std::size_t>(pos)].second = best_dist[t];
        }
    }
}

template <int K>
void launch_knn_template(const float2* query,
                         const int query_count,
                         const float2* data,
                         const int data_count,
                         std::pair<int, float>* result) {
    constexpr std::size_t smem_bytes = knn_shared_bytes<K>();

    const dim3 block(KNN_BLOCK_THREADS);
    const dim3 grid((query_count + KNN_WARPS_PER_BLOCK - 1) / KNN_WARPS_PER_BLOCK);

    // This kernel is intentionally shared-memory heavy; prefer the maximum shared carveout.
    cudaFuncSetAttribute(knn_kernel<K>, cudaFuncAttributeMaxDynamicSharedMemorySize,
                         static_cast<int>(smem_bytes));
    cudaFuncSetAttribute(knn_kernel<K>, cudaFuncAttributePreferredSharedMemoryCarveout, 100);

    knn_kernel<K><<<grid, block, smem_bytes>>>(query, query_count, data, data_count, result);
}

} // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn_detail::launch_knn_template<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_detail::launch_knn_template<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_detail::launch_knn_template<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_detail::launch_knn_template<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_detail::launch_knn_template<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_detail::launch_knn_template<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem statement guarantees valid k, so this path is not expected.
            break;
    }
}

#include <cuda_runtime.h>
#include <math_constants.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace knn_detail {

// Design summary:
//
// * One warp owns one query.
// * The current top-k for that query is kept private to the warp in a striped layout:
//       lane l owns ranks l, l+32, l+64, ...
//   This makes the reverse-order access used by the bitonic top-k merge a simple lane-reversal
//   shuffle (`source_lane = 31 - lane`).
// * Each warp also owns a k-entry candidate buffer in shared memory plus a shared counter.
// * The whole block streams the `data` array through a large shared-memory tile. All query warps
//   reuse that tile, which is the dominant optimization for million-point data sets.
// * Whenever the candidate buffer is merged, the steps follow the requested scheme exactly:
//     1) sort buffer ascending with bitonic sort,
//     2) bitonic min-merge with the reversed intermediate result,
//     3) sort again to obtain the updated ascending intermediate result.
//
// Tuning choice:
//
// For k <= 512 we use 32 warps/block (1024 threads) to maximize reuse of each shared tile.
// For k == 1024 each warp needs an 8 KiB candidate buffer, so 16 warps/block is the best fit
// that still leaves room for a useful data tile under the 160 KiB opt-in shared-memory budget
// supported by A100 and H100-class GPUs.

constexpr int      kWarpSize          = 32;
constexpr unsigned kFullMask          = 0xFFFFFFFFu;
constexpr size_t   kSharedBudgetBytes = 160 * 1024;

// Compile-time launch/shared-memory configuration for a given (K, warps/block).
template <int K, int WARPS_PER_BLOCK>
struct KernelConfig {
    static_assert(K >= kWarpSize && K <= 1024 && (K & (K - 1)) == 0, "K must be a power of two in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    static_assert((WARPS_PER_BLOCK * kWarpSize) <= 1024, "Block size exceeds CUDA limit.");

    static constexpr int items_per_lane = K / kWarpSize;
    static constexpr int block_threads  = WARPS_PER_BLOCK * kWarpSize;

    // Candidate buffer uses a structure-of-arrays layout in shared memory to keep the bitonic
    // sort/merge on 4-byte banks.
    static constexpr size_t candidate_dist_bytes = static_cast<size_t>(WARPS_PER_BLOCK) * K * sizeof(float);
    static constexpr size_t candidate_idx_bytes  = static_cast<size_t>(WARPS_PER_BLOCK) * K * sizeof(int);
    static constexpr size_t count_bytes          = static_cast<size_t>(WARPS_PER_BLOCK) * sizeof(int);

    // Leave enough shared memory for the tile after reserving all per-warp candidate storage.
    static_assert(candidate_dist_bytes + candidate_idx_bytes + count_bytes + kWarpSize * sizeof(float2) <= kSharedBudgetBytes,
                  "Configuration leaves no room for even one warp-wide data chunk.");

    static constexpr size_t available_tile_bytes = kSharedBudgetBytes - candidate_dist_bytes - candidate_idx_bytes - count_bytes;
    static constexpr int    raw_tile_points      = static_cast<int>(available_tile_bytes / sizeof(float2));

    // Round the tile size down to a multiple of a warp:
    //   * simplifies per-warp chunking,
    //   * preserves 16-byte alignment for float4 vectorized tile loads because K and tile_points
    //     are both multiples of 32, so every tile_base is also a multiple of 32.
    static constexpr int tile_points = (raw_tile_points / kWarpSize) * kWarpSize;

    static_assert(tile_points >= kWarpSize, "Tile must contain at least one warp-wide chunk.");
    static_assert((tile_points % kWarpSize) == 0, "Tile size must be warp-aligned.");

    static constexpr size_t shared_bytes =
        static_cast<size_t>(tile_points) * sizeof(float2) +
        candidate_dist_bytes +
        candidate_idx_bytes +
        count_bytes;

    static_assert(shared_bytes <= kSharedBudgetBytes, "Shared-memory budget exceeded.");
};

template <int K> struct PreferredWarps;
template <> struct PreferredWarps<32>   { static constexpr int value = 32; };
template <> struct PreferredWarps<64>   { static constexpr int value = 32; };
template <> struct PreferredWarps<128>  { static constexpr int value = 32; };
template <> struct PreferredWarps<256>  { static constexpr int value = 32; };
template <> struct PreferredWarps<512>  { static constexpr int value = 32; };
template <> struct PreferredWarps<1024> { static constexpr int value = 16; };

// Total order on (distance, index). The index tie-break is not required for correctness of the
// problem statement, but it gives the bitonic network a deterministic strict weak order.
__device__ __forceinline__ bool pair_less(float ad, int ai, float bd, int bi) {
    return (ad < bd) || ((ad == bd) && (ai < bi));
}

__device__ __forceinline__ bool pair_greater(float ad, int ai, float bd, int bi) {
    return pair_less(bd, bi, ad, ai);
}

__device__ __forceinline__ float squared_l2(const float2 p, float qx, float qy) {
    const float dx = p.x - qx;
    const float dy = p.y - qy;
    return fmaf(dx, dx, dy * dy);
}

// Warp-cooperative in-place bitonic sort of K key/value pairs stored in shared memory.
// Each lane owns the striped indices lane, lane+32, lane+64, ...
template <int K>
__device__ __forceinline__ void bitonic_sort_shared(float* dist, int* idx, int lane) {
    constexpr int ITEMS = K / kWarpSize;

    // Avoid fully unrolling the outer bitonic stages; that would inflate code size heavily for
    // K = 1024. The per-lane striped loop is still fully unrolled.
    #pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            #pragma unroll
            for (int t = 0; t < ITEMS; ++t) {
                const int i = lane + t * kWarpSize;
                const int j = i ^ stride;

                if (j > i) {
                    const float di = dist[i];
                    const int   ii = idx[i];
                    const float dj = dist[j];
                    const int   ij = idx[j];

                    const bool ascending = ((i & size) == 0);
                    if ((ascending  && pair_greater(di, ii, dj, ij)) ||
                        (!ascending && pair_less   (di, ii, dj, ij))) {
                        dist[i] = dj; idx[i] = ij;
                        dist[j] = di; idx[j] = ii;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Seed the private intermediate result with the first K data points and sort it ascending.
// This tightens max_distance immediately, which sharply improves later filtering.
template <int K>
__device__ __forceinline__ float seed_topk(
    const float2* __restrict__ data,
    float qx,
    float qy,
    float* scratch_dist,
    int* scratch_idx,
    float (&best_dist)[K / kWarpSize],
    int   (&best_idx )[K / kWarpSize],
    int lane)
{
    constexpr int ITEMS = K / kWarpSize;

    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = lane + t * kWarpSize;
        scratch_dist[p] = squared_l2(data[p], qx, qy);
        scratch_idx [p] = p;
    }
    __syncwarp();

    bitonic_sort_shared<K>(scratch_dist, scratch_idx, lane);

    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = lane + t * kWarpSize;
        best_dist[t] = scratch_dist[p];
        best_idx [t] = scratch_idx [p];
    }

    // In striped layout, rank K-1 is held by lane 31 at slot ITEMS-1.
    float kth = best_dist[ITEMS - 1];
    return __shfl_sync(kFullMask, kth, kWarpSize - 1);
}

// Merge the shared candidate buffer into the warp-private intermediate result.
// Steps:
//   1) pad the unused tail with (+inf, INT_MAX) and sort the whole K-entry buffer ascending,
//   2) write cand[i] = min(cand[i], best[K-1-i]) to form a bitonic sequence,
//   3) sort that bitonic sequence ascending,
//   4) copy back to the private striped top-k and refresh max_distance.
template <int K>
__device__ __forceinline__ void flush_candidates(
    float* cand_dist,
    int* cand_idx,
    int* count_ptr,
    float (&best_dist)[K / kWarpSize],
    int   (&best_idx )[K / kWarpSize],
    float& max_distance,
    int lane)
{
    constexpr int ITEMS = K / kWarpSize;

    int count = 0;
    if (lane == 0) {
        count = *count_ptr;
    }
    count = __shfl_sync(kFullMask, count, 0);

    if (count == 0) {
        return;
    }

    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = lane + t * kWarpSize;
        if (p >= count) {
            cand_dist[p] = CUDART_INF_F;
            cand_idx [p] = INT_MAX;
        }
    }
    __syncwarp();

    bitonic_sort_shared<K>(cand_dist, cand_idx, lane);

    const int reverse_lane = kWarpSize - 1 - lane;

    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = lane + t * kWarpSize;

        const float bd = cand_dist[p];
        const int   bi = cand_idx [p];

        // Reverse rank K-1-p maps to:
        //   source lane = 31 - lane
        //   source slot = ITEMS - 1 - t
        const float rd_local = best_dist[ITEMS - 1 - t];
        const int   ri_local = best_idx [ITEMS - 1 - t];
        const float rd       = __shfl_sync(kFullMask, rd_local, reverse_lane);
        const int   ri       = __shfl_sync(kFullMask, ri_local, reverse_lane);

        if (pair_less(bd, bi, rd, ri)) {
            cand_dist[p] = bd;
            cand_idx [p] = bi;
        } else {
            cand_dist[p] = rd;
            cand_idx [p] = ri;
        }
    }
    __syncwarp();

    bitonic_sort_shared<K>(cand_dist, cand_idx, lane);

    #pragma unroll
    for (int t = 0; t < ITEMS; ++t) {
        const int p = lane + t * kWarpSize;
        best_dist[t] = cand_dist[p];
        best_idx [t] = cand_idx [p];
    }

    float kth = best_dist[ITEMS - 1];
    max_distance = __shfl_sync(kFullMask, kth, kWarpSize - 1);

    if (lane == 0) {
        *count_ptr = 0;
    }
    __syncwarp();
}

template <int K, int WARPS_PER_BLOCK>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize, 1)
void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result)
{
    using Config = KernelConfig<K, WARPS_PER_BLOCK>;
    constexpr int ITEMS       = Config::items_per_lane;
    constexpr int TILE_POINTS = Config::tile_points;

    // Dynamic shared-memory layout:
    //   [ float2 tile[TILE_POINTS] ]
    //   [ float  cand_dist[WARPS_PER_BLOCK * K] ]
    //   [ int    cand_idx [WARPS_PER_BLOCK * K] ]
    //   [ int    cand_count[WARPS_PER_BLOCK] ]
    extern __shared__ __align__(16) unsigned char shared_raw[];

    float2* const tile          = reinterpret_cast<float2*>(shared_raw);
    float*  const cand_dist_all = reinterpret_cast<float*>(tile + TILE_POINTS);
    int*    const cand_idx_all  = reinterpret_cast<int*>(cand_dist_all + WARPS_PER_BLOCK * K);
    int*    const cand_count    = cand_idx_all + WARPS_PER_BLOCK * K;

    const int lane       = threadIdx.x & (kWarpSize - 1);
    const int warp_local = threadIdx.x >> 5;
    const int query_idx  = blockIdx.x * WARPS_PER_BLOCK + warp_local;
    const bool active    = (query_idx < query_count);

    float* const cand_dist = cand_dist_all + warp_local * K;
    int*   const cand_idx  = cand_idx_all  + warp_local * K;
    int*   const count_ptr = cand_count    + warp_local;

    if (lane == 0) {
        *count_ptr = 0;
    }

    // Broadcast the query coordinates from lane 0.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Warp-private intermediate top-k in striped layout.
    float best_dist[ITEMS];
    int   best_idx [ITEMS];
    float max_distance = CUDART_INF_F;

    if (active) {
        max_distance = seed_topk<K>(data, qx, qy, cand_dist, cand_idx, best_dist, best_idx, lane);
    }

    // Process the rest of the data in shared-memory tiles.
    for (int tile_base = K; tile_base < data_count; tile_base += TILE_POINTS) {
        const int remaining = data_count - tile_base;
        const int batch_n   = (remaining < TILE_POINTS) ? remaining : TILE_POINTS;

        // Vectorized block-wide load: because K and TILE_POINTS are multiples of 32, tile_base is
        // always a multiple of 32, so (data + tile_base) remains 16-byte aligned and can be read
        // as float4 safely.
        const int pair_count = batch_n >> 1;
        const float4* const data_vec = reinterpret_cast<const float4*>(data + tile_base);
        float4* const tile_vec       = reinterpret_cast<float4*>(tile);

        for (int i = threadIdx.x; i < pair_count; i += Config::block_threads) {
            tile_vec[i] = data_vec[i];
        }
        if ((batch_n & 1) && threadIdx.x == 0) {
            tile[batch_n - 1] = data[tile_base + batch_n - 1];
        }

        __syncthreads();

        if (active) {
            // Each warp scans the cached tile in chunks of 32 points so that at most one candidate
            // per lane is generated before the next buffer-capacity decision.
            for (int offset = 0; offset < batch_n; offset += kWarpSize) {
                const int local_i = offset + lane;

                float dist = 0.0f;
                int   data_index = 0;
                bool  is_candidate = false;

                if (local_i < batch_n) {
                    const float2 p = tile[local_i];
                    dist = squared_l2(p, qx, qy);
                    data_index = tile_base + local_i;
                    is_candidate = (dist < max_distance);
                }

                const unsigned candidate_mask = __ballot_sync(kFullMask, is_candidate);
                const int num_candidates = __popc(candidate_mask);

                if (num_candidates != 0) {
                    int count = 0;
                    if (lane == 0) {
                        count = *count_ptr;
                    }
                    count = __shfl_sync(kFullMask, count, 0);

                    // If inserting this whole wave would overflow the k-entry buffer, merge the
                    // existing buffer first. The candidate decisions in the current wave were made
                    // against the old max_distance. That is still safe: max_distance only shrinks,
                    // so keeping these "possibly now too loose" candidates cannot lose correctness;
                    // the subsequent top-k merge will discard them if needed.
                    if (count + num_candidates > K) {
                        flush_candidates<K>(cand_dist, cand_idx, count_ptr,
                                            best_dist, best_idx, max_distance, lane);
                        count = 0;
                    }

                    if (is_candidate) {
                        const int pos = atomicAdd(count_ptr, 1);
                        cand_dist[pos] = dist;
                        cand_idx [pos] = data_index;
                    }
                    __syncwarp();

                    if (count + num_candidates == K) {
                        flush_candidates<K>(cand_dist, cand_idx, count_ptr,
                                            best_dist, best_idx, max_distance, lane);
                    }
                }
            }
        }

        __syncthreads();
    }

    if (active) {
        // Final merge for the residual, partially filled candidate buffer.
        flush_candidates<K>(cand_dist, cand_idx, count_ptr,
                            best_dist, best_idx, max_distance, lane);

        const size_t out_base = static_cast<size_t>(query_idx) * K;

        #pragma unroll
        for (int t = 0; t < ITEMS; ++t) {
            const size_t p = static_cast<size_t>(lane + t * kWarpSize);
            result[out_base + p].first  = best_idx[t];
            result[out_base + p].second = best_dist[t];
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
inline void launch_knn_specialized(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    using Config = KernelConfig<K, WARPS_PER_BLOCK>;

    // Prefer shared memory over L1 because this kernel is explicitly tile-reuse driven.
    (void)cudaFuncSetCacheConfig(knn_kernel<K, WARPS_PER_BLOCK>, cudaFuncCachePreferShared);
    (void)cudaFuncSetAttribute(knn_kernel<K, WARPS_PER_BLOCK>,
                               cudaFuncAttributePreferredSharedMemoryCarveout, 100);
    (void)cudaFuncSetAttribute(knn_kernel<K, WARPS_PER_BLOCK>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(Config::shared_bytes));

    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    knn_kernel<K, WARPS_PER_BLOCK>
        <<<blocks, Config::block_threads, Config::shared_bytes>>>(
            query, query_count, data, data_count, result);
}

template <int K>
inline void launch_knn_preferred(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result)
{
    launch_knn_specialized<K, PreferredWarps<K>::value>(query, query_count, data, data_count, result);
}

} // namespace knn_detail

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0) {
        return;
    }

    // k only takes six legal values; dispatching to fully specialized kernels keeps the per-lane
    // private top-k size compile-time constant and lets the compiler optimize heavily.
    switch (k) {
        case 32:
            knn_detail::launch_knn_preferred<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_detail::launch_knn_preferred<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_detail::launch_knn_preferred<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_detail::launch_knn_preferred<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_detail::launch_knn_preferred<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_detail::launch_knn_preferred<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem guarantees that k is valid, so this path is unreachable for legal input.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

// Warp size is fixed by the problem statement.
constexpr int kWarpThreads = 32;

// A single tile size is used across all launch variants.
// 2016 = 63 * 32, i.e. an integer number of warp-sized chunks.
// This value is deliberately chosen so that even the heaviest A100-compatible
// variants (e.g. K=512/W=18 and K=1024/W=9) fit under the opt-in shared-memory
// limit, while still being large enough to amortize global-memory loads.
constexpr int kDataTilePoints = 2016;

// The host-side launcher asks for enough blocks to cover roughly 75% of the SMs.
// This balances two competing goals:
//   1) larger blocks -> more queries reuse each shared-memory tile,
//   2) smaller blocks -> more grid-level parallelism when query_count is modest.
constexpr int kTargetGridCoverageNum = 3;
constexpr int kTargetGridCoverageDen = 4;

using packed_t = unsigned long long;
using output_pair_t = std::pair<int, float>;

// Distances are non-negative squared L2 distances, so IEEE-754 bit patterns
// preserve the numerical order for all finite values and +inf. Packing the
// distance into the high 32 bits makes a plain unsigned compare sort by
// distance first. The low 32 bits carry the index payload and provide a
// deterministic tie-breaker, although the problem statement does not require
// any specific tie resolution.
__device__ __forceinline__ packed_t pack_pair(const float dist, const int idx) {
    return (static_cast<packed_t>(__float_as_uint(dist)) << 32) |
           static_cast<unsigned int>(idx);
}

__device__ __forceinline__ float unpack_dist(const packed_t v) {
    return __uint_as_float(static_cast<unsigned int>(v >> 32));
}

__device__ __forceinline__ int unpack_idx(const packed_t v) {
    return static_cast<int>(static_cast<unsigned int>(v));
}

__device__ __forceinline__ float squared_l2_2d(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

// Warp-local bitonic sort on a K-element array stored in the caller warp's
// private shared-memory segment. The implementation follows the requested
// bitonic-sort structure exactly, with each lane owning a striped subset:
//   global position p  <->  lane = p & 31, slot = p >> 5.
template <int K>
__device__ __forceinline__ void bitonic_sort_shared(packed_t* arr) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    static_assert(K >= kWarpThreads && K <= 1024, "K out of supported range");
    constexpr int ITEMS_PER_LANE = K / kWarpThreads;

    const int lane = threadIdx.x & (kWarpThreads - 1);

    __syncwarp();

    // Keep the stage loops dynamic to avoid excessive code size, but fully
    // unroll the per-lane striped accesses, which are short and compile-time
    // known.
#pragma unroll 1
    for (int size = 2; size <= K; size <<= 1) {
#pragma unroll 1
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
#pragma unroll
            for (int item = 0; item < ITEMS_PER_LANE; ++item) {
                const int i = item * kWarpThreads + lane;
                const int l = i ^ stride;

                if (l > i) {
                    const bool ascending = ((i & size) == 0);

                    const packed_t a = arr[i];
                    const packed_t b = arr[l];

                    const bool do_swap = ascending ? (a > b) : (a < b);
                    if (do_swap) {
                        arr[i] = b;
                        arr[l] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// Merge the warp-private top-k (kept in registers, striped across the warp)
// with the shared-memory candidate buffer exactly as requested:
//   1) sort buffer ascending with bitonic sort,
//   2) form the bitonic merge sequence via min(buffer[i], result[k-i-1]),
//   3) bitonic-sort that sequence to produce the updated top-k.
// The candidate counter is reset to zero on exit, and max_distance is updated.
template <int K>
__device__ __forceinline__ void merge_candidate_buffer_into_result(
    packed_t* candidate_buffer,
    packed_t* scratch_buffer,
    int* candidate_count,
    packed_t (&result_pairs)[K / kWarpThreads],
    float& max_distance)
{
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    constexpr int ITEMS_PER_LANE = K / kWarpThreads;
    constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

    const int lane = threadIdx.x & (kWarpThreads - 1);
    const packed_t inf_pair = pack_pair(CUDART_INF_F, -1);

    __syncwarp();

    int count = 0;
    if (lane == 0) {
        count = *candidate_count;
    }
    count = __shfl_sync(FULL_MASK, count, 0);

    // Pad the unused tail with +inf so the prescribed sort/merge path can be
    // used uniformly for both full and partial buffers.
#pragma unroll
    for (int item = 0; item < ITEMS_PER_LANE; ++item) {
        const int pos = item * kWarpThreads + lane;
        if (pos >= count) {
            candidate_buffer[pos] = inf_pair;
        }
    }
    __syncwarp();

    // Step 1: sort the candidate buffer in ascending order.
    bitonic_sort_shared<K>(candidate_buffer);

    // Copy the current sorted intermediate result to shared scratch so the
    // reverse-indexed accesses needed by the bitonic merge are cheap.
#pragma unroll
    for (int item = 0; item < ITEMS_PER_LANE; ++item) {
        const int pos = item * kWarpThreads + lane;
        scratch_buffer[pos] = result_pairs[item];
    }
    __syncwarp();

    // Step 2: min(buffer[i], result[k-i-1]) -> bitonic sequence containing the
    // k smallest elements of the union.
#pragma unroll
    for (int item = 0; item < ITEMS_PER_LANE; ++item) {
        const int pos = item * kWarpThreads + lane;
        const packed_t a = candidate_buffer[pos];
        const packed_t b = scratch_buffer[K - 1 - pos];
        candidate_buffer[pos] = (a < b) ? a : b;
    }
    __syncwarp();

    // Step 3: sort the merged bitonic sequence ascending.
    bitonic_sort_shared<K>(candidate_buffer);

    // Copy the updated top-k back to the warp-private register file.
#pragma unroll
    for (int item = 0; item < ITEMS_PER_LANE; ++item) {
        const int pos = item * kWarpThreads + lane;
        result_pairs[item] = candidate_buffer[pos];
    }

    // The k-th nearest neighbor lives in global position K-1, which maps to
    // lane 31 and slot ITEMS_PER_LANE-1 because K is always a multiple of 32.
    float tail = 0.0f;
    if (lane == kWarpThreads - 1) {
        tail = unpack_dist(result_pairs[ITEMS_PER_LANE - 1]);
    }
    max_distance = __shfl_sync(FULL_MASK, tail, kWarpThreads - 1);

    if (lane == 0) {
        *candidate_count = 0;
    }
    __syncwarp();
}

// Kernel overview:
//   * one warp owns one query,
//   * the whole block cooperatively loads data tiles into shared memory,
//   * each active warp computes distances from its own query to the cached tile,
//   * accepted candidates are appended to a per-warp shared buffer,
//   * whenever the buffer becomes full, it is merged into the warp-private top-k.
template <int K, int WARPS_PER_BLOCK, int DATA_TILE_POINTS>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpThreads)
void knn_2d_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    output_pair_t* __restrict__ result)
{
    static_assert((K & (K - 1)) == 0, "K must be a power of two");
    static_assert(K >= kWarpThreads && K <= 1024, "K out of supported range");
    static_assert(K % kWarpThreads == 0, "K must be divisible by warp size");
    static_assert(DATA_TILE_POINTS % kWarpThreads == 0, "Tile size must be a multiple of warp size");
    static_assert(WARPS_PER_BLOCK >= 1, "At least one warp per block is required");
    static_assert(WARPS_PER_BLOCK * kWarpThreads <= 1024, "Block size exceeds CUDA limit");

    constexpr int ITEMS_PER_LANE = K / kWarpThreads;
    constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

    const int lane = threadIdx.x & (kWarpThreads - 1);
    const int warp_in_block = threadIdx.x >> 5;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_in_block;
    const bool active = (query_idx < query_count);

    // Shared-memory layout:
    //   [tile of float2 data points]
    //   [per-warp candidate buffer, packed distance/index pairs]
    //   [per-warp scratch buffer, same format]
    //   [per-warp candidate counts]
    extern __shared__ unsigned char shared_raw[];
    auto* s_tile = reinterpret_cast<float2*>(shared_raw);
    auto* s_candidate = reinterpret_cast<packed_t*>(s_tile + DATA_TILE_POINTS);
    auto* s_scratch = s_candidate + static_cast<size_t>(WARPS_PER_BLOCK) * K;
    auto* s_counts = reinterpret_cast<int*>(s_scratch + static_cast<size_t>(WARPS_PER_BLOCK) * K);

    packed_t* candidate_buffer = s_candidate + static_cast<size_t>(warp_in_block) * K;
    packed_t* scratch_buffer = s_scratch + static_cast<size_t>(warp_in_block) * K;
    int* candidate_count = s_counts + warp_in_block;

    // Warp-private top-k, striped across lanes:
    //   result position p is stored in lane (p & 31), slot (p >> 5).
    packed_t topk[ITEMS_PER_LANE];
    float max_distance = CUDART_INF_F;
    float qx = 0.0f;
    float qy = 0.0f;

    if (lane == 0) {
        *candidate_count = 0;
    }
    __syncwarp();

    if (active) {
        // Load the query point once per warp and broadcast to all lanes.
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(FULL_MASK, qx, 0);
        qy = __shfl_sync(FULL_MASK, qy, 0);

        // Initialize the intermediate top-k from the first K data points.
        // This immediately establishes a useful max_distance and prevents the
        // candidate buffer from filling with every early point.
#pragma unroll
        for (int item = 0; item < ITEMS_PER_LANE; ++item) {
            const int data_idx = item * kWarpThreads + lane;
            const float2 p = data[data_idx];
            const float dist = squared_l2_2d(qx, qy, p);
            scratch_buffer[data_idx] = pack_pair(dist, data_idx);
        }
        __syncwarp();

        bitonic_sort_shared<K>(scratch_buffer);

#pragma unroll
        for (int item = 0; item < ITEMS_PER_LANE; ++item) {
            const int pos = item * kWarpThreads + lane;
            topk[item] = scratch_buffer[pos];
        }

        float tail = 0.0f;
        if (lane == kWarpThreads - 1) {
            tail = unpack_dist(topk[ITEMS_PER_LANE - 1]);
        }
        max_distance = __shfl_sync(FULL_MASK, tail, kWarpThreads - 1);
    }

    // Process the remaining data points in shared-memory tiles.
    for (int tile_begin = K; tile_begin < data_count; tile_begin += DATA_TILE_POINTS) {
        const int remaining = data_count - tile_begin;
        const int tile_count = (remaining < DATA_TILE_POINTS) ? remaining : DATA_TILE_POINTS;

        // Cooperative block-wide load of the next tile.
        for (int i = threadIdx.x; i < tile_count; i += blockDim.x) {
            s_tile[i] = data[tile_begin + i];
        }
        __syncthreads();

        if (active) {
            const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

            // One chunk = 32 cached points, one candidate point per lane.
#pragma unroll 1
            for (int chunk = 0; chunk < tile_count; chunk += kWarpThreads) {
                const int local_idx = chunk + lane;

                float dist = 0.0f;
                int data_idx = tile_begin + local_idx;
                bool accept = false;

                if (local_idx < tile_count) {
                    const float2 p = s_tile[local_idx];
                    dist = squared_l2_2d(qx, qy, p);
                    accept = (dist < max_distance);
                }

                // Within a 32-point chunk, use one warp-aggregated atomicAdd plus
                // per-lane prefix ranks. This still uses atomicAdd exactly for the
                // shared candidate count / position reservation, but avoids 32
                // independent atomics when many lanes accept simultaneously.
                unsigned pending_mask = __ballot_sync(FULL_MASK, accept);

                while (pending_mask != 0u) {
                    const int rank = __popc(pending_mask & lane_mask_lt);
                    const int nvalid = __popc(pending_mask);

                    int base = 0;
                    if (lane == 0) {
                        base = atomicAdd(candidate_count, nvalid);
                    }
                    base = __shfl_sync(FULL_MASK, base, 0);

                    const int available = (base < K) ? (K - base) : 0;

                    if (available > 0 && accept && rank < available) {
                        candidate_buffer[base + rank] = pack_pair(dist, data_idx);
                    }
                    __syncwarp();

                    // The requested behavior is to merge immediately whenever the
                    // buffer becomes full, including the exact-fill case.
                    const bool buffer_full = (base + nvalid) >= K;

                    if (!buffer_full) {
                        accept = false;
                        pending_mask = 0u;
                    } else {
                        const bool leftover = accept && (rank >= available);

                        if (lane == 0) {
                            *candidate_count = K;
                        }
                        __syncwarp();

                        merge_candidate_buffer_into_result<K>(
                            candidate_buffer, scratch_buffer, candidate_count, topk, max_distance);

                        // Any candidates that did not fit are re-evaluated against
                        // the tightened threshold; those that are no longer useful
                        // are discarded immediately.
                        accept = leftover && (dist < max_distance);
                        pending_mask = __ballot_sync(FULL_MASK, accept);
                    }
                }
            }
        }

        // All warps must finish consuming the cached tile before it is reused.
        __syncthreads();
    }

    if (active) {
        int pending = 0;
        if (lane == 0) {
            pending = *candidate_count;
        }
        pending = __shfl_sync(FULL_MASK, pending, 0);

        if (pending > 0) {
            merge_candidate_buffer_into_result<K>(
                candidate_buffer, scratch_buffer, candidate_count, topk, max_distance);
        }

        // Write the final sorted top-k list back to global memory in row-major
        // query-major order: result[query_idx * K + j].
        output_pair_t* out_row = result + static_cast<size_t>(query_idx) * static_cast<size_t>(K);

#pragma unroll
        for (int item = 0; item < ITEMS_PER_LANE; ++item) {
            const int pos = item * kWarpThreads + lane;
            const packed_t v = topk[item];

            // Direct member stores avoid relying on any device-side std::pair
            // constructors; the destination memory already exists in cudaMalloc-
            // allocated storage.
            out_row[pos].first = unpack_idx(v);
            out_row[pos].second = unpack_dist(v);
        }
    }
}

template <int K, int WARPS_PER_BLOCK, int DATA_TILE_POINTS>
constexpr size_t shared_bytes_for_variant() {
    return static_cast<size_t>(DATA_TILE_POINTS) * sizeof(float2) +
           static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(K) * sizeof(packed_t) * 2 +
           static_cast<size_t>(WARPS_PER_BLOCK) * sizeof(int);
}

template <int WARPS_PER_BLOCK>
inline int blocks_for_queries(const int query_count) {
    return (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
}

template <int K, int WARPS_PER_BLOCK, int DATA_TILE_POINTS>
inline bool fits_shared_budget(const int max_optin_shared_bytes) {
    return shared_bytes_for_variant<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>() <=
           static_cast<size_t>(max_optin_shared_bytes);
}

template <int K, int WARPS_PER_BLOCK, int DATA_TILE_POINTS>
inline void launch_variant(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    output_pair_t* result)
{
    constexpr size_t SHARED_BYTES = shared_bytes_for_variant<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>();

    // The interface requested a void return type, so this launcher intentionally
    // keeps the call path minimal and leaves CUDA error handling to the caller's
    // surrounding workflow.
    cudaFuncSetAttribute(
        knn_2d_kernel<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHARED_BYTES));

    cudaFuncSetAttribute(
        knn_2d_kernel<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(WARPS_PER_BLOCK * kWarpThreads);
    const dim3 grid(blocks_for_queries<WARPS_PER_BLOCK>(query_count));

    knn_2d_kernel<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>
        <<<grid, block, SHARED_BYTES>>>(query, query_count, data, data_count, result);
}

template <int K, int WARPS_PER_BLOCK, int DATA_TILE_POINTS>
inline bool try_launch_variant(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    output_pair_t* result,
    int min_grid_blocks,
    int max_optin_shared_bytes)
{
    if (fits_shared_budget<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>(max_optin_shared_bytes) &&
        blocks_for_queries<WARPS_PER_BLOCK>(query_count) >= min_grid_blocks)
    {
        launch_variant<K, WARPS_PER_BLOCK, DATA_TILE_POINTS>(
            query, query_count, data, data_count, result);
        return true;
    }
    return false;
}

template <int K>
inline void dispatch_k(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    output_pair_t* result,
    int sm_count,
    int max_optin_shared_bytes)
{
    constexpr int TILE = kDataTilePoints;

    const int min_grid_blocks =
        (sm_count * kTargetGridCoverageNum + (kTargetGridCoverageDen - 1)) / kTargetGridCoverageDen;

    if constexpr (K <= 256) {
        // Small/medium K can profit from fairly wide blocks because the
        // per-query register/shared footprint is modest.
        if (try_launch_variant<K, 32, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K, 24, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K, 16, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K, 12, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K,  8, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;

        // Fallback for smaller query batches and/or smaller shared-memory budgets.
        launch_variant<K, 4, TILE>(query, query_count, data, data_count, result);
    } else if constexpr (K == 512) {
        // K=512 still benefits from large tile reuse, but the larger top-k state
        // makes the very wide variants expensive in shared memory. W=24 is H100-
        // friendly; W=18 stays within the A100 envelope.
        if (try_launch_variant<K, 24, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K, 18, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K, 12, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K,  8, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;

        launch_variant<K, 4, TILE>(query, query_count, data, data_count, result);
    } else {
        // K=1024 is the heaviest case. W=12 fits only on Hopper-class large
        // shared-memory budgets; W=9 fits on A100; the narrower variants keep
        // enough grid-level parallelism when query_count is smaller.
        if (try_launch_variant<K, 12, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K,  9, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K,  6, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;
        if (try_launch_variant<K,  4, TILE>(query, query_count, data, data_count, result, min_grid_blocks, max_optin_shared_bytes)) return;

        launch_variant<K, 2, TILE>(query, query_count, data, data_count, result);
    }
}

} // namespace

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    int sm_count = 0;
    int max_optin_shared_bytes = 0;

    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    cudaDeviceGetAttribute(&max_optin_shared_bytes, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    if (sm_count <= 0) {
        sm_count = 1;
    }
    if (max_optin_shared_bytes <= 0) {
        // Conservative fallback that still allows the narrowest variants.
        max_optin_shared_bytes = 49152;
    }

    switch (k) {
        case 32:
            dispatch_k<32>(query, query_count, data, data_count, result, sm_count, max_optin_shared_bytes);
            break;
        case 64:
            dispatch_k<64>(query, query_count, data, data_count, result, sm_count, max_optin_shared_bytes);
            break;
        case 128:
            dispatch_k<128>(query, query_count, data, data_count, result, sm_count, max_optin_shared_bytes);
            break;
        case 256:
            dispatch_k<256>(query, query_count, data, data_count, result, sm_count, max_optin_shared_bytes);
            break;
        case 512:
            dispatch_k<512>(query, query_count, data, data_count, result, sm_count, max_optin_shared_bytes);
            break;
        case 1024:
            dispatch_k<1024>(query, query_count, data, data_count, result, sm_count, max_optin_shared_bytes);
            break;
        default:
            // The problem statement guarantees valid k values, so this path is
            // unreachable for conforming callers.
            break;
    }
}

#include <cuda_runtime.h>

#include <algorithm>
#include <climits>
#include <cstddef>
#include <utility>

namespace {

// One warp owns one query. The current sorted top-k is kept entirely in registers, split
// evenly across the warp: each lane stores k/32 consecutive entries.
//
// A block also stages a tile of the data set in shared memory so that several warps reuse
// each global load. Separate shared-memory regions hold per-warp candidate buffers.
//
// The runtime launches one of three block shapes:
//
//   4 warps / block,  tile cap 1024  -> 40,960 B shared at k=1024, allows 4 resident
//                                       blocks on a 164 KB A100 SM.
//   8 warps / block,  tile cap 2048  -> 81,920 B shared at k=1024, allows 2 resident
//                                       blocks on a 164 KB A100 SM.
//  16 warps / block,  tile cap 3584  -> 159,744 B shared at k=1024, allows 1 resident
//                                       block on a 164 KB A100 SM.
//
// The launcher picks the largest reuse factor (warps per block) that still leaves roughly
// 75% as many blocks as SMs for the current query count. This balances:
//   * more warps/block  -> better reuse of the staged data tile,
//   * fewer warps/block -> more independent blocks when the query set is smaller.
//
// Ties are allowed to resolve arbitrarily by the problem statement. The sorting network
// uses the data index as a deterministic secondary key only to make the total order strict.
constexpr int      kWarpSize     = 32;
constexpr unsigned kFullMask     = 0xFFFFFFFFu;
constexpr int      kInvalidIndex = INT_MAX;

template <int WARPS_PER_BLOCK>
struct BlockConfig;

template <>
struct BlockConfig<4> {
    static constexpr int BLOCK_THREADS = 4 * kWarpSize;
    static constexpr int TILE_CAP      = 1024;
};

template <>
struct BlockConfig<8> {
    static constexpr int BLOCK_THREADS = 8 * kWarpSize;
    static constexpr int TILE_CAP      = 2048;
};

template <>
struct BlockConfig<16> {
    static constexpr int BLOCK_THREADS = 16 * kWarpSize;
    static constexpr int TILE_CAP      = 3584;
};

__device__ __forceinline__ bool item_less(float a_dist, int a_idx, float b_dist, int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__ void swap_items(float& a_dist, int& a_idx, float& b_dist, int& b_idx) {
    const float td = a_dist;
    const int   ti = a_idx;
    a_dist = b_dist;
    a_idx  = b_idx;
    b_dist = td;
    b_idx  = ti;
}

// Distributed bitonic sort over K items, where each lane owns ITEMS_PER_THREAD consecutive
// items. Because ITEMS_PER_THREAD is a power of two and the lane owns a consecutive range,
// any inter-lane exchange always targets the same register slot in the partner lane.
// For j < ITEMS_PER_THREAD, the exchange is purely intra-lane and becomes a simple register swap.
template <int K, int ITEMS_PER_THREAD>
__device__ __forceinline__ void bitonic_sort_warp(float (&dist)[ITEMS_PER_THREAD],
                                                  int (&idx)[ITEMS_PER_THREAD],
                                                  int lane) {
#pragma unroll
    for (int seq = 2; seq <= K; seq <<= 1) {
#pragma unroll
        for (int stride = seq >> 1; stride > 0; stride >>= 1) {
            if (stride >= ITEMS_PER_THREAD) {
                const int lane_xor = stride / ITEMS_PER_THREAD;

#pragma unroll
                for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
                    const int  global_i  = lane * ITEMS_PER_THREAD + item;
                    const bool up        = ((global_i & seq) == 0);
                    const bool lower_half = ((lane & lane_xor) == 0);
                    const bool keep_min  = (lower_half == up);

                    const float other_dist = __shfl_xor_sync(kFullMask, dist[item], lane_xor);
                    const int   other_idx  = __shfl_xor_sync(kFullMask, idx[item],  lane_xor);

                    if (keep_min) {
                        if (item_less(other_dist, other_idx, dist[item], idx[item])) {
                            dist[item] = other_dist;
                            idx[item]  = other_idx;
                        }
                    } else {
                        if (item_less(dist[item], idx[item], other_dist, other_idx)) {
                            dist[item] = other_dist;
                            idx[item]  = other_idx;
                        }
                    }
                }
            } else {
#pragma unroll
                for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
                    const int partner = item ^ stride;
                    if (partner > item) {
                        const int  global_i = lane * ITEMS_PER_THREAD + item;
                        const bool up       = ((global_i & seq) == 0);
                        const bool do_swap  = up
                            ? item_less(dist[partner], idx[partner], dist[item], idx[item])
                            : item_less(dist[item], idx[item], dist[partner], idx[partner]);

                        if (do_swap) {
                            swap_items(dist[item], idx[item], dist[partner], idx[partner]);
                        }
                    }
                }
            }
        }
    }
}

// Merge the shared-memory candidate buffer with the register-resident intermediate result,
// exactly in the order requested by the prompt:
//
//   0. intermediate result in registers is already sorted ascending,
//   1. swap intermediate result <-> shared buffer, so the buffer is now in registers,
//   2. bitonic-sort the buffer in ascending order,
//   3. create the bitonic "first K of the union" sequence by taking
//      min(buffer[i], intermediate[K-1-i]),
//   4. bitonic-sort again to obtain the updated intermediate result.
//
// Invalid entries in a partially filled buffer are padded with (+inf, INT_MAX) so they sort last.
template <int K, int ITEMS_PER_THREAD>
__device__ __forceinline__ void flush_candidate_buffer(float (&reg_dist)[ITEMS_PER_THREAD],
                                                       int (&reg_idx)[ITEMS_PER_THREAD],
                                                       float* warp_buf_dist,
                                                       int* warp_buf_idx,
                                                       int& buf_count,
                                                       float& max_distance,
                                                       int lane) {
    if (buf_count == 0) {
        return;
    }

    __syncwarp(kFullMask);

#pragma unroll
    for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
        const int global_i = lane * ITEMS_PER_THREAD + item;
        if (global_i >= buf_count) {
            warp_buf_dist[global_i] = CUDART_INF_F;
            warp_buf_idx[global_i]  = kInvalidIndex;
        }
    }

    __syncwarp(kFullMask);

#pragma unroll
    for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
        const int global_i = lane * ITEMS_PER_THREAD + item;

        const float cand_dist = warp_buf_dist[global_i];
        const int   cand_idx  = warp_buf_idx[global_i];

        warp_buf_dist[global_i] = reg_dist[item];
        warp_buf_idx[global_i]  = reg_idx[item];

        reg_dist[item] = cand_dist;
        reg_idx[item]  = cand_idx;
    }

    __syncwarp(kFullMask);

    bitonic_sort_warp<K, ITEMS_PER_THREAD>(reg_dist, reg_idx, lane);

#pragma unroll
    for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
        const int global_i = lane * ITEMS_PER_THREAD + item;

        const float other_dist = warp_buf_dist[K - 1 - global_i];
        const int   other_idx  = warp_buf_idx[K - 1 - global_i];

        if (item_less(other_dist, other_idx, reg_dist[item], reg_idx[item])) {
            reg_dist[item] = other_dist;
            reg_idx[item]  = other_idx;
        }
    }

    bitonic_sort_warp<K, ITEMS_PER_THREAD>(reg_dist, reg_idx, lane);

    buf_count = 0;

    // The k-th nearest neighbor is the last element of the sorted register file layout:
    // lane 31, last local slot.
    max_distance = __shfl_sync(kFullMask, reg_dist[ITEMS_PER_THREAD - 1], kWarpSize - 1);
}

template <int K, int WARPS_PER_BLOCK>
__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           std::pair<int, float>* __restrict__ result,
                           int tile_points) {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "K must be a power of two in [32, 1024].");
    static_assert(K % kWarpSize == 0, "K must be divisible by 32.");

    constexpr int ITEMS_PER_THREAD = K / kWarpSize;
    constexpr int BLOCK_THREADS    = BlockConfig<WARPS_PER_BLOCK>::BLOCK_THREADS;

    // Dynamic shared memory layout:
    //   [block-wide data tile][warp0 buf dist][warp1 buf dist]...[warpN buf dist]
    //   [warp0 buf idx ][warp1 buf idx ]...[warpN buf idx ]
    extern __shared__ __align__(16) unsigned char smem_raw[];
    float2* sh_data     = reinterpret_cast<float2*>(smem_raw);
    float*  sh_buf_dist = reinterpret_cast<float*>(sh_data + tile_points);
    int*    sh_buf_idx  = reinterpret_cast<int*>(sh_buf_dist + WARPS_PER_BLOCK * K);

    const int warp_id  = threadIdx.x >> 5;
    const int lane     = threadIdx.x & (kWarpSize - 1);
    const int query_id = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool valid_query = (query_id < query_count);

    float* warp_buf_dist = sh_buf_dist + warp_id * K;
    int*   warp_buf_idx  = sh_buf_idx  + warp_id * K;

    // Private top-k result kept in registers, distributed across the warp.
    float reg_dist[ITEMS_PER_THREAD];
    int   reg_idx[ITEMS_PER_THREAD];

#pragma unroll
    for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
        reg_dist[item] = CUDART_INF_F;
        reg_idx[item]  = kInvalidIndex;
    }

    float qx = 0.0f;
    float qy = 0.0f;

    if (valid_query) {
        float2 q = make_float2(0.0f, 0.0f);
        if (lane == 0) {
            q = query[query_id];
        }
        qx = __shfl_sync(kFullMask, q.x, 0);
        qy = __shfl_sync(kFullMask, q.y, 0);
    }

    // Warp-uniform candidate count. It is replicated in every lane because that is cheaper
    // than a shared scalar and avoids extra memory traffic.
    int   buf_count     = 0;
    float max_distance  = CUDART_INF_F;
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    for (int tile_base = 0; tile_base < data_count; tile_base += tile_points) {
        int tile_count = data_count - tile_base;
        if (tile_count > tile_points) {
            tile_count = tile_points;
        }

        // Whole block loads the current data tile into shared memory.
        for (int i = threadIdx.x; i < tile_count; i += BLOCK_THREADS) {
            sh_data[i] = data[tile_base + i];
        }

        __syncthreads();

        if (valid_query) {
            const int rounds = (tile_count + kWarpSize - 1) / kWarpSize;

#pragma unroll 1
            for (int round = 0; round < rounds; ++round) {
                const int local_data_idx = round * kWarpSize + lane;
                const bool active = (local_data_idx < tile_count);

                float dist = CUDART_INF_F;
                int   data_idx = tile_base + local_data_idx;

                if (active) {
                    const float2 p  = sh_data[local_data_idx];
                    const float  dx = qx - p.x;
                    const float  dy = qy - p.y;

                    // Squared Euclidean distance. A NaN can only arise from invalid input data;
                    // map it to +inf so that it naturally sinks to the end of the ordering.
                    dist = __fmaf_rn(dx, dx, dy * dy);
                    if (!(dist >= 0.0f)) {
                        dist = CUDART_INF_F;
                    }
                }

                bool keep = active && (dist < max_distance);
                unsigned mask = __ballot_sync(kFullMask, keep);
                int selected = __popc(mask);

                if (selected) {
                    // If the packed append would overflow the shared candidate buffer, merge the
                    // current buffer first and re-evaluate the current candidate against the new
                    // (usually tighter) max_distance.
                    if (buf_count + selected > K) {
                        flush_candidate_buffer<K, ITEMS_PER_THREAD>(
                            reg_dist, reg_idx, warp_buf_dist, warp_buf_idx, buf_count, max_distance, lane);

                        keep = active && (dist < max_distance);
                        mask = __ballot_sync(kFullMask, keep);
                        selected = __popc(mask);
                    }

                    if (selected) {
                        const int base = buf_count;
                        const int rank = __popc(mask & lane_mask_lt);

                        if (keep) {
                            warp_buf_dist[base + rank] = dist;
                            warp_buf_idx[base + rank]  = data_idx;
                        }

                        buf_count = base + selected;

                        if (buf_count == K) {
                            flush_candidate_buffer<K, ITEMS_PER_THREAD>(
                                reg_dist, reg_idx, warp_buf_dist, warp_buf_idx, buf_count, max_distance, lane);
                        }
                    }
                }
            }
        }

        // The data-tile region in shared memory is reused by the next iteration.
        __syncthreads();
    }

    if (valid_query) {
        if (buf_count) {
            flush_candidate_buffer<K, ITEMS_PER_THREAD>(
                reg_dist, reg_idx, warp_buf_dist, warp_buf_idx, buf_count, max_distance, lane);
        }

        std::pair<int, float>* out =
            result + static_cast<std::size_t>(query_id) * K + lane * ITEMS_PER_THREAD;

#pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            out[item].first  = reg_idx[item];
            out[item].second = reg_dist[item];
        }
    }
}

inline int query_threshold_for_warps_per_block(int sm_count, int warps_per_block) {
    // ceil(0.75 * sm_count * warps_per_block)
    return (3 * sm_count * warps_per_block + 3) / 4;
}

template <int K, int WARPS_PER_BLOCK>
bool try_launch_knn(const float2* query,
                    int query_count,
                    const float2* data,
                    int data_count,
                    std::pair<int, float>* result,
                    int max_shared_optin) {
    constexpr int BLOCK_THREADS = BlockConfig<WARPS_PER_BLOCK>::BLOCK_THREADS;
    constexpr int TILE_CAP      = BlockConfig<WARPS_PER_BLOCK>::TILE_CAP;

    const std::size_t fixed_bytes =
        static_cast<std::size_t>(WARPS_PER_BLOCK) * K * (sizeof(float) + sizeof(int));

    if (fixed_bytes >= static_cast<std::size_t>(max_shared_optin)) {
        return false;
    }

    const int max_tile_points =
        static_cast<int>((static_cast<std::size_t>(max_shared_optin) - fixed_bytes) / sizeof(float2));

    if (max_tile_points <= 0) {
        return false;
    }

    // tile_limit is the largest full-tile size this variant will ever ask for on this device.
    // The actual launch may use fewer points if data_count is smaller.
    int tile_limit = TILE_CAP;
    if (tile_limit > max_tile_points) {
        tile_limit = max_tile_points;
        if (tile_limit > BLOCK_THREADS) {
            tile_limit = (tile_limit / BLOCK_THREADS) * BLOCK_THREADS;
        }
    }

    if (tile_limit <= 0) {
        return false;
    }

    const int tile_points = std::min(tile_limit, data_count);
    const std::size_t max_dynamic_smem =
        fixed_bytes + static_cast<std::size_t>(tile_limit) * sizeof(float2);
    const std::size_t launch_dynamic_smem =
        fixed_bytes + static_cast<std::size_t>(tile_points) * sizeof(float2);

    // Allow >48 KB dynamic shared memory and bias the SM partition toward shared memory.
    if (cudaFuncSetAttribute(knn_kernel<K, WARPS_PER_BLOCK>,
                             cudaFuncAttributeMaxDynamicSharedMemorySize,
                             static_cast<int>(max_dynamic_smem)) != cudaSuccess) {
        return false;
    }

    (void)cudaFuncSetAttribute(knn_kernel<K, WARPS_PER_BLOCK>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               static_cast<int>(cudaSharedmemCarveoutMaxShared));

    const int grid_x = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    knn_kernel<K, WARPS_PER_BLOCK><<<grid_x, BLOCK_THREADS, launch_dynamic_smem>>>(
        query, query_count, data, data_count, result, tile_points);

    return true;
}

template <int K>
void launch_for_k(const float2* query,
                  int query_count,
                  const float2* data,
                  int data_count,
                  std::pair<int, float>* result) {
    // Conservative A100 defaults in case attribute queries fail; the actual device values are
    // used when available.
    int device            = 0;
    int sm_count          = 108;
    int max_shared_optin  = 163840;

    if (cudaGetDevice(&device) == cudaSuccess) {
        int value = 0;
        if (cudaDeviceGetAttribute(&value, cudaDevAttrMultiProcessorCount, device) == cudaSuccess) {
            sm_count = value;
        }
        if (cudaDeviceGetAttribute(&value, cudaDevAttrMaxSharedMemoryPerBlockOptin, device) == cudaSuccess) {
            max_shared_optin = value;
        }
    }

    // Prefer more reuse only when the resulting number of blocks is still large enough to
    // keep the GPU well occupied.
    if (query_count >= query_threshold_for_warps_per_block(sm_count, 16)) {
        if (try_launch_knn<K, 16>(query, query_count, data, data_count, result, max_shared_optin)) {
            return;
        }
        if (try_launch_knn<K, 8>(query, query_count, data, data_count, result, max_shared_optin)) {
            return;
        }
        (void)try_launch_knn<K, 4>(query, query_count, data, data_count, result, max_shared_optin);
        return;
    }

    if (query_count >= query_threshold_for_warps_per_block(sm_count, 8)) {
        if (try_launch_knn<K, 8>(query, query_count, data, data_count, result, max_shared_optin)) {
            return;
        }
        (void)try_launch_knn<K, 4>(query, query_count, data, data_count, result, max_shared_optin);
        return;
    }

    (void)try_launch_knn<K, 4>(query, query_count, data, data_count, result, max_shared_optin);
}

}  // namespace

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            launch_for_k<32>(query, query_count, data, data_count, result);
            return;
        case 64:
            launch_for_k<64>(query, query_count, data, data_count, result);
            return;
        case 128:
            launch_for_k<128>(query, query_count, data, data_count, result);
            return;
        case 256:
            launch_for_k<256>(query, query_count, data, data_count, result);
            return;
        case 512:
            launch_for_k<512>(query, query_count, data, data_count, result);
            return;
        case 1024:
            launch_for_k<1024>(query, query_count, data, data_count, result);
            return;
        default:
            // Inputs are documented to be valid, so this path is only a defensive no-op.
            return;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace knn_internal {

// NVIDIA warps are 32 lanes wide on all supported architectures.
constexpr int WARP_SIZE = 32;
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;
constexpr int INVALID_INDEX = -1;

// Tuned for modern data-center GPUs:
// - 128-thread blocks use a 1024-point batch so that even k=1024 keeps the
//   worst-case shared-memory footprint low enough for high residency.
// - 256/512-thread blocks use a 2048-point batch because their occupancy is
//   already limited by block size/shared memory on A100/H100, so a larger batch
//   reduces barrier overhead without hurting the intended occupancy target.
constexpr int THREADS_SMALL = 128;
constexpr int THREADS_MEDIUM = 256;
constexpr int THREADS_LARGE = 512;

constexpr int BATCH_SMALL = 1024;
constexpr int BATCH_LARGE = 2048;

template <int K, int THREADS_PER_BLOCK, int BATCH_POINTS>
struct KernelConfig {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0),
                  "k must be a power of two in [32, 1024].");
    static_assert((THREADS_PER_BLOCK % WARP_SIZE) == 0,
                  "Block size must be a multiple of 32.");
    static_assert((BATCH_POINTS % WARP_SIZE) == 0,
                  "Batch size must be a multiple of 32.");
    static_assert((BATCH_POINTS % THREADS_PER_BLOCK) == 0,
                  "This implementation assumes an integer number of shared-memory loads per thread.");

    static constexpr int kWarpsPerBlock = THREADS_PER_BLOCK / WARP_SIZE;
    static constexpr int kItemsPerThread = K / WARP_SIZE;
    static constexpr int kLoadsPerThread = BATCH_POINTS / THREADS_PER_BLOCK;

    // Two float arrays are used for the shared-memory batch cache (SoA layout)
    // to avoid the 2-way bank conflicts that a float2 AoS layout would create.
    static constexpr std::size_t kBatchSharedBytes =
        static_cast<std::size_t>(BATCH_POINTS) * 2 * sizeof(float);

    // Each warp owns a private candidate buffer in shared memory:
    //   K distances + K indices.
    static constexpr std::size_t kDynamicSharedBytes =
        static_cast<std::size_t>(kWarpsPerBlock) * K * (sizeof(float) + sizeof(int));

    static constexpr std::size_t kTotalSharedBytes =
        kBatchSharedBytes + kDynamicSharedBytes;
};

// Warp-local bitonic sort over K elements distributed across the warp.
// Lane L stores K/32 consecutive elements.
// - If the comparator pair stays within a lane, we swap register values directly.
// - Otherwise, the two compared elements are at the same register index in two
//   different lanes, so we exchange them with shfl_xor.
template <int K>
__device__ __forceinline__ void bitonic_sort_warp(
    float (&dist)[K / WARP_SIZE],
    int (&idx)[K / WARP_SIZE]) {
    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;

    const int lane = static_cast<int>(threadIdx.x) & (WARP_SIZE - 1);
    const int lane_base = lane * ITEMS_PER_THREAD;

    // Ties are intentionally left unspecified as permitted by the interface.
    #pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            if (stride < ITEMS_PER_THREAD) {
                // Intra-lane comparators: swap directly in registers.
                #pragma unroll
                for (int r = 0; r < ITEMS_PER_THREAD; ++r) {
                    const int partner = r ^ stride;
                    if (partner > r) {
                        const int global_i = lane_base + r;
                        const bool ascending = ((global_i & size) == 0);

                        const float a_dist = dist[r];
                        const float b_dist = dist[partner];

                        if ((ascending && (a_dist > b_dist)) ||
                            (!ascending && (a_dist < b_dist))) {
                            dist[r] = b_dist;
                            dist[partner] = a_dist;

                            const int a_idx = idx[r];
                            idx[r] = idx[partner];
                            idx[partner] = a_idx;
                        }
                    }
                }
            } else {
                // Inter-lane comparators: exchange the same register slot
                // between the two partner lanes.
                const int lane_xor = stride / ITEMS_PER_THREAD;

                #pragma unroll
                for (int r = 0; r < ITEMS_PER_THREAD; ++r) {
                    const float other_dist = __shfl_xor_sync(FULL_MASK, dist[r], lane_xor);
                    const int other_idx = __shfl_xor_sync(FULL_MASK, idx[r], lane_xor);

                    const int global_i = lane_base + r;
                    const bool ascending = ((global_i & size) == 0);
                    const bool lower_half = ((global_i & stride) == 0);
                    const bool keep_min = (ascending == lower_half);

                    if (keep_min) {
                        if (other_dist < dist[r]) {
                            dist[r] = other_dist;
                            idx[r] = other_idx;
                        }
                    } else {
                        if (dist[r] < other_dist) {
                            dist[r] = other_dist;
                            idx[r] = other_idx;
                        }
                    }
                }
            }
        }
    }
}

// Flush/merge path requested by the problem statement:
// 1. Swap the shared-memory candidate buffer with the register-resident result
//    so that the buffer is now in registers.
// 2. Bitonic-sort the buffer in ascending order.
// 3. Merge it with the previous intermediate result (now in shared memory) via
//    elementwise min(buffer[i], old_result[K-1-i]), producing a bitonic
//    sequence containing the smallest K elements.
// 4. Bitonic-sort again to restore the ascending top-k invariant.
template <int K>
__device__ __forceinline__ void merge_buffer_into_result(
    float* cand_dist_warp,
    int* cand_idx_warp,
    int& buffer_count,
    float (&result_dist)[K / WARP_SIZE],
    int (&result_idx)[K / WARP_SIZE],
    float& max_distance) {
    if (buffer_count == 0) {
        return;
    }

    constexpr int ITEMS_PER_THREAD = K / WARP_SIZE;

    const int lane = static_cast<int>(threadIdx.x) & (WARP_SIZE - 1);
    const int lane_base = lane * ITEMS_PER_THREAD;

    // Ensure all prior candidate-buffer writes performed by the warp are visible
    // before the buffer is read back.
    __syncwarp(FULL_MASK);

    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
        const int pos = lane_base + i;

        const float candidate_dist = (pos < buffer_count) ? cand_dist_warp[pos] : CUDART_INF_F;
        const int candidate_idx = (pos < buffer_count) ? cand_idx_warp[pos] : INVALID_INDEX;

        cand_dist_warp[pos] = result_dist[i];
        cand_idx_warp[pos] = result_idx[i];

        result_dist[i] = candidate_dist;
        result_idx[i] = candidate_idx;
    }

    // Shared memory now contains the old sorted intermediate result.
    __syncwarp(FULL_MASK);

    bitonic_sort_warp<K>(result_dist, result_idx);

    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
        const int pos = lane_base + i;
        const int rev = K - 1 - pos;

        const float other_dist = cand_dist_warp[rev];
        if (other_dist < result_dist[i]) {
            result_dist[i] = other_dist;
            result_idx[i] = cand_idx_warp[rev];
        }
    }

    bitonic_sort_warp<K>(result_dist, result_idx);

    // The result is sorted ascending, so the K-th nearest neighbor is the last
    // globally stored element, owned by lane 31.
    const float lane_last =
        (lane == (WARP_SIZE - 1)) ? result_dist[ITEMS_PER_THREAD - 1] : 0.0f;
    max_distance = __shfl_sync(FULL_MASK, lane_last, WARP_SIZE - 1);

    buffer_count = 0;
}

template <int K, int THREADS_PER_BLOCK, int BATCH_POINTS>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result) {
    using Config = KernelConfig<K, THREADS_PER_BLOCK, BATCH_POINTS>;
    constexpr int WARPS_PER_BLOCK = Config::kWarpsPerBlock;
    constexpr int ITEMS_PER_THREAD = Config::kItemsPerThread;
    constexpr int LOADS_PER_THREAD = Config::kLoadsPerThread;

    const int tid = static_cast<int>(threadIdx.x);
    const int lane = tid & (WARP_SIZE - 1);
    const int warp_id = tid >> 5;

    const int query_idx = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active = (query_idx < query_count);

    // Shared-memory batch cache in SoA form to avoid shared-memory bank conflicts
    // when an entire warp reads x/y for consecutive points.
    __shared__ float s_batch_x[BATCH_POINTS];
    __shared__ float s_batch_y[BATCH_POINTS];

    // Dynamic shared memory holds only the per-warp candidate buffers:
    // [warps * K distances][warps * K indices]
    extern __shared__ unsigned int s_dyn[];
    float* const cand_dist = reinterpret_cast<float*>(s_dyn);
    int* const cand_idx =
        reinterpret_cast<int*>(cand_dist + WARPS_PER_BLOCK * K);

    float* const cand_dist_warp = cand_dist + warp_id * K;
    int* const cand_idx_warp = cand_idx + warp_id * K;

    // Register-resident intermediate top-k, distributed across the warp.
    float result_dist[ITEMS_PER_THREAD];
    int result_idx[ITEMS_PER_THREAD];

    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
        result_dist[i] = CUDART_INF_F;
        result_idx[i] = INVALID_INDEX;
    }

    int buffer_count = 0;
    float max_distance = CUDART_INF_F;

    // Load the query point once per warp and broadcast from lane 0.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active) {
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(FULL_MASK, qx, 0);
        qy = __shfl_sync(FULL_MASK, qy, 0);
    }

    // Scan the data set in shared-memory-backed batches.
    for (int batch_start = 0; batch_start < data_count; batch_start += BATCH_POINTS) {
        int valid_batch = data_count - batch_start;
        if (valid_batch > BATCH_POINTS) {
            valid_batch = BATCH_POINTS;
        }

        // Whole-block cooperative load into shared memory.
        #pragma unroll
        for (int it = 0; it < LOADS_PER_THREAD; ++it) {
            const int batch_pos = tid + it * THREADS_PER_BLOCK;
            if (batch_pos < valid_batch) {
                const float2 p = data[batch_start + batch_pos];
                s_batch_x[batch_pos] = p.x;
                s_batch_y[batch_pos] = p.y;
            }
        }

        __syncthreads();

        if (active) {
            // Process the shared-memory batch in warp-sized chunks so that every
            // lane computes one distance and ballot-compacts the accepted points.
            for (int chunk_base = 0; chunk_base < valid_batch; chunk_base += WARP_SIZE) {
                // The ballot can contribute at most 32 new candidates, so flush
                // early whenever fewer than 32 slots remain.
                if (buffer_count > (K - WARP_SIZE)) {
                    merge_buffer_into_result<K>(
                        cand_dist_warp, cand_idx_warp,
                        buffer_count, result_dist, result_idx, max_distance);
                }

                const int point_in_batch = chunk_base + lane;

                float dist = CUDART_INF_F;
                int data_index = INVALID_INDEX;
                bool keep = false;

                if (point_in_batch < valid_batch) {
                    data_index = batch_start + point_in_batch;
                    const float dx = qx - s_batch_x[point_in_batch];
                    const float dy = qy - s_batch_y[point_in_batch];
                    dist = fmaf(dx, dx, dy * dy);
                    keep = (dist < max_distance);
                }

                const unsigned keep_mask = __ballot_sync(FULL_MASK, keep);
                const int new_candidates = __popc(keep_mask);
                const int base = buffer_count;

                // Rank within the compacted ballot output.
                const unsigned lower_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
                const int rank = __popc(keep_mask & lower_mask);

                if (keep) {
                    const int pos = base + rank;
                    cand_dist_warp[pos] = dist;
                    cand_idx_warp[pos] = data_index;
                }

                buffer_count = base + new_candidates;

                if (buffer_count == K) {
                    merge_buffer_into_result<K>(
                        cand_dist_warp, cand_idx_warp,
                        buffer_count, result_dist, result_idx, max_distance);
                }
            }
        }

        __syncthreads();
    }

    if (active) {
        if (buffer_count > 0) {
            merge_buffer_into_result<K>(
                cand_dist_warp, cand_idx_warp,
                buffer_count, result_dist, result_idx, max_distance);
        }

        // Write back the final sorted top-k.
        const int lane_base = lane * ITEMS_PER_THREAD;
        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K) +
            static_cast<std::size_t>(lane_base);

        #pragma unroll
        for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
            result[out_base + i].first = result_idx[i];
            result[out_base + i].second = result_dist[i];
        }
    }
}

template <int K, int THREADS_PER_BLOCK, int BATCH_POINTS>
inline void launch_knn_specialized(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result) {
    using Config = KernelConfig<K, THREADS_PER_BLOCK, BATCH_POINTS>;
    constexpr int QUERIES_PER_BLOCK = Config::kWarpsPerBlock;

    const int blocks = (query_count + QUERIES_PER_BLOCK - 1) / QUERIES_PER_BLOCK;

    // Request the shared-memory carveout needed by the large-k specializations.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, THREADS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(Config::kDynamicSharedBytes));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, THREADS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);
    (void)cudaFuncSetCacheConfig(
        knn_kernel<K, THREADS_PER_BLOCK, BATCH_POINTS>,
        cudaFuncCachePreferShared);

    knn_kernel<K, THREADS_PER_BLOCK, BATCH_POINTS>
        <<<blocks, THREADS_PER_BLOCK, Config::kDynamicSharedBytes>>>(
            query, query_count, data, data_count, result);
}

template <int K>
inline void launch_knn_autotuned(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result) {
    int device = 0;
    int sm_count = 1;
    int max_optin_shared = 48 * 1024;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaDeviceGetAttribute(
        &max_optin_shared, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    if (sm_count <= 0) {
        sm_count = 1;
    }
    if (max_optin_shared <= 0) {
        max_optin_shared = 48 * 1024;
    }

    const std::size_t max_shared =
        static_cast<std::size_t>(max_optin_shared);

    constexpr std::size_t shared_small =
        KernelConfig<K, THREADS_SMALL, BATCH_SMALL>::kTotalSharedBytes;
    constexpr std::size_t shared_medium =
        KernelConfig<K, THREADS_MEDIUM, BATCH_LARGE>::kTotalSharedBytes;
    constexpr std::size_t shared_large =
        KernelConfig<K, THREADS_LARGE, BATCH_LARGE>::kTotalSharedBytes;

    const bool fit_small = (shared_small <= max_shared);
    const bool fit_medium = (shared_medium <= max_shared);
    const bool fit_large = (shared_large <= max_shared);

    // Heuristic:
    // - Larger blocks reuse every loaded data batch across more queries.
    // - Smaller blocks increase grid granularity when query_count is modest.
    // Use the largest tile that still gives roughly >= 75% SM coverage.
    const int threshold_large =
        (sm_count * (THREADS_LARGE / WARP_SIZE) * 3 + 3) / 4;
    const int threshold_medium =
        (sm_count * (THREADS_MEDIUM / WARP_SIZE) * 3 + 3) / 4;

    if (fit_large && query_count >= threshold_large) {
        launch_knn_specialized<K, THREADS_LARGE, BATCH_LARGE>(
            query, query_count, data, data_count, result);
    } else if (fit_medium && query_count >= threshold_medium) {
        launch_knn_specialized<K, THREADS_MEDIUM, BATCH_LARGE>(
            query, query_count, data, data_count, result);
    } else if (fit_small) {
        launch_knn_specialized<K, THREADS_SMALL, BATCH_SMALL>(
            query, query_count, data, data_count, result);
    } else if (fit_medium) {
        launch_knn_specialized<K, THREADS_MEDIUM, BATCH_LARGE>(
            query, query_count, data, data_count, result);
    } else {
        // This fallback should never be taken on the target A100/H100-class GPUs,
        // but 128 threads is the lowest shared-memory footprint among the tuned variants.
        launch_knn_specialized<K, THREADS_SMALL, BATCH_SMALL>(
            query, query_count, data, data_count, result);
    }
}

}  // namespace knn_internal

void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn_internal::launch_knn_autotuned<32>(
                query, query_count, data, data_count, result);
            break;
        case 64:
            knn_internal::launch_knn_autotuned<64>(
                query, query_count, data, data_count, result);
            break;
        case 128:
            knn_internal::launch_knn_autotuned<128>(
                query, query_count, data, data_count, result);
            break;
        case 256:
            knn_internal::launch_knn_autotuned<256>(
                query, query_count, data, data_count, result);
            break;
        case 512:
            knn_internal::launch_knn_autotuned<512>(
                query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_internal::launch_knn_autotuned<1024>(
                query, query_count, data, data_count, result);
            break;
        default:
            // Input validity guarantees that this path is unreachable.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace {

// Fixed hardware-oriented tuning:
// - 256 threads/block => 8 warps/block => 8 queries/block.
//   This is a good balance between occupancy and shared-memory data reuse.
// - 1792 cached data points/block (7 float2 loads/thread) is intentionally close
//   to the largest tile that still allows two resident worst-case blocks/SM on
//   A100-class parts when K=1024 and each warp owns a K-entry shared buffer.
constexpr int kWarpSize       = 32;
constexpr int kBlockThreads   = 256;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr int kDataTilePoints = 1792;
constexpr unsigned kFullMask  = 0xffffffffu;

static_assert(kBlockThreads % kWarpSize == 0, "block size must be a multiple of warp size");
static_assert(kDataTilePoints % kBlockThreads == 0, "tile size chosen for exact cooperative loads");
static_assert(kDataTilePoints % kWarpSize == 0, "tile size chosen for exact warp-sized processing groups");

// Shared-memory candidate record.
// Distance is stored first because it is the hot comparison key.
// The record is 8 bytes and naturally maps well to shared-memory transactions.
struct alignas(8) Candidate {
    float distance;
    int   index;
};

static_assert(sizeof(Candidate) == 8, "Candidate must stay compact");

// Small helper used by the local (in-thread) stages of bitonic sort.
__device__ __forceinline__
void swap_pair(float &a_dist, int &a_idx, float &b_dist, int &b_idx) {
    const float td = a_dist;
    a_dist = b_dist;
    b_dist = td;

    const int ti = a_idx;
    a_idx = b_idx;
    b_idx = ti;
}

__device__ __forceinline__
void maybe_swap_pair(float &a_dist, int &a_idx, float &b_dist, int &b_idx, bool ascending) {
    // Ties are intentionally left unresolved in any particular way.
    const bool do_swap = ascending ? (b_dist < a_dist) : (b_dist > a_dist);
    if (do_swap) {
        swap_pair(a_dist, a_idx, b_dist, b_idx);
    }
}

// Warp-wide bitonic sort over K elements distributed as consecutive chunks:
// lane t owns positions [t * (K/32), ..., t * (K/32) + (K/32 - 1)].
//
// Because K and K/32 are powers of two, every cross-thread compare-exchange
// always targets the same register slot index in the partner lane. This is
// exactly the layout requested in the problem statement.
template <int K>
__device__ __forceinline__
void bitonic_sort_warp(float (&dist)[K / kWarpSize], int (&index)[K / kWarpSize]) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024]");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size");

    constexpr int kItemsPerThread = K / kWarpSize;

    const int lane        = threadIdx.x & (kWarpSize - 1);
    const int thread_base = lane * kItemsPerThread;

    // Standard bitonic sort network.
    #pragma unroll
    for (int stage_size = 2; stage_size <= K; stage_size <<= 1) {
        #pragma unroll
        for (int stride = stage_size >> 1; stride > 0; stride >>= 1) {
            if (stride < kItemsPerThread) {
                // Intra-thread compare/swap: both elements are in the same lane's registers.
                #pragma unroll
                for (int r = 0; r < kItemsPerThread; ++r) {
                    const int partner_r = r ^ stride;
                    if (partner_r > r) {
                        const bool ascending = (((thread_base + r) & stage_size) == 0);
                        maybe_swap_pair(dist[r], index[r], dist[partner_r], index[partner_r], ascending);
                    }
                }
            } else {
                // Inter-thread compare/exchange: partner lives in another lane, same register slot.
                const int partner_lane_delta = stride / kItemsPerThread;

                #pragma unroll
                for (int r = 0; r < kItemsPerThread; ++r) {
                    const float other_dist = __shfl_xor_sync(kFullMask, dist[r],  partner_lane_delta);
                    const int   other_idx  = __shfl_xor_sync(kFullMask, index[r], partner_lane_delta);

                    const int  i         = thread_base + r;
                    const bool ascending = ((i & stage_size) == 0);
                    const bool lower     = ((i & stride) == 0);
                    const bool keep_min  = (lower == ascending);

                    const bool take_other = keep_min ? (other_dist < dist[r]) : (other_dist > dist[r]);
                    if (take_other) {
                        dist[r]  = other_dist;
                        index[r] = other_idx;
                    }
                }
            }

            // Keep explicit warp-stage boundaries around the network steps.
            __syncwarp();
        }
    }
}

// max_distance is the current pruning threshold, i.e. the distance of the
// current k-th nearest neighbor.
template <int K>
__device__ __forceinline__
void update_max_distance(const float (&best_dist)[K / kWarpSize], float &max_distance) {
    constexpr int kItemsPerThread = K / kWarpSize;

    float tail = CUDART_INF_F;
    if ((threadIdx.x & (kWarpSize - 1)) == (kWarpSize - 1)) {
        tail = best_dist[kItemsPerThread - 1];
    }
    max_distance = __shfl_sync(kFullMask, tail, kWarpSize - 1);
}

// Merge the shared-memory candidate buffer into the register-resident
// intermediate top-K, exactly following the requested sequence:
//
// 0. Invariant: intermediate result in registers is sorted ascending.
// 1. Swap buffer and intermediate result so the buffer is in registers.
// 2. Sort the register-resident buffer ascending with bitonic sort.
// 3. Build a bitonic sequence by taking min(buffer[i], intermediate[K-1-i]).
// 4. Bitonic-sort that sequence ascending to obtain the updated top-K.
template <int K>
__device__ __forceinline__
void merge_buffer_into_best(float (&best_dist)[K / kWarpSize],
                            int (&best_index)[K / kWarpSize],
                            Candidate *warp_buffer,
                            int buf_count,
                            float &max_distance) {
    constexpr int kItemsPerThread = K / kWarpSize;

    const int lane        = threadIdx.x & (kWarpSize - 1);
    const int thread_base = lane * kItemsPerThread;

    // Step 1: swap shared buffer <-> register-resident intermediate result.
    #pragma unroll
    for (int r = 0; r < kItemsPerThread; ++r) {
        const int pos = thread_base + r;

        Candidate buffered;
        if (pos < buf_count) {
            buffered = warp_buffer[pos];
        } else {
            buffered.distance = CUDART_INF_F;
            buffered.index    = -1;
        }

        warp_buffer[pos] = Candidate{best_dist[r], best_index[r]};

        best_dist[r]  = buffered.distance;
        best_index[r] = buffered.index;
    }
    __syncwarp();

    // Step 2: sort the buffer now living in registers.
    bitonic_sort_warp<K>(best_dist, best_index);

    // Step 3: bitonic merge construction.
    // warp_buffer currently stores the old intermediate result in ascending order.
    #pragma unroll
    for (int r = 0; r < kItemsPerThread; ++r) {
        const int pos = thread_base + r;
        const Candidate other = warp_buffer[K - 1 - pos];

        if (other.distance < best_dist[r]) {
            best_dist[r]  = other.distance;
            best_index[r] = other.index;
        }
    }
    __syncwarp();

    // Step 4: sort the resulting bitonic sequence to obtain the updated top-K.
    bitonic_sort_warp<K>(best_dist, best_index);

    // Update pruning threshold.
    update_max_distance<K>(best_dist, max_distance);
}

// Flush a warp-local shared candidate buffer into the register-resident top-K.
template <int K>
__device__ __forceinline__
void flush_buffer(float (&best_dist)[K / kWarpSize],
                  int (&best_index)[K / kWarpSize],
                  Candidate *warp_buffer,
                  int &buf_count,
                  volatile int *warp_count_ptr,
                  float &max_distance) {
    if (buf_count == 0) {
        return;
    }

    // Ensure all prior shared-memory candidate stores are visible to the warp.
    __syncwarp();

    merge_buffer_into_best<K>(best_dist, best_index, warp_buffer, buf_count, max_distance);

    buf_count = 0;
    if ((threadIdx.x & (kWarpSize - 1)) == 0) {
        *warp_count_ptr = 0;
    }

    __syncwarp();
}

template <int K>
__global__ __launch_bounds__(kBlockThreads, 2)
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                std::pair<int, float> * __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && ((K & (K - 1)) == 0), "K must be a power of two in [32, 1024]");

    constexpr int kItemsPerThread = K / kWarpSize;
    constexpr int kLoadsPerThread = kDataTilePoints / kBlockThreads;

    extern __shared__ unsigned char shared_raw[];

    // Shared-memory layout:
    // [data tile][warp0 buffer][warp1 buffer]...[warpN buffer][warp candidate counts]
    float2 *data_tile = reinterpret_cast<float2 *>(shared_raw);
    Candidate *candidate_buffers =
        reinterpret_cast<Candidate *>(data_tile + kDataTilePoints);
    volatile int *candidate_counts =
        reinterpret_cast<volatile int *>(candidate_buffers + kWarpsPerBlock * K);

    const int tid     = threadIdx.x;
    const int lane    = tid & (kWarpSize - 1);
    const int warp_id = tid >> 5;

    const int query_idx    = static_cast<int>(blockIdx.x) * kWarpsPerBlock + warp_id;
    const bool active_warp = (query_idx < query_count);

    Candidate *warp_buffer      = candidate_buffers + warp_id * K;
    volatile int *warp_count_ptr = candidate_counts + warp_id;

    // Each warp owns one shared counter for its candidate buffer.
    if (lane == 0) {
        *warp_count_ptr = 0;
    }
    __syncwarp();

    // Register-resident intermediate result: each lane stores K/32 consecutive items.
    float best_dist[kItemsPerThread];
    int   best_index[kItemsPerThread];

    #pragma unroll
    for (int r = 0; r < kItemsPerThread; ++r) {
        best_dist[r]  = CUDART_INF_F;
        best_index[r] = -1;
    }

    float max_distance = CUDART_INF_F;
    int   buf_count    = 0;

    // Load the query point once per warp and broadcast from lane 0.
    float qx = 0.0f;
    float qy = 0.0f;
    if (lane == 0 && active_warp) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Prefix mask used to map ballot hits to compact positions in the shared buffer.
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    // Process the database in shared-memory tiles.
    for (int tile_base = 0; tile_base < data_count; tile_base += kDataTilePoints) {
        int tile_count = data_count - tile_base;
        if (tile_count > kDataTilePoints) {
            tile_count = kDataTilePoints;
        }

        // Cooperative block load of the current data tile.
        #pragma unroll
        for (int i = 0; i < kLoadsPerThread; ++i) {
            const int local = tid + i * kBlockThreads;
            if (local < tile_count) {
                data_tile[local] = data[tile_base + local];
            }
        }

        __syncthreads();

        if (active_warp) {
            // Iterate over the cached tile in warp-sized groups so that every lane
            // participates in every ballot, even for the final partial group.
            for (int group_base = 0; group_base < tile_count; group_base += kWarpSize) {
                const int local = group_base + lane;

                float dist = CUDART_INF_F;
                int   idx  = -1;
                bool  pred = false;

                if (local < tile_count) {
                    const float2 p = data_tile[local];

                    const float dx = qx - p.x;
                    const float dy = qy - p.y;

                    // Squared Euclidean distance; no sqrt, exactly as requested.
                    dist = fmaf(dx, dx, dy * dy);
                    idx  = tile_base + local;
                    pred = (dist < max_distance);
                }

                const unsigned hit_mask = __ballot_sync(kFullMask, pred);

                if (hit_mask != 0u) {
                    const int hits = __popc(hit_mask);
                    const int rank = __popc(hit_mask & lane_mask_lt);
                    const int space = K - buf_count;

                    if (hits <= space) {
                        // Everything fits into the current shared candidate buffer.
                        if (pred) {
                            warp_buffer[buf_count + rank] = Candidate{dist, idx};
                        }

                        __syncwarp();

                        buf_count += hits;
                        if (lane == 0) {
                            *warp_count_ptr = buf_count;
                        }

                        // Merge immediately when the buffer becomes full.
                        if (buf_count == K) {
                            flush_buffer<K>(best_dist, best_index, warp_buffer, buf_count, warp_count_ptr, max_distance);
                        }
                    } else {
                        // The incoming hit set would overflow the buffer.
                        // Fill the remaining space, merge, then append the leftovers
                        // to the now-empty buffer.
                        if (pred && rank < space) {
                            warp_buffer[buf_count + rank] = Candidate{dist, idx};
                        }

                        __syncwarp();

                        buf_count = K;
                        if (lane == 0) {
                            *warp_count_ptr = K;
                        }

                        flush_buffer<K>(best_dist, best_index, warp_buffer, buf_count, warp_count_ptr, max_distance);

                        if (pred && rank >= space) {
                            warp_buffer[rank - space] = Candidate{dist, idx};
                        }

                        __syncwarp();

                        buf_count = hits - space;
                        if (lane == 0) {
                            *warp_count_ptr = buf_count;
                        }

                        // This second immediate flush is only needed for the degenerate
                        // K=32 case when the leftover set also fills the buffer.
                        if (buf_count == K) {
                            flush_buffer<K>(best_dist, best_index, warp_buffer, buf_count, warp_count_ptr, max_distance);
                        }
                    }
                }
            }
        }

        // The next tile overwrites data_tile, so all warps in the block must finish.
        __syncthreads();
    }

    if (active_warp) {
        // Final partial-buffer merge, if any candidates remain.
        flush_buffer<K>(best_dist, best_index, warp_buffer, buf_count, warp_count_ptr, max_distance);

        // Write the sorted top-K result. The output distance remains squared L2.
        const int out_base = query_idx * K + lane * kItemsPerThread;

        #pragma unroll
        for (int r = 0; r < kItemsPerThread; ++r) {
            result[out_base + r].first  = best_index[r];
            result[out_base + r].second = best_dist[r];
        }
    }
}

template <int K>
constexpr std::size_t shared_memory_bytes() {
    return static_cast<std::size_t>(kDataTilePoints) * sizeof(float2) +
           static_cast<std::size_t>(kWarpsPerBlock)  * K * sizeof(Candidate) +
           static_cast<std::size_t>(kWarpsPerBlock)  * sizeof(int);
}

template <int K>
inline void launch_knn_kernel(const float2 *query,
                              int query_count,
                              const float2 *data,
                              int data_count,
                              std::pair<int, float> *result) {
    constexpr std::size_t smem_bytes = shared_memory_bytes<K>();

    // The interface returns void, so configuration calls are intentionally fire-and-forget.
    // The target devices in the problem statement support this dynamic shared-memory size.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    knn_kernel<K><<<grid, block, smem_bytes>>>(query, query_count, data, data_count, result);
}

} // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // Launch is intentionally asynchronous; callers can synchronize externally if needed.
    switch (k) {
        case 32:   launch_knn_kernel<32>(query, query_count, data, data_count, result);   break;
        case 64:   launch_knn_kernel<64>(query, query_count, data, data_count, result);   break;
        case 128:  launch_knn_kernel<128>(query, query_count, data, data_count, result);  break;
        case 256:  launch_knn_kernel<256>(query, query_count, data, data_count, result);  break;
        case 512:  launch_knn_kernel<512>(query, query_count, data, data_count, result);  break;
        case 1024: launch_knn_kernel<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Unreachable for valid inputs.
    }
}

