namespace knn_detail {

// Warp-per-query k-NN for 2D points with squared Euclidean distance.
//
// Tuning choices:
// - 256 threads/block = 8 warps/block = 8 queries/block.
// - 2048 staged data points per batch.
//   For the worst supported case K=1024, dynamic shared memory is
//   2048*sizeof(float2) + 8*1024*(sizeof(float)+sizeof(int)) + 8*sizeof(int)
//   = 81,952 bytes, which fits the intended A100/H100 target while still
//   allowing two resident blocks/SM in the common configuration.
//
// The algorithm follows the requested structure exactly:
// - one warp computes one query;
// - the current top-k is kept distributed in registers, with each thread owning
//   K/32 consecutive entries;
// - each warp has a shared-memory candidate buffer of size K (indices+distances);
// - block-wide batches of data points are cached in shared memory;
// - candidates are collected with warp ballots;
// - whenever the candidate buffer is full, it is merged into the register top-k
//   via: swap -> bitonic sort -> bitonic merge -> bitonic sort.
//
// No auxiliary device memory is allocated; shared memory is reused both for the
// staged data batch and for the per-warp candidate buffers.

constexpr unsigned FULL_MASK      = 0xffffffffu;
constexpr int      WARP_SIZE      = 32;
constexpr int      LAST_LANE      = WARP_SIZE - 1;
constexpr int      BLOCK_THREADS  = 256;
constexpr int      WARPS_PER_BLOCK = BLOCK_THREADS / WARP_SIZE;
constexpr int      BATCH_POINTS   = 2048;
constexpr int      LOAD_ITERS     = BATCH_POINTS / BLOCK_THREADS;
constexpr int      INVALID_INDEX  = -1;

static_assert(BLOCK_THREADS % WARP_SIZE == 0, "BLOCK_THREADS must be a multiple of 32.");
static_assert(BATCH_POINTS % WARP_SIZE == 0, "BATCH_POINTS must be a multiple of 32.");
static_assert(BATCH_POINTS % BLOCK_THREADS == 0, "BATCH_POINTS must be divisible by BLOCK_THREADS.");

template <int K>
constexpr size_t shared_bytes() {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "K must be a power of two in [32, 1024].");
    return sizeof(float2) * BATCH_POINTS
         + sizeof(float)  * WARPS_PER_BLOCK * K
         + sizeof(int)    * WARPS_PER_BLOCK * K
         + sizeof(int)    * WARPS_PER_BLOCK;
}

// Invalid placeholders use index = -1.
// When distances tie, valid entries must rank before placeholders; otherwise a
// real +inf distance could incorrectly lose to a sentinel +inf.
__device__ __forceinline__ bool pair_less(const float da, const int ia,
                                          const float db, const int ib) {
    if (da < db) return true;
    if (da > db) return false;

    const bool a_valid = (ia >= 0);
    const bool b_valid = (ib >= 0);
    if (a_valid != b_valid) return a_valid;  // valid < invalid

    return ia < ib;
}

__device__ __forceinline__ bool pair_greater(const float da, const int ia,
                                             const float db, const int ib) {
    return pair_less(db, ib, da, ia);
}

__device__ __forceinline__ void swap_pair(float &da, int &ia, float &db, int &ib) {
    const float td = da;
    da = db;
    db = td;

    const int ti = ia;
    ia = ib;
    ib = ti;
}

// Distributed bitonic sort over K elements stored as K/32 consecutive registers
// per thread. For strides smaller than K/32, both elements of a compare-swap
// pair live in the same thread and are swapped locally. For larger strides, the
// partner lives in another lane, and the exchange uses warp shuffles. Because
// the distribution is by consecutive chunks, cross-lane exchanges always touch
// the same register index within each lane.
template <int K>
__device__ __forceinline__ void bitonic_sort_warp(float (&dist)[K / WARP_SIZE],
                                                  int   (&idx )[K / WARP_SIZE],
                                                  const int lane) {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "Invalid K.");
    constexpr int REGS_PER_THREAD = K / WARP_SIZE;
    const int lane_base = lane * REGS_PER_THREAD;

    #pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            if constexpr (REGS_PER_THREAD > 1) {
                if (stride < REGS_PER_THREAD) {
                    #pragma unroll
                    for (int r = 0; r < REGS_PER_THREAD; ++r) {
                        const int rp = r ^ stride;
                        if (rp > r) {
                            const int  i         = lane_base + r;
                            const bool ascending = ((i & size) == 0);
                            const bool do_swap   = ascending
                                ? pair_greater(dist[r], idx[r], dist[rp], idx[rp])
                                : pair_less   (dist[r], idx[r], dist[rp], idx[rp]);

                            if (do_swap) {
                                swap_pair(dist[r], idx[r], dist[rp], idx[rp]);
                            }
                        }
                    }
                    continue;
                }
            }

            const int lane_mask = stride / REGS_PER_THREAD;

            #pragma unroll
            for (int r = 0; r < REGS_PER_THREAD; ++r) {
                const float other_d = __shfl_xor_sync(FULL_MASK, dist[r], lane_mask);
                const int   other_i = __shfl_xor_sync(FULL_MASK, idx [r], lane_mask);

                const int  i         = lane_base + r;
                const bool ascending = ((i & size) == 0);
                const bool lower     = ((lane & lane_mask) == 0);
                const bool keep_min  = (ascending == lower);

                const bool take_other = keep_min
                    ? pair_greater(dist[r], idx[r], other_d, other_i)
                    : pair_less   (dist[r], idx[r], other_d, other_i);

                if (take_other) {
                    dist[r] = other_d;
                    idx [r] = other_i;
                }
            }
        }
    }
}

// Merge the shared-memory candidate buffer into the register-resident top-k.
// This is the exact requested sequence:
//   1) swap buffer <-> top-k so the buffer moves to registers;
//   2) sort that register buffer with bitonic sort;
//   3) form a bitonic sequence by taking min(buffer[i], old_topk[K-1-i]);
//   4) sort the bitonic sequence with bitonic sort.
//
// The shared candidate buffer is reused as scratch space for the old top-k, so
// the kernel never allocates extra storage.
//
// topk_full is intentionally tracked separately from max_distance:
// before the first K valid elements exist, max_distance is only a sentinel,
// so filtering must be disabled to avoid dropping true +inf distances.
template <int K>
__device__ __forceinline__ void flush_candidates(float (&topk_dist)[K / WARP_SIZE],
                                                 int   (&topk_idx )[K / WARP_SIZE],
                                                 float *warp_buf_dist,
                                                 int   *warp_buf_idx,
                                                 int   *warp_buf_count,
                                                 const int lane,
                                                 int   &candidate_count,
                                                 float &max_distance,
                                                 bool  &topk_full) {
    constexpr int REGS_PER_THREAD = K / WARP_SIZE;
    const int lane_base = lane * REGS_PER_THREAD;

    // Order all previous shared-memory writes by this warp before consuming the buffer.
    __syncwarp();

    // Pad the partially filled candidate buffer with sentinels so the merge always
    // operates on exactly K elements.
    #pragma unroll
    for (int r = 0; r < REGS_PER_THREAD; ++r) {
        const int pos = lane_base + r;
        if (pos >= candidate_count) {
            warp_buf_dist[pos] = CUDART_INF_F;
            warp_buf_idx [pos] = INVALID_INDEX;
        }
    }

    // Swap shared candidate buffer with the register top-k:
    // - registers receive the (unsorted) candidate buffer,
    // - shared memory receives the old sorted top-k, which becomes merge scratch.
    #pragma unroll
    for (int r = 0; r < REGS_PER_THREAD; ++r) {
        const int pos = lane_base + r;

        const float buf_d = warp_buf_dist[pos];
        const int   buf_i = warp_buf_idx [pos];

        warp_buf_dist[pos] = topk_dist[r];
        warp_buf_idx [pos] = topk_idx [r];

        topk_dist[r] = buf_d;
        topk_idx [r] = buf_i;
    }

    // Every lane will now read arbitrary positions from the old top-k in shared memory.
    __syncwarp();

    // Step 2: sort the former candidate buffer now living in registers.
    bitonic_sort_warp<K>(topk_dist, topk_idx, lane);

    // Step 3: build the bitonic merge input by pairing ascending buffer[i] with
    // descending old_topk[K-1-i] and keeping only the smaller of the two.
    #pragma unroll
    for (int r = 0; r < REGS_PER_THREAD; ++r) {
        const int i       = lane_base + r;
        const int rev_i   = K - 1 - i;
        const float old_d = warp_buf_dist[rev_i];
        const int   old_i = warp_buf_idx [rev_i];

        if (pair_greater(topk_dist[r], topk_idx[r], old_d, old_i)) {
            topk_dist[r] = old_d;
            topk_idx [r] = old_i;
        }
    }

    // Step 4: sort the bitonic sequence back into ascending order.
    bitonic_sort_warp<K>(topk_dist, topk_idx, lane);

    // Update the pruning threshold and whether the top-k is fully initialized.
    const float kth_dist_local = topk_dist[REGS_PER_THREAD - 1];
    const int   kth_idx_local  = topk_idx [REGS_PER_THREAD - 1];
    max_distance = __shfl_sync(FULL_MASK, kth_dist_local, LAST_LANE);
    topk_full    = (__shfl_sync(FULL_MASK, kth_idx_local,  LAST_LANE) >= 0);

    candidate_count = 0;
    if (lane == 0) {
        warp_buf_count[0] = 0;
    }
}

using result_pair_t = std::pair<int, float>;

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(const float2 * __restrict__ query,
                const int query_count,
                const float2 * __restrict__ data,
                const int data_count,
                result_pair_t * __restrict__ result) {
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0, "Invalid K.");
    constexpr int REGS_PER_THREAD = K / WARP_SIZE;

    // Shared memory layout:
    //   [0, BATCH_POINTS)                          : staged float2 data batch
    //   [0, WARPS_PER_BLOCK*K)                    : per-warp candidate distances
    //   [0, WARPS_PER_BLOCK*K)                    : per-warp candidate indices
    //   [0, WARPS_PER_BLOCK)                      : per-warp candidate counts
    extern __shared__ unsigned char smem_raw[];
    float2 *const sh_batch      = reinterpret_cast<float2*>(smem_raw);
    float  *const sh_buf_dist   = reinterpret_cast<float*>(sh_batch + BATCH_POINTS);
    int    *const sh_buf_idx    = reinterpret_cast<int*>(sh_buf_dist + WARPS_PER_BLOCK * K);
    int    *const sh_buf_count  = reinterpret_cast<int*>(sh_buf_idx  + WARPS_PER_BLOCK * K);

    const int lane     = threadIdx.x & (WARP_SIZE - 1);
    const int warp_id  = threadIdx.x >> 5;
    const int query_id = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK + warp_id;
    const bool active_query = (query_id < query_count);

    float *const warp_buf_dist  = sh_buf_dist  + warp_id * K;
    int   *const warp_buf_idx   = sh_buf_idx   + warp_id * K;
    int   *const warp_buf_count = sh_buf_count + warp_id;

    // Shared-memory bookkeeping variable requested by the specification.
    if (lane == 0) {
        warp_buf_count[0] = 0;
    }

    // Load one query point per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active_query && lane == 0) {
        const float2 q = query[query_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Register-resident distributed top-k.
    float topk_dist[REGS_PER_THREAD];
    int   topk_idx [REGS_PER_THREAD];

    #pragma unroll
    for (int r = 0; r < REGS_PER_THREAD; ++r) {
        topk_dist[r] = CUDART_INF_F;
        topk_idx [r] = INVALID_INDEX;
    }

    int   candidate_count = 0;
    float max_distance    = CUDART_INF_F;
    bool  topk_full       = false;

    // Precomputed lane mask for compacting ballot-selected candidates.
    const unsigned lane_lt_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);

    for (int base = 0; base < data_count; base += BATCH_POINTS) {
        const int remaining   = data_count - base;
        const int batch_count = (remaining < BATCH_POINTS) ? remaining : BATCH_POINTS;

        // Whole-block staging of a large data batch into shared memory.
        #pragma unroll
        for (int it = 0; it < LOAD_ITERS; ++it) {
            const int t = threadIdx.x + it * BLOCK_THREADS;
            if (t < batch_count) {
                sh_batch[t] = data[base + t];
            }
        }
        __syncthreads();

        if (active_query) {
            // Each warp scans the cached batch in tiles of 32 points so that
            // one ballot handles exactly one point per lane.
            for (int tile = 0; tile < batch_count; tile += WARP_SIZE) {
                const int local_idx  = tile + lane;
                const bool valid_pt  = (local_idx < batch_count);

                float dist = CUDART_INF_F;
                int   data_idx = base + local_idx;

                if (valid_pt) {
                    const float2 p  = sh_batch[local_idx];
                    const float  dx = qx - p.x;
                    const float  dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                }

                // Before the first full top-k exists, max_distance is only a
                // sentinel, so filtering is disabled to avoid dropping +inf values.
                bool keep = valid_pt && (!topk_full || (dist < max_distance));
                unsigned keep_mask = __ballot_sync(FULL_MASK, keep);
                int new_candidates = __popc(keep_mask);

                if (new_candidates != 0) {
                    // If the current tile would overflow the candidate buffer,
                    // first flush the existing buffer, then re-evaluate this tile
                    // against the tighter threshold.
                    if (candidate_count + new_candidates > K) {
                        flush_candidates<K>(topk_dist, topk_idx,
                                            warp_buf_dist, warp_buf_idx, warp_buf_count,
                                            lane, candidate_count, max_distance, topk_full);

                        keep = valid_pt && (!topk_full || (dist < max_distance));
                        keep_mask = __ballot_sync(FULL_MASK, keep);
                        new_candidates = __popc(keep_mask);
                    }

                    if (new_candidates != 0) {
                        if (keep) {
                            const int offset = __popc(keep_mask & lane_lt_mask);
                            const int pos    = candidate_count + offset;
                            warp_buf_dist[pos] = dist;
                            warp_buf_idx [pos] = data_idx;
                        }

                        candidate_count += new_candidates;
                        if (lane == 0) {
                            warp_buf_count[0] = candidate_count;
                        }

                        if (candidate_count == K) {
                            flush_candidates<K>(topk_dist, topk_idx,
                                                warp_buf_dist, warp_buf_idx, warp_buf_count,
                                                lane, candidate_count, max_distance, topk_full);
                        }
                    }
                }
            }
        }

        // All warps must finish reading the staged batch before the block overwrites it.
        __syncthreads();
    }

    if (active_query && candidate_count > 0) {
        flush_candidates<K>(topk_dist, topk_idx,
                            warp_buf_dist, warp_buf_idx, warp_buf_count,
                            lane, candidate_count, max_distance, topk_full);
    }

    if (active_query) {
        // Write back the sorted top-k in row-major order:
        // result[query_id * K + j] = {index, squared_distance}.
        const int lane_base = lane * REGS_PER_THREAD;
        result_pair_t *out = result
                           + static_cast<size_t>(query_id) * static_cast<size_t>(K)
                           + static_cast<size_t>(lane_base);

        #pragma unroll
        for (int r = 0; r < REGS_PER_THREAD; ++r) {
            out[r].first  = topk_idx[r];
            out[r].second = topk_dist[r];
        }
    }
}

template <int K>
inline void launch_knn_impl(const float2 *query,
                            const int query_count,
                            const float2 *data,
                            const int data_count,
                            result_pair_t *result) {
    const size_t smem = shared_bytes<K>();

    // The target devices support this amount of dynamic shared memory.
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(smem));
    (void)cudaFuncSetAttribute(knn_kernel<K>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               static_cast<int>(cudaSharedmemCarveoutMaxShared));

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, smem>>>(query, query_count, data, data_count, result);
}

} // namespace knn_detail

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   knn_detail::launch_knn_impl<32>(query, query_count, data, data_count, result);   return;
        case 64:   knn_detail::launch_knn_impl<64>(query, query_count, data, data_count, result);   return;
        case 128:  knn_detail::launch_knn_impl<128>(query, query_count, data, data_count, result);  return;
        case 256:  knn_detail::launch_knn_impl<256>(query, query_count, data, data_count, result);  return;
        case 512:  knn_detail::launch_knn_impl<512>(query, query_count, data, data_count, result);  return;
        case 1024: knn_detail::launch_knn_impl<1024>(query, query_count, data, data_count, result); return;
        default:   return; // Inputs are guaranteed valid, so this path is unreachable in normal use.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <climits>
#include <cstddef>

namespace {

// Warp-specialized 2D k-NN for squared Euclidean distance.
//
// Design choices tuned for modern data-center GPUs (A100/H100 class):
//   * One warp computes one query.
//   * 256 threads/block = 8 warps/block, so each staged data batch is reused by 8 queries.
//   * 2048 data points/batch. With K=1024 this yields:
//         2048 * sizeof(float2)                          = 16 KiB
//         8 warps * 1024 * (sizeof(float)+sizeof(int))   = 64 KiB
//       total dynamic shared memory per block            = 80 KiB
//     which still allows two resident blocks on 164 KiB SMs.
//
// The current top-k list is distributed across warp registers exactly as requested:
// each lane owns K/32 consecutive elements.
// A warp-private shared-memory candidate buffer collects only points closer than the
// current k-th distance. Whenever the buffer fills (or overflows on the next ballot),
// it is merged into the register-resident top-k using the specified bitonic procedure.

constexpr int kWarpSize         = 32;
constexpr int kBlockThreads     = 256;
constexpr int kWarpsPerBlock    = kBlockThreads / kWarpSize;
constexpr int kBatchPoints      = 2048;
constexpr int kBatchFloat4      = kBatchPoints / 2;                 // 1 float4 == 2 float2
constexpr int kFloat4LoadsPerThread = kBatchFloat4 / kBlockThreads; // 1024 / 256 = 4
constexpr unsigned kFullMask    = 0xFFFFFFFFu;
constexpr int kInvalidIndex     = INT_MAX;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of 32.");
static_assert(kBatchPoints % kWarpSize == 0, "Batch size must be a multiple of 32.");
static_assert(kBatchPoints % 2 == 0, "Batch size must be even for float4 vector loads.");
static_assert(kBatchFloat4 % kBlockThreads == 0, "Full-batch float4 loads must divide evenly.");

// Device code writes through a POD with the same binary layout as std::pair<int,float>.
// This avoids depending on device-side std::pair constructors/operators.
struct PairStorage {
    int   first;
    float second;
};

static_assert(sizeof(PairStorage) == 8, "PairStorage must be tightly packed.");
static_assert(sizeof(std::pair<int, float>) == sizeof(PairStorage),
              "std::pair<int,float> must have the same layout as {int,float}.");

// Total ordering used by the sorting network.
// Distances are primary keys, indices are deterministic tie-breakers.
__device__ __forceinline__
bool pair_less(const float a_dist, const int a_idx,
               const float b_dist, const int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__
void compare_swap_pair(float& a_dist, int& a_idx,
                       float& b_dist, int& b_idx,
                       const bool ascending) {
    const bool do_swap = ascending
        ? pair_less(b_dist, b_idx, a_dist, a_idx)
        : pair_less(a_dist, a_idx, b_dist, b_idx);

    if (do_swap) {
        const float tmp_dist = a_dist;
        const int   tmp_idx  = a_idx;
        a_dist = b_dist;
        a_idx  = b_idx;
        b_dist = tmp_dist;
        b_idx  = tmp_idx;
    }
}

__device__ __forceinline__
float squared_l2(const float qx, const float qy, const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return __fmaf_rn(dx, dx, dy * dy);
}

template <int K>
__device__ __forceinline__
float current_max_distance(const float (&topk_dist)[K / kWarpSize]) {
    constexpr int kItemsPerThread = K / kWarpSize;
    return __shfl_sync(kFullMask, topk_dist[kItemsPerThread - 1], kWarpSize - 1);
}

// One fully compile-time-unrolled bitonic compare/exchange pass.
// Because K and K/32 are powers of two, once J reaches the lane-local chunk size,
// the partner moves to another lane but keeps the same register offset. This exactly
// matches the prompt and allows cross-lane exchanges via shuffle-xor on one register
// per offset.
template <int KStage, int J, int K>
__device__ __forceinline__
void bitonic_pass(float (&dist)[K / kWarpSize],
                  int   (&idx )[K / kWarpSize],
                  const int lane) {
    constexpr int kItemsPerThread = K / kWarpSize;

    if constexpr (J < kItemsPerThread) {
        // Partner stays inside the same lane; compare/swap can be done locally.
        #pragma unroll
        for (int r = 0; r < kItemsPerThread; ++r) {
            const int partner = r ^ J;
            if (partner > r) {
                const int logical_i = lane * kItemsPerThread + r;
                const bool ascending = ((logical_i & KStage) == 0);
                compare_swap_pair(dist[r], idx[r], dist[partner], idx[partner], ascending);
            }
        }
    } else {
        // Partner sits in another lane but at the same intra-lane register offset.
        constexpr int kLaneMask = J / kItemsPerThread;

        #pragma unroll
        for (int r = 0; r < kItemsPerThread; ++r) {
            const float self_dist  = dist[r];
            const int   self_idx   = idx[r];
            const float other_dist = __shfl_xor_sync(kFullMask, self_dist, kLaneMask);
            const int   other_idx  = __shfl_xor_sync(kFullMask, self_idx,  kLaneMask);

            const int  logical_i = lane * kItemsPerThread + r;
            const bool ascending = ((logical_i & KStage) == 0);
            const bool lower     = ((logical_i & J) == 0);

            // ascending: lower keeps min, upper keeps max
            // descending: lower keeps max, upper keeps min
            const bool take_min  = (ascending == lower);
            const bool take_self = take_min
                ? !pair_less(other_dist, other_idx, self_dist, self_idx) // self <= other
                : !pair_less(self_dist, self_idx, other_dist, other_idx); // self >= other

            if (!take_self) {
                dist[r] = other_dist;
                idx[r]  = other_idx;
            }
        }
    }

    if constexpr (J > 1) {
        bitonic_pass<KStage, (J >> 1), K>(dist, idx, lane);
    }
}

template <int KStage, int K>
__device__ __forceinline__
void bitonic_stages(float (&dist)[K / kWarpSize],
                    int   (&idx )[K / kWarpSize],
                    const int lane) {
    bitonic_pass<KStage, (KStage >> 1), K>(dist, idx, lane);
    if constexpr (KStage < K) {
        bitonic_stages<(KStage << 1), K>(dist, idx, lane);
    }
}

template <int K>
__device__ __forceinline__
void bitonic_sort(float (&dist)[K / kWarpSize],
                  int   (&idx )[K / kWarpSize],
                  const int lane) {
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K & (K - 1)) == 0,   "K must be a power of two.");
    static_assert((K % kWarpSize) == 0, "K must be divisible by 32.");
    bitonic_stages<2, K>(dist, idx, lane);
}

// Merge the warp-private candidate buffer into the register-resident intermediate result.
// The implementation follows the requested procedure:
//
//   0. Invariant: intermediate result is already sorted ascending.
//   1. Swap buffer and intermediate result so that the buffer moves to registers.
//   2. Sort that register-resident buffer with bitonic sort.
//   3. Form a bitonic top-k merge: new[i] = min(buffer[i], result[k-i-1]).
//   4. Sort the merged bitonic sequence ascending to obtain the updated top-k.
//
// Shared memory is warp-private here, so warp synchronization is sufficient.
template <int K>
__device__ __forceinline__
float merge_candidate_buffer(float (&topk_dist)[K / kWarpSize],
                             int   (&topk_idx )[K / kWarpSize],
                             float* warp_buffer_dist,
                             int*   warp_buffer_idx,
                             const int buffer_count,
                             const int lane) {
    constexpr int kItemsPerThread = K / kWarpSize;

    // Step 1: swap shared buffer <-> register-resident top-k, while padding the
    // candidate buffer with +inf for the final (possibly partially full) merge.
    #pragma unroll
    for (int r = 0; r < kItemsPerThread; ++r) {
        const int pos = lane * kItemsPerThread + r;

        const float buf_dist = (pos < buffer_count) ? warp_buffer_dist[pos] : CUDART_INF_F;
        const int   buf_idx  = (pos < buffer_count) ? warp_buffer_idx[pos]  : kInvalidIndex;

        warp_buffer_dist[pos] = topk_dist[r];
        warp_buffer_idx[pos]  = topk_idx[r];

        topk_dist[r] = buf_dist;
        topk_idx[r]  = buf_idx;
    }
    __syncwarp(kFullMask);

    // Step 2: sort the (former) candidate buffer now stored in registers.
    bitonic_sort<K>(topk_dist, topk_idx, lane);

    // Step 3: build the bitonic top-k merge against the reversed old result.
    #pragma unroll
    for (int r = 0; r < kItemsPerThread; ++r) {
        const int pos = lane * kItemsPerThread + r;
        const int rev = K - 1 - pos;

        const float other_dist = warp_buffer_dist[rev];
        const int   other_idx  = warp_buffer_idx[rev];

        if (pair_less(other_dist, other_idx, topk_dist[r], topk_idx[r])) {
            topk_dist[r] = other_dist;
            topk_idx[r]  = other_idx;
        }
    }

    // Step 4: final ascending sort of the bitonic sequence.
    bitonic_sort<K>(topk_dist, topk_idx, lane);

    return current_max_distance<K>(topk_dist);
}

// Process one data point per lane:
//   * filter by the current max_distance,
//   * compact passing lanes with a warp ballot,
//   * append them to the shared candidate buffer,
//   * flush/merge the buffer when needed.
//
// If the current ballot would overflow the buffer, we first merge the existing buffer,
// then re-ballot the same tile against the tightened max_distance so that newly rejected
// points are not appended unnecessarily.
template <int K>
__device__ __forceinline__
void consider_candidate(const bool  valid,
                        const float candidate_distance,
                        const int   candidate_index,
                        float (&topk_dist)[K / kWarpSize],
                        int   (&topk_idx )[K / kWarpSize],
                        float* warp_buffer_dist,
                        int*   warp_buffer_idx,
                        int&   buffer_count,
                        float& max_distance,
                        const unsigned lane_mask_lt,
                        const int lane) {
    bool is_candidate = valid && (candidate_distance < max_distance);
    unsigned cand_mask = __ballot_sync(kFullMask, is_candidate);
    int cand_count = __popc(cand_mask);

    if (cand_count == 0) {
        return;
    }

    if (buffer_count + cand_count > K) {
        __syncwarp(kFullMask);
        max_distance = merge_candidate_buffer<K>(
            topk_dist, topk_idx,
            warp_buffer_dist, warp_buffer_idx,
            buffer_count, lane);
        buffer_count = 0;

        // Re-apply the tighter threshold produced by the merge.
        is_candidate = valid && (candidate_distance < max_distance);
        cand_mask = __ballot_sync(kFullMask, is_candidate);
        cand_count = __popc(cand_mask);

        if (cand_count == 0) {
            return;
        }
    }

    if (is_candidate) {
        const int local_rank = __popc(cand_mask & lane_mask_lt);
        const int pos = buffer_count + local_rank;
        warp_buffer_dist[pos] = candidate_distance;
        warp_buffer_idx[pos]  = candidate_index;
    }

    // buffer_count is warp-uniform; every lane carries the same replicated scalar.
    buffer_count += cand_count;
    __syncwarp(kFullMask);

    if (buffer_count == K) {
        max_distance = merge_candidate_buffer<K>(
            topk_dist, topk_idx,
            warp_buffer_dist, warp_buffer_idx,
            buffer_count, lane);
        buffer_count = 0;
    }
}

template <int K>
__global__ __launch_bounds__(kBlockThreads, 2)
void knn_kernel(const float2* __restrict__ query,
                const int query_count,
                const float2* __restrict__ data,
                const int data_count,
                PairStorage* __restrict__ result) {
    constexpr int kItemsPerThread = K / kWarpSize;

    // Shared-memory layout:
    //   [0, kBatchPoints)                              -> staged float2 data batch
    //   [kBatchPoints, kBatchPoints + kWarpsPerBlock*K) -> candidate distances
    //   [..]                                            -> candidate indices
    extern __shared__ float4 smem_vec[];
    float2* const s_data = reinterpret_cast<float2*>(smem_vec);
    float*  const s_buffer_dist = reinterpret_cast<float*>(s_data + kBatchPoints);
    int*    const s_buffer_idx  = reinterpret_cast<int*>(s_buffer_dist + kWarpsPerBlock * K);

    const int lane    = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_idx = blockIdx.x * kWarpsPerBlock + warp_id;
    const bool active = (query_idx < query_count);

    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    // Register-resident intermediate result: K/32 consecutive elements per lane.
    float topk_dist[kItemsPerThread];
    int   topk_idx [kItemsPerThread];
    #pragma unroll
    for (int i = 0; i < kItemsPerThread; ++i) {
        topk_dist[i] = CUDART_INF_F;
        topk_idx[i]  = kInvalidIndex;
    }

    // Load the query once per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    if (active) {
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);
    }

    float* const warp_buffer_dist = s_buffer_dist + warp_id * K;
    int*   const warp_buffer_idx  = s_buffer_idx  + warp_id * K;

    int   buffer_count = 0;          // warp-uniform count of buffered candidates
    float max_distance = CUDART_INF_F;

    for (int batch_base = 0; batch_base < data_count; batch_base += kBatchPoints) {
        const int remaining  = data_count - batch_base;
        const int batch_size = (remaining >= kBatchPoints) ? kBatchPoints : remaining;

        if (batch_size == kBatchPoints) {
            // Full batches dominate; load them with aligned float4 vector loads.
            // data comes from cudaMalloc and batch_base is always even here, so
            // reinterpret_cast<float4*> is 16-byte aligned.
            const float4* const g_data4 =
                reinterpret_cast<const float4*>(data) + (batch_base >> 1);

            #pragma unroll
            for (int i = 0; i < kFloat4LoadsPerThread; ++i) {
                const int vec_idx = threadIdx.x + i * kBlockThreads;
                smem_vec[vec_idx] = g_data4[vec_idx];
            }
        } else {
            // Scalar tail path for the final partial batch.
            for (int i = threadIdx.x; i < batch_size; i += kBlockThreads) {
                s_data[i] = data[batch_base + i];
            }
        }

        __syncthreads();

        if (active) {
            if (batch_size == kBatchPoints) {
                // Full-batch path: all lanes are valid in every 32-point tile.
                for (int tile = 0; tile < kBatchPoints; tile += kWarpSize) {
                    const int data_idx = batch_base + tile + lane;
                    const float2 p = s_data[tile + lane];
                    const float dist = squared_l2(qx, qy, p);

                    consider_candidate<K>(
                        true, dist, data_idx,
                        topk_dist, topk_idx,
                        warp_buffer_dist, warp_buffer_idx,
                        buffer_count, max_distance,
                        lane_mask_lt, lane);
                }
            } else {
                // Tail path: the final tile may be partially valid.
                for (int tile = 0; tile < batch_size; tile += kWarpSize) {
                    const int local_idx = tile + lane;
                    const bool valid = (local_idx < batch_size);

                    float dist = CUDART_INF_F;
                    if (valid) {
                        const float2 p = s_data[local_idx];
                        dist = squared_l2(qx, qy, p);
                    }

                    const int data_idx = batch_base + local_idx;

                    consider_candidate<K>(
                        valid, dist, data_idx,
                        topk_dist, topk_idx,
                        warp_buffer_dist, warp_buffer_idx,
                        buffer_count, max_distance,
                        lane_mask_lt, lane);
                }
            }
        }

        // The staged batch is shared by the whole block, so the block must finish
        // consuming it before the next load overwrites the cache.
        __syncthreads();
    }

    if (active) {
        // Flush any residual candidates left in the buffer after the last batch.
        if (buffer_count > 0) {
            (void)merge_candidate_buffer<K>(
                topk_dist, topk_idx,
                warp_buffer_dist, warp_buffer_idx,
                buffer_count, lane);
        }

        // Write the final sorted top-k neighbors back in the required row-major layout.
        PairStorage* const out =
            result
            + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K)
            + static_cast<std::size_t>(lane) * static_cast<std::size_t>(kItemsPerThread);

        #pragma unroll
        for (int i = 0; i < kItemsPerThread; ++i) {
            out[i].first  = topk_idx[i];
            out[i].second = topk_dist[i];
        }
    }
}

template <int K>
constexpr std::size_t shared_bytes_for_k() {
    return static_cast<std::size_t>(kBatchPoints) * sizeof(float2)
         + static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(K) * (sizeof(float) + sizeof(int));
}

template <int K>
void launch_knn(const float2* query,
                const int query_count,
                const float2* data,
                const int data_count,
                PairStorage* result) {
    const std::size_t shared_bytes = shared_bytes_for_k<K>();

    // Full dynamic shared-memory opt-in is required for the larger K values.
    const cudaError_t attr0 = cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shared_bytes));
    const cudaError_t attr1 = cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);
    (void)attr0;
    (void)attr1;

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    knn_kernel<K><<<grid, block, shared_bytes>>>(
        query, query_count,
        data, data_count,
        result);
}

} // anonymous namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    // K is specialized at compile time so that:
    //   * each lane's K/32 slice is a fixed-size register array,
    //   * the bitonic sorting network is fully unrolled,
    //   * no extra device memory allocation is needed.
    PairStorage* const out = reinterpret_cast<PairStorage*>(result);

    switch (k) {
        case 32:   launch_knn<32>(query, query_count, data, data_count, out);   return;
        case 64:   launch_knn<64>(query, query_count, data, data_count, out);   return;
        case 128:  launch_knn<128>(query, query_count, data, data_count, out);  return;
        case 256:  launch_knn<256>(query, query_count, data, data_count, out);  return;
        case 512:  launch_knn<512>(query, query_count, data, data_count, out);  return;
        case 1024: launch_knn<1024>(query, query_count, data, data_count, out); return;
        default:
            // The prompt guarantees valid K values, so this path is unreachable.
            return;
    }
}

#include <cuda_runtime.h>
#include <climits>
#include <cstddef>
#include <cmath>
#include <utility>

namespace {

// Warp size is fixed by the problem statement.
constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

// Tuning choice:
// - 256 threads/block = 8 warps/block = 8 queries/block.
//   This gives good data reuse (the block-wide shared-memory tile is reused by 8 queries)
//   while still producing enough blocks when query_count is in the low-thousands.
// - 2048 points/tile = 16 KiB shared tile.
//   Together with the worst-case candidate buffer for K=1024 (64 KiB dynamic shared),
//   total shared memory is exactly 80 KiB/block. Two such blocks fit exactly into the
//   160 KiB shared-memory budget of A100-class SMs.
constexpr int kThreadsPerBlock = 256;
constexpr int kWarpsPerBlock = kThreadsPerBlock / kWarpSize;
constexpr int kDataTilePoints = 2048;

// Internal sentinel used only for padded / unused slots inside the sort/merge network.
// Smaller indices are considered "better" for equal distances, so INT_MAX makes padded
// +inf entries the worst possible items and keeps them at the tail after sorting.
constexpr int kInvalidIndex = INT_MAX;

template <int K>
constexpr std::size_t candidate_buffer_bytes() {
    return static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(K) *
           (sizeof(float) + sizeof(int));
}

constexpr std::size_t kTileSharedBytes =
    static_cast<std::size_t>(kDataTilePoints) * sizeof(float2);

// Sanity-check the chosen hyper-parameters: worst-case shared memory is 80 KiB/block.
static_assert(kTileSharedBytes + candidate_buffer_bytes<1024>() == 81920u,
              "Shared-memory footprint must remain 80 KiB/block at K=1024.");

// Total ordering used by the bitonic network.
// Distances are primary keys; indices are only a deterministic tie-breaker.
// The problem statement allows any tie resolution, but a total order makes the
// compare/exchange network well-defined.
__device__ __forceinline__ bool pair_less(const float a_dist, const int a_idx,
                                          const float b_dist, const int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__ void swap_pair(float &a_dist, int &a_idx,
                                          float &b_dist, int &b_idx) {
    const float tmp_dist = a_dist;
    const int tmp_idx = a_idx;
    a_dist = b_dist;
    a_idx = b_idx;
    b_dist = tmp_dist;
    b_idx = tmp_idx;
}

// Squared Euclidean distance in 2D. No square root is taken because the required output
// is the squared L2 norm.
__device__ __forceinline__ float squared_l2(const float qx, const float qy,
                                            const float2 p) {
    const float dx = qx - p.x;
    const float dy = qy - p.y;
    return fmaf(dx, dx, dy * dy);
}

// Bitonic sort over K elements distributed across one warp.
// Layout invariant:
//   - Each thread owns ELEMS_PER_THREAD = K / 32 consecutive positions.
//   - Therefore, when the compare distance "stride" is smaller than ELEMS_PER_THREAD,
//     both partners live in the same thread and can be swapped locally.
//   - Otherwise, both partners live in different lanes but always at the same local
//     register index, so warp shuffles exchange them directly.
template <int K, int ELEMS_PER_THREAD>
__device__ __forceinline__ void bitonic_sort_regs(float (&dist)[ELEMS_PER_THREAD],
                                                  int (&idx)[ELEMS_PER_THREAD],
                                                  const int lane) {
    const int lane_base = lane * ELEMS_PER_THREAD;

    #pragma unroll
    for (int stage = 2; stage <= K; stage <<= 1) {
        #pragma unroll
        for (int stride = stage >> 1; stride > 0; stride >>= 1) {
            if (stride < ELEMS_PER_THREAD) {
                // Same-thread compare/exchange.
                #pragma unroll
                for (int e = 0; e < ELEMS_PER_THREAD; ++e) {
                    const int partner_e = e ^ stride;
                    if (partner_e > e) {
                        const int g = lane_base + e;
                        const bool ascending = ((g & stage) == 0);
                        const bool do_swap =
                            ascending
                                ? pair_less(dist[partner_e], idx[partner_e], dist[e], idx[e])
                                : pair_less(dist[e], idx[e], dist[partner_e], idx[partner_e]);

                        if (do_swap) {
                            swap_pair(dist[e], idx[e], dist[partner_e], idx[partner_e]);
                        }
                    }
                }
            } else {
                // Cross-thread compare/exchange via shuffles.
                const int lane_delta = stride / ELEMS_PER_THREAD;
                const int partner_lane = lane ^ lane_delta;

                #pragma unroll
                for (int e = 0; e < ELEMS_PER_THREAD; ++e) {
                    const float other_dist = __shfl_sync(kFullMask, dist[e], partner_lane);
                    const int other_idx = __shfl_sync(kFullMask, idx[e], partner_lane);

                    const int g = lane_base + e;
                    const bool ascending = ((g & stage) == 0);
                    const bool keep_min = ascending ? (lane < partner_lane)
                                                    : (lane > partner_lane);

                    const bool take_other =
                        keep_min ? pair_less(other_dist, other_idx, dist[e], idx[e])
                                 : pair_less(dist[e], idx[e], other_dist, other_idx);

                    if (take_other) {
                        dist[e] = other_dist;
                        idx[e] = other_idx;
                    }
                }
            }

            // Bitonic networks are stage-based. An explicit warp barrier preserves the stage
            // boundary and also satisfies the prompt requirement to synchronize warp
            // communication appropriately.
            __syncwarp(kFullMask);
        }
    }
}

// Flushes the shared candidate buffer into the register-resident intermediate result.
// This implements exactly the merge procedure requested in the prompt:
//
// 0. Invariant: best_* is sorted ascending.
// 1. Swap the buffer and intermediate result so the buffer moves into registers.
// 2. Sort the register-resident buffer with bitonic sort.
// 3. Form the bitonic sequence merged[i] = min(buffer[i], best[K-1-i]).
// 4. Sort that bitonic sequence again to obtain the updated intermediate result.
//
// The candidate buffer is warp-private inside shared memory, so __syncwarp is sufficient.
template <int K, int ELEMS_PER_THREAD>
__device__ __forceinline__ void flush_candidate_buffer(
    float (&best_dist)[ELEMS_PER_THREAD],
    int (&best_idx)[ELEMS_PER_THREAD],
    float *cand_dist,
    int *cand_idx,
    int &buf_count,
    float &max_distance,
    bool &filter_open,
    const int lane) {
    if (buf_count == 0) {
        return;
    }

    const int lane_base = lane * ELEMS_PER_THREAD;
    const int active_count = buf_count;

    __syncwarp(kFullMask);

    // Step 1: swap the shared candidate buffer with the sorted intermediate result.
    #pragma unroll
    for (int e = 0; e < ELEMS_PER_THREAD; ++e) {
        const int g = lane_base + e;
        const bool valid_candidate = (g < active_count);

        const float candidate_dist = valid_candidate ? cand_dist[g] : CUDART_INF_F;
        const int candidate_idx = valid_candidate ? cand_idx[g] : kInvalidIndex;

        cand_dist[g] = best_dist[e];
        cand_idx[g] = best_idx[e];

        best_dist[e] = candidate_dist;
        best_idx[e] = candidate_idx;
    }

    __syncwarp(kFullMask);

    // Step 2: sort the former candidate buffer now held in registers.
    bitonic_sort_regs<K, ELEMS_PER_THREAD>(best_dist, best_idx, lane);

    // Step 3: bitonic merge construction with the reversed current best from shared memory.
    const int reverse_base = K - 1 - lane_base;
    #pragma unroll
    for (int e = 0; e < ELEMS_PER_THREAD; ++e) {
        const int reverse_g = reverse_base - e;
        const float other_dist = cand_dist[reverse_g];
        const int other_idx = cand_idx[reverse_g];

        if (pair_less(other_dist, other_idx, best_dist[e], best_idx[e])) {
            best_dist[e] = other_dist;
            best_idx[e] = other_idx;
        }
    }

    // Step 4: sort the bitonic sequence to restore the ascending invariant.
    bitonic_sort_regs<K, ELEMS_PER_THREAD>(best_dist, best_idx, lane);

    // Update the pruning threshold: the k-th nearest element lives in the last register
    // of lane 31 because each lane stores a consecutive chunk.
    const float kth_local =
        (lane == (kWarpSize - 1)) ? best_dist[ELEMS_PER_THREAD - 1] : 0.0f;
    max_distance = __shfl_sync(kFullMask, kth_local, kWarpSize - 1);

    // While max_distance remains +inf, the filter is intentionally disabled so the first
    // K elements are admitted unconditionally. This also keeps the algorithm correct if
    // some computed distances overflow to +inf before a finite threshold is established.
    filter_open = (max_distance == CUDART_INF_F);
    buf_count = 0;

    __syncwarp(kFullMask);
}

template <int K, int THREADS_PER_BLOCK, int DATA_TILE_POINTS>
__global__ __launch_bounds__(THREADS_PER_BLOCK)
void knn_kernel(const float2 *__restrict__ query,
                const int query_count,
                const float2 *__restrict__ data,
                const int data_count,
                std::pair<int, float> *__restrict__ result) {
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert(K >= kWarpSize && K <= 1024, "K must be in [32, 1024].");
    static_assert((K % kWarpSize) == 0, "K must be divisible by warp size.");
    static_assert((THREADS_PER_BLOCK % kWarpSize) == 0,
                  "Block size must be a multiple of warp size.");
    static_assert((DATA_TILE_POINTS % kWarpSize) == 0,
                  "Tile size must be a multiple of warp size.");

    constexpr int WARPS_PER_BLOCK = THREADS_PER_BLOCK / kWarpSize;
    constexpr int ELEMS_PER_THREAD = K / kWarpSize;

    // Static shared tile reused by the entire block across 8 queries.
    __shared__ float2 tile[DATA_TILE_POINTS];

    // Dynamic shared memory holds the per-warp candidate buffers:
    //   [WARPS_PER_BLOCK * K floats][WARPS_PER_BLOCK * K ints]
    extern __shared__ unsigned char smem_raw[];
    float *const cand_dist_all = reinterpret_cast<float *>(smem_raw);
    int *const cand_idx_all =
        reinterpret_cast<int *>(cand_dist_all + WARPS_PER_BLOCK * K);

    const int tid = static_cast<int>(threadIdx.x);
    const int warp_id = tid / kWarpSize;
    const int lane = tid & (kWarpSize - 1);
    const int lane_base = lane * ELEMS_PER_THREAD;
    const unsigned lower_lane_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);

    float *const cand_dist = cand_dist_all + warp_id * K;
    int *const cand_idx = cand_idx_all + warp_id * K;

    // Blocks advance over query groups in a grid-stride fashion. With the default launch
    // configuration this loop usually executes only once, but keeping it grid-strided
    // makes the kernel robust to any future launch policy.
    const int query_group_stride = static_cast<int>(gridDim.x) * WARPS_PER_BLOCK;

    for (int query_base = static_cast<int>(blockIdx.x) * WARPS_PER_BLOCK;
         query_base < query_count;
         query_base += query_group_stride) {
        const int query_idx = query_base + warp_id;
        const bool active_query = (query_idx < query_count);

        // One query per warp. Lane 0 loads the query point, then broadcasts it.
        float qx = 0.0f;
        float qy = 0.0f;
        if (active_query && lane == 0) {
            const float2 q = query[query_idx];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(kFullMask, qx, 0);
        qy = __shfl_sync(kFullMask, qy, 0);

        // Register-resident intermediate result. Each thread owns K/32 consecutive slots.
        float best_dist[ELEMS_PER_THREAD];
        int best_idx[ELEMS_PER_THREAD];

        // buf_count is intentionally replicated in every lane; ballot counts are identical in
        // all lanes, so the value stays consistent without shared-memory traffic.
        int buf_count = 0;
        float max_distance = CUDART_INF_F;
        bool filter_open = true;

        if (active_query) {
            #pragma unroll
            for (int e = 0; e < ELEMS_PER_THREAD; ++e) {
                best_dist[e] = CUDART_INF_F;
                best_idx[e] = kInvalidIndex;
            }
        }

        // Stream the data set through shared memory in block-wide tiles.
        for (int data_base = 0; data_base < data_count; data_base += DATA_TILE_POINTS) {
            const int remaining = data_count - data_base;
            const int tile_count = (remaining < DATA_TILE_POINTS) ? remaining : DATA_TILE_POINTS;
            const float2 *const data_base_ptr = data + data_base;

            // Whole-block cooperative load of the next tile.
            for (int load_idx = tid; load_idx < tile_count; load_idx += THREADS_PER_BLOCK) {
                tile[load_idx] = data_base_ptr[load_idx];
            }
            __syncthreads();

            if (active_query) {
                // Process one warp-sized group from shared memory at a time so a single ballot
                // tells the warp how many candidates passed the distance threshold.
                for (int base = 0; base < tile_count; base += kWarpSize) {
                    const int local_idx = base + lane;
                    const bool valid = (local_idx < tile_count);

                    float distance = 0.0f;
                    int data_idx = kInvalidIndex;

                    if (valid) {
                        const float2 p = tile[local_idx];
                        distance = squared_l2(qx, qy, p);
                        data_idx = data_base + local_idx;
                    }

                    bool pass = valid && (filter_open || (distance < max_distance));
                    unsigned mask = __ballot_sync(kFullMask, pass);
                    int accepted = __popc(mask);

                    // If the current warp ballot would overflow the candidate buffer, flush the
                    // existing buffer first, then re-filter the current 32 distances against the
                    // updated threshold.
                    if (buf_count + accepted > K) {
                        flush_candidate_buffer<K, ELEMS_PER_THREAD>(
                            best_dist, best_idx,
                            cand_dist, cand_idx,
                            buf_count, max_distance, filter_open,
                            lane);

                        pass = valid && (filter_open || (distance < max_distance));
                        mask = __ballot_sync(kFullMask, pass);
                        accepted = __popc(mask);
                    }

                    if (accepted != 0) {
                        const int offset = buf_count;

                        if (pass) {
                            const int rank = __popc(mask & lower_lane_mask);
                            cand_dist[offset + rank] = distance;
                            cand_idx[offset + rank] = data_idx;
                        }

                        __syncwarp(kFullMask);

                        buf_count = offset + accepted;

                        if (buf_count == K) {
                            flush_candidate_buffer<K, ELEMS_PER_THREAD>(
                                best_dist, best_idx,
                                cand_dist, cand_idx,
                                buf_count, max_distance, filter_open,
                                lane);
                        }
                    }
                }
            }

            // The tile is block-shared and will be overwritten by the next iteration.
            __syncthreads();
        }

        // Final partial buffer flush, if needed.
        if (active_query) {
            if (buf_count != 0) {
                flush_candidate_buffer<K, ELEMS_PER_THREAD>(
                    best_dist, best_idx,
                    cand_dist, cand_idx,
                    buf_count, max_distance, filter_open,
                    lane);
            }

            // Store the final sorted K nearest neighbors.
            std::pair<int, float> *out =
                result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K) + lane_base;

            #pragma unroll
            for (int e = 0; e < ELEMS_PER_THREAD; ++e) {
                out[e].first = best_idx[e];
                out[e].second = best_dist[e];
            }
        }
    }
}

// Launch helper for a compile-time K. K must be specialized because:
// - Each thread stores K/32 neighbors in registers.
// - The bitonic network size depends on K.
// - The shared candidate buffer size depends on K.
template <int K>
void launch_knn_case(const float2 *query,
                     const int query_count,
                     const float2 *data,
                     const int data_count,
                     std::pair<int, float> *result) {
    constexpr int THREADS = kThreadsPerBlock;
    constexpr int TILE = kDataTilePoints;
    constexpr std::size_t DYNAMIC_SHARED_BYTES = candidate_buffer_bytes<K>();

    // The shared data tile is static (16 KiB). Only the per-warp candidate buffer is dynamic.
    // Prefer maximum shared-memory carveout because the kernel relies on shared-memory tiling
    // much more than on L1 capacity.
    (void)cudaFuncSetAttribute(
        knn_kernel<K, THREADS, TILE>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(DYNAMIC_SHARED_BYTES));
    (void)cudaFuncSetAttribute(
        knn_kernel<K, THREADS, TILE>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const int blocks = (query_count + kWarpsPerBlock - 1) / kWarpsPerBlock;
    if (blocks > 0) {
        knn_kernel<K, THREADS, TILE><<<blocks, THREADS, DYNAMIC_SHARED_BYTES>>>(
            query, query_count, data, data_count, result);
    }
}

} // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   launch_knn_case<32>(query, query_count, data, data_count, result); break;
        case 64:   launch_knn_case<64>(query, query_count, data, data_count, result); break;
        case 128:  launch_knn_case<128>(query, query_count, data, data_count, result); break;
        case 256:  launch_knn_case<256>(query, query_count, data, data_count, result); break;
        case 512:  launch_knn_case<512>(query, query_count, data, data_count, result); break;
        case 1024: launch_knn_case<1024>(query, query_count, data, data_count, result); break;
        default: break; // Inputs are guaranteed valid by the problem statement.
    }
}

#include <cuda_runtime.h>
#include <utility>

namespace {

// This implementation is written for NVIDIA GPUs with 32-thread warps (A100/H100 class GPUs).
constexpr int kWarpSize     = 32;
constexpr int kWarpSizeLog2 = 5;
constexpr unsigned kFullMask = 0xffffffffu;
constexpr int kInvalidIndex  = 0x7fffffff;

// POD mirror of std::pair<int, float>.
// The public interface uses std::pair<int, float>*, but relying on device-side std::pair
// support is unnecessary. We only need binary-compatible storage.
struct alignas(std::pair<int, float>) ResultPairDevice {
    int   first;
    float second;
};

static_assert(sizeof(ResultPairDevice) == sizeof(std::pair<int, float>),
              "std::pair<int, float> must match ResultPairDevice size.");
static_assert(alignof(ResultPairDevice) == alignof(std::pair<int, float>),
              "std::pair<int, float> must match ResultPairDevice alignment.");

template <int K>
struct KTraits {
    static_assert(K >= 32 && K <= 1024, "K must be in [32, 1024].");
    static_assert((K & (K - 1)) == 0, "K must be a power of two.");
    static_assert((K % kWarpSize) == 0, "K must be divisible by the warp size.");
    static constexpr int LOCAL  = K / kWarpSize;     // register slots per thread
    // One dummy slot per 32 logical elements. The padding removes bank conflicts for:
    //   * ballot-compacted contiguous appends
    //   * stride-LOCAL accesses during swap/merge
    //   * reversed stride-LOCAL accesses during the bitonic merge step
    static constexpr int PADDED = K + K / kWarpSize;
};

__device__ __forceinline__ int logical_to_physical(int logical_idx) {
    // One extra hole after every 32 logical elements.
    return logical_idx + (logical_idx >> kWarpSizeLog2);
}

__device__ __forceinline__ bool pair_less(float ad, int ai, float bd, int bi) {
    // Distance is the primary key; index is only a deterministic tie-breaker for the sorting network.
    return (ad < bd) || ((ad == bd) && (ai < bi));
}

__device__ __forceinline__ void pair_swap(float &ad, int &ai, float &bd, int &bi) {
    const float td = ad;
    ad = bd;
    bd = td;

    const int ti = ai;
    ai = bi;
    bi = ti;
}

__device__ __forceinline__ float sq_l2_2d(float qx, float qy, float px, float py) {
    const float dx = qx - px;
    const float dy = qy - py;
    return __fmaf_rn(dx, dx, dy * dy);
}

// Distributed bitonic sort over K values.
// Layout:
//   - one warp owns K values
//   - each thread owns LOCAL = K / 32 consecutive logical positions
//   - cross-thread exchanges always happen between the same local register index;
//     those exchanges use warp shuffles
//   - intra-thread exchanges stay in registers
template <int K>
__device__ __forceinline__
void bitonic_sort(float (&dist)[KTraits<K>::LOCAL], int (&idx)[KTraits<K>::LOCAL], int lane) {
    constexpr int LOCAL = KTraits<K>::LOCAL;
    const int lane_base = lane * LOCAL;

    #pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
        // Cross-thread stages: stride >= LOCAL.
        // Since each thread stores consecutive logical positions, the compared element in the
        // partner thread always has the same local register index.
        #pragma unroll
        for (int stride = size >> 1; stride >= LOCAL; stride >>= 1) {
            const int lane_xor = stride / LOCAL;
            const bool ascending   = ((lane_base & size) == 0);
            const bool lane_lower  = ((lane & lane_xor) == 0);
            const bool take_min    = ascending ? lane_lower : !lane_lower;

            #pragma unroll
            for (int r = 0; r < LOCAL; ++r) {
                const float other_d = __shfl_xor_sync(kFullMask, dist[r], lane_xor);
                const int   other_i = __shfl_xor_sync(kFullMask, idx[r],  lane_xor);

                if (take_min) {
                    if (pair_less(other_d, other_i, dist[r], idx[r])) {
                        dist[r] = other_d;
                        idx[r]  = other_i;
                    }
                } else {
                    if (pair_less(dist[r], idx[r], other_d, other_i)) {
                        dist[r] = other_d;
                        idx[r]  = other_i;
                    }
                }
            }
        }

        // Intra-thread stages: stride < LOCAL.
        #pragma unroll
        for (int stride = ((size >> 1) < LOCAL ? (size >> 1) : (LOCAL >> 1)); stride > 0; stride >>= 1) {
            #pragma unroll
            for (int r = 0; r < LOCAL; ++r) {
                const int partner = r ^ stride;
                if (partner > r) {
                    const bool ascending = (((lane_base + r) & size) == 0);
                    if (ascending) {
                        if (pair_less(dist[partner], idx[partner], dist[r], idx[r])) {
                            pair_swap(dist[r], idx[r], dist[partner], idx[partner]);
                        }
                    } else {
                        if (pair_less(dist[r], idx[r], dist[partner], idx[partner])) {
                            pair_swap(dist[r], idx[r], dist[partner], idx[partner]);
                        }
                    }
                }
            }
        }
    }
}

// Merge the warp-local candidate buffer into the warp-local intermediate result.
// The implementation follows the requested procedure exactly:
//
// 1. Swap the shared-memory candidate buffer with the register-resident intermediate result,
//    so the buffer ends up in registers and the old intermediate result ends up in shared memory.
// 2. Bitonic-sort the candidate buffer in ascending order.
// 3. Form the requested bitonic merge:
//      merged[i] = min(sorted_buffer[i], old_result[K - i - 1])
// 4. Bitonic-sort the merged bitonic sequence in ascending order to obtain the new result.
//
// The candidate buffer may be partially full on the final flush; missing entries are treated as +inf.
template <int K>
__device__ __forceinline__
void merge_candidate_buffer(float (&dist)[KTraits<K>::LOCAL],
                            int   (&idx)[KTraits<K>::LOCAL],
                            float *warp_buf_dist,
                            int   *warp_buf_idx,
                            int lane,
                            int &buffer_count,
                            float &max_distance) {
    constexpr int LOCAL = KTraits<K>::LOCAL;
    const int lane_base = lane * LOCAL;

    // Candidate writes into shared memory happened earlier and came from arbitrary lanes.
    // A warp barrier is sufficient because the buffer is warp-private.
    __syncwarp(kFullMask);

    // Step 1: swap buffer <-> intermediate result.
    #pragma unroll
    for (int r = 0; r < LOCAL; ++r) {
        const int logical = lane_base + r;
        const int phys    = logical_to_physical(logical);

        const float cand_d = (logical < buffer_count) ? warp_buf_dist[phys] : CUDART_INF_F;
        const int   cand_i = (logical < buffer_count) ? warp_buf_idx[phys]  : kInvalidIndex;

        warp_buf_dist[phys] = dist[r];
        warp_buf_idx[phys]  = idx[r];

        dist[r] = cand_d;
        idx[r]  = cand_i;
    }

    // Make the spilled old intermediate result visible before Step 3 reads it back.
    __syncwarp(kFullMask);

    // Step 2: sort the candidate buffer in registers.
    bitonic_sort<K>(dist, idx, lane);

    // Step 3: build the requested bitonic merge in registers.
    #pragma unroll
    for (int r = 0; r < LOCAL; ++r) {
        const int logical     = lane_base + r;
        const int reverse_pos = K - 1 - logical;
        const int reverse_phys = logical_to_physical(reverse_pos);

        const float old_d = warp_buf_dist[reverse_phys];
        const int   old_i = warp_buf_idx[reverse_phys];

        if (pair_less(old_d, old_i, dist[r], idx[r])) {
            dist[r] = old_d;
            idx[r]  = old_i;
        }
    }

    // Step 4: sort the bitonic sequence in ascending order.
    bitonic_sort<K>(dist, idx, lane);

    // Update the pruning threshold with the K-th smallest distance.
    max_distance = __shfl_sync(kFullMask, dist[LOCAL - 1], 31);
    buffer_count = 0;
}

// Brute-force k-NN kernel for 2D points.
//
// Hyper-parameters chosen for A100/H100:
//   * 256 threads/block = 8 warps/block = 8 queries/block
//     This keeps enough blocks in flight for "thousands of queries" while reusing every
//     shared-memory data tile across eight independent queries.
//   * DATA_TILE = 4096 for K <= 512 and DATA_TILE = 2048 for K = 1024
//     This keeps the worst-case shared-memory footprint inside the opt-in shared memory
//     budget while preserving good tile reuse.
template <int K, int BLOCK_THREADS, int DATA_TILE>
__global__ __launch_bounds__(BLOCK_THREADS)
void knn_kernel(const float2 *__restrict__ query,
                int query_count,
                const float2 *__restrict__ data,
                int data_count,
                ResultPairDevice *__restrict__ result) {
    static_assert((BLOCK_THREADS % kWarpSize) == 0, "BLOCK_THREADS must be a multiple of 32.");

    constexpr int LOCAL           = KTraits<K>::LOCAL;
    constexpr int PADDED_K        = KTraits<K>::PADDED;
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;

    // Shared-memory layout:
    //   [data_x[DATA_TILE] | data_y[DATA_TILE] | cand_dist[WARPS_PER_BLOCK][PADDED_K] | cand_idx[WARPS_PER_BLOCK][PADDED_K]]
    //
    // The data tile is stored in SoA form (x[], y[]) to keep warp reads conflict-free when
    // lanes access consecutive cached points.
    extern __shared__ __align__(16) unsigned char smem_raw[];
    float *s_data_x = reinterpret_cast<float *>(smem_raw);
    float *s_data_y = s_data_x + DATA_TILE;
    float *s_buf_dist = s_data_y + DATA_TILE;
    int   *s_buf_idx  = reinterpret_cast<int *>(s_buf_dist + WARPS_PER_BLOCK * PADDED_K);

    const int tid     = threadIdx.x;
    const int warp_id = tid >> kWarpSizeLog2;
    const int lane    = tid & (kWarpSize - 1);

    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool active   = (query_idx < query_count);

    // Warp-private shared candidate buffer.
    float *warp_buf_dist = s_buf_dist + warp_id * PADDED_K;
    int   *warp_buf_idx  = s_buf_idx  + warp_id * PADDED_K;

    // Register-resident intermediate result; each thread keeps LOCAL consecutive logical positions.
    float reg_dist[LOCAL];
    int   reg_idx[LOCAL];

    #pragma unroll
    for (int r = 0; r < LOCAL; ++r) {
        reg_dist[r] = CUDART_INF_F;
        reg_idx[r]  = kInvalidIndex;
    }

    float qx = 0.0f;
    float qy = 0.0f;
    if (active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Warp-uniform replicated registers:
    //   * buffer_count = number of valid logical entries currently stored in the warp-local shared candidate buffer
    //   * max_distance = current K-th smallest distance (pruning threshold)
    int   buffer_count = 0;
    float max_distance = CUDART_INF_F;

    for (int tile_start = 0; tile_start < data_count; tile_start += DATA_TILE) {
        const int remaining = data_count - tile_start;
        const int tile_count = (remaining < DATA_TILE) ? remaining : DATA_TILE;

        // Cooperative block-wide load of a data tile from global memory into shared memory.
        for (int i = tid; i < tile_count; i += BLOCK_THREADS) {
            const float2 p = data[tile_start + i];
            s_data_x[i] = p.x;
            s_data_y[i] = p.y;
        }

        __syncthreads();

        if (active) {
            // One warp-round processes 32 cached data points: lane l handles cached point base + l.
            #pragma unroll 1
            for (int base = 0; base < tile_count; base += kWarpSize) {
                const int local_idx  = base + lane;
                const bool valid     = (local_idx < tile_count);

                float d = CUDART_INF_F;
                int data_idx = 0;

                if (valid) {
                    d = sq_l2_2d(qx, qy, s_data_x[local_idx], s_data_y[local_idx]);
                    data_idx = tile_start + local_idx;
                }

                // If adding this round would overflow the candidate buffer, merge first,
                // tighten max_distance, and retry the same round.
                while (true) {
                    const bool keep = valid && (d < max_distance);
                    const unsigned keep_mask = __ballot_sync(kFullMask, keep);
                    const int keep_count = __popc(keep_mask);

                    if ((buffer_count + keep_count > K) && (buffer_count > 0)) {
                        merge_candidate_buffer<K>(reg_dist, reg_idx,
                                                  warp_buf_dist, warp_buf_idx,
                                                  lane, buffer_count, max_distance);
                        continue;
                    }

                    // Ballot compaction: selected lanes store their candidates contiguously.
                    if (keep) {
                        const unsigned lower_lane_mask = (lane == 0) ? 0u : ((1u << lane) - 1u);
                        const int offset  = __popc(keep_mask & lower_lane_mask);
                        const int logical = buffer_count + offset;
                        const int phys    = logical_to_physical(logical);

                        warp_buf_dist[phys] = d;
                        warp_buf_idx[phys]  = data_idx;
                    }

                    buffer_count += keep_count;

                    // Merge immediately when the buffer becomes full so the pruning threshold stays tight.
                    if (buffer_count == K) {
                        merge_candidate_buffer<K>(reg_dist, reg_idx,
                                                  warp_buf_dist, warp_buf_idx,
                                                  lane, buffer_count, max_distance);
                    }
                    break;
                }
            }
        }

        // Reuse the shared data tile for the next batch.
        __syncthreads();
    }

    // Final flush of a partially filled candidate buffer.
    if (active && buffer_count > 0) {
        merge_candidate_buffer<K>(reg_dist, reg_idx,
                                  warp_buf_dist, warp_buf_idx,
                                  lane, buffer_count, max_distance);
    }

    // Store the final K nearest neighbors for this query.
    if (active) {
        const int out_base = query_idx * K;
        const int lane_base = lane * LOCAL;

        #pragma unroll
        for (int r = 0; r < LOCAL; ++r) {
            result[out_base + lane_base + r].first  = reg_idx[r];
            result[out_base + lane_base + r].second = reg_dist[r];
        }
    }
}

template <int K, int DATA_TILE>
inline void launch_knn_impl(const float2 *query,
                            int query_count,
                            const float2 *data,
                            int data_count,
                            std::pair<int, float> *result) {
    constexpr int BLOCK_THREADS    = 256;
    constexpr int WARPS_PER_BLOCK  = BLOCK_THREADS / kWarpSize;
    constexpr int PADDED_K         = KTraits<K>::PADDED;

    const size_t shared_bytes =
        size_t(DATA_TILE) * sizeof(float) * 2 +
        size_t(WARPS_PER_BLOCK) * size_t(PADDED_K) * (sizeof(float) + sizeof(int));

    // Opt in to the large dynamic shared-memory footprint required by the warp-local candidate buffers.
    (void)cudaFuncSetAttribute(knn_kernel<K, BLOCK_THREADS, DATA_TILE>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(shared_bytes));
    (void)cudaFuncSetAttribute(knn_kernel<K, BLOCK_THREADS, DATA_TILE>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    const int grid = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    knn_kernel<K, BLOCK_THREADS, DATA_TILE>
        <<<grid, BLOCK_THREADS, shared_bytes>>>(
            query,
            query_count,
            data,
            data_count,
            reinterpret_cast<ResultPairDevice *>(result));

    // Surface invalid launch configurations immediately while preserving asynchronous execution.
    (void)cudaPeekAtLastError();
}

} // namespace

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            launch_knn_impl<32, 4096>(query, query_count, data, data_count, result);
            break;
        case 64:
            launch_knn_impl<64, 4096>(query, query_count, data, data_count, result);
            break;
        case 128:
            launch_knn_impl<128, 4096>(query, query_count, data, data_count, result);
            break;
        case 256:
            launch_knn_impl<256, 4096>(query, query_count, data, data_count, result);
            break;
        case 512:
            launch_knn_impl<512, 4096>(query, query_count, data, data_count, result);
            break;
        case 1024:
            // For K = 1024, a smaller tile keeps the block shared-memory footprint low enough
            // to preserve strong occupancy on A100/H100 while still reusing the tile across 8 queries.
            launch_knn_impl<1024, 2048>(query, query_count, data, data_count, result);
            break;
        default:
            // The API contract guarantees that k is valid.
            break;
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <utility>

namespace detail {

// Tuned for modern data-center GPUs (A100/H100):
// - 256 threads/block = 8 warps/block, so each staged data tile is reused by 8 queries.
// - DATA_TILE = 2048 keeps the staged point batch large enough to amortize __syncthreads()
//   while still allowing two resident blocks/SM even for K=1024:
//     shared bytes = 2*2048*sizeof(float) + 8*K*(sizeof(float)+sizeof(int))
//                  = 16 KiB + 64 KiB = 80 KiB at K=1024.
constexpr int BLOCK_THREADS    = 256;
constexpr int WARPS_PER_BLOCK  = BLOCK_THREADS / 32;
constexpr int DATA_TILE        = 2048;
constexpr unsigned FULL_MASK   = 0xFFFFFFFFu;

using result_pair = std::pair<int, float>;

__device__ __forceinline__ bool pair_less(float da, int ia, float db, int ib) {
    return (da < db) || ((da == db) && (ia < ib));
}

__device__ __forceinline__ bool pair_greater(float da, int ia, float db, int ib) {
    return pair_less(db, ib, da, ia);
}

__device__ __forceinline__ void swap_pair(float &da, int &ia, float &db, int &ib) {
    const float td = da;
    const int   ti = ia;
    da = db;
    ia = ib;
    db = td;
    ib = ti;
}

// Warp-distributed bitonic sort on K elements.
// Layout invariant:
//   thread t owns elements [t*(K/32), ..., t*(K/32) + (K/32 - 1)].
// Because K/32 is a power of two, whenever bitonic partner distance exceeds the per-thread
// chunk size, the partner element always has the same register index inside the partner thread.
// This lets us use:
//   - plain register swaps for intra-thread exchanges
//   - warp shuffles for inter-thread exchanges
template <int K>
__device__ __forceinline__ void bitonic_sort_warp(
    float (&dist)[K / 32],
    int   (&idx)[K / 32],
    int lane_base)
{
    constexpr int E = K / 32;

    #pragma unroll
    for (int size = 2; size <= K; size <<= 1) {
        #pragma unroll
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            if constexpr (E > 1) {
                if (stride < E) {
                    // Intra-thread compare/exchange: both elements reside in this thread.
                    #pragma unroll
                    for (int r = 0; r < E; ++r) {
                        const int partner = r ^ stride;
                        if (partner > r) {
                            const int g = lane_base + r;
                            const bool ascending = ((g & size) == 0);

                            const bool out_of_order = ascending
                                ? pair_greater(dist[r], idx[r], dist[partner], idx[partner])
                                : pair_less(dist[r], idx[r], dist[partner], idx[partner]);

                            if (out_of_order) {
                                swap_pair(dist[r], idx[r], dist[partner], idx[partner]);
                            }
                        }
                    }
                } else {
                    // Inter-thread compare/exchange: partner is in another lane, same register slot.
                    const int lane_xor = stride / E;

                    #pragma unroll
                    for (int r = 0; r < E; ++r) {
                        const float other_d = __shfl_xor_sync(FULL_MASK, dist[r], lane_xor);
                        const int   other_i = __shfl_xor_sync(FULL_MASK, idx[r],  lane_xor);

                        const int g = lane_base + r;
                        const bool ascending       = ((g & size) == 0);
                        const bool smaller_partner = ((g & stride) == 0);
                        const bool keep_min        = (ascending == smaller_partner);

                        const bool take_other = keep_min
                            ? pair_greater(dist[r], idx[r], other_d, other_i)
                            : pair_less(dist[r], idx[r], other_d, other_i);

                        if (take_other) {
                            dist[r] = other_d;
                            idx[r]  = other_i;
                        }
                    }
                }
            } else {
                // Special case K=32 -> one element per lane.
                const float other_d = __shfl_xor_sync(FULL_MASK, dist[0], stride);
                const int   other_i = __shfl_xor_sync(FULL_MASK, idx[0],  stride);

                const int g = lane_base;
                const bool ascending       = ((g & size) == 0);
                const bool smaller_partner = ((g & stride) == 0);
                const bool keep_min        = (ascending == smaller_partner);

                const bool take_other = keep_min
                    ? pair_greater(dist[0], idx[0], other_d, other_i)
                    : pair_less(dist[0], idx[0], other_d, other_i);

                if (take_other) {
                    dist[0] = other_d;
                    idx[0]  = other_i;
                }
            }
        }
    }
}

template <int K>
__device__ __forceinline__ float kth_distance(const float (&dist)[K / 32]) {
    constexpr int E = K / 32;
    return __shfl_sync(FULL_MASK, dist[E - 1], 31);
}

// Flushes the shared-memory candidate buffer into the warp-private intermediate result.
// This follows the requested merge procedure exactly:
//   0. intermediate result is already sorted ascending
//   1. swap shared buffer <-> register intermediate, so buffer is now in registers
//   2. bitonic sort the buffer in ascending order
//   3. form a bitonic top-K merge against the reversed intermediate held in shared memory
//   4. bitonic sort again, yielding the updated sorted intermediate result
template <int K>
__device__ __forceinline__ void flush_candidate_buffer(
    float (&result_dist)[K / 32],
    int   (&result_idx)[K / 32],
    float *warp_buf_dist,
    int   *warp_buf_idx,
    int   &buffer_count,
    float &max_distance,
    int lane_base)
{
    constexpr int E = K / 32;

    // Pad the unused tail with +inf so that the final partial buffer can be merged with
    // the exact same code path as a full buffer.
    #pragma unroll
    for (int r = 0; r < E; ++r) {
        const int g = lane_base + r;
        if (g >= buffer_count) {
            warp_buf_dist[g] = CUDART_INF_F;
            warp_buf_idx[g]  = -1;
        }
    }

    // Step 1: swap shared candidate buffer with the register-resident intermediate result.
    // Each thread swaps only its own contiguous chunk, so no temporary arrays are needed.
    #pragma unroll
    for (int r = 0; r < E; ++r) {
        const int g = lane_base + r;

        const float tmp_d = warp_buf_dist[g];
        const int   tmp_i = warp_buf_idx[g];

        warp_buf_dist[g] = result_dist[r];
        warp_buf_idx[g]  = result_idx[r];

        result_dist[r]   = tmp_d;
        result_idx[r]    = tmp_i;
    }

    // Shared memory now contains the old sorted intermediate result, which will be read in
    // reverse order during the merge step.
    __syncwarp(FULL_MASK);

    // Step 2: sort the buffer in registers.
    bitonic_sort_warp<K>(result_dist, result_idx, lane_base);

    // Step 3: top-K bitonic merge with reversed old intermediate result in shared memory.
    #pragma unroll
    for (int r = 0; r < E; ++r) {
        const int g   = lane_base + r;
        const int rev = K - 1 - g;

        const float other_d = warp_buf_dist[rev];
        const int   other_i = warp_buf_idx[rev];

        if (pair_less(other_d, other_i, result_dist[r], result_idx[r])) {
            result_dist[r] = other_d;
            result_idx[r]  = other_i;
        }
    }

    // Step 4: sort the merged bitonic sequence to recover the new sorted intermediate result.
    bitonic_sort_warp<K>(result_dist, result_idx, lane_base);

    max_distance = kth_distance<K>(result_dist);
    buffer_count = 0;
}

template <int K>
__global__ __launch_bounds__(BLOCK_THREADS, 2)
void knn_kernel(
    const float2 *__restrict__ query,
    int query_count,
    const float2 *__restrict__ data,
    int data_count,
    result_pair *__restrict__ result)
{
    static_assert(K >= 32 && K <= 1024, "K out of supported range");
    static_assert((K & (K - 1)) == 0, "K must be a power of two");

    constexpr int E = K / 32;

    extern __shared__ unsigned char shared_raw[];

    // Shared layout:
    //   [sm_x DATA_TILE floats][sm_y DATA_TILE floats]
    //   [candidate distances WARPS_PER_BLOCK*K floats]
    //   [candidate indices   WARPS_PER_BLOCK*K ints]
    float * const sm_x         = reinterpret_cast<float *>(shared_raw);
    float * const sm_y         = sm_x + DATA_TILE;
    float * const sm_buf_dist  = sm_y + DATA_TILE;
    int   * const sm_buf_idx   = reinterpret_cast<int *>(sm_buf_dist + WARPS_PER_BLOCK * K);

    const int tid       = threadIdx.x;
    const int lane      = tid & 31;
    const int warp_id   = tid >> 5;
    const int lane_base = lane * E;

    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    const int query_idx   = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool warp_active = (query_idx < query_count);

    // One query per warp. Load once in lane 0 and broadcast.
    float qx = 0.0f;
    float qy = 0.0f;
    if (warp_active) {
        float qx0 = 0.0f;
        float qy0 = 0.0f;
        if (lane == 0) {
            const float2 q = query[query_idx];
            qx0 = q.x;
            qy0 = q.y;
        }
        qx = __shfl_sync(FULL_MASK, qx0, 0);
        qy = __shfl_sync(FULL_MASK, qy0, 0);
    }

    // Warp-private intermediate result in registers: each thread owns E consecutive neighbors.
    float result_dist[E];
    int   result_idx[E];

    #pragma unroll
    for (int r = 0; r < E; ++r) {
        result_dist[r] = CUDART_INF_F;
        result_idx[r]  = -1;
    }

    // Kept redundantly in all lanes of the warp so that updates are warp-synchronous and cheap.
    float max_distance = CUDART_INF_F;
    int   buffer_count = 0;

    float * const warp_buf_dist = sm_buf_dist + warp_id * K;
    int   * const warp_buf_idx  = sm_buf_idx  + warp_id * K;

    // Iterate over the database in block-cooperative shared-memory tiles.
    for (int base = 0; base < data_count; base += DATA_TILE) {
        const int remaining  = data_count - base;
        const int tile_count = (remaining < DATA_TILE) ? remaining : DATA_TILE;

        // Whole block stages the next tile.
        for (int i = tid; i < tile_count; i += BLOCK_THREADS) {
            const float2 p = data[base + i];
            sm_x[i] = p.x;
            sm_y[i] = p.y;
        }

        __syncthreads();

        if (warp_active) {
            // Each warp walks the cached tile in lane-strided order.
            // One distance per lane per iteration, then warp-ballot compaction into the buffer.
            #pragma unroll 1
            for (int t = lane; t < tile_count; t += 32) {
                const float dx = qx - sm_x[t];
                const float dy = qy - sm_y[t];
                const float d  = fmaf(dx, dx, dy * dy);
                const int   di = base + t;

                bool pending = (d < max_distance);

                // If the current ballot overflows the buffer, insert what fits, flush, then
                // continue with the leftover candidates from the same ballot.
                while (true) {
                    const unsigned mask = __ballot_sync(FULL_MASK, pending);
                    if (mask == 0u) {
                        break;
                    }

                    const int pending_count = __popc(mask);
                    const int rank          = pending ? __popc(mask & lane_mask_lt) : -1;
                    const int space         = K - buffer_count;
                    const int stored        = (space < pending_count) ? space : pending_count;

                    if (pending && rank < stored) {
                        const int pos = buffer_count + rank;
                        warp_buf_dist[pos] = d;
                        warp_buf_idx[pos]  = di;
                    }

                    __syncwarp(FULL_MASK);

                    buffer_count += stored;

                    if (buffer_count == K) {
                        flush_candidate_buffer<K>(
                            result_dist, result_idx,
                            warp_buf_dist, warp_buf_idx,
                            buffer_count, max_distance,
                            lane_base);
                    }

                    // Leftover candidate from this ballot iteration, if any.
                    pending = pending && (rank >= stored) && (d < max_distance);
                }
            }
        }

        // Ensure no warp still consumes the tile before the next one is staged.
        __syncthreads();
    }

    // Final partial buffer flush, if needed.
    if (warp_active) {
        if (buffer_count > 0) {
            flush_candidate_buffer<K>(
                result_dist, result_idx,
                warp_buf_dist, warp_buf_idx,
                buffer_count, max_distance,
                lane_base);
        }

        const std::size_t out_base = static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int r = 0; r < E; ++r) {
            const std::size_t out_pos = out_base + static_cast<std::size_t>(lane_base + r);
            result[out_pos].first  = result_idx[r];
            result[out_pos].second = result_dist[r];
        }
    }
}

template <int K>
inline void launch_knn_impl(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    result_pair *result)
{
    constexpr std::size_t SHARED_BYTES =
        2ull * DATA_TILE * sizeof(float) +
        static_cast<std::size_t>(WARPS_PER_BLOCK) * K * (sizeof(float) + sizeof(int));

    // Opt in to the required dynamic shared memory size and bias the SM partition toward shared
    // memory because the kernel deliberately uses shared memory as both a block-wide data cache
    // and per-warp candidate storage.
    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(SHARED_BYTES));

    cudaFuncSetAttribute(
        knn_kernel<K>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    cudaFuncSetCacheConfig(knn_kernel<K>, cudaFuncCachePreferShared);

    const dim3 block(BLOCK_THREADS);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn_kernel<K><<<grid, block, SHARED_BYTES>>>(
        query, query_count, data, data_count, result);
}

} // namespace detail

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:   detail::launch_knn_impl<32>(query, query_count, data, data_count, result);   break;
        case 64:   detail::launch_knn_impl<64>(query, query_count, data, data_count, result);   break;
        case 128:  detail::launch_knn_impl<128>(query, query_count, data, data_count, result);  break;
        case 256:  detail::launch_knn_impl<256>(query, query_count, data, data_count, result);  break;
        case 512:  detail::launch_knn_impl<512>(query, query_count, data, data_count, result);  break;
        case 1024: detail::launch_knn_impl<1024>(query, query_count, data, data_count, result); break;
        default:   break; // Inputs are specified to be valid; this keeps the function total.
    }
}

#include <cuda_runtime.h>
#include <utility>
#include <cstddef>

namespace knn_detail {

// Fixed warp size mandated by CUDA on NVIDIA GPUs.
constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xFFFFFFFFu;

// Per-k compile-time parameters.
// - REGS_PER_THREAD: each lane stores k/32 consecutive neighbors in registers.
// - SHARED_STRIDE: one extra padding slot per lane-chunk for k > 32 to avoid
//   worst-case 32-way bank conflicts when all lanes access the same register slot.
// - WARP_BUF_ELEMS: physical shared-memory footprint of one warp-local candidate buffer.
// - TILE_POINTS: block-wide data tile cached in shared memory. Larger tiles are used
//   when k is small; for k >= 512 the tile is reduced to preserve occupancy.
template <int K>
struct KnnTraits {
    static_assert(K >= 32 && K <= 1024, "k must be in [32, 1024]");
    static_assert((K & (K - 1)) == 0, "k must be a power of two");
    static_assert((K % kWarpSize) == 0, "k must be divisible by 32");

    static constexpr int REGS_PER_THREAD = K / kWarpSize;
    static constexpr int SHARED_STRIDE = (REGS_PER_THREAD == 1) ? 1 : (REGS_PER_THREAD + 1);
    static constexpr int WARP_BUF_ELEMS = kWarpSize * SHARED_STRIDE;
    static constexpr int TILE_POINTS = (K >= 512) ? 1024 : 2048;
};

// Swap one (index, distance) pair.
__device__ __forceinline__ void swap_pair(float &a_dist, int &a_idx, float &b_dist, int &b_idx) {
    const float td = a_dist;
    a_dist = b_dist;
    b_dist = td;

    const int ti = a_idx;
    a_idx = b_idx;
    b_idx = ti;
}

// Select the other element if it is smaller/larger in distance.
// Ties are intentionally left unresolved, as permitted by the specification.
__device__ __forceinline__ void select_other_by_distance(
    float &self_dist, int &self_idx,
    const float other_dist, const int other_idx,
    const bool take_min)
{
    if (take_min) {
        if (other_dist < self_dist) {
            self_dist = other_dist;
            self_idx = other_idx;
        }
    } else {
        if (self_dist < other_dist) {
            self_dist = other_dist;
            self_idx = other_idx;
        }
    }
}

// Map a logical buffer position in [0, K) to the padded shared-memory layout.
template <int K>
__device__ __forceinline__ int shared_phys_index_from_logical(const int logical) {
    constexpr int M = KnnTraits<K>::REGS_PER_THREAD;
    constexpr int STRIDE = KnnTraits<K>::SHARED_STRIDE;

    const int lane_chunk = logical / M;
    const int off = logical - lane_chunk * M;
    return lane_chunk * STRIDE + off;
}

// One Bitonic Sort stage for a k-element array distributed over a warp:
// each lane owns M = k/32 consecutive elements.
template <int K>
__device__ __forceinline__ void bitonic_sort_stage(
    float (&dist)[KnnTraits<K>::REGS_PER_THREAD],
    int (&idx)[KnnTraits<K>::REGS_PER_THREAD],
    const int stage,
    const int j,
    const int lane)
{
    constexpr int M = KnnTraits<K>::REGS_PER_THREAD;
    const int base = lane * M;

    if (j < M) {
        // Intra-lane compare-exchange: both elements are already in registers.
        #pragma unroll
        for (int off = 0; off < M; ++off) {
            const int partner = off ^ j;
            if (partner > off) {
                const int logical = base + off;
                const bool ascending = ((logical & stage) == 0);

                if (ascending) {
                    if (dist[partner] < dist[off]) {
                        swap_pair(dist[off], idx[off], dist[partner], idx[partner]);
                    }
                } else {
                    if (dist[off] < dist[partner]) {
                        swap_pair(dist[off], idx[off], dist[partner], idx[partner]);
                    }
                }
            }
        }
    } else {
        // Inter-lane compare-exchange: partner element has the same local register slot.
        const int lane_delta = j / M;
        const int partner_lane = lane ^ lane_delta;
        const bool lower_lane = (lane < partner_lane);

        #pragma unroll
        for (int off = 0; off < M; ++off) {
            const float other_dist = __shfl_xor_sync(kFullMask, dist[off], lane_delta);
            const int other_idx = __shfl_xor_sync(kFullMask, idx[off], lane_delta);

            const int logical = base + off;
            const bool ascending = ((logical & stage) == 0);
            const bool take_min = ascending ? lower_lane : !lower_lane;

            select_other_by_distance(dist[off], idx[off], other_dist, other_idx, take_min);
        }
    }
}

// Full Bitonic Sort in ascending order.
template <int K>
__device__ __forceinline__ void bitonic_sort_ascending(
    float (&dist)[KnnTraits<K>::REGS_PER_THREAD],
    int (&idx)[KnnTraits<K>::REGS_PER_THREAD],
    const int lane)
{
    #pragma unroll
    for (int stage = 2; stage <= K; stage <<= 1) {
        #pragma unroll
        for (int j = stage >> 1; j > 0; j >>= 1) {
            bitonic_sort_stage<K>(dist, idx, stage, j, lane);
        }
    }
}

// Bitonic merge of an already bitonic sequence into ascending order.
template <int K>
__device__ __forceinline__ void bitonic_merge_ascending(
    float (&dist)[KnnTraits<K>::REGS_PER_THREAD],
    int (&idx)[KnnTraits<K>::REGS_PER_THREAD],
    const int lane)
{
    constexpr int M = KnnTraits<K>::REGS_PER_THREAD;

    if (M == 1) {
        // Specialized fast path for k == 32.
        #pragma unroll
        for (int j = K >> 1; j > 0; j >>= 1) {
            const float other_dist = __shfl_xor_sync(kFullMask, dist[0], j);
            const int other_idx = __shfl_xor_sync(kFullMask, idx[0], j);
            const bool take_min = (lane < (lane ^ j));
            select_other_by_distance(dist[0], idx[0], other_dist, other_idx, take_min);
        }
        return;
    }

    #pragma unroll
    for (int j = K >> 1; j > 0; j >>= 1) {
        if (j < M) {
            // Intra-lane ascending merge.
            #pragma unroll
            for (int off = 0; off < M; ++off) {
                const int partner = off ^ j;
                if (partner > off) {
                    if (dist[partner] < dist[off]) {
                        swap_pair(dist[off], idx[off], dist[partner], idx[partner]);
                    }
                }
            }
        } else {
            // Inter-lane ascending merge.
            const int lane_delta = j / M;
            const int partner_lane = lane ^ lane_delta;
            const bool lower_lane = (lane < partner_lane);

            #pragma unroll
            for (int off = 0; off < M; ++off) {
                const float other_dist = __shfl_xor_sync(kFullMask, dist[off], lane_delta);
                const int other_idx = __shfl_xor_sync(kFullMask, idx[off], lane_delta);

                select_other_by_distance(dist[off], idx[off], other_dist, other_idx, lower_lane);
            }
        }
    }
}

// Merge the shared candidate buffer with the sorted intermediate result in registers.
// Required sequence:
// 1) swap buffer and result so the buffer is in registers,
// 2) sort the buffer,
// 3) build the top-k bitonic sequence via min(buffer[i], result[k-i-1]),
// 4) bitonic-merge that sequence into a new sorted intermediate result.
template <int K>
__device__ __forceinline__ void merge_buffer_with_result(
    float (&best_dist)[KnnTraits<K>::REGS_PER_THREAD],
    int (&best_idx)[KnnTraits<K>::REGS_PER_THREAD],
    float &max_distance,
    const int buffer_count,
    float *const s_buf_dist,
    int *const s_buf_idx,
    const int lane)
{
    constexpr int M = KnnTraits<K>::REGS_PER_THREAD;
    constexpr int STRIDE = KnnTraits<K>::SHARED_STRIDE;

    __syncwarp(kFullMask);

    // Step 1: move the candidate buffer into registers and spill the current result
    // back into the same shared-memory area. Unused candidate slots are padded with +inf.
    #pragma unroll
    for (int off = 0; off < M; ++off) {
        const int logical = lane * M + off;
        const int phys = lane * STRIDE + off;

        const float cand_dist = (logical < buffer_count) ? s_buf_dist[phys] : CUDART_INF_F;
        const int cand_idx = (logical < buffer_count) ? s_buf_idx[phys] : -1;

        s_buf_dist[phys] = best_dist[off];
        s_buf_idx[phys] = best_idx[off];

        best_dist[off] = cand_dist;
        best_idx[off] = cand_idx;
    }

    __syncwarp(kFullMask);

    // Step 2: sort the buffer in ascending order.
    bitonic_sort_ascending<K>(best_dist, best_idx, lane);

    // Step 3: merge sorted buffer (ascending) with previous result (ascending, read in reverse)
    // into a bitonic sequence containing the k smallest elements of the union.
    #pragma unroll
    for (int off = 0; off < M; ++off) {
        const int phys_rev = (kWarpSize - 1 - lane) * STRIDE + (M - 1 - off);
        const float other_dist = s_buf_dist[phys_rev];
        const int other_idx = s_buf_idx[phys_rev];

        if (other_dist < best_dist[off]) {
            best_dist[off] = other_dist;
            best_idx[off] = other_idx;
        }
    }

    // Step 4: the sequence is bitonic; a bitonic merge restores ascending order.
    bitonic_merge_ascending<K>(best_dist, best_idx, lane);

    // Refresh the pruning threshold with the k-th neighbor distance.
    const float tail = (lane == (kWarpSize - 1)) ? best_dist[M - 1] : 0.0f;
    max_distance = __shfl_sync(kFullMask, tail, kWarpSize - 1);
}

// Append one warp ballot worth of candidates to the shared buffer, and flush+merge
// whenever the buffer reaches size k.
template <int K>
__device__ __forceinline__ void append_candidates_mask(
    const float cand_dist,
    const int cand_idx,
    const unsigned mask,
    float (&best_dist)[KnnTraits<K>::REGS_PER_THREAD],
    int (&best_idx)[KnnTraits<K>::REGS_PER_THREAD],
    float *const s_buf_dist,
    int *const s_buf_idx,
    const int lane,
    const unsigned lane_mask_lt,
    int &buffer_count,
    float &max_distance)
{
    if (mask == 0u) {
        return;
    }

    const bool is_candidate = ((mask >> lane) & 1u) != 0u;
    const int rank = __popc(mask & lane_mask_lt);
    const int num = __popc(mask);
    const int old_count = buffer_count;

    if (old_count + num < K) {
        // Fast path: the warp-local buffer still has space.
        if (is_candidate) {
            const int logical = old_count + rank;
            const int phys = shared_phys_index_from_logical<K>(logical);
            s_buf_dist[phys] = cand_dist;
            s_buf_idx[phys] = cand_idx;
        }

        __syncwarp(kFullMask);
        buffer_count = old_count + num;
        return;
    }

    // Fill the remaining slots, merge, then re-test any overflow candidates against
    // the tightened max_distance before storing them in the now-empty buffer.
    const int fill = K - old_count;

    if (is_candidate && rank < fill) {
        const int logical = old_count + rank;
        const int phys = shared_phys_index_from_logical<K>(logical);
        s_buf_dist[phys] = cand_dist;
        s_buf_idx[phys] = cand_idx;
    }

    __syncwarp(kFullMask);

    buffer_count = K;
    merge_buffer_with_result<K>(best_dist, best_idx, max_distance, buffer_count, s_buf_dist, s_buf_idx, lane);
    buffer_count = 0;

    if (old_count + num > K) {
        const bool keep_remainder = is_candidate && (rank >= fill) && (cand_dist < max_distance);
        const unsigned rem_mask = __ballot_sync(kFullMask, keep_remainder);
        const int rem_num = __popc(rem_mask);

        if (keep_remainder) {
            const int rem_rank = __popc(rem_mask & lane_mask_lt);
            const int phys = shared_phys_index_from_logical<K>(rem_rank);
            s_buf_dist[phys] = cand_dist;
            s_buf_idx[phys] = cand_idx;
        }

        __syncwarp(kFullMask);
        buffer_count = rem_num;
    }
}

// One warp computes the k-NN result for one query.
// The block cooperatively loads data tiles into shared memory for reuse across all warps.
template <int K, int WARPS_PER_BLOCK>
__launch_bounds__(WARPS_PER_BLOCK * kWarpSize)
__global__ void knn2d_kernel(
    const float2 * __restrict__ query,
    const int query_count,
    const float2 * __restrict__ data,
    const int data_count,
    std::pair<int, float> * __restrict__ result)
{
    constexpr int M = KnnTraits<K>::REGS_PER_THREAD;
    constexpr int TILE_POINTS = KnnTraits<K>::TILE_POINTS;
    constexpr int WARP_BUF_ELEMS = KnnTraits<K>::WARP_BUF_ELEMS;

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp_in_block = threadIdx.x >> 5;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_in_block;
    const bool valid_query = (query_idx < query_count);

    // Use a 16-byte aligned dynamic shared-memory base.
    extern __shared__ uint4 smem_vec[];
    unsigned char *const smem_raw = reinterpret_cast<unsigned char *>(smem_vec);

    float2 *const s_data = reinterpret_cast<float2 *>(smem_raw);
    float *const s_buf_dist_all =
        reinterpret_cast<float *>(smem_raw + static_cast<std::size_t>(TILE_POINTS) * sizeof(float2));
    int *const s_buf_idx_all =
        reinterpret_cast<int *>(reinterpret_cast<unsigned char *>(s_buf_dist_all) +
                                static_cast<std::size_t>(WARPS_PER_BLOCK) * WARP_BUF_ELEMS * sizeof(float));

    float *const s_buf_dist = s_buf_dist_all + warp_in_block * WARP_BUF_ELEMS;
    int *const s_buf_idx = s_buf_idx_all + warp_in_block * WARP_BUF_ELEMS;

    // Lane-local prefix mask for ballot compaction.
    const unsigned lane_mask_lt = (lane == 0) ? 0u : ((1u << lane) - 1u);

    // Load query point once per warp and broadcast it.
    float qx = 0.0f;
    float qy = 0.0f;
    if (valid_query && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Sorted intermediate result: each lane owns M consecutive neighbors in registers.
    float best_dist[M];
    int best_idx[M];
    #pragma unroll
    for (int off = 0; off < M; ++off) {
        best_dist[off] = CUDART_INF_F;
        best_idx[off] = -1;
    }

    float max_distance = CUDART_INF_F;
    int buffer_count = 0;

    // Iterate over the dataset in block-cached tiles.
    for (int batch_start = 0; batch_start < data_count; batch_start += TILE_POINTS) {
        int batch_size = data_count - batch_start;
        if (batch_size > TILE_POINTS) {
            batch_size = TILE_POINTS;
        }

        // Cooperative, coalesced tile load.
        for (int t = threadIdx.x; t < batch_size; t += blockDim.x) {
            s_data[t] = data[batch_start + t];
        }

        __syncthreads();

        if (valid_query) {
            // Each warp consumes the tile 32 points at a time so that one ballot compactly
            // appends one warp-width group of candidates.
            #pragma unroll 1
            for (int tile_off = 0; tile_off < batch_size; tile_off += kWarpSize) {
                const int local = tile_off + lane;
                const bool active = (local < batch_size);

                float dist = CUDART_INF_F;
                int cand_global_idx = 0;

                if (active) {
                    const float2 p = s_data[local];
                    const float dx = qx - p.x;
                    const float dy = qy - p.y;
                    dist = fmaf(dx, dx, dy * dy);
                    cand_global_idx = batch_start + local;
                }

                const unsigned mask = __ballot_sync(kFullMask, active && (dist < max_distance));

                if (mask != 0u) {
                    append_candidates_mask<K>(
                        dist, cand_global_idx, mask,
                        best_dist, best_idx,
                        s_buf_dist, s_buf_idx,
                        lane, lane_mask_lt,
                        buffer_count, max_distance);
                }
            }
        }

        // Ensure all warps are done with the tile before overwriting shared memory.
        __syncthreads();
    }

    if (valid_query) {
        // Final partial flush, if any candidates remain buffered.
        if (buffer_count > 0) {
            merge_buffer_with_result<K>(best_dist, best_idx, max_distance, buffer_count, s_buf_dist, s_buf_idx, lane);
        }

        // Write the sorted result back in the required row-major layout.
        std::pair<int, float> *const out =
            result + static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int off = 0; off < M; ++off) {
            const int logical = lane * M + off;
            out[logical].first = best_idx[off];
            out[logical].second = best_dist[off];
        }
    }
}

template <int K, int WARPS_PER_BLOCK>
constexpr std::size_t shared_bytes_for_kernel() {
    return static_cast<std::size_t>(KnnTraits<K>::TILE_POINTS) * sizeof(float2) +
           static_cast<std::size_t>(WARPS_PER_BLOCK) * KnnTraits<K>::WARP_BUF_ELEMS * (sizeof(float) + sizeof(int));
}

template <int K, int WARPS_PER_BLOCK>
inline void launch_knn_kernel(
    const float2 *query,
    const int query_count,
    const float2 *data,
    const int data_count,
    std::pair<int, float> *result)
{
    const std::size_t shmem_bytes = shared_bytes_for_kernel<K, WARPS_PER_BLOCK>();

    // Opt in to the required dynamic shared memory and bias the SM partitioning
    // toward shared memory, which is critical for tile reuse and warp-local buffers.
    (void)cudaFuncSetAttribute(
        knn2d_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shmem_bytes));

    (void)cudaFuncSetAttribute(
        knn2d_kernel<K, WARPS_PER_BLOCK>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    const dim3 block(WARPS_PER_BLOCK * kWarpSize);
    const dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    knn2d_kernel<K, WARPS_PER_BLOCK><<<grid, block, shmem_bytes>>>(
        query, query_count, data, data_count, result);
}

template <int K>
inline void select_and_launch(
    const float2 *query,
    const int query_count,
    const float2 *data,
    const int data_count,
    std::pair<int, float> *result,
    const int sm_count,
    const int max_optin_shared)
{
    // Choose the largest warp-group count per block that still leaves enough blocks
    // to cover all SMs. This maximizes data-tile reuse within a block while avoiding
    // obvious under-subscription when the query count is only moderately large.
    const int blocks16 = (query_count + 15) / 16;
    const int blocks8 = (query_count + 7) / 8;

    if (shared_bytes_for_kernel<K, 16>() <= static_cast<std::size_t>(max_optin_shared) &&
        blocks16 >= sm_count) {
        launch_knn_kernel<K, 16>(query, query_count, data, data_count, result);
    } else if (shared_bytes_for_kernel<K, 8>() <= static_cast<std::size_t>(max_optin_shared) &&
               blocks8 >= sm_count) {
        launch_knn_kernel<K, 8>(query, query_count, data, data_count, result);
    } else {
        launch_knn_kernel<K, 4>(query, query_count, data, data_count, result);
    }
}

} // namespace knn_detail

void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0) {
        return;
    }

    int device = 0;
    int sm_count = 0;
    int max_optin_shared = 0;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaDeviceGetAttribute(&max_optin_shared, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);

    // Conservative fallbacks match the A100-class minimum among the intended targets.
    if (sm_count <= 0) {
        sm_count = 1;
    }
    if (max_optin_shared <= 0) {
        max_optin_shared = 163840;
    }

    switch (k) {
        case 32:
            knn_detail::select_and_launch<32>(query, query_count, data, data_count, result, sm_count, max_optin_shared);
            break;
        case 64:
            knn_detail::select_and_launch<64>(query, query_count, data, data_count, result, sm_count, max_optin_shared);
            break;
        case 128:
            knn_detail::select_and_launch<128>(query, query_count, data, data_count, result, sm_count, max_optin_shared);
            break;
        case 256:
            knn_detail::select_and_launch<256>(query, query_count, data, data_count, result, sm_count, max_optin_shared);
            break;
        case 512:
            knn_detail::select_and_launch<512>(query, query_count, data, data_count, result, sm_count, max_optin_shared);
            break;
        case 1024:
            knn_detail::select_and_launch<1024>(query, query_count, data, data_count, result, sm_count, max_optin_shared);
            break;
        default:
            // Inputs are specified to be valid; this path is only a defensive guard.
            break;
    }
}

#include <cuda_runtime.h>

#include <climits>
#include <cstddef>
#include <utility>

namespace knn_detail {

// Optimized design summary:
// - One warp computes one query.
// - The current top-K for that query is kept in registers, distributed so each lane owns K/32
//   consecutive entries.
// - A warp-private shared-memory candidate buffer stores up to K newly found closer points.
// - The database is scanned in large shared-memory tiles loaded cooperatively by the full block.
// - Whenever the candidate buffer fills, it is merged into the register-resident intermediate
//   result using the exact bitonic-sort-based procedure requested by the prompt.
//
// Hyper-parameters chosen for A100/H100-class GPUs:
// - 8 warps/block = 256 threads/block. This maximizes reuse of each shared-memory tile across
//   multiple queries while still fitting a large tile and the per-warp candidate buffers into
//   shared memory.
// - ~79.75 KiB dynamic shared memory/block (80 KiB minus 256 B headroom). On A100 this allows
//   two resident blocks/SM within the 163840 B shared-memory budget, while keeping the tile as
//   large as possible.

constexpr int kWarpSize = 32;
constexpr unsigned kFullMask = 0xffffffffu;
constexpr int kWarpsPerBlock = 8;
constexpr int kBlockThreads = kWarpsPerBlock * kWarpSize;
constexpr std::size_t kTargetDynamicSmemBytes = 80u * 1024u - 256u;
constexpr int kInvalidIndex = INT_MAX;

// Device code should not rely on std::pair constructors being __device__-callable.
// The result buffer comes from cudaMalloc, so we reinterpret it as a POD with the same ABI.
struct alignas(std::pair<int, float>) PairIFPOD {
    int first;
    float second;
};

static_assert(sizeof(PairIFPOD) == sizeof(std::pair<int, float>),
              "std::pair<int,float> must be ABI-compatible with {int,float}.");
static_assert(alignof(PairIFPOD) == alignof(std::pair<int, float>),
              "std::pair<int,float> alignment must match {int,float}.");

// Total order used inside the sorting network.
// Ties on distance may be resolved arbitrarily by the problem statement; using the index as a
// secondary key simply makes the network deterministic and keeps sentinel entries at the end.
__device__ __forceinline__ bool pair_less(const float a_dist, const int a_idx,
                                          const float b_dist, const int b_idx) {
    return (a_dist < b_dist) || ((a_dist == b_dist) && (a_idx < b_idx));
}

__device__ __forceinline__ void swap_pair(float& a_dist, int& a_idx,
                                          float& b_dist, int& b_idx) {
    const float td = a_dist;
    a_dist = b_dist;
    b_dist = td;

    const int ti = a_idx;
    a_idx = b_idx;
    b_idx = ti;
}

// Warp-wide bitonic sort over K elements distributed across the 32 lanes.
// Each lane owns LOCAL_K = K/32 consecutive values.
// Because LOCAL_K is a power of two and the ownership is consecutive, XOR partners work out as:
// - stride < LOCAL_K   : partner stays in the same lane, so registers can be swapped directly.
// - stride >= LOCAL_K  : partner is in another lane, but always at the same local register index,
//                        so a single __shfl_xor_sync per local slot suffices.
template <int K>
__device__ __forceinline__ void bitonic_sort_warp(float* dist, int* idx, const int lane) {
    static_assert((K & (K - 1)) == 0 && K >= 32 && K <= 1024,
                  "K must be a supported power of two.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");

    constexpr int LOCAL_K = K / kWarpSize;
    const int lane_base = lane * LOCAL_K;

    #pragma unroll
    for (int stage = 2; stage <= K; stage <<= 1) {
        #pragma unroll
        for (int stride = stage >> 1; stride > 0; stride >>= 1) {
            if (stride < LOCAL_K) {
                #pragma unroll
                for (int r = 0; r < LOCAL_K; ++r) {
                    const int partner = r ^ stride;
                    if (partner > r) {
                        const int global_i = lane_base + r;
                        const bool sort_asc = ((global_i & stage) == 0);

                        if (sort_asc) {
                            if (pair_less(dist[partner], idx[partner], dist[r], idx[r])) {
                                swap_pair(dist[r], idx[r], dist[partner], idx[partner]);
                            }
                        } else {
                            if (pair_less(dist[r], idx[r], dist[partner], idx[partner])) {
                                swap_pair(dist[r], idx[r], dist[partner], idx[partner]);
                            }
                        }
                    }
                }
            } else {
                const int lane_delta = stride / LOCAL_K;

                #pragma unroll
                for (int r = 0; r < LOCAL_K; ++r) {
                    const float other_d = __shfl_xor_sync(kFullMask, dist[r], lane_delta);
                    const int other_i = __shfl_xor_sync(kFullMask, idx[r], lane_delta);

                    const int global_i = lane_base + r;
                    const bool sort_asc = ((global_i & stage) == 0);
                    const bool lower = ((global_i & stride) == 0);

                    // In ascending subsequences the lower index keeps the smaller element.
                    // In descending subsequences the lower index keeps the larger element.
                    const bool keep_small = (sort_asc == lower);

                    if (keep_small) {
                        if (pair_less(other_d, other_i, dist[r], idx[r])) {
                            dist[r] = other_d;
                            idx[r] = other_i;
                        }
                    } else {
                        if (pair_less(dist[r], idx[r], other_d, other_i)) {
                            dist[r] = other_d;
                            idx[r] = other_i;
                        }
                    }
                }
            }

            // The next network layer depends on the outputs of the current one. Shuffles already
            // synchronize the exchange itself; this warp barrier makes the layer-to-layer
            // dependency explicit and keeps the warp converged on Volta+ schedulers.
            __syncwarp(kFullMask);
        }
    }
}

// Merges the shared-memory candidate buffer into the sorted register-resident intermediate result
// using the exact sequence requested:
//
// 1. Swap buffer <-> intermediate result so the buffer moves into registers.
// 2. Bitonic-sort the register buffer.
// 3. Build the bitonic sequence C[i] = min(A[i], B[K-1-i]) where A is the sorted buffer in
//    registers and B is the old intermediate result in shared memory.
// 4. Bitonic-sort C to obtain the updated intermediate result.
//
// shared_buffer_* is warp-private even though it resides in shared memory.
template <int K>
__device__ __forceinline__ void merge_buffer_into_result(float* result_dist,
                                                         int* result_idx,
                                                         float* shared_buffer_dist,
                                                         int* shared_buffer_idx,
                                                         int& buffer_count,
                                                         float& max_distance,
                                                         const int lane) {
    constexpr int LOCAL_K = K / kWarpSize;
    const int lane_base = lane * LOCAL_K;

    // Order all prior writes to the warp-private shared buffer before this merge reads them.
    __syncwarp(kFullMask);

    // Step 1: swap buffer <-> intermediate result.
    #pragma unroll
    for (int r = 0; r < LOCAL_K; ++r) {
        const int pos = lane_base + r;

        const float buffer_d = (pos < buffer_count) ? shared_buffer_dist[pos] : CUDART_INF_F;
        const int buffer_i = (pos < buffer_count) ? shared_buffer_idx[pos] : kInvalidIndex;

        shared_buffer_dist[pos] = result_dist[r];
        shared_buffer_idx[pos] = result_idx[r];

        result_dist[r] = buffer_d;
        result_idx[r] = buffer_i;
    }

    // The old intermediate result is now in shared memory and will be consumed in reverse order.
    __syncwarp(kFullMask);

    // Step 2: sort the buffer now resident in registers.
    bitonic_sort_warp<K>(result_dist, result_idx, lane);

    // Step 3: build the bitonic sequence containing the smallest K elements of the 2K union.
    #pragma unroll
    for (int r = 0; r < LOCAL_K; ++r) {
        const int pos = lane_base + r;
        const int mirror = K - 1 - pos;

        const float other_d = shared_buffer_dist[mirror];
        const int other_i = shared_buffer_idx[mirror];

        if (pair_less(other_d, other_i, result_dist[r], result_idx[r])) {
            result_dist[r] = other_d;
            result_idx[r] = other_i;
        }
    }

    // Step 4: sort the bitonic sequence to restore the ascending invariant.
    bitonic_sort_warp<K>(result_dist, result_idx, lane);

    // The K-th nearest neighbor is the globally last element, which resides in lane 31 at the
    // last local slot because ownership is consecutive.
    const float local_last = result_dist[LOCAL_K - 1];
    max_distance = __shfl_sync(kFullMask, local_last, kWarpSize - 1);
    buffer_count = 0;
}

template <int K, int WARPS_PER_BLOCK, int TILE_POINTS>
__global__ __launch_bounds__(WARPS_PER_BLOCK * kWarpSize, 2)
void knn_kernel(const float2* __restrict__ query,
                int query_count,
                const float2* __restrict__ data,
                int data_count,
                std::pair<int, float>* __restrict__ result) {
    static_assert((K & (K - 1)) == 0 && K >= 32 && K <= 1024,
                  "K must be a supported power of two.");
    static_assert((K % kWarpSize) == 0, "K must be a multiple of warp size.");
    static_assert(WARPS_PER_BLOCK > 0, "At least one warp is required.");
    static_assert((TILE_POINTS % kWarpSize) == 0, "Tile size must be a multiple of the warp size.");

    constexpr int LOCAL_K = K / kWarpSize;

    extern __shared__ unsigned char shared_raw[];

    // The input is AoS in global memory (float2), but the shared-memory tile is stored as SoA
    // (x[] and y[]) so every warp streams through conflict-free 32-bit shared accesses.
    float* tile_x = reinterpret_cast<float*>(shared_raw);
    float* tile_y = tile_x + TILE_POINTS;
    float* candidate_dist = tile_y + TILE_POINTS;
    int* candidate_idx = reinterpret_cast<int*>(candidate_dist + WARPS_PER_BLOCK * K);

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp_id = threadIdx.x >> 5;
    const int query_idx = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const bool warp_active = (query_idx < query_count);

    const unsigned lower_lane_mask = (1u << lane) - 1u;
    const int lane_base = lane * LOCAL_K;

    // One lane loads the query point and broadcasts it to the rest of the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (warp_active && lane == 0) {
        const float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(kFullMask, qx, 0);
    qy = __shfl_sync(kFullMask, qy, 0);

    // Warp-private candidate buffer slices in shared memory.
    float* warp_buffer_dist = candidate_dist + warp_id * K;
    int* warp_buffer_idx = candidate_idx + warp_id * K;

    // Intermediate result kept in registers; initially K sentinels, which is already sorted.
    float result_dist[LOCAL_K];
    int result_idx[LOCAL_K];
    #pragma unroll
    for (int r = 0; r < LOCAL_K; ++r) {
        result_dist[r] = CUDART_INF_F;
        result_idx[r] = kInvalidIndex;
    }

    // Warp-uniform state replicated in registers.
    int buffer_count = 0;
    float max_distance = CUDART_INF_F;

    for (int base = 0; base < data_count; base += TILE_POINTS) {
        const int batch_count = (base + TILE_POINTS <= data_count) ? TILE_POINTS : (data_count - base);

        // Cooperative block-wide load of the current database tile.
        for (int t = threadIdx.x; t < batch_count; t += WARPS_PER_BLOCK * kWarpSize) {
            const float2 p = data[base + t];
            tile_x[t] = p.x;
            tile_y[t] = p.y;
        }
        __syncthreads();

        if (warp_active) {
            // The loop is written in fixed 32-point rounds so every lane participates in every
            // ballot, even in the last partial round of the tile.
            const int rounds = (batch_count + kWarpSize - 1) >> 5;

            for (int round = 0; round < rounds; ++round) {
                const int tile_pos = (round << 5) + lane;
                const bool valid = (tile_pos < batch_count);

                float dist = CUDART_INF_F;
                int data_idx = kInvalidIndex;

                if (valid) {
                    const float dx = qx - tile_x[tile_pos];
                    const float dy = qy - tile_y[tile_pos];
                    dist = fmaf(dx, dx, dy * dy);  // squared Euclidean distance
                    data_idx = base + tile_pos;
                }

                bool is_candidate = valid && (dist < max_distance);
                unsigned mask = __ballot_sync(kFullMask, is_candidate);
                int num = __popc(mask);

                if (num != 0) {
                    // If this ballot would overflow the shared candidate buffer, flush the current
                    // buffer first, then re-test the same 32 distances against the tightened
                    // threshold before storing them.
                    if (buffer_count + num > K) {
                        merge_buffer_into_result<K>(result_dist,
                                                    result_idx,
                                                    warp_buffer_dist,
                                                    warp_buffer_idx,
                                                    buffer_count,
                                                    max_distance,
                                                    lane);

                        is_candidate = valid && (dist < max_distance);
                        mask = __ballot_sync(kFullMask, is_candidate);
                        num = __popc(mask);
                    }

                    if (num != 0) {
                        const int base_pos = buffer_count;

                        if (is_candidate) {
                            const int offset = __popc(mask & lower_lane_mask);
                            warp_buffer_dist[base_pos + offset] = dist;
                            warp_buffer_idx[base_pos + offset] = data_idx;
                        }

                        buffer_count += num;

                        // The prompt requires merging whenever the warp-private buffer is full.
                        if (buffer_count == K) {
                            merge_buffer_into_result<K>(result_dist,
                                                        result_idx,
                                                        warp_buffer_dist,
                                                        warp_buffer_idx,
                                                        buffer_count,
                                                        max_distance,
                                                        lane);
                        }
                    }
                }
            }
        }

        // Prevent any warp from overwriting the shared tile for the next batch before all warps
        // are done consuming the current one.
        __syncthreads();
    }

    if (warp_active) {
        // Flush the last partially filled candidate buffer.
        if (buffer_count != 0) {
            merge_buffer_into_result<K>(result_dist,
                                        result_idx,
                                        warp_buffer_dist,
                                        warp_buffer_idx,
                                        buffer_count,
                                        max_distance,
                                        lane);
        }

        // Write the final sorted top-K results back to global memory.
        PairIFPOD* const out = reinterpret_cast<PairIFPOD*>(result);
        const std::size_t out_base =
            static_cast<std::size_t>(query_idx) * static_cast<std::size_t>(K);

        #pragma unroll
        for (int r = 0; r < LOCAL_K; ++r) {
            const std::size_t pos = out_base + static_cast<std::size_t>(lane_base + r);
            out[pos] = PairIFPOD{result_idx[r], result_dist[r]};
        }
    }
}

// K takes one of only six legal values. Specializing on K lets the compiler fully unroll the
// local register loops and the bitonic network, which is much faster than a runtime-generic path.
template <int K>
inline void launch_knn_impl(const float2* query,
                            int query_count,
                            const float2* data,
                            int data_count,
                            std::pair<int, float>* result) {
    constexpr std::size_t kCandidateBytes =
        static_cast<std::size_t>(kWarpsPerBlock) * static_cast<std::size_t>(K) *
        (sizeof(float) + sizeof(int));
    constexpr std::size_t kBytesPerSharedPoint = 2 * sizeof(float);  // x[] + y[]
    constexpr int kRawTilePoints =
        static_cast<int>((kTargetDynamicSmemBytes - kCandidateBytes) / kBytesPerSharedPoint);
    constexpr int kTilePoints = kRawTilePoints & ~31;
    constexpr std::size_t kSmemBytes =
        static_cast<std::size_t>(kTilePoints) * kBytesPerSharedPoint + kCandidateBytes;

    static_assert(kCandidateBytes < kTargetDynamicSmemBytes,
                  "Shared-memory budget too small for the candidate buffers.");
    static_assert(kTilePoints >= 32, "Shared-memory budget leaves no room for a tile.");
    static_assert((kTilePoints % 32) == 0, "Tile size must be warp-aligned.");
    static_assert(kSmemBytes <= kTargetDynamicSmemBytes,
                  "Computed shared-memory usage exceeds the target budget.");

    const dim3 block(kBlockThreads);
    const dim3 grid((query_count + kWarpsPerBlock - 1) / kWarpsPerBlock);

    // Dynamic shared memory above 48 KiB requires opt-in. Prefer the shared-heavy carveout since
    // this kernel is intentionally shared-memory-centric.
    (void)cudaFuncSetAttribute(knn_kernel<K, kWarpsPerBlock, kTilePoints>,
                               cudaFuncAttributeMaxDynamicSharedMemorySize,
                               static_cast<int>(kSmemBytes));
    (void)cudaFuncSetAttribute(knn_kernel<K, kWarpsPerBlock, kTilePoints>,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);
    (void)cudaFuncSetCacheConfig(knn_kernel<K, kWarpsPerBlock, kTilePoints>,
                                 cudaFuncCachePreferShared);

    knn_kernel<K, kWarpsPerBlock, kTilePoints>
        <<<grid, block, kSmemBytes>>>(query, query_count, data, data_count, result);
}

}  // namespace knn_detail

void run_knn(const float2* query,
             int query_count,
             const float2* data,
             int data_count,
             std::pair<int, float>* result,
             int k) {
    if (query_count <= 0) {
        return;
    }

    switch (k) {
        case 32:
            knn_detail::launch_knn_impl<32>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_detail::launch_knn_impl<64>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_detail::launch_knn_impl<128>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_detail::launch_knn_impl<256>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_detail::launch_knn_impl<512>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_detail::launch_knn_impl<1024>(query, query_count, data, data_count, result);
            break;
        default:
            // The contract guarantees a supported power-of-two K, but keep the function total.
            break;
    }
}
